      SUBROUTINE DPLOEX(ILOOST,ILOOLI,NUMLIL,NUMLOE,NUMENE,MAXLOO,      &
                        IHPNV,IHPNV2,ILOCPN,ASTARV,AINCV,ASTOPV,        &
                        NUMLOI,ILOOIT,ILOOIF,                           &
                        ILOOSP,ILOOEP,IANSLO,IWIDLL,MAXLIL,MAXCIL,      &
                        IANS,IANSLC,IWIDTH,                             &
                        ICOM,ICOM2,ICOMT,ICOMI,ACOM,ICOMLC,ICOML2,      &
                        IHARG,IHARG2,IARGT,IARG,ARG,IHARLC,IHARL2,      &
                        NUMARG,                                         &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,MAXNAM,  &
                        IN,IIFSW,NUMIF,IHOST1,IHOST2,                   &
                        IBUGLO,IBUGTY,ISUBRO,IERROR)
!
!     PURPOSE--EXECUTE THE COMMANDS IN A LOOP
!              (THESE COMMANDS HAVE BEEN AUTOMATICALLY STORED).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER 1982
!     UPDATED         --APRIL    1989 ADD ISUBRO AS AN ARGUMENT
!     UPDATED         --FEBRUARY 1994 FIX BUG THAT DELETE IN LOOP WIPED
!                                     OUT LOOP INDEX PARAMETER
!     UPDATED         --FEBRUARY 1994 ADD BREAK LOOP COMMAND
!     UPDATED         --JANUARY  2005 FOR LOOPS OF TYPE
!                                         LOOP FOR K = 3 1 2
!                                     MODIFY SO THAT LOOP NOT EXECUTED
!                                     AND SET INDEX VALUE TO START
!                                     VALUE
!     UPDATED         --FEBRUARY 2006 USE MAXCIL (RATHER THAN 80) AS
!                                     THE MAXIMUM NUMBER OF
!                                     CHARACTERS PER LINE IN LOOP
!     UPDATED         --FEBRUARY 2006 BUG IN BREAK LOOP WHEN BREAK
!                                     OCCURS IN FIRST ITERATION OF
!                                     THE LOOP
!     UPDATED         --AUGUST   2007 FIX BUG WHEN THERE IS A DELETE
!                                     IN THE LOOP COMMAND
!     UPDATED         --MAY      2011 ADD MAXLOO TO SPECIFY MAXIMUM
!                                     NUMBER OF NESTED LOOPS
!     UPDATED         --OCTOBER  2018 ILOOIF TO KEEP TRACK OF IF LEVEL
!                                     WHEN INITIATE LOOP
!     UPDATED         --OCTOBER  2018 "CONTINUE LOOP"
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ILOOST
      CHARACTER*4 IHPNV
      CHARACTER*4 IHPNV2
      CHARACTER*4 IANSLO
      CHARACTER*4 IANS
      CHARACTER*4 IANSLC
      CHARACTER*4 ICOM
      CHARACTER*4 ICOM2
      CHARACTER*4 ICOMT
      CHARACTER*4 ICOMLC
      CHARACTER*4 ICOML2
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
      CHARACTER*4 IHARLC
      CHARACTER*4 IHARL2
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 IHOST1
      CHARACTER*4 IHOST2
      CHARACTER*4 IBUGLO
      CHARACTER*4 IBUGTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHPN
      CHARACTER*4 IHPN2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFOUNF
      CHARACTER*4 IIFSW
!
      DIMENSION IHPNV(*)
      DIMENSION IHPNV2(*)
      DIMENSION ILOCPN(*)
      DIMENSION ASTARV(*)
      DIMENSION AINCV(*)
      DIMENSION ASTOPV(*)
      DIMENSION NUMLOI(*)
      DIMENSION ILOOIT(*)
      DIMENSION ILOOSP(*)
      DIMENSION ILOOEP(*)
      DIMENSION ILOOIF(*)
      DIMENSION IANSLO(MAXLIL,MAXCIL)
      DIMENSION IWIDLL(*)
!
      DIMENSION IANS(*)
      DIMENSION IANSLC(*)
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
      DIMENSION IHARLC(*)
      DIMENSION IHARL2(*)
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
      DIMENSION IN(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLO'
      ISUBN2='EX  '
      J12=0
!
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOEX--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGLO,IBUGTY,IERROR
   52   FORMAT('IBUGLO,IBUGTY,IERROR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ILOOST,ILOOLI,NUMLIL,NUMLOE,NUMENE
   53   FORMAT('ILOOST,ILOOLI,NUMLIL,NUMLOE,NUMENE = ',A4,4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)NUMLOE,NUMENE,NUMLIL,MAXCIL
   54   FORMAT('NUMLOE,NUMENE,NUMLIL,MAXCIL = ',4I8)
        DO 55 I=1,10
          WRITE(ICOUT,56)I,IHPNV(I),IHPNV2(I),ILOCPN(I),ILOOSP(I),   &
                         ILOOEP(I)
   56     FORMAT('I,IHPNV(I),IHPNV2(I),ILOCPN(I),ILOOSP(I),',   &
                 'ILOOEP(I) =',I8,2(2X,A4),3I8)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,10
          WRITE(ICOUT,61)I,ASTARV(I),AINCV(I),ASTOPV(I),   &
                         NUMLOI(I),ILOOIT(I)
   61     FORMAT('I,ASTARV(I),AINCV(I),ASTOPV(I),NUMLOI(I),',   &
                 'ILOOIT(I) =',I8,3E15.7,2I8)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 65 I=1,NUMLIL
          WRITE(ICOUT,66)I,IWIDLL(I)
   66     FORMAT('I,IWIDLL(I) = ',I8,I8)
          CALL DPWRST('XXX','BUG ')
          JMAX=IWIDLL(I)
          WRITE(ICOUT,67)(IANSLO(I,J),J=1,MIN(80,JMAX))
   67     FORMAT('(IANSLO(I,J),J=1,JMAX) = ',80A1)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)IWIDTH,NUMARG,ICOM,ICOM2
   71   FORMAT('IWIDTH,NUMARG,ICOM,ICOM2 = ',2I8,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICOMLC,ICOML2
   72   FORMAT('ICOMLC,ICOML2 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)(IANS(I),I=1,MIN(80,IWIDTH))
   73   FORMAT('(IANS(I),I=1,IWIDTH) = ',80A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,74)(IANSLC(I),I=1,MIN(80,IWIDTH))
   74   FORMAT('(IANSLC(I),I=1,IWIDTH) = ',80A1)
        CALL DPWRST('XXX','BUG ')
        DO 75 I=1,NUMNAM
          WRITE(ICOUT,76)I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I)
   76     FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I) = ',   &
                 I8,2X,A4,2X,A4,2X,A4,I8,E15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,77)I,IHARLC(I),IHARL2(I)
   77     FORMAT('I,IHARLC(I),IHARL2(I) = ',I8,2X,A4,2X,A4)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 80 I=1,NUMNAM
          WRITE(ICOUT,81)I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),   &
                         VALUE(I)
   81     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),',   &
                 'VALUE(I) = ',I8,2X,A4,2X,A4,2X,A4,I8,E15.7)
          CALL DPWRST('XXX','BUG ')
   80   CONTINUE
!
      ENDIF
!
!               *************************************************
!               **  STEP 1--                                   **
!               **  IF ENTRY IS FROM OUTSIDE THIS SUBROUTINE,  **
!               **  THEN INCREMENT THE LOOP LINE NUMBER        **
!               **  WHICH SPECIFIES WHICH LINE OF THE LOOP     **
!               **  WILL BE EXAMINED AND EXECUTED.             **
!               *************************************************
!
      ILOOLI=ILOOLI+1
!
!               **********************************************
!               **  STEP 2--                                **
!               **  COPY THE STORED LINE BACK INTO IANS(.)  **
!               **********************************************
!
 1200 CONTINUE
!
      ISTEPN='2'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1230 J=1,MAXCIL
        IANS(J)='    '
        IANSLC(J)='    '
 1230 CONTINUE
!
      IWIDTH=IWIDLL(ILOOLI)
      DO 1250 J=1,IWIDTH
        IANSLC(J)=IANSLO(ILOOLI,J)
 1250 CONTINUE
      CALL DPUPPE(IANSLC,IWIDTH,IANS,IBUGLO,IERROR)
!
      IF(IBUGLO.EQ.'ON' .OR. ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1261)
 1261   FORMAT('--------------------')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1262)ILOOLI
 1262   FORMAT('CURRENT LINE NUMBER ILOOLI = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1263)(IANSLC(I),I=1,MIN(IWIDTH,80))
 1263   FORMAT('(IANSLC(I),I=1,80) = ',80A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************
!               **  STEP 3--                            **
!               **  EXTRACT THE COMMAND NAME AND        **
!               **  SEPARATE OUT THE VARIOUS ARGUMENTS  **
!               ******************************************
!
      ISTEPN='3'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPTYPE(IANSLC,IWIDTH,IBUGTY,   &
                  ICOM,ICOM2,ICOMT,ICOMI,ACOM,ICOMLC,ICOML2,   &
                  IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                  IHARG,IHARG2,IARGT,IARG,ARG,IHARLC,IHARL2,NUMARG,   &
                  IHOST1,IHOST2)
!
!               ******************************************
!               **  STEP 4--                            **
!               **  SEARCH FOR LOOP COMMAND             **
!               **  AND BRANCH ACCORDINGLY;             **
!               **  SEARCH FOR END OF LOOP COMMAND      **
!               **  AND BRANCH ACCORDINGLY;             **
!               **  IF NEITHER, THEN JUMP TO EXIT       **
!               **              FOR NORMAL PROCESSING.  **
!               ******************************************
!
!
      ISTEPN='4'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,1401)ICOM,ILOOLI
 1401   FORMAT('ICOM,ILOOLI = ',A4,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!  BUG FIX: ALLOW IF COMMANDS TO BE NESTED WITHIN LOOP (AUGUST, 1987)
!           SO SPECIFICALLY CHECK FOR "END LOOP" TO AVOID CONFLICT
!           WITH "END IF"
!  FEBRUARY 1994.  BREAK LOOP COMMAND.
!
      IF(ICOM.EQ.'LOOP')THEN
        GO TO 1400
!
!               *************************************************
!               **  STEP 6--                                   **
!               **  TREAT THE CASE WHEN COMMAND = END OF LOOP  **
!               **  NUMENE = NUMBER OF    END OF LOOP          **
!               **  COMMANDS ENCOUNTERED                       **
!               *************************************************
!
      ELSEIF(   &
        (ICOM.EQ.'END'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LOOP') .OR.   &
        (ICOM.EQ.'END'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'LOOP'))THEN
        ISTEPN='6'
        IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        NUMENE=NUMENE+1
        ILOOEP(NUMLOE)=ILOOLI
        GO TO 1700
      ELSEIF(ICOM.EQ.'BREA'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LOOP')THEN
        IF(IIFSW.EQ.'TRUE')THEN
          IF(NUMIF.GT.0)NUMIF=NUMIF-1
          GO TO 1700
        ELSE
          GO TO 9000
        ENDIF
      ELSEIF(ICOM.EQ.'CONT'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LOOP')THEN
!
!       TREAT "CONTINUE LOOOP" AS ESSENTIALLY EQUIVALENT TO "END LOOP".
!       HOWEVER, HAVE TO TWEAK VARIOUS SETTINGS APPROPRIATELY.
!
!       CONTINUE LOOP JUST GOES TO THE NEXT ITERATION OF THE LOOP
!
        IF(IIFSW.EQ.'TRUE')THEN
          ILOOLI=ILOOSP(NUMENE)
          GO TO 1700
        ELSE
          GO TO 9000
        ENDIF
      ENDIF
      GO TO 9000
!
!               **********************************************
!               **  STEP 4.1--                              **
!               **  TREAT THE CASE WHEN THE COMMAND = LOOP  **
!               **  NUMLOE = NUMBER OF    LOOP   COMMANDS   **
!               **  ENCOUNTERED                             **
!               **********************************************
!
 1400 CONTINUE
      ISTEPN='4.1'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMLOE=NUMLOE+1
      IF(NUMLOE.GT.MAXLOO)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1301)
 1301   FORMAT('****** ERROR IN LOOP COMMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1302)MAXLOO
 1302   FORMAT('       MAXIMUM NUMBER OF NESTED LOOPS (',I3,   &
               ') EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
        NUMLOE=NUMLOE-1
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     OCTOBER 2018: SAVE THE CURRENT "IF LEVEL" FOR THIS NESTING
!                   LEVEL OF THE LOOP
!
      ILOOIF(NUMLOE)=NUMIF
!
!     DECEMBER 2006: WHEN IF SWITCH IS FALSE, DO NOT
!                    PROCESS LOOP COMMAND.
!
      IF(IIFSW.EQ.'FALS')GO TO 9000
!
!               *********************************************
!               **  STEP 4.2--                             **
!               **  SEARCH FOR FIRST OCCURRANCE OF    FOR  **
!               *********************************************
!
      ISTEPN='4.2'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,1413)ILOOLI,NUMLOE,ILOOIF(NUMLOE)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      JMAX=NUMARG-1
      DO 1405 J=1,JMAX
        J2=J
        JP1=J+1
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    '.AND.   &
           IHARG(JP1).EQ.'I   '.AND.IHARG2(JP1).EQ.'   ')GO TO 1430
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 1450
 1405 CONTINUE
      GO TO 1410
!
!               **********************************************
!               **  STEP 4.3A--                             **
!               **  TREAT THE CASE WHERE   FOR   NOT FOUND  **
!               **********************************************
!
 1410 CONTINUE
      ISTEPN='4.3A'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      KMIN=1
      ASTART=KMIN
      KDEL=1
      AINC=KDEL
      KMAX=1
      ASTOP=KMAX
      NUMINC=1
!
      IHPN='I   '
      IHPN2='    '
      IHPNV(NUMLOE)=IHPN
      IHPNV2(NUMLOE)=IHPN2
      ASTARV(NUMLOE)=ASTART
      AINCV(NUMLOE)=AINC
      ASTOPV(NUMLOE)=ASTOP
      ILOOSP(NUMLOE)=ILOOLI
      NUMLOI(NUMLOE)=NUMINC
!
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1412)
 1412   FORMAT('THIS IS THE    NO FOR    CASE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1413)ILOOLI,NUMLOE,ILOOIF(NUMLOE)
 1413   FORMAT('ILOOLI,NUMLOE,ILOOIF(NUMLOE) = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1414)IHPNV(NUMLOE),IHPNV2(NUMLOE)
 1414   FORMAT('IHPNV(NUMLOE),IHPNV2(NUMLOE) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1415)ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE)
 1415   FORMAT('ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE) = ',   &
               3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1416)ILOOSP(NUMLOE),ILOOEP(NUMLOE)
 1416   FORMAT('ILOOSP(NUMLOE),ILOOEP(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1417)NUMLOI(NUMLOE),ILOOIT(NUMLOE)
 1417   FORMAT('NUMLOI(NUMLOE),ILOOIT(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 1490
!
!               **********************************
!               **  STEP 4.3B--                 **
!               **  TREAT THE    FOR I    CASE  **
!               **********************************
!
 1430 CONTINUE
      ISTEPN='4.3B'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      JP3=JP1+2
      JP4=JP1+3
      JP5=JP1+4
      KMIN=1
      IF(JP3.LE.NUMARG)KMIN=IARG(JP3)
      ASTART=KMIN
      KDEL=1
      IF(JP4.LE.NUMARG)KDEL=IARG(JP4)
      AINC=KDEL
      KMAX=KMIN
      IF(JP5.LE.NUMARG)KMAX=IARG(JP5)
      ASTOP=KMAX
      NUMINC=((KMAX-KMIN)/KDEL)+1
!
      IHPN='I   '
      IHPN2='    '
      IHPNV(NUMLOE)=IHPN
      IHPNV2(NUMLOE)=IHPN2
      ASTARV(NUMLOE)=ASTART
      AINCV(NUMLOE)=AINC
      ASTOPV(NUMLOE)=ASTOP
      ILOOSP(NUMLOE)=ILOOLI
      NUMLOI(NUMLOE)=NUMINC
!
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1432)
 1432   FORMAT('THIS IS THE    FOR I    CASE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1433)ILOOLI
 1433   FORMAT('ILOOLI = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1434)IHPNV(NUMLOE),IHPNV2(NUMLOE)
 1434   FORMAT('IHPNV(NUMLOE),IHPNV2(NUMLOE) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1435)ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE)
 1435   FORMAT('ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE) = ',   &
               3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1436)ILOOSP(NUMLOE),ILOOEP(NUMLOE)
 1436   FORMAT('ILOOSP(NUMLOE),ILOOEP(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1437)NUMLOI(NUMLOE),ILOOIT(NUMLOE)
 1437   FORMAT('NUMLOI(NUMLOE),ILOOIT(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 1490
!
!               *******************************************
!               **  STEP 4.3C--                          **
!               **  TREAT THE     GENERAL FOR      CASE  **
!               *******************************************
!
 1450 CONTINUE
      ISTEPN='4.3C'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      IFOLOC=J2
      ILALOC=IFOLOC-1
!
      IF(IPRINT.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      DO 1460 ITER=1,1000
        IFOLOC=ILALOC+1
        J=IFOLOC
        JP1=J+1
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    '.AND.   &
           IHARG(JP1).EQ.'I   '.AND.IHARG2(JP1).EQ.'   ')GO TO 1480
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 1470
        GO TO 1490
 1470 CONTINUE
!
      CALL DPEXS2(IFOLOC,IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
      IANS,IWIDTH,   &
      IHPN,IHPN2,ASTART,AINC,ASTOP,NUMINC,ILALOC,IBUGLO,IFOUNF,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IFOUNF='YES'
        GO TO 9000
      ENDIF
!
      IF(IFOUNF.EQ.'NO')GO TO 1490
      IHPNV(NUMLOE)=IHPN
      IHPNV2(NUMLOE)=IHPN2
      ASTARV(NUMLOE)=ASTART
      AINCV(NUMLOE)=AINC
      ASTOPV(NUMLOE)=ASTOP
      ILOOSP(NUMLOE)=ILOOLI
      NUMLOI(NUMLOE)=NUMINC
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1472)
 1472   FORMAT('THIS IS THE    GENERAL FOR    CASE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1473)ILOOLI
 1473   FORMAT('ILOOLI = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1474)IHPNV(NUMLOE),IHPNV2(NUMLOE)
 1474   FORMAT('IHPNV(NUMLOE),IHPNV2(NUMLOE) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1475)ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE)
 1475   FORMAT('ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE) = ',   &
               3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1476)ILOOSP(NUMLOE),ILOOEP(NUMLOE)
 1476   FORMAT('ILOOSP(NUMLOE),ILOOEP(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1477)NUMLOI(NUMLOE),ILOOIT(NUMLOE)
 1477   FORMAT('NUMLOI(NUMLOE),ILOOIT(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
 1460 CONTINUE
!
 1480 CONTINUE
!
!               ***************************************
!               **  STEP 4.4--                       **
!               **  WRITE OUT A MESSAGE INDICATING   **
!               **  THE TOTAL NUMBER OF ITERATIONS.  **
!               ***************************************
!
 1490 CONTINUE
      ISTEPN='4.4'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IPROD=1
      IF(NUMLOE.GT.0)THEN
        DO 1491 I=1,NUMLOE
          IPROD=IPROD*NUMLOI(I)
 1491   CONTINUE
      ENDIF
!
      NUMLAP=IPROD
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,1496)NUMLOI(NUMLOE),IPROD
 1496   FORMAT('NUMLOI(NUMLOE),IPROD = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ILOOIT(NUMLOE)=0
      GO TO 1700
!
!               *************************************************
!               **  STEP 7.1--                                 **
!               **  FOR BOTH THE    LOOP   COMMAND,            **
!               **  AND THE   END OF LOOP   COMMAND,           **
!               **  COMPUTE THE NEXT VALUE FOR THIS PARAMETER  **
!               *************************************************
!
 1700 CONTINUE
      ISTEPN='7.1'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILOOIT(NUMLOE)=ILOOIT(NUMLOE)+1
      ITER=ILOOIT(NUMLOE)
      AITER=ITER
      PV=ASTARV(NUMLOE)+(AITER-1.0)*AINCV(NUMLOE)
      N1=NUMLOI(NUMLOE)
!CCCC IF(ITER.EQ.N1)PV=ASTOPV(NUMLOE)       APRIL 27, 1987
!  FIX AUGUST, 1987
!  LOOP GETS INCREMENTED ONCE PAST LAST VALUE. ADJUST STOP VALUE
!  SO THAT WHEN EXIT LOOP, HAS LAST "GOOD" VALUE
      IF(ITER.GT.N1)PV=PV-AINCV(NUMLOE)
!  END FIX
!CCCC ADD FOLLOWING BLOCK FOR BREAK LOOP COMMAND.  FEBRUARY 1994.
      IF(ICOM.EQ.'BREA'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LOOP')THEN
        ITER=N1+1
        PV=PV-AINCV(NUMLOE)
      END IF
!CCCC JANUARY 2005: IF HAVE SOMETHING LIKE
!CCCC
!CCCC                   LOOP FOR K = 3 1 2
!CCCC
!CCCC               THEN WE WANT TO TERMINATE LOOP WITHOUT
!CCCC               EXECUTING IT.
!
      IF(AINCV(NUMLOE).GT.0)THEN
        IF(ASTOPV(NUMLOE).LT.ASTARV(NUMLOE))THEN
          ITER=N1+1
          PV=ASTARV(NUMLOE)
        ENDIF
      ELSEIF(AINCV(NUMLOE).LT.0)THEN
        IF(ASTOPV(NUMLOE).GT.ASTARV(NUMLOE))THEN
          ITER=N1+1
          PV=ASTARV(NUMLOE)
        ENDIF
      ENDIF
!
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(ICOM.EQ.'END')THEN
          WRITE(ICOUT,1712)
 1712     FORMAT('AN    END OF LOOP   LINE HAS BEEN ENCOUNTERED')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,1713)NUMLOE,ILOOLI,ICOM
 1713   FORMAT('NUMLOE,ILOOLI,ICOM = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1714)IHPNV(NUMLOE),IHPNV2(NUMLOE)
 1714   FORMAT('IHPNV(NUMLOE),IHPNV2(NUMLOE) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1715)ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE)
 1715   FORMAT('ASTARV(NUMLOE),AINCV(NUMLOE),ASTOPV(NUMLOE) = ',   &
               3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1716)ILOOSP(NUMLOE),ILOOEP(NUMLOE)
 1716   FORMAT('ILOOSP(NUMLOE),ILOOEP(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1717)NUMLOI(NUMLOE),ILOOIT(NUMLOE)
 1717   FORMAT('NUMLOI(NUMLOE),ILOOIT(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1718)ITER,N1,PV
 1718   FORMAT('ITER,N1,PV = ',I8,I8,E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 7.2--                        **
!               **  FOR BOTH THE    LOOP   COMMAND,   **
!               **  AND THE   END OF LOOP   COMMAND,  **
!               **  DEFINE THE NEXT LINE OF THE LOOP  **
!               **  TO BE EXAMINED                    **
!               ****************************************
!
      ISTEPN='7.2'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        WRITE(ICOUT,1705)ILOOLI,ITER,N1,NUMLOE
 1705   FORMAT('ILOOLI,ITER,N1,NUMLOE = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1706)ILOOSP(NUMLOE),ILOOEP(NUMLOE)
 1706   FORMAT('ILOOSP(NUMLOE),ILOOEP(NUMLOE) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ILOOLI=ILOOSP(NUMLOE)+1
      IF(ITER.GT.N1)ILOOLI=ILOOEP(NUMLOE)+1
!
!CCCC ADD FOLLOWING BLOCK FOR BREAK LOOP COMMAND.  FEBRUARY 1994.
!CCCC BUG.  BREAK LOOP NORMALLY IN IF BLOCK, WHEN THERE IS ERROR
!CCCC IN IF STATEMENT (OR THERE IS NO IF), THEN GET SEG FAULT
!CCCC BECAUSE ILOOEP NOT YET DEFINED (I.E., BREAK LOOP ENCOUNTERED
!CCCC BEFORE END OF LOOP, NEED AT LEAST ONE ITERATION THROUGH LOOP).
!
!CCCC IF(ILOOEP(NUMLOE).GT.0)THEN
        IF(ICOM.EQ.'BREA'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LOOP')THEN
          ILOOLI=ILOOEP(NUMLOE)+1
        END IF
!CCCC ELSE
!CCCC ENDIF
!  BUG FIX: AUGUST, 1987 FOLLOWING 2 LINES MOVED TO CORRECT PROBLEM
!  WITH NESTED LOOPS.  FOR NESTED LOOPS, VALUE OF INNER LOOP IS ASSIGNED
!  TO OUTER LOOP
!  DR. FILLIBEN CORRECTED PROBLEM ELSEWHERE.  UNCOMMENT THIS FIX
!
!CCCC IF(ITER.GT.N1)NUMLOE=NUMLOE-1
!CCCC IF(ITER.GT.N1)NUMENE=NUMENE-1
!
!               *******************************************
!               **  STEP 7.3--                           **
!               **  FOR BOTH THE    LOOP   COMMAND,      **
!               **  AND THE   END OF LOOP   COMMAND,     **
!               **  IF THE NEXT LINE TO BE EXAMINED IS   **
!               **  BEYOND THE LOOP TABLE, THEN          **
!               **  THE LOOPING IS COMPLETED--           **
!               **  BRANCH TO RESET ALL LOOP VARIABLES.  **
!               *******************************************
!
      ISTEPN='7.3'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC BUG FIX.  ADD FOLLOWING LINE.     JANUARY 1999.
!CCCC BUG IS IF NO IF AROUND BREAK LOOP (WHICH ALSO OCCURS
!CCCC IF THERE IS AN ERROR IN THE IF)
      IF(ILOOLI.LT.0)GO TO 1800
      IF(ILOOLI.GT.NUMLIL)GO TO 1800
!
!               ********************************************
!               **  STEP 7.4--                            **
!               **  FOR BOTH THE    LOOP   COMMAND,       **
!               **  AND THE   END OF LOOP   COMMAND,      **
!               **  ENTER THE TERMPORARY VALUE FOR        **
!               **  FOR THE LOOP PARAMETER                **
!               **  INTO THE PERMANENT INTERNAL DATAPLOT  **
!               **  NAME TABLE.                           **
!               ********************************************
!
!
      ISTEPN='7.4'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ****************************************************
!               **  STEP 7.5--                                    **
!               **  IS THIS A LOOP COMMAND?                       **
!               **  IF SO, SEARCH THE INTERNAL DATAPLOT           **
!               **  NAME TABLE FOR THE PARAMETER NAME.            **
!               **  IF NOT, THEN THE NAME SHOULD ALREADY HAVE     **
!               **  BEEN ENTERED                                  **
!               **  INTO THE INTERNAL DATAPLOT NAME TABLE.        **
!               ****************************************************
!
      ISTEPN='7.5'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC IF(ITER.LE.1)GO TO 1720
      IF(ICOM.EQ.'LOOP')GO TO 1720
      GO TO 1760
!
 1720 CONTINUE
!
      IH=IHPNV(NUMLOE)
      IH2=IHPNV2(NUMLOE)
      IF(NUMNAM.LE.0)GO TO 1729
      DO 1725 J1=1,NUMNAM
        J12=J1
        IF(IH.EQ.IHNAME(J1).AND.IH2.EQ.IHNAM2(J1))THEN
          ILOCPN(NUMLOE)=J12
          GO TO 1760
        ENDIF
 1725 CONTINUE
 1729 CONTINUE
      IF(NUMNAM.GE.MAXNAM)THEN
!
        WRITE(ICOUT,1731)
 1731   FORMAT('***** ERROR IN LOOP EXECUTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1732)
 1732   FORMAT('      THE NUMBER OF DATAPLOT NAMES HAS JUST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1734)MAXNAM
 1734   FORMAT('      EXCEEDED THE ALLOWABLE MAXIMUM OF ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1735)
 1735   FORMAT('      THIS OCCURRED IN ATTEMPTING TO ENTER ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1736)IH,IH2
 1736   FORMAT('      THE PARAMETER NAME ',A4,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1737)
 1737   FORMAT('      INTO THE INTERNAL DATAPLOT NAME LIST.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1738)
 1738   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1739)(IANS(I),I=1,MIN(100,IWIDTH))
 1739   FORMAT('      ',100A1)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 7.6--                            **
!               **  ENTER LOOP PARAMETER VALUE            **
!               **  INTO PERMANENT INTERNAL DATAPLOT      **
!               **  NAME TABLE.                           **
!               **  TREAT THE CASE WHERE COMMAND = LOOP   **
!               **  AND PARAMETER NAME NOT YET EXIST      **
!               **  IN GENERAL DATAPLOT NAME TABLE.       **
!               ********************************************
!
      ISTEPN='7.6'
      IF(ISUBRO.EQ.'LOEX')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMNAM=NUMNAM+1
      J12=NUMNAM
      ILOCPN(NUMLOE)=J12
      IHNAME(J12)=IH
      IHNAM2(J12)=IH2
      IUSE(J12)='P'
!
      VALUE(J12)=PV
      IVALUE(J12)=INT(PV+0.5)
!CCCC ADD FOLLOWING LINE FOR DELETE IN LOOP BUG.  FEBRUARY 1994.
      IN(J12)=1
      GO TO 1780
!
!               ****************************************
!               **  STEP 7.7--                        **
!               **  ENTER LOOP PARAMETER VALUE        **
!               **  INTO PERMANENT INTERNAL DATAPLOT  **
!               **  NAME TABLE.                       **
!               **  TREAT THE CASE WHERE COMMAND = LOOP*
!               **  OR COMMAND = END OF LOOP, AND     **
!               **  PARAMETER NAME ALREADY IN TABLE.  **
!               ****************************************
!
 1760 CONTINUE
      ISTEPN='7.7'
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,1761)J12,PV
 1761   FORMAT('J12,PV = ',I8,E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC IF(ITER.GT.N1)GO TO 1780
!
!CCCC AUGUST 2007: NOTE THAT IF THERE IS A DELETE IN THE
!CCCC              LOOP, THIS CHANGES THE LOCATION OF THE
!CCCC              LOOP INDEX PARAMETER IN THE NAME TABLE.
!CCCC              SO OBTAIN CURRENT POSITION JUST TO BE SURE.
!
                                                                                                                                  
      IH=IHPNV(NUMLOE)
      IH2=IHPNV2(NUMLOE)
      DO 1775 J1=1,NUMNAM
        J12=J1
        IF(IH.EQ.IHNAME(J1).AND.IH2.EQ.IHNAM2(J1))THEN
          ILOCPN(NUMLOE)=J12
          GO TO 1779
        ENDIF
 1775 CONTINUE
      J12=ILOCPN(NUMLOE)
 1779 CONTINUE
!
      VALUE(J12)=PV
      IVALUE(J12)=INT(PV+0.5)
!CCCC ADD FOLLOWING LINE FOR DELETE IN LOOP BUG.  FEBRUARY 1994.
      IN(J12)=1
!
!     BUG FIX: WRONG LOOP PARAMETER WAS SET
!     FOLLOWING 2 LINES MOVED FROM ELSEWHERE IN THE ROUTINE
!     DR. FILLIBEN FIXED PROBLEM ELSEWHERE 9/87, COMMENT OUT MY
!     CHANGE.
!
      IF(ITER.GT.N1)THEN
        IF(NUMLOE.GE.1)ILOOIF(NUMLOE)=0
        NUMLOE=NUMLOE-1
        NUMENE=NUMENE-1
      ENDIF
!  END FIX
      GO TO 1780
!
 1780 CONTINUE
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,1781)ITER,N1,J12,PV
 1781   FORMAT('ITER,N1,J12,PV = ',3I8,E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1782)J12,IVALUE(J12),VALUE(J12)
 1782   FORMAT('J12,IVALUE(J12),VALUE(J12) = ',I8,I8,E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1783)NUMLOE
 1783   FORMAT('NUMLOE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1784)NUMLOI(1)
 1784   FORMAT('NUMLOI(1) = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1785)ASTARV(1),AINCV(1),ASTOPV(1)
 1785   FORMAT('ASTARV(1),AINCV(1),ASTOPV(1) = ',3E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 1200
!
!               ***********************************************
!               **  STEP 7.10--                              **
!               **  THE EXECUTION OF ALL LOOPS IS COMPLETED; **
!               **  RESET LOOPING VARIABLES.                 **
!               ***********************************************
!
 1800 CONTINUE
      ILOOST='OFF'
      ILOOLI=0
      NUMLIL=0
      NUMLOE=0
      NUMENE=0
!
      DO 1810 I=1,10
        IHPNV(I)='    '
        IHPNV2(I)='    '
        ILOCPN(I)=-99
        ASTARV(I)=-99.0
        AINCV(I)=-99.0
        ASTOPV(I)=-99.0
        NUMLOI(I)=0
        ILOOIT(I)=0
        ILOOSP(I)=-99
        ILOOEP(I)=-99
 1810 CONTINUE
!
      DO 1820 I=1,25
        IWIDLL(I)=0
        DO 1830 J=1,MAXCIL
          IANSLO(I,J)='    '
 1830   CONTINUE
 1820 CONTINUE
!
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOEX')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOEX--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGLO,IBUGTY,IERROR
 9012   FORMAT('IBUGLO,IBUGTY,IERROR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ILOOST,ILOOLI,NUMLIL,NUMLOE,NUMENE
 9013   FORMAT('ILOOST,ILOOLI,NUMLIL,NUMLOE,NUMENE = ',A4,4I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,10
          WRITE(ICOUT,9016)I,IHPNV(I),IHPNV2(I),ILOCPN(I),ILOOSP(I),   &
                           ILOOEP(I)
 9016     FORMAT('I,IHPNV(I),IHPNV2(I),ILOCPN(I),ILOOSP(I),',   &
                 'ILOOEP(I) =',I8,2X,A4,2X,A4,I8,I8,I8)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,10
          WRITE(ICOUT,9021)I,ASTARV(I),AINCV(I),ASTOPV(I),NUMLOI(I),   &
                           ILOOIT(I)
 9021     FORMAT('I,ASTARV(I),AINCV(I),ASTOPV(I),NUMLOI(I),',   &
                 'ILOOIT(I) =',I8,3E15.7,2I8)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 9025 I=1,NUMLIL
          WRITE(ICOUT,9026)I,IWIDLL(I)
 9026     FORMAT('I,IWIDLL(I) = ',I8,I8)
          CALL DPWRST('XXX','BUG ')
          JMAX=IWIDLL(I)
          WRITE(ICOUT,9027)(IANSLO(I,J),J=1,MIN(80,JMAX))
 9027     FORMAT('(IANSLO(I,J),J=1,JMAX) = ',80A1)
          CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 9040 I=1,NUMNAM
          WRITE(ICOUT,9041)I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),   &
                           VALUE(I)
 9041     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),',   &
                 'VALUE(I) = ',I8,2X,A4,2X,A4,2X,A4,I8,E15.7)
          CALL DPWRST('XXX','BUG ')
 9040   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOEX
      SUBROUTINE DPLODG(IHARG,IARGT,ARG,NUMARG,   &
      ALOWDG,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE DEGREE (1 FOR LINEAR, 2 FOR QUADRATIC)
!              TO BE USED FOR THE LOWESS SMOOTHER.
!              THE SPECIFIED LOWESS DEGREE VALUE WILL BE PLACED
!              IN THE FLOATING POINT VARIABLE ALOWDG.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!     OUTPUT ARGUMENTS--ALOWDG  (A  FLOATING POINT VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/3
!     ORIGINAL VERSION--MARCH     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 9000
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'=')GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'DEGR')GO TO 1110
      IF(IHARG(NUMARG).EQ.'?')GO TO 8100
      GO TO 9000
!
 1110 CONTINUE
      IF(IHARG(NUMARG).EQ.'DEGR')GO TO 1150
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1160
      GO TO 1120
!
 1120 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,1121)
 1121 FORMAT('***** ERROR IN DPLODG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('      ILLEGAL FORM FOR LOWESS DEGREE COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1130)
 1130 FORMAT('      THE ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)
 1131 FORMAT('          LOWESS DEGREE 1 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('          LOWESS DEGREE 2 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      THE DEFAULT DEGREE IS 1 (= LINEAR LOWESS)')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1150 CONTINUE
      HOLD=1.0
      GO TO 1180
!
 1160 CONTINUE
      HOLD=ARG(NUMARG)
      IF(HOLD.LE.1.5)HOLD=1.0
      IF(HOLD.GT.1.5)HOLD=2.0
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      ALOWDG=HOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1281)ALOWDG
 1281 FORMAT('THE LOWESS DEGREE HAS JUST BEEN SET ',   &
      'TO ',F10.4)
 1289 CONTINUE
      GO TO 9000
!
!               ********************************************
!               **  STEP 81--                             **
!               **  TREAT THE    ?    CASE--              **
!               **  DUMP OUT CURRENT AND DEFAULT VALUES.  **
!               ********************************************
!
 8100 CONTINUE
      IFOUND='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8111)ALOWDG
 8111 FORMAT('THE CURRENT LOWESS DEGREE    IS ',F10.4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8121)
 8121 FORMAT('THE DEFAULT LOWESS DEGREE    IS 1.0')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLODG
      SUBROUTINE DPLOFR(IHARG,IARGT,ARG,NUMARG,   &
      ALOWFR,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE FRACTION (0.0 TO 1.0).
!              TO BE USED FOR THE LOWESS SMOOTHER.
!              THE SPECIFIED LOWESS FRACTION VALUE WILL BE PLACED
!              IN THE FLOATING POINT VARIABLE ALOWFR.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!     OUTPUT ARGUMENTS--ALOWFR  (A  FLOATING POINT VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/1
!     ORIGINAL VERSION--DECEMBER 1988.
!     UPDATED         --NOVEMBER  1989.  CHECK LOWESS FRACTION 0 TO 1
!     UPDATED         --NOVEMBER  1989.  LOWESS FRACTION DEFAULT TO .1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 9000
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'=')GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FRAC')GO TO 1110
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'DECI')GO TO 1110
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'PROP')GO TO 1110
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'PERC')GO TO 1110
      IF(IHARG(NUMARG).EQ.'?')GO TO 8100
      GO TO 9000
!
 1110 CONTINUE
      IF(IHARG(NUMARG).EQ.'FRAC')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DECI')GO TO 1150
      IF(IHARG(NUMARG).EQ.'PROP')GO TO 1150
      IF(IHARG(NUMARG).EQ.'PERC')GO TO 1150
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1160
      GO TO 1120
!
 1120 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,1121)
 1121 FORMAT('***** ERROR IN DPLOFR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('      ILLEGAL FORM FOR LOWESS FRACTION/',   &
      'DECIMAL/PROPORTION/PERCENTAGE COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1124)
 1124 FORMAT('      EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('      SUPPOSE THE THE ANALYST IS CARRYING OUT  ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('      A LOWESS SMOOTH, ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)
 1127 FORMAT('      AND SUPPOSE THE ANALYST WISHES THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1128)
 1128 FORMAT('      SMOOTHING WINDOW TO BE 20% OF THE X-WIDTH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1130)
 1130 FORMAT('      THEN THE ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)
 1131 FORMAT('          LOWESS FRACTION .2 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('          LOWESS DECIMAL .2 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1133)
 1133 FORMAT('          LOWESS PROPORTION 20 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('          LOWESS PERCENTAGE 20 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      THE DEFAULT FRACTION IS .5 (= 50%)')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1150 CONTINUE
!CCCC THE FOLLOWING LINE WAS CHANGED NOVEMBER 1989
!CCCC HOLD=.5
      HOLD=.1
      GO TO 1180
!
 1160 CONTINUE
      HOLD=ARG(NUMARG)
      IF(IHARG(1).EQ.'PROP')HOLD=HOLD/100.0
      IF(IHARG(1).EQ.'PERC')HOLD=HOLD/100.0
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      ALOWFR=HOLD
!CCCC THE FOLLOWING LINE WAS INSERTED NOVEMBER 1989
      ALOWPR=100.0*ALOWFR
!
!CCCC THE FOLLOWING SECTION WAS INSERTED NOVEMBER 1989
!               **************************************************
!               **  CHECK THAT THE LOWESS FRACTION              **
!               **  IS BETWEEN 0 AND 1 (EXCLUSIVELY)            **
!               **************************************************
!
      IF(IHARG(1).EQ.'FRAC')GO TO 1210
      IF(IHARG(1).EQ.'DECI')GO TO 1210
      GO TO 1229
 1210 CONTINUE
      IF(ALOWFR.GT.0.0.AND.ALOWFR.LE.1.0)GO TO 1229
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1211)
 1211 FORMAT('***** ERROR IN DPLOFR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1212)
 1212 FORMAT('      ILLEGAL INPUT VALUE FOR THE LOWESS FRACTION.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1213)
 1213 FORMAT('      THE LOWESS FRACTION (INDICATING THE SIZE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1214)
 1214 FORMAT('      OF THE LOWESS NEIGHBORHOOD)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('      MUST BE LARGER THAN 0.0 AND SMALLER THAN 1.0.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)
 1216 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1217)ALOWFR
 1217 FORMAT('      THE VALUE OF THE LOWESS FRACTION = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1218)
 1218 FORMAT('      CORRECT THIS VALUE VIA THE    LOWESS FRACTION ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1219)
 1219 FORMAT('      COMMAND, AS IN      LOWESS FRACTION .5')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1229 CONTINUE
!
      IF(IHARG(1).EQ.'PROP')GO TO 1230
      IF(IHARG(1).EQ.'PERC')GO TO 1230
      GO TO 1249
 1230 CONTINUE
      IF(ALOWPR.GT.0.0.AND.ALOWPR.LE.100.0)GO TO 1249
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1231)
 1231 FORMAT('***** ERROR IN DPLOFR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1232)
 1232 FORMAT('      ILLEGAL INPUT VALUE FOR THE LOWESS PROPORTION.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1233)
 1233 FORMAT('      THE LOWESS PROPORTION (INDICATING THE SIZE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1234)
 1234 FORMAT('      OF THE LOWESS NEIGHBORHOOD)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1235)
 1235 FORMAT('      MUST BE LARGER THAN 0 AND SMALLER THAN 100.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1236)
 1236 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1237)ALOWPR
 1237 FORMAT('      THE VALUE OF THE LOWESS PROPORTION = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1238)
 1238 FORMAT('      CORRECT THIS VALUE VIA THE  LOWESS PROPORTION ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1239)
 1239 FORMAT('      COMMAND, AS IN      LOWESS PROPORTION 50')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1249 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      IF(IHARG(1).EQ.'FRAC'.OR.IHARG(1).EQ.'DECI')   &
      WRITE(ICOUT,1281)ALOWFR
 1281 FORMAT('THE LOWESS FRACTION (0.0 TO 1.0) HAS JUST BEEN SET ',   &
      'TO ',F10.4)
      IF(IHARG(1).EQ.'FRAC'.OR.IHARG(1).EQ.'DECI')   &
      CALL DPWRST('XXX','BUG ')
!CCCC THE FOLLOWING 4 LINES WERE INSERTED NOVEMBER 1989
      IF(IHARG(1).EQ.'PROP'.OR.IHARG(1).EQ.'PERC')   &
      WRITE(ICOUT,1282)ALOWPR
 1282 FORMAT('THE LOWESS PROPORTION (0 TO 100) HAS JUST BEEN SET ',   &
      'TO ',F10.4)
      IF(IHARG(1).EQ.'PROP'.OR.IHARG(1).EQ.'PERC')   &
      CALL DPWRST('XXX','BUG ')
 1289 CONTINUE
      GO TO 9000
!
!               ********************************************
!               **  STEP 81--                             **
!               **  TREAT THE    ?    CASE--              **
!               **  DUMP OUT CURRENT AND DEFAULT VALUES.  **
!               ********************************************
!
 8100 CONTINUE
      IFOUND='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8111)ALOWFR
 8111 FORMAT('THE CURRENT LOWESS FRACTION    IS ',F10.4)
      CALL DPWRST('XXX','BUG ')
      ALOWPR=100.0*ALOWFR
      WRITE(ICOUT,8112)ALOWPR
 8112 FORMAT('THE CURRENT LOWESS PROPORTION  IS ',F10.4,' %')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8121)
 8121 FORMAT('THE DEFAULT LOWESS FRACTION    IS 0.1')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8122)
 8122 FORMAT('THE DEFAULT LOWESS PROPORTION  IS 10 %')
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLOFR
      SUBROUTINE DPLORE(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        ISUBRO,IBUGG2,IBUGG3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A LORENZ PLOT.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015/2
!     ORIGINAL VERSION--FEBRUARY  2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IFOUN1
      CHARACTER*4 IFOUN2
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASE
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN0
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION ZY(MAXOBV)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XDESGN(MAXOBV,2)
!
      INCLUDE 'DPCOZZ.INC'
!
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),ZY(1))
      EQUIVALENCE (GARBAG(IGARB3),XTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB4),XTEMP2(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB6),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB7),XIDTE3(1))
      EQUIVALENCE (GARBAG(IGARB8),XDESGN(1,1))
!
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPLO'
      ISUBN2='RE  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
      MAXV2=1
      MINN2=5
!
!               ***************************************************
!               **  TREAT THE LORENZ PLOT                        **
!               ***************************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  EXTRACT THE COMMAND                             **
!               **  LOOK FOR ONE OF THE FOLLOWING COMMANDS:         **
!               **    1) LORENZ PLOT Y                              **
!               **    2) MULTIPLE LORENZ PLOT Y1 ... YK             **
!               **    3) REPLICATED LORENZ PLOT Y X1  X2            **
!               ******************************************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'LORE')GO TO 89
      IF(ICOM.EQ.'MULT')GO TO 89
      IF(ICOM.EQ.'REPL')GO TO 89
      GO TO 9000
!
   89 CONTINUE
      ICASPL='LORE'
      IMULT='OFF'
      IREPL='OFF'
      ILASTC=-9999
!
      IF(ICOM.EQ.'LORE')THEN
        IFOUN1='YES'
      ELSEIF(ICOM.EQ.'MULT')THEN
        IMULT='ON'
      ELSEIF(ICOM.EQ.'REPL')THEN
        IREPL='ON'
      ENDIF
!
      ISTOP=NUMARG-1
      DO 90 I=1,NUMARG
        IF(IHARG(I).EQ.'PLOT' .OR. IHARG(I).EQ.'CURV')THEN
          ISTOP=I
          GO TO 99
        ENDIF
   90 CONTINUE
   99 CONTINUE
!
      IFOUND='NO'
      DO 100 I=1,ISTOP
        IF(IHARG(I).EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(IHARG(I).EQ.'LORE')THEN
          IFOUN1='YES'
          IFOUN2='YES'
          ILASTC=MAX(ILASTC,I)
        ELSEIF(IHARG(I).EQ.'PLOT' .OR. IHARG(I).EQ.'CURV')THEN
          IFOUN2='YES'
          ILASTC=MAX(ILASTC,I)
        ELSEIF(IHARG(I).EQ.'REPL')THEN
          IREPL='ON'
        ELSEIF(IHARG(I).EQ.'MULT')THEN
          IMULT='ON'
        ENDIF
  100 CONTINUE
!
      IF(IFOUN1.EQ.'YES' .AND. IFOUN2.EQ.'YES')IFOUND='YES'
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN LORENZ PLOT--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THE LORENZ PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(ILASTC.GE.1)THEN
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        ILASTC=0
      ENDIF
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'LORE')THEN
        WRITE(ICOUT,112)ICASPL,IMULT,IREPL
  112   FORMAT('ICASPL,IMULT,IREPL = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='LORENZ PLOT'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IF(IMULT.EQ.'ON')IFLAGE=0
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=3
      IF(IREPL.EQ.'ON')THEN
        MINNVA=2
        MAXNVA=3
        IFLAGM=0
      ELSEIF(IMULT.EQ.'ON')THEN
        MINNVA=1
        MAXNVA=30
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      NRESP=0
      NREPL=0
      IF(IREPL.EQ.'OFF' .AND. NUMVAR.GT.1)IMULT='ON'
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,512)
  512     FORMAT('      MUST BE BETWEEN 1 AND 2;  SUCH WAS NOT THE ',   &
                 'CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        NRESP=1
      ENDIF
!
!               ********************************************
!               **  STEP 6--                              **
!               **  GENERATE THE LORENZ PLOTS FOR         **
!               **  THE VARIOUS CASES.                    **
!               ********************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')THEN
        ISTEPN='6'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,601)NRESP,NREPL
  601   FORMAT('NRESP,NREPL = ',2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     INCLUDE A LINE BETWEEN (0,0) AND (1,1) FOR ALL CASES
!
      Y(1)=0.0
      X(1)=0.0
      D(1)=1.0
      Y(2)=1.0
      X(2)=1.0
      D(2)=1.0
      NCURVE=1
      NPLOTP=2
!
!               *************************************************
!               **  STEP 7A--                                  **
!               **  CASE 1: NO REPLICATION CASE                **
!               *************************************************
!
      IF(NREPL.EQ.0)THEN
!
        ISTEPN='7A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        DO 810 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,811)IRESP,NCURVE
  811       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,Y1,Y1,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGG3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************************
!               **  STEP 8B--                                      **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!               *****************************************************
!
          CALL DPLOR2(Y1,NLOCAL,NCURVE,ICASPL,MINN2,GINI,   &
                      Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
          IH='GINI'
          IF(NRESP.EQ.1)THEN
            IH2='    '
          ELSE
            IF(IRESP.LE.9)THEN
              IH2='    '
              WRITE(IH2(1:1),'(I1)')IRESP
            ELSE
              WRITE(IH2(1:2),'(I2)')IRESP
            ENDIF
          ENDIF
          VALUE0=GINI
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGG3,IERROR)
!
  810   CONTINUE
!
!               *****************************************************
!               **  STEP 9A--                                      **
!               **  CASE 3: ONE OR TWO  REPLICATION VARIABLES.     **
!               **          FOR THIS CASE, THE NUMBER OF RESPONSE  **
!               **          VARIABLES MUST BE EXACTLY 1.           **
!               *****************************************************
!
      ELSEIF(NRESP.EQ.1 .AND. NREPL.GE.1)THEN
        ISTEPN='9A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 910 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 910
          J=J+1
!
!         RESPONSE VARIABLE IN Y1
!
          IJ=MAXN*(ICOLR(1)-1)+I
          IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
!
          ICOLC=1
          DO 920 IR=1,MIN(NREPL,2)
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  920     CONTINUE
!
  910   CONTINUE
        NLOCAL=J
!
!       *****************************************************
!       **  STEP 9B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='9B'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,931)
  931     FORMAT('***** FROM THE MIDDLE  OF FREQ--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,932)ICASPL,NUMVAR,NLOCAL
  932     FORMAT('ICASPL,NUMVAR,NQ = ',A4,2I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 935 I=1,NLOCAL
              WRITE(ICOUT,936)I,Y1(I),XDESGN(I,1),XDESGN(I,2)
  936         FORMAT('I,Y1(I),XDESGN(I,1),XDESGN(I,2) = ',I8,3F12.5)
              CALL DPWRST('XXX','BUG ')
  935       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPFRE5(XDESGN(1,1),XDESGN(1,2),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,   &
                   XTEMP1,XTEMP2,   &
                   NUMSE1,NUMSE2,   &
                   IBUGG3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 9D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLOR2(ZY,NTEMP,NCURVE,ICASPL,MINN2,GINI,   &
                          Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
              IH='GINI'
              IF(NCURVE.LE.10)THEN
                IH2='    '
                WRITE(IH2(1:1),'(I1)')NCURVE-1
              ELSE
                WRITE(IH2(1:2),'(I2)')NCURVE-1
              ENDIF
              VALUE0=GINI
              CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                          IANS,IWIDTH,IBUGG3,IERROR)
!
            ENDIF
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLOR2(ZY,NTEMP,NCURVE,ICASPL,MINN2,GINI,   &
                          Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
              IH='GINI'
              IF(NCURVE.LE.10)THEN
                IH2='    '
                WRITE(IH2(1:1),'(I1)')NCURVE-1
              ELSE
                WRITE(IH2(1:2),'(I2)')NCURVE-1
              ENDIF
              VALUE0=GINI
              CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                          IANS,IWIDTH,IBUGG3,IERROR)
!
            ENDIF
 1220     CONTINUE
 1210     CONTINUE
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LORE')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GT.0)THEN
          DO 9015 I=1,NPLOTP
            WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLORE
      SUBROUTINE DPLOR2(Y,N,NCURVE,ICASPL,MINN2,GINI,   &
                        Y2,X2,D2,N2,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE A LORENZ PLOT.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--COBHAM AND SUMNER (2014), "IS INEQUALITY ALL ABOUT THE
!                 TAILS", SIGNIFICANCE, PP. 10-13.
!     VERSION NUMBER--2015/2
!     ORIGINAL VERSION--FEBRUARY  2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLO'
      ISUBN2='R2  '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'LOR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('***** AT THE BEGINNING OF DPLOR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)N,N2,NCURVE
   72   FORMAT('N,N2,NCURVE = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,Y(I)
   74     FORMAT('I, Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.MINN2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN LORENZ PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)MINN2
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST ',   &
               I8,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 60 I=1,N
      IF(Y(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)HOLD
   62 FORMAT('      ALL RESPONSE VALUES ARE IDENTICALLY EQUAL TO ',   &
             G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   69 CONTINUE
!
!               **********************************************
!               **  STEP 2--                                **
!               **  ALGORITHM FOR LORENZ CURVE:             **
!               **     1) SORT THE DATA IN Y                **
!               **     2) X AXIS COORDINATE = i/N           **
!               **     3) Y AXIS COORDINATE = CUSUM/TOTSUM  **
!               **        WHERE:                            **
!               **        CUMSUM=CUMULATIVE SUM OF Y        **
!               **        TOTSUM=SUM OF Y                   **
!               **********************************************
!
      CALL SORT(Y,N,Y)
!
      IF(Y(1).LT.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,203)
  203   FORMAT('      THE RESPONSE VARIABLE CONTAINS NEGATIVE ',   &
               'NUMBERS AND THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,205)
  205   FORMAT('      LORENZ CURVE IS NOT CURRENTLY SUPPORTED FOR ',   &
               'NEGATIVE NUMBERS.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DSUM1=0.0D0
      DO 210 I=1,N
        DSUM1=DSUM1 + DBLE(Y(I))
  210 CONTINUE
!
      NTEMP=0
      N2=N2+1
      NSTART=N2
      Y2(N2)=0.0
      X2(N2)=0.0
      D2(N2)=REAL(NCURVE)
      DSUM2=0.0D0
      DO 220 I=1,N
        DSUM2=DSUM2 + DBLE(Y(I))
        N2=N2+1
        NTEMP=NTEMP+1
        Y2(N2)=REAL(DSUM2/DSUM1)
        X2(N2)=REAL(I)/REAL(N)
        D2(N2)=REAL(NCURVE)
  220 CONTINUE
      N2=N2+1
      NTEMP=NTEMP+1
      Y2(N2)=1.0
      X2(N2)=1.0
      D2(N2)=REAL(NCURVE)
!
      NUMVAR=2
      CALL INTVEC(Y2(NSTART),X2(NSTART),NTEMP,NUMVAR,IWRITE,XYINT,   &
                  IBUGG3,IERROR)
      GINI=0.5 - XYINT
!
      NPLOTV=2
      GO TO 9000
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'LOR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,IERROR,N2,DSUM1,GINI
 9012   FORMAT('ICASPL,IERROR,N2,DSUM1,GINI = ',2(A4,2X),I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N2
          WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I)
 9016     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2G15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOR2
      SUBROUTINE DPLOST(ILOOST,ILOOLI,NUMLIL,NUMLOS,NUMENS,   &
                        IANSLC,IWIDTH,ICOM,IHARG,IHARG2,NUMARG,IANSLO,   &
                        IWIDLL,MAXCIL,MAXLIL,IERRFA,IGUIFL,ICONCH,   &
                        IBUGLO,ISUBRO,IERROR)
!
!     PURPOSE--STORE A COMMAND LINE IN A LOOP FOR FUTURE EXECUTION.
!     ORIGINAL VERSION--DECEMBER  1982
!     UPDATED         --DECEMBER  1988. NO STORAGE OF COMMENT LINES
!     UPDATED         --DECEMBER  1988. RESTORE CONTROL IF MAX LINES
!     UPDATED         --FEBRUARY  1989. FIX IF > 80 COLUMNS (ALAN)
!     UPDATED         --SEPTEMBER 2012. FATAL ERROR LOGIC IF TOO MANY
!                                       LINES
!     UPDATED         --APRIL     2018. SUPPORT "LOOP WHILE"
!     UPDATED         --AUGUST    2020. FOR STORAGE PURPOSES, SET MAXIMIUM
!                                       LENGTH OF STORED LOOP LINE TO
!                                       256 RATHER THAN 1,024.  IN THIS
!                                       ROUTINE, BREAK UP LINES > 256
!                                       CHARACTERS INTO MULTIPLE LINES
!                                       WITH CONTINUATION CHARACTER
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ILOOST
      CHARACTER*4 IANSLC
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IANSLO
      CHARACTER*4 IERRFA
      CHARACTER*4 IGUIFL
      CHARACTER*4 ICASE
      CHARACTER*4 ICONCH
      CHARACTER*4 IBUGLO
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION IANSLC(*)
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
!
      DIMENSION IANSLO(MAXLIL,MAXCIL)
      DIMENSION IWIDLL(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLO'
      ISUBN2='ST  '
!
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOST')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGLO,ISUBRO,IERROR,ILOOST,ICOM
   52   FORMAT('IBUGLO,ISUBRO,IERROR,ILOOST,ICOM = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)NUMLOS,NUMENS,IWIDTH
   54   FORMAT('NUMLOS,NUMENS,IWIDTH = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ILOOLI,NUMLIL,MAXLIL,MAXCIL
   55   FORMAT('ILOOLI,NUMLIL,MAXLIL,MAXCIL = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)(IANSLC(J),J=1,MIN(80,IWIDTH))
   59   FORMAT('(IANSLC(J),J=1,IWIDTH) = ',80A1)
        CALL DPWRST('XXX','BUG ')
        DO 65 I=1,NUMLIL
          WRITE(ICOUT,66)I,IWIDLL(I)
   66     FORMAT('I,IWIDLL(I) = ',I8,I8)
          CALL DPWRST('XXX','BUG ')
          JMAX=IWIDLL(I)
          WRITE(ICOUT,67)(IANSLO(I,J),J=1,MIN(100,JMAX))
   67     FORMAT('(IANSLO(I,J),J=1,JMAX) = ',100A1)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
        DO 75 I=1,NUMLIL
          WRITE(ICOUT,76)I,IHARG(I),IHARG2(I)
   76     FORMAT('I,IHARG(I),IHARG2(I)) = ',I8,2X,2A4)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************************
!               **  STEP 0--                        **
!               **  CHECK LOOP STATUS FOR    STORE  **
!               **  CHECK COMMAND FOR        LOOP   **
!               **  BRANCH ACCORDINGLY.             **
!               **************************************
!
      IF(ICOM.EQ.'LOOP')THEN
!
!               *******************************
!               **  STEP 1--                 **
!               **  TREAT THE CASE WHEN THE  **
!               **  CURRENT COMMAND = LOOP   **
!               *******************************
!
        ISTEPN='1'
        IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOST')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ILOOST='STOR'
        ILOOLI=ILOOLI+1
        IF(ILOOLI.GT.MAXLIL)GO TO 4000
        NUMLIL=ILOOLI
        NUMLOS=NUMLOS+1
        IWIDLL(ILOOLI)=IWIDTH
        JMAX=IWIDTH
!
!       2020/08: BREAK INTO MULTIPLE LINES IF NEEDED
!
        NCONCH=1
        IF(ICONCH(4:4).NE.' ')THEN
          NCONCH=4
        ELSEIF(ICONCH(3:3).NE.' ')THEN
          NCONCH=3
        ELSEIF(ICONCH(2:2).NE.' ')THEN
          NCONCH=2
        ENDIF
!
        IF(JMAX.LE.MAXCIL)THEN
          DO 1050 J=1,JMAX
            IANSLO(ILOOLI,J)=IANSLC(J)
 1050     CONTINUE
        ELSEIF(JMAX.GT.MAXCIL .AND. JMAX.LE.2*MAXCIL)THEN
          JTEMP=MAXCIL-NCONCH
          DO 1051 J=1,JTEMP
            IANSLO(ILOOLI,J)=IANSLC(J)
 1051     CONTINUE
          DO 1052 J=JTEMP+1,JTEMP+NCONCH
            IANSLO(ILOOLI,J)=ICONCH(J:J)
 1052     CONTINUE
          IWIDLL(ILOOLI)=JTEMP+NCONCH
          ILOOLI=ILOOLI+1
          DO 1053 J=JTEMP+1,JMAX
            IANSLO(ILOOLI,J)=IANSLC(J)
 1053     CONTINUE
          IWIDLL(ILOOLI)=JMAX-JTEMP
        ELSEIF(JMAX.GT.2*MAXCIL .AND. JMAX.LE.3*MAXCIL)THEN
          JTEMP=MAXCIL-NCONCH
          DO 1061 J=1,JTEMP
            IANSLO(ILOOLI,J)=IANSLC(J)
 1061     CONTINUE
          DO 1062 J=JTEMP+1,JTEMP+NCONCH
            IANSLO(ILOOLI,J)=ICONCH(J:J)
 1062     CONTINUE
          IWIDLL(ILOOLI)=JTEMP+NCONCH
          ILOOLI=ILOOLI+1
          DO 1063 J=JTEMP+1,2*JTEMP
            IANSLO(ILOOLI,J)=IANSLC(J)
 1063     CONTINUE
          DO 1064 J=2*JTEMP+1,JTEMP+NCONCH
            IANSLO(ILOOLI,J)=ICONCH(J:J)
 1064     CONTINUE
          IWIDLL(ILOOLI)=JTEMP+NCONCH
          ILOOLI=ILOOLI+1
          ICNT=0
          DO 1065 J=2*JTEMP+1,JMAX
            IANSLO(ILOOLI,J)=IANSLC(J)
            ICNT=ICNT+1
 1065     CONTINUE
          IWIDLL(ILOOLI)=ICNT
        ELSEIF(JMAX.GT.3*MAXCIL)THEN
          JTEMP=MAXCIL-NCONCH
          DO 1071 J=1,JTEMP
            IANSLO(ILOOLI,J)=IANSLC(J)
 1071     CONTINUE
          DO 1072 J=JTEMP+1,JTEMP+NCONCH
            IANSLO(ILOOLI,J)=ICONCH(J:J)
 1072     CONTINUE
          IWIDLL(ILOOLI)=JTEMP+NCONCH
          ILOOLI=ILOOLI+1
          DO 1073 J=JTEMP+1,2*JTEMP
            IANSLO(ILOOLI,J)=IANSLC(J)
 1073     CONTINUE
          DO 1074 J=2*JTEMP+1,JTEMP+NCONCH
            IANSLO(ILOOLI,J)=ICONCH(J:J)
 1074     CONTINUE
          IWIDLL(ILOOLI)=JTEMP+NCONCH
          ILOOLI=ILOOLI+1
          DO 1075 J=2*JTEMP+1,3*JTEMP
            IANSLO(ILOOLI,J)=IANSLC(J)
 1075     CONTINUE
          DO 1076 J=3*JTEMP+1,JTEMP+NCONCH
            IANSLO(ILOOLI,J)=ICONCH(J:J)
 1076     CONTINUE
          IWIDLL(ILOOLI)=JTEMP+NCONCH
          ILOOLI=ILOOLI+1
          ICNT=0
          DO 1077 J=3*JTEMP+1,MIN(JMAX,4*MAXCIL)
            IANSLO(ILOOLI,J)=IANSLC(J)
            ICNT=ICNT+1
 1077     CONTINUE
          IWIDLL(ILOOLI)=ICNT
        ENDIF
        GO TO 9000
!
      ELSEIF(ILOOST.EQ.'STOR')THEN
!
!               *******************************
!               **  STEP 2--                 **
!               **  TREAT THE CASE WHEN THE  **
!               **  LOOP STATUS = STORE      **
!               *******************************
!
        ISTEPN='2'
        IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOST')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC   THE FOLLOWING LINE WAS ADDED IN DECEMBER 1988
!CCCC   TO AVOID STORING COMMENT LINES IN A LOOP   (DECEMBER 1988)
!CCCC   AND THEREBY SAVE SOME STORAGE              (DECEMBER 1988)
!
        IF(IWIDTH.GE.1.AND.IANSLC(1).EQ.'.')GO TO 9000
        ILOOLI=ILOOLI+1
        IF(ILOOLI.GT.MAXLIL)GO TO 4000
        NUMLIL=ILOOLI
        IWIDLL(ILOOLI)=IWIDTH
!CCCC   THE FOLLOWING 3 LINES WERE ADDED (FEBRUARY 1989)
!CCCC   TO AVOID PROBLEMS WHEN > 80 COLUMNS  (FEBRUARY 1989)
        JMAX=IWIDTH
        IF(JMAX.GT.MAXCIL)JMAX=MAXCIL
        DO 2050 J=1,JMAX
          IANSLO(ILOOLI,J)=IANSLC(J)
 2050   CONTINUE
!
!               ************************************
!               **  STEP 3--                      **
!               **  TREAT THE CASE WHEN THE       **
!               **  CURRENT COMMAND = END OF LOOP **
!               ************************************
!
        IF(ICOM.EQ.'END')THEN
          IF((NUMARG.GE.1.AND.IHARG(1).EQ.'LOOP') .OR.   &
             (NUMARG.GE.2.AND.IHARG(2).EQ.'LOOP'))THEN
            NUMENS=NUMENS+1
            IF(NUMENS.EQ.NUMLOS)THEN
              ILOOST='EXEC'
              ILOOLI=0
            ELSE
              ILOOST='STOR'
            ENDIF
          ENDIF
          GO TO 9000
        ELSE
          GO TO 9000
        ENDIF
      ELSE
        GO TO 9000
      ENDIF
!
!               ****************************
!               **  STEP 4--              **
!               **  TREAT THE ERROR CASE  **
!               ****************************
!
 4000 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,4011)
 4011 FORMAT('***** ERROR IN LOOP STORE--')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,4012)
 4012 FORMAT('      THE TOTAL NUMBER OF LINES IN ALL NESTED LOOPS')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,4014)MAXLIL
 4014 FORMAT('      HAS JUST EXCEEDED THE ALLOWABLE MAXIMUM (',I8,')')
      CALL DPWRST('XXX','WRIT')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,4015)
 4015   FORMAT('      THE CURRENT LINE BEING PROCESSED IS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,4016)(IANSLC(J),J=1,MIN(80,IWIDTH))
 4016   FORMAT(6X,80A1)
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IERROR='YES'
!
!     2012/09: AT JIM's REQUEST, PROMPT IF YOU WANT TO
!              CONTINUE IF THIS ERROR ENCOUNTERED.
!
      IF(IERROR.EQ.'YES')THEN
        ICASE='LOOP'
        CALL DPERRO(IERRFA,IANSLC,IWIDTH,IGUIFL,   &
                    ISUBN1,ISUBN2,ICASE,   &
                    IBUGLO,ISUBRO,IERROR)
      ENDIF
!
!CCCC THE FOLLOWING 5 LINES WERE ADDED DECEMBER 1988
!CCCC TO GIVE CONTROL BACK TO THE USER (DECEMBER 1988)
!CCCC IN CASE HAVE EXCEEDED MAX NUMBER OF LOOP LINES (DECEMBER 1988)
!
      ILOOST='OFF'
      ILOOLI=0
      NUMLIL=0
      NUMLOS=0
      NUMENS=0
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGLO.EQ.'ON'.OR.ISUBRO.EQ.'LOST')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IERROR,NUMLOS,NUMENS,IWIDTH
 9014   FORMAT('IERROR,NUMLOS,NUMENS,IWIDTH = ',A4,2X,3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)ILOOLI,NUMLIL,MAXLIL,MAXCIL
 9015   FORMAT('ILOOLI,NUMLIL,MAXLIL,MAXCIL = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9019)(IANSLC(J),J=1,MIN(80,IWIDTH))
 9019   FORMAT('(IANSLC(J),J=1,IWIDTH) = ',80A1)
        CALL DPWRST('XXX','BUG ')
        DO 9025 I=1,NUMLIL
          WRITE(ICOUT,9026)I,IWIDLL(I)
 9026     FORMAT('I,IWIDLL(I) = ',I8,I8)
          CALL DPWRST('XXX','BUG ')
          JMAX=IWIDLL(I)
          WRITE(ICOUT,9027)(IANSLO(I,J),J=1,MIN(80,JMAX))
 9027     FORMAT('(IANSLO(I,J),J=1,JMAX) = ',80A1)
          CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOST
      SUBROUTINE DPLOW(ALOWFR,ALOWDG,ICAPSW,IFORSW,   &
                       XTEMP3,XTEMP4,XTEMP1,XTEMP2,MAXNXT,   &
                       IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!CCCC ADD ARGUMENT FOR LOWESS DEGREE.  MARCH 1994.
!
!     PURPOSE--CARRY OUT A LOWESS FIT OF Y ON X.  (USEFUL FOR ADDING A
!              ROBUST SMOOTH LINE TO A SCATTER PLOT)
!     NOTE--ALOWFR IS A NUMBER BETWEEN 0.0 AND 1.0
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/2
!     ORIGINAL VERSION--FEBRUARY  1988.
!     UPDATED         --MARCH     1988. ADD LOFCDF
!     UPDATED         --JANUARY   1988. DECLARE ICTAR1&2 AS CHARACTER
!     UPDATED         --NOVEMBER  1989. ALLOW SINGLE VARIABLE
!     UPDATED         --NOVEMBER  1989. CHECK LOWESS FRACTION 0 TO 1
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --APRIL     1992. COMMENT OUT 2 DEBUG LINES
!     UPDATED         --APRIL     1992. NPLOTP TO NS IN DEBUG SECTION
!     UPDATED         --MARCH     1994. ADD ARGUMENT
!     UPDATED         --FEBRUARY  1999. ADD SEASONAL LOESS
!     UPDATED         --FEBRUARY  2012. USE DPPARS
!     UPDATED         --JANUARY   2024. TWEAK PARSING OF SEASONAL
!                                       LOWESS COMMAND
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IREP
      CHARACTER*4 IREPU
      CHARACTER*4 IRESU
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
      LOGICAL ROBUST
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION W(MAXOBV)
      DIMENSION XTEMP5(MAXOBV)
      DIMENSION XTEMP6(MAXOBV)
      DIMENSION XTEMP7(MAXOBV)
      DIMENSION XWORK(10*MAXOBV)
      DIMENSION PRED2(MAXOBV)
      DIMENSION RES2(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),W(1))
      EQUIVALENCE (GARBAG(IGARB4),PRED2(1))
      EQUIVALENCE (GARBAG(IGARB5),RES2(1))
      EQUIVALENCE (GARBAG(IGARB6),XTEMP5(1))
      EQUIVALENCE (GARBAG(IGARB7),XTEMP6(1))
      EQUIVALENCE (GARBAG(IGARB8),XTEMP7(1))
      EQUIVALENCE (GARBAG(IGARB9),XWORK(1))
!CCCC END CHANGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLO'
      ISUBN2='W   '
!
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOW--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   54   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,57)IFOUND,IERROR,MAXN,MAXNXT,ALOWFR
   57   FORMAT('IFOUND,IERROR,MAXN,MAXNXT,ALOWFR = ',2(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************
!               **  TREAT THE LOWESS    FIT CASE **
!               ***********************************
!
!               ***************************
!               **  STEP 11--            **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
!CCCC FEBRUARY 1999.  ADD SUPPORT FOR SEASONAL LOWESS COMMAND.
!
      ISTEPN='11'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASAN='PLOW'
      ILASTC=0
      IF(ICOM.EQ.'LOWE'.OR.ICOM.EQ.'LOES')THEN
        IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FIT')THEN
          ILASTC=1
        ELSEIF(NUMARG.GE.1.AND.IHARG(1).EQ.'SMOO')THEN
          ILASTC=1
        ENDIF
      ELSEIF(ICOM.EQ.'SEAS')THEN
        IF(NUMARG.GE.2.AND.   &
          (IHARG(1).EQ.'LOWE'.OR.IHARG(1).EQ.'LOES').AND.   &
           IHARG(2).EQ.'FIT ')THEN
          ILASTC=ILASTC+2
          ICASAN='SLOW'
        ELSEIF(NUMARG.GE.2.AND.   &
          (IHARG(1).EQ.'LOWE'.OR.IHARG(1).EQ.'LOES').AND.   &
           IHARG(2).EQ.'SMOO')THEN
          ILASTC=ILASTC+2
          ICASAN='SLOW'
        ELSEIF(NUMARG.GE.1.AND.   &
          (IHARG(1).EQ.'LOWE'.OR.IHARG(1).EQ.'LOES'))THEN
          ILASTC=1
          ICASAN='SLOW'
        ELSE
          IFOUND='NO'
          GO TO 9000
        ENDIF
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='LOWESS'
      MINN2=2
      MINNA=1
      MAXNA=100
      MINNVA=1
      MAXNVA=2
      IFLAGE=1
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      IF(ICASAN.EQ.'SLOW')THEN
        INAME='SEASONAL LOWESS'
        MAXNVA=1
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT
  182   FORMAT('NQ,NUMVAR,IMULT = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS INSERTED NOVEMBER 1989
!               **************************************************
!               **  STEP 10--                                   **
!               **  CHECK THAT THE LOWESS FRACTION              **
!               **  IS BETWEEN 0 AND 1 (EXCLUSIVELY)            **
!               **************************************************
!
      IF(ALOWFR.LE.0.0.OR.ALOWFR.GT.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1011)
 1011   FORMAT('***** ERROR IN LOWESS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1012)
 1012   FORMAT('      THE VALUE OF THE LOWESS FRACTION IS OUTSIDE THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)
 1013   FORMAT('     (0,1) INTERVAL (THIS VALUE SPECIFIES THE SIZE OF')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1014)
 1014   FORMAT('      OF THE LOWESS NEIGHBORHOOD)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1017)ALOWFR
 1017   FORMAT('      THE VALUE OF THE LOWESS FRACTION = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1018)
 1018   FORMAT('      CORRECT THIS VALUE VIA THE    LOWESS FRACTION ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1019)
 1019   FORMAT('      COMMAND, AS IN      LOWESS FRACTION .5')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 33--                               **
!               **  FORM THE SUBSETTED VARIABLES            **
!               **       Y1(.)                              **
!               **       Y2(.)                              **
!               **  CONTAINING                              **
!               **       THE VERTICAL AXIS VARIABLE         **
!               **       THE HORIZONTAL AXIS VARIABLE       **
!               **  RESPECTIVELY.                           **
!               **********************************************
!
      ISTEPN='33'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y2,Y1,NS,NS,NS,ICASE,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NUMVAR.EQ.1)THEN
        DO 3310 I=1,NS
          Y2(I)=REAL(I)
 3310   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 41--                                       **
!               **  CARRY OUT THE LOWESS FIT                        **
!               ******************************************************
!
      ISTEPN='41'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC MARCH 1994.  ADD ARGUMENT.
!CCCC CALL DPLOW2(Y1,Y2,W,NS,ALOWFR,ALOWDG,
      IF(ICASAN.EQ.'PLOW')THEN
        CALL DPLOW2(Y1,Y2,W,NS,ALOWFR,ALOWDG,ICAPSW,ICAPTY,IFORSW,   &
                    XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                    XTEMP6,XTEMP7,MAXNXT,   &
                    IREP,REPSD,REPDF,RESSD,RESDF,PRED2,RES2,ALFCDF,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSEIF(ICASAN.EQ.'SLOW')THEN
!
        IHP='PERI'
        IHP2='OD  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          PERIOD=12.0
        ELSE
          PERIOD=VALUE(ILOCP)
        ENDIF
        NP=INT(PERIOD+0.5)
!
        IHP='STLW'
        IHP2='IDTH'
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          NWIDTH=NS/10
        ELSE
          NWIDTH=INT(VALUE(ILOCP)+0.5)
        ENDIF
!
        IHP='STLS'
        IHP2='DEG '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ISDEG=0
        ELSE
          ISDEG=INT(VALUE(ILOCP)+0.5)
        ENDIF
!
        IHP='STLT'
        IHP2='DEG '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ITDEG=0
        ELSE
          ITDEG=INT(VALUE(ILOCP)+0.5)
        ENDIF
!
        IHP='STLT'
        IHP2='DEG '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
          IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
          ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ROBUST=.TRUE.
        ELSE
          ROBUST=.TRUE.
          IF(INT(VALUE(ILOCP)+0.5).EQ.1)ROBUST=.FALSE.
        ENDIF
!
        CALL STLEZ(Y1,NS,NP,NWIDTH,ISDEG,ITDEG,ROBUST,NO,   &
                   W,XTEMP1,XTEMP2,XWORK)
        DO 5010 I=1,NS
          PRED2(I)=XTEMP1(I)+XTEMP2(I)
          RES2(I)=Y1(I)-PRED2(I)
 5010   CONTINUE
!
!               ***************************************
!               **  STEP 51--                        **
!               **  WRITE SEASONAL, TREND TO FILE    **
!               ***************************************
!
        IOP='OPEN'
        IFLG1=1
        IFLG2=0
        IFLG3=0
        IFLG4=0
        IFLG5=0
        CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        DO 5110 I=1,NS
          WRITE(IOUNI1,5111)XTEMP1(I),XTEMP2(I)
 5111     FORMAT(E15.7,E15.7)
 5110   CONTINUE
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,5192)
 5192     FORMAT(6X,'SEASONAL AND TREND COMPONENTS WRITTEN TO FILE ',   &
                 'DPST1F.DAT')
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IOP='CLOS'
        CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
      ENDIF
!
!               ***************************************
!               **  STEP 52--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='42'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOLPR=MAXCP1
      ICOLRE=MAXCP2
      IREPU='ON'
      IRESU='ON'
      CALL UPDAPR(ICOLPR,ICOLRE,PRED2,RES2,PRED,RES,ISUB,NRIGHT(1),   &
                  IREPU,REPSD,REPDF,IRESU,RESSD,RESDF,ALFCDF,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,ILOCN,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLOW')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOW--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ICASAN,NS,MAXN,MAXNXT,NUMVAR
 9014   FORMAT('ICASAN,NS,MAXN,MAXNXT,NUMVAR = ',A4,2X,5I8)
        CALL DPWRST('XXX','BUG ')
        IF(NS.GT.0)THEN
          DO 9020 I=1,NS
            WRITE(ICOUT,9021)I,Y1(I),Y2(I),PRED2(I),RES2(I),ISUB(I)
 9021       FORMAT('I,Y1(I),Y2(I),PRED2(I),RES2(I),ISUB(I) = ',   &
                   I8,4G15.7,I8)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOW
      SUBROUTINE DPLOW2(Y,X,W,N,ALOWFR,ALOWDG,ICAPSW,ICAPTY,IFORSW,   &
                        XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                        XTEMP6,XTEMP7,MAXNXT,   &
                        IREP,REPSD,REPDF,RESSD,RESDF,PRED2,RES2,ALFCDF,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/2
!     ORIGINAL VERSION--FEBRUARY  1988.
!     UPDATED         --MARCH     1988. ADD LOFCDF
!     UPDATED         --NOVEMBER  1989. RESIDUAL SD
!     UPDATED         --FEBRUARY  2012. USE DPDTA1 TO PRINT OUTPUT
!     UPDATED         --JULY      2019. CALL LIST TO DPREPS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IREP
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION W(*)
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION XTEMP6(*)
      DIMENSION XTEMP7(*)
!
      DIMENSION PRED2(*)
      DIMENSION RES2(*)
!
      PARAMETER(NUMCLI=10)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=30)
      CHARACTER*40 ITITLE
      CHARACTER*40 ITITLZ
      CHARACTER*40 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLO'
      ISUBN2='W2  '
      IERROR='NO'
!
      RESSD=0.0
      RESDF=0.0
      REPSD=0.0
      REPDF=0.0
      ALFCDF=(-999.99)
      CDF2=-999.99
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOW2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,IBUGA3
   52   FORMAT('N,IBUGA3 = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I),W(I)
   56     FORMAT('I,Y(I),X(I),W(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!               ********************************************************
!               **  STEP 11--                                         **
!               **  PRINT OUT THE HEADER AND PRELIMINARY INFORMATION  **
!               **  FOR THE FIT                                       **
!               ********************************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      AN=N
      NN=INT(ALOWFR*AN+0.5)
!
      IF(IPRINT.EQ.'ON')THEN
        ITITLE='Lowess Fit'
        NCTITL=10
        ITITLZ=' '
        NCTITZ=0
!
        ICNT=1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Size:'
        NCTEXT(ICNT)=12
        AVALUE(ICNT)=REAL(N)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Lowess Fraction (0 to 1):'
        NCTEXT(ICNT)=25
        AVALUE(ICNT)=ALOWFR
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Lowess Degree (1 or 2):'
        NCTEXT(ICNT)=23
        IJUNK=INT(ALOWDG+0.1)
        AVALUE(ICNT)=REAL(IJUNK)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Neighborhood Size:'
        NCTEXT(ICNT)=18
        AVALUE(ICNT)=REAL(NN)
        IDIGIT(ICNT)=0
      ENDIF
!
!               ********************************************************
!               **  STEP 12--                                         **
!               **  CHECK FOR REPLICATION AND IF EXISTENT COMPUTE     **
!               **  A (MODEL-FREE) REPLICATION STANDARD DEVIATION.    **
!               ********************************************************
!
      ISTEPN='12'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVAR=1
      CALL DPREPS(Y,X,N,N,NUMVAR,   &
                  XTEMP6,XTEMP7,   &
                  IREP,REPSS,REPMS,REPSD,REPDF,NUMSET,IBUGA3,IERROR)
      IREPDF=INT(REPDF+0.5)
!
      IF(IPRINT.EQ.'ON')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        IF(IREP.EQ.'NO')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='No Replication Case'
          NCTEXT(ICNT)=19
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
        ELSE
          ICNT=ICNT+1
          ITEXT(ICNT)='Replication Case'
          NCTEXT(ICNT)=16
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
        ENDIF
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Distinct Subsets:'
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=REAL(NUMSET)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
!               *************************************************
!               **  STEP 21--                                  **
!               **  CARRY OUT THE LOWESS FIT                   **
!               *************************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
!CCCC MARCH 1994.  ADD ARGUMENT.
!CCCC CALL LOWESS(Y,X,N,ALOWFR,
      CALL LOWESS(Y,X,N,ALOWFR,ALOWDG,   &
                  XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                  XTEMP6,XTEMP7,MAXNXT,   &
                  PRED2,RES2,ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')THEN
        WRITE(ICOUT,2111)N
 2111   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 2112 I=1,N
          WRITE(ICOUT,2113)I,Y(I),PRED2(I),RES2(I)
 2113     FORMAT('I,Y(I),PRED2(I),RES2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 2112   CONTINUE
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS COMMENTED OUT NOVEMBER 1989
!CCCC RESSD=SD
!CCCC RESDF=NDF
!CCCC RESMS=RESSD*RESSD
!CCCC RESSS=RESMS*RESDF
!
!CCCC THE FOLLOWING SECTION WAS INSERTED NOVEMBER 1989
      DENOM=N-1
      RESSS=0.0
      DO 2120 I=1,N
        RESSS=RESSS+RES2(I)**2
 2120 CONTINUE
      RESMS=RESSS/DENOM
      S=0.0
      IF(RESMS.GT.0.0)S=SQRT(RESMS)
      RESDF=DENOM
      IRESDF=INT(RESDF+0.5)
      RESSD=S
!CCCC RESAAR=SUMAB/AN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')THEN
        WRITE(ICOUT,2121)RESSD,RESDF,RESMS,RESSS
 2121   FORMAT('RESSD,RESDF,RESMS,RESSS = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************************
!               **  STEP 31--                                        **
!               **  PRINT OUT THE PARAMETER ESTIMATES AND THEIR      **
!               **  STANDARD DEVIATIONS.  ALSO PRINT OUT THE         **
!               **  RESIDUAL STANDARD DEVIATION AND THE GOODNESS OF  **
!               **  FIT INFORMATION.                                 **
!               *******************************************************
!
      IFITDF=IRESDF-IREPDF
      IF(IREP.EQ.'YES' .AND. IFITDF.GE.1)THEN
        FITDF=IFITDF
        FITSS=RESSS-REPSS
        FITMS=100000.0
        IF(FITDF.GT.0.0)FITMS=FITSS/FITDF
        FSTAT=100000.0
        IF(REPMS.GT.0.0)FSTAT=FITMS/REPMS
        CALL FCDF(FSTAT,IFITDF,IREPDF,CDF)
        CDF2=100.0*CDF
        ALFCDF=CDF
      ENDIF
!
      IF(IPRINT.EQ.'ON')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Residual Standard Deviation:'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=RESSD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Residual Degrees of Freedom:'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=REAL(IRESDF)
        IDIGIT(ICNT)=0
!
        IF(IREP.EQ.'YES')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Replication Standard Deviation:'
          NCTEXT(ICNT)=31
          AVALUE(ICNT)=REPSD
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Replication Degrees of Freedom:'
          NCTEXT(ICNT)=31
          AVALUE(ICNT)=REAL(IREPDF)
          IDIGIT(ICNT)=0
!
          IFITDF=IRESDF-IREPDF
          IF(IFITDF.LT.1)THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='The Lack of Fit F Test cannot be done'
            NCTEXT(ICNT)=37
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='because there are 0 degrees of freedom'
            NCTEXT(ICNT)=38
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='in the numerator of the F ratio.  This'
            NCTEXT(ICNT)=38
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='This happens when the number of'
            NCTEXT(ICNT)=31
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='parameters fitted is identical to the'
            NCTEXT(ICNT)=37
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='number of distinct subsets.'
            NCTEXT(ICNT)=27
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ELSE
            ICNT=ICNT+1
            ITEXT(ICNT)='Lack of Fit F Ratio:'
            NCTEXT(ICNT)=20
            AVALUE(ICNT)=FSTAT
            IDIGIT(ICNT)=NUMDIG
            ICNT=ICNT+1
            ITEXT(ICNT)='Lack of Fit F CDF (%):'
            NCTEXT(ICNT)=22
            AVALUE(ICNT)=CDF2
            IDIGIT(ICNT)=NUMDIG
            ICNT=ICNT+1
            ITEXT(ICNT)='Lack of Fit Degrees of Freedom 1:'
            NCTEXT(ICNT)=33
            AVALUE(ICNT)=REAL(IFITDF)
            IDIGIT(ICNT)=0
            ICNT=ICNT+1
            ITEXT(ICNT)='Lack of Fit Degrees of Freedom 2:'
            NCTEXT(ICNT)=33
            AVALUE(ICNT)=REAL(IREPDF)
            IDIGIT(ICNT)=0
          ENDIF
        ENDIF
!
        NUMROW=ICNT
        DO 2410 I=1,NUMROW
          NTOT(I)=15
 2410   CONTINUE
!
        IFRST=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                    NCTEXT,AVALUE,IDIGIT,   &
                    NTOT,NUMROW,   &
                    ICAPSW,ICAPTY,ILAST,IFRST,   &
                    ISUBRO,IBUGA3,IERROR)
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOW2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOW2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N,NUMVAR
 9013   FORMAT('IERROR,N,NUMVAR = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N
          WRITE(ICOUT,9021)I,PRED2(I),RES2(I)
 9021     FORMAT('I,PRED2(I),RES2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOW2
      SUBROUTINE DPLRDI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DISTINGUISH BETWEEN TWO DISTRIBUTIONS BASED ON THE
!              RATIO OF THE LIKELIHOOD FUNCTIONS.  IN MANY CASES,
!              SEVERAL DISTRIBUTIONS MAY BOTH FIT A GIVEN DATASET.
!              THE LIKELIHOOD RATIO TEST PROVIDES A METHOD FOR
!              CHOOSING BETWEEN THE TWO.  THIS IS GENERALLY MORE
!              POWERFUL THAN K-S OR ANDERSON-DARLING TEST BEACAUSE
!              WE ARE TESTING A SPECIFIC ALTERNATIVE RATHER THAN
!              ANY ALTERNATIVE DISTRIBUTION.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/5
!     ORIGINAL VERSION--MAY       2014.
!     UPDATED         --JULY      2019. TWEAK SCRATCH STORAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASE
      CHARACTER*4 IFLAGU
      CHARACTER*4 IMULT
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IREPL
      CHARACTER*4 IRANSV
      CHARACTER*4 IRELAT
!
      CHARACTER*60 IDIST1
      CHARACTER*60 IDIST2
      CHARACTER*40 INAME
!
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(7)
      CHARACTER*4 IVARI2(7)
      REAL PVAR(MAXSPN)
      REAL PID(7)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION TEMP5(MAXOBV)
      DIMENSION TEMP6(MAXOBV)
      DIMENSION TEMP7(MAXOBV)
      DIMENSION YTEMP(MAXOBV)
      DIMENSION YSTAT(MAXOBV)
!
      DIMENSION XDESGN(MAXOBV,6)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XIDTE4(MAXOBV)
      DIMENSION XIDTE5(MAXOBV)
      DIMENSION XIDTE6(MAXOBV)
      DIMENSION ZY(MAXOBV)
!
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
!
      DIMENSION ITEMP1(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
      INCLUDE 'DPCOZI.INC'
!
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB3),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB4),TEMP3(1))
      EQUIVALENCE (GARBAG(IGARB5),TEMP4(1))
      EQUIVALENCE (GARBAG(IGARB6),TEMP5(1))
      EQUIVALENCE (GARBAG(IGARB7),TEMP6(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP7(1))
      EQUIVALENCE (GARBAG(IGARB9),YTEMP(1))
      EQUIVALENCE (GARBAG(IGAR10),XIDTEM(1))
      EQUIVALENCE (GARBAG(JGAR11),XIDTE2(1))
      EQUIVALENCE (GARBAG(JGAR12),XIDTE3(1))
      EQUIVALENCE (GARBAG(JGAR13),XIDTE4(1))
      EQUIVALENCE (GARBAG(JGAR14),XIDTE5(1))
      EQUIVALENCE (GARBAG(JGAR15),XIDTE6(1))
      EQUIVALENCE (GARBAG(JGAR16),ZY(1))
      EQUIVALENCE (GARBAG(JGAR17),YSTAT(1))
      EQUIVALENCE (GARBAG(JGAR18),XDESGN(1,1))
      EQUIVALENCE (DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR2),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR3),DTEMP3(1))
      EQUIVALENCE (IGARBG(IDGAR1),ITEMP1(1))
!
!-----COMMON----------------------------------------------------------
!
      COMMON/ISED/ISED1,ISED2,ISED3,ISED4,ISED5,ISED6,   &
                  ISED7,ISED8,ISED9,ISED10,ISED11
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOS2.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ICASAN='    '
      ICASPL='    '
      ICASP2='    '
      IRELAT='OFF'
      IREPL='OFF'
      IMULT='OFF'
      IRANSV=IRANAL
      IRANAL='FIBC'
      ISEESV=ISEED
      ISEED=16411
      NSAVE=-9999
!
      ISUBN1='DPLR'
      ISUBN2='DI  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MINN2=5
!
!               ***************************************************
!               **  TREAT THE <DIST1>  <DIST2>  DISTRIBUTIONAL   **
!               **            LIKELIHOOD RATIO TEST     CASE     **
!               ***************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRDI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLRDI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,IBUGA3,IBUGQ,MAXNXT
   53   FORMAT('IBUGA2,IBUGA3,IBUGQ,MAXNXT = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************
!               **  STEP 1--               **
!               **  EXTRACT THE COMMAND    **
!               *****************************
!
!     LOOK FOR THE WORDS "DISTRIBUTIONAL LIKELIHOOD RATIO".  ALSO LOOK
!     ALSO LOOK FOR OPTIONAL KEYWORDS "REPLICATION",
!     AND "MULTIPLE". AND "TEST"
!
!     ALSO LOOK FOR THE WORD "AND".  THIS IS USED TO SEPARATE THE
!     TWO DISTRIBUTIONAL NAMES.  NOTE THAT IF BOTH DISTRIBUTIONS ARE
!     A SINGLE NAME, THEN THIS KEYWORD MAY BE OMITTED.  HOWEVER, IF
!     THIS IS NOT THE CASE AND THE "AND" KEYWORD IS NOT FOUND, REPORT
!     AN ERROR.
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTC=9999
      ILASTZ=9999
      ILASTA=9999
      IFOUND='NO'
      DO 100 I=1,NUMARG-1
        IF(IHARG(I).EQ.'DIST' .AND. IHARG(I+1).EQ.'LIKE' .AND.   &
           IHARG(I+2).EQ.'RATI')THEN
          IFOUND='YES'
          ICASAN='DLKR'
          ILASTC=MIN(ILASTC,I-1)
          ILASTZ=I+3
        ELSEIF(IHARG(I).EQ.'REPL')THEN
          IREPL='ON'
          ILASTC=MIN(ILASTC,I-1)
        ELSEIF(IHARG(I).EQ.'MULT')THEN
          IMULT='ON'
          ILASTC=MIN(ILASTC,I-1)
!
        ELSEIF(IHARG(I).EQ.'TEST')THEN
          IF(IHARG(I-3).EQ.'DIST' .AND. IHARG(I-2).EQ.'LIKE' .AND.   &
                 IHARG(I-1).EQ.'RATI')THEN
            ILASTZ=I+1
          ENDIF
        ELSEIF(IHARG(I).EQ.'AND ')THEN
          ILASTA=I
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN DISTRIBUTIONAL LIKELIHOOD RATIO TEST')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THIS COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(ILASTA.EQ.9999 .AND. ILASTC.NE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      AND KEYWORD TO SEPARATE DISTRIBUTION NAMES ',   &
               'NOT FOUND.')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 2--EXTRACT THE FIRST DISTRIBUTION NAME  **
!               ***************************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,211)IMULT,IREPL,ILASTC,ILASTZ
  211   FORMAT('IMULT,IREPL,ILASTC,ILASTZ = ',2(A4,2X),2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      JMIN=0
      IF(ILASTA.NE.9999)THEN
        JMAX=ILASTA-1
      ELSE
        JMAX=0
      ENDIF
!
      IDIST1=' '
      CALL EXTDIS(ICOM,ICOM2,IHARG,IHARG2,NUMARG,JMIN,JMAX,   &
                  ICASPL,IDIST1,NUMSHA,IFOUND,ILOCV,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')THEN
        WRITE(ICOUT,252)ICASPL,NUMSHA,IDIST1
  252   FORMAT('AFTER EXTDIS: ICASPL,NUMSHA,IDIST1 = ',A4,2X,I8,2X,A60)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFOUND.EQ.'NO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,262)
  262   FORMAT('      NO MATCH FOUND FOR THE FIRST DISTRIBUTION NAME.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 3--EXTRACT THE SECOND DISTRIBUTION NAME **
!               ***************************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,271)IMULT,IREPL,ILASTC,ILASTZ,ILASTA
  271   FORMAT('IMULT,IREPL,ILASTC,ILASTZ,ILASTA = ',2(A4,2X),3I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ILASTA.NE.9999)THEN
        JMIN=ILASTA+1
      ELSE
        JMIN=1
      ENDIF
      JMAX=ILASTC
!
      IDIST2=' '
      CALL EXTDIS(ICOM,ICOM2,IHARG,IHARG2,NUMARG,JMIN,JMAX,   &
                  ICASP2,IDIST2,NUMSHA,IFOUND,ILOCV,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')THEN
        WRITE(ICOUT,254)ICASP2,NUMSHA,IDIST2
  254   FORMAT('AFTER EXTDIS: ICASP2,NUMSHA,IDIST2 = ',A4,2X,I8,2X,A60)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFOUND.EQ.'NO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,264)
  264   FORMAT('      NO MATCH FOUND FOR SECOND DISTRIBUTION NAME.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSE
        ISHIFT=ILASTZ-1
        IF(ISHIFT.GT.0)THEN
          CALL ADJUST(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='DISTRIBUTIONAL LIKELIHOOD RATIO TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IF(IMULT.EQ.'ON')IFLAGE=0
      IFLAGM=1
      IF(IREPL.EQ.'ON')IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=-99
      MAXNVA=-99
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF CENSORING   VARIABLES (0-1) **
!               **  3) NUMBER OF GROUPING    VARIABLES (0-2) **
!               **  4) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               ***********************************************
!
      ISTEPN='5'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
      NRESP=NUMVAR
      IF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 6--                                 **
!               **  GENERATE THE DISTRIBUTIONAL LIKELIHOOD   **
!               **  RATIO TEST       FOR THE VARIOUS CASES.  **
!               ***********************************************
!
      ISTEPN='6'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ******************************************
!               **  STEP 7A--                           **
!               **  CASE 1: NO REPLICATION CASE         **
!               ******************************************
!
      IF(NRESP.GE.1 .AND. IREPL.EQ.'OFF')THEN
        ISTEPN='7A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NCURVE=0
        DO 710 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IINDX=ICOLR(IRESP)
          PID(1)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
!
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,711)IRESP,NCURVE
  711       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,TEMP1,TEMP1,NS1,NS2,NS3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          ISTEPN='7B'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          CALL DPLRD2(Y1,NS1,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                      PID,IVARID,IVARI2,NREPL,MINMAX,   &
                      TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                      YTEMP,YSTAT,   &
                      DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                      IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                      IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                      IFLAGL,AL,   &
                      IFORSW,ICAPSW,ICAPTY,ISEED,   &
                      CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                      STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                      APOW90,APOW95,APOW99,   &
                      IBUGA3,ISUBRO,IERROR)
!
!               ***************************************
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='7C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IFLAGU='FILE'
          IF(NRESP.EQ.1)IFLAGU='ON'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                      APOW90,APOW95,APOW99,   &
                      IFLAGU,IFRST,ILAST,ICASAN,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
  710   CONTINUE
!
!               ***************************************************
!               **  STEP 8A--                                    **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.   **
!               ***************************************************
!
      ELSEIF(NRESP.EQ.1 .AND. NREPL.GE.1)THEN
        ISTEPN='8A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRDI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        PID(1)=CPUMIN
        IVARID(1)=IVARN1(1)
        IVARI2(1)=IVARN2(1)
        IADD=1
        DO 903 II=1,NREPL
          IVARID(II+1)=IVARN1(II+IADD)
          IVARI2(II+1)=IVARN2(II+IADD)
  903   CONTINUE
!
        ICOL=1
        NUMVA2=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,TEMP1,TEMP1,NS1,NS2,NS3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   TEMP1,TEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGA3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 9D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            PID(2)=XIDTEM(ISET1)
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPLRD2(ZY,NTEMP,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                          PID,IVARID,IVARI2,NREPL,MINMAX,   &
                          TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                          YTEMP,YSTAT,   &
                          DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                          IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                          ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                          IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                          IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                          IFLAGL,AL,   &
                          IFORSW,ICAPSW,ICAPTY,ISEED,   &
                          CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                          STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                          APOW90,APOW95,APOW99,   &
                          IBUGA3,ISUBRO,IERROR)
!
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            PID(2)=XIDTEM(ISET1)
            PID(3)=XIDTE2(ISET2)
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPLRD2(ZY,NTEMP,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                          PID,IVARID,IVARI2,NREPL,MINMAX,   &
                          TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                          YTEMP,YSTAT,   &
                          DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                          IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                          ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                          IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                          IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                          IFLAGL,AL,   &
                          IFORSW,ICAPSW,ICAPTY,ISEED,   &
                          CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                          STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                          APOW90,APOW95,APOW99,   &
                          IBUGA3,ISUBRO,IERROR)
!
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            PID(2)=XIDTEM(ISET1)
            PID(3)=XIDTE2(ISET2)
            PID(4)=XIDTE3(ISET3)
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPLRD2(ZY,NTEMP,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                          PID,IVARID,IVARI2,NREPL,MINMAX,   &
                          TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                          YTEMP,YSTAT,   &
                          DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                          IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                          ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                          IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                          IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                          IFLAGL,AL,   &
                          IFORSW,ICAPSW,ICAPTY,ISEED,   &
                          CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                          STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                          APOW90,APOW95,APOW99,   &
                          IBUGA3,ISUBRO,IERROR)
!
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            PID(2)=XIDTEM(ISET1)
            PID(3)=XIDTE2(ISET2)
            PID(4)=XIDTE3(ISET3)
            PID(5)=XIDTE4(ISET4)
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPLRD2(ZY,NTEMP,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                          PID,IVARID,IVARI2,NREPL,MINMAX,   &
                          TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                          YTEMP,YSTAT,   &
                          DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                          IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                          ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                          IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                          IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                          IFLAGL,AL,   &
                          IFORSW,ICAPSW,ICAPTY,ISEED,   &
                          CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                          STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                          APOW90,APOW95,APOW99,   &
                          IBUGA3,ISUBRO,IERROR)
!
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            PID(2)=XIDTEM(ISET1)
            PID(3)=XIDTE2(ISET2)
            PID(4)=XIDTE3(ISET3)
            PID(5)=XIDTE4(ISET4)
            PID(6)=XIDTE5(ISET5)
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPLRD2(ZY,NTEMP,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                          PID,IVARID,IVARI2,NREPL,MINMAX,   &
                          TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                          YTEMP,YSTAT,   &
                          DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                          IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                          ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                          IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                          IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                          IFLAGL,AL,   &
                          IFORSW,ICAPSW,ICAPTY,ISEED,   &
                          CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                          STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                          APOW90,APOW95,APOW99,   &
                          IBUGA3,ISUBRO,IERROR)
!
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            PID(2)=XIDTEM(ISET1)
            PID(3)=XIDTE2(ISET2)
            PID(4)=XIDTE3(ISET3)
            PID(5)=XIDTE4(ISET4)
            PID(6)=XIDTE5(ISET5)
            PID(7)=XIDTE6(ISET6)
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                ZY(K)=Y1(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            NPLOT1=NPLOTP
            IF(NTEMP.GT.0)THEN
              CALL DPLRD2(ZY,NTEMP,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                          PID,IVARID,IVARI2,NREPL,MINMAX,   &
                          TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                          YTEMP,YSTAT,   &
                          DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                          IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                          ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                          IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                          IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                          IFLAGL,AL,   &
                          IFORSW,ICAPSW,ICAPTY,ISEED,   &
                          CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                          STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                          APOW90,APOW95,APOW99,   &
                          IBUGA3,ISUBRO,IERROR)
!
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            NPTEMP=NPLOT2-NPLOT1
            CALL DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IRANAL=IRANSV
      ISEED=ISEESV
!
      IF(IERROR.EQ.'YES')THEN
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,9001)(IANS(I),I=1,MIN(100,IWIDTH))
 9001     FORMAT(100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRDI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLRDI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLRDI
      SUBROUTINE DPLRD2(Y,N,ICASPL,IDIST1,ICASP2,IDIST2,MAXOBV,   &
                        PID,IVARID,IVARI2,NREPL,MINMAX,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                        YTEMP,YSTAT,   &
                        DTEMP1,DTEMP2,DTEMP3,ITEMP1,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                        IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                        IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                        IFLAGL,AL,   &
                        IFORSW,ICAPSW,ICAPTY,ISEED,   &
                        CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                        STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--DISTINGUISH BETWEEN TWO DISTRIBUTIONS BASED ON THE
!              RATIO OF THE LIKELIHOOD FUNCTIONS.  IN MANY CASES,
!              SEVERAL DISTRIBUTIONS MAY BOTH FIT A GIVEN DATASET.
!              THE LIKELIHOOD RATIO TEST PROVIDES A METHOD FOR
!              CHOOSING BETWEEN THE TWO.  THIS IS GENERALLY MORE
!              POWERFUL THAN K-S OR ANDERSON-DARLING TEST BEACAUSE
!              WE ARE TESTING A SPECIFIC ALTERNATIVE RATHER THAN
!              ANY ALTERNATIVE DISTRIBUTION.
!
!              THE BASIC ALGORITHM IS:
!
!                1. FIT THE DATA  TO BOTH DISTRIBUTIONS USING
!                   MAXIMIMUM LIKELIHOOD.
!
!                2. COMPUTE THE LIKELIHOOD FUNCTION FOR BOTH
!                   DISTRIBUTIONS AND COMPUTE THE RATIO OF THE
!                   LIKELIHOODS (THE NULL HYPOTHESIS DISTRIBUTION
!                   IS USED FOR THE DENONIMATOR, THE ALTERNATIVE
!                   HYPOTHESIS DISTRIBUTION IS USED FOR THE
!                   NUMERATOR).  THIS IS THE TEST STATISTIC.
!
!                3. TO DETERMINE CRITICAL VALUES, SIMULATE 10,000
!                   RUNS FROM THE NULL HYPOTHESIS DISTRIBUTION
!                   AND COMPUTE THE ABOVE TEST STATISTIC.
!
!              NOTE THAT CURRENTLY ONLY UNGROUPED AND UNCENSORED DATA
!              IS SUPPORTED.
!
!     REFERENCES--DUMONCEAUX, ANTLE AND HAAS (1973), "LIKELIHOOD RATIO
!                 TEST FOR DISCRMINATION BETWEEN TWO MODELS WITH UNKNOWN
!                 AND LOCATION AND SCALE PARAMETERS", TECHNOMETRICS,
!                 VOL. 15, NO. 1, PP. 19-27.
!               --DUMONCEAUX AND ANTLE (1973), "DISCRIMINATION BETWEEN
!                 THE LOG-NORMAL AND THE WEIBULL DISTRIBUTIONS",
!                 TECHNOMETRICS, VOL. 15, NO. 4, PP. 923-926.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/5
!     ORIGINAL VERSION--MAY       2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IGAUDF
      CHARACTER*4 IEXPBC
      CHARACTER*4 IWEIBC
      CHARACTER*4 ICENTY
      CHARACTER*4 IDFTTY
!
      CHARACTER*4 IHSTCW
      CHARACTER*4 IHSTOU
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*60 IDIST1
      CHARACTER*60 IDIST2
!
      CHARACTER*4 IDIR
      CHARACTER*4 ICENSO
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION YTEMP(*)
      DIMENSION YSTAT(*)
      DIMENSION PID(*)
!
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION TEMP6(*)
      DIMENSION TEMP7(*)
!
      DIMENSION CLWIDT(*)
      DIMENSION CLLIMI(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
      INTEGER ITEMP1(*)
!
      DOUBLE PRECISION DSTAT
      DOUBLE PRECISION DN
!
      PARAMETER (NUMALP=7)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=40)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROw,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL ISNANZ
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       50.0, 75.0, 80.0, 90.0, 95.0, 99.0, 99.9/
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='DPLR'
      ISUBN2='D2  '
      IERROR='NO'
      ICENSO='OFF'
      STATVA=CPUMIN
      STATCD=CPUMIN
      PVAL=CPUMIN
      CV50=CPUMIN
      CV75=CPUMIN
      CV90=CPUMIN
      CV95=CPUMIN
      CV99=CPUMIN
      APOW90=CPUMIN
      APOW95=CPUMIN
      APOW99=CPUMIN
      IFLGL1=1
      IFLGL2=1
      IFLGS1=1
      IFLGS2=1
!
      DO 10 I=1,100000
        YSTAT(I)=0.0
   10 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPLRD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,ICASP2,N,MINMAX,IFLAGL,AL
   72   FORMAT('ICASPL,ICASP2,N,MINMAX,IFLAGL,AL = ',2(A4,2X),3I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 85 I=1,N
            WRITE(ICOUT,86)I,Y(I)
   86       FORMAT('I,Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
   85     CONTINUE
        ENDIF
        WRITE(ICOUT,87)PID(1),NREPL
   87   FORMAT('PID(1),NREPL = ',G15.7,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.5)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN DISTRIBUTIONAL LIKELIHOOD RATIO TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 5.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 60 I=1,N
        IF(Y(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)HOLD
   62 FORMAT('      ALL ELEMENTS OF THE RESPONSE VARIABLE ARE ',   &
             'IDENTICALLY EQUAL TO ',G15.7)
                                                                                                                                  
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   69 CONTINUE
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE BASIC TEST STATISTIC   **
!               *****************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DN=DBLE(N)
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST1,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
!     IDENTIFY SPECIAL CASES:
!
!       1. NORMAL-EXPONENTIAL
!       2. EXPONENTIAL-NORMAL
!       3. NORMAL-DOUBLE EXPONENTIAL
!       4. DOUBLE EXPONENTIAL-NORMAL
!
      ICASET=0
      IF(ICASPL.EQ.'NORM' .AND. ICASP2.EQ.'EXPO')ICASET=1
      IF(ICASPL.EQ.'EXPO' .AND. ICASP2.EQ.'NORM')ICASET=2
      IF(ICASPL.EQ.'NORM' .AND. ICASP2.EQ.'DEXP')ICASET=3
      IF(ICASPL.EQ.'DEXP' .AND. ICASP2.EQ.'NORM')ICASET=4
!
!               ***************************************************
!               **  STEP 3A-                                     **
!               **  COMPUTE ML ESTIMATES FOR FIRST DISTRIBUTION  **
!               ***************************************************
!
      ISTEPN='3A'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPML1(Y,TEMP1,N,ICASPL,IFLAGD,IFLAG9,   &
                 TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                 DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                 ALOCS1,SCALS1,ALOWLI,AUPPLI,   &
                 SH1S1,SH2S1,SH3S1,SH4S1,   &
                 SH5S1,SH6S1,S7S1,   &
                 YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                 IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                 ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                 IGEODF,IBGEDF,IGAUDF,   &
                 ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                 CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                 IBUGA3,ISUBRO,IERROR)
!
      IF(IERROR.EQ.'YES')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('      UNABLE TO OBTAIN MAXIMUM LIKELIHOOD ESTIMATE ',   &
               'FOR FIRST DISTRIBUTION')
                                                                                                                                  
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ALOCS1.EQ.CPUMIN)THEN
        ALOCS1=0.0
        IFLGL1=0
      ENDIF
      IF(SCALS1.EQ.CPUMIN)THEN
        SCALS1=1.0
        IFLGS1=0
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
        WRITE(ICOUT,101)ALOCS1,SCALS1,SH1S1,SH2S1
  101   FORMAT('ML ESTIMATES FOR H0 DIST: ALOCS1,SCALS1,SH1S1,SH2S1 = ',   &
               4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************************
!               **  STEP 3B-                                         **
!               **  COMPUTE LIKELIHOOD VALUE FOR FIRST DISTRIBUTION  **
!               *******************************************************
!
      ISTEPN='3B'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPLIK1(Y,TEMP1,N,ICASPL,   &
                  SH1S1,SH2S1,SH3S1,SH4S1,   &
                  SH5S1,SH6S1,SH7S1,   &
                  YLOWLM,YUPPLM,A,B,MINMAX,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                  IGETDF,ICONDF,IGOMDF,IKATDF,   &
                  IGIGDF,IGEODF,   &
                  ALOCS1,SCALS1,   &
                  ALIKE1,AIC1,AICC1,BIC1,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               ***************************************************
!               **  STEP 4A-                                     **
!               **  COMPUTE ML ESTIMATES FOR SECOND DISTRIBUTION **
!               ***************************************************
!
      ISTEPN='4A'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPML1(Y,TEMP1,N,ICASP2,IFLAGD,IFLAG9,   &
                 TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                 DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                 ALOCS2,SCALS2,ALOWLI,AUPPLI,   &
                 SH1S2,SH2S2,SH3S2,SH4S2,   &
                 SH5S2,SH6S2,SH7S2,   &
                 YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                 IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                 ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                 IGEODF,IBGEDF,IGAUDF,   &
                 ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                 CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                 IBUGA3,ISUBRO,IERROR)
!
      IF(IERROR.EQ.'YES')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('      UNABLE TO OBTAIN MAXIMUM LIKELIHOOD ESTIMATE ',   &
               'FOR SECOND DISTRIBUTION')
                                                                                                                                  
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ALOCS2.EQ.CPUMIN)THEN
        ALOCS2=0.0
        IFLGL2=0
      ENDIF
      IF(SCALS2.EQ.CPUMIN)THEN
        SCALS2=1.0
        IFLGS2=0
      ENDIF
!
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
        WRITE(ICOUT,103)ALOCS2,SCALS2,SH1S2,SH2S2
  103   FORMAT('ML ESTIMATES FOR HA DIST: ALOCS2,SCALS2,SH1S2,SH2S2 = ',   &
               4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************************
!               **  STEP 4B-                                         **
!               **  COMPUTE LIKELIHOOD VALUE FOR SECOND DISTRIBUTION **
!               *******************************************************
!
      ISTEPN='4B'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPLIK1(Y,TEMP1,N,ICASP2,   &
                  SH1S2,SH2S2,SH3S2,SH4S2,   &
                  SH5S2,SH6S2,SH7S2,   &
                  YLOWLM,YUPPLM,A,B,MINMAX,   &
                  IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                  ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                  IGETDF,ICONDF,IGOMDF,IKATDF,   &
                  IGIGDF,IGEODF,   &
                  ALOCS2,SCALS2,   &
                  ALIKE2,AIC2,AICC2,BIC2,   &
                  IBUGA3,ISUBRO,IERROR)
!
      IF(ICASET.EQ.1)THEN
        STATVA=SCALS1/SCALS2
      ELSEIF(ICASET.EQ.2)THEN
        STATVA=SCALS1/SCALS2
      ELSEIF(ICASET.EQ.3)THEN
        STATVA=SCALS1/SCALS2
      ELSEIF(ICASET.EQ.4)THEN
        STATVA=SCALS1/SCALS2
      ELSE
        DSTAT=(DEXP(DBLE(ALIKE2))/DEXP(DBLE(ALIKE1)))**(1.0D0/DN)
        STATVA=REAL(DSTAT)
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
        WRITE(ICOUT,111)ALIKE1,ALIKE2,STATVA
  111   FORMAT('ALIKE1,ALIKE2,STATVA = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 5--                              **
!               **  SIMULATION TO OBTAIN CRITICAL VALUES  **
!               ********************************************
!
!     GENERATE SAMPLES FROM THE H0 DISTRIBUTION.  LOCATION AND
!     SCALE PARAMETERS WILL BE SET TO 0 AND 1.  IF THERE IS A SHAPE
!     PARAMETER, USE THE ESTIMATED VALUE FROM ABOVE.
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC NMCSAM=100
      NMCSAM=10000
      NCNT=0
      NTEMP=N
!
      DO 2110 I=1,NMCSAM
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,311)I
  311     FORMAT('MONTE CARLO ITERATION ',I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        CALL DPRAN2(ICASPL,ISEED,YTEMP,NTEMP,TEMP1,   &
                    A,B,MINMAX,   &
                    SH1S1,SH2S1,SH3S1,SH4S1,   &
                    SH5S1,SH6S1,SH7S1,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                    IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
!
!               ***************************************************
!               **  STEP 5A-                                     **
!               **  COMPUTE ML ESTIMATES FOR FIRST DISTRIBUTION  **
!               ***************************************************
!
        ISTEPN='5A'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPML1(YTEMP,TEMP1,NTEMP,ICASPL,IFLAGD,IFLAG9,   &
                   TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                   DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                   ALOCT1,SCALT1,ALOWLI,AUPPLI,   &
                   SH1T1,SH2T1,SH3T1,SH4T1,   &
                   SH5T1,SH6T1,S7T1,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 2110
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,2111)ALOCT1,SCALT1,SH1T1,SH2T1
 2111     FORMAT('ML ESTIMATES FOR H0 DIST: ALOCT1,SCALT1,SH1T1,',   &
                 'SH2T1 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      IF(ALOCT1.EQ.CPUMIN)ALOCT1=0.0
!
!               ********************************************************
!               **  STEP 5B-                                         **
!               **  COMPUTE LIKELIHOOD VALUE FOR FIRST DISTRIBUTION  **
!               *******************************************************
!
        ISTEPN='5B'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPLIK1(YTEMP,TEMP1,NTEMP,ICASPL,   &
                    SH1T1,SH2T1,SH3T1,SH4T1,   &
                    SH5T1,SH6T1,SH7T1,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ALOCT1,SCALT1,   &
                    ALIKE1,AIC1,AICC1,BIC1,   &
                    IBUGA3,ISUBRO,IERROR)
!
!               ***************************************************
!               **  STEP 5C-                                     **
!               **  COMPUTE ML ESTIMATES FOR SECOND DISTRIBUTION **
!               ***************************************************
!
        ISTEPN='4A'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPML1(YTEMP,TEMP1,NTEMP,ICASP2,IFLAGD,IFLAG9,   &
                   TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                   DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                   ALOCT2,SCALT2,ALOWLI,AUPPLI,   &
                   SH1T2,SH2T2,SH3T2,SH4T2,   &
                   SH5T2,SH6T2,S7T2,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 2110
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,2213)ALOCT2,SCALT2,SH1T2,SH2T2
 2213     FORMAT('ML ESTIMATES FOR HA DIST: ALOCT2,SCALT2,',   &
                 'SH1T2,SH2T2 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      IF(ALOCT2.EQ.CPUMIN)ALOCT2=0.0
!
!               *******************************************************
!               **  STEP 5D-                                         **
!               **  COMPUTE LIKELIHOOD VALUE FOR SECOND DISTRIBUTION **
!               *******************************************************
!
        ISTEPN='5D'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPLIK1(YTEMP,TEMP1,NTEMP,ICASP2,   &
                    SH1T2,SH2T2,SH3T2,SH4T2,   &
                    SH5T2,SH6T2,SH7T2,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ALOCT2,SCALT2,   &
                    ALIKE2,AIC2,AICC2,BIC2,   &
                    IBUGA3,ISUBRO,IERROR)
!
        NCNT=NCNT+1
        IF(ICASET.EQ.1)THEN
          YSTAT(NCNT)=SCALT1/SCALT2
        ELSEIF(ICASET.EQ.2)THEN
          YSTAT(NCNT)=SCALT1/SCALT2
        ELSEIF(ICASET.EQ.3)THEN
          YSTAT(NCNT)=SCALT1/SCALT2
        ELSEIF(ICASET.EQ.4)THEN
          YSTAT(NCNT)=SCALT1/SCALT2
        ELSE
          DSTAT=(DEXP(DBLE(ALIKE2))/DEXP(DBLE(ALIKE1)))**(1.0D0/DN)
          STATT=REAL(DSTAT)
          IF(ISNANZ(STATT))THEN
            NCNT=NCNT-1
          ELSE
            YSTAT(NCNT)=REAL(DSTAT)
          ENDIF
        ENDIF
!
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,2119)I,ALIKE1,ALIKE2,YSTAT(NCNT)
 2119     FORMAT('I,ALIKE1,ALIKE2,YSTAT(NCNT) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2110 CONTINUE
!
      IDIR='UPPE'
      CALL DPGOF8(YSTAT,NCNT,STATVA,PVAL,IDIR,   &
                  IBUGA3,ISUBRO,IERROR)
      STATCD=1.0 - PVAL
      IF(NCNT.EQ.NMCSAM)THEN
        CV50=YSTAT(5000)
        CV75=YSTAT(7500)
        CV80=YSTAT(8000)
        CV90=YSTAT(9000)
        CV95=YSTAT(9500)
        CV99=YSTAT(9900)
        CV999=YSTAT(9990)
      ELSEIF(NCNT.LT.1000)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      LESS THAN 1,000 (OF 10,000) OF THE CRITICAL ',   &
               'VALUE SIMULATIONS GENERATED A VALID STATISTIC.')
                                                                                                                                  
        IERROR='YES'
        GO TO 9000
      ELSE
        IWRITE='OFF'
        P100=50.0
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV50,IBUGA3,IERROR)
        P100=75.0
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV75,IBUGA3,IERROR)
        P100=80.0
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV80,IBUGA3,IERROR)
        P100=90.0
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV90,IBUGA3,IERROR)
        P100=95.0
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV95,IBUGA3,IERROR)
        P100=99.0
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV99,IBUGA3,IERROR)
        P100=99.9
        CALL PERCEN(P100,YSTAT,NCNT,IWRITE,TEMP1,MAXOBV,   &
                    CV999,IBUGA3,IERROR)
      ENDIF
!
!               ********************************************
!               **  STEP 6--                              **
!               **  SIMULATION TO OBTAIN CRITICAL VALUES  **
!               ********************************************
!
!     GENERATE SAMPLES FROM THE H1 DISTRIBUTION.  LOCATION AND
!     SCALE PARAMETERS WILL BE SET TO 0 AND 1.  IF THERE IS A SHAPE
!     PARAMETER, USE THE ESTIMATED VALUE FROM ABOVE.
!
!     FOR POWER, GENERATE SIMULATIONS FROM THE H1 DISTRIBUTION
!     RATHER THAN THE H0 DISTRIBUTION AND THEN COUNT HOW MANY
!     TIMES EACH DISTRIBUTION IS SELECTED BASED ON THE CUT-OFF
!     FOR ALPHA = 0.90, 0.95, AND 0.99.
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC NMCSAM=100
      NMCSA2=5000
      NCNT2=0
      NTEMP=N
      I90COR=0
      I95COR=0
      I99COR=0
      I90INC=0
      I95INC=0
      I99INC=0
!
      DO 6110 I=1,NMCSA2
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,6111)I
 6111     FORMAT('POWER SIMULATIONS: MONTE CARLO ITERATION ',I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        CALL DPRAN2(ICASP2,ISEED,YTEMP,NTEMP,TEMP1,   &
                    A,B,MINMAX,   &
                    SH1S2,SH2S2,SH3S2,SH4S2,   &
                    SH5S2,SH6S2,SH7S2,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                    IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
!
!               ***************************************************
!               **  STEP 6A-                                     **
!               **  COMPUTE ML ESTIMATES FOR FIRST DISTRIBUTION  **
!               ***************************************************
!
        ISTEPN='6A'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPML1(YTEMP,TEMP1,NTEMP,ICASPL,IFLAGD,IFLAG9,   &
                   TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                   DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                   ALOCT1,SCALT1,ALOWLI,AUPPLI,   &
                   SH1T1,SH2T1,SH3T1,SH4T1,   &
                   SH5T1,SH6T1,S7T1,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 6110
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,6121)ALOCT1,SCALT1,SH1T1,SH2T1
 6121     FORMAT('ML ESTIMATES FOR H0 DIST: ALOCT1,SCALT1,SH1T1,',   &
                 'SH2T1 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      IF(ALOCT1.EQ.CPUMIN)ALOCT1=0.0
!
!               ********************************************************
!               **  STEP 6B-                                         **
!               **  COMPUTE LIKELIHOOD VALUE FOR FIRST DISTRIBUTION  **
!               *******************************************************
!
        ISTEPN='6B'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPLIK1(YTEMP,TEMP1,NTEMP,ICASPL,   &
                    SH1T1,SH2T1,SH3T1,SH4T1,   &
                    SH5T1,SH6T1,SH7T1,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ALOCT1,SCALT1,   &
                    ALIKE1,AIC1,AICC1,BIC1,   &
                    IBUGA3,ISUBRO,IERROR)
!
!               ***************************************************
!               **  STEP 6C-                                     **
!               **  COMPUTE ML ESTIMATES FOR SECOND DISTRIBUTION **
!               ***************************************************
!
        ISTEPN='6C'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPML1(YTEMP,TEMP1,NTEMP,ICASP2,IFLAGD,IFLAG9,   &
                   TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                   DTEMP1,DTEMP2,DTEMP3,ITEMP1,MAXOBV,   &
                   ALOCT2,SCALT2,ALOWLI,AUPPLI,   &
                   SH1T2,SH2T2,SH3T2,SH4T2,   &
                   SH5T2,SH6T2,S7T2,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 6110
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,6131)ALOCT2,SCALT2,SH1T2,SH2T2
 6131     FORMAT('ML ESTIMATES FOR HA DIST: ALOCT2,SCALT2,',   &
                 'SH1T2,SH2T2 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      IF(ALOCT2.EQ.CPUMIN)ALOCT2=0.0
!
!               *******************************************************
!               **  STEP 6D-                                         **
!               **  COMPUTE LIKELIHOOD VALUE FOR SECOND DISTRIBUTION **
!               *******************************************************
!
        ISTEPN='6D'
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPLIK1(YTEMP,TEMP1,NTEMP,ICASP2,   &
                    SH1T2,SH2T2,SH3T2,SH4T2,   &
                    SH5T2,SH6T2,SH7T2,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ALOCT2,SCALT2,   &
                    ALIKE2,AIC2,AICC2,BIC2,   &
                    IBUGA3,ISUBRO,IERROR)
!
        NCNT2=NCNT2+1
        IF(ICASET.EQ.1)THEN
          STATT=SCALT1/SCALT2
        ELSEIF(ICASET.EQ.2)THEN
          STATT=SCALT1/SCALT2
        ELSEIF(ICASET.EQ.3)THEN
          STATT=SCALT1/SCALT2
        ELSEIF(ICASET.EQ.4)THEN
          STATT=SCALT1/SCALT2
        ELSE
          DSTAT=(DEXP(DBLE(ALIKE2))/DEXP(DBLE(ALIKE1)))**(1.0D0/DN)
          STATT=REAL(DSTAT)
          IF(ISNANZ(STATT))GO TO 6110
        ENDIF
!
!       NOW DETERMINE IF DISTRIBUTION CORRECTLY CLASSIFIED.
!
        IF(STATT.GT.CV90)THEN
          I90COR=I90COR+1
        ELSE
          I90INC=I90INC+1
        ENDIF
!
        IF(STATT.GT.CV95)THEN
          I95COR=I95COR+1
        ELSE
          I95INC=I95INC+1
        ENDIF
!
        IF(STATT.GT.CV99)THEN
          I99COR=I99COR+1
        ELSE
          I99INC=I99INC+1
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
          WRITE(ICOUT,6141)I,ALIKE1,ALIKE2,STATT
 6141     FORMAT('I,ALIKE1,ALIKE2,STATT = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 6110 CONTINUE
!
      APOW90=REAL(I90COR)/REAL(I90COR + I90INC)
      APOW95=REAL(I95COR)/REAL(I95COR + I95INC)
      APOW99=REAL(I99COR)/REAL(I99COR + I99INC)
!
!               ******************************
!               **   STEP 7--               **
!               **   WRITE OUT EVERYTHING   **
!               ******************************
!
      ISTEPN='7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Distributional Likelihood Ratio Test'
      NCTITL=36
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Data are from distribution -'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)(1:40)=IDIST1(1:40)
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: Data are from distribution -'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)(1:40)=IDIST2(1:40)
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='H0 Distribution:'
      NCTEXT(ICNT)=16
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(ALOCS1.NE.CPUMIN .AND. IFLGL1.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Location Parameter:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=ALOCS1
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(SCALS1.NE.CPUMIN .AND. IFLGS1.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Scale Parameter:'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=SCALS1
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(SH1S1.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Shape Parameter 1:'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=SH1S1
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(SH2S1.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Shape Parameter 2:'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=SH2S1
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha Distribution:'
      NCTEXT(ICNT)=16
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(ALOCS2.NE.CPUMIN .AND. IFLGL2.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Location Parameter:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=ALOCS2
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(SCALS2.NE.CPUMIN .AND. IFLGS2.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Scale Parameter:'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=SCALS2
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(SH1S2.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Shape Parameter 1:'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=SH1S2
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      IF(SH2S2.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Shape Parameter 2:'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=SH2S2
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Test:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF of Test Statistic:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value:'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=PVAL
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Simulations for CV:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=NCNT
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Simulations for Power:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=NCNT2
      IDIGIT(ICNT)=0
!
      NUMROW=ICNT
      DO 7210 I=1,NUMROW
        NTOT(I)=15
 7210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='7A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='7B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE=' '
      NCTITL=0
!
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:44)='Percent Points of the Reference Distribution'
      NCTITL=44
      NUMLIN=1
      NUMROW=NUMALP
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 7221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 7221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=1
      IDIGIT(3)=3
      DO 7223 I=1,NUMROW
        DO 7225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            AMAT(I,J)=ALPHA(I)
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            IF(I.EQ.1)THEN
              AMAT(I,J)=RND(CV50,IDIGIT(J))
            ELSEIF(I.EQ.2)THEN
              AMAT(I,J)=RND(CV75,IDIGIT(J))
            ELSEIF(I.EQ.3)THEN
              AMAT(I,J)=RND(CV80,IDIGIT(J))
            ELSEIF(I.EQ.4)THEN
              AMAT(I,J)=RND(CV90,IDIGIT(J))
            ELSEIF(I.EQ.5)THEN
              AMAT(I,J)=RND(CV95,IDIGIT(J))
            ELSEIF(I.EQ.6)THEN
              AMAT(I,J)=RND(CV99,IDIGIT(J))
            ELSEIF(I.EQ.7)THEN
              AMAT(I,J)=RND(CV999,IDIGIT(J))
            ENDIF
          ENDIF
 7225   CONTINUE
 7223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.FALSE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='7D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Upper 1-Tailed Test)'
      NCTITL=33
      NUMLIN=2
      NUMROW=3
      NUMCOL=5
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=1
      ITITL2(2,1)='Alpha'
      NCTIT2(2,1)=5
!
      ITITL2(1,2)=' '
      NCTIT2(1,2)=1
      ITITL2(2,2)='CDF'
      NCTIT2(2,2)=3
!
      ITITL2(1,3)='Power'
      NCTIT2(1,3)=5
      ITITL2(2,3)='(1-Beta)'
      NCTIT2(2,3)=8
!
      ITITL2(1,4)='Critical'
      NCTIT2(1,4)=8
      ITITL2(2,4)='Value'
      NCTIT2(2,4)=5
!
      ITITL2(1,5)=' '
      NCTIT2(1,5)=1
      ITITL2(2,5)='Conclusion'
      NCTIT2(2,5)=10
!
      NMAX=0
      DO 7321 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=7
        IF(I.EQ.3)NTOT(I)=10
        IF(I.EQ.4)NTOT(I)=10
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=3
        ITYPCO(I)='ALPH'
 7321 CONTINUE
      ITYPCO(3)='NUME'
      ITYPCO(4)='NUME'
      IDIGIT(1)=0
      IDIGIT(2)=0
      IDIGIT(3)=2
      IDIGIT(4)=3
      DO 7323 I=1,NUMROW
        DO 7325 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
 7325   CONTINUE
 7323 CONTINUE
      IVALUE(1,1)='10%'
      IVALUE(2,1)='5%'
      IVALUE(3,1)='1%'
      IVALUE(1,2)='90%'
      IVALUE(2,2)='95%'
      IVALUE(3,2)='99%'
      NCVALU(1,1)=3
      NCVALU(2,1)=2
      NCVALU(3,1)=2
      NCVALU(1,2)=3
      NCVALU(2,2)=3
      NCVALU(3,2)=3
      IF(STATVA.GT.CV90)IVALUE(1,5)='Reject H0'
      IF(STATVA.GT.CV95)IVALUE(2,5)='Reject H0'
      IF(STATVA.GT.CV99)IVALUE(3,5)='Reject H0'
      AMAT(1,3)=RND(APOW90,IDIGIT(3))
      AMAT(2,3)=RND(APOW95,IDIGIT(3))
      AMAT(3,3)=RND(APOW99,IDIGIT(3))
      AMAT(1,4)=RND(CV90,IDIGIT(4))
      AMAT(2,4)=RND(CV95,IDIGIT(4))
      AMAT(3,4)=RND(CV99,IDIGIT(4))
      IVALUE(1,5)='Accept H0'
      IVALUE(2,5)='Accept H0'
      IVALUE(3,5)='Accept H0'
      NCVALU(1,5)=9
      NCVALU(2,5)=9
      NCVALU(3,5)=9
!
      IWHTML(1)=125
      IWHTML(2)=125
      IWHTML(3)=125
      IWHTML(4)=150
      IWHTML(5)=150
      IWRTF(1)=1200
      IWRTF(2)=IWRTF(1)+1200
      IWRTF(3)=IWRTF(2)+1200
      IWRTF(4)=IWRTF(3)+2000
      IWRTF(5)=IWRTF(4)+2000
      IFRST=.FALSE.
      ILAST=.TRUE.
!
      ISTEPN='7E'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRD2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLRD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)STATVA,NMCSAM,PVAL,STATCD
 9012   FORMAT('STATVA,NMCSAM,PVAL,STATCD ',G15.7,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)CV50,CV75,CV90,CV95,CV99
 9014   FORMAT('CV50,CV75,CV90,CV95,CV99 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(NMCSAM.GT.1)THEN
          DO 9020 I=1,MIN(NMCSAM,100)
            WRITE(ICOUT,9021)I,YSTAT(I)
 9021       FORMAT('I,YSTAT(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLRD2
      SUBROUTINE DPLRD4(STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                        APOW90,APOW95,APOW99,   &
                        IFLAGU,IFRST,ILAST,ICASPL,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPLRDI.  THIS ROUTINE
!              UPDATES THE PARAMETERS "STATVAL", "STATCDF", AND
!              "PVALUE" AFTER A DISTRIBUTIONAL LIKELIHOOD RATIO
!              COMPUTATION.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/05
!     ORIGINAL VERSION--MAY       2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IST1CS
      CHARACTER*4 IOP
!
      SAVE IOUNI1
      SAVE IST1CS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRD4')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLRD4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,STATVA,STATCD,PVAL
   53   FORMAT('ICASPL,STATVA,STATCD,PVAL = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
!
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')THEN
            IST1CS='CLOS'
            GO TO 9000
          ELSE
            IST1CS='OPEN'
          ENDIF
!
          WRITE(IOUNI1,295)
  295     FORMAT(11X,'STATVAL',8X,'STATCDF',8X,'PVALUE',   &
                 7X,'CV90',11X,'CV95',11X,'CV99',11X,   &
                 'POW90',10X,'POW95',10X,'POW99')
  299     FORMAT(6E15.7)
        ENDIF
        IF(IST1CS.EQ.'OPEN')THEN
          WRITE(IOUNI1,299)STATVA,STATCD,PVAL,CV90,CV95,CV99,   &
                           APOW90,APOW95,APOW99
        ENDIF
      ELSEIF(IFLAGU.EQ.'ON')THEN
        IH='STAT'
        IH2='VAL '
        VALUE0=STATVA
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IF(STATCD.NE.CPUMIN)THEN
          IH='STAT'
          IH2='CDF '
          VALUE0=STATCD
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(PVAL.NE.CPUMIN)THEN
          IH='PVAL'
          IH2='UE  '
          VALUE0=PVAL
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CV90.NE.CPUMIN)THEN
          IH='CUTO'
          IH2='FF90'
          VALUE0=CV90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CV95.NE.CPUMIN)THEN
          IH='CUTO'
          IH2='FF95'
          VALUE0=CV95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CV99.NE.CPUMIN)THEN
          IH='CUTO'
          IH2='FF99'
          VALUE0=CV99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(APOW90.NE.CPUMIN)THEN
          IH='POWE'
          IH2='R90 '
          VALUE0=APOW90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(APOW95.NE.CPUMIN)THEN
          IH='POWE'
          IH2='R95 '
          VALUE0=APOW95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(APOW99.NE.CPUMIN)THEN
          IH='POWE'
          IH2='R99 '
          VALUE0=APOW99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
      IF(ILAST .AND. IFLAGU.EQ.'FILE' .AND. IST1CS.EQ.'OPEN')THEN
        IOP='CLOS'
        IFLAG1=1
        IFLAG2=0
        IFLAG3=0
        IFLAG4=0
        IFLAG5=0
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
        IST1CS='CLOS'
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRD4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPLRD4--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLRD4
      SUBROUTINE DPLRST(MAXNXT,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT A 2-SAMPLE LINEAR RANK SUM TEST FOR EITHER
!              EQUAL LOCATION OR EQUAL SCALE.
!     EXAMPLE--TWO SAMPLE LINEAR RANK SUM TEST Y1 Y2
!              TWO SAMPLE LINEAR RANK SUM TEST Y1 Y2 Y3 Y4
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/07
!     ORIGINAL VERSION--JULY      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
      CHARACTER*4 ICTMP5
      CHARACTER*4 ICTMP6
      CHARACTER*4 ICTMP7
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION TEMP1(2*MAXOBV)
      DIMENSION TEMP2(2*MAXOBV)
      DIMENSION TEMP3(2*MAXOBV)
      DIMENSION SCORE(2*MAXOBV)
      DIMENSION TAG(2*MAXOBV)
      EQUIVALENCE(GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE(GARBAG(IGARB3),TEMP2(1))
      EQUIVALENCE(GARBAG(IGARB5),TEMP3(1))
      EQUIVALENCE(GARBAG(IGARB7),SCORE(1))
      EQUIVALENCE(GARBAG(IGARB9),TAG(1))
      EQUIVALENCE(GARBAG(JGAR11),Y1(1))
      EQUIVALENCE(GARBAG(JGAR12),Y2(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLR'
      ISUBN2='ST  '
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               *****************************************************
!               **  TREAT THE TWO SAMPLE LINEAR RANK SUM TEST CASE **
!               *****************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRST')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLRST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  EXTRACT THE COMMAND                                **
!               *********************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTZ=9999
      ICASAN='LRST'
      ICASA2='TWOT'
      ICASA3='TEST'
!
!     LOOK FOR:
!
!          TWO SAMPLE LINEAR RANK SUM TEST
!          2   SAMPLE LINEAR RANK SUM TEST
!          LOWER TAILED
!          UPPER TAILED
!
      DO 100 I=0,NUMARG-1
!
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
        ELSE
          ICTMP1=IHARG(I)
        ENDIF
        ICTMP2=IHARG(I+1)
        ICTMP3=IHARG(I+2)
        ICTMP4=IHARG(I+3)
        ICTMP5=IHARG(I+4)
        ICTMP6=IHARG(I+5)
        ICTMP7=IHARG(I+6)
!
        IF(ICTMP1.EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(ICTMP1.EQ.'TWO ' .AND. ICTMP2.EQ.'SAMP' .AND.   &
               ICTMP3.EQ.'LINE' .AND. ICTMP4.EQ.'RANK' .AND.   &
               ICTMP5.EQ.'SUM ' .AND. ICTMP6.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='LRST'
          ILASTZ=I+5
        ELSEIF(ICTMP1.EQ.'TWO ' .AND. ICTMP2.EQ.'SAMP' .AND.   &
               ICTMP3.EQ.'LINE' .AND. ICTMP4.EQ.'RANK' .AND.   &
               ICTMP5.EQ.'SUM ' .AND. ICTMP6.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='LRST'
          ILASTZ=I+5
!CCCC   ELSEIF(ICTMP1.EQ.'TWO ' .AND. ICTMP2.EQ.'SAMP' .AND.
!CCCC1         ICTMP3.EQ.'LINE' .AND. ICTMP4.EQ.'RANK' .AND.
!CCCC1         ICTMP5.EQ.'SUM ' .AND. ICTMP6.EQ.'CONF' .AND.
!CCCC1         (ICTMP7.EQ.'INTE' .OR. ICTMP7.EQ.'LIMI'))THEN
!CCCC     IFOUND='YES'
!CCCC     ICASAN='LRST'
!CCCC     ICASA3='CONF'
!CCCC     ILASTZ=I+6
!CCCC   ELSEIF(ICTMP1.EQ.'2   ' .AND. ICTMP2.EQ.'SAMP' .AND.
!CCCC1         ICTMP3.EQ.'LINE' .AND. ICTMP4.EQ.'RANK' .AND.
!CCCC1         ICTMP5.EQ.'SUM ' .AND. ICTMP6.EQ.'CONF' .AND.
!CCCC1         (ICTMP7.EQ.'INTE' .OR. ICTMP7.EQ.'LIMI'))THEN
!CCCC     IFOUND='YES'
!CCCC     ICASAN='LRST'
!CCCC     ICASA3='CONF'
        ELSEIF(ICTMP1.EQ.'TWO ' .AND. ICTMP2.EQ.'SAMP' .AND.   &
               ICTMP3.EQ.'LINE' .AND. ICTMP4.EQ.'RANK' .AND.   &
               ICTMP5.EQ.'SUM ')THEN
          IFOUND='YES'
          ICASAN='LRST'
          ILASTZ=I+4
        ELSEIF(ICTMP1.EQ.'TWO ' .AND. ICTMP2.EQ.'SAMP' .AND.   &
               ICTMP3.EQ.'LINE' .AND. ICTMP4.EQ.'RANK' .AND.   &
               ICTMP5.EQ.'SUM ')THEN
          IFOUND='YES'
          ICASAN='LRST'
          ILASTZ=I+4
        ELSEIF(ICTMP1.EQ.'LOWE' .AND. ICTMP2.EQ.'TAIL')THEN
          ICASA2='LOWE'
          ILASTZ=MAX(ILASTZ,I+1)
        ELSEIF(ICTMP1.EQ.'UPPE' .AND. ICTMP2.EQ.'TAIL')THEN
          ICASA2='UPPE'
          ILASTZ=MAX(ILASTZ,I+1)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRST')THEN
        WRITE(ICOUT,91)ICASAN,ICASA2,ICASA3,ISHIFT
   91   FORMAT('DPLRST: ICASAN,ICASA2,ICASA3,ISHIFT = ',   &
               3(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='TWO SAMPLE LINEAR RANK TEST'
      MINNA=1
      MAXNA=100
      MINN2=3
      IFLAGE=0
      IFLAGM=1
      MINNVA=2
      MAXNVA=MAXSPN
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRST')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 3A--                                       **
!               **  CASE 1: TWO RESPONSE VARIABLES, NO REPLICATION  **
!               ******************************************************
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRST')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVA2=1
      DO 5210 I=1,NUMVAR
        ICOL=I
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,Y1,Y1,NS1,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        ISTRT2=I+1
        ISTOP2=NUMVAR
!
        DO 5220 J=ISTRT2,ISTOP2
!
          ICOL=J
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y2,Y2,Y2,NS2,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               *************************************************
!               **  STEP 52--                                  **
!               **  PERFORM A STWO SAMPLE LINEAR RANK SUM TEST **
!               *************************************************
!
          ISTEPN='52'
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRST')THEN
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5211)
 5211       FORMAT('***** FROM DPLRST, BEFORE CALL DPLRS2--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5212)I,J,NS1,NS2,MAXN
 5212       FORMAT('I,J,NS1,NS2,MAXN = ',5I8)
            CALL DPWRST('XXX','BUG ')
            DO 5215 II=1,MAX(NS1,NS2)
              WRITE(ICOUT,5216)II,Y1(II),Y2(II)
 5216         FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
 5215       CONTINUE
          ENDIF
!
          IVARID=IVARN1(I)
          IVARI2=IVARN2(I)
          IVARI3=IVARN1(J)
          IVARI4=IVARN2(J)
          MAXNX2=2*MAXNXT
          CALL DPLRS2(Y1,NS1,Y2,NS2,ICASA2,ICASA3,ILRASC,   &
                      SCORE,TAG,TEMP1,TEMP2,TEMP3,MAXNX2,   &
                      ICAPSW,ICAPTY,IFORSW,   &
                      IVARID,IVARI2,IVARI3,IVARI4,   &
                      STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                      CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                      CTU999,CTU995,CTU990,CT975,CTU950,CTU900,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LRST')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(NUMVAR.GT.2)THEN
            IFLAGU='FILE'
          ELSE
            IFLAGU='ON'
          ENDIF
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(I.EQ.1 .AND. J.EQ.2)IFRST=.TRUE.
          IF(I.EQ.NUMVAR .AND. J.EQ.NUMVAR)ILAST=.TRUE.
          CALL DPMNN5(ICASA2,   &
                      STATVA,STATCD,   &
                      PVAL2T,PVALLT,PVALUT,   &
                      CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                      CTU999,CTU995,CTU990,CT975,CTU950,CTU900,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
 5220   CONTINUE
 5210 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LRST')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLRST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLRST
      SUBROUTINE DPLRS2(Y1,N1,Y2,N2,ICASAN,ICASA3,ILRASC,   &
                        SCORE,TAG,TEMP1,TEMP2,TEMP3,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IVARID,IVARI2,IVARI3,IVARI4,   &
                        STATVA,STATCD,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                        CTU999,CTU995,CTU990,CTU975,CTU950,CTU900,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT A 2-SAMPLE LINEAR RANK SUM TEST.
!              SPECIFICALLY,
!
!              1. COMPUTE THE TEST STATISTIC
!
!                    S = SUM[i=1 to n][tag(i)*a(R(i))]
!
!                 WHERE
!
!                    R(i)     IS THE RANK OF THE i-TH OBSERVATION
!                    a(R(i))  IS A SCORE BASED ON THE RANK OF THE i-TH
!                             OBSERVATION
!                    tag(i)   IS THE GROUP-ID OF THE i-TH OBSERVATION
!                    n        IS THE TOTAL NUMNBER OF OBSERVATIONS
!
!                 NOTE THAT TAG MUST HAVE EXACTLY TWO DISTINCT VALUES.
!
!                 THE FOLLOWING SCORES FOR TESTING EQUAL LOCATIONS ARE
!
!                    1. WILCOX:          a(R(I)) = R(i)
!                    2. MEDIAN:          a(R(I)) = 1    if R(i) >  (n+1)/2
!                                                = 0    if R(i) <= (n+1)/2
!                    3. SAVAGE:          a(R(i)) = SUM[j=1 to R(i)]
!                                                  [1/(n-j+1)]
!                                                  (used for testing equal
!                                                  locations of Gumbel
!                                                  distributions)
!                    4. VAN DER WAERDEN: a(R(i)) = NORPPF(R(i)/(n+1))
!
!                 THE FOLLOWING SCORES FOR TESTING EQUAL DISPERSION ARE
!
!                    1. ANSARI BRADLEY:  a(R(I)) = (n+1)/2 - |R(i) - (N+1)/2|
!                    2. KLOTZ:           a(R(I)) = (NORPPF(R(i)/(n+1)))**2
!                    3. MOOD:            a(R(I)) = (R(i) - (n+1)/2)**2
!                    4. CONOVER:         a(R(I)) = (Rank(U(i))**2
!                                                  U(i)=|X(ij) - XBAR(j)|
!                                                  (XBAR = MEAN OF J-TH GROUP)
!                    5. SAVAGE:          a(R(i)) = SUM[j=1 to R(i)]
!                                                  [1/(n-j+1)]
!                                                  (used for testing equal
!                                                  scales of exponential
!                                                  distributions)
!     EXAMPLE--STWO SAMPLE LINEAR RANK SUM TEST Y1 Y2
!     SAMPLE 1 IS IN INPUT VECTOR Y1 (WITH N1 OBSERVATIONS).
!     SAMPLE 2 IS IN INPUT VECTOR Y2 (WITH N2 OBSERVATIONS).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/07
!     ORIGINAL VERSION--JULY      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA3
      CHARACTER*4 ILRASC
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!CCCC CHARACTER*4 ICASA2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION SCORE(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
!
!CCCC DIMENSION CONF(5)
!CCCC DIMENSION T(5)
!CCCC DIMENSION TSDERR(5)
!CCCC DIMENSION ALOWER(5)
!CCCC DIMENSION AUPPER(5)
!
!     PARAMETER (NUMALP=6)
!     REAL ALPHA(NUMALP)
      PARAMETER (NUMAL2=4)
      REAL ALPHA2(NUMAL2)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=40)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!     DATA ALPHA/0.90, 0.95, 0.975, 0.99, 0.995, 0.999/
      DATA ALPHA2/0.80, 0.90, 0.95, 0.99/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLR'
      ISUBN2='S2  '
      IERROR='NO'
      IWRITE='OFF'
!
      CTL001=0.0
      CTL005=0.0
      CTL010=0.0
      CTL025=0.0
      CTL050=0.0
      CTL100=0.0
      CTU999=0.0
      CTU995=0.0
      CTU990=0.0
      CTU975=0.0
      CTU950=0.0
      CTU900=0.0
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      CTL001=CPUMIN
      CTL005=CPUMIN
      CTL010=CPUMIN
      CTL025=CPUMIN
      CTL050=CPUMIN
      CTL100=CPUMIN
      CTU900=CPUMIN
      CTU950=CPUMIN
      CTU975=CPUMIN
      CTU990=CPUMIN
      CTU995=CPUMIN
      CTU999=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRS2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPLRS2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA3,ILRASC
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,ICASA3,ILRASC = ',4(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)IVARID,IVARI2,IVARI3,IVARI4
   53   FORMAT('IVARID,IVARI2,IVARI3,IVARI4 = ',3(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)MAXNXT,N1,NUMDIG,D0
   55   FORMAT('MAXNST,N1,NUMDIG,D0 = ',3I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(N1.GE.1)THEN
          DO 56 I=1,N1
            WRITE(ICOUT,57)I,Y1(I),Y2(I)
   57       FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ENDIF
      ENDIF
!
!               ************************************
!               **   STEP 1--                     **
!               **   CALL DPSGT3 TO COMPUTE THE   **
!               **   BASIC TEST STATISTIC         **
!               ************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y1,N1,IWRITE,YMEAN1,IBUGA3,IERROR)
      CALL SD(Y1,N1,IWRITE,YSD1,IBUGA3,IERROR)
      CALL MEDIAN(Y1,N1,IWRITE,TEMP1,MAXNXT,YMED1,IBUGA3,IERROR)
      CALL MEAN(Y2,N2,IWRITE,YMEAN2,IBUGA3,IERROR)
      CALL MEDIAN(Y2,N2,IWRITE,TEMP1,MAXNXT,YMED2,IBUGA3,IERROR)
      CALL SD(Y2,N2,IWRITE,YSD2,IBUGA3,IERROR)
!
      ALPHAZ=0.95
      CALL DPLRS3(Y1,N1,Y2,N2,ILRASC,SCORE,TAG,   &
                  TEMP1,TEMP2,TEMP3,MAXNXT,   &
                  S,STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  STATME,STATSD,STATVA,   &
                  ALPHAZ,ALCL,UCL,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               ***************************************
!               **  STEP 21--                        **
!               **  COMPUTE THE CRITICAL VALUES FOR  **
!               **  VARIOUS VALUES OF ALPHA          **
!               ***************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NORMAL APPROXIMATION VALUES
!
      CALL NORPPF(.005,CTL005)
      CALL NORPPF(.010,CTL010)
      CALL NORPPF(.025,CTL025)
      CALL NORPPF(.050,CTL050)
      CALL NORPPF(.100,CTL100)
      CALL NORPPF(.200,CTL200)
      CALL NORPPF(.500,CTL500)
      CALL NORPPF(.500,CTU500)
      CALL NORPPF(.800,CTU800)
      CALL NORPPF(.900,CTU900)
      CALL NORPPF(.950,CTU950)
      CALL NORPPF(.975,CTU975)
      CALL NORPPF(.990,CTU990)
      CALL NORPPF(.995,CTU995)
!
!               *************************************************
!               **   STEP 22--                                 **
!               **   WRITE OUT EVERYTHING FOR A TWO SAMPLE     **
!               **   LINEAR RANK SUM TEST                      **
!               *************************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      IF(ICASA3.EQ.'TEST')THEN
        IF(ICASAN.EQ.'LOWE')THEN
          ITITLE='Two Sample Lower-Tailed Linear Rank Sum Test'
          NCTITL=44
        ELSEIF(ICASAN.EQ.'UPPE')THEN
          ITITLE='Two Sample Upper-Tailed Linear Rank Sum Test'
          NCTITL=44
        ELSE
          ITITLE='Two Sample Two-Sided Linear Rank Sum Test'
          NCTITL=41
        ENDIF
      ELSE
!CCCC   ITITLE='Confidence Interval for the Linear Rank Sum'
!CCCC   NCTITL=44
      ENDIF
!
      IF(ILRASC.EQ.'WILC')THEN
        ITITLZ='(Wilcoxon Scores)'
        NCTITZ=17
      ELSEIF(ILRASC.EQ.'MEDI')THEN
        ITITLZ='(Median Scores)'
        NCTITZ=15
      ELSEIF(ILRASC.EQ.'MOOD')THEN
        ITITLZ='(Mood Scores)'
        NCTITZ=13
      ELSEIF(ILRASC.EQ.'VAND')THEN
        ITITLZ='(Van Der Waerden Scores)'
        NCTITZ=24
      ELSEIF(ILRASC.EQ.'CONO')THEN
        ITITLZ='(Conover Scores)'
        NCTITZ=16
      ELSEIF(ILRASC.EQ.'KLOT')THEN
        ITITLZ='(Klotz Scores)'
        NCTITZ=14
      ELSEIF(ILRASC.EQ.'SAVA')THEN
        ITITLZ='(Savage Scores)'
        NCTITZ=15
      ELSEIF(ILRASC.EQ.'ANSA')THEN
        ITITLZ='(Ansari Bradley Scores)'
        NCTITZ=23
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='First Response Variable: '
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(30:33),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Response Variable: '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
      WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI4(1:4)
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICASA3.EQ.'TEST')THEN
!
!       HYPOTHESIS TEST CASE
!
        IF(ILRASC.EQ.'WILC' .OR. ILRASC.EQ.'VAND' .OR.   &
         ILRASC.EQ.'MEDI' .OR. ILRASC.EQ.'SAVA')THEN
          IF(ICASAN.EQ.'TWOT')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='H0: Location1 = Location2'
            NCTEXT(ICNT)=26
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='Ha: Location1 not equal Location2'
            NCTEXT(ICNT)=34
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ELSEIF(ICASAN.EQ.'LOWE')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='H0: Location1 < Location2'
            NCTEXT(ICNT)=25
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='Ha: Location1 >= Location2'
            NCTEXT(ICNT)=29
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ELSEIF(ICASAN.EQ.'UPPE')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='H0: Location1 > Location2'
            NCTEXT(ICNT)=25
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='Ha: Location1 <= Location2'
            NCTEXT(ICNT)=27
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ENDIF
        ELSE
          IF(ICASAN.EQ.'TWOT')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='H0: Scale1 = Scale2'
            NCTEXT(ICNT)=19
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='Ha: Scale1 not equal Scale2'
            NCTEXT(ICNT)=27
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ELSEIF(ICASAN.EQ.'LOWE')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='H0: Scale1 < Scale2'
            NCTEXT(ICNT)=19
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='Ha: Scale1 >= Scale2'
            NCTEXT(ICNT)=20
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ELSEIF(ICASAN.EQ.'UPPE')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='H0: Scale1 > Scale2'
            NCTEXT(ICNT)=19
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
            ICNT=ICNT+1
            ITEXT(ICNT)='Ha: Scale1 <= Scale2'
            NCTEXT(ICNT)=20
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ENDIF
        ENDIF
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations for Sample 1:'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Mean for Sample 1:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=YMEAN1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Median for Sample 1:'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=YMED1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Deviation for Sample 1:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=YSD1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations for Sample 2:'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=REAL(N2)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Mean for Sample 2:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=YMEAN2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Median for Sample 2:'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=YMED2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Deviation for Sample 2:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=YSD2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICASA3.EQ.'TEST')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Test (Normal Approximation):'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Test Statistic Value:'
        NCTEXT(ICNT)=21
        AVALUE(ICNT)=STATVA
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Score Value:'
        NCTEXT(ICNT)=12
        AVALUE(ICNT)=S
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Expected Value of Test Statistic:'
        NCTEXT(ICNT)=33
        AVALUE(ICNT)=STATME
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Standard Deviation of Test Statistic:'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=STATSD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='CDF Value:'
        NCTEXT(ICNT)=10
        AVALUE(ICNT)=STATCD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='P-Value (2-tailed test):'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=PVAL2T
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='P-Value (lower-tailed test):'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=PVALLT
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='P-Value (upper-tailed test):'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=PVALUT
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      NUMROW=ICNT
      DO 2110 I=1,NUMROW
        NTOT(I)=15
 2110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='21A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(ICASA3.EQ.'TEST')THEN
        ISTEPN='21B'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(ICASAN.EQ.'TWOT')THEN
          ITITLE='Two-Tailed Test: Normal Approximation'
          NCTITL=37
        ELSEIF(ICASAN.EQ.'LOWE')THEN
          ITITLE='Lower-Tailed Test: Normal Approximation'
          NCTITL=39
        ELSEIF(ICASAN.EQ.'UPPE')THEN
          ITITLE='Upper-Tailed Test: Normal Approximation'
          NCTITL=39
        ENDIF
        ITITL9=' '
        NCTIT9=0
!
        DO 2130 J=1,NUMCLI
          DO 2140 I=1,MAXLIN
            ITITL2(I,J)=' '
            NCTIT2(I,J)=0
 2140     CONTINUE
 2130   CONTINUE
!
        IF(ICASAN.NE.'TWOT')THEN
          NUMCOL=4
          ITITL2(2,1)='Significance'
          NCTIT2(2,1)=12
          ITITL2(3,1)='Level'
          NCTIT2(3,1)=5
!
          ITITL2(2,2)='Test '
          NCTIT2(2,2)=4
          ITITL2(3,2)='Statistic'
          NCTIT2(3,2)=9
!
          ITITL2(2,3)='Critical'
          NCTIT2(2,3)=8
          IF(ICASAN.EQ.'LOWE')THEN
            ITITL2(3,3)='Value (<)'
            NCTIT2(3,3)=9
          ELSE
            ITITL2(3,3)='Value (>)'
            NCTIT2(3,3)=9
          ENDIF
!
          ITITL2(1,4)='Null'
          NCTIT2(1,4)=4
          ITITL2(2,4)='Hypothesis'
          NCTIT2(2,4)=10
          ITITL2(3,4)='Conclusion'
          NCTIT2(3,4)=10
!
        ELSE
          NUMCOL=5
          ITITL2(2,1)='Significance'
          NCTIT2(2,1)=12
          ITITL2(3,1)='Level'
          NCTIT2(3,1)=5
!
          ITITL2(2,2)='Test '
          NCTIT2(2,2)=4
          ITITL2(3,2)='Statistic'
          NCTIT2(3,2)=9
!
          ITITL2(1,3)='Lower'
          NCTIT2(1,3)=5
          ITITL2(2,3)='Critical'
          NCTIT2(2,3)=8
          ITITL2(3,3)='Value (<)'
          NCTIT2(3,3)=9
!
          ITITL2(1,4)='Upper'
          NCTIT2(1,4)=5
          ITITL2(2,4)='Critical'
          NCTIT2(2,4)=8
          ITITL2(3,4)='Value (>)'
          NCTIT2(3,4)=9
!
          ITITL2(1,5)='Null'
          NCTIT2(1,5)=4
          ITITL2(2,5)='Hypothesis'
          NCTIT2(2,5)=10
          ITITL2(3,5)='Conclusion'
          NCTIT2(3,5)=10
!
        ENDIF
!
        NMAX=0
        DO 2150 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT(I)=15
          NMAX=NMAX+NTOT(I)
          ITYPCO(I)='NUME'
          IDIGIT(I)=NUMDIG
          IF(ICASAN.NE.'TWOT')THEN
            IF(I.EQ.1 .OR. I.EQ.4)THEN
              ITYPCO(I)='ALPH'
            ENDIF
          ELSE
            IF(I.EQ.1 .OR. I.EQ.5)THEN
              ITYPCO(I)='ALPH'
            ENDIF
          ENDIF
 2150   CONTINUE
!
        IWHTML(1)=125
        IWHTML(2)=175
        IWHTML(3)=175
        IWHTML(4)=175
        IWHTML(5)=175
        IINC=1800
        IINC2=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
        IWRTF(5)=IWRTF(4)+IINC
!
        DO 2160 J=1,NUMAL2
!
          AMAT(J,2)=STATVA
          IF(ICASAN.EQ.'TWOT')THEN
            ALPHAT=ALPHA2(J)
            ATEMP=(1.0 - ALPHAT)/2.0
            ATEMP=1.0 - ATEMP
            CALL NORPPF(ATEMP,CUTTMP)
            AMAT(J,3)=-CUTTMP
            AMAT(J,4)=CUTTMP
            IVALUE(J,5)(1:6)='REJECT'
            IF(ABS(STATVA).LT.AMAT(J,4))THEN
              IVALUE(J,5)(1:6)='ACCEPT'
            ENDIF
            NCVALU(J,5)=6
!
            WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
            IVALUE(J,1)(5:5)='%'
            NCVALU(J,1)=5
          ELSEIF(ICASAN.EQ.'LOWE' .OR. ICASAN.EQ.'UPPE')THEN
            IVALUE(J,4)(1:6)='REJECT'
            ALPHAT=ALPHA2(J)
            CALL NORPPF(ALPHAT,CUTTMP)
            IF(ICASAN.EQ.'LOWE')THEN
              CUTTMP=-ABS(CUTTMP)
              IF(STATVA.GT.CUTTMP)THEN
                IVALUE(J,4)(1:6)='ACCEPT'
              ENDIF
            ELSEIF(ICASAN.EQ.'UPPE')THEN
              CUTTMP=ABS(CUTTMP)
              IF(STATVA.LT.CUTTMP)THEN
                IVALUE(J,4)(1:6)='ACCEPT'
              ENDIF
            ENDIF
            AMAT(J,3)=CUTTMP
            NCVALU(J,4)=6
!
            WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
            IVALUE(J,1)(5:5)='%'
            NCVALU(J,1)=5
          ENDIF
 2160   CONTINUE
!
        NUMLIN=3
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
!
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMAL2,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSE
!
!       CONFIDENCE INTERVAL CASE.  THIS DOESN'T ACTUALLY MAKE
!       SENSE SO DE-ACTIVATE FOR NOW.
!
!CCCC   ISTEPN='5B'
!CCCC   IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS2')
!CCCC1    CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC   ICASA2='LRST'
!CCCC   CONF(1)=80.0
!CCCC   CONF(2)=90.0
!CCCC   CONF(3)=95.0
!CCCC   CONF(4)=99.0
!CCCC   CONF(5)=99.9
!CCCC   CALL NORPPF(.900,T(1))
!CCCC   CALL NORPPF(.950,T(2))
!CCCC   CALL NORPPF(.975,T(3))
!CCCC   CALL NORPPF(.995,T(4))
!CCCC   CALL NORPPF(.9995,T(5))
!CCCC   DO3010I=1,5
!CCCC     TSDERR(I)=STATSD
!CCCC     ALOWER(I)=STATVA - T(I)*STATSD
!CCCC     AUPPER(I)=STATVA + T(I)*STATSD
!3010   CONTINUE
!
!CCCC   CALL DPDT11(CONF,T,TSDERR,ALOWER,AUPPER,
!CCCC1              ICASA2,ICAPSW,ICAPTY,NUMDIG,
!CCCC1              ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LRS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLRS2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATCD,PVAL2T,PVALLT,PVALUT
 9013   FORMAT('STATVA,STATCD,PVAL2T,PVALLT,PVALUT = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLRS2
      SUBROUTINE DPLRS3(Y1,N1,Y2,N2,ILRASC,SCORE,TAG,   &
                        TEMP1,TEMP2,TEMP3,MAXNXT,   &
                        S,STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                        AMEAN,SD,VAR,   &
                        ALPHA,LCL,UCL,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES A TWO SAMPLE LINEAR SUM RANK TEST.
!              SPECIFICALLY,
!
!              1. COMPUTE THE TEST STATISTIC
!
!                    S = SUM[i=1 to n][tag(i)*a(R(i))]
!
!                 WHERE
!
!                    R(i)     IS THE RANK OF THE i-TH OBSERVATION
!                    a(R(i))  IS A SCORE BASED ON THE RANK OF THE i-TH
!                             OBSERVATION
!                    tag(i)   IS THE GROUP-ID OF THE i-TH OBSERVATION
!                    n        IS THE TOTAL NUMNBER OF OBSERVATIONS
!
!                 NOTE THAT TAG MUST HAVE EXACTLY TWO DISTINCT VALUES.
!
!                 THE FOLLOWING SCORES FOR TESTING EQUAL LOCATIONS ARE
!
!                    1. WILCOX:          a(R(I)) = R(i)
!                    2. MEDIAN:          a(R(I)) = 1    if R(i) >  (n+1)/2
!                                                = 0    if R(i) <= (n+1)/2
!                    3. SAVAGE:          a(R(i)) = SUM[j=1 to R(i)]
!                                                  [1/(n-j+1)]
!                                                  (used for testing equal
!                                                  locations of Gumbel
!                                                  distributions)
!                    4. VAN DER WAERDEN: a(R(i)) = NORPPF(R(i)/(n+1))
!
!                 THE FOLLOWING SCORES FOR TESTING EQUAL DISPERSION ARE
!
!                    1. ANSARI BRADLEY:  a(R(I)) = (n+1)/2 - |R(i) - (N+1)/2|
!                    2. KLOTZ:           a(R(I)) = (NORPPF(R(i)/(n+1)))**2
!                    3. MOOD:            a(R(I)) = (R(i) - (n+1)/2)**2
!                    4. CONOVER:         a(R(I)) = (Rank(U(i))**2
!                                                  U(i)=|X(ij) - XBAR(j)|
!                                                  (XBAR = MEAN OF J-TH GROUP)
!                    5. SAVAGE:          a(R(i)) = SUM[j=1 to R(i)]
!                                                  [1/(n-j+1)]
!                                                  (used for testing equal
!                                                  scales of exponential
!                                                  distributions)
!     EXAMPLE--TWO SAMPLE LINEAR RANK SUM TEST Y1 Y2
!              SAMPLE 1 IS IN INPUT VECTOR Y1 (WITH N1 OBSERVATIONS)
!              SAMPLE 2 IS IN INPUT VECTOR Y2 (WITH N2 OBSERVATIONS).
!     REFERENCE--xx
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/06
!     ORIGINAL VERSION--JULY      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL        LCL
!
      CHARACTER*4 ILRASC
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION SCORE(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLR'
      ISUBN2='S3  '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=CPUMIN
      STATV1=CPUMIN
      STATV2=CPUMIN
      STATV3=CPUMIN
      STATCD=CPUMIN
      PVAL2T=CPUMIN
      PVALLT=CPUMIN
      PVALUT=CPUMIN
!
      DO 10 II=1,MAXNXT
        SCORE(II)=0.0
        TAG(II)=0.0
        TEMP1(II)=0.0
        TEMP2(II)=0.0
        TEMP3(II)=0.0
   10 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPLRS3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ILRASC,N1,N2,ALPHA
   52   FORMAT('IBUGA3,ISUBRO,ILRASC,N1,N2,ALPHA = ',   &
               3(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MAX(N1,N2)
          WRITE(ICOUT,57)I,Y1(I),Y2(I)
   57     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LE.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN TWO SAMPLE LINEAR RANK SUM TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE MUST BE 3 OR LARGER.  SUCH WAS NOT THE ',   &
               'CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N1
  117   FORMAT('      THE NUMBER OF OBSERVATIONS   = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LE.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N2
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************
!               **   STEP 2--                     **
!               **   CREATE COMBINED DATA SET AND **
!               **   BASIC TEST STATISTIC         **
!               ************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LE.N2)THEN
        DO 205 II=1,N1
          TAG(II)=1.0
  205   CONTINUE
        DO 210 II=1,N2
          Y1(N1+II)=Y2(II)
          TAG(N1+II)=0.0
  210   CONTINUE
        N=N1+N2
      ELSE
        DO 225 II=1,N1
          TAG(II)=0.0
  225   CONTINUE
        DO 230 II=1,N2
          Y1(N1+II)=Y2(II)
          TAG(N1+II)=1.0
  230   CONTINUE
        N=N1+N2
      ENDIF
!
!     CALL THE APPROPRIATE SCORE STATISTIC
!
      IF(ILRASC.EQ.'WILC')THEN
        CALL RANK(Y1,N,IWRITE,SCORE,TEMP1,MAXNXT,IBUGA3,IERROR)
      ELSEIF(ILRASC.EQ.'SAVA')THEN
        CALL SSCORE(Y1,N,IWRITE,SCORE,IBUGA3,ISUBRO,IERROR)
      ELSEIF(ILRASC.EQ.'CONO')THEN
        CALL CSCORE(Y1,TAG,N,IWRITE,SCORE,TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSEIF(ILRASC.EQ.'VAND')THEN
        CALL VSCORE(Y1,N,IWRITE,SCORE,TEMP1,MAXNXT,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSEIF(ILRASC.EQ.'ANSA')THEN
        CALL ASCORE(Y1,N,IWRITE,SCORE,TEMP1,MAXNXT,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSEIF(ILRASC.EQ.'MOOD')THEN
        CALL MSCORE(Y1,N,IWRITE,SCORE,TEMP1,MAXNXT,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSEIF(ILRASC.EQ.'MEDI')THEN
        CALL DSCORE(Y1,N,IWRITE,SCORE,TEMP1,MAXNXT,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSEIF(ILRASC.EQ.'KLOT')THEN
        CALL KSCORE(Y1,N,IWRITE,SCORE,TEMP1,MAXNXT,   &
                    IBUGA3,ISUBRO,IERROR)
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,252)ILRASC
  252   FORMAT('      THE REQUESTED SCORE (',A4,') IS NOT CURRENTLY ',   &
               'SUPPORTED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
      STATVA=0.0
      SUM1=0.0
      SUM2=0.0
      NTEMP=0
      DO 260 I=1,N
        IF(TAG(I).EQ.1.0)THEN
          STATVA=STATVA + SCORE(I)
          NTEMP=NTEMP+1
        ENDIF
        SUM1=SUM1 + SCORE(I)
  260 CONTINUE
      S=STATVA
      AMEAN=(REAL(NTEMP)/REAL(N))*SUM1
      AVESCO=SUM1/REAL(N)
      DO 270 I=1,N
        SUM2=SUM2 + (SCORE(I) - AVESCO)**2
  270 CONTINUE
      AFACT=REAL(N1)*REAL(N2)/(REAL(N)*(REAL(N)-1.0))
      VAR=AFACT*SUM2
      SD=SQRT(VAR)
      STATVA=(STATVA - AMEAN)/SD
      CALL NORCDF(STATVA,STATCD)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(STATVA.LE.0.0)THEN
        PVAL2T=2.0*PVALLT
      ELSE
        PVAL2T=2.0*PVALUT
      ENDIF
!
!     GENERATE CONFIDENCE LIMITS - NOT SURE ABOUT THIS SECTION,
!     COMMENT OUT FOR NOW.
!
!CCCC ALPHAT=ALPHA
!CCCC IF(ALPHA.GE.1.0 .AND. ALPHA.LT.100.0)ALPHAT=ALPHA/100.
!CCCC IF(ALPHAT.LE.0.0 .OR.  ALPHAT.GE.1.0)ALPHAT=0.05
!CCCC IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
!CCCC ALPHAT=ALPHAT/2.0
!CCCC ADF=REAL(N-1)
!CCCC CALL TPPF(ALPHAT,ADF,PPF)
!CCCC CALL NORPPF(ALPHAT,PPF)
!CCCC PPF=ABS(PPF)
!CCCC UCL=STATVA + PPF*SD
!CCCC LCL=STATVA - PPF*SD
      UCL=CPUMIN
      LCL=CPUMIN
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LRS3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLRS3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
        IF(IERROR.EQ.'NO')THEN
          WRITE(ICOUT,9013)STATVA,STATCD,PVALLT,PVALUT,PVAL2T
 9013     FORMAT('STATVA,STATCD,PVALLT,PVALUT,PVAL2T = ',5G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9014)SUM1,SUM2,AMEAN,SD,Z,NTEMP
 9014     FORMAT('SUM1,SUM2,AMEAN,SD,Z,NTEMP = ',5G15.7,I10)
          CALL DPWRST('XXX','WRIT')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLRS3
      SUBROUTINE DPLTES(YTEMP,XTEMP,MAXNXT,ICASAN,   &
                        ICAPSW,IFORSW,IMULT,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT LEVENE TEST (K-SAMPLE HOMOGENEITY OF VARIANCES)
!     EXAMPLE--LEVENE TEST Y X
!     REFERENCE--Levene, H. (1960). In Contributions to Probability
!                and Statistics: Essays in Honor of Harold Hotelling,
!                I. Olkin et al. eds., Stanford University Press,
!                pp. 278-292.
!              --Brown, M. B. and Forsythe, A. B. (1974), Journal
!                of the American Statistical Association, 69, 364-367.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/9
!     ORIGINAL VERSION--SEPTEMBER 1997.
!     UPDATED         --AUGIST    1999. BUG FIX IN CALCULATION,
!                                       ADD OPTION OF MEDIAN,
!                                       MEAN, OR TRIMMED MEAN
!     UPDATED         --JANUARY   2004. SUPPORT FOR HTML, LATEX OUTPUT
!     UPDATED         --FEBRUARY  2011. USE DPPARS
!     UPDATED         --FEBRUARY  2011. SUPPORT FOR "MULTIPLE" CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
!
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN0
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION YMEDIA(MAXOBV)
      DIMENSION YMEAN(MAXOBV)
      DIMENSION T(MAXOBV)
      DIMENSION TBARIV(MAXOBV)
      DIMENSION DTAG(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE(GARBAG(IGARB1),YMEDIA(1))
      EQUIVALENCE(GARBAG(IGARB2),T(1))
      EQUIVALENCE(GARBAG(IGARB3),TBARIV(1))
      EQUIVALENCE(GARBAG(IGARB4),DTAG(1))
      EQUIVALENCE(GARBAG(IGARB5),YMEAN(1))
      EQUIVALENCE(GARBAG(IGARB6),TEMP1(1))
      EQUIVALENCE(GARBAG(IGARB7),TEMP2(1))
      EQUIVALENCE(GARBAG(IGARB8),TEMP3(1))
      EQUIVALENCE(GARBAG(IGARB9),TEMP4(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLT'
      ISUBN2='ES  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IERROR='NO'
      IFOUND='YES'
!
!               **************************************
!               **  TREAT THE LEVENE TEST CASE  **
!               **************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LTES')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLTES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,IMULT,IFORSW
   55   FORMAT('MAXNXT,IMULT,IFORSW = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTES')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='LEVENE TEST'
      MINNA=1
      MAXNA=100
      MINNVA=2
      MAXNVA=2
      IFLAGE=1
      IFLAGM=0
      IF(IMULT.EQ.'ON')THEN
        IFLAGE=0
        IFLAGM=1
        MINNVA=2
        MAXNVA=30
      ENDIF
      MINN2=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTES')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT
  182   FORMAT('NQ,NUMVAR,IMULT = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  GENERATE THE LEVENE TEST       FOR THE VARIOUS  **
!               **  CASES                                           **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
!     NOTE: ONLY ALLOW MATRIX ARGUMENTS FOR "MULTIPLE" CASE.
!           FOR CASE WHERE SECOND VARIABLE IS A GROUP-ID VARIABLE,
!           MATRIX ARGUMENTS DON'T MAKE SENSE.
!
      IF(IMULT.EQ.'OFF')THEN
        ISTEPN='3A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTES')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=2
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,X,YTEMP,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ******************************************************
!               **  STEP 3B--
!               **  PREPARE FOR ENTRANCE INTO DPLTE2--
!               ******************************************************
!
        ISTEPN='3B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,331)
  331     FORMAT('***** FROM DPLTES, AS WE ARE ABOUT TO CALL DPLTE2--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,332)NLOCAL
  332     FORMAT('NLOCAL = ',I8)
          CALL DPWRST('XXX','BUG ')
          DO 335 I=1,NLOCAL
            WRITE(ICOUT,336)I,Y(I),X(I)
  336       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
  335     CONTINUE
        ENDIF
!
        CALL DPLTE2(Y,X,NLOCAL,ICASAN,MAXOBV,IVARN1,IVARN2,   &
                    YTEMP,XTEMP,YMEAN,YMEDIA,T,TBARIV,DTAG,MAXNXT,   &
                    TEMP1,TEMP2,TEMP3,TEMP4,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,ILEVGS,   &
                    STATVA,STATCD,PVALUE,   &
                    CUT0,CUT50,CUT75,CUT90,CUT95,CUT99,CUT999,   &
                    IBUGA3,ISUBRO,IERROR)
!
!               *******************************************************
!               **  STEP 4A--                                        **
!               **  CASE 2: MULTIPLE RESPONSE VARIABLES.  NOTE THAT  **
!               **          LEVENE TEST, THE MULTIPLE LABS ARE       **
!               **          CONVERTED INTO A "Y X" STACKED PAIR      **
!               **          WHERE "X" IS THE LAB-ID VARIABLE.        **
!               *******************************************************
!
      ELSEIF(IMULT.EQ.'ON')THEN
        ISTEPN='4A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTES')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=NUMVAR
        CALL DPPAR8(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    XTEMP,Y,X,NLOCAL,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NUMVAR=2
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LTES')THEN
          ISTEPN='4B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,442)
  442     FORMAT('***** FROM THE MIDDLE  OF DPLTES--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,443)ICASAN,NUMVAR,NLOCAL
  443     FORMAT('ICASAN,NUMVAR,NLOCAL = ',A4,2I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 445 I=1,NLOCAL
              WRITE(ICOUT,446)I,Y(I),X(I)
  446         FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
  445       CONTINUE
          ENDIF
        ENDIF
!
        CALL DPLTE2(Y,X,NLOCAL,ICASAN,MAXOBV,IVARN1,IVARN2,   &
                    YTEMP,XTEMP,YMEAN,YMEDIA,T,TBARIV,DTAG,MAXNXT,   &
                    TEMP1,TEMP2,TEMP3,TEMP4,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,ILEVGS,   &
                    STATVA,STATCD,PVALUE,   &
                    CUT0,CUT50,CUT75,CUT90,CUT95,CUT99,CUT999,   &
                    IBUGA3,ISUBRO,IERROR)
!
      ENDIF
!
!               ***************************************
!               **  STEP 61--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='61'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LTES')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN0='DPLT'
!
      IH='STAT'
      IH2='VAL '
      VALUE0=STATVA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='CDF '
      VALUE0=STATCD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PVAL'
      IH2='UE  '
      VALUE0=PVALUE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF0 '
      VALUE0=CUT0
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF50'
      VALUE0=CUT50
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF75'
      VALUE0=CUT75
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF90'
      VALUE0=CUT90
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF95'
      VALUE0=CUT95
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF99'
      VALUE0=CUT99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F999'
      VALUE0=CUT99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LTES')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLTES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NLOCAL,STATVA,STATCD
 9014   FORMAT('NLOCAL,STATVA,STATCD = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLTES
      SUBROUTINE DPLTE2(Y,TAG,N,ICASAN,MAXOBV,IVARID,IVARI2,   &
                        YTEMP,XTEMP,YMEAN,YMEDIA,T,TBARIV,DTAG,MAXNXT,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,   &
                        ICAPSW,ICAPTY,IFORSW,IMULT,ILEVGS,   &
                        STATVA,STATCD,PVAL,   &
                        CUT0,CUT50,CUT75,CUT90,CUT95,CUT99,CUT999,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT LEVENE'S TEST
!              (K-SAMPLE HOMOSCEDASTICITY TEST)
!     EXAMPLE--LEVENE'S TEST Y TAG
!     REFERENCE--Levene, H. (1960). In Contributions to Probability
!                and Statistics: Essays in Honor of Harold Hotelling,
!                I. Olkin et al. eds., Stanford University Press,
!                pp. 278-292.
!              --Brown, M. B. and Forsythe, A. B. (1974), Journal
!                of the American Statistical Association, 69, 364-367.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/9
!     ORIGINAL VERSION--SEPTEMBER 1997.
!     UPDATED         --AUGUST    1999. BUG FIX IN CALCULATION,
!                                       SUPPORT FOR MEDIAN, MEAN,
!                                       OR TRIMMED MEAN VERSION
!     UPDATED         --JANUARY   2004. SUPPORT FOR HTML, LATEX OUTPUT
!     UPDATED         --JULY      2005. ADD SOME TEXT TO THE OUTPUT
!                                       TO MAKE IT MORE EXPLICIT
!                                       WHICH VARIANT OF THE TEST
!                                       IS BEING USED.
!     UPDATED         --FEBRUARY  2011. USE DPDTA1 AND DPDTA4 TO PRINT
!                                       OUTPUT TABLES.  THIS ADDS RTF
!                                       SUPPORT AND SPECIFICATION OF
!                                       THE NUMBER OF DIGITS.
!     UPDATED         --FEBRUARY  2011. OPTION TO PRINT GROUP
!                                       STATISITCS.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 ILEVGS
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DSUM1
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION DTAG(*)
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
      DIMENSION YMEDIA(*)
      DIMENSION YMEAN(*)
      DIMENSION T(*)
      DIMENSION TBARIV(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
!
      PARAMETER (NUMALP=8)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=4)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       0.0, 50.0, 75.0, 90.0, 95.0, 97.5, 99.0, 99.9/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLT'
      ISUBN2='E2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LTE2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPLTE2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IMULT,ILEVGS,N
   52   FORMAT('IBUGA3,ISUBRO,IMULT,ILEVGS,N = ',4(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN LEVENE TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1112)
 1112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1114)N
 1114   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 1135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 1139
 1135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1131)HOLD
 1131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
 1139 CONTINUE
!
      HOLD=TAG(1)
      DO 1235 I=2,N
      IF(TAG(I).NE.HOLD)GO TO 1239
 1235 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1231)HOLD
 1231 FORMAT('      THE GROUP-ID VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
 1239 CONTINUE
!
!               ******************************
!               **  STEP 41--               **
!               **  CARRY OUT CALCULATIONS  **
!               **  FOR    LEVENE'S TEST    **
!               ******************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL DISTIN(TAG,N,IWRITE,DTAG,NUMDIS,IBUGA3,IERROR)
!
      DO 4200 IDIS=1,NUMDIS
         J=0
         DO 4300 I=1,N
            IF(TAG(I).EQ.DTAG(IDIS))THEN
               J=J+1
               YTEMP(J)=Y(I)
            ENDIF
 4300    CONTINUE
         CALL MEDIAN(YTEMP,J,IWRITE,XTEMP,MAXNXT,YMED,   &
                     IBUGA3,IERROR)
         CALL MEAN(YTEMP,J,IWRITE,YMEANT,IBUGA3,IERROR)
         CALL SD(YTEMP,J,IWRITE,YSD,IBUGA3,IERROR)
         TEMP1(IDIS)=REAL(J)
         TEMP2(IDIS)=YMEANT
         TEMP3(IDIS)=YMED
         TEMP4(IDIS)=YSD
         IF(ICASAN.EQ.'LMED')THEN
           YMEDIA(IDIS)=YMED
         ELSEIF(ICASAN.EQ.'LMEA')THEN
           YMEDIA(IDIS)=YMEANT
         ELSEIF(ICASAN.EQ.'LTRI')THEN
           NTRIM1=-1
           NTRIM2=-1
           PROP1=10.0
           PROP2=10.0
           IUPPER=MAXOBV
           CALL TRIMME(YTEMP,J,PROP1,PROP2,NTRIM1,NTRIM2,IWRITE,XTEMP,   &
                       IUPPER,YMEDIA(IDIS),   &
                       IBUGA3,ISUBRO,IERROR)
           TEMP3(IDIS)=YMEDIA(IDIS)
         ELSE
           CALL MEDIAN(YTEMP,J,IWRITE,XTEMP,MAXNXT,YMEDIA(IDIS),   &
                       IBUGA3,IERROR)
         ENDIF
         DO 4400 I=1,N
           IF(TAG(I).EQ.DTAG(IDIS))T(I)=ABS(Y(I)-YMEDIA(IDIS))
 4400    CONTINUE
 4200 CONTINUE
!
!CCCC BUG FIX IN FOLLOWING LINE.  AUGUST 1999.
!CCCC CALL MEAN(Y,N,IWRITE,TBAR,IBUGA3,IERROR)
      CALL MEAN(T,N,IWRITE,TBAR,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LTE2')THEN
        WRITE(ICOUT,4901)TBAR
 4901   FORMAT('TBAR = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 4905 I=1,N
          WRITE(ICOUT,4906)I,TAG(I),DTAG(I),Y(I),T(I)
 4906     FORMAT('I,TAG(I),DTAG(I),Y(I),T(I)=',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 4905   CONTINUE
      ENDIF
!
      DO 5200 IDIS=1,NUMDIS
         J=0
         DO 5300 I=1,N
            IF(TAG(I).EQ.DTAG(IDIS))THEN
               J=J+1
!CCCC BUG FIS: AUGUST 1999
!CCCC          YTEMP(J)=Y(I)
               YTEMP(J)=T(I)
            ENDIF
 5300    CONTINUE
         CALL MEAN(YTEMP,J,IWRITE,YMEAN(IDIS),IBUGA3,IERROR)
         DO 5400 I=1,N
           IF(TAG(I).EQ.DTAG(IDIS))TBARIV(I)=YMEAN(IDIS)
 5400    CONTINUE
 5200 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LTE2')THEN
        DO 5205 I=1,N
          WRITE(ICOUT,5206)I,TAG(I),DTAG(I),TBARIV(I)
 5206     FORMAT('I,TAG(I),DTAG(I),TBARIV(I)=',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 5205   CONTINUE
      ENDIF
!
      DSUM1=0.D0
      DO 6100 I=1,N
        DSUM1=DSUM1 + (TBARIV(I)-TBAR)**2
 6100 CONTINUE
      SSQ=REAL(DSUM1)
      NUMDF=NUMDIS-1
      ANUMMS=SSQ/REAL(NUMDF)
!
      DSUM1=0.D0
      DO 6200 I=1,N
        DSUM1=DSUM1 + (T(I)-TBARIV(I))**2
 6200 CONTINUE
      SSQ=REAL(DSUM1)
      IDENDF=N-NUMDIS
      DENMS=SSQ/REAL(IDENDF)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LTE2')THEN
        WRITE(ICOUT,6201)ANUMMS,DENMS
 6201   FORMAT('ANUMMS,DENMS=',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      STATVA=ANUMMS/DENMS
      CALL FCDF(STATVA,NUMDF,IDENDF,STATCD)
      PVAL=1.0-STATCD
!
      KM1=NUMDIS-1
      NMK=N-NUMDIS
!
      CUT0=0.0
      CALL FPPF(.50,KM1,NMK,CUT50)
      CALL FPPF(.75,KM1,NMK,CUT75)
      CALL FPPF(.90,KM1,NMK,CUT90)
      CALL FPPF(.95,KM1,NMK,CUT95)
      CALL FPPF(.99,KM1,NMK,CUT975)
      CALL FPPF(.99,KM1,NMK,CUT99)
      CALL FPPF(.999,KM1,NMK,CUT999)
!
!               ******************************
!               **   STEP 42--              **
!               **   WRITE OUT EVERYTHING   **
!               **   FOR   LEVENE'S TEST    **
!               ******************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Levene F-Test for Shift in Variation'
      NCTITL=36
      IF(ICASAN.EQ.'LMED')THEN
        ITITLZ='(Case: Test Based on Medians)'
        NCTITZ=29
      ELSEIF(ICASAN.EQ.'LMEA')THEN
        ITITLZ='(Case: Test Based on Means)'
        NCTITZ=27
      ELSEIF(ICASAN.EQ.'LTRI')THEN
        ITITLZ='(Case: Test Based on Trimmed Means)'
        NCTITZ=35
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(IMULT.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Group-ID Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
!     IF REQUESTED, PRINT OUT GROUP INFORMATION.  SINCE NUMBER
!     OF GROUPS IS UNKNOWN (AND POTENTIALLY LARGE, PRINT EACH
!     GROUP AS A SEPARATE TABLE.
!
      IF(ILEVGS.EQ.'ON')THEN
!
        DO 2160 I=1,NUMDIS
!
          NUMROW=ICNT
          DO 2165 II=1,NUMROW
            NTOT(II)=15
 2165     CONTINUE
!
          IFRST=.TRUE.
          ILAST=.TRUE.
!
          CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                      AVALUE,IDIGIT,   &
                      NTOT,NUMROW,   &
                      ICAPSW,ICAPTY,ILAST,IFRST,   &
                      ISUBRO,IBUGA3,IERROR)
          ICNT=0
          ITITLE=' '
          NCTITL=0
          ITITLZ=' '
          NCTITZ=0
!
          ICNT=ICNT+1
          ITEXT(ICNT)=' '
          NCTEXT(ICNT)=1
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
!
          IF(IMULT.EQ.'ON')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='Group Variable: '
            WRITE(ITEXT(ICNT)(17:20),'(A4)')IVARID(I)(1:4)
            WRITE(ITEXT(ICNT)(21:24),'(A4)')IVARI2(I)(1:4)
            NCTEXT(ICNT)=24
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ELSE
            ICNT=ICNT+1
            ITEXT(ICNT)='Group    '
            WRITE(ITEXT(ICNT)(7:9),'(I3)')I
            NCTEXT(ICNT)=9
            AVALUE(ICNT)=0.0
            IDIGIT(ICNT)=-1
          ENDIF
          ICNT=ICNT+1
          ITEXT(ICNT)='Number of Observations:'
          NCTEXT(ICNT)=23
          AVALUE(ICNT)=TEMP1(I)
          IDIGIT(ICNT)=0
          ICNT=ICNT+1
          ITEXT(ICNT)='Mean:'
          NCTEXT(ICNT)=5
          AVALUE(ICNT)=TEMP2(I)
          IDIGIT(ICNT)=NUMDIG
          IF(ICASAN.EQ.'LTRI')THEN
            ICNT=ICNT+1
            ITEXT(ICNT)='Trimmed Mean:'
            NCTEXT(ICNT)=13
            AVALUE(ICNT)=TEMP3(I)
            IDIGIT(ICNT)=NUMDIG
          ELSE
            ICNT=ICNT+1
            ITEXT(ICNT)='Median:'
            NCTEXT(ICNT)=7
            AVALUE(ICNT)=TEMP3(I)
            IDIGIT(ICNT)=NUMDIG
          ENDIF
          ICNT=ICNT+1
          ITEXT(ICNT)='SD:'
          NCTEXT(ICNT)=3
          AVALUE(ICNT)=TEMP4(I)
          IDIGIT(ICNT)=NUMDIG
 2160   CONTINUE
!
        IF(ICNT.GT.0)THEN
          NUMROW=ICNT
          DO 2168 II=1,NUMROW
            NTOT(II)=15
 2168     CONTINUE
!
          IFRST=.TRUE.
          ILAST=.TRUE.
!
          CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                      AVALUE,IDIGIT,   &
                      NTOT,NUMROW,   &
                      ICAPSW,ICAPTY,ILAST,IFRST,   &
                      ISUBRO,IBUGA3,IERROR)
          ICNT=0
        ENDIF
!
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Homogeneous Variances'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: Variances Are Not Homogeneous'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=REAL(NUMDIS)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Levene Test Statistic Value:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF of Test Statistic:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value:'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=1.0 - STATCD
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE=' '
      NCTITL=0
!
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:44)='Percent Points of the Reference Distribution'
      NCTITL=44
      NUMLIN=1
      NUMROW=8
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 4221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=1
      IDIGIT(3)=3
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            AMAT(I,J)=ALPHA(I)
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            IF(I.EQ.1)THEN
              AMAT(I,J)=RND(CUT0,IDIGIT(J))
            ELSEIF(I.EQ.2)THEN
              AMAT(I,J)=RND(CUT50,IDIGIT(J))
            ELSEIF(I.EQ.3)THEN
              AMAT(I,J)=RND(CUT75,IDIGIT(J))
            ELSEIF(I.EQ.4)THEN
              AMAT(I,J)=RND(CUT90,IDIGIT(J))
            ELSEIF(I.EQ.5)THEN
              AMAT(I,J)=RND(CUT95,IDIGIT(J))
            ELSEIF(I.EQ.6)THEN
              AMAT(I,J)=RND(CUT975,IDIGIT(J))
            ELSEIF(I.EQ.7)THEN
              AMAT(I,J)=RND(CUT99,IDIGIT(J))
            ELSEIF(I.EQ.8)THEN
              AMAT(I,J)=RND(CUT999,IDIGIT(J))
            ENDIF
          ENDIF
 4225   CONTINUE
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.FALSE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CDF1=CUT90
      CDF2=CUT95
      CDF3=CUT975
      CDF4=CUT99
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Upper 1-Tailed Test)'
      NCTITL=33
      NUMLIN=1
      NUMROW=4
      NUMCOL=4
      ITITL2(1,1)='Alpha'
      ITITL2(1,2)='CDF'
      ITITL2(1,3)='Critical Value'
      ITITL2(1,4)='Conclusion'
      NCTIT2(1,1)=5
      NCTIT2(1,2)=3
      NCTIT2(1,3)=14
      NCTIT2(1,4)=10
!
      NMAX=0
      DO 4321 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=7
        IF(I.EQ.3)NTOT(I)=17
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=3
        ITYPCO(I)='ALPH'
 4321 CONTINUE
      ITYPCO(3)='NUME'
      IDIGIT(1)=0
      IDIGIT(2)=0
      DO 4323 I=1,NUMROW
        DO 4325 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
 4325   CONTINUE
 4323 CONTINUE
      IVALUE(1,1)='10%'
      IVALUE(2,1)='5%'
      IVALUE(3,1)='2.5%'
      IVALUE(4,1)='1%'
      IVALUE(1,2)='90%'
      IVALUE(2,2)='95%'
      IVALUE(3,2)='97.5%'
      IVALUE(4,2)='99%'
      NCVALU(1,1)=3
      NCVALU(2,1)=2
      NCVALU(3,1)=4
      NCVALU(4,1)=2
      NCVALU(1,2)=3
      NCVALU(2,2)=3
      NCVALU(3,2)=5
      NCVALU(4,2)=3
      IVALUE(1,4)='Accept H0'
      IVALUE(2,4)='Accept H0'
      IVALUE(3,4)='Accept H0'
      IVALUE(4,4)='Accept H0'
      NCVALU(1,4)=9
      NCVALU(2,4)=9
      NCVALU(3,4)=9
      NCVALU(4,4)=9
      IF(STATVA.GT.CUT90)IVALUE(1,4)='Reject H0'
      IF(STATVA.GT.CUT95)IVALUE(2,4)='Reject H0'
      IF(STATVA.GT.CUT975)IVALUE(3,4)='Reject H0'
      IF(STATVA.GT.CUT99)IVALUE(4,4)='Reject H0'
      AMAT(1,3)=RND(CUT90,IDIGIT(3))
      AMAT(2,3)=RND(CUT95,IDIGIT(3))
      AMAT(3,3)=RND(CUT975,IDIGIT(3))
      AMAT(4,3)=RND(CUT99,IDIGIT(3))
!
      IWHTML(1)=150
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWRTF(1)=1500
      IWRTF(2)=IWRTF(1)+1500
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IFRST=.FALSE.
      ILAST=.TRUE.
!
      ISTEPN='42E'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LTE2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LTE2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLTE2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)STATVA,STATCD,PVAL
 9014   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLTE2
      SUBROUTINE DPLUJA(XTEMP1,MAXNXT,   &
                        ICASAN,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT LJUNG BOX TEST FOR RANDOMNESS
!     EXAMPLE--LJUNG BOX TEST Y
!     REFERENCE--PETER BROCKWELL AND RICHARD DAVIS (2002).
!                "INTRODUCTION TO TIME SERIES AND FORECASTING",
!                SECOND EDITION, SPRINGER.
!     TEST--  Q=N*(N+2_SUM[J=1 TO H][RHOHAT**2/(N-J)
!             REJECT RANDOMNESS IF Q > CHI-SQUARE PPF(H,1-ALPHA)
!             WHERE RHOHAT IS THE SAMPLE AUTOCORRELATION
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/3
!     ORIGINAL VERSION--FEBRUARY  2003.
!     UPDATED         --MARCH     2011. USE DPPARS ROUTINE
!     UPATED          --MARCH     2011. REWRITTEN TO HANDLE MULTIPLE
!                                       RESPONSE VARIABLES, GROUP-ID
!                                       VARIABLES, OR A LAB-ID VARIABLE
!     UPATED          --JULY      2019. TWEAK TO SCRATCH STORAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 MESSAG
      CHARACTER*4 IHWUSE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IFLAGU
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
      CHARACTER*4 ICASE
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(1)
      CHARACTER*4 IVARI2(1)
      REAL PVAR(MAXSPN)
      REAL PID(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      DIMENSION XTEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION YTEMP1(MAXOBV)
      DIMENSION XDESGN(MAXOBV,7)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XIDTE4(MAXOBV)
      DIMENSION XIDTE5(MAXOBV)
      DIMENSION XIDTE6(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),YTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB2),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB3),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB4),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTE3(1))
      EQUIVALENCE (GARBAG(IGARB6),XIDTE4(1))
      EQUIVALENCE (GARBAG(IGARB7),XIDTE5(1))
      EQUIVALENCE (GARBAG(IGARB8),XIDTE6(1))
      EQUIVALENCE (GARBAG(IGARB9),TEMP2(1))
      EQUIVALENCE (GARBAG(IGAR10),XDESGN(1,1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLU'
      ISUBN2='JA  '
      ICASAN='LUJA'
      IREPL='NO'
      IMULT='NO'
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ********************************************
!               **  TREAT THE LJUNG-BOX        TEST CASE  **
!               ********************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLUJA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************************************
!               **  STEP 1--                                       **
!               **  EXTRACT THE COMMAND                            **
!               **  LOOK FOR ONE OF THE FOLLOWING COMMANDS:        **
!               **    1) LJUNG-BOX TEST   Y                        **
!               **    2) MULTIPLE LJUNG-BOX TEST   Y1 ... YK       **
!               **    3) REPLICATED LJUNG-BOX TEST   Y X1 ... XK   **
!               *****************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTC=9999
      ILASTZ=9999
!
      DO 100 I=0,NUMARG-1
!
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
        ELSE
          ICTMP1=IHARG(I)
        ENDIF
        ICTMP2=IHARG(I+1)
        ICTMP3=IHARG(I+2)
        ICTMP4=IHARG(I+3)
!
        IF(ICTMP1.EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(ICTMP1.EQ.'LJUN' .AND. ICTMP2.EQ.'BOX' .AND.   &
               ICTMP3.EQ.'TEST')THEN
          IFOUND='YES'
          ILASTC=I
          ILASTZ=I+2
        ELSEIF(ICTMP1.EQ.'LJUN' .AND. ICTMP2.EQ.'BOX')THEN
          IFOUND='YES'
          ILASTC=I
          ILASTZ=I+1
        ELSEIF(ICTMP1.EQ.'REPL')THEN
          IREPL='ON'
          ILASTC=MIN(ILASTC,I)
          ILASTZ=MAX(ILASTZ,I)
        ELSEIF(ICTMP1.EQ.'MULT')THEN
          IMULT='ON'
          ILASTC=MIN(ILASTC,I)
          ILASTZ=MAX(ILASTZ,I)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')THEN
        WRITE(ICOUT,91)ICASAN,IMULT,IREPL,ISHIFT
   91   FORMAT('DPFRTE: ICASAN,IMULT,IREPL,ISHIFT = ',3(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN LJUNG-BOX TEST--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,103)
  103     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION"')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,104)
  104     FORMAT('      FOR THE LJUNG-BOX TEST COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='LJUNG-BOX TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=1
      IF(IREPL.EQ.'ON')THEN
        IFLAGM=0
        IFLAGE=1
      ENDIF
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=MAXSPN
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               ***********************************************
!
      ISTEPN='5'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,512)
  512     FORMAT('      MUST BE BETWEEN ONE AND SIX.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        NRESP=NUMVAR
        IMULT='ON'
      ENDIF
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')THEN
        WRITE(ICOUT,521)NRESP,NREPL
  521   FORMAT('NRESP,NREPL = ',2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************************************
!               **  STEP 53--                                      **
!               **  DETERMINE IF THE ANALYST HAS SPECIFIED THE     **
!               **  NUMBER OF LAGS DESIRED FOR THE LJUNG-BOX TEST. **
!               **  SEARCH FOR ONE OF THE FOLLOWING PREVIOUSLY     **
!               **  DEFINED PARAMETER NAMES:                       **
!               **       LAGS, LAG, OR NUMLAG                      **
!               **  IF FOUND, USE THE SPECIFIED VALUE              **
!               **  (WHICH MUST BE BETWEEN 1 AND 1000, INCLUSIVE); **
!               **  IF NOT FOUND, USE THE DEFAULT VALUE            **
!               **  (USUALLY NS/4) WHICH WILL BE DEFINED           **
!               **  IN THE SUBROUTINE DPLJU2.                      **
!               *****************************************************
!
      ISTEPN='53'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMLAG=0
!
      IH='LAGS'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        NUMLAG=INT(VALUE(ILOCV)+0.5)
        GO TO 590
      ENDIF
!
      IH='LAG '
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        NUMLAG=INT(VALUE(ILOCV)+0.5)
        GO TO 590
      ENDIF
!
      IH='NUML'
      IH2='AG  '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        NUMLAG=INT(VALUE(ILOCV)+0.5)
        GO TO 590
      ENDIF
!
  590 CONTINUE
!
!               ******************************************************
!               **  STEP 6--                                        **
!               **  GENERATE THE LJUNG-BOX        TEST FOR THE      **
!               **  VARIOUS CASES                                   **
!               ******************************************************
!
      ISTEPN='6'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ******************************************
!               **  STEP 8A--                           **
!               **  CASE 1: NO REPLICATION VARIABLES    **
!               ******************************************
!
      IF(NREPL.LT.1)THEN
        ISTEPN='8A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NCURVE=0
        DO 810 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IINDX=ICOLR(IRESP)
          PID(1)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
!
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,811)IRESP,NCURVE
  811       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y,XTEMP1,XTEMP1,NS1,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!         *****************************************************
!         **  STEP 8B--                                      **
!         *****************************************************
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LUJA')THEN
            ISTEPN='8B'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,822)
  822       FORMAT('***** FROM THE MIDDLE  OF DPLUJA--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,823)ICASAN,NUMVAR,NLOCAL
  823       FORMAT('ICASAN,NUMVAR,NQ = ',A4,2I8)
            CALL DPWRST('XXX','BUG ')
            IF(NLOCAL.GE.1)THEN
              DO 825 I=1,NLOCAL
                WRITE(ICOUT,826)I,Y(I)
  826           FORMAT('I,Y(I) = ',I8,G15.7)
                CALL DPWRST('XXX','BUG ')
  825         CONTINUE
            ENDIF
          ENDIF
!
          CALL DPLUJ2(Y,NS1,MAXNXT,   &
                      ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                      PID,IVARID,IVARI2,NREPL,   &
                      STATVA,STATCD,PVAL,   &
                      CUT0,CUT50,CUT75,CUT90,CUT95,   &
                      CUT975,CUT99,CUT999,   &
                      YTEMP1,NUMLAG,   &
                      ISUBRO,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(NRESP.GT.1)THEN
            IFLAGU='FILE'
          ELSE
            IFLAGU='ON'
          ENDIF
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          CALL DPFRT5(STATVA,STATCD,PVAL,   &
                      CUT0,CUT50,CUT75,CUT90,CUT95,   &
                      CUT975,CUT99,CUT999,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
  810   CONTINUE
!
!               ****************************************************
!               **  STEP 9A--                                     **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.    **
!               **          FOR THIS CASE, THE NUMBER OF RESPONSE **
!               **          VARIABLES MUST BE EXACTLY 1.          **
!               **          FOR THIS CASE, ALL VARIABLES MUST     **
!               **          HAVE THE SAME LENGTH.                 **
!               ****************************************************
!
      ELSEIF(NREPL.GE.1)THEN
        ISTEPN='9A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 910 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 910
          J=J+1
!
!         RESPONSE VARIABLE IN Y
!
          ICOLC=1
          IJ=MAXN*(ICOLR(ICOLC)-1)+I
          IF(ICOLR(ICOLC).LE.MAXCOL)Y(J)=V(IJ)
          IF(ICOLR(ICOLC).EQ.MAXCP1)Y(J)=PRED(I)
          IF(ICOLR(ICOLC).EQ.MAXCP2)Y(J)=RES(I)
          IF(ICOLR(ICOLC).EQ.MAXCP3)Y(J)=YPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP4)Y(J)=XPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP5)Y(J)=X2PLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP6)Y(J)=TAGPLO(I)
!
          IF(NREPL.GE.1)THEN
            DO 920 IR=1,MIN(NREPL,6)
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  920       CONTINUE
          ENDIF
!
  910   CONTINUE
        NLOCAL=J
!
!       *****************************************************
!       **  STEP 9B--                                      **
!       **  CALL DPLUJ2 TO PERFORM LJUNG-BOX        TEST.  **
!       *****************************************************
!
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LUJA')THEN
          ISTEPN='9C'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,941)
  941     FORMAT('***** FROM THE MIDDLE  OF DPLUJA--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,942)ICASAN,NUMVAR,NLOCAL,NREPL
  942     FORMAT('ICASAN,NUMVAR,NLOCAL,NREPL = ',   &
                 A4,3I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 945 I=1,NLOCAL
              WRITE(ICOUT,946)I,Y(I),XDESGN(I,1),XDESGN(I,2)
  946         FORMAT('I,Y(I),XDESGN(I,1),XDESGN(I,2) = ',   &
                     I8,4F12.5)
              CALL DPWRST('XXX','BUG ')
  945       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   XTEMP1,TEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGA3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 9D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NCURVE=0
        IADD=1
!
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            PID(IADD+1)=XIDTEM(ISET1)
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLUJ2(TEMP1,NTEMP,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          YTEMP1,NUMLAG,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            CALL DPFRT5(STATVA,STATCD,PVAL,   &
                        CUT0,CUT50,CUT75,CUT90,CUT95,   &
                        CUT975,CUT99,CUT999,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLUJ2(TEMP1,NTEMP,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          YTEMP1,NUMLAG,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPFRT5(STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLUJ2(TEMP1,NTEMP,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          YTEMP1,NUMLAG,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPFRT5(STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLUJ2(TEMP1,NTEMP,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          YTEMP1,NUMLAG,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPFRT5(STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLUJ2(TEMP1,NTEMP,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          YTEMP1,NUMLAG,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPFRT5(STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            PID(6+IADD)=XIDTE6(ISET4)
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPLUJ2(TEMP1,NTEMP,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          YTEMP1,NUMLAG,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPFRT5(STATVA,STATCD,PVAL,   &
                          CUT0,CUT50,CUT75,CUT90,CUT95,   &
                          CUT975,CUT99,CUT999,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LUJA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLUJA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLUJA
      SUBROUTINE DPLUJ2(Y,N,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,ICASAN,   &
                        PID,IVARID,IVARI2,NREPL,   &
                        STATVA,STATCD,PVAL,   &
                        CUT0,CUT50,CUT75,CUT90,CUT95,   &
                        CUT975,CUT99,CUT999,   &
                        YTEMP1,NUMLAG,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT THE LJUNG-BOX TEST
!              FOR RANDOMNESS.
!     EXAMPLE--LJUNG-BOX TEST Y
!     REFERENCE--PETER BROCKWELL AND RICHARD DAVIS (2002).
!                "INTRODUCTION TO TIME SERIES AND FORECASTING",
!                SECOND EDITION, SPRINGER.
!     TEST--  Q=N*(N+2_SUM[J=1 TO H][RHOHAT**2/(N-J)
!             REJECT RANDOMNESS IF Q > CHI-SQUARE PPF(H,1-ALPHA)
!             WHERE RHOHAT IS THE SAMPLE AUTOCORRELATION
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/3
!     ORIGINAL VERSION--FEBRUARY  2003.
!     UPDATED         --MARCH     2011. USE DPDTA1 AND DPDTA5 TO PRINT
!                                       TABLES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION YTEMP1(*)
      DIMENSION PID(*)
!
      PARAMETER (NUMALP=8)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLU'
      ISUBN2='J2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPLUJ2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)ICASAN,IBUGA3,ISUBRO,N
   52   FORMAT('ICASAN,IBUGA3,ISUBRO,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I), = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN LJUNG-BOX TEST.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1113)
 1113   FORMAT('      AT LEAST SIX OBSERVATIONS REQUIRED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1115)N
 1115   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 1135 I=2,N
      IF(Y(I).NE.HOLD)GO TO 1139
 1135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1131)HOLD
 1131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
 1139 CONTINUE
!
!               *******************************
!               **  STEP 2--                 **
!               **  IF NECESSARY,            **
!               **  COMPUTE THE MAXIMUM LAG  **
!               *******************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MAXLAG=MAXNXT
      IF(NUMLAG.GE.1)KMAX=NUMLAG
      IF(NUMLAG.LE.0)KMAX=N/4
      IF(NUMLAG.LE.0.AND.N.LE.32)KMAX=N/2
      IF(NUMLAG.LE.0.AND.N.LE.16)KMAX=N
      IF(KMAX.GT.MAXLAG)KMAX=MAXLAG
      NM1=N-1
      IF(KMAX.GT.NM1)KMAX=NM1
      IF(N.LE.16)THEN
         NM2=N-2
         IF(KMAX.GT.NM2)KMAX=NM2
      ENDIF
      KMAXM1=KMAX-1
      AKMAXM=KMAXM1
!
!               ******************************************************
!               **  STEP 2.1--                                      **
!               **  COMPUTE THE AUTOCORRELATIONS FOR THE Y  DATA    **
!               **  DO SO IN 3 STEPS--                              **
!               **     1) COMPUTE THE SAMPLE MEAN;                  **
!               **     2) COMPUTE THE SAMPLE VARIANCE;              **
!               **     3) COMPUTE THE AUTOCORRELATIONS;             **
!               **  REFERENCE--JENKINS AND WATTS, PAGE 382 (9.3.1)  **
!               ******************************************************
!
      ISTEPN='2.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     COMPUTE AUTOCORRELATIONS FOR N <= 20
!
      IF(N.LE.16)THEN
        AN=N
!
        DO 2110 K=1,KMAXM1
          NMK=N-K
          ANMK=NMK
          SUM1=0.0
          SUM2=0.0
          DO 2120 I=1,NMK
            J=I+K
            SUM1=SUM1+Y(I)
            SUM2=SUM2+Y(J)
 2120     CONTINUE
          Y1BAR=SUM1/ANMK
          Y2BAR=SUM2/ANMK
!
          SUM1=0.0
          SUM2=0.0
          DO 2130 I=1,NMK
            J=I+K
            SUM1=SUM1+(Y(I)-Y1BAR)**2
            SUM2=SUM2+(Y(J)-Y2BAR)**2
 2130     CONTINUE
          SSQ1=SUM1
          SSQ2=SUM2
!
          SUM1=0.0
          DO 2140 I=1,NMK
            J=I+K
            SUM1=SUM1+(Y(I)-Y1BAR)*(Y(J)-Y2BAR)
 2140     CONTINUE
          ANUM=SUM1
!
          SQRT1=0.0
          IF(SSQ1.GT.0.0)SQRT1=SQRT(SSQ1)
          SQRT2=0.0
          IF(SSQ2.GT.0.0)SQRT2=SQRT(SSQ2)
          DENOM=SQRT1*SQRT2
          AC=0.0
          IF(DENOM.GT.0.0)AC=ANUM/DENOM
          YTEMP1(K)=AC
 2110   CONTINUE
      ELSE
!
!     COMPUTE AUTOCORRELATIONS FOR N >= 21
!
        AN=N
!
        SUM1=0.0
        DO 2210 I=1,N
          SUM1=SUM1+Y(I)
 2210   CONTINUE
        Y1BAR=SUM1/AN
!
        SUM1=0.0
        DO 2220 I=1,N
          SUM1=SUM1+(Y(I)-Y1BAR)*(Y(I)-Y1BAR)
 2220   CONTINUE
        VARB1=SUM1/AN
        VAR1=SUM1/(AN-1.0)
!
        DO 2230 K=1,KMAXM1
          SUM1=0.0
          NMK=N-K
          DO 2240 I=1,NMK
            J=I+K
            SUM1=SUM1+(Y(I)-Y1BAR)*(Y(J)-Y1BAR)
 2240     CONTINUE
          YTEMP1(K)=SUM1/AN
          YTEMP1(K)=YTEMP1(K)/VARB1
 2230   CONTINUE
      ENDIF
!
!               ******************************
!               **  STEP 23--               **
!               **  CARRY OUT CALCULATIONS  **
!               **  FOR LJUNG-BOX     TEST  **
!               ******************************
!
      ISTEPN='23'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
!
      SUM1=0.0
      DO 2310 I=1,KMAXM1
        SUM1=SUM1 + YTEMP1(I)*YTEMP1(I)/REAL(N-I)
 2310 CONTINUE
!
      Q=AN*(AN+2.0)*SUM1
      STATVA=Q
      CALL CHSCDF(Q,KMAXM1,STATCD)
      PVAL=1.0-STATCD
!
      CUT0=0.
!
      ALPHA=.5
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT50)
!
      ALPHA=.25
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT75)
!
      ALPHA=.10
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT90)
!
      ALPHA=.05
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT95)
!
      ALPHA=.025
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT975)
!
      ALPHA=.01
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT99)
!
      ALPHA=.001
      P2=1.0-ALPHA
      CALL CHSPPF(P2,KMAXM1,CUT999)
!
!               *********************************
!               **   STEP 41--                 **
!               **   WRITE OUT EVERYTHING      **
!               **   FOR LJUNG-BOX TEST        **
!               *********************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Ljung-Box Test for Randomness'
      NCTITL=29
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NREPL.GT.0)THEN
        IADD=1
        DO 2101 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+IADD
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 2101   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: The Data Are Random'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: The Data Are Not Random'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Lag Tested:'
      NCTEXT(ICNT)=11
      AVALUE(ICNT)=REAL(KMAXM1)
      IDIGIT(ICNT)=0
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Lag 1 Autocorrelation:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=YTEMP1(1)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Lag 2 Autocorrelation:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=YTEMP1(2)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Lag 3 Autocorrelation:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=YTEMP1(3)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Ljung-Box Test Statistic:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value:'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=PVAL
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 4110 I=1,NUMROW
        NTOT(I)=15
 4110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Upper One-Tailed Test)'
      NCTITL=35
!
      DO 5030 J=1,5
        DO 5040 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 5040   CONTINUE
 5030 CONTINUE
!
      ITITL2(2,1)='Null'
      NCTIT2(2,1)=4
      ITITL2(3,1)='Hypothesis'
      NCTIT2(3,1)=10
!
      ITITL2(2,2)='Confidence'
      NCTIT2(2,2)=10
      ITITL2(3,2)='Level'
      NCTIT2(3,2)=5
!
      ITITL2(2,3)='Test'
      NCTIT2(2,3)=4
      ITITL2(3,3)='Statistic'
      NCTIT2(3,3)=9
!
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Value (>)'
      NCTIT2(3,4)=9
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 2050 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=12
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='ALPH'
        IF(I.EQ.3 .OR. I.EQ.4)ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IWHTML(1)=150
        IWHTML(2)=125
        IWHTML(3)=150
        IWHTML(4)=150
        IWHTML(5)=150
        IINC=1600
        IINC2=1400
        IINC3=2200
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC3
        IWRTF(4)=IWRTF(3)+IINC3
        IWRTF(5)=IWRTF(4)+IINC3
!
        DO 2060 J=1,NUMALP
!
          AMAT(J,I)=0.0
          AMAT(J,3)=STATVA
          IVALUE(J,1)='Random'
          NCVALU(J,1)=6
          IVALUE(J,5)(1:6)='REJECT'
          IF(J.EQ.1)THEN
            IVALUE(J,2)(1:5)='0.0%'
            AMAT(J,4)=CUT0
            IF(STATVA.LT.CUT0)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.2)THEN
            IVALUE(J,2)(1:5)='50.0%'
            AMAT(J,4)=CUT50
            IF(STATVA.LT.CUT50)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.3)THEN
            IVALUE(J,2)(1:5)='75.0%'
            AMAT(J,4)=CUT75
            IF(STATVA.LT.CUT75)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.4)THEN
            IVALUE(J,2)(1:5)='90.0%'
            AMAT(J,4)=CUT90
            IF(STATVA.LT.CUT90)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.5)THEN
            IVALUE(J,2)(1:5)='95.0%'
            AMAT(J,4)=CUT95
            IF(STATVA.LT.CUT95)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.6)THEN
            IVALUE(J,2)(1:5)='97.5%'
            AMAT(J,4)=CUT975
            IF(STATVA.LT.CUT975)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.7)THEN
            IVALUE(J,2)(1:5)='99.0%'
            AMAT(J,4)=CUT99
            IF(STATVA.LT.CUT99)IVALUE(J,5)(1:6)='ACCEPT'
          ELSEIF(J.EQ.8)THEN
            IVALUE(J,2)(1:5)='99.9%'
            AMAT(J,4)=CUT999
            IF(STATVA.LT.CUT999)IVALUE(J,5)(1:6)='ACCEPT'
          ENDIF
          NCVALU(J,2)=5
          NCVALU(J,5)=6
!
 2060   CONTINUE
 2050 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LUJ2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLUJ2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR,STATVA,STATCD,PVAL
 9012   FORMAT('IERROR,STATVA,STATCD,PVAL = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLUJ2
      SUBROUTINE DPMABA(IHARG,IARGT,ARG,NUMARG,ADEMBA,MAXMAR,AMARBA,   &
      IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MARKER BASES.
!              THESE ARE LOCATED IN THE VECTOR AMARBA(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --IARGT  (A  CHARACTER VECTOR)
!                     --ARG
!                     --NUMARG
!                     --ADEMBA
!                     --MAXMAR
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--AMARBA (A FLOATING POINT VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
      DIMENSION AMARBA(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPMA'
      ISUBN2='BA  '
!
      NUMMAR=0
      IHOLD1='-999'
      HOLD1=-999.0
      HOLD2=-999.0
!
      IF(IBUGP2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMABA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR
   52 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXMAR,NUMMAR
   53 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IHOLD1,HOLD1,HOLD2
   54 FORMAT('IHOLD1,HOLD1,HOLD2 = ',A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)ADEMBA
   55 FORMAT('ADEMBA = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,60)NUMARG
   60 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,NUMARG
      WRITE(ICOUT,66)IHARG(I),IARGT(I),ARG(I)
   66 FORMAT('IHARG(I),IARGT(I),ARG(I) = ',2(A4,2X),G15.7)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,70)AMARBA(1)
   70 FORMAT('AMARBA(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 75 I=1,10
      WRITE(ICOUT,76)I,AMARBA(I)
   76 FORMAT('I,AMARBA(I) = ',I8,2X,E15.7)
      CALL DPWRST('XXX','BUG ')
   75 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.0)GO TO 9000
      IF(NUMARG.EQ.1)GO TO 1110
      IF(NUMARG.EQ.2)GO TO 1120
      IF(NUMARG.EQ.3)GO TO 1130
      GO TO 1140
!
 1110 CONTINUE
      GO TO 1200
!
 1120 CONTINUE
      IF(IHARG(2).EQ.'ALL')IHOLD1='    '
      IF(IHARG(2).EQ.'ALL')HOLD1=ADEMBA
      IF(IHARG(2).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1130 CONTINUE
      IF(IHARG(2).EQ.'ALL')IHOLD1=IHARG(3)
      IF(IHARG(2).EQ.'ALL')HOLD1=ARG(3)
      IF(IHARG(2).EQ.'ALL')GO TO 1300
      IF(IHARG(3).EQ.'ALL')IHOLD1=IHARG(2)
      IF(IHARG(3).EQ.'ALL')HOLD1=ARG(2)
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1140 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE     SPECIFICATION  CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.1)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMMAR=1
      AMARBA(1)=ADEMBA
      GO TO 1270
!
 1220 CONTINUE
      NUMMAR=NUMARG-1
      IF(NUMMAR.GT.MAXMAR)NUMMAR=MAXMAR
      DO 1225 I=1,NUMMAR
      J=I+1
      IHOLD1=IHARG(J)
      HOLD1=ARG(J)
      HOLD2=HOLD1
      IF(IHOLD1.EQ.'ON')HOLD2=ADEMBA
      IF(IHOLD1.EQ.'OFF')HOLD2=ADEMBA
      IF(IHOLD1.EQ.'AUTO')HOLD2=ADEMBA
      IF(IHOLD1.EQ.'DEFA')HOLD2=ADEMBA
      AMARBA(I)=HOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMMAR
      WRITE(ICOUT,1276)I,AMARBA(I)
 1276 FORMAT('THE BASE OF MARKER ',I6,   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMMAR=MAXMAR
      HOLD2=HOLD1
      IF(IHOLD1.EQ.'ON')HOLD2=ADEMBA
      IF(IHOLD1.EQ.'OFF')HOLD2=ADEMBA
      IF(IHOLD1.EQ.'AUTO')HOLD2=ADEMBA
      IF(IHOLD1.EQ.'DEFA')HOLD2=ADEMBA
      DO 1315 I=1,NUMMAR
      AMARBA(I)=HOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)AMARBA(I)
 1316 FORMAT('THE BASE OF ALL MARKERS',   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMABA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGP2,IFOUND,IERROR
 9012 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)MAXMAR,NUMMAR
 9013 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IHOLD1,HOLD1,HOLD2
 9014 FORMAT('IHOLD1,HOLD1,HOLD2 = ',A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)ADEMBA
 9015 FORMAT('ADEMBA = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9030)AMARBA(1)
 9030 FORMAT('AMARBA(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 9035 I=1,10
      WRITE(ICOUT,9036)I,AMARBA(I)
 9036 FORMAT('I,AMARBA(I) = ',I8,2X,E15.7)
      CALL DPWRST('XXX','BUG ')
 9035 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMABA
      SUBROUTINE DPMACL(IHARG,IARG,NUMARG,IDEFMC,IRGBMX,IMARCO,IMARC2,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE COLOR FOR THE MARGIN (THE REGION OUTSIDE THE
!              FRAME LINES).  THE COLOR FOR THE MARGIN WILL BE PLACED
!              IN THE CHARACTER VARIABLE IMARCO.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEFMC
!     OUTPUT ARGUMENTS--IMARCO
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IDEFMC
      CHARACTER*4 IMARCO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHARG(*)
      DIMENSION IARG(*)
      DIMENSION IMARC2(3)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)THEN
        IMARCO=IDEFMC
      ELSEIF(IHARG(1).EQ.'COLO')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           NUMARG.EQ.1)THEN
          IMARCO=IDEFMC
        ELSE
          IMARCO=IHARG(NUMARG)
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1181)IMARCO
 1181     FORMAT('THE MARGIN COLOR HAS JUST BEEN SET TO ',A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ELSEIF(IHARG(1).EQ.'RGB ' .AND. IHARG(2).EQ.'COLO')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           NUMARG.LE.4)THEN
          IMARC2(1)=-1
          IMARC2(2)=-1
          IMARC2(3)=-1
        ELSE
          IMARC2(1)=IARG(3)
          IMARC2(2)=IARG(4)
          IMARC2(3)=IARG(5)
          IF(IMARC2(1).LT.0 .OR. IMARC2(1).GT.IRGBMX)IMARC2(1)=-1
          IF(IMARC2(2).LT.0 .OR. IMARC2(2).GT.IRGBMX)IMARC2(2)=-1
          IF(IMARC2(3).LT.0 .OR. IMARC2(3).GT.IRGBMX)IMARC2(3)=-1
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2181)IMARC2(1),IMARC2(2),IMARC2(3)
 2181     FORMAT('THE MARGIN RGB COLORS HAVE JUST BEEN SET TO ',3I6)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPMACL
      SUBROUTINE DPMACR(ICOM,ICOM2,   &
                        IMACRO,IMACNU,IMACCS,   &
                        IMACL1,IMACL2,IMACLR,IMALEV,   &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                        IANSLC,IANS,IWIDTH,   &
                        IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
                        IOFILE,   &
                        ILOOST,ILOOLI,NUMLIL,NUMLOS,   &
                        IANSLO,IWIDLL,MAXCI2,MAXLI2,   &
                        IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--OPERATE ON MACROS (= SUB-PROGRAMS).
!              THERE ARE 3 CAPABILITITES IN THIS REGARD--
!                 1) TURN THE MACRO SWITCH 'ON' WHICH WILL
!                    ALLOW A MACRO TO BE CREATED.
!                 2) TURN THE MACRO SWITCH 'OFF' WHICH WILL
!                    TERMINATE THE CREATION OF A MACRO.
!                 3) ADD THE CONTENTS OF A MACRO TO THE INPUT RUNSTTREAM
!                    WHICH (IN EFFECT) WILL ALLOW A MACRO
!                    TO BE EXECUTED.
!
!     CALLED BY--MAIN, MAINSU
!
!     NOTE--THESE CAPABILITITIES WILL ALLOW MACROS TO BE DYNAMICALLY
!           CONSTRUCTED AND USED FROM WITHIN A DATAPLOT PROGRAM.
!           WHEN THE MACRO SWITCH IS ON, ALL ENTERED DATAPLOT
!           INSTRUCTIONS ARE AUTOMATICALLY COPIED INTO A SPECIFIED
!           SYSTEM FILE OR SUBFILE.  WHEN THE MACRO SWITCH IS OFF,
!           NO SUCH COPYING IS DONE.  THE SPECIFIED STATUS (ON/OFF)
!           OF THE MACRO WILL BE PLACED IN THE HOLLERITH VARIABLE IMACRO.
!           IMACL1 = FIRST LINE OF THE MACRO TO BE EXECUTED
!           IMACL2 = LAST  LINE OF THE MACRO TO BE EXECUTED
!           IMACLR = NUMBER OF LINES OF MACRO ALREADY READ
!     INPUT  ARGUMENTS--ICOM
!                     --ICOM2
!     INPUT  ARGUMENTS--IMACNU (AN INTEGER VALUE
!                              BY WHICH THE MACRO FILE/SUBFILE MAY BE
!                              REFERENCED IN A FORTRAN I/O STATEMENT.
!                     --IMACCS (A HOLLERITH VARIABLE CONTAINING STATUS
!                              INFORMATION FOR THE MACRO FILE/SUBFILE
!                     --IANSLC (A  HOLLERITH VECTOR WHOSE I-TH ELEMENT
!                              CONTAINS THE I-TH CHARACTER OF THE
!                              ORIGINAL INPUT COMMAND LINE.
!                     --IWIDTH (AN INTEGER VARIABLE WHICH CONTAINS THE
!                              NUMBER OF CHARACTERS IN THE ORIGINAL
!                              COMMAND LINE.
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!                     --IBUG   (A HOLLERITH VARIABLE FOR DEBUGGING
!     OUTPUT ARGUMENTS--IMACRO (AN INTEGER VARIABLE WHICH IF 'ON'
!                              INDICATES THAT CURRENT COMMANDS ARE ALSO
!                              BEING DIVERTED SO AS TO CONSTRUCT A MACRO;
!                              AND IF OFF INDICATES THAT A MACRO IS NOT
!                              BEING CONSTRUCTED.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/1
!     ORIGINAL VERSION--NOVEMBER  1980.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --JANUARY   1982.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   1983.
!     UPDATED         --SEPTEMBER 1983.
!     UPDATED         --JANUARY   1986.
!     UPDATED         --MAY       1990. FOR CALL CASE, SET FILE STATUS='OLD'
!     UPDATED         --AUGUST    1994. SIMPLIFY CODE THROUGHOUT
!     UPDATED         --AUGUST    1994. EXECUTE A SUBSET OF A FILE
!     UPDATED         --APRIL     1997. DIFFERENT UNIT FOR "CREATE
!                                       FILE." CASE TO FIX BUG IF
!                                       "CALL FILE." ENCOUNTERED WHILE
!                                       CREATE IS ON.
!     UPDATED         --JULY      2003. BUG: FILE NAME < 80
!                                       CHARACTERS, BUT COMMAND LINE
!                                       > 80 CHARACTERS
!     UPDATED         --SEPTEMBER 2005. SUPPORT FOR ARGUMENTS TO
!                                       MACROS.  THIS ROUTINE STORES
!                                       THE ARGUMENTS.
!     UPDATED         --OCTOBER   2014. MAXIMUM NUMBER OF COMMAND LINE
!                                       ARGUMENTS RAISED FROM 10 TO 50
!     UPDATED         --OCTOBER   2014. SET FILE NAME QUOTE TO "ON" WHEN
!                                       PARSING COMMAND LINE ARGUMENTS
!     UPDATED         --MARCH     2015. ADD "CALL EXIT" "CALL EXIT ALL"
!                                       COMMANDS
!     UPDATED         --NOVEMBER  2015. LOOP STORE DOES NOT DO COMMAND
!                                       SUBSTITUTION (I.E., "^").  CHECK
!                                       IF FILE NAME STARTS WITH "^"
!                                       (NOTE THAT THIS DOES NOT FIX
!                                       PROBLEM IF "^" STRING DEPENDS
!                                       ON THE LOOP INDEX).
!     UPDATED         --MAY       2016. OPTION ON WHETHER TO STRIP
!                                       QUOTES FROM MACROS
!     UPDATED         --SEPTEMBER 2016. IF FIRST ARGUMENT IS "NULL",
!                                       RE-INITIALIZE ARGUMENT LIST
!     UPDATED         --JANUARY   2017. COMMAND LINE ARGUMENTS THAT
!                                       START WITH "-" (DPEXWO TREATS
!                                       AS WORD SEPARATOR)
!     UPDATED         --JULY      2017. WHEN CALL ENTERED WITHIN A LOOP,
!                                       INSERT A "INSERT CALL LINE
!                                       ARGUMENTS" COMMAND IN SAVED LOOP
!                                       LINES.
!     UPDATED         --MAY       2018. SUPPORT VARIOUS NEW FORMS FOR
!                                       PASSING COMMAND LINE ARGUMENTS
!     UPDATED         --OCTOBER   2020. SAVE CURRENT CALL COMMAND LINE
!     UPDATED         --MARCH     2021. FOR
!                                          CALL X = X2
!                                       REMOVE SPACES AROUND "="
!     UPDATED         --MARCH     2021. FIX BUG WITH
!                                          CALL MACRO.DP STR="Y(23)"
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
!
      CHARACTER*4 ICOM
      CHARACTER*4 ICOM2
      CHARACTER*4 IMACRO
      CHARACTER*12 IMACCS
      CHARACTER*4 IHNAME(*)
      CHARACTER*4 IHNAM2(*)
      CHARACTER*4 IUSE
      CHARACTER*4 IANSLC(*)
      CHARACTER*4 IANS(*)
      CHARACTER*4 IHARG(*)
      CHARACTER*4 IHARG2(*)
      CHARACTER*4 IARGT(*)
      CHARACTER*4 IOFILE
      CHARACTER*4 ILOOST
      CHARACTER*4 IANSLO
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=MAXFNC) :: IFILE
      CHARACTER*12 ISTAT
      CHARACTER*12 IFORM
      CHARACTER*12 IACCES
      CHARACTER*12 IPROT
      CHARACTER*12 ICURST
      CHARACTER*4 IENDFI
      CHARACTER*4 IREWIN
      CHARACTER*4 ISUBN0
      CHARACTER*4 IERRFI
!
      CHARACTER*4 IANSI
!CCCC CHARACTER*80 ICANS
!CCCC CHARACTER*255 ICANS
      CHARACTER (LEN=MAXSTR) :: ICANS
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFILQZ
      CHARACTER*4 IHYPS2
      CHARACTER*4 ICOMC2
!
!CCCC THE FOLLOWING 3 LINES WERE ADDED     AUGUST 1994
!CCCC CHARACTER*4 ICASEQ
!CCCC CHARACTER*4 IBUGQ
      CHARACTER*1 ICJUNK
!
!CCCC CHARACTER*255 ISTR
!CCCC CHARACTER*255 ISTR2
      CHARACTER (LEN=MAXSTR) :: ISTR
      CHARACTER (LEN=MAXSTR) :: ISTR2
!
! ---------------------------------------------------------------------
!
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION IUSE(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
!
      DIMENSION IANSLO(MAXLI2,MAXCI2)
      DIMENSION IWIDLL(*)
!
!-----COMMON----------------------------------------------------------
!
      CHARACTER (LEN=MAXFNC) :: IMANAM(10)
      COMMON/IMAC/IMACN2,IMALE2,IMANAM
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
!CCCC THE FOLLOWING LINE WAS ADDED        AUGUST 1994
!CCCC INCLUDE 'DPCODA.INC' BOMBS
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOFO.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='YES'
      IERROR='NO'
      ISUBN1='DPMA'
      ISUBN2='CR  '
      ICOMC2=ICOMCL
!
      IF(ICOM.EQ.'MACR' .AND. IHARG(1).EQ.'SUBS' .AND.   &
         IHARG(2).EQ.'CHAR')GO TO 9000
!
!CCCC THE FOLLOWING LINE WAS ADDED    AUGUST 1994
      MINN2=1
!
      KMIN=0
      KDEL=0
      KMAX=0
      JP3=0
      JP4=0
      JP5=0
      IH='UNKN'
      IH2='UNKN'
      J12=0
      J22=0
      J32=0
      J42=0
      J52=0
      J62=0
      J72=0
      J82=0
      J92=0
      J102=0
      IPAR2=0
      IPAR3=0
      IPAR4=0
      IPAR5=0
      IPAR6=0
      IPAR7=0
      IPAR8=0
      IPAR9=0
      IPAR10=0
!
      P2=0.0
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,51)
   51    FORMAT('***** AT THE BEGINNING OF DPMACR--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)IMACRO,IMACNU,IMACCS,IMACL1,IMACL2
   52    FORMAT('IMACRO,IMACNU,IMACCS,IMACL1,IMACL2 = ',   &
         A4,I8,2X,A12,I8,I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,53)IBUGS2,IERROR,ICOM,ICOM2,MAXOBV,IWIDTH
   53    FORMAT('IBUGS2,IERROR,ICOM,ICOM2,MAXOBV,IWIDTH = ',   &
                4(A4,2X),2I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,55)(IANS(I),I=1,MIN(120,IWIDTH))
   55    FORMAT('IANS(1...120) = ',120A1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,56)(IANSLC(I),I=1,MIN(120,IWIDTH))
   56    FORMAT('IANSLC(1...120) = ',120A1)
         CALL DPWRST('XXX','BUG ')
!
         WRITE(ICOUT,57)NUMARG
   57    FORMAT('NUMARG = ',I8)
         CALL DPWRST('XXX','BUG ')
         IF(NUMARG.GE.1)THEN
            DO 58 I=1,NUMARG
               WRITE(ICOUT,59)I,IHARG(I),IHARG2(I),IARGT(I),ARG(I)
   59          FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),ARG(I) = ',   &
                      I8,2X,3(A4,2X),G15.7)
               CALL DPWRST('XXX','BUG ')
   58       CONTINUE
         ENDIF
!
         WRITE(ICOUT,62)MAXNAM,NUMNAM,NUMCHA,ICRENU,NUMLOS
   62    FORMAT('MAXNAM,NUMNAM,NUMCHA,ICRENU,NUMLOS = ',5I8)
         CALL DPWRST('XXX','BUG ')
         IF(NUMNAM.GE.1)THEN
            DO 65 I=1,NUMNAM
               WRITE(ICOUT,66)I,IHNAME(I),IHNAM2(I),IUSE(I),   &
               IVALUE(I),VALUE(I)
   66          FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),',   &
               'IVALUE(I),VALUE(I) = ',I8,2X,A4,2X,A4,2X,A4,I8,E15.7)
               CALL DPWRST('XXX','BUG ')
   65       CONTINUE
         ENDIF
         WRITE(ICOUT,73)(IA(I),I=1,MIN(100,NUMCHA))
   73    FORMAT('(IA(I),I=1,NUMCHA) = ',100A1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,82)ICRENA
   82    FORMAT('ICRENA = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,83)ICREST,ICREFO,ICREAC,ICREFO,ICRECS
   83    FORMAT('ICREST,ICREFO,ICREAC,ICREFO,ICRECS = ',4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************************
!               **  STEP 11--                                     **
!               **  FOR THE SPECIAL CASE WHEN THE                 **
!               **  EXECUTION OF A MACRO HAS JUST BEEN FINISHED,  **
!               **  JUMP TO CLOSING THE FILE                      **
!               ****************************************************
!
      ISTEPN='11'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     2015/03: CHECK FOR "CALL EXIT" AND "CALL EXIT ALL" COMMANDS
!
      IF(IMACCS.EQ.'CLO2        ')GO TO 5000
      IF(ICOM.EQ.'CALL' .AND. IHARG(1).EQ.'EXIT')THEN
        IF(IHARG(2).EQ.'ALL ')GO TO 5500
!CCCC   GO TO 5000
        GO TO 5500
      ENDIF
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  FOR THE SPECIAL CASE WHEN HAVE THE       **
!               **  END CREATE     COMMAND, OR THE           **
!               **  END MACRO      COMMAND, OR THE           **
!               **  END OF CREATE      COMMAND,              **
!               **  END OF MACRO       COMMAND,              **
!               **  JUMP IMMEDIATELY TO THE SECTION OF CODE  **
!               **  WHICH PUTS ON AN END OF FILE AND         **
!               **  CLOSES THE FILE/SUBFILE.                 **
!               ***********************************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'END ')THEN
        IF(NUMARG.EQ.1 .AND. (IHARG(1).EQ.'CREA' .OR.   &
          IHARG(1).EQ.'MACR'))GO TO 4000
        IF(NUMARG.EQ.2 .AND. IHARG(1).EQ.'OF  ' .AND.   &
          (IHARG(2).EQ.'CREA' .OR. IHARG(2).EQ.'MACR'))GO TO 4000
!CCCC   IF(NUMARG.EQ.1 .AND. IHARG(1).EQ.'CALL')GO TO xxxx
!CCCC   IF(NUMARG.EQ.2 .AND. IHARG(1).EQ.'OF  ' .AND.
!CCCC1    IHARG(2).EQ.'CALL')GO TO xxxx
      ENDIF
!
!               ***************************************************************
!               **  STEP 13--
!               **  DETERMINE THE TYPE CASE--
!               **       1) OPERATE ON A MACRO RESIDING IN A FILE;
!               **       2) OPERATE ON A MACRO FROM THE TERMINAL (ILLEGAL).
!               **  NOTE--IOFILE  WILL EQUAL 'YES' ONLY IN FILE CASE.
!               **  IN OTHER WORDS, THIS STEP MAKES SURE
!               **  THAT A FILE NAME IS EXISTENT AFTER THE
!               **  CREATE   AND   CALL   COMMANDS.
!               ***************************************************************
!
      ISTEPN='13'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWORD=2
      CALL DPFILE(IANSLC,IWIDTH,IWORD,   &
      IOFILE,IBUGS2,ISUBRO,IERROR)
!
!               **********************************************
!               **  STEP 14--                               **
!               **  IF NO FILE NAME GIVEN,                  **
!               **  THEN GENERATE AN ERROR MESSAGE.         **
!               **********************************************
!
      ISTEPN='14'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IOFILE.NE.'YES')THEN
         IERROR='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1411)
 1411    FORMAT('***** ERROR IN DPMACR--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1412)
 1412    FORMAT('      THE DESIRED MACRO OPERATION CANNOT BE CARRIED')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1414)
 1414    FORMAT('      BECAUSE NO USER FILE NAME WAS GIVEN.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1415)
 1415    FORMAT('      ILLUSTRATIVE EXAMPLE TO DEMONSTRATE THE ',   &
                'PROPER FORM--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1417)
 1417    FORMAT('      SUPPOSE THE ANALYST WISHES TO EXECUTE A MACRO ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1419)
 1419    FORMAT('      RESIDING IN THE MASS STORAGE FILE    MAC3.  ,')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1420)
 1420    FORMAT('      THEN THE FOLLOWING COMMAND LINE IS ENTERED--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1421)
 1421    FORMAT('         CALL MAC3.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!               *************************************
!               **  STEP 15--                      **
!               **  IF HAVE THE FILE INPUT CASE    **
!               **  (WHICH WE MUST HAVE)--         **
!               **  COPY OVER VARIABLES            **
!               *************************************
!
      ISTEPN='15'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOUNIT=ICRENU
      IFILE=ICRENA
      ISTAT=ICREST
      IF(IFILE.EQ.ISYSNA)ISTAT=ISYSST
      IF(IFILE.EQ.ILOGNA)ISTAT=ILOGST
      IFORM=ICREFO
      IACCES=ICREAC
      IPROT=ICREPR
!     (SEE ADDITIONAL RESETTING OF   IPROT   BELOW
!     IF HAVE THE SYSTEM LOGIN AND/OR THE LOCAL LOGIN MACRO FILES)
      ICURST=ICRECS
!
      ISUBN0='MACR'
      IERRFI='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
         WRITE(ICOUT,1513)ISUBN0,IERRFI,IOUNIT
 1513    FORMAT('ISUBN0,IERRFI,IOUNIT = ',2(A4,2X),I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1514)IFILE
 1514    FORMAT('IFILE = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1515)ISTAT,IFORM,IACCES,IPROT,ICURST
 1515    FORMAT('ISTAT,IFORM,IACCES,IPROT,ICURST = ',4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************************
!               **  STEP 16--                                **
!               **  IF HAVE THE FILE INPUT CASE--            **
!               **  (WHICH WE MUST HAVE)--                   **
!               **  CHECK TO SEE IF THE MACRO FILE MAY EXIST **
!               ***********************************************
!
      ISTEPN='16'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISTAT.EQ.'NONE')THEN
         IERROR='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1611)
 1611    FORMAT('***** IMPLEMENTATION ERROR IN DPMACR--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1612)
 1612    FORMAT('      THE DESIRED MACRO CREATE/CALL CANNOT BE CARRIED')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1614)
 1614    FORMAT('      OUT BECAUSE THE INTERNAL VARIABLE    ICREST ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1615)
 1615    FORMAT('      WHICH ALLOWS SUCH MACRO OPERATIONS HAS BEEN ',   &
                'SET TO    NONE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1617)ISTAT,ICREST
 1617    FORMAT('ISTAT,ICREST = ',A12,2X,A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1618)
 1618    FORMAT('      PLEASE CONTACT YOUR DATAPLOT IMPLEMENTOR')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1619)
 1619    FORMAT('      TO CORRECT THE SETTING IN SUBROUTINE INITFO.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!               ********************************
!               **  STEP 17--                 **
!               **  EXTRACT THE FILE NAME.    **
!               **  THIS IS NEEDED FOR MOST   **
!               **  (BUT NOT ALL) VARIATIONS  **
!               **  OF THE MACRO COMMAND.     **
!               ********************************
!
      ISTEPN='17'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1710 I=1,MAXSTR
         IANSI=IANSLC(I)
         ICANS(I:I)=IANSI(1:1)
 1710 CONTINUE
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=2
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                  ICOL1,ICOL2,IFILE,NCFILE,   &
                  IBUGS2,ISUBRO,IERROR)
!
      IF(NCFILE.LE.0)THEN
         IERROR='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1411)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1742)
 1742    FORMAT('      A USER FILE NAME IS REQUIRED IN THE CREATE AND ',   &
                'CALL COMMANDS')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1744)
 1744    FORMAT('      (FOR EXAMPLE,    CALL PROG7.DP) BUT NONE WAS ',   &
                'GIVEN HERE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1746)
 1746    FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
         CALL DPWRST('XXX','BUG ')
         IF(IWIDTH.GE.1)THEN
           WRITE(ICOUT,1747)(IANSLC(I),I=1,MIN(100,IWIDTH))
 1747      FORMAT('      ',100A1)
           CALL DPWRST('XXX','BUG ')
         ELSE
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
         ENDIF
         GO TO 9000
      ENDIF
!
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(IFILE.EQ.ISYSNA)IPROT=ISYSPR
      IF(IFILE.EQ.ILOGNA)IPROT=ILOGPR
!
!               *****************************************
!               **  STEP 25--                          **
!               **  CHECK THE DESIRED MACRO OPERATION  **
!               **  (ON, OFF, OR EXECUTE).             **
!               *****************************************
!
      ISTEPN='25'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'MACR'.AND.ICOM2.EQ.'O   ')THEN
        IF(NUMARG.LE.0)GO TO 2900
        IF(NUMARG.EQ.1 .OR. IHARG(2).EQ.'ON' .OR.   &
           IHARG(2).EQ.'AUTO')GO TO 3000
        IF(IHARG(2).EQ.'OFF' .OR. IHARG(2).EQ.'DEFA')GO TO 4000
        IF(IHARG(2).EQ.'CLOS')GO TO 5000
!
        IF(IHARG(2).EQ.'EXEC')THEN
          NSARG=3
          GO TO 6000
        ELSEIF(IHARG(2).EQ.'ADD')THEN
          NSARG=3
          GO TO 6000
        ELSEIF(IHARG(2).EQ.'CALL')THEN
          NSARG=3
          GO TO 6000
        ELSEIF(IHARG(2).EQ.'RUN')THEN
          NSARG=3
          GO TO 6000
        ENDIF
      ELSEIF(ICOM.EQ.'END '.AND.ICOM2.EQ.'    ')THEN
        IF(NUMARG.EQ.1 .AND. IHARG(1).EQ.'CREA')GO TO 4000
        IF(NUMARG.GE.2 .AND. IHARG(1).EQ.'OF  ' .AND.   &
          IHARG(2).EQ.'CREA')GO TO 4000
      ELSEIF(ICOM.EQ.'CREA'.AND.ICOM2.EQ.'TE  ')THEN
        IF(NUMARG.GE.1)GO TO 3000
      ELSEIF(   &
        (ICOM.EQ.'CALL' .AND. ICOM2.EQ.'    ') .OR.   &
        (ICOM.EQ.'ADD ' .AND. ICOM2.EQ.'    ') .OR.   &
        (ICOM.EQ.'RUN ' .AND. ICOM2.EQ.'    ') .OR.   &
        (ICOM.EQ.'EXEC' .AND. ICOM2.EQ.'UTE '))THEN
        NSARG=2
        IF(NUMARG.GE.1)GO TO 6000
      ENDIF
!
 2900 CONTINUE
!
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1411)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2912)
 2912 FORMAT('      THE DESIRED MACRO OPERATION CANNOT BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2914)
 2914 FORMAT('      BECAUSE THE SPECIFIED OPERATION WAS ILLEGAL.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1415)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1417)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1419)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1420)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1421)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               ********************************************************
!               **  STEP 30--                                         **
!               **  TREAT THE MACRO ON (= CREATE) CASE.  CARRY OUT    **
!               **  WHATEVER SYSTEM OPERATIONS ARE NEEDED IN ORDER TO **
!               **  OPERATE ON THE FILE OR SUBFILE.  FOR MOST         **
!               **  INSTALLATIONS, THIS REQUIRES                      **
!               **      1) AN OPENING OF THE FILE OR SUBFILE;         **
!               **      2) AN EQUIVALENCING OF THE FILE OR SUBFILE;   **
!               **      3) A  REWINDING OF THE FILE OR SUBFILE.       **
!               **  THE CODE BELOW OPENS THE FILE OR SUBFILE.  THE    **
!               **  CODE ALSO EQUIVALENCES THE FILES OR SUBFILES      **
!               **  TO THE FORTRAN LOGICAL UNIT NUMBER DESIGNATED IN  **
!               **  THE VARIABLE IMACNU (IN THE SUBROUTINE INITFO;    **
!               **  THE CODE ALSO REWINDS THE FILE OR SUBFILE.        **
!               ********************************************************
!
 3000 CONTINUE
      ISTEPN='30'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMACRO='ON'
!CCCC IOUNIT=IMACNU       OCTOBER 8, 1986
!CCCC APRIL 1997.  SEPARATE UNIT FOR CREATE AND CALL TO AVOID INFINITE
!CCCC LOOP
!CCCC IOUNIT=ICRENU
      IOUNIT=ICREN2
!
      IREWIN='ON'
      CALL DPOPFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      IF(IERRFI.EQ.'YES')THEN
        IERROR='YES'
        GO TO 9000
      ENDIF
      IMACCS=ICURST
!
      IF(IFEEDB.EQ.'ON')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,3011)
 3011    FORMAT('THE CREATE (MACRO) SWITCH HAS JUST BEEN TURNED ON.')
         CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
!               ****************************************************************
!               **  STEP 40--
!               **  TREAT THE MACRO OFF (= END OF CREATE) CASE.
!               **  CARRY OUT WHATEVER SYSTEM OPERATIONS ARE NEEDED
!               **  IN ORDER TO OPERATE ON THE FILE OR SUBFILE.
!               **  FOR MOST INSTALLATIONS, THIS REQUIRES
!               **      1) A PLACING OF AN END MARK OF THE FILE OR SUBFILE;
!               **      2) A FREEING (DEASSIGNING) OF THE FILE OR SUBFILE;
!               ****************************************************************
!
 4000 CONTINUE
      ISTEPN='40'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMACRO='OFF'
!CCCC IOUNIT=IMACNU       OCTOBER 8, 1986
!CCCC APRIL 1997.  SEPARATE UNIT FOR CREATE AND CALL
!CCCC IOUNIT=ICRENU
      IOUNIT=ICREN2
!
      IENDFI='ON'
      IREWIN='ON'
      CALL DPCLFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      IF(IERRFI.EQ.'YES')GO TO 9000
!
      IF(IFEEDB.EQ.'ON')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,4011)
 4011    FORMAT('THE CREATE (MACRO) SWITCH HAS JUST BEEN TURNED OFF.')
         CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
!               ************************************
!               **  STEP 50--                     **
!               **  TREAT THE MACRO CLOSE CASE.   **
!               ************************************
!
!     NOTE 10/14/2008: WHEN MACROS ARE NESTED, ICURST GETS SET
!                      TO CLOSED WHEN THE INNER-MOST MACRO IS
!                      CLOSED.  THIS RESULTS IN SUBSEQUENT MACROS
!                      NOT GETTING CLOSED.  SINCE WE DO NOT KEEP
!                      A SEPARATE STATUS FLAG FOR EACH FILE IN
!                      THE NEST, NEED TO BE SURE THAT WE CLOSE
!                      THE FILE REGARDLESS OF VALUE OF "ICURST".
!
 5000 CONTINUE
      ISTEPN='50'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOUNIT=IMACNU
      IENDFI='OFF'
      IREWIN='ON'
      ICURST='OPEN'
      CALL DPCLFI(IOUNIT,IMANAM(IMALEV),ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      IF(IERRFI.EQ.'YES')GO TO 9000
!
!     NOW RESET MACRO LEVEL
!
      IMACCS='JUNK'
      IF(IMALEV.GE.1)IMANAM(IMALEV)='NO'
      IMALEV=IMALEV-1
      IF(IMALEV.LE.0)THEN
        IMACNU=IRD
        IMALEV=0
        IMACRO='OFF'
      ELSE
        IMACNU=IMACNU-1
        IF(IMALEV.EQ.1)IMACNU=ICRENU
      ENDIF
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,5011)IMACNU
 5011    FORMAT('MACRO FILE NUMBER ',I8,' HAS JUST BEEN CLOSED')
         CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
!               ************************************
!               **  STEP 55--                     **
!               **  TREAT THE CALL EXIT   CASE.   **
!               ************************************
!
!     NOTE 2015/03: ADD SUPPORT FOR A "CALL EXIT" CASE.  FOR EXAMPLE,
!                   THIS CAN BE USED TO EXIT A MACRO IF AN ERROR
!                   CONDITION IS ENCOUNTERED.
!
!                   THERE ARE 2 CASES:
!
!                      1. EXIT THE CURRENT MACRO ONLY
!
!                      2. EXIT ALL MACROS (I.E., RETURN CONTROL
!                         TO THE TERMINAL).
!
!                   THE EXIT CURRENT CASE IS HANDLED BY THE STEP 50 CODE.
!                   THIS BLOCK HANDLES THE EXIT ALL CASE.
!
 5500 CONTINUE
      ISTEPN='55'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IMALEV.GE.1)THEN
        DO 5510 II=1,IMALEV
          IOUNIT=IMACNU
          IENDFI='OFF'
          IREWIN='ON'
          ICURST='OPEN'
          CALL DPCLFI(IOUNIT,IMANAM(IMALEV),ISTAT,IFORM,IACCES,IPROT,   &
                      ICURST,IENDFI,IREWIN,ISUBN0,IERRFI,   &
                      IBUGS2,ISUBRO,IERROR)
          IF(IERRFI.EQ.'YES')GO TO 9000
!
!         NOW RESET MACRO LEVEL
!
          IF(IMALEV.GE.1)IMANAM(IMALEV)='NO'
          IMALEV=IMALEV-1
          IF(IMALEV.LE.0)THEN
            IMACNU=IRD
            IMALEV=0
            IMACRO='OFF'
          ELSEIF(IMALEV.EQ.1)THEN
            IMACNU=ICRENU
          ELSEIF(IMALEV.GE.2)THEN
            IMACNU=IMACNU-1
          ENDIF
 5510   CONTINUE
      ENDIF
!
      IMACCS='JUNK'
!
      IF(IFEEDB.EQ.'ON')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,5511)
 5511    FORMAT('ALL MACRO FILES HAVE BEEN CLOSED.')
         CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
!               ********************************************************
!               **  STEP 60--                                         **
!               **  TREAT THE MACRO (= CALL) CASE.                    **
!               **  CARRY OUT WHATEVER SYSTEM OPERATIONS ARE NEEDED   **
!               **  IN ORDER TO OPERATE ON THE FILE OR SUBFILE.       **
!               **  FOR MOST INSTALLATIONS, THIS REQUIRES             **
!               **      1) AN OPENING OF THE FILE OR SUBFILE;         **
!               **      2) AN EQUIVALENCING OF THE FILE OR SUBFILE;   **
!               **      3) A  REWINDING OF THE FILE OR SUBFILE.       **
!               **      4) SKIPPING OVER ANY FRONT LINES              **
!               ********************************************************
!
 6000 CONTINUE
      ISTEPN='60'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     OCTOBER 2020: SAVE THE CURRENT CALL COMMAND LINE
!
      IMCRCL=' '
      DO 6003 II=1,MIN(IWIDTH,1024)
        IMCRCL(II:II)=IANSLC(II)(1:1)
 6003 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED   AUGUST 1994
!CCCC TO ALLOW FOR FOR/SUBSET           AUGUST 1994
!               *****************************************
!               **  STEP 61--                          **
!               **  CHECK TO SEE THE TYPE CASE--       **
!               **    1) UNQUALIFIED (THAT IS, FULL);  **
!               **    2) SUBSET/EXCEPT; OR             **
!               **    3) FOR.                          **
!               *****************************************
!
      ISTEPN='61'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC THE FOLLOWING SECTION WAS ADDED   AUGUST 1994
!CCCC TO ALLOW FOR FOR/SUBSET           AUGUST 1994
!               *********************************************
!               **  STEP 62--                              **
!               **  BRANCH    TO THE APPROPRIATE SUBCASE   **
!               **  (FULL, SUBSET, OR FOR).                **
!               *********************************************
!
      ISTEPN='62'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               **************************************************
!               **  STEP 63--                                   **
!               **  FIND THE FIRST AND LAST ROW OF THE SUB-CHUNK**
!               **  OF THE FILE BEING EXECUTED                  **
!               **  IMACL1 = FIRST LINE TO BE EXECUTED          **
!               **  IMACL2 = LAST  LINE TO BE EXECUTED          **
!               **  IMACLR = NUMBER OF LINES ALREADY EXECUTED   **
!               **************************************************
!
      ISTEPN='63'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,6001)IMALEV,NUMARG,NSARG
 6001   FORMAT('IMALEV,NUMARG,NSARG = ',3I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC THE FOLLOWING IS A PATCH                          AUGUST 1994
!CCCC TO MAKE    CALL <FILE> FOR I = ... ... ... WORK   AUGUST 1994
!
!CCCC SEPTEMBER 2005.  IF NO FOR CLAUSE, THEN INTERPRET ANY
!CCCC                  ARGUMENTS AFTER "CALL FILE." AS COMMAND
!CCCC                  LINE ARGUMENTS.
!CCCC
!CCCC                  IF THIS IS THE FIRST LEVEL CALL, CLEAR THE
!CCCC                  COMMAND LINE ARGUMENTS IF NO ARGUMENTS ARE
!CCCC                  GIVEN.
!CCCC
!CCCC MAY 2016.        OPTION TO ALLOW USER TO SPECIFY WHETHER QUOTES
!CCCC                  SHOULD BE STRIPPED OFF OF COMMAND LINE ARGUMENTS.
!CCCC
!CCCC SEPTEMBER 2016.  IF FIRST ARGUMENT IS "NULL", CLEAR ARGUMENT LIST.
!CCCC
!CCCC OCTOBER 2016.    UPDATE MAXIMUM NUMBER OF CHARACTERS FOR ARGUMENT
!CCCC                  TO 80.  ALSO ALLOW NAMED ARGUMENTS, E.G.
!CCCC
!CCCC                      CALL TEST.DP  Y=Y3  X=X2
!CCCC
!CCCC JANUARY   2017.  IF ARGUMENT STARTS WITH "-", DPEXWO TREATS AS
!CCCC                  WORD SEPARATOR AND REMOVES IT.  ADD OPTION TO
!CCCC                  NOT TREAT LEADING "-" AS WORD SEPARATOR.
!CCCC
!CCCC JULY      2017.  IF THE CALL COMMAND IS GIVEN WITHIN A LOOP,
!CCCC                  DATAPLOT SAVES THE CONTENTS OF THE CALL FILE
!CCCC                  RATHER THAN CALL COMMAND.  THIS MEANS THAT
!CCCC                  ARGUMENTS ARE LOST AFTER THE FIRST ITERATION
!CCCC                  OF THE LOOP.  THE COMMAND
!CCCC
!CCCC                     INSERT CALL LINE ARGUMENTS <string>
!CCCC
!CCCC                  WAS ADDED TO ADDRESS THIS PROBLEM.  THIS ROUTINE
!CCCC                  WILL INSERT THE COMMAND INTO THE SAVED LOOP
!CCCC                  COMMANDS.  WHEN THE LOOP IS EXECUTED, THAT
!CCCC                  COMMAND WILL RESTORE THE COMMAND LINE ARGUMENTS.
!CCCC
!CCCC MAY       2018.  IF NO COMMAND LINE ARGUMENTS GIVEN, THEN
!CCCC                  DON'T CLEAR PREVIOUS LIST.
!CCCC
!CCCC MARCH     2021.  FOR NAMED ARGUMENTS, REMOVE SPACES AROUND "="
!CCCC                  SIGNS
!
      IF(NUMARG.LT.NSARG)GO TO 6399
!
      IBLANK=0
      ICNT=0
      IFLAGP=0
!
!     2021/03: 1) COMMAND LINE LENGTH RAISED FROM 255 TO 1024
!              2) REMOVE SPACES AROUND EQUAL SIGNS NOT EMBEDDED
!                 IN QUOTES
!
      IMACCL=' '
      DO 6290 I=1,MIN(IWIDTH,1024)
        IF(IBLANK.EQ.0 .AND. IANSLC(I)(1:1).EQ.' ')GO TO 6290
        IBLANK=1
        ICNT=ICNT+1
        IMACCL(ICNT:ICNT)=IANSLC(I)(1:1)
 6290 CONTINUE
      NMACCL=ICNT
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
        WRITE(ICOUT,6291)NMACCL,IMACCL(1:NMACCL)
 6291   FORMAT('AFTER 6290: NMACCL,IMACCL(1:NMACCL) = ',I6,2X,A)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     2021/03: STRIP OUT SPACES AROUND EQUAL SIGNS NOT EMBEDDED
!              IN QUOTES
!
      IFLAGQ=0
      IFLAGE=0
      ICNT=0
      ISTR=' '
      ISPACE=0
      DO 6293 I=1,NMACCL
!
        IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
          WRITE(ICOUT,66291)I,IFLAGQ,IFLAGE,ICNT,IMACCL(I:I),   &
                            ISTR(1:MAX(1,ICNT))
66291     FORMAT('6293: I,IFLAGQ,IFLAGE,ICNT,IMACCL(I:I),ISTR = ',   &
                 4I6,2X,A1,2X,A)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IMACCL(I:I).EQ.'"')THEN
!
!         CHECK FOR QUOTE AND DETERMINE WHETHER OPENING OR CLOSING QUOTE
!
          ICNT=ICNT+1
          ISTR(ICNT:ICNT)=IMACCL(I:I)
          IF(IFLAGQ.EQ.0)THEN
            IFLAGQ=1
            IFLAGE=0
          ELSE
            IFLAGQ=0
            ISPACE=1
          ENDIF
        ELSEIF(IFLAGE.EQ.1)THEN
!
!         NON-QUOTED EQUAL SIGN, REMOVE BLANKS AFTER
!
          IF(IMACCL(I:I).NE.' ')THEN
            ICNT=ICNT+1
            ISTR(ICNT:ICNT)=IMACCL(I:I)
            IFLAGE=0
          ELSE
            GO TO 6293
          ENDIF
        ELSEIF(IMACCL(I:I).EQ.'=' .AND. IFLAGQ.EQ.0)THEN
!
!         NON-QUOTED EQUAL, REMOVE PRECEEDING BLANKS
!
!         ONE AMBIGUITY:
!
!             call sub.dp  frame=   type=data
!
!         IS "type=data" THE ARGUMENT FOR frame OR DOES IT
!         DEFINE A NEW NAMED ARGUMENT?  CHECK: IF THERE IS A
!         SINGLE UNQUOTED WORD BEFORE NEXT UNQUOTED EQUAL SIGN,
!         THEN ASSUME IT IS AN ARGUMENT NAME.  ADDRESS THIS BY
!         ADDING A BLANK CHARACTER AFTER THE "frame=".
!
          ISKIP=0
          IF(I.GT.1)THEN
            DO 6295 JJ=I-1,1,-1
              IF(IMACCL(JJ:JJ).NE.' ')THEN
                GO TO 6296
              ELSE
                ISKIP=ISKIP+1
              ENDIF
 6295       CONTINUE
 6296       CONTINUE
            IF(ISKIP.GT.0)THEN
              ICNT=ICNT-ISKIP
              ISTR(ICNT+1:ICNT+ISKIP)=' '
            ENDIF
            ICNT=ICNT+1
            ISTR(ICNT:ICNT)=IMACCL(I:I)
            IFLAGE=1
          ENDIF
!
          IF(I.LT.NMACCL)THEN
            NWORD=0
            IFLAGC=0
            DO 67291 JJ=I+1,NMACCL
!
              IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
                WRITE(ICOUT,96299)I,JJ,IMACCL(JJ:JJ)
96299           FORMAT('AT 6729: I,JJ,IMACCL(JJ:JJ) = ',2I6,2X,A1)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
              IF(IMACCL(JJ:JJ).EQ.'"')GO TO 6293
              IF(IMACCL(JJ:JJ).EQ.'=')THEN
!
                IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
                  WRITE(ICOUT,96291)NWORD
96291             FORMAT('AT NEXT =: NWORD = ',I6)
                  CALL DPWRST('XXX','BUG ')
                ENDIF
!
                IF(NWORD.LE.1)THEN
                  ICNT=ICNT+1
                  ISTR(ICNT:ICNT)='"'
                  ICNT=ICNT+1
                  ISTR(ICNT:ICNT)=' '
                  ICNT=ICNT+1
                  ISTR(ICNT:ICNT)='"'
                  ICNT=ICNT+1
                  ISTR(ICNT:ICNT)=' '
                ENDIF
                GO TO 6293
              ENDIF
!
              IF(IMACCL(JJ:JJ).EQ.' ')THEN
!
                IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
                  WRITE(ICOUT,96292)IFLAGC
96292             FORMAT('SPACE CHARACTER: IFLAGC = ',I6)
                  CALL DPWRST('XXX','BUG ')
                ENDIF
!
                IF(IFLAGC.EQ.1)IFLAGC=0
              ELSE
                IF(IFLAGC.EQ.0)NWORD=NWORD+1
                IFLAGC=1
!
                IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
                  WRITE(ICOUT,96293)IMACCL(JJ:JJ)
96293             FORMAT('NON-SPACE CHARACTER: IMACCL(JJ:JJ) = ',A1)
                  CALL DPWRST('XXX','BUG ')
                ENDIF
              ENDIF
67291       CONTINUE
          ENDIF
!
        ELSE
          ICNT=ICNT+1
          ISTR(ICNT:ICNT)=IMACCL(I:I)
        ENDIF
 6293 CONTINUE
!
      IF(ICNT.NE.NMACCL)THEN
        IMACCL=' '
        IMACCL(1:ICNT)=ISTR(1:ICNT)
        NMACCL=ICNT
        DO 6297 II=1,NMACCL
          IANSLC(II)=IMACCL(II:II)
          IANS(II)=IMACCL(II:II)
          ICANS(II:II)=IANSLC(II)(1:1)
 6297   CONTINUE
        DO 6298 II=NMACCL+1,IWIDTH
          IANSLC(II)=' '
          IANS(II)=' '
          ICANS(II:II)=IANSLC(II)(1:1)
 6298   CONTINUE
        IWIDTH=NMACCL
      ENDIF
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
        WRITE(ICOUT,6299)NMACCL,IMACCL(1:NMACCL)
 6299   FORMAT('AFTER 6299: NMACCL,IMACCL(1:NMACCL) = ',I6,2X,A)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IMACL1=1
      IMACL2=100000
      IHYPS2=IHYPSW
      ICOMCL='ON'
!
      IF(IMALEV.EQ.1)THEN
        DO 6380 II=1,50
          IMACAR(II)=' '
          IMACLA(II)=' '
          IMACLL(II)=0
 6380   CONTINUE
        NMACAG=0
        NMACLA=0
      ENDIF
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
        WRITE(ICOUT,6381)NUMARG,NSARG,ILOOLI,ILOOST
 6381   FORMAT('NUMARG,NSARG,ILOOLI,ILOOST = ',3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IHARG(2).EQ.'FOR ')THEN
         IF(NUMARG.GE.7)THEN
            IMACL1=IARG(5)
            IMACL2=IARG(7)
         ENDIF
      ELSE IF(NUMARG.GE.NSARG)THEN
        NMACAG=0
        NMACLA=0
        DO 6390 II=1,50
          IMACAR(II)=' '
          IMACLA(II)=' '
          IMACLL(II)=0
 6390   CONTINUE
        IFILQZ=IFILQU
!
!       ENTER THE CALL ARGUMENTS IN THE SAVED LOOP COMMANDS
!
        IF(ILOOST.EQ.'STOR' .AND. ILOOLI.LT.MAXLIL)THEN
          NCSTR=22
          ISTR(1:NCSTR)='INSERT CALL ARGUMENTS '
!
          DO 6391 I=1,MAXSTR
            ICANS(I:I)=IANSLC(I)(1:1)
 6391     CONTINUE
!
          ISTART=1
          ISTOP=IWIDTH
          IWORD=3
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,6382)ISTART,ISTOP
 6382       FORMAT('BEFORE DPEXW3: ISTART,ISTOP = ',2I8)
            CALL DPWRST('XXX','BUG ')
            DO 6383 JJ=1,IWIDTH
              WRITE(ICOUT,6384)JJ,ICANS(JJ:JJ)
 6384         FORMAT('JJ,ICANS(JJ:JJ) = ',I5,2X,A1)
              CALL DPWRST('XXX','BUG ')
 6383       CONTINUE
          ENDIF
!
          CALL DPEXW3(ICANS,ISTART,ISTOP,IWORD,   &
                      ICOL1,ICOL2,ISTR2,NCTEMP,   &
                      IBUGS2,ISUBRO,IERROR)
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,6386)ICOL1,ICOL2,NCTEMP
 6386       FORMAT('AFTER DPEXW3: ICOL1,ICOL2,NCTEMP = ',3I8)
            CALL DPWRST('XXX','BUG ')
            DO 6387 JJ=1,NCTEMP
              WRITE(ICOUT,6388)JJ,ISTR2(JJ:JJ)
 6388         FORMAT('JJ,ISTR2(JJ:JJ) = ',I5,2X,A1)
              CALL DPWRST('XXX','BUG ')
 6387       CONTINUE
          ENDIF
!
          IF(ICOL1.LE.ICOL2)THEN
            DO 6392 JJ=1,NCTEMP
              NCSTR=NCSTR+1
              ISTR(NCSTR:NCSTR)=ISTR2(JJ:JJ)
 6392       CONTINUE
!
            IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
              WRITE(ICOUT,16387)
16387         FORMAT('AFTER INSERTING COMMAND LINE ARGUMENTS')
              CALL DPWRST('XXX','BUG ')
              DO 16388 JJ=1,NCSTR
                WRITE(ICOUT,16389)JJ,ISTR(JJ:JJ)
16389           FORMAT('JJ,ISTR(JJ:JJ) = ',I5,2X,A1)
                CALL DPWRST('XXX','BUG ')
16388         CONTINUE
            ENDIF
!
          ENDIF
!
          ILOOLI=ILOOLI+1
          NUMLIL=ILOOLI
          IWIDLL(ILOOLI)=NCSTR
          IF(NCSTR.GT.MAXCIL)NCSTR=MAXCIL
          DO 6393 JJ=1,NCSTR
            IANSLO(ILOOLI,JJ)(1:1)=ISTR(JJ:JJ)
 6393     CONTINUE
!
        ENDIF
!
!       DPTYPE DOES NOT SPLIT WORDS IN THE WAY NEEDED IN PARSING
!       COMMAND LINE ARGUMENTS.  CALL DPNUWO TO DETERMINE THE
!       NUMBER OF WORDS ON THE COMMAND LINE.
!
        ISTR=' '
        DO 16381 II=1,IWIDTH
          ISTR(II:II)=IANSLC(II)(1:1)
16381   CONTINUE
        ISTART=1
        CALL DPNUWO(ISTR,ISTART,IWIDTH,NWORD,IBUGS2,ISUBRO,IERROR)
!
        IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
          WRITE(ICOUT,16382)NWORD,IERROR
16382     FORMAT('AFTER DPNUWO: NWORD,IERROR = ',I5,2X,A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IFILQU='ON'
        DO 6370 J=NSARG+1,NWORD
          NMACAG=NMACAG+1
          IF(NMACAG.GT.50)GO TO 6379
          ISTART=1
          ISTOP=IWIDTH
          IWORD=J
          IHYPSW='OFF'
          CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                      ICOL1,ICOL2,IMACAR(NMACAG),NCTEMP,   &
                      IBUGS2,ISUBRO,IERROR)
          IHYPSW=IHYPS2
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            ISTEPN='637'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,6394)J,IWORD,NMACAG,NCTEMP,IMACAR(NMACAG)
 6394       FORMAT('6370: J,IWORD,NMACAG,NCTEMP,IMACAR(NMACAG) = ',   &
                   4I5,2X,A100)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         CHECK IF 80 CHARACTERS EXCEEDED (BE SURE TO MAKE LAST
!         CHARACTER A QUOTE IF FIRST CHARACTER IS A QUOTE).
!
!CCCC     IF(NCTEMP.GT.80)THEN
          IF(NCTEMP.GT.MAXFNC)THEN
            NCTEMP=MAXFNC
            IF(IMACAR(NMACAG)(1:1).EQ.'"')   &
               IMACAR(NMACAG)(NCTEMP:NCTEMP)='"'
          ENDIF
!
!         REMOVE LEADING/TRAILING QUOTES IF NEEEDED
!
          IF(IMACAR(NMACAG)(1:1).EQ.'"' .AND.   &
             IMACAR(NMACAG)(NCTEMP:NCTEMP).EQ.'"')THEN
            IF(IQUOST.EQ.'ON')THEN
              IMACAR(NMACAG)(1:NCTEMP-2)=IMACAR(NMACAG)(2:NCTEMP-1)
              NCTEMP=NCTEMP-2
              IMACAR(NMACAG)(NCTEMP+1:NCTEMP+2)='  '
            ENDIF
          ENDIF
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,17394)
17394       FORMAT('AFTER STRIP QUOTES: NMACAG,IMACAR(NMACAG) =',   &
                   I5,2X,A100)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         2016/09: IF FIRST ARGUMENT IS "NULL", THEN BLANK OUT
!                  ARGUMENT LIST AND SET NUMBER OF ARGUMENTS TO 0.
!
          IF(NMACAG.EQ.1)THEN
            IF(IMACAR(1).EQ.'NULL' .OR. IMACAR(1).EQ.'null')THEN
              IMACAR(1)=' '
              NMACAG=0
              GO TO 6379
            ENDIF
          ENDIF
!
!         2018/05: ALLOW "EMPTY" ARGUMENTS, DO NOT SET TO ZZZZNULL
!
!         2021/03: TEMPORARILY SET BLANK ARGUMENTS TO "ZZZZEMPTY",
!                  THESE WILL BE SET TO BLANK AT THE END.
!
          IF(NCTEMP.EQ.1 .AND. IMACAR(NMACAG)(1:1).EQ.' ')THEN
            IMACAR(NMACAG)='ZZZZEMPTY'
            NCTEMP=9
          ELSEIF(NCTEMP.EQ.0)THEN
            IMACAR(NMACAG)='ZZZZEMPTY'
            NCTEMP=9
          ENDIF
!
!         2016/10: CHECK FOR NAMED ARGUMENTS
!
!         2018/04: CHECK FOR FOLLOWING 2 CASES
!
!                  1.  "FRAME=FOR I = 1 1 50"
!                  2.   FRAME="FOR I = 1 1 50"
!
!                  AS FIRST STEP, CHECK FOR FIRST OCCURENCE OF QUOTE
!                  (IF ANY) AND FIRST OCCURRENCE OF EQUAL SIGN.
!
!                  NOTE THAT CODE WAS ADDED IN MAIN AND DPTYPE ROUTINES
!                  SO THAT EQUAL SIGN WILL NOT BE A DELIMITER ON A CALL
!                  COMMAND.
!
          IPOSQU=0
          IPOSEQ=0
!
!         CHECK FOR FIRST EQUAL CHARACTER.  HOWEVER, IF THE EQUAL
!         CHARACTER IS PRECEEDED BY AN ESCAPE CHARACTER ("\"), THEN
!         REMOVE THE ESCAPE CHARACTER BUT TREAT AS NO EQUAL CHARACTER
!         CASE.  START WITH CHARACTER POSITION 2 AS THERE NEEDS TO BE
!         AT LEAST ONE CHARACTER FOR THE ARGUMENT NAME.
!
!         2019/11: ONLY TRIGGER "NAMED" ARGUMENT IF THERE IS A SINGLE
!                  WORD TO LEFT OF EQUAL SIGN.
!
          DO 36311 II=2,NCTEMP-1
            IF(IMACAR(NMACAG)(II:II).EQ.'=')THEN
              IF(II.GT.1 .AND. IMACAR(NMACAG)(II-1:II-1).EQ.'\')THEN
                IMACAR(NMACAG)(II-1:NCTEMP-1)=IMACAR(NMACAG)(II:NCTEMP)
                IMACAR(NMACAG)(NCTEMP:NCTEMP)=' '
                NCTEMP=NCTEMP-1
                GO TO 36319
              ENDIF
              DO 36113 LL=1,II-1
                IF(IMACAR(NMACAG)(LL:LL).NE.' ')THEN
                  IFRST=LL
                  GO TO 36114
                ENDIF
36113         CONTINUE
              GO TO 36319
36114         CONTINUE
              DO 36115 LL=II-1,IFRST,-1
                IF(IMACAR(NMACAG)(LL:LL).NE.' ')THEN
                  ILAST=LL
                  GO TO 36116
                ENDIF
36115         CONTINUE
              GO TO 36319
36116         CONTINUE
              DO 36117 LL=IFRST,ILAST
                IF(IMACAR(NMACAG)(LL:LL).EQ.' ')THEN
                  GO TO 36319
                ENDIF
36117         CONTINUE
!
              IPOSEQ=II
              GO TO 36319
            ENDIF
36311     CONTINUE
36319     CONTINUE
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,18394)NMACAG,IMACAR(NMACAG)
18394       FORMAT('AT 36319: NMACAG,IMACAR(NMACAG) = ',I5,2X,A)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,18396)IFRST,ILAST,IPOSEQ
18396       FORMAT('IFRST,ILAST,IPOSEQ = ',3I6)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         NOW CHECK FOR OCCURENCE OF QUOTE.  NOTE THAT QUOTE IS ONLY
!         TREATED AS AN ARGUMENT DELIMITER IF IT IS THE FIRST CHARACTER
!         IN THE STRING OR THE FIRST CHARACTER AFTER THE EQUAL SIGN.  IN
!         ADDITION, IF A QUOTE DELIMITER IS FOUND, CHECK FOR A QUOTE AS
!         THE LAST CHARACTER.  IF NOT FOUND, THEN ADD IT.
!
          IF(IMACAR(NMACAG)(1:1).EQ.'"')THEN
            IPOSQU=1
          ELSEIF(IMACAR(NMACAG)(IPOSEQ+1:IPOSEQ+1).EQ.'"')THEN
            IPOSQU=IPOSEQ+1
          ENDIF
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,36394)IPOSEQ,IPOSQU,NCTEMP
36394       FORMAT('IPOSEQ,IPOSQU,NCTEMP = ',3I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         IF ENDING QUOTE NOT PRESENT, ADD IT.
!
          IF(IPOSQU.GT.0)THEN
            IF(IMACAR(NMACAG)(NCTEMP:NCTEMP).EQ.')')THEN
              IF(IMACAR(NMACAG)(NCTEMP-1:NCTEMP-1).NE.'"')THEN
                NCTEMP=NCTEMP+1
                IMACAR(NMACAG)(NCTEMP-1:NCTEMP)='")'
              ENDIF
            ELSE
              IF(IMACAR(NMACAG)(NCTEMP:NCTEMP).NE.'"')THEN
                NCTEMP=NCTEMP+1
                IMACAR(NMACAG)(NCTEMP:NCTEMP)='"'
              ENDIF
            ENDIF
          ENDIF
!
!         PROCESS STRING BASED ON WHETHER QUOTES/EQUAL SIGNS ARE
!         PRESENT.
!
          IF(IPOSEQ.EQ.0 .AND. IPOSQU.EQ.0)THEN
!
!           CASE WITH NO EQUAL AND NO QUOTE.  IN THIS CASE, WE HAVE
!           A POSITIONAL ARGUMENT AND DO NOT NEED TO PROCESS QUOTES.
!
!           IN THIS CASE, NO ADDITIONAL PROCESSING IS REQUIRED.
!
            IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
              WRITE(ICOUT,46351)
46351         FORMAT('NO EQUAL, NO QUOTE CASE: NOTHING DONE')
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ELSEIF(IPOSEQ.EQ.0 .AND. IPOSQU.GE.1)THEN
!
!           CASE WITH NO EQUAL BUT WITH QUOTE.  IN THIS CASE, WE HAVE
!           A POSITIONAL ARGUMENT AND WE NEED TO PROCESS QUOTES.
!
!           ONLY PROCESSING REQUIRED IS TO STRIP OFF LEADING/TRAILING
!           QUOTE IF THAT OPTION SET.
!
            IF(IQUOST.EQ.'ON')THEN
              IF(IMACAR(NMACAG)(NCTEMP:NCTEMP).EQ.')')THEN
                IMACAR(NMACAG)(1:NCTEMP-3)=IMACAR(NMACAG)(2:NCTEMP-2)
                NCTEMP=NCTEMP-2
                IMACAR(NMACAG)(NCTEMP:NCTEMP+2)=')  '
              ELSE
                IMACAR(NMACAG)(1:NCTEMP-2)=IMACAR(NMACAG)(2:NCTEMP-1)
                IMACAR(NMACAG)(NCTEMP+1:NCTEMP+2)='  '
                NCTEMP=NCTEMP-2
              ENDIF
            ENDIF
!
            IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
              WRITE(ICOUT,46361)
46361         FORMAT('NO EQUAL, QUOTE CASE:')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46363)NMACAG,NCTEMP,IMACAR(NMACAG)
46363         FORMAT('NMACAG,NCTEMP,IMACAR(NMACAG) = ',2I8,A100)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ELSEIF(IPOSEQ.GE.1 .AND. IPOSQU.EQ.0)THEN
!
!           CASE WITH EQUAL AND NO QUOTE.  IN THIS CASE, WE HAVE
!           A NAMED ARGUMENT AND DO NOT NEED TO PROCESS QUOTES.
!
!           IN THIS CASE, NEED TO MODIFY THE MACRO NAME TABLE AND
!           ALSO ADJUST THE ARGUMENT STRING.
!
            NMACLA=NMACLA+1
            IMACLL(NMACLA)=NMACAG
            IMACLA(NMACLA)(1:IPOSEQ-1)=IMACAR(NMACAG)(1:IPOSEQ-1)
            IMACNC(NMACLA)=IPOSEQ-1
            ICNT2=NCTEMP-IPOSEQ
            IF(ICNT2.GE.1)THEN
              IMACAR(NMACAG)(1:ICNT2)=IMACAR(NMACAG)(IPOSEQ+1:NCTEMP)
              IMACAR(NMACAG)(ICNT2+1:NCTEMP)=' '
              NCTEMP=ICNT2
            ELSE
              IMACAR(NMACAG)=' '
              NCTEMP=1
            ENDIF
!
            IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
              WRITE(ICOUT,46371)
46371         FORMAT('EQUAL, NO QUOTE CASE:')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46373)NMACAG,NCTEMP,IMACAR(NMACAG)
46373         FORMAT('NMACAG,NCTEMP,IMACAR(NMACAG) = ',2I8,2X,A100)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46375)NMACLA,IMACLL(NMACLA),IMACNC(NMACLA),   &
                                IMACLA(NMACLA)
46375         FORMAT('NMACLA,IMACLL(NMACLA),IMACNC(NMACLA),',  &
                     'IMACLA(NMACLA) = ',3I8,A8)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ELSEIF(IPOSEQ.GE.1 .AND. IPOSQU.GE.1)THEN
!
!           CASE WITH EQUAL AND QUOTE.  IN THIS CASE, WE HAVE
!           A NAMED ARGUMENT AND WE NEED TO PROCESS QUOTES.
!
!           TREAT CASE WHERE QUOTE IS FOR THE FULL STRING SEPARATELY
!           FROM CASE WHERE QUOTE IS FOR THE VALUE ONLY.
!
            IF(IPOSQU.EQ.1)THEN
              NMACLA=NMACLA+1
              IMACLL(NMACLA)=NMACAG
              ICNT=IPOSEQ-2
              IMACLA(NMACLA)(1:ICNT)=IMACAR(NMACAG)(2:IPOSEQ-1)
              IMACNC(NMACLA)=ICNT
              ICNT2=NCTEMP-IPOSEQ-1
              IF(ICNT2.GE.1)THEN
                IMACAR(NMACAG)(1:ICNT2)=   &
                  IMACAR(NMACAG)(IPOSEQ+1:NCTEMP-1)
                IMACAR(NMACAG)(ICNT2+1:MAXFNC)=' '
                NCTEMP=ICNT2
              ELSE
                IMACAR(NMACAG)='ZZZZEMPTY'
                NCTEMP=9
              ENDIF
            ELSE
              NMACLA=NMACLA+1
              IMACLL(NMACLA)=NMACAG
              ICNT=IPOSEQ-1
              IMACLA(NMACLA)(1:ICNT)=IMACAR(NMACAG)(1:IPOSEQ-1)
              IMACNC(NMACLA)=ICNT
              ICNT2=NCTEMP-IPOSEQ
              IF(ICNT2.GE.1)THEN
                IMACAR(NMACAG)(1:ICNT2)=IMACAR(NMACAG)(IPOSEQ+1:NCTEMP)
                IMACAR(NMACAG)(ICNT2+1:MAXFNC)=' '
                NCTEMP=ICNT2
              ELSE
                IMACAR(NMACAG)='ZZZZEMPTY'
                NCTEMP=9
              ENDIF
              IF(IQUOST.EQ.'ON' .AND. NCTEMP.GE.2)THEN
                IF(IMACAR(NMACAG)(NCTEMP:NCTEMP).EQ.')')THEN
                  IMACAR(NMACAG)(1:NCTEMP-3)=IMACAR(NMACAG)(2:NCTEMP-2)
                  NCTEMP=NCTEMP-2
                  IMACAR(NMACAG)(NCTEMP:NCTEMP+2)=')  '
                ELSE
                  IMACAR(NMACAG)(1:NCTEMP-2)=IMACAR(NMACAG)(2:NCTEMP-1)
                  NCTEMP=NCTEMP-2
                  IMACAR(NMACAG)(NCTEMP+1:NCTEMP+2)='  '
                ENDIF
                IF(NCTEMP.LE.0)THEN
                  IMACAR(NMACAG)='ZZZZEMPTY'
                  NCTEMP=9
                ENDIF
              ENDIF
            ENDIF
!
            IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
              WRITE(ICOUT,46381)
46381         FORMAT('EQUAL, QUOTE CASE:')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46373)NMACAG,NCTEMP,IMACAR(NMACAG)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46375)NMACLA,IMACLL(NMACLA),IMACNC(NMACLA),   &
                                IMACLA(NMACLA)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ENDIF
!
          IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,6373)NMACAG,NCTEMP,IMACAR(NMACAG)
 6373       FORMAT('NMACAG,NCTEMP,IMACAR(NMACAG) = ',2I5,2X,A100)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 6370   CONTINUE
 6379   CONTINUE
        IFILQU=IFILQZ
!
!       2018/04: CHECK FOR OPENING AND CLOSING PARENTHEIS AROUND FULL
!                ARGUMENT LIST (E.G., CALL (Y=Y,X=X)).
!
!                NOTE THAT THE LEFT PARENTHESIS MAY BE PART OF THE
!                ARGUMENT LABEL (IF GIVEN) OR THE ARGUMENT VALUE
!                (IF ARGUMENTS ENTERED BY POSITION).  THE RIGHT
!                PARENTHESIS WILL ALWAYS BE PART OF THE ARGUMENT
!                VALUE.
!
!                AS A FURTHER COMPLICATION, NEED TO CHECK IF THE
!                LEFT PARENTHESIS IS FOLLOWED BY A SPACE AND LIKEWISE
!                IF THE RIGHT PARENTHESIS IS PRECEEDED BY A SPACE.
!
        IF(NMACAG.GE.1)THEN
!
!         STEP 1: CHECK IF EITHER FIRST LABEL OR FIRST ARGUMENT IS
!                 STARTS WITH A PARENTHESIS.  CHECK LABEL FIRST.
!
          IFLAG=0
          IFLAGL=0
          IF(IMACLA(1)(1:1).EQ.'(')THEN
            IFLAG=1
            IFLAGL=1
            DO 16392 KK=1,7
              IMACLA(1)(KK:KK)=IMACLA(1)(KK+1:KK+1)
16392       CONTINUE
            IMACLA(1)(8:8)=' '
            IMACNC(1)=IMACNC(1)-1
!
!           NOW REMOVE ANY LEADING SPACES FROM LABEL
!
            DO 16394 KK=1,IMACNC(1)
              IF(IMACLA(1)(KK:KK).NE.' ')THEN
                IF(KK.GT.1)THEN
                  NCTEMP=IMACNC(1) - KK + 1
                  IMACLA(1)(1:NCTEMP)=IMACLA(1)(KK:IMACNC(1))
                  IMACLA(1)(NCTEMP+1:8)=' '
                  IMACNC(1)=NCTEMP
                ENDIF
                GO TO 16396
              ENDIF
16394       CONTINUE
16396       CONTINUE
          ELSEIF(IMACAR(1)(1:1).EQ.'(')THEN
            IFLAG=2
            IFLAGL=2
            DO 16393 KK=1,MAXFNC-1
              IMACAR(1)(KK:KK)=IMACAR(1)(KK+1:KK+1)
16393       CONTINUE
            IMACAR(1)(MAXFNC:MAXFNC)=' '
          ENDIF
!
          IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,46661)IFLAG
46661       FORMAT('IFLAG = ',I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         STEP 2: CHECK IF LAST ARGUMENT VALUE ENDS WITH RIGHT
!                 PARENTHESIS
!
!                 2021/03/15: ONLY DO THIS IF THERE WAS A BEGINNING
!                             LEFT PARETHESIS
!
          IF(IFLAGL.GT.0)THEN
            DO 16391 JJ=MAXFNC,1,-1
              IF(IMACAR(NMACAG)(JJ:JJ).EQ.')')THEN
                IMACAR(NMACAG)(JJ:JJ)=' '
              ENDIF
16391       CONTINUE
          ENDIF
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,46391)
46391       FORMAT('AFTER REMOVE LEADING/TRAILING PARENTHESIS')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46392)NMACLA,IMACLL(1),IMACNC(1),   &
                              IMACLA(1)
46392       FORMAT('NMACLA,IMACLL(1),IMACNC(1),IMACLA(1) = ',   &
                   3I8,2X,A8)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46375)NMACLA,IMACLL(NMACLA),   &
                              IMACNC(NMACCL),IMACLA(NMACLA)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ENDIF
!
 6399 CONTINUE
!
!     2021/03: CHECK FOR "ZZZZEMPTY" ON ANY ARGUMENTS AND
!              RESET THIS TO AN EMPTY ARGUMENT
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
        WRITE(ICOUT,49391)
49391   FORMAT('CHECK FOR ZZZZEMPTY')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NMACAG.GE.1)THEN
        DO 66381 II=1,NMACAG
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
            WRITE(ICOUT,6639)II,NCTEMP,IMACNC(II)
 6639       FORMAT('II,NCTEMP,IMACNC(II) = ',3I6)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IMACAR(II)(1:9).EQ.'ZZZZEMPTY')THEN
            IMACAR(II)=' '
          ENDIF
66381   CONTINUE
      ENDIF
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'MACR')THEN
        WRITE(ICOUT,6375)NMACLA,NMACAG
 6375   FORMAT('NMACLA,NMACAG = ',2I5)
        CALL DPWRST('XXX','BUG ')
        IF(NMACLA.GE.1)THEN
          DO 6376 JJ=1,NMACLA
            WRITE(ICOUT,6377)JJ,IMACLL(JJ),IMACNC(JJ),IMACLA(JJ)
 6377       FORMAT('JJ,IMACLL(JJ),IMACNC(JJ),IMACLA(JJ) = ',3I5,2X,A8)
            CALL DPWRST('XXX','BUG ')
 6376     CONTINUE
        ENDIF
!
        IF(NMACAG.GE.1)THEN
          DO 26386 JJ=1,NMACAG
            WRITE(ICOUT,26387)JJ,IMACAR(JJ)
26387       FORMAT('JJ,IMACAR(JJ) = ',I5,2X,A100)
            CALL DPWRST('XXX','BUG ')
26386     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************************
!               **  STEP 64--                                         **
!               **  THE CODE BELOW OPENS THE FILE OR SUBFILE. THE     **
!               **  CODE ALSO EQUIVALENCES THE FILES OR SUBFILES TO   **
!               **  THE FORTRAN LOGICAL UNIT NUMBER DESIGNATED        **
!               **  IN THE VARIABLE IMACNU (IN THE MAIN PROGRAM);     **
!               **  THE RECOMMENDED VALUE FOR IMACNU IS 34; IF THIS   **
!               **  IS INAPPROPRIATE, MAKE CHANGES IN INITHK AND DPSYOP.
!               **  THE CODE ALSO REWINDS THE FILE OR SUBFILE.        **
!               ********************************************************
!
      ISTEPN='64'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC IMACRO='EXEC'
!CCCC IOUNIT=IMACN2
      IOUNIT=IMACNU
!
      IREWIN='ON'
!CCCC MAY,1990.  SET ISTAT TO "OLD" FOR CALL CASE.  DO THIS SO WILL
!CCCC SEARCH THE SYSTEM DIRECTORY IF NOT FOUND AS REQUESTED. (ALAN)
      ISTAT='OLD'
      CALL DPOPFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      IF(IERRFI.EQ.'YES')THEN
        IERROR='YES'
        GO TO 9000
      ENDIF
      IMACRO='EXEC'
      IMACCS=ICURST
!
!     2014/02: SAVE NAME OF MACRO.
!
!CCCC ICRENA=IFILE
      IMANAM(IMALEV)=' '
      IMANAM(IMALEV)=IFILE
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,6411)
 6411    FORMAT('A MACRO FILE HAS JUST BEEN OPENED FOR EXECUTION')
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED    AUGUST 1994
!               **************************************************
!               **  STEP 65--                                   **
!               **  IF THE CALL COMMAND IS EXECUTING ONLY A     **
!               **  (NECESSARILY CONTIGUOUS) PART OF A FILE,    **
!               **  THEN SKIP OVER ANY NON-EXECUTING FRONT LINES**
!               **  OF THE FILE (THAT IS, READ THE FILE         **
!               **  FROM LINE 1 TO LINE (IMACL1-1)).            **
!               **************************************************
!
      ISTEPN='65'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMACLR=0
      IF(IMACL1.GE.2)THEN
         IMAX=IMACL1-1
         DO 6500 I=1,IMAX
!CCCC       CALL DPREFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,
!CCCC1      IA,NUMCHA,
!CCCC1      ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!CCCC       IF(IERROR.EQ.'YES')GO TO 9000
!CCCC THE FOLLOWING IS ALSO A PATCH   FOR   CALL <FILE> FOR ETC.
            IMACLR=IMACLR+1
            READ(IOUNIT,6511)ICJUNK
 6511       FORMAT(A1)
 6500    CONTINUE
      ENDIF
      GO TO 9000
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
!
      ICOMCL=ICOMC2
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MACR')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
 9011    FORMAT('***** AT THE END       OF DPMACR--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9012)IMACRO,IMACNU,IMACCS,IMACL1,IMACL2
 9012    FORMAT('IMACRO,IMACNU,IMACCS,IMACL1,IMACL2 = ',   &
         A4,I8,2X,A12,I8,I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9013)IBUGS2,IFOUND,IERROR,IOUNIT,NUMCHA
 9013    FORMAT('IBUGS2,IFOUND,IERROR,IOUNIT,NUMCHA = ',3(A4,2X),2I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9015)ICOM,ICOM2,IOFILE,IWIDTH,NUMARG,NMACAG
 9015    FORMAT('ICOM,ICOM2,IOFILE,IWIDTH,NUMARG,NMACAG = ',   &
                3(A4,2X),3I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9017)(IANSLC(I),I=1,MIN(120,IWIDTH))
 9017    FORMAT('IANSLC(.) = ',120A1)
         CALL DPWRST('XXX','BUG ')
!
         IF(NUMARG.GE.1)THEN
            DO 9019 I=1,NUMARG
               WRITE(ICOUT,9020)I,IHARG(I),IHARG2(I)
 9020          FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2(2X,A4))
               CALL DPWRST('XXX','BUG ')
 9019       CONTINUE
         ENDIF
!
         WRITE(ICOUT,9031)JP3,JP4,JP5,KMIN,KDEL,KMAX
 9031    FORMAT('JP2,JP3,JP4,KMIN,KDEL,KMAX = ',6I8)
         CALL DPWRST('XXX','BUG ')
!
         WRITE(ICOUT,9032)NUMNAM
 9032    FORMAT('NUMNAM = ',I8)
         CALL DPWRST('XXX','BUG ')
         IF(NUMNAM.GE.1)THEN
            DO 9035 I=1,NUMNAM
               WRITE(ICOUT,9036)I,IHNAME(I),IHNAM2(I),IUSE(I),   &
               IVALUE(I),VALUE(I)
 9036          FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),',   &
               'IVALUE(I),VALUE(I) = ',I8,2X,A4,2X,A4,2X,A4,I8,E15.7)
               CALL DPWRST('XXX','BUG ')
 9035       CONTINUE
         ENDIF
!
         WRITE(ICOUT,9043)(IA(I),I=1,MIN(120,NUMCHA))
 9043    FORMAT('(IA(I),I=1,IMAX) = ',120A1)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9052)IFILE
 9052    FORMAT('IFILE  = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9053)ISTAT,IFORM,IACCES,IPROT,ICURST
 9053    FORMAT('ISTAT,IFORM,IACCES,IPROT  = ',4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9058)IENDFI,IREWIN,IERRFI,ISUBN0
 9058    FORMAT('IENDFI,IREWIN,IERRFI,ISUBN0 = ',3(A4,2X),A12)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMACR
      SUBROUTINE DPMAHA(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--COMPUTE MANTEL-HAENSZEL TEST.
!     EXAMPLE--MANTEL-HAENSZEL TEST Y1 Y2
!            --MANTEL-HAENSZEL TEST Y1 Y2 GROUPID
!            --MANTEL-HAENSZEL TEST Y1 GROUPID1 Y2 GROUPID2
!     REFERENCE--FLEISS, LEVIN, AND PAIK (2003), "STATISTICAL
!                METHODS FOR RATES AND PROPORTIONS", THIRD
!                EDITION, WILEY, PP. 250-253.
!              --CONOVER (1999), "PRACTICAL NONPARAMETRIC
!                STATISTICS", THIRD EDITION, WILEY, PP. 192-195.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/5
!     ORIGINAL VERSION--MAY       2007.
!     UPDATED         --JANUARY   2011. USE DPPARS, DPPAR3
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASEQ
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN0
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
!
      PARAMETER (MAXSPN=20)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      REAL TEMP1(MAXOBV)
      REAL TEMP2(MAXOBV)
      REAL TEMP3(MAXOBV)
      REAL TEMP4(MAXOBV)
      REAL TEMP5(MAXOBV)
      REAL XIDTEM(MAXOBV)
      REAL XIDTE2(MAXOBV)
      REAL Y1(MAXOBV)
      REAL Y2(MAXOBV)
      REAL XGROU1(MAXOBV)
      REAL XGROU2(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB2),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB3),TEMP3(1))
      EQUIVALENCE (GARBAG(IGARB4),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB6),Y1(1))
      EQUIVALENCE (GARBAG(IGARB7),Y2(1))
      EQUIVALENCE (GARBAG(IGARB8),XGROU1(1))
      EQUIVALENCE (GARBAG(IGARB9),XGROU2(1))
      EQUIVALENCE (GARBAG(IGAR10),TEMP4(1))
      EQUIVALENCE (GARBAG(JGAR11),TEMP5(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='HA  '
      IFOUND='YES'
      IERROR='NO'
      ICASE='RAW '
      ICASEQ='UNKN'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MINN2=2
!
!
!               *********************************************
!               **  TREAT THE MANTEL-HAENSZEL TEST CASE    **
!               *********************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAHA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAHA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)MAXNXT,NUMARG
   56   FORMAT('MAXNXT,NUMARG = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 59 I=1,NUMARG
          WRITE(ICOUT,57)I,IHARG(I),IHARG2(I),ARG(I)
   57     FORMAT('I,IHARG(I),IHARG2(I),ARG(I) = ',I5,A4,A4,G15.7)
   59   CONTINUE
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAHA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='MANTEL-HAENSZEL TEST'
      MINNA=2
      MAXNA=100
      MINN2=2
      IFLAGE=19
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=2
      MAXNVA=4
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAHA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),PVAR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),PVAR(I) = ',I8,2X,A4,A4,2X,3I8,G15.7)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!     NOTE: THE NUMBER OF VARIABLES DETERMINES HOW THE
!           ARGUMENTS ARE DETERMINED:
!
!           NUMVAR = 2: BOTH VARIABLES ARE RESPONSE VARIABLES
!                       (Y1 AND Y2)
!           NUMVAR = 3: VARIABLES 1 AND 2 ARE THE RESPONSE
!                       VARIABLES (Y1 AND Y2) AND VARIABLE 3
!                       IS THE GROUP ID VARIABLE (XGROU1).
!           NUMVAR = 4: VARIABLE 1 = FIRST RESPONSE VARIABLE
!                       VARIABLE 2 = FIRST GROUP ID VARIABLE
!                       VARIABLE 3 = SECOND RESPONSE VARIABLE
!                       VARIABLE 2 = SECOND GROUP ID VARIABLE
!
      IF(NUMVAR.EQ.2)THEN
        ICASE='VARI'
        ICOL=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,Y2,TEMP1,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NS1=NLOCAL
        NS2=0
      ELSEIF(NUMVAR.EQ.3)THEN
        ICASE='VARI'
        ICOL=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,Y2,XGROU1,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NS1=NLOCAL
        NS2=0
      ELSEIF(NUMVAR.EQ.4)THEN
        ICOL=1
        CALL DPPAR7(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,XGROU1,Y2,XGROU2,NLOCAL,NLOCA2,NLOCA3,NLOCA4,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NS1=NLOCAL
        NS2=NLOCA3
      ENDIF
!
!               *****************************************
!               **  STEP 61--                         **
!               **  COMPUTE THE MANTEL-HAENSZEL TEST  **
!               ****************************************
!
      ISTEPN='61'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAHA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MAHA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6111)
 6111   FORMAT('***** FROM DPMAHA--READY TO COMPUTE TEST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6112)NS1
 6112   FORMAT('NS1 = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 6120 I=1,MIN(100,NS1)
          WRITE(ICOUT,6122)I,Y1(I),Y2(I),XGROU1(I),XGROU2(I)
 6122     FORMAT('I,Y1(I),Y2(I),XGROU1(I),XGROU2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 6120   CONTINUE
      ENDIF
!
      CALL DPMAH2(Y1,XGROU1,NS1,Y2,XGROU2,NS2,NUMVAR,   &
                  XIDTEM,XIDTE2,   &
                  TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                  ICASE,ICASAN,   &
                  ICAPSW,ICAPTY,IFORSW,   &
                  STATVA,CDF,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 62--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='62'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAHA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN0='MAHA'
!
      IH='STAT'
      IH2='VAL '
      VALUE0=STATVA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='CDF '
      VALUE0=CDF
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAHA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAHA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA2,IBUGA3
 9012   FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IERROR
 9016   FORMAT('IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAHA
      SUBROUTINE DPMAH2(Y1,X1,N1,Y2,X2,N2,NUMVAR,   &
                        XIDTEM,XIDTE2,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                        ICASE,ICASAN,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        STATVA,CDF,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM AN MANTEL-HAENSZEL TEST
!              THE INPUT CAN EITHER BE RAW DATA OR SUMMARY DATA:
!
!                  1) RAW DATA - EQUAL SAMPLE SIZES
!
!                     IN THIS CASE, THERE ARE THREE VARIABLES.
!                     THE FIRST TWO OF THESE VARIABLES SHOULD CONTAIN
!                     1'S (FOR SUCCESS) OR 0'S (FAILURES).  THE THIRD
!                     VARIABLE IS A GROUP-ID VARIABLE.
!
!                     IN THIS CASE, THE FIRST TASK IS TO
!                     CROSS TABULATE THE FIRST TWO VARIABLES
!                     INTO THE K TABLES.
!
!                     THIS CASE CAN HANDLE UNEQUAL SAMPLE SIZES
!                     BY SPECIFYING MISSING VALUES (USING THE
!                     SET STATISTIC MISSING VALUE COMMAND TO
!                     SPECIFY WHAT VALUE IS INTERPRETED AS THE
!                     MISSING VALUE).
!
!                  2) RAW DATA - UNEQUAL SAMPLE SIZES
!
!                     IN THIS CASE, THERE ARE FOUR VARIABLES.
!
!                     VARIABLE 1 = RESPONSE VARIABLE FOR SAMPLE 1
!                                  (SHOULD CONTAIN 1's TO DENOTE
!                                  SUCCESS AND 0's TO DENOTE
!                                  FAILURE).
!                     VARIABLE 2 = GROUP ID VARIABLE FOR SAMPLE 1.
!                     VARIABLE 3 = RESPONSE VARIABLE FOR SAMPLE 2
!                                  (SHOULD CONTAIN 1's TO DENOTE
!                                  SUCCESS AND 0's TO DENOTE
!                                  FAILURE).
!                     VARIABLE 4 = GROUP ID VARIABLE FOR SAMPLE 2.
!
!                     IN THIS CASE, THE FIRST TASK IS TO
!                     CROSS TABULATE THE FIRST TWO VARIABLES
!                     INTO THE K TABLES.
!
!                  3) SUMMARY DATA
!
!                     IN THIS CASE, THERE ARE TWO VARIABLES.
!                     THE VARIABLES CONTAIN A SERIES 2X2 TABLES.
!                     THAT IS, ROWS 1 AND 2 DEFINE TABLE 1,
!                     ROWS 3 AND 4 DEFINE TABLE 2, AND SO ON.
!
!              ULTIMATELY, WE SHOULD END UP WITH K TABLES WHERE
!              THE ITH TABLE LOOKS LIKE:
!
!                  X(I)         R(I)-X(I)             | R(I)
!                  C(I)-X(i)    N(I)-R(I)-C(I)+X(I)   | N(I)-R(I)
!                  ==============================================
!                  C(I)         N(I)-C(I)             | N(I)
!
!              THIS ROUTINE IMPLEMENTS THE MANTEL-HAENSZEL TEST
!              DOCUMENTED IN SECTION 5 CHAPTER 10 OF THE
!              FLEIS, LEVIN, AND PAIK BOOK CITED BELOW.  SEE THIS
!              REFERENCE FOR THE DETAILS OF THE METHOD.
!
!     EXAMPLE--MANTEL-HAENSZEL TEST Y1 Y2
!            --MANTEL-HAENSZEL TEST Y1 Y2 GROUPID
!            --MANTEL-HAENSZEL TEST Y1 GROUPID1 Y2 GROUPID2
!     REFERENCE--FLEISS, LEVIN, AND PAIK (2003), "STATISTICAL
!                METHODS FOR RATES AND PROPORTIONS", THIRD
!                EDITION, WILEY, PP. 250-253.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGYU LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/5
!     ORIGINAL VERSION--MAY       2007.
!     UPDATED         --FEBRUARY  2011. USE DPAUFI TO OPEN/CLOSE
!                                       AUXILLARY FILES
!     UPDATED         --FEBRUARY  2011. USE DPDTA1, DPDT5B TO PRINT
!                                       TABLES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 ICASE
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
!
      CHARACTER*6 ICONC1
      CHARACTER*6 ICONC2
      CHARACTER*6 ICONC3
      CHARACTER*6 ICONC4
      CHARACTER*6 ICONC5
      CHARACTER*6 ICONC6
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DSUM6
      DOUBLE PRECISION DSUM7
      DOUBLE PRECISION DSUM8
      DOUBLE PRECISION DSUM9
      DOUBLE PRECISION DTERM1
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
!
      PARAMETER (NUMALP=6)
      DIMENSION SIGVAL(NUMALP)
      DIMENSION ALOWCL(NUMALP)
      DIMENSION AUPPCL(NUMALP)
      DIMENSION ALOWC2(NUMALP)
      DIMENSION AUPPC2(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=4)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      IDIGI2(MAXRO2,NUMCLI)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXRO2,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXRO2,NUMCLI)
      INTEGER      NCOLSP(MAXLIN,NUMCLI)
      INTEGER      ROWSEP(MAXRO2)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXRO2,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA SIGVAL /0.50, 0.80, 0.90, 0.95, 0.975, 0.99/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='H2  '
      IERROR='NO'
      IWRITE='NO'
!
      ICONC1='ACCEPT'
      ICONC2='ACCEPT'
      ICONC3='ACCEPT'
      ICONC4='ACCEPT'
      ICONC5='ACCEPT'
      ICONC6='ACCEPT'
!
      NSUMM=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMAH2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE
   52   FORMAT('IBUGA3,ISUBRO,ICASE = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N1,N2,NUMVAR,PSTAMV
   55   FORMAT('N1,N2,NUMVAR = ',3I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N1
          WRITE(ICOUT,57)I,Y1(I),Y2(I),X1(I),X2(I)
   57     FORMAT('I,Y1(I),Y2(I),X1(I),X2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 0--                              **
!               **  IF ONLY TWO VARIABLES GIVEN, CREATE   **
!               **  THE GROUP-ID VARIABLE.  FOR THREE     **
!               **  VARIABLES, CHECK WHETHER WE HAVE RAW  **
!               **  DATA OR SUMMARY DATA.                 **
!               ********************************************
!
      ISTEPN='0'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAH2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMVAR.EQ.2)THEN
        ICASE='SUMM'
        NGROUP=0
        DO 100 I=1,N1
          ITEMP=MOD(I,2)
          IF(ITEMP.EQ.1)THEN
            NGROUP=NGROUP+1
          ENDIF
          X1(I)=REAL(NGROUP)
          X2(I)=REAL(NGROUP)
  100   CONTINUE
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAH2')THEN
          WRITE(ICOUT,151)NGROUP
  151     FORMAT('TWO-VARIABLE CASE: NGROUPS = ',I8)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ELSEIF(NUMVAR.EQ.3)THEN
        ICASE='SUMM'
        CALL DISTIN(X1,N1,IWRITE,XIDTEM,NGROUP,IBUGA3,IERROR)
        CALL SORT(XIDTEM,NGROUP,XIDTEM)
        DO 200 K=1,NGROUP
          HOLD=XIDTEM(K)
          L=0
          DO 210 I=1,N1
            IF(X1(I).EQ.HOLD)THEN
              L=L+1
            ENDIF
  210     CONTINUE
          IF(L.NE.2)THEN
            ICASE='RAW'
            GO TO 299
          ENDIF
  200   CONTINUE
!
      ELSEIF(NUMVAR.EQ.4)THEN
        ICASE='SUMM'
        CALL DISTIN(X1,N1,IWRITE,XIDTEM,NGROU1,IBUGA3,IERROR)
        CALL SORT(XIDTEM,NGROU2,XIDTEM)
        CALL DISTIN(X2,N2,IWRITE,XIDTE2,NGROU2,IBUGA3,IERROR)
        CALL SORT(XIDTE2,NGROU2,XIDTE2)
!
        IF(NGROU1.NE.NGROU2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,231)
  231     FORMAT('     THE NUMBER OF GROUPS IS DIFFERENT FOR ',   &
                 'SAMPLE ONE AND SAMPLE TWO.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,233)NGROU1
  233     FORMAT('     SAMPLE ONE HAS ',I8,' GROUPS.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,235)NGROU2
  235     FORMAT('     SAMPLE TWO HAS ',I8,' GROUPS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        EPS=0.01
        DO 240 K=1,NGROU1
          DIFF=ABS(XIDTEM(K) - XIDTE2(K))
          IF(DIFF.GT.EPS)THEN
             WRITE(ICOUT,999)
             CALL DPWRST('XXX','WRIT')
             WRITE(ICOUT,1101)
             CALL DPWRST('XXX','WRIT')
             WRITE(ICOUT,241)
  241        FORMAT('     THE GROUP IDs DIFFER FOR THE TWO ',   &
                    'SAMPLES.')
             CALL DPWRST('XXX','WRIT')
             IERROR='YES'
             GO TO 9000
          ENDIF
  240   CONTINUE
!
!       CHECK BOTH GROUP-ID VARIABLES.  CURRENTLY, BOTH SAMPLES
!       SHOULD BE THE SAME (I.E., EITHER BOTH SUMMARY DATA OR
!       BOTH RAW DATA, BUT NOT ONE RAW AND THE OTHER SUMMARY).
!
        DO 250 K=1,NGROU1
          HOLD=XIDTEM(K)
          L=0
          DO 260 I=1,N1
            IF(X1(I).EQ.HOLD)THEN
              L=L+1
            ENDIF
  260     CONTINUE
          IF(L.NE.2)THEN
            ICASE='RAW'
            GO TO 299
          ENDIF
  250   CONTINUE
!
        DO 270 K=1,NGROU2
          HOLD=XIDTE2(K)
          L=0
          DO 280 I=1,N1
            IF(X2(I).EQ.HOLD)THEN
              L=L+1
            ENDIF
  280     CONTINUE
          IF(L.NE.2)THEN
            ICASE='RAW'
            GO TO 299
          ENDIF
  270   CONTINUE
!
      ENDIF
!
  299 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  FOR RAW DATA CASE, CROSS TABULATE     **
!               **  THE DATA.  PUT SUMMARY DATA IN TEMP1  **
!               **  AND TEMP2.                            **
!               ********************************************
!
!
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAH2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,251)ICASAN,ICASE
  251   FORMAT('THREE-VARIABLE CASE: ICASAN, ICASE = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1101)
 1101   FORMAT('***** ERROR IN MANTEL-HAENSZEL TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1103)
 1103   FORMAT('      THE NUMBER OF OBSERVATIONS  IS < 2.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1105)N1
 1105   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ICASE.EQ.'SUMM')THEN
        DO 300 I=1,N1
          TEMP1(I)=Y1(I)
          TEMP2(I)=Y2(I)
  300   CONTINUE
        NSUMM=N1
        NGROUP=N1/2
!
!       CASE WHERE SAMPLES HAVE EQUAL SIZES FOR EACH GROUP
!
      ELSEIF(NUMVAR.EQ.3)THEN
!
        EPS=0.01
        ICNT2=0
        DO 400 K=1,NGROUP
          HOLD=XIDTEM(K)
          ICNT=0
          DO 410 I=1,N1
            DIFF=ABS(HOLD-X1(I))
            IF(DIFF.LE.EPS)THEN
              ICNT=ICNT+1
              TEMP3(ICNT)=Y1(I)
              TEMP4(ICNT)=Y2(I)
            ENDIF
  410     CONTINUE
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
            WRITE(ICOUT,401)K,ICNT,HOLD
  401       FORMAT('K,ICNT,HOLD = ',2I8,G15.7)
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          CALL ODDDIS(TEMP3,ICNT,PSTAMV,IWRITE,TEMP5,N11,N21,NOUT,   &
                      IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          CALL ODDDIS(TEMP4,ICNT,PSTAMV,IWRITE,TEMP5,N12,N22,NOUT,   &
                      IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
            WRITE(ICOUT,411)N11,N21,N12,N22
  411       FORMAT('N11,N21,N12,N22 = ',4I8)
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          ICNT2=ICNT2+1
          TEMP1(ICNT2)=REAL(N11)
          TEMP2(ICNT2)=REAL(N12)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
            WRITE(ICOUT,413)ICNT2,TEMP1(ICNT2),TEMP2(ICNT2)
  413       FORMAT('ICNT2,TEMP1(ICNT2),TEMP2(ICNT2) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          ICNT2=ICNT2+1
          TEMP1(ICNT2)=REAL(N21)
          TEMP2(ICNT2)=REAL(N22)
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
            WRITE(ICOUT,413)ICNT2,TEMP1(ICNT2),TEMP2(ICNT2)
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
  400   CONTINUE
        NSUMM=ICNT2
!
      ELSEIF(NUMVAR.EQ.4)THEN
!
        EPS=0.01
        ICNT2=0
        DO 500 K=1,NGROU1
          HOLD=XIDTEM(K)
          ICNT=0
          DO 510 I=1,N1
            DIFF=ABS(HOLD-X1(I))
            IF(DIFF.LE.EPS)THEN
              ICNT=ICNT+1
              TEMP3(ICNT)=Y1(I)
            ENDIF
  510     CONTINUE
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
            WRITE(ICOUT,501)K,ICNT,HOLD
  501       FORMAT('K,ICNT,HOLD = ',2I8,G15.7)
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          CALL ODDDIS(TEMP3,ICNT,PSTAMV,IWRITE,TEMP5,N11,N21,NOUT,   &
                      IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          ICNT2=ICNT2+1
          TEMP1(ICNT2)=REAL(N11)
          ICNT2=ICNT2+1
          TEMP1(ICNT2)=REAL(N21)
  500   CONTINUE
!
        ICNT2=0
        DO 550 K=1,NGROU2
          HOLD=XIDTE2(K)
          ICNT=0
          DO 560 I=1,N2
            DIFF=ABS(HOLD-X2(I))
            IF(DIFF.LE.EPS)THEN
              ICNT=ICNT+1
              TEMP4(ICNT)=Y2(I)
            ENDIF
  560     CONTINUE
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
            WRITE(ICOUT,561)K,ICNT,HOLD
  561       FORMAT('K,ICNT,HOLD = ',2I8,G15.7)
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          CALL ODDDIS(TEMP4,ICNT,PSTAMV,IWRITE,TEMP5,N12,N22,NOUT,   &
                      IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          ICNT2=ICNT2+1
          TEMP2(ICNT2)=REAL(N12)
          ICNT2=ICNT2+1
          TEMP2(ICNT2)=REAL(N22)
  550   CONTINUE
!
        NSUMM=ICNT2
        NGROUP=NGROU1
!
      ENDIF
!
!               ********************************************
!               **  STEP 14--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               **  ALL TABLE ENTRIES SHOULD BE           **
!               **  NON-NEGATIVE INTEGERS.  NEGATIVE      **
!               **  VALUES WILL BE FLAGGED AS ERRORS      **
!               **  WHILE NON-INTEGER VALUES WILL BE      **
!               **  ROUNDED TO NEAREST INTEGER.           **
!               ********************************************
!
      ISTEPN='14'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAH2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
!
      NTEMP=MOD(NSUMM,2)
      IF(NTEMP.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1411)
 1411   FORMAT('      FOR THE SUMMARY DATA, THE NUMBER OF ROWS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1413)
 1413   FORMAT('      SHOULD BE EVEN;  SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1415)NSUMM
 1415   FORMAT('      THE NUMBER OF ROWS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 1420 I=1,NSUMM
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
          WRITE(ICOUT,1401)I,TEMP1(I),TEMP2(I)
 1401     FORMAT('I,TEMP1(I),TEMP2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        ITEMP=INT(TEMP1(I)+0.5)
        IF(ITEMP.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1421)
 1421     FORMAT('      FOR THE SUMMARY DATA, THE DATA VALUES ',   &
                'DENOTE COUNTS.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1423)I
 1423     FORMAT('      A NEGATIVE COUNT WAS ENCOUNTERED FOR ',   &
                 'RESPONSE VARIABLE ONE FOR ROW ',I8)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        TEMP1(I)=REAL(ITEMP)
!
        ITEMP=INT(TEMP2(I)+0.5)
        IF(ITEMP.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1431)
 1431     FORMAT('      FOR THE SUMMARY DATA CASE, THE DATA VALUES ',   &
                'DENOTE COUNTS.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1433)I
 1433     FORMAT('      A NEGATIVE COUNT WAS ENCOUNTERED FOR ',   &
                 'RESPONSE VARIABLE TWO FOR ROW ',I8)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        TEMP2(I)=REAL(ITEMP)
 1420 CONTINUE
!
!               ********************************************
!               **  STEP 20--                             **
!               **  GENERATE THE LOG ODDS RATIO TABLE     **
!               **  AND COMPUTE THE CHI-SQUARE ANALYSIS   **
!               **  OF THE LOG ODDS RATIO.                **
!               ********************************************
!
      ISTEPN='20'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAH2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     FLEISS AND HIS CO-AUTHORS DEFINE THE TABLE:
!
!                 |  SAMPLE 1     SAMPLE 2      |
!        =====================================================
!        PRESENT  |  X(i)         m(i) - X(i)   | m(i)
!        ABSENT   |  N(i1)-X(i)   X(i) - l(i)   | N(i.) - m(i)
!        =================================================
!                 |  N(i1)        N(i2)         | N(i.)
!
!     IN OUR CODING:
!
!         N11 = X(i)
!         N21 = N(i1)
!         N12 = m(i) - X(i)
!         N22 = X(i) - L(i)
!
!     FLEISS THEN DENOTES
!
!         R(i) = X(i)*(X(i) - l(i))/N(i.)
!              = N11*N22/NTOT
!         S(i) = (m(i) - X(i))*(N(i1) - X(i))/N(i.)
!              = N12*N21/NTOT
!         P(i) = (X(i) + X(i) - l(i))/N(i.)
!              = (N11 + N22)/NTOT
!         Q(i) = (m(i) - X(i) + N(i1) - X(i))/N(i.)
!              = 1 - P(i)
!              = (N12 +  N21)/NTOT
!
!     R, S, P, AND Q ARE THE SUMS OVER ALL GROUPS FOR EACH
!     OF THESE.
!
!     THEN THE MANTEL-HAENSZEL ESTIMATE IS:
!
!        COMMON ODDS RATIO = OMEGAHAT(MH)
!                          = R/S
!
!     AND THE VARIANCE OF THE LOG OF THE COMMON ODDS RATIO IS
!
!         VAR(LN(OMEGAHAT(MH))) = 0.5*{SUM[P(i)*R(i)]/R**2 +
!                                 SUM[P(i)*S(i) + Q(i)*R(i)]/R*S +
!                                 SUM[Q(i)*S(i)]/S**2}
!
!         WHERE ALL SUMMATIONS ARE OVER THE GROUPS.
!
!     THE MANTEL-HAENSZEL CHI-SQUARE TEST STATISTIC IS THEN
!
!         {|SUM[i=1 to NGROUP][(N(i1)*N(i2)/N(i.))*
!                              (P(i1)-P(i2)| - 0.5}**2/
!         SUM[i=1 to NGROUP][N(i1)*N(i2)*pbar(i)*qbar(i)/(N(i.)]
!
!     WHERE
!
!         P(i1) = N11/Ni1
!         P(i2) = N12/Ni2
!
!         pbar(i) = (N(i1)*P(i1) + N(i2)*P(i2))/NTOT
!         qbar(i) = 1 - pbar(i)
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=1
      IFLAG3=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NTEMP=2
      MAXGRP=10000
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
      DSUM6=0.0D0
      DSUM7=0.0D0
      DSUM8=0.0D0
      DSUM9=0.0D0
!
      DO 2010 K=1,NGROUP
        ISTRT=(K-1)*2+1
!
        AN11=TEMP1(ISTRT)
        AN21=TEMP1(ISTRT+1)
        AN12=TEMP2(ISTRT)
        AN22=TEMP2(ISTRT+1)
        ANTOT=AN11 + AN21 + AN12 + AN22
        RI=AN11*AN22/ANTOT
        SI=AN12*AN21/ANTOT
        PI=(AN11 + AN22)/ANTOT
        QI=1.0 - PI
        AN1=AN11+AN21
        AN2=AN12+AN22
        PI1=AN11/AN1
        PI2=AN12/AN2
        PIBAR=(AN1*PI1 + AN2*PI2)/ANTOT
!
        DSUM1=DSUM1 + DBLE(RI)
        DSUM2=DSUM2 + DBLE(SI)
        DSUM3=DSUM3 + DBLE(PI)
        DSUM4=DSUM4 + DBLE(QI)
        DSUM5=DSUM5 + DBLE(PI*RI)
        DSUM6=DSUM6 + DBLE(PI*SI + QI*RI)
        DSUM7=DSUM7 + DBLE(QI*SI)
        DSUM8=DSUM8 + DBLE(PI1-PI2)*DBLE(AN1)*DBLE(AN2)/DBLE(ANTOT)
        DSUM9=DSUM9 + DBLE(PIBAR)*(1.0D0-DBLE(PIBAR))*DBLE(AN1)*   &
                      DBLE(AN2)/(DBLE(ANTOT)-1.0D0)
!
        CALL ODDRAT(TEMP1(ISTRT),NTEMP,TEMP2(ISTRT),NTEMP,PSTAMV,   &
                    IWRITE,TEMP5,STAT,   &
                    IBUGA3,IERROR)
        TEMP3(K)=STAT
        CALL LOGIT(TEMP1(ISTRT),NTEMP,TEMP2(ISTRT),NTEMP,PSTAMV,   &
                    IWRITE,TEMP5,STAT,   &
                    IBUGA3,IERROR)
        TEMP3(MAXGRP+K)=STAT
        CALL LOGISE(TEMP1(ISTRT),NTEMP,TEMP2(ISTRT),NTEMP,PSTAMV,   &
                    IWRITE,TEMP5,STAT,   &
                    IBUGA3,IERROR)
        TEMP3(2*MAXGRP+K)=STAT
        TEMP3(3*MAXGRP+K)=RI
        TEMP3(4*MAXGRP+K)=SI
        TEMP3(5*MAXGRP+K)=PI
        TEMP3(6*MAXGRP+K)=QI
!
        WRITE(IOUNI2,2004)RI,SI,PI,QI,PIBAR
 2004   FORMAT(5E15.7)
!
 2010 CONTINUE
      R=REAL(DSUM1)
      S=REAL(DSUM2)
      P=REAL(DSUM3)
      Q=REAL(DSUM4)
!
      ODDRCO=REAL(DSUM1/DSUM2)
      DTERM1=(DSUM5/DSUM1**2) + (DSUM6/(DSUM1*DSUM2)) +   &
             (DSUM7/DSUM2**2)
      DTERM1=DTERM1/2.0D0
      ODDRSE=SQRT(DTERM1)
!
      DTERM1=(DABS(DSUM8) - 0.5D0)**2/DSUM9
      STATVA=REAL(DTERM1)
!
      IOP='CLOS'
      IFLAG1=0
      IFLAG2=1
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     PRINT SUMMARY OF LOG(ODDS RATIO) TABLE
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE(1:26)='Summary of Log(Odds Ratio)'
      NCTITL=26
      ITITL9=' '
      NCTIT9=0
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      ITITL2(2,1)=' '
      NCTIT2(2,1)=0
      ITITL2(3,1)='Group'
      NCTIT2(3,1)=5
!
      ITITL2(1,2)=' | '
      NCTIT2(1,2)=3
      ITITL2(2,2)=' | '
      NCTIT2(2,2)=3
      ITITL2(3,2)=' | '
      NCTIT2(3,2)=3
!
      ITITL2(1,3)=' '
      NCTIT2(1,3)=0
      ITITL2(2,3)='Odds Ratio'
      NCTIT2(2,3)=10
      ITITL2(3,3)='O(i)'
      NCTIT2(3,3)=4
!
      ITITL2(1,4)='Log of'
      NCTIT2(1,4)=6
      ITITL2(2,4)='Odds Ratio'
      NCTIT2(2,4)=10
      ITITL2(3,4)='L(i)'
      NCTIT2(3,4)=4
!
      ITITL2(1,5)='Standard'
      NCTIT2(1,5)=8
      ITITL2(2,5)='Error'
      NCTIT2(2,5)=5
      ITITL2(3,5)='SE(L(i))'
      NCTIT2(3,5)=8
!
      NMAX=0
      NUMCOL=5
      DO 4010 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        ITYPCO(I)='NUME'
        NTOT(I)=15
        NCOLSP(1,I)=1
        NCOLSP(2,I)=1
        NCOLSP(3,I)=1
        IF(I.EQ.2)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=3
        ENDIF
        NMAX=NMAX+NTOT(I)
 4010 CONTINUE
      IWHTML(1)=125
      IWHTML(2)=50
      IWHTML(3)=150
      IWHTML(4)=150
      IWHTML(5)=150
      IINC=1600
      IINC2=200
      IINC3=1000
      IWRTF(1)=IINC3
      IWRTF(2)=IWRTF(1)+IINC2
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      DO 4081 J=1,NGROUP
        DO 4083 I=1,NUMCOL
          IVALUE(J,I)=' '
          NCVALU(J,I)=0
          AMAT(J,I)=0.0
          IF(I.EQ.1)THEN
            IDIGIT(I)=0
          ELSE
            IDIGIT(I)=NUMDIG
          ENDIF
 4083   CONTINUE
        IVALUE(J,2)=' | '
        NCVALU(J,2)=3
        IJUNK=INT(XIDTEM(J)+0.5)
        AMAT(J,1)=REAL(IJUNK)
        AMAT(J,3)=TEMP3(J)
        AMAT(J,4)=TEMP3(MAXGRP+J)
        AMAT(J,5)=TEMP3(2*MAXGRP+J)
 4081 CONTINUE
!
      ICNT=NGROUP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXRO2,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IDFAS=1
      CALL CHSCDF(STATVA,IDFAS,CDFASS)
      CDF=CDFASS
!
      ITITLE='Mantel-Haenszel Test'
      NCTITL=20
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=REAL(NGROUP)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='M-H Estimate of Combined Log(Odds Ratio):'
      NCTEXT(ICNT)=41
      AVALUE(ICNT)=ODDRCO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='M-H Standard Error of Combined Log(Odds Ratio):'
      NCTEXT(ICNT)=47
      AVALUE(ICNT)=ODDRSE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Mantel-Haenszel Test Statistic (Association):'
      NCTEXT(ICNT)=45
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Chi-Square Degrees of Freedom:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=REAL(IDFAS)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Chi-Square CDF of Test Statistic:'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=CDF
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 4090 I=1,NUMROW
        NTOT(I)=15
 4090 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                  NCTEXT,AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               ************************************************
!               **  STEP 22--                                 **
!               **  PRINT TABLE FOR OVERALL ASSOCIATION TEST  **
!               ************************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ODC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICONC1='REJECT'
      ICONC2='REJECT'
      ICONC3='REJECT'
      ICONC4='REJECT'
      ICONC5='REJECT'
      ICONC6='REJECT'
!
      CALL CHSPPF(SIGVAL(1),IDFAS,CV1)
      CALL CHSPPF(SIGVAL(2),IDFAS,CV2)
      CALL CHSPPF(SIGVAL(3),IDFAS,CV3)
      CALL CHSPPF(SIGVAL(4),IDFAS,CV4)
      CALL CHSPPF(SIGVAL(5),IDFAS,CV5)
      CALL CHSPPF(SIGVAL(6),IDFAS,CV6)
!
      IF(0.000.LE.CDFASS.AND.CDFASS.LE.SIGVAL(1))ICONC1='ACCEPT'
      IF(0.000.LE.CDFASS.AND.CDFASS.LE.SIGVAL(2))ICONC2='ACCEPT'
      IF(0.000.LE.CDFASS.AND.CDFASS.LE.SIGVAL(3))ICONC3='ACCEPT'
      IF(0.000.LE.CDFASS.AND.CDFASS.LE.SIGVAL(4))ICONC4='ACCEPT'
      IF(0.000.LE.CDFASS.AND.CDFASS.LE.SIGVAL(5))ICONC5='ACCEPT'
      IF(0.000.LE.CDFASS.AND.CDFASS.LE.SIGVAL(6))ICONC6='ACCEPT'
!
      ITITLE(1:39)='Mantel-Haenszel Test for Overall Degree'
      ITITLE(40:54)=' of Association'
      NCTITL=54
      ITITL9=' '
      NCTIT9=0
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      ITITL2(2,1)='Null'
      NCTIT2(2,1)=4
      ITITL2(3,1)='Hypothesis'
      NCTIT2(3,1)=10
!
      ITITL2(1,2)=' '
      NCTIT2(1,2)=0
      ITITL2(2,2)='Confidence'
      NCTIT2(2,2)=10
      ITITL2(3,2)='Level'
      NCTIT2(3,2)=5
!
      ITITL2(1,3)=' '
      NCTIT2(1,3)=0
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value'
      NCTIT2(3,3)=5
!
      ITITL2(1,4)='Null Hypothesis'
      NCTIT2(1,4)=15
      ITITL2(2,4)='Acceptance'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Interval'
      NCTIT2(3,4)=8
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 4110 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        IF(I.EQ.3)THEN
          ITYPCO(I)='NUME'
        ELSE
          ITYPCO(I)='ALPH'
        ENDIF
        IF(I.EQ.2)THEN
          IDIGIT(I)=1
        ELSEIF(I.EQ.3)THEN
          IDIGIT(I)=2
        ELSE
          IDIGIT(I)=NUMDIG
        ENDIF
        DO 4111 J=1,NUMALP
          NCVALU(J,I)=0
 4111   CONTINUE
 4110 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=125
      IWHTML(3)=125
      IWHTML(4)=150
      IWHTML(5)=150
      IINC=1600
      IINC2=1400
      IINC3=2200
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC2
      IWRTF(4)=IWRTF(3)+IINC3
      IWRTF(5)=IWRTF(4)+IINC2
!
      IVALUE(1,2)='50.0%'
      NCVALU(1,2)=5
      AMAT(1,3)=CV1
      IVALUE(1,4)='(0,0.500)'
      NCVALU(1,4)=9
      IVALUE(1,5)(1:6)=ICONC1(1:6)
      NCVALU(1,5)=6
!
      IVALUE(2,2)='80.0%'
      NCVALU(2,2)=5
      AMAT(2,3)=CV2
      IVALUE(2,4)='(0,0.800)'
      NCVALU(2,4)=9
      IVALUE(2,5)(1:6)=ICONC2(1:6)
      NCVALU(2,5)=6
!
      IVALUE(3,2)='90.0%'
      NCVALU(3,2)=5
      AMAT(3,3)=CV3
      IVALUE(3,4)='(0,0.900)'
      NCVALU(3,4)=9
      IVALUE(3,5)(1:6)=ICONC3(1:6)
      NCVALU(3,5)=6
!
      IVALUE(4,2)='95.0%'
      NCVALU(4,2)=5
      AMAT(4,3)=CV4
      IVALUE(4,4)='(0,0.950)'
      NCVALU(4,4)=9
      IVALUE(4,5)(1:6)=ICONC4(1:6)
      NCVALU(4,5)=6
!
      IVALUE(5,2)='97.5%'
      NCVALU(5,2)=5
      AMAT(5,3)=CV5
      IVALUE(5,4)='(0,0.975)'
      NCVALU(5,4)=9
      IVALUE(5,5)(1:6)=ICONC5(1:6)
      NCVALU(5,5)=6
!
      IVALUE(6,2)='99.0%'
      NCVALU(6,2)=5
      AMAT(6,3)=CV6
      IVALUE(6,4)='(0,0.990)'
      NCVALU(6,4)=9
      IVALUE(6,5)(1:6)=ICONC6(1:6)
      NCVALU(6,5)=6
!
      DO 4120 J=1,NUMALP
        AMAT(J,1)=0.0
        AMAT(J,2)=0.0
        AMAT(J,4)=0.0
        AMAT(J,5)=0.0
        IVALUE(J,1)='No Association'
        NCVALU(J,1)=14
 4120 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
!
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXRO2,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               ************************************************
!               **  STEP 24--                                 **
!               **  PRINT TABLE FOR CONFIDENCE INTERVAL FOR   **
!               **  COMMON LOG(ODDS RATIO)                    **
!               ************************************************
!
      ISTEPN='24'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAH2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 4270 I=1,NUMALP
        ALPHA=(1.0 - SIGVAL(I))/2.0
        CALL NORPPF(ALPHA,CV)
        ALOWCL(I)=ODDRCO + CV*ODDRSE
        AUPPCL(I)=ODDRCO - CV*ODDRSE
        ALOWC2(I)=EXP(ALOWCL(I))
        AUPPC2(I)=EXP(AUPPCL(I))
        WRITE(IOUNI1,4271)ALPHA,ALOWCL(I),AUPPCL(I),   &
                          ALOWC2(I),AUPPC2(I)
 4271   FORMAT(F10.5,1X,4E15.7)
 4270 CONTINUE
!
      IOP='CLOS'
      IFLAG1=1
      IFLAG2=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      ITITLE(1:33)='Large Sample Confidence Interval '
      ITITLE(34:52)='for Log(Odds Ratio)'
      NCTITL=52
      ITITL9=' '
      NCTIT9=0
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      NCOLSP(1,1)=1
      ITITL2(2,1)=' '
      NCTIT2(2,1)=0
      NCOLSP(2,1)=1
      ITITL2(3,1)='Confidence'
      NCTIT2(3,1)=10
      NCOLSP(3,1)=1
      ITITL2(4,1)='Value (%)'
      NCTIT2(4,1)=9
      NCOLSP(4,1)=1
!
      ITITL2(1,2)='Log(Odds Ratio)'
      NCTIT2(1,2)=15
      NCOLSP(1,2)=2
      ITITL2(2,2)='(               )'
      WRITE(ITITL2(2,2)(2:16),'(G15.7)')ODDRCO
      NCTIT2(2,2)=17
      NCOLSP(2,2)=2
      ITITL2(3,2)='Lower'
      NCTIT2(3,2)=5
      NCOLSP(3,2)=1
      ITITL2(4,2)='Limit'
      NCTIT2(4,2)=5
      NCOLSP(4,2)=1
!
      ITITL2(1,3)=' '
      NCTIT2(1,3)=0
      NCOLSP(1,3)=0
      ITITL2(2,3)=' '
      NCTIT2(2,3)=0
      NCOLSP(2,3)=0
      ITITL2(3,3)='Upper'
      NCTIT2(3,3)=5
      NCOLSP(3,3)=1
      ITITL2(4,3)='Limit'
      NCTIT2(4,3)=5
      NCOLSP(4,3)=1
!
      ITITL2(1,4)='Odds Ratio'
      NCTIT2(1,4)=10
      NCOLSP(1,4)=2
      ITITL2(2,4)='(               )'
      WRITE(ITITL2(2,4)(2:16),'(G15.7)')EXP(ODDRCO)
      NCTIT2(2,4)=17
      NCOLSP(2,4)=2
      ITITL2(3,4)='Lower'
      NCTIT2(3,4)=5
      NCOLSP(3,4)=1
      ITITL2(4,4)='Limit'
      NCTIT2(4,4)=5
      NCOLSP(4,4)=1
!
      ITITL2(1,5)=' '
      NCTIT2(1,5)=0
      NCOLSP(1,5)=0
      ITITL2(2,5)=' '
      NCTIT2(2,5)=0
      NCOLSP(2,5)=0
      ITITL2(3,5)='Upper'
      NCTIT2(3,5)=5
      NCOLSP(3,5)=1
      ITITL2(4,5)='Limit'
      NCTIT2(4,5)=5
      NCOLSP(4,5)=1
!
      NMAX=0
      DO 4410 I=1,NUMCLI
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        DO 4420 J=1,MAXROW
          IF(I.EQ.1)THEN
            IDIGI2(J,I)=2
          ELSE
            IDIGI2(J,I)=NUMDIG
          ENDIF
 4420   CONTINUE
        IWHTML(1)=75
        IWHTML(2)=150
        IWHTML(3)=150
        IWHTML(4)=150
        IWHTML(5)=150
        IINC=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
        IWRTF(5)=IWRTF(4)+IINC
        IFRST=.TRUE.
        ILAST=.TRUE.
!
        DO 4430 J=1,NUMALP
          ATEMP=100.0*SIGVAL(J)
          AMAT(J,1)=ATEMP
          AMAT(J,2)=ALOWCL(J)
          AMAT(J,3)=AUPPCL(J)
          AMAT(J,4)=ALOWC2(J)
          AMAT(J,5)=AUPPC2(J)
          IVALUE(J,1)=' '
          IVALUE(J,2)=' '
          IVALUE(J,3)=' '
          IVALUE(J,4)=' '
          IVALUE(J,5)=' '
          NCVALU(J,1)=0
          NCVALU(J,2)=0
          NCVALU(J,3)=0
          NCVALU(J,4)=0
          NCVALU(J,5)=0
          ROWSEP(J)=0
 4430   CONTINUE
!
 4410 CONTINUE
!
      NUMLIN=4
      NUMCOL=5
      ICNT=NUMALP
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDT5B(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXRO2,ICNT,   &
                  IDIGI2,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  NCOLSP,ROWSEP,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAH2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAH2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)AN11,AN21,AN12,AN22
 9013   FORMAT('AN11,AN21,AN12,AN22=',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)AN1,AN2
 9015   FORMAT('AN1,AN2=',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)N11,N21,N12,N22
 9017   FORMAT('N11,N21,N12,N22=',4I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAH2
      SUBROUTINE DPMAND(ICAPSW,IFORSW,ISEED,IBOOSS,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,   &
                        IFOUND,IERROR)
!
!     PURPOSE--COMPUTE CONSENSUS MEANS USING FOLLOWING APPROACHES:
!              1) MANDEL-PAULE
!              2) MODIFIED MANDEL-PAULE
!              3) VANGEL-RUKHIN MAXIMUM LIKELIHOOD
!              4) DERSIMONIAN AND LARID
!              5) GRAYBILL-DEAL
!              6) FAIRWEATHER
!              7) GENERALIZED CONFIDENCE INTERVALS
!              8) GRAND MEAN
!              9) MEAN OF MEANS
!             10) BOB
!             11) SCHILLER-EBERHARDT
!             12) BAYESIAN CONSENSUS PROCEDURE OF GUTHRIE AND HAGWOOD
!             13) MEDIAN OF MEANS
!             14) HUBER MEAN OF MEANS
!             15) LINEAR POOL
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!                 CODE FOR MANDEL-PAULE, VANGEL-RUKHIN
!                 PROVIDED BY MARK VANGEL, BOB BASED ON MACROS
!                 PROVIDED BY STEFAN LEIGH.  GENERALIZED CONFIDENCE
!                 INTERVAL CODE PROVIDED BY JACK WANG.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2000/10
!     ORIGINAL VERSION--OCTOBER   2000.
!     UPDATED         --AUGUST    2001. IWRITE VARIABLE
!     UPDATED         --OCTOBER   2002. SUPPORT FOR "CAPTURE HTML"
!                                       (ADD ICAPSW TO CALL LIST)
!     UPDATED         --MARCH     2006. ADD IFORSW TO CALL LIST
!                                       DPMAN2 COMPLETELY REWRITTEN:
!                                       1) CODE MODULARIZED INTO
!                                          DISTINCT SUBROUTINES
!                                       2) FORMATTING REVISED FOR
!                                          CONSISTENCY AND CLARITY
!                                       3) NEW METHODS ADDED
!     UPDATED         --FEBRUARY  2010. USE DPPARS
!     UPDATED         --JUNE      2010. FIVE METHODS CAN USE LABS WITH
!                                       ZERO STANDARD DEVIATION
!     UPDATED         --OCTOBER   2011. FOR SUMMARY CASE, ADD OPTIONAL
!                                       LABID COLUMN
!     UPDATED         --JUNE      2012. ADD ISEED AND IBOOSS (FOR
!                                       BOOTSTRAP COMPUTATIONS)
!     UPDATED         --OCTOBER   2014. FOR SUMMARY DATA, OPTION TO
!                                       INPUT MEAN AND UNCERTAINTY
!                                       (I.E., S/SQRT(N) INSTEAD OF
!                                       S AND N).  IN SOME CASES, DATA
!                                       IS AVAILABLE IN THIS FORM.
!     UPDATED         --MARCH     2017. MEDIAN OF MEANS
!     UPDATED         --MARCH     2017. HUBER MEAN OF MEANS
!     UPDATED         --JULY      2019. TWEAK SCRATCH STORAGE
!     UPDATED         --APRIL     2023. LINEAR POOL METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES----------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASEQ
!
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASE
!
      DOUBLE PRECISION YDL
      DOUBLE PRECISION DLOWD2
      DOUBLE PRECISION DHIGD2
      DOUBLE PRECISION DLOWD3
      DOUBLE PRECISION DHIGD3
      DOUBLE PRECISION DLOWD4
      DOUBLE PRECISION DHIGD4
      DOUBLE PRECISION DLOWD5
      DOUBLE PRECISION DHIGD5
      DOUBLE PRECISION DLOWD6
      DOUBLE PRECISION DHIGD6
      DOUBLE PRECISION SEBOK1
      DOUBLE PRECISION SEBOK2
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Y3(MAXOBV)
!
      INTEGER IZ(MAXOBV)
      INTEGER IZ2(MAXOBV)
      INTEGER ITEMP1(MAXOBV)
!
      DOUBLE PRECISION Z2(MAXOBV)
      DOUBLE PRECISION Z3(MAXOBV)
      DOUBLE PRECISION Z4(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
!
      DIMENSION Z1(MAXOBV)
      DIMENSION Z6(MAXOBV)
      DIMENSION Z7(MAXOBV)
      DIMENSION Z8(MAXOBV)
      DIMENSION Z9(MAXOBV)
      DIMENSION PLABID(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XPLOTZ(MAXOBV)
      DIMENSION YPLOTZ(MAXOBV)
      DIMENSION WTS(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),Y3(1))
      EQUIVALENCE (GARBAG(IGARB4),Z1(1))
      EQUIVALENCE (GARBAG(IGARB5),Z6(1))
      EQUIVALENCE (GARBAG(IGARB4),Z7(1))
      EQUIVALENCE (GARBAG(IGARB8),Z8(1))
      EQUIVALENCE (GARBAG(IGARB9),Z9(1))
      EQUIVALENCE (GARBAG(IGAR10),PLABID(1))
      EQUIVALENCE (GARBAG(JGAR11),XTEMP1(1))
      EQUIVALENCE (GARBAG(JGAR12),XTEMP2(1))
      EQUIVALENCE (GARBAG(JGAR13),XTEMP3(1))
      EQUIVALENCE (GARBAG(JGAR14),XTEMP4(1))
      EQUIVALENCE (GARBAG(JGAR15),XPLOTZ(1))
      EQUIVALENCE (GARBAG(JGAR16),YPLOTZ(1))
      EQUIVALENCE (GARBAG(JGAR17),WTS(1))
!
      INCLUDE 'DPCOZD.INC'
      EQUIVALENCE (DGARBG(IDGAR1),Z2(1))
      EQUIVALENCE (DGARBG(IDGAR2),Z3(1))
      EQUIVALENCE (DGARBG(IDGAR3),Z4(1))
      EQUIVALENCE (DGARBG(IDGAR4),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR5),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR6),DTEMP3(1))
!
      INCLUDE 'DPCOZI.INC'
      EQUIVALENCE (IGARBG(IIGAR1),IZ(1))
      EQUIVALENCE (IGARBG(IIGAR2),IZ2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP1(1))
!
!-----COMMON----------------------------------------------------
!
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
      INCLUDE 'DPCOST.INC'
!
!-----START POINT------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='ND  '
      IERROR='NO'
      ICASEQ='UNKN'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               **************************************
!               **  TREAT THE MANDEL ANALYSIS CASE  **
!               **************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MAND')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MAND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTC=0
      IF(NUMARG.GE.1.AND.ICOM.EQ.'MAND'.AND.   &
        IHARG(1).EQ.'PAUL')THEN
        ILASTC=1
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'MAND'.AND.   &
        IHARG(1).EQ.'ANAL')THEN
        ILASTC=1
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'MAND'.AND.   &
        IHARG(1).EQ.'PAUL'.AND.IHARG(2).EQ.'ANAL')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'CONS'.AND.   &
        IHARG(1).EQ.'MEAN'.AND.IHARG(2).EQ.'ANAL')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'CONS'.AND.   &
        IHARG(1).EQ.'MEAN')THEN
        ILASTC=1
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'BOB '.AND.   &
        IHARG(1).EQ.'ANAL')THEN
        ILASTC=1
      ELSEIF(ICOM.EQ.'MAND')THEN
        ILASTC=0
      ELSEIF(ICOM.EQ.'BOB ')THEN
        ILASTC=0
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'MAND'.AND.IHARG(2).EQ.'PAUL')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'MAND'.AND.IHARG(2).EQ.'ANAL')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.3.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'MAND'.AND.IHARG(2).EQ.'PAUL'.AND.   &
        IHARG(3).EQ.'ANAL')THEN
        ILASTC=3
      ELSEIF(NUMARG.GE.3.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'CONS'.AND.IHARG(2).EQ.'MEAN'.AND.   &
        IHARG(3).EQ.'ANAL')THEN
        ILASTC=3
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'CONS'.AND.IHARG(2).EQ.'MEAN')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'BOB '.AND.IHARG(2).EQ.'ANAL')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'MAND')THEN
        ILASTC=1
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'SUMM'.AND.   &
        IHARG(1).EQ.'BOB ')THEN
        ILASTC=1
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      IFOUND='YES'
      IF(ILASTC.GT.0)THEN
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CONSENSUS MEAN'
      MINNA=2
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=2
      MAXNVA=4
      DO 210 I=1,MAXSPN
        IVARTY(I)='XXXX'
  210 CONTINUE
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MAND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ****************************************
!               **  STEP 3--                          **
!               **  EXTRACT THE DATA                  **
!               ****************************************
!
!     THE FOLLOWING CASES ARE SUPPORTED:
!
!       1) NUMVAR = 2
!
!          RAW DATA CASE, THE "X" VARIABLE IS ALSO THE LAB-ID
!
!       2) NUMVAR = 3
!
!          SUMMARY DATA CASE, NO LAB-ID VARIABLE GIVEN
!
!       2) NUMVAR = 4
!
!          SUMMARY DATA CASE, LAB-ID VARIABLE GIVEN
!
      ICASE='VARI'
      ICOL=1
      CALL DPPAR5(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y2,Y3,PLABID,Z9,Z9,Z9,NS,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NUMVAR.EQ.3)THEN
        DO 310 I=1,NS
          PLABID(I)=REAL(I)
  310   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 8--                                    **
!               **  PREPARE FOR ENTRANCE INTO DPMAN2--          **
!               **************************************************
!
      ISTEPN='8'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MAND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IH='SIGM'
      IH2='AH  '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        SIGMAH=0.0
      ELSE
        SIGMAH=VALUE(ILOCP)
        IF(SIGMAH.LT.0.0)SIGMAH=0.0
      ENDIF
      IH='DFH '
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IDFH=1
      ELSE
        IDFH=INT(VALUE(ILOCP)+ 0.5)
      ENDIF
      IF(IDFH.LE.0)IDFH=1
!
!     2023/04: LINEAR POOL METHOD SUPPORTS A WEIGHTS VARIABLE
!              FOR THE LABS
!
      DO 410 JJ=1,MAXOBV
        WTS(JJ)=0.0
  410  CONTINUE
!
      IF(ILIPCM.EQ.'ON' .AND. ILIPWT.NE.'OFF ')THEN
        IH=ILIPWT(1:4)
        IH2=ILIPWT(5:8)
        IHWUSE='V'
        MESSAG='NO'
        CALL CHECKN(IH,IH2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
!
        IF(IERROR.EQ.'NO')THEN
          ICOLQP=IVALUE(ILOCV)
          NTEMP=IN(ILOCV)
          ICNT=0
          DO 418 I=1,NTEMP
            IJ=MAXN*(ICOLQP-1)+I
            ICNT=ICNT+1
            IF(ICOLQP.LE.MAXCOL)WTS(ICNT)=V(IJ)
            IF(ICOLQP.EQ.MAXCP1)WTS(ICNT)=PRED(I)
            IF(ICOLQP.EQ.MAXCP2)WTS(ICNT)=RES(I)
            IF(ICOLQP.EQ.MAXCP3)WTS(ICNT)=YPLOT(I)
            IF(ICOLQP.EQ.MAXCP4)WTS(ICNT)=XPLOT(I)
            IF(ICOLQP.EQ.MAXCP5)WTS(ICNT)=X2PLOT(I)
            IF(ICOLQP.EQ.MAXCP6)WTS(ICNT)=TAGPLO(I)
  418     CONTINUE
        ENDIF
      ENDIF
!               ***********************************************
!               **  STEP 9--                                 **
!               **  CARRY OUT THE CONSENSUS MEANS ANALYSIS   **
!               ***********************************************
!
      ISTEPN='9'
