      IH2='EAN '
      VALUE0=XBCP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BCPS'
      IH2='E   '
      VALUE0=XBCPSE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='MEDO'
      IH2='FMEA'
      VALUE0=XMEDME
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='MEDM'
      IH2='EASE'
      VALUE0=SEMEK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='H15O'
      IH2='FMEA'
      VALUE0=XH15
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='H15M'
      IH2='EASE'
      VALUE0=SEHMK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='LINP'
      IH2='MEAN'
      VALUE0=XLP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='LINP'
      IH2='SE  '
      VALUE0=XLIPSE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='LINP'
      IH2='95LL'
      VALUE0=ALOWLP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='LINP'
      IH2='95UL'
      VALUE0=AUPPLP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MAN2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NS,NUMVAR,ABIAS,ICASEQ
 9014   FORMAT('NS,NUMVAR,ABIAS,ICASEQ = ',2I8,G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAND
      SUBROUTINE DPMAN2(Y1,Y2,Y3,PLABID,NPTS,NUMVAR,MAXNXT,          &
                        DAT,X,T,W,                                   &
                        AMEAN,ASD,N,                                 &
                        AMEANF,ASDF,NFULL,                           &
                        XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,          &
                        DTEMP1,DTEMP2,DTEMP3,                        &
                        XPLOT,YPLOT,WTS,NPLOT,                       &
                        IHLEFT,IHLEF2,IHRIGH,IHRIG2,IHRI21,IHRI22,   &
                        SIGMAH,IDFH,                                 &
                        XGRAND,S2WPOO,SW,ASD2,ASD3,                  &
                        SET1,SET2,                                   &
                        XMPS,S2BMPS,SEMP,                            &
                        XMMPS,S2BMMP,SEMMP,                          &
                        XMLS,S2BMLS,SEML,                            &
                        XSE,XSES2,ABIAS,ISEDF,                       &
                        ASM,ASB,AKU,                                 &
                        XGD,XGDS2,                                   &
                        XGCI,XDL,XDLS2,YDL,SEDLK1,SEHDK1,SERUK1,     &
                        XDLK2,XDLK3,DLOWD2,DHIGD2,DLOWD3,DHIGD3,     &
                        SEBOK1,SEBOK2,DLOWD4,DHIGD4,                 &
                        DLOWD5,DHIGD5,DLOWD6,DHIGD6,                 &
                        SEGCI,XFW,SEFWK1,SEFWK2,                     &
                        XBCP,XBCPSE,XBCPK1,XBCPK2,XMEDME,SEMEK1,     &
                        XH15,SEHMK1,SEHMK2,H15LCL,H15UCL,            &
                        XLP,XLIPSE,ALOWLP,AUPPLP,                    &
                        IWRITE,                                      &
                        ICAPSW,ICAPTY,IFORSW,ISEED,IBOOSS,           &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A CONSENSUS MEAN ANALYSIS USING FOLLOWING
!              APPROACHES
!              1) MANDEL-PAULE
!              2) MODIFIED MANDEL-PAULE
!              3) VANGEL-RUKHIN MAXIMUM LIKELIHOOD
!              4) DERSIMONIAN AND LARID
!              5) GRAYBILL-DEAL
!              6) FAIRWEATHER
!              7) GENERALIZED CONFIDENCE INTERVALS
!              8) GRAND MEAN
!              9) MEAN OF MEANS
!             10) BOB
!             11) SCHILLER-EBERHARDT
!             12) BAYESIAN CONSENSUS PROCEDURE OF GUTHRIE AND HAGWOOD
!             13) MEDIAN OF MEANS
!             14) HUBER MEAN OF MEANS
!             15) LINEAR POOL
!     WRITTEN BY--CODE FOR MANDEL-PAULE, MAXIMUM LIKELIHOOD
!                 PROVIDED BY MARK VANGEL, BOB BASED ON MACROS
!                 PROVIDED BY STEFAN LEIGH.
!     PRINTING--YES
!     SUBROUTINES NEEDED--FCDF
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2000/10
!     ORIGINAL VERSION--OCTOBER   2000.
!     UPDATED  VERSION--FEBRUARY  2001. FROM JAMES YEN, A FEW
!                                       TERMINOLOGY CHANGES,
!                                       FIX TO BOB COMPUTATION
!     UPDATED  VERSION--AUGUST    2001. ADD IWRITE
!     UPDATED  VERSION--APRIL     2002. PRINTING OF GRAND MEAN
!     UPDATED  VERSION--OCTOBER   2002. SUPPORT FOR "CAPTURE HTML"
!     UPDATED  VERSION--OCTOBER   2003. SUPPORT FOR "CAPTURE LATEX"
!     UPDATED  VERSION--APRIL     2004. SOME MODIFICATIONS TO THE
!                                       FORMATTING OF THE OUTPUT
!     UPDATED  VERSION--MARCH     2006. SPLIT ROUTINE INTO MULTIPLE
!                                       SUBROUTINES
!     UPDATED  VERSION--MARCH     2006. IFORSW FOR SIGNIFICANT DIGITS
!     UPDATED  VERSION--MARCH     2006. REVISE OUTPUT FORMAT
!     UPDATED  VERSION--JUNE      2006. SET COMMANDS TO INDIVIDUALLY
!                                       CONTROL WHETHER A PARTICULAR
!                                       METHOD IS APPLIED
!     UPDATED  VERSION--JUNE      2006. OMIT LABS WITH ONLY ONE
!                                       OBSERVATION
!     UPDATED  VERSION--JUNE      2006. ADD THE BAYESIAN CONSENSUS
!                                       PROCEDURE METHOD OF HAGWOOD
!                                       AND GUTHRIE (A REFINEMENT OF
!                                       BOB)
!     UPDATED  VERSION--FEBRUARY  2007. FOR THE BAYESIAN CONSENSUS
!                                       AND BOB METHODS,
!                                       AUTOMATICALLY SUPPRESS IF
!                                       TOO MANY LABS
!     UPDATED  VERSION--FEBRUARY  2010. USE DPDTA1, DPDTA2 FOR TABLES
!     UPDATED  VERSION--JUNE      2010. FIVE METHODS CAN HANDLE CASE
!                                       WHERE SOME LABS HAVE 0 STANDARD
!                                       DEVIATION
!     UPDATED  VERSION--OCTOBER   2011. OPTIONAL LABID VARIABLE FOR
!                                       SUMMARY DATA CASE
!     UPDATED         --OCTOBER   2014. FOR SUMMARY DATA, OPTION TO
!                                       INPUT MEAN AND UNCERTAINTY
!                                       (I.E., S/SQRT(N) INSTEAD OF
!                                       S AND N) (IN SOME CASES, DATA
!                                       IS ONLY AVAILABLE IN THIS FORM).
!     UPDATED         --AUGUST    2015. DON'T RESTART VERBATIM MODE
!                                       HERE AS THIS IS ALREADY DONE
!                                       BY THE LAST TABLE ROUTINE
!     UPDATED         --MARCH     2017. MEDIAN OF MEANS
!     UPDATED         --MARCH     2017. HUBER MEAN OF MEANS
!     UPDATED         --APRIL     2023. LINEAR POOL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IPTEMP
      CHARACTER*4 IPRISV
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 IHRI21
      CHARACTER*4 IHRI22
!
      LOGICAL IFLAG9
!
      REAL SIGMAH
      REAL XMPS
      REAL XMMPS
      REAL S2BMPS
      REAL S2BMMP
      REAL XMLS
      REAL S2BMLS
      REAL AMNX
      REAL AMXX
      REAL ASM
      REAL ASB
      REAL AKU
      REAL AKUK1
      REAL AKUK2
      REAL XGRAND
      REAL SW
      REAL S2WPOO
      REAL SEMP
      REAL SEMPK1
      REAL SEMPK2
      REAL SEML
      REAL SEMLK1
      REAL SEMLK2
      REAL SEMLBO
      REAL SEMLB2
      REAL SEMMP
      REAL SEMMP1
      REAL SEMMP2
      REAL SDGRAN
      REAL ASD2
      REAL ASD3
      REAL ABIAS
      REAL XGD
      REAL XGDS2
      REAL XGCI
      REAL SET1
      REAL SET1K1
      REAL SET1K2
      REAL SET2
      REAL SET2K1
      REAL SET2K2
      REAL XSE
      REAL XSES2
      REAL SEGDK1
      REAL SEGDK2
      REAL SESUK1
      REAL SESUK2
      REAL XDL
      REAL XDLS2
      REAL SEDLK1
      REAL SEDLK2
      REAL SERUK1
      REAL SERUK2
      REAL SEHDK1
      REAL SEHDK2
      REAL XDLK2
      REAL XDLK3
      REAL SEGCI
      REAL XFW
      REAL XFWS2
      REAL SEFWK1
      REAL SEFWK2
      REAL XBCP
      REAL XBCPSE
      REAL XBCPK1
      REAL XBCPK2
      REAL YDL2
      REAL XMEDME
      REAL SEMED
      REAL SEMED2
      REAL SEMEDB
      REAL SEMDB2
      REAL STS2B
      REAL STXMU
      REAL SEMEK1
      REAL SEMEK2
      REAL ALOWCL
      REAL AUPPCL
      REAL XH15
      REAL SEHMK1
      REAL SEHMK2
      REAL H15LCL
      REAL H15UCL
!
      CHARACTER*4 IOP
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
      REAL PLABID(*)
      REAL AMEAN(*)
      REAL ASD(*)
      REAL AMEANF(*)
      REAL ASDF(*)
      REAL XTEMP1(*)
      REAL XTEMP2(*)
      REAL XTEMP3(*)
      REAL XTEMP4(*)
      REAL XPLOT(*)
      REAL YPLOT(*)
      REAL WTS(*)
!
      INTEGER N(*)
      INTEGER NFULL(*)
      INTEGER ITEMP1(*)
!
      REAL DAT(*)
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION T(*)
      DOUBLE PRECISION W(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      COMMON /MPCOM/ T0, T1
!
      INCLUDE 'DPCOST.INC'
!
      CHARACTER*4 IBOBSV
      CHARACTER*4 IBCPSV
      CHARACTER*4 IUNCFL
      CHARACTER*4 IDFFL
!
      INTEGER NUMDIG
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      IPTEMP=IPRINT
      IFLAG9=.TRUE.
      IUNCFL='OFF'
      IDFFL='OFF'
      ISUBN1='DPMA'
      ISUBN2='N2  '
!
      IBOBSV=IBOBCM
      IBCPSV=IBCPCM
!
      XMPS=CPUMIN
      XMMPS=CPUMIN
      XMLS=CPUMIN
      XDL=CPUMIN
      XGD=CPUMIN
      XFW=CPUMIN
      XGCI=CPUMIN
      XGRAND=CPUMIN
      ASM=CPUMIN
      XSE=CPUMIN
      XBCP=CPUMIN
      SEMED=CPUMIN
      SEMED2=CPUMIN
      SEMEDB=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAN2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NUMVAR,IFORSW
   52   FORMAT('NPTS,NUMVAR,IFORSW = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NPTS
          WRITE(ICOUT,56)I,Y1(I),Y2(I),Y3(I),PLABID(I)
   56     FORMAT('I,Y1(I),Y2(I),Y3(I),PLABID(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NPTS.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN CONSENSUS MEANS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE CONSENSUS',   &
               'MEANS ANALYSIS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('      MUST BE AT LEAST 2; THE ENTERED NUMBER OF')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,104)NPTS
  104   FORMAT('      OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 1.1--                                  **
!               **   OPEN THE STORAGE FILES                     **
!               **************************************************
!
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=1
      IFLAG3=1
      IFLAG4=1
      IFLAG5=1
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-7
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!               ***********************************************
!               **  STEP 2.1--                               **
!               **  IF TWO VARIABLES ENTERED, THEN           **
!               **     Y1 = RESPONSE VARIABLE                **
!               **     Y2 = LAB ID VARIABLE                  **
!               **  1) COPY RESPONSE DATA TO "DAT"           **
!               **  2) DETERMINE NUMBER OF DISTINCT LABS     **
!               **  3) SORT RESPONSE (DAT) BY LAB ID         **
!               **  4) DETERMINE NUMER OF POINTS IN EACH LAB **
!               ***********************************************
!
      IF(NUMVAR.GE.3)GO TO 6100
!
      CALL DPMAN3(Y1,Y2,Y3,NPTS,NUMVAR,NLAB,     &
                  DAT,X,T,                       &
                  AMEAN,ASD,N,                   &
                  AMEANF,ASDF,NFULL,NLABF,NPTSF, &
                  IHLEFT,IHLEF2,IHRIGH,IHRIG2,   &
                  ASM,ASD2,ASD3,                 &
                  XGRAND,S2WPOO,SW,              &
                  AMNX,AMXX,                     &
                  IWRITE,IOUNI1,                 &
                  ICAPSW,ICAPTY,NUMDIG,          &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     FEBRUARY 2007: FOR BOB, SUPPRESS IF NLAB > 5.  FOR
!                    BAYESIAN CONSENSUS PROCEDURE, SUPPRESS
!                    IF NLAB > 6.
!
      IF(NLAB.GT.6)IBCPCM='OFF'
      IF(NLAB.GT.5)IBOBCM='OFF'
!
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     FOLLOWING CALL NEEDED TO INITIALIZE MANDEL-PAULE
!     AND VANGEL-RUKHIN METHODS
!
      CALL MPPREP (NLAB, X, T, T0, T1)
!
!     MANDEL-PAULE
!
      IF(IMPACM.EQ.'ON' .OR. IVRUCM.EQ.'ON' .OR. ISCECM.EQ.'ON')THEN
        IFLAGZ=0
        IF(IMPACM.EQ.'OFF' .AND. IVRUCM.EQ.'OFF')IFLAGZ=1
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMNPL(Y1,Y2,Y3,NPTS,NLAB,               &
                    X,T,N,                            &
                    XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                    DLOWMP,DHIGMP,STXMU,STS2B,        &
                    IWRITE,                           &
                    ICAPSW,ICAPTY,NUMDIG,             &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
!
        WRITE(IOUNI5,1122)
 1122   FORMAT('WEIGHTS FOR MANDEL-PAULE')
        DO 1123 I=1,NLAB
          DTERM1=DBLE(ASD(I))**2/DBLE(N(I))
          WITEMP=1.0D0/(S2BMPS + DTERM1)
          WRITE(IOUNI5,'(E15.7)')WITEMP
 1123   CONTINUE
!
      ENDIF
!
!     MODIFIED MANDEL-PAULE
!
      IF(IMMPCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMMPL(Y1,Y2,Y3,NPTS,NLAB,                 &
                    X,T,N,                              &
                    XMMPS,S2BMMP,SEMMP,SEMMP1,SEMMP2,   &
                    DLOWMM,DHIGMM,                      &
                    IWRITE,                             &
                    ICAPSW,ICAPTY,NUMDIG,               &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
!
        WRITE(IOUNI5,1132)
 1132   FORMAT('WEIGHTS FOR MODIFIED MANDEL-PAULE')
        DO 1133 I=1,NLAB
          DTERM1=DBLE(ASD(I))**2/DBLE(N(I))
          WITEMP=1.0D0/(S2BMMP + DTERM1)
          WRITE(IOUNI5,'(E15.7)')WITEMP
 1133   CONTINUE
!
      ENDIF
!
!     VANGEL-RUKHIN MAXIMUM LIKELIHOOD
!
      IF(IVRUCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPVRML(NPTS,NLAB,                                         &
                    AMEAN,ASD,N,                                       &
                    XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP1,XTEMP1,XTEMP2,   &
                    X,T,W,DTEMP1,DTEMP2,                               &
                    XMLS,S2BMLS,SEML,SEMLK1,SEMLK2,                    &
                    DLOWML,DHIGML,STXMU,STS2B,                         &
                    SEMLBO,DLOWM2,DHIGM2,                              &
                    IWRITE,                                            &
                    ICAPSW,ICAPTY,IOUNI5,NUMDIG,ISEED,                 &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  DERSIMONIAN LAIRD
!
      IF(IDSLCM.EQ.'ON' .OR. IDS2CM.EQ.'ON' .OR.   &
         IDS3CM.EQ.'ON' .OR. IDS4CM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPDERS(NPTS,NLAB,                                         &
                    AMEAN,ASD,N,                                       &
                    XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP1,XTEMP1,XTEMP2,   &
                    XTEMP4,DTEMP1,DTEMP2,DTEMP3,                       &
                    YPLOT,XPLOT,NPLOT,                                 &
                    XDL,XDLS2,YDL,SEDLK1,SEDLK2,DLOWDL,DHIGDL,         &
                    SERUK1,SERUK2,DLOWD2,DHIGD2,                       &
                    SEHDK1,SEHDK2,DLOWD3,DHIGD3,                       &
                    SEBOK1,SEBOK2,DLOWD4,DHIGD4,                       &
                    DLOWD5,DHIGD5,DLOWD6,DHIGD6,                       &
                    XDLK2,XDLK3,                                       &
                    IWRITE,IOUNI5,                                     &
                    ICAPSW,ICAPTY,NUMDIG,ISEED,IBOOSS,                 &
                    ISUBRO,IBUGA3,IERROR)
        YDL2=REAL(YDL)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  GRAYBILL-DEAL
!
      IF(IGRDCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPGRAY(NPTS,NLAB,                 &
                    AMEAN,ASD,N,               &
                    XGD,XGDS2,SEGDK1,SEGDK2,   &
                    XGDS20,XGDSZ1,XGDSZ2,      &
                    DLOWGD,DHIGGD,             &
                    IWRITE,IOUNI5,             &
                    ICAPSW,ICAPTY,NUMDIG,      &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  FAIRWEATHER
!
      IF(IFAICM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPFAIR(NPTS,NLAB,                                 &
                    AMEAN,ASD,N,                               &
                    XFW,XFWS2,SEFWK1,SEFWK2,                   &
                    DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3, &
                    IWRITE,                                    &
                    ICAPSW,ICAPTY,IFLAG9,NUMDIG,               &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  IYER-WANG GENERALIZED CONFIDENCE INTERVAL
!
      IF(IGCICM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPGCI(NPTS,NLAB,              &
                   AMEAN,ASD,N,            &
                   T,W,                    &
                   XGCI,SEGCI,             &
                   DLOWGC,DHIGGC,          &
                   IWRITE,IOUNI5,          &
                   ICAPSW,ICAPTY,NUMDIG,   &
                   ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     GRAND MEAN
!
      IF(IGMECM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPGMEA(NPTSF,NLABF,                      &
                    XGRAND,ASD2,SET1,SET1K1,SET1K2,   &
                    DLOWT2,DHIGT2,                    &
                    IWRITE,                           &
                    ICAPSW,ICAPTY,NUMDIG,             &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     MEAN OF MEANS
!
      IF(IMOMCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMMEA(NPTSF,NLABF,                   &
                    ASM,ASD2,SET2,SET2K1,SET2K2,   &
                    DLOWT1,DHIGT1,                 &
                    IWRITE,                        &
                    ICAPSW,ICAPTY,NUMDIG,          &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     BOB (BOUND ON BIAS)
!
      IF(IBOBCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPBOB(NPTSF,NLABF,               &
                   AMEANF,ASDF,AMNX,AMXX,SW,  &
                   ASM,ASB,AKU,AKUK1,AKUK2,   &
                   DLOWBO,DHIGBO,             &
                   IWRITE,                    &
                   ICAPSW,ICAPTY,NUMDIG,      &
                   ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     SCHILLER-EBERHARDT
!
      IF(ISCECM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPSCEB(NPTS,NLAB,             &
                    W,N,                   &
                    AMEAN,ASD,S2BMPS,      &
                    XSE,XSES2,IDFH,SIGMAH, &
                    SESUK1,SESUK2,         &
                    DLOWSE,DHIGSE,         &
                    IWRITE,                &
                    ICAPSW,ICAPTY,NUMDIG,  &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
      IF(IBCPCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPBCP(NPTS,NLAB,                   &
                   AMEAN,ASD,N,AMNX,AMXX,       &
                   XBCP,XBCPSE,XBCPK1,XBCPK2,   &
                   DLOWBC,DHIGBC,               &
                   IWRITE,                      &
                   ICAPSW,ICAPTY,NUMDIG,        &
                   ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     MEDIAN OF MEANS
!
      IF(IMEMCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMEDM(NLAB,AMEANF,ASDF,XTEMP1,XTEMP2,       &
                    IWRITE,ICAPSW,ICAPTY,NUMDIG,MAXNXT,   &
                    XMEDME,SEMEK1,SEMEK2,ALOWCL,AUPPCL,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     HUBER H15 MEAN OF MEANS
!
      IF(IHUBCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPHMEA(NLAB,AMEANF,ASDF,XTEMP1,XTEMP2,       &
                    IWRITE,ICAPSW,ICAPTY,NUMDIG,MAXNXT,   &
                    XH15,SEHMK1,SEHMK2,H15LCL,H15UCL,     &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     LINEAR POOL
!
      IF(ILIPCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPLIPO(NLAB,AMEANF,ASDF,WTS,NFULL,         &
                    XTEMP1,XTEMP2,XTEMP3,XTEMP4,        &
                    XLP,XLIPSE,ALOWLP,AUPPLP,           &
                    IWRITE,IOUNI5,                      &
                    ICAPSW,ICAPTY,MAXNXT,NUMDIG,ISEED,  &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     MEDIAN OF MEANS
!
!CCCC IF(IMEMCM.EQ.'ON')THEN
!CCCC   IFLAGZ=0
!CCCC   IF(ICMET5.EQ.'OFF')IFLAGZ=1
!CCCC   IF(IFLAGZ.EQ.1)THEN
!CCCC     IPRISV=IPRINT
!CCCC     IPRINT='OFF'
!CCCC   ENDIF
!CCCC   CALL DPMMED(NPTSF,NLABF,AMEANF,ASDF,
!CCCC1              XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,
!CCCC1              DTEMP1,DTEMP2,DTEMP3,
!CCCC1              XMEDME,SEMED,SEMEDB,
!CCCC1              DLWME0,DHGME0,DLWME1,DHGME1,
!CCCC1              DLWME2,DHGME2,DLWME3,DHGME3,
!CCCC1              IWRITE,IOUNI5,MAXNXT,
!CCCC1              ICAPSW,ICAPTY,NUMDIG,ISEED,IBOOSS,
!CCCC1              ISUBRO,IBUGA3,IERROR)
!CCCC   IF(IFLAGZ.EQ.1)THEN
!CCCC     IPRINT=IPRISV
!CCCC   ENDIF
!CCCC ENDIF
!
!     CONFIDENCE LIMITS TABLE
!
      CALL DPMAN5(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XGCI,XDL,XFW,XBCP,   &
      DLOWMP,DHIGMP,DLOWMM,DHIGMM,DLOWML,DHIGML,DLOWM2,DHIGM2,   &
      DLOWBO,DHIGBO,DLOWSE,DHIGSE,DLOWT1,DHIGT1,   &
      DLOWT2,DHIGT2,DLOWGD,DHIGGD,DLOWGC,DHIGGC,   &
      DLOWDL,DHIGDL,DLOWD2,DHIGD2,DLOWD3,DHIGD3,DLOWD4,DHIGD4,   &
      DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
      DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3,   &
      DLOWBC,DHIGBC,   &
      XMEDME,SEMED,   &
      DLWME0,DHGME0,DLWME1,DHGME1,   &
      DLWME2,DHGME2,DLWME3,DHGME3,   &
      SEMPK1,SEMMP1,SEMLK1,SEMLBO,AKUK1,SESUK1,SET2K1,   &
      SET1K1,SEGDK1,SEDLK1,SEHDK1,SERUK1,SEBOK1,SEGCI,   &
      SEFWK1,XBCPK1,SEMEDB,ALOWCL,AUPPCL,SEMEK1,   &
      XH15,SEHMK1,XLP,XLIPSE,ALOWLP,AUPPLP,   &
      IWRITE,IOUNI2,   &
      ICAPSW,ICAPTY,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
!     STANDARD AND EXPANDED UNCERTAINTIES TABLE
!
      IK=1
      CALL DPMAN6(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XDL,XGCI,XFW,XBCP,   &
      SEMPK1,SEMMP1,SEMLK1,SEMLBO,AKUK1,SESUK1,SET1K1,   &
      SET2K1,SEGDK1,SEDLK1,SEHDK1,SERUK1,SEBOK1,SEGCI,SEFWK1,XBCPK1,   &
      XMEDME,SEMED,SEMEDB,SEMEK1,XH15,SEHMK1,XLP,XLIPSE,   &
      IWRITE,   &
      ICAPSW,ICAPTY,IK,IOUNI3,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
      IK=2
      SEMLB2=2.0*SEMLBO
      SEMED2=2.0*SEMED
      SEMDB2=2.0*SEMEDB
      XLIPS2=2.0*XLIPSE
      CALL DPMAN6(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XDL,XGCI,XFW,XBCP,   &
      SEMPK2,SEMMP2,SEMLK2,SEMLB2,AKUK2,SESUK2,SET1K2,   &
      SET2K2,SEGDK2,SEDLK2,SEHDK2,SERUK2,SEBOK2,   &
      2.0*SEGCI,SEFWK2,XBCPK2,   &
      XMEDME,SEMED2,SEMDB2,SEMEK2,XH15,SEHMK2,XLP,XLIPS2,   &
      IWRITE,   &
      ICAPSW,ICAPTY,IK,IOUNI4,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
      GO TO 8000
!
!               ***********************************************
!               **  STEP 2.1--                               **
!               **  IF THREE VARIABLES ENTERED, THEN FIRST   **
!               **  VARIABLE IS LAB MEANS, SECOND VARIABLE IS**
!               **  LAB SD, AND THIRD VARIABLE IS NUMBER OF  **
!               **  OBSERVATIONS FOR LAB.                    **
!               ***********************************************
!
!     2014/10: SUPPORT FOR CASE WHERE DATA GIVEN IN THE FORM OF
!              LAB MEAN AND LAB UNCERTAINTY (I.E., S/SQRT(N)).
!              DATA FROM EXTERNAL LABS IS OFTEN REPORTED IN THIS
!              FORM.
!
!              FOR THIS TYPE OF DATA, THE "SAMPLE SIZE" FIELD
!              CAN BE ENTERED IN ONE OF THE FOLLOWING TWO WAYS:
!
!                  1) IF THE SAMPLE SIZE IS GIVEN AS A NEGATIVE
!                     VALUE, THEN THE ABSOLUTE VALUE OF THE
!                     SAMPLE SIZE WILL BE INTERPRETED AS THE
!                     "EFFECTIVE DEGREES OF FREEDOM".  NOTE THAT
!                     IN MANY OF THE FORMULAS, THERE WILL BE
!
!                         S(i)/N(i)
!
!                     TERMS.  FOR NEGATIVE SAMPLE SIZE, THE S(i)
!                     ENTERED WILL BE INTERPRETED AS S(i)/N(i) FOR
!                     THESE FORMULAS.  SOME FORMULAS WILL HAVE AN
!                     "N(i) - C" TERM.  THESE FORMULAS WILL USE THE
!                     ABSOLUTE VALUE OF THE SAMPLE SIZE FOR N(i).
!
!                  1) IF THE SAMPLE SIZE IS GIVEN AS 0, THEN THIS MEANS
!                     NO EFFECTIVE DEGREES OF FREEDOM ARE AVAILABLE.
!                     FOR THIS CASE, FORMULAS THAT REQUIRE "N(i) - C"
!                     TERMS WILL NOT BE SUPPORTED.
!
 6100 CONTINUE
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
!
      NLAB=NPTS
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,6211)
 6211   FORMAT('***** ERROR IN CONSENSUS MEANS ANALYSIS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,6212)
 6212   FORMAT('      FOR THE SUMMARY CASE OF THE CONSENSUS MEANS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,6214)
 6214   FORMAT('      COMMAND, THERE MUST BE AT LEAST TWO LABS.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,6220)
 6220   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NTOT=0
      IF(NUMVAR.GE.3)THEN
        DO 6110 I=1,NLAB
          IF(Y3(I).GE.0.0)THEN
            IVAL=INT(Y3(I)+0.5)
          ELSE
            AVAL=ABS(Y3(I))
            IVAL=INT(AVAL+0.5)
          ENDIF
          N(I)=IVAL
          NTOT=NTOT+N(I)
 6110   CONTINUE
      ENDIF
!
      CALL DPMAN4(Y1,Y2,Y3,PLABID,NLAB,NTOT,NUMVAR,   &
                  DAT,X,T,   &
                  AMEAN,ASD,N,   &
                  AMEANF,ASDF,NFULL,NLABF,NTOTF,   &
                  IHLEFT,IHLEF2,IHRIGH,IHRIG2,IHRI21,IHRI22,   &
                  ASM,ASD2,ASD3,SDGRAN,   &
                  XGRAND,S2WPOO,SW,   &
                  AMNX,AMXX,   &
                  IWRITE,IOUNI1,   &
                  ICAPSW,ICAPTY,NUMDIG,IUNCFL,IDFFL,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IERROR.EQ.'YES')GO TO 9000
!
!CCCC CALL MPPREP (NLAB, X, T, T0, T1)
!
      EPS=0.00001
      T0=AMNX - EPS
      T1=AMXX
      DO 6120 I=1,NLAB
        X(I)=(X(I)-T0)/(T1-T0)
        T(I)=T(I)/((T1-T0)**2)
 6120 CONTINUE
!
!
!     MANDEL-PAULE
!
      IF(IMPACM.EQ.'ON' .OR. IVRUCM.EQ.'ON' .OR. ISCECM.EQ.'ON')THEN
        IFLAGZ=0
        IF(IMPACM.EQ.'OFF' .AND. IVRUCM.EQ.'OFF')IFLAGZ=1
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMNPL(Y1,Y2,Y3,NTOT,NLAB,   &
                    X,T,N,   &
                    XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                    DLOWMP,DHIGMP,STXMU,STS2B,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
!
        WRITE(IOUNI5,6122)
 6122   FORMAT('WEIGHTS FOR MANDEL-PAULE')
        DO 6123 I=1,NLAB
          DTERM1=DBLE(Y2(I))**2/DBLE(N(I))
          WITEMP=1.0D0/(S2BMPS + DTERM1)
          WRITE(IOUNI5,'(E15.7)')WITEMP
 6123   CONTINUE
!
      ENDIF
!
!     MODIFIED MANDEL-PAULE
!
      IF(IMMPCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMMPL(Y1,Y2,Y3,NTOT,NLAB,   &
                    X,T,N,   &
                    XMMPS,S2BMMP,SEMMP,SEMMP1,SEMMP2,   &
                    DLOWMM,DHIGMM,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
!
        WRITE(IOUNI5,6132)
 6132   FORMAT('WEIGHTS FOR MODIFIED MANDEL-PAULE')
        DO 6133 I=1,NLAB
          DTERM1=DBLE(Y2(I))**2/DBLE(N(I))
          WITEMP=1.0D0/(S2BMMP + DTERM1)
          WRITE(IOUNI5,'(E15.7)')WITEMP
 6133   CONTINUE
!
      ENDIF
!
!     VANGEL-RUKHIN MAXIMUM LIKELIHOOD
!
      IF(IVRUCM.EQ.'ON' .AND. IDFFL.EQ.'OFF')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPVRML(NTOT,NLAB,   &
                    AMEAN,ASD,N,   &
                    XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP1,XTEMP1,XTEMP2,   &
                    X,T,W,DTEMP1,DTEMP2,   &
                    XMLS,S2BMLS,SEML,SEMLK1,SEMLK2,   &
                    DLOWML,DHIGML,STXMU,STS2B,   &
                    SEMLBO,DLOWM2,DHIGM2,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,IOUNI5,NUMDIG,ISEED,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  DERSIMONIAN LAIRD
!
      IF(IDSLCM.EQ.'ON' .OR. IDS2CM.EQ.'ON' .OR.   &
         IDS3CM.EQ.'ON' .OR. IDS4CM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPDERS(NTOT,NLAB,   &
                    AMEAN,ASD,N,   &
                    XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP1,   &
                    XTEMP1,XTEMP2,XTEMP4,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    YPLOT,XPLOT,NPLOT,   &
                    XDL,XDLS2,YDL,SEDLK1,SEDLK2,DLOWDL,DHIGDL,   &
                    SERUK1,SERUK2,DLOWD2,DHIGD2,   &
                    SEHDK1,SEHDK2,DLOWD3,DHIGD3,   &
                    SEBOK1,SEBOK2,DLOWD4,DHIGD4,   &
                    DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
                    XDLK2,XDLK3,   &
                    IWRITE,IOUNI5,   &
                    ICAPSW,ICAPTY,NUMDIG,ISEED,IBOOSS,   &
                    ISUBRO,IBUGA3,IERROR)
        YDL2=REAL(YDL)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  GRAYBILL-DEAL
!
      IF(IGRDCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPGRAY(NTOT,NLAB,   &
                    AMEAN,ASD,N,   &
                    XGD,XGDS2,SEGDK1,SEGDK2,   &
                    XGDS20,XGDSZ1,XGDSZ2,   &
                    DLOWGD,DHIGGD,   &
                    IWRITE,IOUNI5,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  FAIRWEATHER
!
      IF(IFAICM.EQ.'ON' .AND. IUNCFL.EQ.'OFF')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPFAIR(NTOT,NLAB,   &
                    AMEAN,ASD,N,   &
                    XFW,XFWS2,SEFWK1,SEFWK2,   &
                    DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,IFLAG9,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!  IYER-WANG GENERALIZED CONFIDENCE INTERVAL
!
      IF(IGCICM.EQ.'ON' .AND. IDFFL.EQ.'OFF')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPGCI(NTOT,NLAB,   &
                   AMEAN,ASD,N,   &
                   T,W,   &
                   XGCI,SEGCI,   &
                   DLOWGC,DHIGGC,   &
                   IWRITE,IOUNI5,   &
                   ICAPSW,ICAPTY,NUMDIG,   &
                   ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     GRAND MEAN
!
      IF(IGMECM.EQ.'ON' .AND. IUNCFL.EQ.'OFF')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPGMEA(NTOTF,NLABF,   &
                    XGRAND,SDGRAN,SET1,SET1K1,SET1K2,   &
                    DLOWT2,DHIGT2,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     MEAN OF MEANS
!
      IF(IMOMCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMMEA(NTOTF,NLABF,   &
                    ASM,ASD2,SET2,SET2K1,SET2K2,   &
                    DLOWT1,DHIGT1,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     BOB (BOUND ON BIAS)
!
      IF(IBOBCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPBOB(NTOTF,NLABF,   &
                   AMEANF,ASDF,AMNX,AMXX,SW,   &
                   ASM,ASB,AKU,AKUK1,AKUK2,   &
                   DLOWBO,DHIGBO,   &
                   IWRITE,   &
                   ICAPSW,ICAPTY,NUMDIG,   &
                   ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     SCHILLER-EBERHARDT
!
      IF(ISCECM.EQ.'ON' .AND. IDFFL.EQ.'OFF')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPSCEB(NTOT,NLAB,   &
                    W,N,   &
                    AMEAN,ASD,S2BMPS,   &
                    XSE,XSES2,IDFH,SIGMAH,   &
                    SESUK1,SESUK2,   &
                    DLOWSE,DHIGSE,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
      IF(IBCPCM.EQ.'ON' .AND. IDFFL.EQ.'OFF')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPBCP(NTOT,NLAB,   &
                   AMEAN,ASD,N,AMNX,AMXX,   &
                   XBCP,XBCPSE,XBCPK1,XBCPK2,   &
                   DLOWBC,DHIGBC,   &
                   IWRITE,   &
                   ICAPSW,ICAPTY,NUMDIG,   &
                   ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!     MEDIAN OF MEANS
!
      IF(IMEMCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPMEDM(NLAB,AMEANF,ASDF,XTEMP1,XTEMP2,   &
                    IWRITE,ICAPSW,ICAPTY,NUMDIG,MAXNXT,   &
                    XMEDME,SEMEK1,SEMEK2,ALOWCL,AUPPCL,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!CCCC IF(IMEMCM.EQ.'ON')THEN
!CCCC   IFLAGZ=0
!CCCC   IF(ICMET5.EQ.'OFF')IFLAGZ=1
!CCCC   IF(IFLAGZ.EQ.1)THEN
!CCCC     IPRISV=IPRINT
!CCCC     IPRINT='OFF'
!CCCC   ENDIF
!CCCC   CALL DPMMED(NTOTF,NLABF,AMEANF,ASDF,
!CCCC1              XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,
!CCCC1              DTEMP1,DTEMP2,DTEMP3,
!CCCC1              XMEDME,SEMED,SEMEDB,
!CCCC1              DLWME0,DHGME0,DLWME1,DHGME1,
!CCCC1              DLWME2,DHGME2,DLWME3,DHGME3,
!CCCC1              IWRITE,IOUNI5,MAXNXT,
!CCCC1              ICAPSW,ICAPTY,NUMDIG,ISEED,IBOOSS,
!CCCC1              ISUBRO,IBUGA3,IERROR)
!CCCC   IF(IFLAGZ.EQ.1)THEN
!CCCC     IPRINT=IPRISV
!CCCC   ENDIF
!CCCC ENDIF
!
!     HUBER H15 MEAN OF MEANS
!
      IF(IHUBCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPHMEA(NLAB,AMEANF,ASDF,XTEMP1,XTEMP2,   &
                    IWRITE,ICAPSW,ICAPTY,NUMDIG,MAXNXT,   &
                    XH15,SEHMK1,SEHMK2,H15LCL,H15UCL,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
      IF(ILIPCM.EQ.'ON')THEN
        IFLAGZ=0
        IF(ICMET5.EQ.'OFF')IFLAGZ=1
        IF(IFLAGZ.EQ.1)THEN
          IPRISV=IPRINT
          IPRINT='OFF'
        ENDIF
        CALL DPLIPO(NLAB,AMEAN,ASD,WTS,N,   &
                    XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                    XLP,XLIPSE,ALOWLP,AUPPLP,   &
                    IWRITE,IOUNI5,   &
                    ICAPSW,ICAPTY,MAXNXT,NUMDIG,ISEED,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IFLAGZ.EQ.1)THEN
          IPRINT=IPRISV
        ENDIF
      ENDIF
!
!
!     CONFIDENCE LIMITS TABLE
!
      CALL DPMAN5(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XGCI,XDL,XFW,XBCP,   &
      DLOWMP,DHIGMP,DLOWMM,DHIGMM,DLOWML,DHIGML,DLOWM2,DHIGM2,   &
      DLOWBO,DHIGBO,DLOWSE,DHIGSE,DLOWT1,DHIGT1,   &
      DLOWT2,DHIGT2,DLOWGD,DHIGGD,DLOWGC,DHIGGC,   &
      DLOWDL,DHIGDL,DLOWD2,DHIGD2,DLOWD3,DHIGD3,DLOWD4,DHIGD4,   &
      DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
      DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3,   &
      DLOWBC,DHIGBC,   &
      XMEDME,SEMED,   &
      DLWME0,DHGME0,DLWME1,DHGME1,   &
      DLWME2,DHGME2,DLWME3,DHGME3,   &
      SEMPK1,SEMMP1,SEMLK1,SEMLBO,AKUK1,SESUK1,SET2K1,   &
      SET1K1,SEGDK1,SEDLK1,SEHDK1,SERUK1,SEBOK1,SEGCI,   &
      SEFWK1,XBCPK1,SEMEDB,ALOWCL,AUPPCL,SEMEK1,   &
      XH15,SEHMK1,XLP,XLIPSE,ALOWLP,AUPPLP,   &
      IWRITE,IOUNI2,   &
      ICAPSW,ICAPTY,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
      IK=1
      CALL DPMAN6(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XDL,XGCI,XFW,XBCP,   &
      SEMPK1,SEMMP1,SEMLK1,SEMLBO,AKUK1,SESUK1,SET1K1,   &
      SET2K1,SEGDK1,SEDLK1,SEHDK1,SERUK1,SEBOK1,SEGCI,SEFWK1,XBCPK1,   &
      XMEDME,SEMED,SEMEDB,SEMEK1,XH15,SEHMK1,XLP,XLIPSE,   &
      IWRITE,   &
      ICAPSW,ICAPTY,IK,IOUNI3,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
      IK=2
      SEMLB2=2.0*SEMLBO
      SEMED2=2.0*SEMED
      SEMDB2=2.0*SEMEDB
      XLIPS2=2.0*XLIPSE
      CALL DPMAN6(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XDL,XGCI,XFW,XBCP,   &
      SEMPK2,SEMMP2,SEMLK2,SEMLB2,AKUK2,SESUK2,SET1K2,   &
      SET2K2,SEGDK2,SEDLK2,SEHDK2,SERUK2,SEBOK2,   &
      2.0*SEGCI,SEFWK2,XBCPK2,   &
      XMEDME,SEMED2,SEMDB2,SEMEK2,XH15,SEHMK2,XLP,XLIPS2,   &
      IWRITE,   &
      ICAPSW,ICAPTY,IK,IOUNI4,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
      GO TO 8000
!
 8000 CONTINUE
!
!     RESET "ASIS" MODE
!
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
 5195   FORMAT('<PRE>')
        WRITE(ICOUT,5195)
        CALL DPWRST('XXX','WRIT')
!
!     2015/08: NOTE THAT TABLE ROUTINES ALREADY RESET
!              "VERBATIM" MODE, SO THIS IS REDUNDANT
!              HERE.
!
      ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
!CCCC   CALL DPCONA(92,IBASLC)
!8190   FORMAT(A1,'begin{verbatim}')
!CCCC   WRITE(ICOUT,8190)IBASLC
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','WRIT')
      ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
      ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'WOML')THEN
      ENDIF
!
!     CLOSE OUTPUT FILES
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     DESCRIBE OUTPUT TO TEMPORARY OUTPUT FILES
!
      IF(IFEEDB.EQ.'OFF')GO TO 8099
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')GO TO 8099
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')GO TO 8099
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')GO TO 8099
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'WOML')GO TO 8099
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8002)
 8002 FORMAT('Automatic Output:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,8005)
 8005 FORMAT('The following variables were written to the file ',   &
             'dpst1f.dat:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8011)
 8011 FORMAT('   1. Lab ID')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8021)
 8021 FORMAT('   2. Number of Observations for Lab')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8031)
 8031 FORMAT('   3. Mean of Lab')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8041)
 8041 FORMAT('   4. Variance of Lab')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8051)
 8051 FORMAT('   5. Standard Deviation of Lab')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8054)
 8054 FORMAT('   6. Standard Deviation of Mean of Lab')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,8056)
 8056 FORMAT('The following variables were written to the file ',   &
             'dpst2f.dat:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8058)
 8058 FORMAT('   1. Consensus Means from the Various Methods')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8060)
 8060 FORMAT('   2. Lower 95% Confidence Limit from the ',   &
             'Various Methods')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8062)
 8062 FORMAT('   3. Upper 95% Confidence Limit from the ',   &
             'Various Methods')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,8064)
 8064 FORMAT('The following variables were written to the file ',   &
             'dpst3f.dat:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8058)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8066)
 8066 FORMAT('   2. Standard Uncertainty (k=1) for the Various ',   &
             'Methods')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8068)
 8068 FORMAT('   3. Relative Standard (k=1) Uncertainty ',   &
             '(100*Consensus Mean/Standard Uncertainty)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,8070)
 8070 FORMAT('The following variables were written to the file ',   &
             'dpst4f.dat:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8058)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8072)
 8072 FORMAT('   2. Expanded Uncertainty (k=2) for the Various ',   &
             'Methods')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8074)
 8074 FORMAT('   3. Relative Expanded (k=2) Uncertainty ',   &
             '(100*Consensus Mean/Expanded Uncertainty)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,8075)
 8075 FORMAT('The following variables were written to the file ',   &
             'dpst5f.dat:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8081)
!8081 FORMAT('   1. Maximum Likelihood Weights')
 8081 FORMAT('   1. Consensus Means from Generalized Confidence ',   &
             'Interval Simulations')
      CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,8083)
!8083 FORMAT('   2. Estimate of Tau for Maximum Likelihood')
!CCCC CALL DPWRST('XXX','BUG ')
!
 8099 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IBOBCM=IBOBSV
      IBCPCM=IBCPSV
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAN2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,ISEDF,ABIAS
 9012   FORMAT('IERROR,ISEDF,ABIAS = ',A4,2X,I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPTS,NUMVAR,NLAB,NUMDIG
 9013   FORMAT('NPTS,NUMVAR,NLAB,NUMDIG = ',4I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAN2
      SUBROUTINE DPMAN3(Y1,Y2,Y3,NPTS,NUMVAR,NLAB,   &
                        DAT,X,T,   &
                        AMEAN,ASD,N,   &
                        AMEANF,ASDF,NFULL,NLABF,NPTSF,   &
                        IHLEFT,IHLEF2,IHRIGH,IHRIG2,   &
                        ASM,ASD2,ASD3,   &
                        XGRAND,S2WPOO,SW,   &
                        AMNX,AMXX,   &
                        IWRITE,IOUNI1,   &
                        ICAPSW,ICAPTY,NUMDIG,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE INITIAL SUMMARY TABLES FOR CONSENSUS MEANS
!              COMMAND (FULL DATA CASE).
!     PRINTING--YES
!     SUBROUTINES NEEDED--NONE
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2.
!     UPDATED         --FEBRUARY  2010. USE DPDTA1 AND DPDTA4
!     UPDATED         --JUNE      2010. RETURN VERSIONS OF LAB MEAN AND
!                                       STANDARD DEVIATIONS THAT INCLUDE
!                                       CASES WITH ZERO STANDARD
!                                       DEVIATIONS
!     UPDATED         --OCTOBER   2011. USE "LABID" TO LABEL OUTPUT
!     UPDATED         --JANUARY   2017. OPTION TO SUPPRESS PRINTING
!                                       TABLE (ICMET1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
!
      REAL ATEMP
      REAL RIGHT
      REAL XGRAND
      REAL SW
      REAL S2WPOO
      REAL SDGRAN
      REAL AMNX
      REAL AMXX
      REAL ASM
      REAL ASD2
      REAL ASD3
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
      REAL AMEAN(*)
      REAL ASD(*)
      REAL AMEANF(*)
      REAL ASDF(*)
!
      INTEGER N(*)
      INTEGER NFULL(*)
!
      REAL DAT(*)
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION T(*)
!
      COMMON /MPCOM/ T0, T1
!
      INCLUDE 'DPCOST.INC'
!
      CHARACTER*1 IBASLC
      CHARACTER*4 IRTFMD
      COMMON/COMRTF/IRTFMD
!
      PARAMETER(NUMCLI=6)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*60 ITEXT2(MAXROW,NUMCLI)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      CALL DPCONA(92,IBASLC)
!
      IERROR='NO'
      ISUBN1='DPMA'
      ISUBN2='N3  '
!
      DO 110 JJ=1,NUMCLI
        DO 120 II=1,MAXROW
          ITEXT2(II,JJ)=' '
          NCVALU(II,JJ)=0
  120   CONTINUE
  110 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAN3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NUMVAR
   52   FORMAT('NPTS,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NPTS
          WRITE(ICOUT,56)I,Y1(I),Y2(I),Y3(I)
   56     FORMAT('I,Y1(I),Y2(I),Y3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************************************
!               **  STEP 2.1--                               **
!               **  COMPUTE OVERALL STATISTICS AND COMPUTE   **
!               **  NUMBER OF DISTINCT LABS.                 **
!               **  IF TWO VARIABLES ENTERED, THEN           **
!               **     Y1 = RESPONSE VARIABLE                **
!               **     Y2 = LAB ID VARIABLE                  **
!               **  1) COPY RESPONSE DATA TO "DAT"           **
!               **  2) DETERMINE NUMBER OF DISTINCT LABS     **
!               **  3) SORT RESPONSE (DAT) BY LAB ID         **
!               ***********************************************
!
      CALL MEAN(Y1,NPTS,IWRITE,XGRAND,IBUGA3,IERROR)
      CALL SD(Y1,NPTS,IWRITE,SDGRAN,IBUGA3,IERROR)
      CALL SORTC(Y2,Y1,NPTS,Y2,DAT)
      CALL DISTIN(Y2,NPTS,IWRITE,Y3,NLAB,IBUGA3,IERROR)
!
      IF(IERROR.EQ.'YES')GO TO 9000
!CCCC IF(NLAB.LT.2 .OR. NLAB.GE.NPTS)THEN
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,211)
  211   FORMAT('***** ERROR IN CONSENSUS MEANS ANALYSIS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,212)
  212   FORMAT('      FOR THE TWO VARIABLE SYNTAX OF THE CONSENSUS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,214)
  214   FORMAT('      MEANS COMMAND, THE SECOND VARIABLE IS THE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,216)
  216   FORMAT('      LAB ID VARIABLE.  THE NUMBER OF LABS SHOULD')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,218)
  218   FORMAT('      BE AT LEAST 2 AND LESS THAN THE NUMBER OF')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,220)
  220   FORMAT('      POINTS.  SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,222)NLAB
  222   FORMAT('      NUMBER OF UNIQUE LAB IDS = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,224)NPTS
  224   FORMAT('      TOTAL NUMBER OF POINTS   = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***********************************************
!               **  STEP 2.2--                               **
!               **  COMPUTE THE SUMMARY STATISTICS BY LAB    **
!               **  1) DETERMINE NUMER OF POINTS IN EACH LAB **
!               **  2) MEAN FOR EACH LAB                     **
!               **  3) SD FOR EACH LAB                       **
!               ***********************************************
!
      AMNX=CPUMAX
      AMXX=CPUMIN
      AMNSD=CPUMAX
      AMXSD=CPUMIN
!
      DO 250 I=1,NLAB
        ATEMP=Y3(I)
        N(I)=0
        DO 259 J=1,NPTS
          IF(Y2(J).EQ.ATEMP)THEN
            N(I)=N(I)+1
            Y1(N(I))=DAT(J)
          ENDIF
  259   CONTINUE
!
        IF(N(I).LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,211)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,254)Y3(I)
  254     FORMAT('      LAB ',F10.5,' HAS NO DATA')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSE
          CALL MEAN(Y1,N(I),IWRITE,RIGHT,IBUGA3,IERROR)
          X(I)=DBLE(RIGHT)
          AMEAN(I)=RIGHT
          IF(AMEAN(I).LT.AMNX)AMNX=AMEAN(I)
          IF(AMEAN(I).GT.AMXX)AMXX=AMEAN(I)
          CALL SD(Y1,N(I),IWRITE,ASD(I),IBUGA3,IERROR)
!
          IF(ASD(I).GT.0.0)THEN
            IF(ASD(I).LT.AMNSD)AMNSD=ASD(I)
            IF(ASD(I).GT.AMXSD)AMXSD=ASD(I)
          ENDIF
!
          CALL SDMEAN(Y1,N(I),IWRITE,RIGHT,IBUGA3,IERROR)
          T(I)=DBLE(RIGHT**2)
!
      ENDIF
!
  250 CONTINUE
!
      CALL MEAN(AMEAN,NLAB,IWRITE,ASM,IBUGA3,IERROR)
      CALL SD(AMEAN,NLAB,IWRITE,ASD2,IBUGA3,IERROR)
!
!     COMPUTE:  SQRT{SUM[(YBAR(I) - YGRAND)**2/(N-1)]}
!
      DSUM1=0.0D0
      DO 260 I=1,NLAB
        DTERM1=DBLE(AMEAN(I)) - DBLE(XGRAND)
        DSUM1=DSUM1 + DTERM1**2
  260 CONTINUE
      DTERM1=DSQRT(DSUM1/DBLE(NLAB-1))
      ASD3=REAL(DTERM1)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 270 J=1,NLAB
        DTERM1=DBLE(N(J)-1.0D0)
        DSUM2=DSUM2 + DTERM1*(DBLE(ASD(J))**2)
        DSUM3=DSUM3 + DTERM1
        DTERM1=DBLE(N(J))
        IF(DTERM1.NE.0.0D0)THEN
          DSUM1=DSUM1 + DBLE(ASD(J))**2/DTERM1
        ENDIF
  270 CONTINUE
!
      DTEMP=DSQRT(DSUM1)/DBLE(NLAB)
      S2WPOO=DSUM2/DSUM3
      SW=REAL(DTEMP)
!
      IF(IPRINT.EQ.'OFF' .OR. ICMET1.EQ.'OFF')GO TO 8000
!
      ITITLE='Consensus Means Analysis'
      NCTITL=24
      ITITLZ='(Full Sample Case)'
      NCTITZ=18
!
      ICNT=1
      ITEXT(ICNT)='Data Summary:'
      NCTEXT(ICNT)=13
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IHLEFT
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IHLEF2
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Lab-ID Variable: '
      WRITE(ITEXT(ICNT)(18:21),'(A4)')IHRIGH
      WRITE(ITEXT(ICNT)(22:25),'(A4)')IHRIG2
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(NPTS)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Grand Mean:'
      NCTEXT(ICNT)=11
      AVALUE(ICNT)=XGRAND
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Grand Standard Deviation:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=SDGRAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Labs:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=NLAB
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Minimum Lab Mean:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=AMNX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Maximum Lab Mean:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=AMXX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Minimum Lab SD:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=AMNSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Maximum Lab SD:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=AMXSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Mean of Lab Means:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=ASM
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD of Lab Means:'
      NCTEXT(ICNT)=16
      AVALUE(ICNT)=ASD2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD of Lab Means (wrt to grand mean):'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=ASD3
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Within Lab (pooled) SD:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=SQRT(S2WPOO)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Within Lab (pooled) Variance:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=S2WPOO
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.FALSE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:42)='Table 1: Summary Statistics by Lab'
      NCTITL=34
      NUMLIN=3
      NUMCOL=6
      ITITL2(1,1)=' '
      ITITL2(2,1)='Lab'
      ITITL2(3,1)='ID'
      NCTIT2(1,1)=0
      NCTIT2(2,1)=3
      NCTIT2(3,1)=2
      ITITL2(1,2)=' '
      ITITL2(2,2)=' '
      ITITL2(3,2)='n(i)'
      NCTIT2(1,2)=0
      NCTIT2(2,2)=0
      NCTIT2(3,2)=4
      ITITL2(1,3)=' '
      ITITL2(2,3)=' '
      ITITL2(3,3)='Mean'
      NCTIT2(1,3)=0
      NCTIT2(2,3)=0
      NCTIT2(3,3)=4
      ITITL2(1,4)=' '
      ITITL2(2,4)=' '
      ITITL2(3,4)='Variance'
      NCTIT2(1,4)=0
      NCTIT2(2,4)=0
      NCTIT2(3,4)=8
      ITITL2(1,5)=' '
      ITITL2(2,5)='Standard'
      ITITL2(3,5)='Deviation'
      NCTIT2(1,5)=0
      NCTIT2(2,5)=8
      NCTIT2(3,5)=9
      ITITL2(1,6)='Standard'
      ITITL2(2,6)='Deviation'
      ITITL2(3,6)='of the Mean'
      NCTIT2(1,6)=8
      NCTIT2(2,6)=9
      NCTIT2(3,6)=11
      NMAX=0
      DO 2421 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=8
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 2421 CONTINUE
!
      IWHTML(1)=75
      IWHTML(2)=75
      IWHTML(3)=125
      IWHTML(4)=125
      IWHTML(5)=125
      IWHTML(6)=125
      IWRTF(1)=800
      IWRTF(2)=IWRTF(1)+800
      IWRTF(3)=IWRTF(2)+1440
      IWRTF(4)=IWRTF(3)+1440
      IWRTF(5)=IWRTF(4)+1440
      IWRTF(6)=IWRTF(5)+1440
      IFRST=.FALSE.
      ILAST=.TRUE.
!
!     PRINT OUT 50 LINES AT A TIME
!
      NSTRT=1
      NSTOP=MIN(NLAB,50)
!
 2420 CONTINUE
      IDIGIT(1)=0
      IDIGIT(2)=0
      ICNT=0
      DO 2423 I=NSTRT,NSTOP
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=Y3(I)
        AMAT(ICNT,2)=REAL(N(I))
        AMAT(ICNT,3)=X(I)
        AMAT(ICNT,4)=ASD(I)**2
        AMAT(ICNT,5)=ASD(I)
        AMAT(ICNT,6)=SQRT(T(I))
        DO 2425 J=1,NUMCOL
          NCVALU(ICNT,J)=0
 2425   CONTINUE
 2423 CONTINUE
!
      NLABT=NSTOP-NSTRT+1
      CALL DPDTA4(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  ITEXT,NCVALU,AMAT,ITYPCO,MAXROW,NLABT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
       IF(NSTOP.LT.NLAB)THEN
         NSTRT=NSTOP+1
         NSTOP=NSTRT+50-1
         IF(NSTOP.GT.NLAB)NSTOP=NLAB
         GO TO 2420
       ENDIF
!
      DO 4190 I=1,NLAB
!CCCC   WRITE(IOUNI1,4196)REAL(I),REAL(N(I)),X(I),ASD(I)**2,
        WRITE(IOUNI1,4196)Y3(I),REAL(N(I)),X(I),ASD(I)**2,   &
                          ASD(I),SQRT(T(I))
 4196   FORMAT(F6.0,2X,F6.0,2X,4E15.7)
 4190 CONTINUE
!
!               *************************************
!               **  STEP 80--                      **
!               **  REMOVE ANY LABS WITH LESS THAN **
!               **  TWO OBSERVATIONS               **
!               *************************************
!
 8000 CONTINUE
      ICNT=0
      ICNT2=0
      NLABF=NLAB
      NPTSF=NPTS
      DO 9100 I=1,NLAB
        AMEANF(I)=AMEAN(I)
        ASDF(I)=ASD(I)
        NFULL(I)=N(I)
        IF(ASD(I).GT.0.0)THEN
          ICNT=ICNT+1
          AMEAN(ICNT)=AMEAN(I)
          ASD(ICNT)=ASD(I)
          N(ICNT)=N(I)
          Y3(ICNT)=Y3(I)
          X(ICNT)=X(I)
          T(ICNT)=T(I)
          ICNT2=ICNT2+N(ICNT)
        ELSE
          IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
            WRITE(ICOUT,9201)
 9201       FORMAT('<PRE>')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
            WRITE(ICOUT,9301)IBASLC
 9301       FORMAT(A1,'begin{verbatim}')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
            IRTFMD='VERB'
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          WRITE(ICOUT,9103)I
 9103     FORMAT('LAB ',I8,' HAS A NON-POSITIVE STANDARD DEVIATION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9105)
 9105     FORMAT('THIS LAB WILL BE OMITTED FROM THE ANALYSIS EXCEPT ',   &
                 'FOR')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9107)
 9107     FORMAT('GRAND MEAN, MEAN/MEDIAN OF MEANS, BOB, AND BCP ',   &
                 'METHODS.')
          CALL DPWRST('XXX','WRIT')
!
          IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
            WRITE(ICOUT,9211)
 9211       FORMAT('</PRE>')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
            WRITE(ICOUT,9311)IBASLC
 9311       FORMAT(A1,'end{verbatim}')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
            IRTFMD='OFF'
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
 9100 CONTINUE
      NLAB=ICNT
      NPTS=ICNT2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAN3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPTS,NUMVAR,NLAB
 9013   FORMAT('NPTS,NUMVAR,NLAB = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NLAB
          WRITE(ICOUT,9023)I,AMEAN(I),ASD(I)
 9023     FORMAT('I,AMEAN(I),ASD(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAN3
      SUBROUTINE DPMAN4(Y1,Y2,Y3,PLABID,NLAB,NTOT,NUMVAR,   &
                        DAT,X,T,   &
                        AMEAN,ASD,N,   &
                        AMEANF,ASDF,NFULL,NLABF,NTOTF,   &
                        IHLEFT,IHLEF2,IHRIGH,IHRIG2,IHRI21,IHRI22,   &
                        ASM,ASD2,ASD3,SDGRAN,   &
                        XGRAND,S2WPOO,SW,   &
                        AMNX,AMXX,   &
                        IWRITE,IOUNI1,   &
                        ICAPSW,ICAPTY,NUMDIG,IUNCFL,IDFFL,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE INITIAL SUMMARY TABLES FOR CONSENSUS MEANS
!              COMMAND (SUMMARY DATA CASE).
!     PRINTING--YES
!     SUBROUTINES NEEDED--NONE
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2.
!     UPDATED         --FEBRUARY  2010. USE DPDTA1 AND DPDTA4
!     UPDATED         --JUNE      2010. SOME METHODS CAN ACCOMODATE
!                                       ZERO STANDARD DEVIATIONS
!     UPDATED         --OCTOBER   2011. SUPPORT FOR OPTIONAL LAB-ID
!                                       VARIABLE
!     UPDATED         --OCTOBER   2014. SUPPORT FOR CASE WHERE
!                                       UNCERTAINTY REPORTED RATHER
!                                       THAN SD AND SAMPLE SIZE
!     UPDATED         --JANUARY   2017. OPTION TO SUPPRESS PRINTING
!                                       TABLE (ICMET1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IUNCFL
      CHARACTER*4 IDFFL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 IHRI21
      CHARACTER*4 IHRI22
!
      REAL XGRAND
      REAL SW
      REAL S2WPOO
      REAL SDGRAN
      REAL AMNX
      REAL AMXX
      REAL ASM
      REAL ASD2
      REAL ASD3
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
      REAL PLABID(*)
      REAL AMEAN(*)
      REAL ASD(*)
      REAL AMEANF(*)
      REAL ASDF(*)
!
      INTEGER N(*)
      INTEGER NFULL(*)
!
      REAL DAT(*)
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION T(*)
!
      COMMON /MPCOM/ T0, T1
!
      CHARACTER*4 IRTFMD
      COMMON/COMRTF/IRTFMD
!
      PARAMETER(NUMCLI=6)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*60 ITEXT2(MAXROW,NUMCLI)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT9(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      IUNCFL='OFF'
      IDFFL='OFF'
      ISUBN1='DPMA'
      ISUBN2='N4  '
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAN4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NLAB,NTOT,IOUNI1
   52   FORMAT('NPTS,NTOT,IOUNI1 = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NLAB
          WRITE(ICOUT,56)I,Y1(I),Y2(I),Y3(I),DAT(I)
   56     FORMAT('I,Y1(I),Y2(I),Y3(I),DAT(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***********************************************
!               **  STEP 2.2--                               **
!               **  COMPUTE THE SUMMARY STATISTICS BY LAB    **
!               **  1) DETERMINE NUMER OF POINTS IN EACH LAB **
!               **  2) MEAN FOR EACH LAB                     **
!               **  3) SD FOR EACH LAB                       **
!               ***********************************************
!
!     2014/10: SOME LABS MAY REPORT AN UNCERTAINTY VALUE RATHER THAN
!              A STANDARD DEVIATION.  SPECIFICALLY, IF THE SAMPLE SIZE
!              IS NON-POSITIVE, THEN IT IS ASSUMED THAT THE STANDARD
!              DEVIATION IS AN "UNCERTAINTY" VALUE.  THIS APPROACH
!              ALLOWS A MIX OF "SD/SAMPLE SIZE" AND "UNCERTAINTY".
!              THIS IS USEFUL BECAUSE INTERNAL LABS TYPICALLY HAVE
!              THE RAW STANDARD DEVIATION AND SAMPLE SIZE WHILE
!              EXTERNAL LABS SOMETIMES ONLY REPORT AN UNCERTAINTY
!              VALUE.
!
!              NOTE THAT IN THIS CASE, A NEGATIVE VALUE FOR THE SAMPLE
!              SIZE WILL BE INTERPRETED AS AN "EFFECTIVE DEGREES OF
!              FREEDOM" WHILE A VALUE OF ZERO INDICATES NO EFFECTIVE
!              DEGREES OF FREEDOM ARE AVAILABLE.
!
!              NOTE THAT IF ONE OR MORE LABS ONLY REPORT AN UNCERTATINY
!              VALUE, THEN CERTAIN SUMMARY STATISTICS CANNOT BE COMPUTED.
!
      T0=10000000.D0
      T1=-T0
!
      AMNX=CPUMAX
      AMXX=CPUMIN
      AMNSD=CPUMAX
      AMXSD=CPUMIN
!
      DO 110 JJ=1,NUMCLI
        DO 120 II=1,MAXROW
          ITEXT2(II,JJ)=' '
          NCVALU(II,JJ)=0
          AMAT(II,JJ)=0.0
  120   CONTINUE
  110 CONTINUE
!
      DO 250 I=1,NLAB
!
        X(I)=DBLE(Y1(I))
        IF(X(I).LT.T0) T0=X(I)
        IF(X(I).GT.T1) T1=X(I)
        AMEAN(I)=Y1(I)
        ASD(I)=Y2(I)
        IF(Y3(I).GE.0)THEN
          N(I)=INT(Y3(I)+0.5)
        ELSE
          N(I)=INT(Y3(I)-0.5)
        ENDIF
        IF(NUMVAR.EQ.3)PLABID(I)=REAL(I)
        IF(N(I).LE.0)THEN
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,211)
  211     FORMAT('***** ERROR IN CONSENSUS MEANS ANALYSIS--')
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,254)I
!C254     FORMAT('      LAB ',I8,' HAS NO DATA')
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     IERROR='YES'
!CCCC     GO TO 9000
          IUNCFL='ON'
!CCCC     N(I)=0
        ENDIF
!
        IF(ASD(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,211)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,256)I,ASD(I)
  256     FORMAT('      LAB ',I8,' HAS NEGATIVE STANDARD DEVIATION (',   &
                 G15.7,')')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IF(N(I).EQ.0)THEN
          T(I)=DBLE(ASD(I))**2
          IDFFL='NONE'
        ELSEIF(N(I).LT.0)THEN
          T(I)=DBLE(ASD(I))**2
          IF(IDFFL.NE.'NONE')IDFFL='ON'
        ELSE
          T(I)=DBLE(ASD(I))**2/DBLE(N(I))
        ENDIF
        IF(AMEAN(I).LT.AMNX)AMNX=AMEAN(I)
        IF(AMEAN(I).GT.AMXX)AMXX=AMEAN(I)
!
        IF(ASD(I).GT.0.0)THEN
          IF(ASD(I).LT.AMNSD)AMNSD=ASD(I)
          IF(ASD(I).GT.AMXSD)AMXSD=ASD(I)
        ENDIF
!
  250 CONTINUE
!
      CALL MEAN(AMEAN,NLAB,IWRITE,ASM,IBUGA3,IERROR)
      CALL SD(AMEAN,NLAB,IWRITE,ASD2,IBUGA3,IERROR)
!
!     FOLLOWING COMPUTATIONS ONLY AVAILABLE IF A POSITIVE SAMPLE SIZE
!     IS GIVEN FOR EACH LAB.
!
      IF(IUNCFL.EQ.'OFF')THEN
        DSUM1=0.0D0
        DO 255 I=1,NLAB
          DSUM1=DSUM1 + (DBLE(N(I))/DBLE(NTOT))*DBLE(AMEAN(I))
  255   CONTINUE
        XGRAND=DSUM1
!
        DSUM1=0.0D0
        DO 258 I=1,NLAB
          DSUM1=DSUM1 + DBLE(N(I))*DBLE(ASD(I))
  258   CONTINUE
        SDGRAN=REAL(DSUM1/DBLE(NTOT-NLAB))
!
!       COMPUTE:  SQRT{SUM[(YBAR(I) - YGRAND)**2/(N-1)]}
!
        DSUM1=0.0D0
        DO 260 I=1,NLAB
          DTERM1=DBLE(AMEAN(I)) - DBLE(XGRAND)
          DSUM1=DSUM1 + DTERM1**2
  260   CONTINUE
        DTERM1=DSQRT(DSUM1/DBLE(NLAB-1))
        ASD3=REAL(DTERM1)
!
        DSUM1=0.0D0
        DSUM2=0.0D0
        DSUM3=0.0D0
        DO 270 J=1,NLAB
          DTERM1=DBLE(N(J)-1.0D0)
          DSUM2=DSUM2 + DTERM1*(DBLE(ASD(J))**2)
          DSUM3=DSUM3 + DTERM1
          DSUM1=DSUM1 + DBLE(ASD(J))**2/DBLE(N(J))
  270   CONTINUE
        XJUNK=XGRAND
        DTEMP=DSQRT(DSUM1)/DBLE(NLAB)
        S2WPOO=DSUM2/DSUM3
        SW=REAL(DTEMP)
      ENDIF
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE='Consensus Means Analysis'
      NCTITL=24
      ITITLZ='(Summary Statistics Case)'
      NCTITZ=25
!
      ICNT=1
      ITEXT(ICNT)='Data Summary:'
      NCTEXT(ICNT)=13
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Mean Variable: '
      WRITE(ITEXT(ICNT)(16:19),'(A4)')IHLEFT
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IHLEF2
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='SD Variable: '
      WRITE(ITEXT(ICNT)(14:17),'(A4)')IHRIGH
      WRITE(ITEXT(ICNT)(18:21),'(A4)')IHRIG2
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Size Variable: '
      WRITE(ITEXT(ICNT)(23:26),'(A4)')IHRI21
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IHRI22
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(IUNCFL.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Total Number of Observations:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=REAL(NTOT)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Grand Mean:'
        NCTEXT(ICNT)=11
        AVALUE(ICNT)=XGRAND
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Grand Standard Deviation:'
        NCTEXT(ICNT)=25
        AVALUE(ICNT)=SDGRAN
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Labs:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=NLAB
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Minimum Lab Mean:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=AMNX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Maximum Lab Mean:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=AMXX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Minimum Lab SD:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=AMNSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Maximum Lab SD:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=AMXSD
      IDIGIT(ICNT)=NUMDIG
      IF(IUNCFL.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Within Lab (pooled) SD:'
        NCTEXT(ICNT)=23
        AVALUE(ICNT)=SQRT(S2WPOO)
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Within Lab (pooled) Variance:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=S2WPOO
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Mean of Lab Means:'
        NCTEXT(ICNT)=18
        AVALUE(ICNT)=ASM
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='SD of Lab Means:'
        NCTEXT(ICNT)=16
        AVALUE(ICNT)=ASD2
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT9(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.FALSE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT9,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
      IF(IUNCFL.EQ.'OFF')THEN
        ITITL9=' '
        NCTIT9=0
        ITITLE(1:42)='Table 1: Summary Statistics by Lab'
        NCTITL=34
        NUMLIN=3
        NUMCOL=6
        ITITL2(1,1)=' '
        ITITL2(2,1)='Lab'
        ITITL2(3,1)='ID'
        NCTIT2(1,1)=0
        NCTIT2(2,1)=3
        NCTIT2(3,1)=2
        ITITL2(1,2)=' '
        ITITL2(2,2)=' '
        ITITL2(3,2)='n(i)'
        NCTIT2(1,2)=0
        NCTIT2(2,2)=0
        NCTIT2(3,2)=4
        ITITL2(1,3)=' '
        ITITL2(2,3)=' '
        ITITL2(3,3)='Mean'
        NCTIT2(1,3)=0
        NCTIT2(2,3)=0
        NCTIT2(3,3)=4
        ITITL2(1,4)=' '
        ITITL2(2,4)=' '
        ITITL2(3,4)='Variance'
        NCTIT2(1,4)=0
        NCTIT2(2,4)=0
        NCTIT2(3,4)=8
        ITITL2(1,5)=' '
        ITITL2(2,5)='Standard'
        ITITL2(3,5)='Deviation'
        NCTIT2(1,5)=0
        NCTIT2(2,5)=8
        NCTIT2(3,5)=9
        ITITL2(1,6)='Standard'
        ITITL2(2,6)='Deviation'
        ITITL2(3,6)='of the Mean'
        NCTIT2(1,6)=8
        NCTIT2(2,6)=9
        NCTIT2(3,6)=11
        NMAX=0
        DO 2401 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT9(I)=15
          IF(I.EQ.1 .OR. I.EQ.2)NTOT9(I)=8
          NMAX=NMAX+NTOT9(I)
          IDIGIT(I)=NUMDIG
          ITYPCO(I)='NUME'
 2401   CONTINUE
!
        IWHTML(1)=75
        IWHTML(2)=75
        IWHTML(3)=125
        IWHTML(4)=125
        IWHTML(5)=125
        IWHTML(6)=125
        IWRTF(1)=800
        IWRTF(2)=IWRTF(1)+800
        IWRTF(3)=IWRTF(2)+1440
        IWRTF(4)=IWRTF(3)+1440
        IWRTF(5)=IWRTF(4)+1440
        IWRTF(6)=IWRTF(5)+1440
        IFRST=.TRUE.
        ILAST=.TRUE.
!
!       PRINT OUT 50 LINES AT A TIME
!
        NSTRT=1
        NSTOP=MIN(NLAB,50)
!
 2420   CONTINUE
        IDIGIT(1)=0
        IDIGIT(2)=0
        ICNT=0
        DO 2423 I=NSTRT,NSTOP
          ICNT=ICNT+1
          NCTEXT(ICNT)=0
          AMAT(ICNT,1)=PLABID(I)
          AMAT(ICNT,2)=REAL(N(I))
          AMAT(ICNT,3)=X(I)
          AMAT(ICNT,4)=ASD(I)**2
          AMAT(ICNT,5)=ASD(I)
          AMAT(ICNT,6)=SQRT(T(I))
          DO 2425 J=1,NUMCOL
            NCVALU(ICNT,J)=0
            ITEXT2(ICNT,J)=' '
 2425     CONTINUE
 2423   CONTINUE
!
        NLABT=NSTOP-NSTRT+1
        IF(ICMET1.EQ.'ON')THEN
          CALL DPDTA4(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      ITEXT2,NCVALU,AMAT,ITYPCO,MAXROW,NLABT,   &
                      IDIGIT,NTOT9,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      ISUBRO,IBUGA3,IERROR)
        ENDIF
!
        IF(NSTOP.LT.NLAB)THEN
          NSTRT=NSTOP+1
          NSTOP=NSTRT+50-1
          IF(NSTOP.GT.NLAB)NSTOP=NLAB
          GO TO 2420
        ENDIF
      ELSE
        ITITL9=' '
        NCTIT9=0
        ITITLE(1:42)='Table 1: Summary Statistics by Lab'
        NCTITL=34
        NUMLIN=2
        NUMCOL=4
        ITITL2(1,1)='Lab'
        ITITL2(2,1)='ID'
        NCTIT2(1,1)=3
        NCTIT2(2,1)=2
        ITITL2(1,2)=' '
        ITITL2(2,2)='Mean'
        NCTIT2(1,2)=0
        NCTIT2(2,2)=4
        ITITL2(1,3)=' '
        ITITL2(2,3)='Uncertainty'
        NCTIT2(1,3)=0
        NCTIT2(2,3)=11
        ITITL2(1,4)='Effective'
        ITITL2(2,4)='Deg of Freedom'
        NCTIT2(1,4)=9
        NCTIT2(2,4)=14
        NMAX=0
        DO 2501 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT9(I)=15
          IF(I.EQ.1)NTOT9(I)=8
          NMAX=NMAX+NTOT9(I)
          IDIGIT(I)=NUMDIG
          ITYPCO(I)='NUME'
 2501   CONTINUE
!
        IWHTML(1)=75
        IWHTML(2)=125
        IWHTML(3)=125
        IWRTF(1)=800
        IWRTF(2)=IWRTF(1)+1440
        IWRTF(3)=IWRTF(2)+1440
        IFRST=.TRUE.
        ILAST=.TRUE.
!
!       PRINT OUT 50 LINES AT A TIME
!
        NSTRT=1
        NSTOP=MIN(NLAB,50)
!
 2520   CONTINUE
        IDIGIT(1)=0
        IDIGIT(4)=0
        ICNT=0
        DO 2523 I=NSTRT,NSTOP
          ICNT=ICNT+1
          NCTEXT(ICNT)=0
          AMAT(ICNT,1)=PLABID(I)
          AMAT(ICNT,2)=X(I)
          AMAT(ICNT,3)=SQRT(T(I))
          IF(N(I).GE.0)THEN
            AMAT(ICNT,4)=REAL(N(I)+0.1)
          ELSE
            AVAL=REAL(N(I))
            AVAL=ABS(AVAL)
            AMAT(ICNT,4)=AVAL+0.1
          ENDIF
          DO 2525 J=1,NUMCOL
            NCVALU(ICNT,J)=0
            ITEXT2(ICNT,J)=' '
 2525    CONTINUE
 2523  CONTINUE
!
        NLABT=NSTOP-NSTRT+1
        IF(ICMET1.EQ.'ON')THEN
          CALL DPDTA4(ITITLE,NCTITL,   &
                     ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                     MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                     ITEXT2,NCVALU,AMAT,ITYPCO,MAXROW,NLABT,   &
                     IDIGIT,NTOT9,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                     ICAPSW,ICAPTY,IFRST,ILAST,   &
                     ISUBRO,IBUGA3,IERROR)
        ENDIF
!
        IF(NSTOP.LT.NLAB)THEN
          NSTRT=NSTOP+1
          NSTOP=NSTRT+50-1
          IF(NSTOP.GT.NLAB)NSTOP=NLAB
          GO TO 2520
        ENDIF
      ENDIF
!
      DO 4190 I=1,NLAB
!CCCC   WRITE(IOUNI1,4196)REAL(I),REAL(N(I)),X(I),ASD(I)**2,
        WRITE(IOUNI1,4196)PLABID(I),REAL(N(I)),X(I),ASD(I)**2,   &
                          ASD(I),SQRT(T(I))
 4196   FORMAT(F6.0,2X,F6.0,2X,4E15.7)
 4190 CONTINUE
!
!               *****************************************
!               **  STEP 80--                          **
!               **  REMOVE ANY LABS WITH NON-POSITIVE  **
!               **  UNCERTAINTY                        **
!               *****************************************
!
 8000 CONTINUE
      ICNT=0
      ICNT2=0
      NLABF=NLAB
      NTOTF=NTOT
      DO 9100 I=1,NLAB
        AMEANF(I)=AMEAN(I)
        ASDF(I)=ASD(I)
        NFULL(I)=N(I)
        IF(ASD(I).GT.0.0)THEN
          ICNT=ICNT+1
          AMEAN(ICNT)=AMEAN(I)
          ASD(ICNT)=ASD(I)
          N(ICNT)=N(I)
          PLABID(ICNT)=PLABID(I)
          T(ICNT)=T(I)
          X(ICNT)=X(I)
          ICNT2=ICNT2+N(I)
        ELSE
          IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
            WRITE(ICOUT,9201)
 9201       FORMAT('<PRE>')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
            WRITE(ICOUT,9301)IBASLC
 9301       FORMAT(A1,'begin{verbatim}')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
            IRTFMD='VERB'
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          WRITE(ICOUT,9103)I
 9103     FORMAT('LAB ',I8,' HAS A NON-POSITIVE STANDARD DEVIATION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9105)
 9105     FORMAT('THIS LAB WILL BE OMITTED FROM THE ANALYSIS EXCEPT ',   &
                 'FOR')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,9107)
 9107     FORMAT('METHODS GRAND MEAN, MEAN/MEDIAN OF MEANS, BOB, AND ',   &
                 'BCP.')
          CALL DPWRST('XXX','WRIT')
!
          IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'HTML')THEN
            WRITE(ICOUT,9211)
 9211       FORMAT('</PRE>')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'LATE')THEN
            WRITE(ICOUT,9311)IBASLC
 9311       FORMAT(A1,'end{verbatim}')
            CALL DPWRST('XXX','WRIT')
          ELSEIF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
            IRTFMD='OFF'
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
 9100 CONTINUE
      NLAB=ICNT
      NTOT=ICNT2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAN4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NTOT
 9013   FORMAT('NTOT = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IBUGA3
 9014   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAN4
      SUBROUTINE DPMAN5(NPTS,NLAB,   &
                        XGRAND,XMPS,XMMPS,XMLS,XSE,   &
                        ASM,XGD,XGCI,XDL,XFAIR,XBCP,   &
                        DLOWMP,DHIGMP,DLOWMM,DHIGMM,DLOWML,DHIGML,   &
                        DLOWM2,DHIGM2,   &
                        DLOWBO,DHIGBO,DLOWSE,DHIGSE,DLOWT1,DHIGT1,   &
                        DLOWT2,DHIGT2,DLOWGD,DHIGGD,DLOWGC,DHIGGC,   &
                        DLOWDL,DHIGDL,DLOWD2,DHIGD2,DLOWD3,DHIGD3,   &
                        DLOWD4,DHIGD4,DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
                        DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3,   &
                        DLOWBC,DHIGBC,   &
                        XMEDME,SEMED,   &
                        DLWME0,DHGME0,DLWME1,DHGME1,   &
                        DLWME2,DHGME2,DLWME3,DHGME3,   &
                        SEMPK1,SEMMP1,SEMLK1,SEMLBO,AKUK1,SESUK1,SET2K1,   &
                        SET1K1,SEGDK1,SEDLK1,SEHDK1,SERUK1,SEBOK1,SEGCI,   &
                        SEFWK1,XBCPK1,SEMEDB,ALOWCL,AUPPCL,SEMEK1,   &
                        XH15,SEHMK1,XLP,SELPK1,ALOWLP,AUPPLP,   &
                        IWRITE,IOUNI2,   &
                        ICAPSW,ICAPTY,NUMDIG,IFLAG9,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE THE CONFIDENCE INTERVAL TABLE FOR THE
!              CONSENSUS MEANS COMMAND
!     PRINTING--YES
!     SUBROUTINES NEEDED--NONE
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2
!                                       ROUTINE
!     UPDATED  VERSION--JUNE      2006. ADD FAIRWEATHER, BCP
!     UPDATED  VERSION--FEBRUARY  2010. USE DPDTA4 TO PRINT TABLE
!     UPDATED  VERSION--MAY       2010. MODIFICATIONS TO DERSIMONIAN-LARID
!     UPDATED  VERSION--OCTOBER   2011. DERSIMONIAN-LARID BOOTSTRAP
!     UPDATED  VERSION--OCTOBER   2011. VANGEL-RUKHIN BOOTSTRAP
!     UPDATED  VERSION--OCTOBER   2012. DERSIMONIAN-LARID BOOTSTRAP UPDATES
!     UPDATED  VERSION--OCTOBER   2012. MEDIAN OF MEANS UPDATE
!     UPDATED  VERSION--JUNE      2013. ADD "UNCERTAINTY INTERVAL" TO
!                                       TABLE
!     UPDATED  VERSION--AUGUST    2014. FOR DSL, K FACTOR WAS COMPUTED
!                                       USING MANDEL-PAULE CONSENSUS
!                                       VALUE.  CORRECTED TO USE DSL
!                                       CONSENSUS VALUE.
!     UPDATED  VERSION--JANUARY   2017. OPTION TO SUPPRESS PRINTING
!                                       TABLE (ICMET3)
!     UPDATED  VERSION--MARCH     2017. MEDIAN OF MEANS UPDATE
!     UPDATED  VERSION--MARCH     2017. HUBER H15 MEAN OF MEANS UPDATE
!     UPDATED  VERSION--APRIL     2023. LINEAR POOL UPDATE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      CHARACTER*45 IMETH
!
      REAL XMPS
      REAL XMMPS
      REAL XMLS
      REAL ASM
      REAL XGRAND
      REAL XGD
      REAL XSE
      REAL XGCI
      REAL XDL
      REAL XFAIR
      REAL XBCP
      REAL XMEDME
      REAL SEMED
      REAL SEMPK1
      REAL SEMMP1
      REAL SEMLK1
      REAL SEMLBO
      REAL SEHDK1
      REAL SEGCI
      REAL AKUK1
      REAL SESUK1
      REAL SET2K1
      REAL SET1K1
      REAL SEGDK1
      REAL SEDLK1
      REAL SEFWK1
      REAL XBCPK1
      REAL SEMEDB
      REAL SERUK1
      REAL ALOWCL
      REAL AUPPCL
      REAL SEMEK1
      REAL XH15
      REAL SEHMK1
      REAL XLP
      REAL SELPK1
      REAL ALOWLP
      REAL AUPPLP
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER(MAXLIN=2)
      PARAMETER(MAXROW=20)
      PARAMETER(MAXCOL=5)
      CHARACTER*4  ALIGN(MAXCOL)
      CHARACTER*4  VALIGN(MAXCOL)
      INTEGER      IDIGIT(MAXCOL)
      INTEGER      NTOT(MAXCOL)
      INTEGER      IWHTML(MAXCOL)
      INTEGER      IWRTF(MAXCOL)
      INTEGER      NCTEXT(MAXROW,MAXCOL)
      INTEGER      NCTIT2(MAXLIN,MAXCOL)
      CHARACTER*40 ITITL9
      CHARACTER*40 ITITLE
      CHARACTER*20 ITITL2(MAXLIN,MAXCOL)
      CHARACTER*40 ITEXT(MAXROW,MAXCOL)
      CHARACTER*4  ITYPCO(MAXCOL)
      REAL         AMAT(MAXROW,MAXCOL)
      LOGICAL      IFRST
      LOGICAL      ILAST
      LOGICAL      IFLAG9
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPMA'
      ISUBN2='N5  '
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN5')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAN5--')
        CALL DPWRST('XXX','BUG ')
