!CCCC   NCTEXT(ICNT,1)=39
!CCCC   AMAT(ICNT,ISTRT+1)=0.0
!CCCC   AMAT(ICNT,ISTRT+2)=XMEDME
!CCCC   AMAT(ICNT,ISTRT+3)=DLWME3
!CCCC   AMAT(ICNT,ISTRT+4)=DHGME3
!CCCC   AKL=XMEDME - DLWME3
!CCCC   AKU=DHGME3 - XMEDME
!CCCC   AK=0.0
!CCCC   IF(SEMEDB.NE.0.0)AK=MAX(AKL,AKU)/SEMEDB
!CCCC   AK=MAX(AKL,AKU)
!CCCC   AMAT(ICNT,ISTRT+5)=AK
!CCCC   IMETH='Median of Means (Kernel Bootstrap)'
!CCCC   WRITE(IOUNI2,4001)XMEDME,DLWME3,DHGME3,AK,IMETH
!
      ENDIF
!
      IF(IHUBCM.EQ.'ON' .AND. XH15.NE.CPUMIN)THEN
!
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 15. Huber H15 Mean of Means'
        NCTEXT(ICNT,1)=27
        AMAT(ICNT,ISTRT+1)=0.0
        AMAT(ICNT,ISTRT+2)=XH15
        H15LCL=XH15 - 1.96*SEHMK1
        H15UCL=XH15 + 1.96*SEHMK1
        AMAT(ICNT,ISTRT+3)=H15LCL
        AMAT(ICNT,ISTRT+4)=H15UCL
        AK=XH15 - H15LCL
        AMAT(ICNT,ISTRT+5)=AK
        IMETH='Huber H15 Mean of Means'
        WRITE(IOUNI2,4001)XH15,H15LCL,H15UCL,AK,IMETH
      ENDIF
!
      IF(ILIPCM.EQ.'ON' .AND. XLP.NE.CPUMIN)THEN
!
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 16. Linear Pool'
        NCTEXT(ICNT,1)=16
        AMAT(ICNT,ISTRT+1)=0.0
        AMAT(ICNT,ISTRT+2)=XLP
        AMAT(ICNT,ISTRT+3)=ALOWLP
        AMAT(ICNT,ISTRT+4)=AUPPLP
        AKT1=XLP - ALOWLP
        AKT2=AUPPLP - XLP
        AK=MAX(AKT1,AKT2)
        AMAT(ICNT,ISTRT+5)=AK
        IMETH='Linear Pool'
        WRITE(IOUNI2,4001)XLP,ALOWLP,AUPPLP,AK,IMETH
      ENDIF
!
      NUMCOL=5
      NUMLIN=2
      NUMROW=ICNT
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4091)
 4091   FORMAT('IN DPMAN5 BEFORE CALL DPDTA4:')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4093)MAXCOL,MAXLIN,NUMCOL,NUMLIN,NUMROW
 4093   FORMAT('MAXCOL,MAXLIN,NUMCOL,NUMLIN,NUMROW=',5I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4095)NMAX,NUMDIG
 4095   FORMAT('NMAX,NUMDIG = ',2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IPRINT.EQ.'OFF' .OR. ICMET3.EQ.'OFF')GO TO 9000
!
      CALL DPDTA4(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,MAXCOL,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAN5--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAN5
      SUBROUTINE DPMAN6(NPTS,NLAB,   &
      XGRAND,XMPS,XMMPS,XMLS,XSE,   &
      ASM,XGD,XDL,XGCI,XFAIR,XBCP,   &
      SEMPK1,SEMMP1,SEMLK1,SEMLBO,AKUK1,SESUK1,SET1K1,   &
      SET2K1,SEGDK1,SEDLK1,SEHDK1,SERUK1,SEBOK1,SEGCI,SEFWK1,XBCPK1,   &
      XMEDME,SEMED,SEMEDB,SEMEK1,XH15,SEHMK1,XLP,SELPK1,   &
      IWRITE,   &
      ICAPSW,ICAPTY,IK,IOUNIT,NUMDIG,IFLAG9,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE THE STANDARD AND EXPANDED UNCERTAINTY
!              TABLE FOR THE CONSENSUS MEANS COMMAND
!              (CALLED TWICE: ONCE FOR K = 1 AND ONCE FOR K = 2)
!     PRINTING--YES
!     SUBROUTINES NEEDED--NONE
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2
!                                       ROUTINE
!     UPDATED         --JUNE      2006. USER CAN SELECT WHICH
!                                       METHODS ARE APPLIED
!     UPDATED         --JUNE      2006. ADD FAIRWEATHER AND BCP
!     UPDATED         --FEBRUARY  2010. USE DPDTA4 TO PRINT TABLE
!     UPDATED         --OCTOBER   2012. DERSIMONIAN-LAIRD BOOTSTRAP
!     UPDATED         --OCTOBER   2012. MEDIAN OF MEANS
!     UPDATED         --JANUARY   2017. OPTION TO SUPPRESS PRINTING
!                                       TABLE (ICMET3)
!     UPDATED         --MARCH     2017. UPDATE TO MEDIAN OF MEANS
!     UPDATED         --MARCH     2017. HUBER H15 MEAN OF MEANS
!     UPDATED         --APRIL     2023. LINEAR POOL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICMETZ
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      CHARACTER*8  IUNCT
      CHARACTER*30 IMETH
!
      LOGICAL IFLAG9
!
      REAL XMPS
      REAL XMMPS
      REAL XMLS
      REAL ASM
      REAL XGRAND
      REAL XGD
      REAL XDL
      REAL XGCI
      REAL XSE
      REAL SEMPK1
      REAL SEMMP1
      REAL SEMLK1
      REAL SEMLBO
      REAL SEHDK1
      REAL SEGCI
      REAL AKUK1
      REAL SESUK1
      REAL SET2K1
      REAL SET1K1
      REAL SEGDK1
      REAL SEDLK1
      REAL XFAIR
      REAL SEFWK1
      REAL XBCP
      REAL XBCPK1
      REAL XMEDME
      REAL SEMED
      REAL SEMEDB
      REAL SERUK1
      REAL SEMEK1
      REAL XH15
      REAL SEHMK1
      REAL XLP
      REAL SELPK1
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      CHARACTER*4 IRTFMD
      COMMON/COMRTF/IRTFMD
!
      PARAMETER(MAXLIN=3)
      PARAMETER(MAXROW=20)
      PARAMETER(MAXCOL=4)
      CHARACTER*4  ALIGN(MAXCOL)
      CHARACTER*4  VALIGN(MAXCOL)
      INTEGER      IDIGIT(MAXCOL)
      INTEGER      NTOT(MAXCOL)
      INTEGER      IWHTML(MAXCOL)
      INTEGER      IWRTF(MAXCOL)
      INTEGER      NCTEXT(MAXROW,MAXCOL)
      INTEGER      NCTIT2(MAXLIN,MAXCOL)
      CHARACTER*40 ITITL9
      CHARACTER*40 ITITLE
      CHARACTER*20 ITITL2(MAXLIN,MAXCOL)
      CHARACTER*40 ITEXT(MAXROW,MAXCOL)
      CHARACTER*4  ITYPCO(MAXCOL)
      REAL         AMAT(MAXROW,MAXCOL)
      LOGICAL      IFRST
      LOGICAL      ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPMA'
      ISUBN2='N6  '
!
      IF(IK.EQ.1)THEN
        ICMETZ=ICMET3
      ELSE
        ICMETZ=ICMET4
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN6')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAN6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWRITE,NPTS,NLAB,IOUNIT
   52   FORMAT('IWRITE,NPTS,NLAB,IOUNIT = ',A4,2X,3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)SEMED,SEMEDB
   54   FORMAT('SEMED,SEMEDB = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IK.EQ.1)THEN
        IUNCT='Standard'
      ELSE
        IUNCT='Expanded'
      ENDIF
!
      NCTIT9=0
      ITITL9=' '
      NCTITL=40
      ITITLE(1:NCTITL)='Table x:  xxxxxxxx Uncertainties (k = x)'
      WRITE(ITITLE(7:7),'(I1)')IK+2
      WRITE(ITITLE(11:18),'(A8)')IUNCT
      WRITE(ITITLE(39:39),'(I1)')IK
      NUMLIN=3
      NUMCOL=4
!
      ITITL2(1,1)=' '
      ITITL2(2,1)=' '
      ITITL2(3,1)='Method'
      NCTIT2(1,1)=0
      NCTIT2(2,1)=0
      NCTIT2(3,1)=6
!
      ITITL2(1,2)=' '
      ITITL2(2,2)='Consensus'
      ITITL2(3,2)='Mean'
      NCTIT2(1,2)=0
      NCTIT2(2,2)=9
      NCTIT2(3,2)=4
!
      WRITE(ITITL2(1,3)(1:8),'(A8)')IUNCT
      ITITL2(2,3)='Uncertainty'
      ITITL2(3,3)='(k = x)'
      WRITE(ITITL2(3,3)(6:6),'(I1)')IK
      NCTIT2(1,3)=8
      NCTIT2(2,3)=11
      NCTIT2(3,3)=7
!
      ITITL2(1,4)='Relative'
      WRITE(ITITL2(2,4)(1:8),'(A8)')IUNCT
      ITITL2(3,4)='Uncertainty (%)'
      NCTIT2(1,4)=8
      NCTIT2(2,4)=8
      NCTIT2(3,4)=15
!
      NMAX=0
      NTOT(1)=35
      NTOT(2)=15
      NTOT(3)=15
      NTOT(4)=18
      DO 4010 J=1,MAXCOL
        VALIGN(J)='b'
        ALIGN(J)='r'
        NMAX=NMAX+NTOT(J)
        IDIGIT(J)=NUMDIG
        IWHTML(J)=125
        ITYPCO(J)='NUME'
 4010 CONTINUE
      ITYPCO(1)='ALPH'
      ALIGN(1)='l'
      IWHTML(1)=225
      IWRTF(1)=3800
      IWRTF(2)=IWRTF(1)+1700
      IWRTF(3)=IWRTF(2)+1700
      IWRTF(4)=IWRTF(3)+1700
      IFRST=.TRUE.
      ILAST=.TRUE.
!
!     POPULATE ROWS OF ARRAY.  NOTE THAT SPECIFIC METHODS ARE
!     CONDITIONAL.
!
      ICNT=0
!
      DO 4020 I=1,MAXROW
        DO 4030 J=1,MAXCOL
          AMAT(I,J)=0.0
          NCTEXT(I,J)=0
          ITEXT(I,J)=' '
 4030   CONTINUE
 4020 CONTINUE
!
      IF(IMPACM.EQ.'ON' .AND. XMPS.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  1. Mandel-Paule'
        NCTEXT(ICNT,1)=17
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XMPS
        AMAT(ICNT,3)=SEMPK1
        AMAT(ICNT,4)=100.0*SEMPK1/XMPS
        ATEMP1=100.0*SEMPK1/XMPS
        IMETH='Mandel-Paule'
        WRITE(IOUNIT,4001)XMPS,SEMPK1,ATEMP1,IMETH
 4001   FORMAT(3E15.7,15X,A30)
      ENDIF
!
      IF(IMMPCM.EQ.'ON' .AND. XMMPS.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  2. Modified Mandel-Paule'
        NCTEXT(ICNT,1)=27
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XMMPS
        AMAT(ICNT,3)=SEMMP1
        AMAT(ICNT,4)=100.0*SEMMP1/XMMPS
        ATEMP1=100.0*SEMMP1/XMMPS
        IMETH='Modified Mandel-Paule'
        WRITE(IOUNIT,4001)XMMPS,SEMMP1,ATEMP1,IMETH
      ENDIF
!
      IF(IVRUCM.EQ.'ON' .AND. XMLS.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 3a. Vangel-Rukhin ML'
        NCTEXT(ICNT,1)=21
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XMLS
        AMAT(ICNT,3)=SEMLK1
        AMAT(ICNT,4)=100.0*SEMLK1/XMLS
        ATEMP1=100.0*SEMLK1/XMLS
        IMETH='Vangel-Rukhin ML'
        WRITE(IOUNIT,4001)XMLS,SEMLK1,ATEMP1,IMETH
      ENDIF
!
      IF(IVRBCM.EQ.'ON' .AND. XMLS.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 3b. Vangel-Rukhin (bootstrap)'
        NCTEXT(ICNT,1)=30
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XMLS
        AMAT(ICNT,3)=SEMLBO
        AMAT(ICNT,4)=100.0*SEMLBO/XMLS
        ATEMP1=100.0*SEMLBO/XMLS
        IMETH='Vangel-Rukhin Bootstrap'
        WRITE(IOUNIT,4001)XMLS,SEMLBO,ATEMP1,IMETH
      ENDIF
!
      IF(IDSLCM.EQ.'ON' .AND. XDL.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 4a. DerSimonian-Laird (original)'
        NCTEXT(ICNT,1)=33
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XDL
        AMAT(ICNT,3)=SEDLK1
        AMAT(ICNT,4)=100.0*SEDLK1/XDL
        ATEMP1=100.0*SEDLK1/XDL
        IMETH='DerSimonian-Laird (Original)'
        WRITE(IOUNIT,4001)XDL,SEDLK1,ATEMP1,IMETH
      ENDIF
!
      IF(IDS2CM.EQ.'ON' .AND. XDL.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 4b. DerSimonian-Laird (H-H-D)'
        NCTEXT(ICNT,1)=30
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XDL
        AMAT(ICNT,3)=SEHDK1
        AMAT(ICNT,4)=100.0*SEHDK1/XDL
        ATEMP1=100.0*SEHDK1/XDL
        IMETH='DerSimonian-Laird (HHD)'
        WRITE(IOUNIT,4001)XDL,SEHDK1,ATEMP1,IMETH
      ENDIF
!
      IF(IDS3CM.EQ.'ON' .AND. XDL.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 4c. DerSimonian-Laird (minmax)'
        NCTEXT(ICNT,1)=31
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XDL
        AMAT(ICNT,3)=SERUK1
        AMAT(ICNT,4)=100.0*SERUK1/XDL
        ATEMP1=100.0*SERUK1/XDL
        IMETH='DerSimonian-Laird (Minmax)'
        WRITE(IOUNIT,4001)XDL,SERUK1,ATEMP1,IMETH
      ENDIF
!
      IF(IDS4CM.EQ.'ON' .AND. XDL.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 4d. DerSimonian-Laird (bootstrap)'
        NCTEXT(ICNT,1)=34
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XDL
        AMAT(ICNT,3)=SEBOK1
        AMAT(ICNT,4)=100.0*SEBOK1/XDL
        ATEMP1=100.0*SEBOK1/XDL
        IMETH='DerSimonian-Laird (Bootstrap)'
        WRITE(IOUNIT,4001)XDL,SEBOK1,ATEMP1,IMETH
      ENDIF
!
      IF(IGRDCM.EQ.'ON' .AND. XGD.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  5. Graybill-Deal'
        NCTEXT(ICNT,1)=20
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XGD
        AMAT(ICNT,3)=SEGDK1
        AMAT(ICNT,4)=100.0*SEGDK1/XGD
        ATEMP1=100.0*SEGDK1/XGD
        IMETH='Graybill-Deal'
        WRITE(IOUNIT,4001)XGD,SEGDK1,ATEMP1,IMETH
      ENDIF
!
      IF(IFAICM.EQ.'ON' .AND. IFLAG9 .AND. XFAIR.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  6. Fairweather (Minmax)'
        NCTEXT(ICNT,1)=25
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XFAIR
        AMAT(ICNT,3)=SEFWK1
        AMAT(ICNT,4)=100.0*SEFWK1/XFAIR
        ATEMP1=100.0*SEFWK1/XFAIR
        IMETH='Fairweather'
        WRITE(IOUNIT,4001)XFAIR,SEFWK1,ATEMP1,IMETH
      ENDIF
!
      IF(IGCICM.EQ.'ON' .AND. XGCI.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  7. Generalized CI'
        NCTEXT(ICNT,1)=19
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XGCI
        AMAT(ICNT,3)=SEGCI
        AMAT(ICNT,4)=100.0*SEGCI/XGCI
        ATEMP1=100.0*SEGCI/XGCI
        IMETH='Generalized CI'
        WRITE(IOUNIT,4001)XGCI,SEGCI,ATEMP1,IMETH
      ENDIF
!
      IF(IGMECM.EQ.'ON' .AND. XGRAND.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  8. Grand Mean'
        NCTEXT(ICNT,1)=15
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XGRAND
        AMAT(ICNT,3)=SET1K1
        AMAT(ICNT,4)=100.0*SET1K1/XGRAND
        ATEMP1=100.0*SET1K1/XGRAND
        IMETH='Grand Mean'
        WRITE(IOUNIT,4001)XGRAND,SET1K1,ATEMP1,IMETH
      ENDIF
!
      IF(IMOMCM.EQ.'ON' .AND. ASM.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)='  9. Mean of Means'
        NCTEXT(ICNT,1)=18
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=ASM
        AMAT(ICNT,3)=SET2K1
        AMAT(ICNT,4)=100.0*SET2K1/ASM
        ATEMP1=100.0*SET2K1/ASM
        IMETH='Mean of Means'
        WRITE(IOUNIT,4001)ASM,SET2K1,ATEMP1,IMETH
      ENDIF
!
      IF(IBOBCM.EQ.'ON' .AND. ASM.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 11. BOB'
        NCTEXT(ICNT,1)=8
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=ASM
        AMAT(ICNT,3)=AKUK1
        AMAT(ICNT,4)=100.0*AKUK1/ASM
        ATEMP1=100.0*AKUK1/ASM
        IMETH='Bob'
        WRITE(IOUNIT,4001)ASM,AKUK1,ATEMP1,IMETH
      ENDIF
!
      IF(ISCECM.EQ.'ON' .AND. XSE.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 12. Schiller-Eberhardt'
        NCTEXT(ICNT,1)=23
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XSE
        AMAT(ICNT,3)=SESUK1
        AMAT(ICNT,4)=100.0*SESUK1/XSE
        ATEMP1=100.0*SESUK1/XSE
        IMETH='Schiller-Eberhardt'
        WRITE(IOUNIT,4001)XSE,SESUK1,ATEMP1,IMETH
      ENDIF
!
      IF(IBCPCM.EQ.'ON' .AND. XBCP.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 13. BCP'
        NCTEXT(ICNT,1)=8
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XBCP
        AMAT(ICNT,3)=XBCPK1
        AMAT(ICNT,4)=100.0*XBCPK1/XBCP
        ATEMP1=100.0*XBCPK1/XBCP
        IMETH='BCP'
        WRITE(IOUNIT,4001)XBCP,XBCPK1,ATEMP1,IMETH
      ENDIF
!
      IF(IMEMCM.EQ.'ON' .AND. XMEDME.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 14. Median of Means'
        NCTEXT(ICNT,1)=20
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XMEDME
        AMAT(ICNT,3)=SEMEK1
        AMAT(ICNT,4)=100.0*SEMEK1/XMEDME
        ATEMP1=100.0*SEMEK1/XMEDME
        IMETH='Median of Means'
        WRITE(IOUNIT,4001)XMEDME,SEMEK1,ATEMP1,IMETH
!
!CCCC   ICNT=ICNT+1
!CCCC   ITEXT(ICNT,1)='14b. Median of Means (bootstrap)'
!CCCC   NCTEXT(ICNT,1)=32
!CCCC   AMAT(ICNT,1)=0.0
!CCCC   AMAT(ICNT,2)=XMEDME
!CCCC   AMAT(ICNT,3)=SEMEDB
!CCCC   AMAT(ICNT,4)=100.0*SEMEDB/XMEDME
!CCCC   ATEMP1=100.0*SEMEDB/XMEDME
!CCCC   IMETH='Meidan of Means (Bootstrap)'
!CCCC   WRITE(IOUNIT,4001)XMEDME,SEMEDB,ATEMP1,IMETH
      ENDIF
!
      IF(IHUBCM.EQ.'ON' .AND. XH15.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 15. Huber H15 Mean of Means'
        NCTEXT(ICNT,1)=28
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XH15
        AMAT(ICNT,3)=SEHMK1
        AMAT(ICNT,4)=100.0*SEHMK1/XH15
        ATEMP1=100.0*SEMEK1/XMEDME
        IMETH='Huber H15 Mean of Means'
        WRITE(IOUNIT,4001)XH15,SEHMK1,ATEMP1,IMETH
      ENDIF
!
      IF(ILIPCM.EQ.'ON' .AND. XLP.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT,1)=' 16. Linear Pool'
        NCTEXT(ICNT,1)=16
        AMAT(ICNT,1)=0.0
        AMAT(ICNT,2)=XLP
        AMAT(ICNT,3)=SELPK1
        ATEMP1=100.0*SELPK1/XLP
        AMAT(ICNT,4)=ATEMP1
        IMETH='Linear Pool'
        WRITE(IOUNIT,4001)XLP,SELPK1,ATEMP1,IMETH
      ENDIF
!
      NUMCOL=4
      NUMLIN=3
      NUMROW=ICNT
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      IF(IPRINT.EQ.'OFF' .OR. ICMETZ.EQ.'OFF')GO TO 9000
!
      CALL DPDTA4(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,MAXCOL,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAN6')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMAN6--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAN6
      SUBROUTINE DPMANN(MAXNXT,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT A 2-SAMPLE MANN-WHITNEY RANK SUM TEST
!     EXAMPLE--MANN-WHITNEY RANK SUM TEST Y1 Y2
!              RANK SUM TEST Y1 Y2
!              MANN-WHITNEY RANK SUM TEST Y1 Y2 Y3 Y4
!              MANN-WHITNEY RANK SUM TEST Y1 TO Y10
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/7
!     ORIGINAL VERSION--JULY      1999.
!     UPDATED         --JANUARY   2007.  CALL LIST TO RANK
!     UPDATED         --MAY       2011.  USE DPPARS AND DPPAR3
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
      CHARACTER*4 ICTMP5
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
      DIMENSION YRANK(2*MAXOBV)
      DIMENSION YTEMP(2*MAXOBV)
      DIMENSION XTEMP3(2*MAXOBV)
      EQUIVALENCE(GARBAG(IGARB1),YRANK(1))
      EQUIVALENCE(GARBAG(IGARB3),YTEMP(1))
      EQUIVALENCE(GARBAG(IGARB5),XTEMP3(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='NN  '
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ************************************************
!               **  TREAT THE MANN-WHITNEY RANK SUM TEST CASE  **
!               ************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MANN')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMANN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  EXTRACT THE COMMAND                                **
!               *********************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MANN')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTZ=9999
      ICASAN='MTES'
      ICASA2='TWOT'
!
!     LOOK FOR:
!
!          RANK SUM TEST/MANN-WHITNEY RANK SUM TEST
!          LOWER TAILED
!          UPPER TAILED
!
      DO 100 I=0,NUMARG-1
!
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
        ELSE
          ICTMP1=IHARG(I)
        ENDIF
        ICTMP2=IHARG(I+1)
        ICTMP3=IHARG(I+2)
        ICTMP4=IHARG(I+3)
        ICTMP5=IHARG(I+4)
!
        IF(ICTMP1.EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(ICTMP1.EQ.'MANN' .AND. ICTMP2.EQ.'WHIT' .AND.   &
               ICTMP3.EQ.'RANK' .AND. ICTMP4.EQ.'SUM ' .AND.   &
               ICTMP5.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='MTES'
          ILASTZ=I+4
        ELSEIF(ICTMP1.EQ.'MANN' .AND. ICTMP2.EQ.'WHIT' .AND.   &
               ICTMP3.EQ.'RANK' .AND. ICTMP4.EQ.'SUM ')THEN
          IFOUND='YES'
          ICASAN='MTES'
          ILASTZ=I+3
        ELSEIF(ICTMP1.EQ.'MANN' .AND. ICTMP2.EQ.'WHIT' .AND.   &
               ICTMP3.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='MTES'
          ILASTZ=I+2
        ELSEIF(ICTMP1.EQ.'MANN' .AND. ICTMP2.EQ.'WHIT')THEN
          IFOUND='YES'
          ICASAN='MTES'
          ILASTZ=I+1
        ELSEIF(ICTMP1.EQ.'RANK' .AND. ICTMP2.EQ.'SUM ' .AND.   &
               ICTMP3.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='MTES'
          ILASTZ=I+2
        ELSEIF(ICTMP1.EQ.'RANK' .AND. ICTMP2.EQ.'SUM ')THEN
          IFOUND='YES'
          ICASAN='MTES'
          ILASTZ=I+1
        ELSEIF(ICTMP1.EQ.'LOWE' .AND. ICTMP2.EQ.'TAIL')THEN
          ICASA2='LOWE'
          ILASTZ=MAX(ILASTZ,I+1)
        ELSEIF(ICTMP1.EQ.'UPPE' .AND. ICTMP2.EQ.'TAIL')THEN
          ICASA2='UPPE'
          ILASTZ=MAX(ILASTZ,I+1)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MANN')THEN
        WRITE(ICOUT,91)ICASAN,ICASA2,ISHIFT
   91   FORMAT('DPMANN: ICASAN,ICASA2,ISHIFT = ',   &
               2(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MANN')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='MANN-WHITNEY RANK SUM TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=1
      MINNVA=2
      MAXNVA=MAXSPN
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MANN')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 3A--                                       **
!               **  CASE 1: TWO RESPONSE VARIABLES, NO REPLICATION  **
!               **          HANDLE MULTIPLE RESPONSE VARIABLES      **
!               **          DIFFERENTLY FOR ONE SAMPLE AND TWO      **
!               **          SAMPLE TESTS.                           **
!               ******************************************************
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MANN')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVA2=1
      DO 5210 I=1,NUMVAR
        ICOL=I
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,Y,Y,NS1,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        ISTRT2=I+1
        ISTOP2=NUMVAR
!
        DO 5220 J=ISTRT2,ISTOP2
!
          ICOL=J
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      X,X,X,NS2,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               *******************************************
!               **  STEP 52--                            **
!               **  PERFORM A MANN-WHITNEY RANK SUM TEST **
!               *******************************************
!
          ISTEPN='52'
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MANN')THEN
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5211)
 5211       FORMAT('***** FROM DPMANN, BEFORE CALL DPMNN2--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5212)I,J,NS1,NS2,MAXN
 5212       FORMAT('I,J,NS1,NS2,MAXN = ',5I8)
            CALL DPWRST('XXX','BUG ')
            DO 5215 II=1,MAX(NS1,NS2)
              WRITE(ICOUT,5216)II,Y(II),X(II)
 5216         FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
 5215       CONTINUE
          ENDIF
!
          IVARID=IVARN1(I)
          IVARI2=IVARN2(I)
          IVARI3=IVARN1(J)
          IVARI4=IVARN2(J)
          CALL DPMNN2(Y,NS1,X,NS2,ICASA2,   &
                     YRANK,YTEMP,XTEMP3,MAXNXT,   &
                     ICAPSW,ICAPTY,IFORSW,   &
                     IVARID,IVARI2,IVARI3,IVARI4,   &
                     STATVA,STATCD,ITAB,   &
                     PVAL2T,PVALLT,PVALUT,   &
                     CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                     CTU999,CTU995,CTU990,CT975,CTU950,CTU900,   &
                     CVL001,CVL005,CVL010,CVL025,CVL050,CVL100,   &
                     CVU999,CVU995,CVU990,CVU975,CVU950,CVU900,   &
                     IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MANN')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(NUMVAR.GT.2)THEN
            IFLAGU='FILE'
          ELSE
            IFLAGU='ON'
          ENDIF
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(I.EQ.1 .AND. J.EQ.2)IFRST=.TRUE.
          IF(I.EQ.NUMVAR .AND. J.EQ.NUMVAR)ILAST=.TRUE.
          IF(ITAB.EQ.1)THEN
            CTL001=CVL001
            CTL005=CVL005
            CTL010=CVL010
            CTL025=CVL025
            CTL050=CVL050
            CTL100=CVL100
            CTU999=CVU999
            CTU995=CVU995
            CTU990=CVU990
            CTU975=CVU975
            CTU950=CVU950
            CTU900=CVU900
          ENDIF
          CALL DPMNN5(ICASA2,   &
                      STATVA,STATCD,   &
                      PVAL2T,PVALLT,PVALUT,   &
                      CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                      CTU999,CTU995,CTU990,CT975,CTU950,CTU900,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
 5220   CONTINUE
 5210 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MANN')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMANN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMANN
      SUBROUTINE DPMNN2(Y1,N1,Y2,N2,ICASAN,   &
                        TEMP1,TEMP2,TEMP3,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IVARID,IVARI2,IVARI3,IVARI4,   &
                        STATVA,STATCD,ITAB,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                        CTU999,CTU995,CTU990,CTU975,CTU950,CTU900,   &
                        CVL001,CVL005,CVL010,CVL025,CVL050,CVL100,   &
                        CVU999,CVU995,CVU990,CVU975,CVU950,CVU900,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT A 2-SAMPLE MANN WHITNEY RANK SUM
!              TEST
!
!              NOTE THAT THIS COMPUTES THE W (RANK STATISTIC), NOT THE
!              U STATISTIC THAT SOME PREFER.
!
!     EXAMPLE--RANK SUM TEST Y1 Y2
!              MANN WHITNEY RANK SUM TEST Y1 Y2
!     SAMPLE 1 IS IN INPUT VECTOR Y1
!              (WITH N1 OBSERVATIONS).
!     SAMPLE 2 IS IN INPUT VECTOR Y2
!              (WITH N1 OBSERVATIONS).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/6
!     ORIGINAL VERSION--JUNE      1999.
!     UPDATED         --AUGUST    2002.
!     UPDATED         --JANUARY   2007. CALL LIST TO RANK
!     UPDATED         --MAY       2011. SWITCH FROM WALPOLE/MEYERS
!                                       FORMULATION TO CONOVER
!                                       IMPLEMENTATION SINCE CONOVER HAS
!                                       A MORE COMPLETE SET OF TABLES FOR
!                                       SMALL SAMPLES
!     UPDATED         --MAY       2011. USE DPDTA1, DPDTA5 TO PRINT
!                                       OUTPUT.  REFORMAT OUTPUT
!                                       SOMEWHAT AS WELL.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
!
      PARAMETER (NUMALP=6)
      REAL ALPHA(NUMALP)
      PARAMETER (NUMAL2=4)
      REAL ALPHA2(NUMAL2)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=40)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/0.90, 0.95, 0.975, 0.99, 0.995, 0.999/
      DATA ALPHA2/0.80, 0.90, 0.95, 0.99/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMN'
      ISUBN2='N2  '
      IERROR='NO'
      IWRITE='OFF'
!
      CTL001=0.0
      CTL005=0.0
      CTL010=0.0
      CTL025=0.0
      CTL050=0.0
      CTL100=0.0
      CTU999=0.0
      CTU995=0.0
      CTU990=0.0
      CTU975=0.0
      CTU950=0.0
      CTU900=0.0
      CVL001=0.0
      CVL005=0.0
      CVL010=0.0
      CVL025=0.0
      CVL050=0.0
      CVL100=0.0
      CVL999=0.0
      CVL995=0.0
      CVL990=0.0
      CVL975=0.0
      CVL950=0.0
      CVL900=0.0
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      CTL001=CPUMIN
      CTL005=CPUMIN
      CTL010=CPUMIN
      CTL025=CPUMIN
      CTL050=CPUMIN
      CTL100=CPUMIN
      CTU900=CPUMIN
      CTU950=CPUMIN
      CTU975=CPUMIN
      CTU990=CPUMIN
      CTU995=CPUMIN
      CTU999=CPUMIN
!
      CVL001=CPUMIN
      CVL005=CPUMIN
      CVL010=CPUMIN
      CVL025=CPUMIN
      CVL050=CPUMIN
      CVL100=CPUMIN
      CVU900=CPUMIN
      CVU950=CPUMIN
      CVU975=CPUMIN
      CVU990=CPUMIN
      CVU995=CPUMIN
      CVU999=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MNN2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMNN2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN
   52   FORMAT('IBUGA3,ISUBRO,ICASAN = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)IVARID,IVARI2,IVARI3,IVARI4
   53   FORMAT('IVARID,IVARI2,IVARI3,IVARI4 = ',3(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N1,NUMDIG,D0
   55   FORMAT('N1,NUMDIG,D0 = ',2I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(N1.GE.1)THEN
          DO 56 I=1,N1
            WRITE(ICOUT,57)I,Y1(I),Y2(I)
   57       FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ENDIF
      ENDIF
!
!               ************************************
!               **   STEP 1--                     **
!               **   CALL DPMNN3 TO COMPUTE THE   **
!               **   BASIC TEST STATISTIC (FOR    **
!               **   EITHER 1-SAMPLE OR 2-SAMPLE  **
!               **   CASE).                       **
!               ************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPMNN3(Y1,N1,Y2,N2,   &
                  TEMP1,TEMP2,TEMP3,MAXNXT,   &
                  STATVA,STATV1,STATV2,STATV3,STATCD,NTIES,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  IBUGA3,ISUBRO,IERROR)
      CALL MEAN(Y1,N1,IWRITE,YMEAN1,IBUGA3,IERROR)
      CALL MEDIAN(Y1,N1,IWRITE,TEMP1,MAXNXT,YMED1,IBUGA3,IERROR)
      CALL MEAN(Y2,N2,IWRITE,YMEAN2,IBUGA3,IERROR)
      CALL MEDIAN(Y2,N2,IWRITE,TEMP1,MAXNXT,YMED2,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 21--                        **
!               **  COMPUTE THE CRITICAL VALUES FOR  **
!               **  VARIOUS VALUES OF ALPHA          **
!               ***************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     LARGE SAMPLE NORMAL APPROXIMATION VALUES FIRST
!
      CALL NORPPF(.005,CTL005)
      CALL NORPPF(.010,CTL010)
      CALL NORPPF(.025,CTL025)
      CALL NORPPF(.050,CTL050)
      CALL NORPPF(.100,CTL100)
      CALL NORPPF(.200,CTL200)
      CALL NORPPF(.500,CTL500)
      CALL NORPPF(.500,CTU500)
      CALL NORPPF(.800,CTU800)
      CALL NORPPF(.900,CTU900)
      CALL NORPPF(.950,CTU950)
      CALL NORPPF(.975,CTU975)
      CALL NORPPF(.990,CTU990)
      CALL NORPPF(.995,CTU995)
!
!     NOW GENERATE EXACT CRITICAL VALUES FROM CONOVER TABLES
!     IF THERE ARE NO TIES AND N1 AND N2 ARE BOTH <= 20.
!
      ITAB=0
      IF(NTIES.EQ.0 .AND. N1.LE.20 .AND. N2.LE.20)THEN
        ITAB=1
        CALL DPMNN6(N1,N2,   &
                    CVL001,CVL005,CVL010,CVL025,CVL050,CVL100,   &
                    IBUGA3,ISUBRO)
!
        AN1=REAL(N1)
        AN2=REAL(N2)
        CONST=AN1*(AN1+AN2+1.0)
        CVU999=CONST - CVL001
        CVU995=CONST - CVL005
        CVU990=CONST - CVL010
        CVU975=CONST - CVL025
        CVU950=CONST - CVL050
        CVU900=CONST - CVL100
      ENDIF
!
!               *************************************************
!               **   STEP 22--                                 **
!               **   WRITE OUT EVERYTHING                      **
!               **   FOR A MANN WHITNEY RANK SUM TEST          **
!               *************************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      IF(ICASAN.EQ.'LOWE')THEN
        ITITLE='Two Sample Lower-Tailed Mann Whitney Rank Sum Test'
        NCTITL=50
      ELSEIF(ICASAN.EQ.'UPPE')THEN
        ITITLE='Two Sample Upper-Tailed Mann Whitney Rank Sum Test'
        NCTITL=50
      ELSE
        ITITLE='Two Sample Two-Sided Mann Whitney Rank Sum Test'
        NCTITL=47
      ENDIF
      ITITLZ='(Conover Formulation)'
      NCTITZ=21
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='First Response Variable: '
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(30:33),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Response Variable: '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
      WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI4(1:4)
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: F(x) = G(x)   for all x'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: F(x) <> G(x)  for some x'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations for Sample 1:'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Mean for Sample 1:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=YMEAN1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Median for Sample 1:'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=YMED1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations for Sample 2:'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=REAL(N2)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Mean for Sample 2:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=YMEAN2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Median for Sample 2:'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=YMED2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Tied Ranks:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=REAL(NTIES)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ITAB.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Test (Small Sample, No Ties, Exact):'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Test (Normal Approximation):'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value (W):'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (2-tailed test):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PVAL2T
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (lower-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALLT
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (upper-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALUT
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 2110 I=1,NUMROW
        NTOT(I)=15
 2110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='21A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='21B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ITAB.EQ.0)THEN
        ITITLE='Two-Tailed Test: Normal Approximation'
        NCTITL=37
      ELSE
        ITITLE='Two-Tailed Test: Exact - Small Sample, No Ties'
        NCTITL=46
      ENDIF
      ITITL9='H0: F(x) = G(x); Ha: F(x) <> G(x)  for some x'
      NCTIT9=45
!
      DO 2130 J=1,NUMCLI
        DO 2140 I=1,MAXLIN
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 2140   CONTINUE
 2130 CONTINUE
!
      IF(ITAB.EQ.0)THEN
        NUMCOL=4
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
!
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (+/-)'
        NCTIT2(3,3)=11
!
        ITITL2(1,4)='Null'
        NCTIT2(1,4)=4
        ITITL2(2,4)='Hypothesis'
        NCTIT2(2,4)=10
        ITITL2(3,4)='Conclusion'
        NCTIT2(3,4)=10
!
      ELSE
        NUMCOL=5
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
!
        ITITL2(1,3)='Lower'
        NCTIT2(1,3)=5
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (<)'
        NCTIT2(3,3)=9
!
        ITITL2(1,4)='Upper'
        NCTIT2(1,4)=5
        ITITL2(2,4)='Critical'
        NCTIT2(2,4)=8
        ITITL2(3,4)='Value (>)'
        NCTIT2(3,4)=9
!
        ITITL2(1,5)='Null'
        NCTIT2(1,5)=4
        ITITL2(2,5)='Hypothesis'
        NCTIT2(2,5)=10
        ITITL2(3,5)='Conclusion'
        NCTIT2(3,5)=10
!
      ENDIF
!
      NMAX=0
      DO 2150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(ITAB.EQ.0)THEN
          IF(I.EQ.1 .OR. I.EQ.4)THEN
            ITYPCO(I)='ALPH'
          ENDIF
        ELSE
          IF(I.EQ.1 .OR. I.EQ.5)THEN
            ITYPCO(I)='ALPH'
          ENDIF
        ENDIF
 2150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(3)=175
      IWHTML(4)=175
      IWHTML(5)=175
      IINC=1800
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      IF(ITAB.EQ.0)THEN
        ICNT=NUMAL2
        DO 2160 J=1,NUMAL2
!
          AMAT(J,2)=STATVA
          ALPHAT=ALPHA2(J)
          ATEMP=(1.0 - ALPHAT)/2.0
          ATEMP=1.0 - ATEMP
          CALL NORPPF(ATEMP,CUTTMP)
          AMAT(J,3)=CUTTMP
          IVALUE(J,4)(1:6)='REJECT'
          IF(ABS(STATVA).LT.AMAT(J,3))THEN
            IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
          NCVALU(J,4)=6
!
          WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
          IVALUE(J,1)(5:5)='%'
          NCVALU(J,1)=5
 2160   CONTINUE
      ELSE
        ICNT=NUMAL2
        DO 3160 J=1,ICNT
!
          AMAT(J,2)=STATVA
          ALPHAT=ALPHA2(J)
          IF(J.EQ.1)THEN
            AMAT(J,3)=CVL100
            AMAT(J,4)=CVU900
          ELSEIF(J.EQ.2)THEN
            AMAT(J,3)=CVL050
            AMAT(J,4)=CVU950
          ELSEIF(J.EQ.3)THEN
            AMAT(J,3)=CVL025
            AMAT(J,4)=CVU975
          ELSEIF(J.EQ.4)THEN
            AMAT(J,3)=CVL005
            AMAT(J,4)=CVU995
          ENDIF
          IVALUE(J,5)(1:6)='ACCEPT'
          IF(STATVA.LT.AMAT(J,3))THEN
            IVALUE(J,5)(1:6)='REJECT'
          ELSEIF(STATVA.GT.AMAT(J,4))THEN
            IVALUE(J,5)(1:6)='REJECT'
          ENDIF
          NCVALU(J,5)=6
!
          WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
          IVALUE(J,1)(5:5)='%'
          NCVALU(J,1)=5
 3160   CONTINUE
      ENDIF
!
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
!
      IF(ICASAN.EQ.'TWOT')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASAN.EQ.'LOWE')THEN
!
        IF(ITAB.EQ.0)THEN
          ITITLE='Lower-Tailed Test: Normal Approximation'
          NCTITL=39
        ELSE
          ITITLE='Lower-Tailed Test: Exact - Small Sample, No Ties'
          NCTITL=48
        ENDIF
        ITITL9='H0: F(x) = G(x); Ha: F(x) < G(x)  for some x'
        NCTIT9=44
!
        IF(ITAB.EQ.0)THEN
          ITITL2(2,3)='Critical'
          NCTIT2(2,3)=8
          ITITL2(3,3)='Value (<)'
          NCTIT2(3,3)=9
          NUMCOL=4
        ELSE
          NUMCOL=4
          ITITL2(1,3)='Lower'
          NCTIT2(1,3)=5
          ITITL2(2,3)='Critical'
          NCTIT2(2,3)=8
          ITITL2(3,3)='Value (<)'
          NCTIT2(3,3)=9
!
          ITITL2(1,4)='Null'
          NCTIT2(1,4)=4
          ITITL2(2,4)='Hypothesis'
          NCTIT2(2,4)=10
          ITITL2(3,4)='Conclusion'
          NCTIT2(3,4)=10
        ENDIF
!
        NMAX=0
        DO 2250 I=1,NUMCOL
          NTOT(I)=15
          NMAX=NMAX+NTOT(I)
 2250   CONTINUE
        ITYPCO(4)='ALPH'
!
        IF(ITAB.EQ.0)THEN
          ICNT=NUMALP
          DO 2260 J=1,NUMALP
!
            AMAT(J,2)=STATVA
            ALPHAT=ALPHA(J)
            ATEMP=(1.0 - ALPHAT)
            CALL NORPPF(ATEMP,CUTTMP)
            AMAT(J,3)=CUTTMP
            IVALUE(J,4)(1:6)='ACCEPT'
            IF(ABS(STATVA).LT.AMAT(J,3))THEN
              IVALUE(J,4)(1:6)='REJECT'
            ENDIF
            NCVALU(J,4)=6
            WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
            IVALUE(J,1)(5:5)='%'
            NCVALU(J,1)=5
 2260     CONTINUE
        ELSE
          ICNT=NUMALP
          DO 3260 J=1,ICNT
!
            AMAT(J,2)=STATVA
            ALPHAT=ALPHA(J)
            IF(J.EQ.1)THEN
              AMAT(J,3)=CVL100
            ELSEIF(J.EQ.2)THEN
              AMAT(J,3)=CVL050
            ELSEIF(J.EQ.3)THEN
              AMAT(J,3)=CVL025
            ELSEIF(J.EQ.4)THEN
              AMAT(J,3)=CVL010
            ELSEIF(J.EQ.5)THEN
              AMAT(J,3)=CVL005
            ELSEIF(J.EQ.6)THEN
              AMAT(J,3)=CVL001
            ENDIF
            IVALUE(J,4)(1:6)='ACCEPT'
            IF(STATVA.LT.AMAT(J,3))THEN
              IVALUE(J,5)(1:6)='REJECT'
            ENDIF
            NCVALU(J,4)=6
!
            WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
            IVALUE(J,1)(5:5)='%'
            NCVALU(J,1)=5
 3260     CONTINUE
        ENDIF
!
        NUMLIN=3
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASAN.EQ.'UPPE')THEN
!
        IF(ITAB.EQ.0)THEN
          ITITLE='Upper-Tailed Test: Normal Approximation'
          NCTITL=39
        ELSE
          ITITLE='Upper-Tailed Test: Exact - Small Sample, No Ties'
          NCTITL=48
        ENDIF
        ITITL9='H0: F(x) = G(x); Ha: F(x) > G(x)  for some x'
        NCTIT9=44
!
        IF(ITAB.EQ.0)THEN
          ITITL2(2,3)='Critical'
          NCTIT2(2,3)=8
          ITITL2(3,3)='Value (>)'
          NCTIT2(3,3)=9
          NUMCOL=4
        ELSE
          NUMCOL=4
          ITITL2(1,3)='Upper'
          NCTIT2(1,3)=5
          ITITL2(2,3)='Critical'
          NCTIT2(2,3)=8
          ITITL2(3,3)='Value (>)'
          NCTIT2(3,3)=9
!
          ITITL2(1,4)='Null'
          NCTIT2(1,4)=4
          ITITL2(2,4)='Hypothesis'
          NCTIT2(2,4)=10
          ITITL2(3,4)='Conclusion'
          NCTIT2(3,4)=10
        ENDIF
!
        NMAX=0
        DO 2350 I=1,NUMCOL
          NTOT(I)=15
          NMAX=NMAX+NTOT(I)
 2350   CONTINUE
        ITYPCO(4)='ALPH'
!
        IF(ITAB.EQ.0)THEN
          ICNT=NUMALP
          DO 2360 J=1,NUMALP
!
            AMAT(J,2)=STATVA
            ALPHAT=ALPHA(J)
            ATEMP=ALPHAT
            CALL NORPPF(ATEMP,CUTTMP)
            AMAT(J,3)=CUTTMP
            IVALUE(J,4)(1:6)='ACCEPT'
            IF(ABS(STATVA).GT.AMAT(J,3))THEN
              IVALUE(J,4)(1:6)='REJECT'
            ENDIF
            NCVALU(J,4)=6
            WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
            IVALUE(J,1)(5:5)='%'
            NCVALU(J,1)=5
 2360     CONTINUE
        ELSE
          ICNT=NUMALP
          DO 3360 J=1,ICNT
!
            AMAT(J,2)=STATVA
            ALPHAT=ALPHA(J)
            IF(J.EQ.1)THEN
              AMAT(J,3)=CVL900
            ELSEIF(J.EQ.2)THEN
              AMAT(J,3)=CVL950
            ELSEIF(J.EQ.3)THEN
              AMAT(J,3)=CVL975
            ELSEIF(J.EQ.4)THEN
              AMAT(J,3)=CVL990
            ELSEIF(J.EQ.5)THEN
              AMAT(J,3)=CVL995
            ELSEIF(J.EQ.6)THEN
              AMAT(J,3)=CVL999
            ENDIF
            IVALUE(J,4)(1:6)='ACCEPT'
            IF(STATVA.GT.AMAT(J,3))THEN
              IVALUE(J,5)(1:6)='REJECT'
            ENDIF
            NCVALU(J,4)=6
!
            WRITE(IVALUE(J,1)(1:4),'(F4.1)')100.0*ALPHAT
            IVALUE(J,1)(5:5)='%'
            NCVALU(J,1)=5
 3360     CONTINUE
        ENDIF
!
        NUMLIN=3
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MNN2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMNN2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATV2,STATCD,PVAL2T,PVALLT,PVALUT
 9013   FORMAT('STATVA,STATV2,STATCD,PVAL2T,PVALLT,PVALUT = ',6G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMNN2
      SUBROUTINE DPMNN3(Y1,N1,Y2,N2,   &
                        TEMP1,TEMP2,YRANK,MAXNXT,   &
                        STATVA,STATV1,STATV2,STATV3,STATCD,NTIES,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MANN-WHITNEY 2-SAMPLE RANK
!              SUM TEST STATISTIC AND ASSOCIATED CDF AND P-VALUES.
!
!              THIS PART IS EXTRACTED FROM DPMNN2 IN ORDER TO
!              ALLOW IT TO BE COMPUTED FROM THE "STATISTICS" ROUTINES
!              (E.G., STATISTIC PLOT, BOOTSTRAP).
!
!     EXAMPLE--MANN WHITNEY RANK SUM TEST Y1 Y2
!              SAMPLE 1 IS IN INPUT VECTOR Y1 (WITH N1 OBSERVATIONS)
!              SAMPLE 2 IS IN INPUT VECTOR Y2 (WITH N2 OBSERVATIONS).
!     REFERENCE--CONOVER (1999), "PRACTICAL NONPARAMETRIC STATISTICS",
!                THIRD EDITION, WILEY, PP. 272 - 281.
!              --WALPOLE AND MEYERS (19xx), "ENGINEERING STATISTICS",
!                XX, PP. XX.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/5
!     ORIGINAL VERSION--MAY       2011. EXTRACTED FROM DPMNN2
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION YRANK(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMN'
      ISUBN2='N3  '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=CPUMIN
      STATV1=CPUMIN
      STATV2=CPUMIN
      STATV3=CPUMIN
      STATCD=CPUMIN
      PVAL2T=CPUMIN
      PVALLT=CPUMIN
      PVALUT=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMNN3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MAX(N1,N2)
          WRITE(ICOUT,57)I,Y1(I),Y2(I)
   57     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 01--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='01'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN MANN-WHITNEY RANK SUM TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'FIRST RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE MUST BE 2 OR LARGER.  SUCH WAS NOT THE ',   &
               'CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N1
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS   = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'SECOND RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N2
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y1(1)
      DO 135 I=2,N1
        IF(Y1(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,131)HOLD
  131 FORMAT('      THE FIRST RESPONSE VARIABLE HAS ALL ELEMENTS = ',   &
             G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
      HOLD=Y2(1)
      DO 145 I=2,N1
        IF(Y2(I).NE.HOLD)GO TO 149
  145 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,141)HOLD
  141 FORMAT('      THE SECOND RESPONSE VARIABLE HAS ALL ELEMENTS = ',   &
             G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
  149 CONTINUE
!
!               ************************************
!               **   STEP 11--                    **
!               **   COMPUTE RANK SUM TEST.       **
!               ************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1100 I=1,N1
        TEMP1(I)=Y1(I)
 1100 CONTINUE
      NTOT=N1
      DO 1110 I=1,N2
        NTOT=NTOT+1
        TEMP1(NTOT)=Y2(I)
 1110 CONTINUE
      CALL RANK(TEMP1,NTOT,IWRITE,YRANK,TEMP2,MAXNXT,IBUGA3,IERROR)
!
!     THE COMPUTED TEST STATISTIC DEPENDS ON WHETHER OR NOT THERE ARE
!     NO TIES IN THE RANKS.
!
!        1) CASE WHERE THERE ARE NO TIES:
!
!               T = SUM[i=1 to N1][R(Y1(i))]
!
!            WHERE R() IS THE RANK FROM THE COMBINED SAMPLE
!
!        2) CASE WHERE THERE ARE MANY TIES IN THE DATA:
!
!               T1 = (T - N1*(N1+N2+1)/2)/
!                    SQRT((N1*N2/((N1+N2)*N1+N2-1))*SUM[i=1 to N1+N2][R(i)**2] -
!                    (N1*N2*(N1+N2+1)**2/(4*(N1+N2-1))
!
!     SO CHECK FOR NUMBER OF TIED RANKS.  BASICALLY, IF THE RANK IS
!     A NON-INTEGER VALUE, THIS IMPLIES THAT IT IS A TIED RANK.
!
      ISTEPN='12'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NTIES=0
      RSUM=0.0
      DO 1210 I=1,NTOT
        ARANK=YRANK(I)
        RSUM=RSUM + ARANK**2
        ITEMP=INT(ARANK)
        ATEMP=ARANK - REAL(ITEMP)
        IF(ABS(ATEMP).GE.0.1)THEN
          NTIES=NTIES+1
        ENDIF
 1210 CONTINUE
!
      T=0.0
      DO 1230 I=1,N1
        T=T+YRANK(I)
 1230 CONTINUE
      STATV1=T
      AN1=REAL(N1)
      AN2=REAL(N2)
      AN=REAL(N1 + N2)
      C1=AN1*(AN+1.0)/2.0
      C2=AN1*AN2/(AN*(AN-1.0))
      C3=AN1*AN2*(AN+1.0)**2/(4.0*(AN-1.0))
      T1=(T - C1)/SQRT(C2*RSUM - C3)
      STATV2=T1
      STATV3=AN1*AN2 + 0.5*AN1*(AN1 + 1.0) - T
!
      IF(NTIES.EQ.0 .AND. N1.LE.20 .AND. N2.LE.20)THEN
        STATVA=STATV1
        TP=AN1*(AN + 1.0)*T
        TVAL=MIN(T,TP)
        ANUM=TVAL + 0.5 -AN1*(AN+1.0)/2.0
        ADEN=SQRT(AN1*AN2*(AN+1.0)/12.0)
        AVAL=ANUM/ADEN
        CALL NORCDF(AVAL,CDF)
        PVAL2T=2.0*CDF
        IF(AVAL.LE.0.0)THEN
          PVAL2T=2.0*CDF
        ELSE
          PVAL2T=2.0*(1.0 - CDF)
        ENDIF
        ANUM=T + 0.5 -AN1*(AN+1.0)/2.0
        ADEN=SQRT(AN1*AN2*(AN+1.0)/12.0)
        AVAL=ANUM/ADEN
        CALL NORCDF(AVAL,CDF)
        PVALLT=CDF
        ANUM=TP + 0.5 -AN1*(AN+1.0)/2.0
        ADEN=SQRT(AN1*AN2*(AN+1.0)/12.0)
        AVAL=ANUM/ADEN
        CALL NORCDF(AVAL,CDF)
        PVALUT=CDF
        STATCD=PVALLT
      ELSE
        STATVA=STATV2
        CALL NORCDF(T1,VAL1)
        VAL2=1.0 - VAL1
        PVALLT=VAL1
        PVALUT=VAL2
        STATCD=VAL1
!CCCC   VAL=MIN(VAL1,VAL2)
!CCCC   PVAL2T=2.0*VAL
        IF(T1.LE.0.0)THEN
          PVAL2T=2.0*PVALLT
        ELSE
          PVAL2T=2.0*PVALUT
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MNN3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMNN3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATV1,STATV2,STATV3,STATCD
 9013   FORMAT('STATVA,STATV1,STATV2,STATV3,STATCD = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)PVALLT,PVALUT,PVAL2T
 9014   FORMAT('PVALLT,PVALUT,PVAL2T = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)NTIES,RSUM,C1,C2,C3
 9015   FORMAT('NTIES,RSUM,C1,C2,C3 = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMNN3
      SUBROUTINE DPMNN5(ICASAN,   &
                        STATVA,STATCD,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                        CTU999,CTU995,CTU990,CTU975,CTU950,CTU900,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPMANN TO UPDATE VARIOUS
!              INTERNAL PARAMETERS AFTER A MANN WHITNEY RANK SUM TEST.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/5
!     ORIGINAL VERSION--MAY       2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IFLAGU
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
      SAVE IOUNI1
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MNN5')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMNN5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)STATVA,STATCD,PVAL2T,PVALLT,PVALUT
   53   FORMAT('STATVA,STATCD,PVAL2T,PVALLT,PVALUT = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICASAN
   55   FORMAT('ICASAN = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
!
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          WRITE(IOUNI1,295)
  295     FORMAT(10X,'STATVAL',8X,'STATCDF',   &
                  9X,'PVAL2T',9X,'PVALLT',9X,'PVALUT',   &
                  7X,'CUTLO001',7X,'CUTLO005',7X,'CUTLOW01',   &
                  7X,'CUTLO025',7X,'CUTLOW05',7X,'CUTLOW10',   &
                  7X,'CUTUPP90',7X,'CUTUPP95',7X,'CUTUP975',   &
                  7X,'CUTUPP99',7X,'CUTUP995',7X,'CUTUP999')
        ENDIF
        WRITE(IOUNI1,298)STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                         CTL001,CTL005,CTL010,CTL025,CTL050,CTL100,   &
                         CTU900,CTU950,CTU975,CTU990,CTU995,CTU999
  298   FORMAT(17E15.7)
      ELSEIF(IFLAGU.EQ.'ON')THEN
        IH='STAT'
        IH2='VALU'
        VALUE0=STATVA
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='STAT'
        IH2='CDF '
        VALUE0=STATCD
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='PVAL'
        IH2='UE  '
        VALUE0=PVAL2T
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='PVAL'
        IH2='UELT'
        VALUE0=PVALLT
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='PVAL'
        IH2='UEUT'
        VALUE0=PVALUT
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTU'
        IH2='PP90'
        VALUE0=CTU900
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTL'
        IH2='OW10'
        VALUE0=CTL100
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTU'
        IH2='PP95'
        VALUE0=CTU950
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTL'
        IH2='OW05'
        VALUE0=CTL050
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTU'
        IH2='P975'
        VALUE0=CTU975
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTL'
        IH2='O025'
        VALUE0=CTL025
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTU'
        IH2='PP99'
        VALUE0=CTU990
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTL'
        IH2='OW01'
        VALUE0=CTL010
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTU'
        IH2='P995'
        VALUE0=CTU995
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTL'
        IH2='O005'
        VALUE0=CTL005
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTU'
        IH2='P999'
        VALUE0=CTU999
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='CUTL'
        IH2='O001'
        VALUE0=CTL001
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MNN5')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR
  301       FORMAT('AFTER CALL DPCLFI, IERROR = ',A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MNN5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPMNN5--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMNN5
      SUBROUTINE DPMNN6(N1,N2,   &
                        CVL001,CVL005,CVL010,CVL025,CVL050,CVL100,   &
