!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2 ROUTINE
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!     UPDATED         --FEBRUARY  2010. USE DPDTA1 TO PRINT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL APPF
      REAL ASM
      REAL ASD2
      REAL SET2
      REAL SET2K1
      REAL SET2K2
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPMM'
      ISUBN2='EA  '
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MMEA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NLAB,ASM,ASD2
   52   FORMAT('NPTS,NLAB,ASM,ASD2 = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IWRITE
   54   FORMAT('IWRITE = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      SET2=ASD2/SQRT(REAL(NLAB))
      SET2K1=SET2
      SET2K2=2.0*SET2
      IDF=NLAB-1
      CALL TPPF(0.975,REAL(IDF),APPF)
      DLOWT1=DBLE(ASM - APPF*SET2)
      DHIGT1=DBLE(ASM + APPF*SET2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' 9. Method: Mean of Means'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Mean of Lab Means:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=ASM
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Deviation of Lab Means:'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=ASD2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (sd/sqrt(n)):'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=SET2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    SD of Consensus Mean (sd/sqrt(n)):'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=SET2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SET2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=2.0*SET2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k =           ):'
      WRITE(ITEXT(ICNT)(31:40),'(F10.7)')APPF
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=APPF*SET2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Degrees of Freedom:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(IDF)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='    t Percent Point Value (alpha = 0.05):'
      NCTEXT(ICNT)=41
      AVALUE(ICNT)=APPF
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Lower 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=DLOWT1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Upper 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=DHIGT1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Note: Mean of Means Best Usage:'
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='          Any Number of Labs:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MMEA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMMEA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERRO,NPTS,NLAB
 9013   FORMAT('IERROR,NPTS,NLAB = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)SET1,SET2,DLOWT1,DHIGT1
 9015   FORMAT('SET1,SET2,DLOWT1,DHIGT1 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMMEA
      SUBROUTINE DPMMED(NPTS,NLAB,AMEAN,ASD,   &
                        TEMP1,TEMP2,TEMP3,AINDEX,IINDEX,   &
                        SMOOTH,FT,DTEMP1,   &
                        XMEDME,SEMED,SEMEK1,   &
                        DLOWM0,DHIGM0,DLOWM1,DHIGM1,   &
                        DLOWM2,DHIGM2,DLOWM3,DHIGM3,   &
                        IWRITE,IOUNI5,MAXNXT,   &
                        ICAPSW,ICAPTY,NUMDIG,ISEED,IBOOSS,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--IMPLEMENT:
!
!              1) MEDIAN OF MEANS
!
!              STANDARD ERRORS ARE OBTAINED VIA A BOOTSTRAP METHOD
!     PRINTING--YES
!     SUBROUTINES NEEDED--TPPF
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012/10
!     ORIGINAL VERSION--OCTOBER   2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      REAL AMEAN(*)
      REAL ASD(*)
      REAL TEMP1(*)
      REAL TEMP2(*)
      REAL TEMP3(*)
      REAL AINDEX(*)
!
      DOUBLE PRECISION SMOOTH(*)
      DOUBLE PRECISION FT(*)
      DOUBLE PRECISION DTEMP1(*)
!
      INTEGER IINDEX(*)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASJB
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL XMEDME
      REAL XMED
      REAL XSD
      REAL SEMED
      REAL SEMEK1
      REAL SEMEK2
      REAL ALPHAL
      REAL ALPHAU
      REAL XPERC
      REAL XPERCL
      REAL XPERCU
      REAL XPERC1
      REAL XPERC2
      REAL WIDTH
      REAL P
      REAL ANI
      REAL AN
      REAL A2NI
      REAL REM
      REAL AIQ
      REAL DIFF
      REAL DIFFT
      REAL ALOW
      REAL AUPP
      REAL AK3
      REAL AIVAR
      REAL ALAMB
      REAL ALPHA
      REAL AK
      REAL CDF1
      REAL CDF2
      REAL GK
      REAL GKP1
      REAL AKP
      REAL ANMK
      REAL ANMKP
      REAL P100
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPMM'
      ISUBN2='ED  '
!
      IINDX=0
      ICNT=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MMED')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMMED--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NLAB,ASM,ASD2
   52   FORMAT('NPTS,NLAB,ASM,ASD2 = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,NLAB
          WRITE(ICOUT,62)I,AMEAN(I),ASD(I)
   62     FORMAT('I,AMEAN(I),ASD(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!     STEP 1: COMPUTE THE MEDIAN OF THE MEANS, THE STANDARD ERROR,
!             AND THE HETTMANSPERGER-SHEATHER 95% CONFIDENCE INTERVAL.
!
      CALL MEDIAN(AMEAN,NLAB,IWRITE,TEMP1,MAXNXT,XMEDME,IBUGA3,IERROR)
      P100=0.5
      CALL QUANSE(P100,AMEAN,NLAB,IWRITE,TEMP1,MAXNXT,IQUASE,SEMED,   &
                  IBUGA3,IERROR)
!
      DP=0.5D0
      AN=REAL(NLAB)
      CALL SORT(AMEAN,NLAB,TEMP1)
      ALPHA=(100.0-95.0)/100.
      CALL BINPPF(DBLE(ALPHA/2.0),DP,NLAB,DPPF)
      AK=REAL(DPPF)
      CALL BINCDF(DBLE(AN-AK),DP,NLAB,DCDF)
      CDF1=REAL(DCDF)
      CALL BINCDF(DBLE(AK-1.0),DP,NLAB,DCDF)
      CDF2=REAL(DCDF)
      GK=CDF1-CDF2
      IF(GK.GE.1.0-ALPHA)THEN
        CALL BINCDF(DBLE(AN-AK-1.0),DP,NLAB,DCDF)
        CDF1=REAL(DCDF)
        CALL BINCDF(DBLE(AK-1.0),DP,NLAB,DCDF)
        CDF2=REAL(DCDF)
        GKP1=CDF1-CDF2
        AKP=AK+1.0
      ELSE
        AK=AK-1.0
        CALL BINCDF(DBLE(AN-AK),DP,NLAB,DCDF)
        CDF1=REAL(DCDF)
        CALL BINCDF(DBLE(AK-1.0),DP,NLAB,DCDF)
        CDF2=REAL(DCDF)
        GKP1=CDF1-CDF2
        AKP=AK+1.0
      ENDIF
      ANMK=AN-AK
      ANMKP=ANMK+1.0
      AIVAR=(GK-1.0+ALPHA)/(GK-GKP1)
      ALAMB=((AN-AK)*AIVAR)/(AK+(AN-2.0*AK)*AIVAR)
      DLOWM0=ALAMB*TEMP1(INT(AKP)) + (1.0-ALAMB)*TEMP1(INT(AK))
      DHIGM0=ALAMB*TEMP1(INT(ANMK)) + (1.0-ALAMB)*TEMP1(INT(ANMKP))
!
!     STEP 2: NOW COMPUTE THE STANDARD ERROR BASED ON A NON-PARAMETRIC
!             BOOTSTRAP.
!
      ICASJB='BOOT'
      NRESAM=IBOOSS
!
      IF(IOUNI5.GT.0)THEN
        WRITE(IOUNI5,1009)
 1009   FORMAT('CONSENSUS MEAN ESTIMATES FROM MEDIAN OF MEANS ',   &
               'BOOTSTRAP SAMPLES')
      ENDIF
!
      DO 1100 IRESAM=1,NRESAM
        CALL DPJBS3(AMEAN,NLAB,ICASJB,IJACIN,ISEED,TEMP2,NTEMP,   &
                    IINDEX,AINDEX,   &
                    IBUGA3,IERROR)
        CALL MEDIAN(TEMP2,NTEMP,IWRITE,TEMP1,MAXNXT,XMED,   &
                    IBUGA3,IERROR)
        TEMP3(IRESAM)=XMED
        DTEMP1(IRESAM)=XMED
        IF(IOUNI5.GT.0)WRITE(IOUNI5,'(E15.7)')XMED
!
 1100 CONTINUE
!
!     STEP 3: COMPUTE BOOTSTRAP BASED STANDARD ERRORS
!
!             3 METHODS FOR COMPUTING 95% CONFIDENCE INTERVAL:
!
!             1) PERCENTILE (THESE ARE NOT NECESSARILY SYMMETRIC
!
!             2) SYMMETRIC INTERVALS EASY WAY - TAKE LARGER OF
!                (MEAN - 0.025 PERCENTILE) AND (0.975 PERCENTILE - MEAN)
!
!             3) COMPUTE KERNEL DENSITY ESTIMATE, MOVE OUT FROM MEAN
!                IN EQUAL INCREMENTS UNTIL APPROPRIATE COVERAGE REACHED
!
!     PERCENTILE METHOD
!
      CALL SD(TEMP3,NRESAM,IWRITE,XSD,IBUGA3,IERROR)
      SEMEK1=XSD
      SEMEK2=2.0*XSD
      ALPHAL=100.0*0.025
      ALPHAU=100.0*0.975
!
      CALL PERCEN(ALPHAL,TEMP3,NRESAM,IWRITE,TEMP1,NRESAM,   &
                  XPERC,IBUGA3,IERROR)
      XPERCL=XPERC
      CALL PERCEN(ALPHAU,TEMP3,NRESAM,IWRITE,TEMP1,NRESAM,   &
                  XPERC,IBUGA3,IERROR)
      XPERCU=XPERC
!
      DLOWM1=DBLE(XPERCL)
      DHIGM1=DBLE(XPERCU)
!
!     SIMPLE SYMMETRIC INTERVAL
!
      WIDTH=MAX(ABS(XMEDME - XPERCL),ABS(XPERCU  - XMEDME))
      DLOWM2=DBLE(XMEDME - WIDTH)
      DHIGM2=DBLE(XMEDME + WIDTH)
      AK2=WIDTH/SEMEK1
!
!     NOW GENERATE THE KERNEL DENSITY TRACE
!
      KFLAG=1
      CALL DSORT(DTEMP1,DTEMP1,NRESAM,KFLAG,IERROR)
      DN=REAL(NRESAM)
      DSUM=0.0D0
      DO 11410 I=1,NRESAM
        DSUM=DSUM + DTEMP1(I)
11410 CONTINUE
      DMEAN=DSUM/DN
      DSUM=0.0D0
      DO 11420 I=1,NRESAM
        DX=DTEMP1(I)
        DSUM=DSUM+(DX-DMEAN)**2
11420 CONTINUE
      DVAR=DSUM/(DN-1.0D0)
      DSD=0.0D0
      IF(DVAR.GT.0.0D0)DSD=DSQRT(DVAR)
!
      P=0.25
      AN=REAL(DN)
      ANI=P*(AN+1.0)
      NI=INT(ANI)
      A2NI=REAL(NI)
      REM=ANI-A2NI
      NIP1=NI+1
      IF(NI.LE.1)NI=1
      IF(NI.GE.NRESAM)NI=NRESAM
      IF(NIP1.LE.1)NIP1=1
      IF(NIP1.GE.NRESAM)NIP1=NRESAM
      XPERC1=(1.0-REM)*DTEMP1(NI)+REM*DTEMP1(NIP1)
!
      P=0.75
      ANI=P*(AN+1.0)
      NI=INT(ANI)
      A2NI=REAL(ANI)
      REM=ANI-A2NI
      NIP1=NI+1
      IF(NI.LE.1)NI=1
      IF(NI.GE.NRESAM)NI=NRESAM
      IF(NIP1.LE.1)NIP1=1
      IF(NIP1.GE.NRESAM)NIP1=NRESAM
      XPERC2=(1.0-REM)*DTEMP1(NI)+REM*DTEMP1(NIP1)
      AIQ=(XPERC2-XPERC1)/1.34
      AIQ=ABS(AIQ)
!
      DH=0.9D0*MIN(DSD,DBLE(AIQ))*DN**(-1.0D0/5.0D0)
      DLO=DTEMP1(1) - 3.0D0*DH
      DHI=DTEMP1(NRESAM) + 3.0D0*DH
!
      ICAL=0
      IKENDP=2048
      IERROR='NO'
      CALL DENEST(DTEMP1,NRESAM,DLO,DHI,DH,FT,SMOOTH,IKENDP,ICAL,   &
                  IERROR)
      DIFF=CPUMAX
      DO 11430 I=1,IKENDP
        TEMP1(I)=REAL(SMOOTH(I))
        TEMP3(I)=REAL(DLO + (DBLE(I) - 0.5D0)*(DHI-DLO)/DBLE(IKENDP))
!CCCC   XPLOT(I)=TEMP3(I)
!CCCC   YPLOT(I)=TEMP1(I)
        DIFFT=ABS(TEMP3(I) - XMEDME)
        IF(DIFFT.LT.DIFF)THEN
          IINDX=I
          DIFF=DIFFT
        ENDIF
11430 CONTINUE
      NPLOT=IKENDP
      NUMVAR=2
      CALL CUMINT(TEMP1,TEMP3,IKENDP,NUMVAR,IWRITE,TEMP2,   &
                  IBUGA3,IERROR)
!
!     THE CUMULATIVE INTEGRAL IS NOW IN TEMP2 (AND TEMP4 IS THE
!     X-COORDINATE).  START FROM XMEDME VALUE AND MOVE IN EQUAL
!     INCREMENTS UNTIL SUFFICENT COVERAGE IS OBTAINED.
!
      ICNT=0
      DHIGM3=TEMP3(IKENDP)
      DLOWM3=TEMP3(1)
      DO 11500 I=IINDX,IKENDP
        ICNT=ICNT+1
        IUPP=IINDX+ICNT
        ILOW=IINDX-ICNT
        IF(ILOW.LT.1)GO TO 11509
        AUPP=1.0 - TEMP2(IUPP)
        ALOW=TEMP2(ILOW)
        IF(ALOW+AUPP.LT.0.05)THEN
          DHIGM3=TEMP3(IUPP)
          DLOWM3=TEMP3(ILOW)
          GO TO 11509
        ENDIF
11500 CONTINUE
11509 CONTINUE
!
      WIDTH=REAL(DHIGM3 - DBLE(XMEDME))
      AK3=WIDTH/SEMEK1
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)='14. Method: Median of Means'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Median of Lab Means:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=XMEDME
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Variance of Median of Means:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=SQRT(SEMED)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=2.0*SEMED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Lower 95% Confidence Interval:'
      NCTEXT(ICNT)=34
!CCCC AVALUE(ICNT)=DLOWM0
      AVALUE(ICNT)=XMEDME - 1.96*SEMED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Upper 95% Confidence Interval:'
      NCTEXT(ICNT)=34
!CCCC AVALUE(ICNT)=DHIGM0
      AVALUE(ICNT)=XMEDME + 1.96*SEMED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Bootstrap Uncertainties:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='    Number of Bootstrap Samples:'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=REAL(NRESAM)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='    Variance of Consensus Mean:'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=SEMEK1**2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMEK1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMEK2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=   &
       '    Lower 95% (percentile bootstrap) Confidence Limit:'
      NCTEXT(ICNT)=54
      AVALUE(ICNT)=DLOWM1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=   &
       '    Upper 95% (percentile bootstrap) Confidence Limit:'
      NCTEXT(ICNT)=54
      AVALUE(ICNT)=DHIGM1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=   &
       '    Lower 95% (symmetric bootstrap) Confidence Limit:'
      NCTEXT(ICNT)=53
      AVALUE(ICNT)=DLOWM2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=   &
       '    Upper 95% (symmetric bootstrap) Confidence Limit:'
      NCTEXT(ICNT)=53
      AVALUE(ICNT)=DHIGM2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    K (symmetric bootstrap) Coverage Factor:'
      NCTEXT(ICNT)=44
      AVALUE(ICNT)=AK2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=   &
       '    Lower 95% (kernel bootstrap) Confidence Limit:'
      NCTEXT(ICNT)=50
      AVALUE(ICNT)=DLOWM3
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=   &
       '    Upper 95% (kernel bootstrap) Confidence Limit:'
      NCTEXT(ICNT)=50
      AVALUE(ICNT)=DHIGM3
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    K (kernel bootstrap) Coverage Factor:'
      NCTEXT(ICNT)=41
      AVALUE(ICNT)=AK3
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='    Note: Median of Means Best Usage:'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='          Any Number of Labs:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MMED')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMMED--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERRO,NPTS,NLAB
 9013   FORMAT('IERROR,NPTS,NLAB = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)SET1,SET2,DLOWT1,DHIGT1
 9015   FORMAT('SET1,SET2,DLOWT1,DHIGT1 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMMED
      SUBROUTINE DPMMPL(Y1,Y2,Y3,NPTS,NLAB,   &
      X,T,N,   &
      XMMPS,S2BMMP,SEMMP,SEMMP1,SEMMP2,   &
      DLOWMM,DHIGMM,   &
      IWRITE,   &
      ICAPSW,ICAPTY,NUMDIG,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--IMPLEMENT MODIFIED MANDEL-PAULE APPROACH TO
!              CONSENSUS MEANS
!     WRITTEN BY--CODE FOR MODIFIED MANDEL-PAULE PROVIDED BY
!                 MARK VANGEL.
!     PRINTING--YES
!     SUBROUTINES NEEDED--MPSUB
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2 ROUTINE
!     UPDATED         --FEBRUARY  2010. USE DPDTA1 TO PRINT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL APPF
      REAL XMP
      REAL XMMPS
      REAL S2BMP
      REAL S2BMMP
      REAL SEMMP
      REAL SEMP
      REAL SEMMP1
      REAL SEMMP2
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
!
      INTEGER N(*)
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION T(*)
!
      COMMON /MPCOM/ T0, T1
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPMM'
      ISUBN2='PL  '
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MMPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMMPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NLAB,T0,T1
   52   FORMAT('NPTS,NLAB,T0,T1 = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NLAB
          WRITE(ICOUT,56)I,Y1(I),Y2(I),Y3(I),X(I),T(I),N(I)
   56     FORMAT('I,Y1(I),Y2(I),Y3(I),X(I),T(I),N(I) = ',   &
                 I8,5G15.7,I8)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,59)IWRITE
   59   FORMAT('IWRITE = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IMANPA='MODI'
      CALL MPSUB  (NLAB, N, X, T, DXMP, DS2BMP, IMANPA,IBUGA3)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        DO 102 J=1,NLAB
        WRITE(ICOUT,101)J,T(J)
  101   FORMAT('AFTER MPSUB: J,T(J)=',I8,G15.7)
        CALL DPWRST('XXX','WRIT')
  102   CONTINUE
      ENDIF
!
      XMP=REAL(DXMP)
      S2BMP=REAL(DS2BMP)
!
      CALL NORPPF(0.975,APPF)
      XMPS=(T1-T0)*XMP + T0
      S2BMPS=REAL(((T1-T0)**2)*S2BMP)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 340 J=1,NLAB
        TI=DBLE(S2BMPS) + ((T1-T0)**2)*T(J)
        XJ=(T1-T0)*X(J) + T0
        DSUM1=DSUM1 +  (XJ-DBLE(XMPS))**2/(TI**2)
        DSUM2=DSUM2 + 1.0D0/TI
  340 CONTINUE
      STDERR=SQRT(DSUM1)/DSUM2
      SEMP=REAL(STDERR)
      SEMMP1=SEMP
      SEMMP2=2.0*SEMP
      DLOWER=XMPS - DBLE(APPF)*STDERR
      DUPPER=XMPS + DBLE(APPF)*STDERR
      DLOWMM=DLOWER
      DHIGMM=DUPPER
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' 2. Method: Modified Mandel-Paule'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Estimate of (unscaled) Consensus Mean:'
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=XMPS
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Estimate of (scaled) Consensus Mean:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=XMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Between Lab Variance (unscaled):'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=S2BMPS
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Between Lab SD (unscaled):'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=SQRT(S2BMPS)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Between Lab Variance (scaled):'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=S2BMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Deviation of Consensus Mean:'
      NCTEXT(ICNT)=41
      AVALUE(ICNT)=SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=2.0*SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k =           ):'
      WRITE(ITEXT(ICNT)(31:40),'(F10.7)')APPF
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=APPF*SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Normal PPF of 0.975:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=APPF
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Lower 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=DLOWER
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Upper 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=DUPPER
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Note: Modified Mandel-Paule Best Usage:'
      NCTEXT(ICNT)=43
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='          6 or More Labs:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
 8000 CONTINUE
      XMMPS=REAL(XMPS)
      S2BMMP=REAL(S2BMPS)
      SEMMP=REAL(STDERR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MMPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMMPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPTS,NLAB
 9013   FORMAT('NPTS,NLAB = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)XMMPS,S2BMMP,SEMMP
 9014   FORMAT('XMMPS,S2BMMP,SEMMP = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)DLOWER,DUPPER
 9015   FORMAT('DLOWER,DUPPER = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMMPL
      SUBROUTINE DPMNPL(Y1,Y2,Y3,NPTS,NLAB,   &
                        X,T,N,   &
                        XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                        DLOWMP,DHIGMP,STXMU,ST2SB,   &
                        IWRITE,   &
                        ICAPSW,ICAPTY,NUMDIG,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--IMPLEMENT MANDEL-PAULE APPROACH TO CONSENSUS MEANS
!     WRITTEN BY--CODE FOR MANDEL-PAULE PROVIDED BY MARK VANGEL.
!     PRINTING--YES
!     SUBROUTINES NEEDED--MPSUB
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006. EXTRACTED FROM DPMAN2 ROUTINE
!     UPDATED         --FEBRUARY  2010. USE DPDTA1 TO PRINT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL APPF
      REAL XMP
      REAL XMPS
      REAL S2BMP
      REAL S2BMPS
      REAL STXMU
      REAL ST2SB
      REAL SEMP
      REAL SEMPK1
      REAL SEMPK2
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
!
      INTEGER N(*)
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION T(*)
!
      COMMON /MPCOM/ T0, T1
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPMN'
      ISUBN2='PL  '
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MNPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMNPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NLAB,IWRITE
   52   FORMAT('NPTS,NLAB,IWRITE = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NPTS
          WRITE(ICOUT,56)I,Y1(I),Y2(I),Y3(I)
   56     FORMAT('I,Y1(I),Y2(I),Y3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      IMANPA='REGU'
      CALL MPSUB  (NLAB, N, X, T, DXMP, DS2BMP, IMANPA,IBUGA3)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        DO 102 J=1,NLAB
        WRITE(ICOUT,101)J,T(J)
  101   FORMAT('AFTER MPSUB: J,T(J)=',I8,G15.7)
        CALL DPWRST('XXX','WRIT')
  102   CONTINUE
      ENDIF
!
      XMP=REAL(DXMP)
      S2BMP=REAL(DS2BMP)
!
      CALL NORPPF(0.975,APPF)
      XMPS=REAL((T1-T0)*XMP + T0)
      S2BMPS=REAL(((T1-T0)**2)*S2BMP)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 109 J=1,NLAB
        TI=DBLE(S2BMPS) + ((T1-T0)**2)*T(J)
        XJ=(T1-T0)*X(J) + T0
        DSUM1=DSUM1 +  (XJ-DBLE(XMPS))**2/(TI**2)
        DSUM2=DSUM2 + 1.0D0/TI
  109 CONTINUE
!
      STDERR=SQRT(DSUM1)/DSUM2
      SEMP=REAL(STDERR)
      SEMPK1=SEMP
      SEMPK2=2.0*SEMP
      DLOWER=XMPS - DBLE(APPF)*STDERR
      DUPPER=XMPS + DBLE(APPF)*STDERR
      DLOWMP=DLOWER
      DHIGMP=DUPPER
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' 1. Method: Mandel-Paule'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Estimate of (unscaled) Consensus Mean:'
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=XMPS
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Estimate of (scaled) Consensus Mean:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=XMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Between Lab Variance (unscaled):'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=S2BMPS
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Between Lab SD (unscaled):'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=SQRT(S2BMPS)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Between Lab Variance (scaled):'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=S2BMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Deviation of Consensus Mean:'
      NCTEXT(ICNT)=41
      AVALUE(ICNT)=SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=2.0*SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k =           ):'
      WRITE(ITEXT(ICNT)(31:40),'(F10.7)')APPF
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=APPF*SEMP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Normal PPF of 0.975:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=APPF
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Lower 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=DLOWER
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Upper 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=DUPPER
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Note: Mandel-Paule Best Usage:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='          6 or More Labs:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
 8000 CONTINUE
      STXMU = DXMP
      ST2SB = DS2BMP
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MNPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMNPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPTS,NLAB
 9013   FORMAT('NPTS,NLAB = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)XMPS,S2BMPS,SEMP
 9014   FORMAT('XMPS,S2BMPs,SEMP = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)DLOWER,DUPPER
 9015   FORMAT('DLOWER,DUPPER = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMNPL
      SUBROUTINE DPMARG(IHARG,IARGT,ARG,NUMARG,PDEFMR,PTEXMR,   &
                        IBUGD2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MARGIN FOR TEXT CHARACTERS.
!              THE MARGIN FOR TEXT CHARACTERS WILL BE PLACED
!              IN THE FLOATING POINT VARIABLE PTEXMR.
!     NOTE--THE MARGIN IS IN STANDARDIZED UNITS (0.0 TO 100.0).
!     NOTE--THE MARGIN DOES NOT INCLUDE BETWEEN-LINE GAP.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --IARGT
!                     --ARG
!                     --NUMARG
!                     --PDEFMR
!                     --IBUGD2
!     OUTPUT ARGUMENTS--PTEXMR
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGD2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMARG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)PDEFMR
   53 FORMAT('PDEFMR = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMARG
   54 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I),IARGT(I),ARG(I)
   56 FORMAT('I,IHARG(I),IARGT(I),ARG(I) = ',I8,2X,A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               *****************************
!               **  TREAT THE MARGIN CASE  **
!               *****************************
!
      IF(NUMARG.LE.0)GO TO 1150
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'?')GO TO 8100
!
      IF(NUMARG.GE.1.AND.IARGT(NUMARG).EQ.'NUMB')   &
      GO TO 1160
!
      IERROR='YES'
      WRITE(ICOUT,1121)
 1121 FORMAT('***** ERROR IN DPMARG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('      ILLEGAL FORM FOR MARGIN ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1124)
 1124 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('      SUPPOSE IT IS DESIRED (AFTER THE TEXT COMMAND)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('      THAT THE CURSOR RETURN TO X = 5')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)
 1127 FORMAT('      (WHERE THE HORIZONTAL SCREEN UNITS RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1128)
 1128 FORMAT('      FROM 0 TO 100,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1130)
 1130 FORMAT('      THEN THE ALLOWABLE FORM IS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)
 1131 FORMAT('           MARGIN 5 ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1150 CONTINUE
      PTEXMR=PDEFMR
      GO TO 1180
!
 1160 CONTINUE
      PTEXMR=ARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE MARGIN (AFTER TEXT IS WRITTEN OUT)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)PTEXMR
 1182 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
!               ********************************************
!               **  STEP 81--                             **
!               **  TREAT THE    ?    CASE--              **
!               **  DUMP OUT CURRENT AND DEFAULT VALUES.  **
!               ********************************************
!
 8100 CONTINUE
      IFOUND='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8111)PTEXMR
 8111 FORMAT('THE CURRENT (TEXT) MARGIN IS ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8112)PDEFMR
 8112 FORMAT('THE DEFAULT (TEXT) MARGIN IS ',E15.7)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGD2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMARG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGD2,ISUBRO,IFOUND,IERROR
 9012 FORMAT('IBUGD2,ISUBRO,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)PTEXMR
 9013 FORMAT('PTEXMR = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMARG
