      IUPFLG='SUBS'
      ISUBN1='DPMA'
      ISUBN2='TC  '
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      ILOCR(1)=ILOCV
      DO 10 I=2,MAXCAS
        ILOCR(I)=ILOCR(I-1)+1
        ITYPA(I)='VARI'
        TEMPS(I)=(-999.0)
        ILISR(I)=(-999)
        ICOLR(I)=(-999)
        NIRIGH(I)=(-999)
   10 CONTINUE
      DO 15 I=2,MAXCA2
        NEWNAM(I)='NO'
        ILISL(I)=(-999)
        ICOLL(I)=(-999)
   15 CONTINUE
!
      DO 20 I=1,MAXOBV
        ISUB(I)=1
   20 CONTINUE
