      NUMVAL=1
      SCAL91=(-999.0)
      NITEM2=0
      NITEM3=0
      NITEM4=0
      NITEM5=0
      NITEM5=0
      NS99=-99
      NREPL=-99
      NIFOR=-99
      ICOLRP=-99
      IJUNK1=-99
