!
      IMATSW='NO'
      ICASMT='INDE'
      ITYP91='VECT'
      ITYP92='VECT'
      ITYP93='VECT'
!
!               ******************************************************
!               **  TREAT THE SUBCASE OF PERFORMING CERTAIN SPECIAL **
!               **  DATA MANIPULATIONS (SORT, RANK, CODE)           **
!               **       1) FOR A FULL VARIABLE, OR                 **
!               **       2) FOR PART OF A VARIABLE.                 **
!               ******************************************************
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMATC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA3,IBUGQ,ISUBRO = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASL7,ICASS7,IFTEXP,ILOCV,NUMARG
   53   FORMAT('ICASL7,ICASS7,IFTEXP,ILOCV,NUMARG = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      ENDIF
!
!     ***************************************************************
!     **  STEP 2A--                                                 *
!     **  EXAMINE THE LEFT-HAND SIDE--                              *
!     **  IS THE VARIABLE NAME TO LEFT OF = SIGN                    *
!     **  ALREADY IN THE NAME LIST?    AS A VARIABLE?               *
!     **  NOTE THAT     ILEFT(I)   IS THE NAME OF THE VARIABLE      *
!     **  ON THE LEFT.                                              *
!     **  NOTE THAT     ILISL(I)  IS THE LINE IN THE TABLE          *
!     **  OF THE NAME ON THE LEFT.                                  *
!     **  NOTE THAT     ICOLL(I)  IS THE DATA COLUMN (1 TO 12)      *
!     **  FOR THE NAME OF THE LEFT.                                 *
!     ***************************************************************
!
      ICASEZ=1
      CALL DPMAT6(ICASL7,ICASEZ,MAXCA2,   &
                  ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                  NUMVAL,NIOLD,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 19000
!
!     FEBRUARY 2006: THE REPLACE COMMAND REQUIRES THAT THE
!                    LEFT-HAND SIDE VARIABLE ALREADY EXISTS.
!
!     AUGUST   2016: THE UNSTACK COMMAND USES THE LEFT-HAND SIDE
!                    VARIABLE AS A "BASE NAME".
!
      IF(ICASL7.EQ.'REPL')THEN
        IF(NEWNAM(ICASEZ).EQ.'YES')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,103)
  103     FORMAT('      THE FIRST VARIABLE ON THE LEFT-HAND SIDE OF')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,105)ILEFT(ICASEZ),ILEF2(ICASEZ)
  105     FORMAT('      THE EQUAL SIGN, (',A4,A4,'), MUST ALREADY ',   &
                 'EXIST.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,107)
  107     FORMAT('      SUCH WAS NOT THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSE
          NILEF1=NIOLD
        ENDIF
      ENDIF
!
      IF(ICASL7.EQ.'FOUT'.OR.ICASL7.EQ.'FOU1'.OR.   &
         ICASL7.EQ.'IFOU'.OR.ICASL7.EQ.'IFO1'.OR.   &
         ICASL7.EQ.'FFT' .OR.ICASL7.EQ.'BINN'.OR.   &
         ICASL7.EQ.'BINR'.OR.ICASL7.EQ.'CUMH'.OR.   &
         ICASL7.EQ.'BINP'.OR.ICASL7.EQ.'BIRP'.OR.   &
         ICASL7.EQ.'ASHR'.OR.ICASL7.EQ.'ASHC'.OR.   &
         ICASL7.EQ.'FFT1'.OR.ICASL7.EQ.'NKDM'.OR.   &
         ICASL7.EQ.'IFFT'.OR.ICASL7.EQ.'IFF1'.OR.   &
         ICASL7.EQ.'COAD'.OR.ICASL7.EQ.'COSU'.OR.   &
         ICASL7.EQ.'COMU'.OR.ICASL7.EQ.'CODI'.OR.   &
         ICASL7.EQ.'COEX'.OR.ICASL7.EQ.'COSR'.OR.   &
         ICASL7.EQ.'CORO'.OR.ICASL7.EQ.'COR1'.OR.   &
         ICASL7.EQ.'COCO'.OR.ICASL7.EQ.'PODI'.OR.   &
         ICASL7.EQ.'SECP'.OR.ICASL7.EQ.'FRAC'.OR.   &
         ICASL7.EQ.'STAC'.OR.ICASL7.EQ.'RSTA'.OR.   &
         ICASL7.EQ.'CFRT'.OR.ICASL7.EQ.'HCO2'.OR.   &
         ICASL7.EQ.'MWUF'.OR.ICASL7.EQ.'JOIN'.OR.   &
         ICASL7.EQ.'IFRT'.OR.ICASL7.EQ.'AGCO'.OR.   &
         ICASL7.EQ.'EBLL'.OR.ICASL7.EQ.'EBUL'.OR.   &
         ICASL7.EQ.'BRAT'.OR.ICASL7.EQ.'EBCL'.OR.   &
         ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
         ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'EQUF'.OR.   &
         ICASL7.EQ.'IQUF'.OR.ICASL7.EQ.'TIQF'.OR.   &
         ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
         ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'NNE3'.OR.   &
         ICASL7.EQ.'FNNE'.OR.ICASL7.EQ.'ANNE'.OR.   &
         ICASL7.EQ.'TPOI'.OR.ICASL7.EQ.'EXTP'.OR.   &
         ICASL7.EQ.'ENCB'.OR.ICASL7.EQ.'INTL'.OR.   &
         ICASL7.EQ.'PARL'.OR.ICASL7.EQ.'PERL'.OR.   &
         ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
         ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
         ICASL7.EQ.'2DCH'.OR.ICASL7.EQ.'EDGV'.OR.   &
         ICASL7.EQ.'2DCH'.OR.ICASL7.EQ.'EDGV'.OR.   &
         ICASL7.EQ.'SPF1'.OR.ICASL7.EQ.'SPF2'.OR.   &
         ICASL7.EQ.'KCO2'.OR.ICASL7.EQ.'SRTB'.OR.   &
         ICASL7.EQ.'CYTB'.OR.ICASL7.EQ.'DPCL'.OR.   &
         ICASL7.EQ.'SOR2'.OR.ICASL7.EQ.'SOR3'.OR.   &
         ICASL7.EQ.'TMIN'.OR.ICASL7.EQ.'TMAX'.OR.   &
         ICASL7.EQ.'SOR4'.OR.ICASL7.EQ.'PEAK'.OR.   &
         ICASL7.EQ.'2DGR'.OR.ICASL7.EQ.'3DGR'.OR.   &
         ICASL7.EQ.'4DGR'.OR.ICASL7.EQ.'DREG'.OR.   &
         ICASL7.EQ.'CBIN'.OR.ICASL7.EQ.'CBIR'.OR.   &
         ICASL7.EQ.'JSCT'.OR.ICASL7.EQ.'WSAT'.OR.   &
         ICASL7.EQ.'YFRA'.OR.ICASL7.EQ.'XFRA'.OR.   &
         ICASL7.EQ.'GSQD'.OR.ICASL7.EQ.'GSQS'.OR.   &
         ICASL7.EQ.'GSQP'.OR.ICASL7.EQ.'GSQM'.OR.   &
         ICASL7.EQ.'GQMN'.OR.ICASL7.EQ.'GQMX'.OR.   &
         ICASL7.EQ.'GSQL'.OR.ICASL7.EQ.'GSQU'.OR.   &
         ICASL7.EQ.'SRNP'.OR.ICASL7.EQ.'PSCO'.OR.   &
         ICASL7.EQ.'NEPA'.OR.ICASL7.EQ.'NEXE')THEN
!
        ICASEZ=2
        CALL DPMAT6(ICASL7,ICASEZ,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(ICASL7.EQ.'CFRT' .OR. ICASL7.EQ.'RSTA' .OR.   &
         ICASL7.EQ.'IFRT' .OR. ICASL7.EQ.'EDGV' .OR.   &
         ICASL7.EQ.'R1TS' .OR. ICASL7.EQ.'R1LT' .OR.   &
         ICASL7.EQ.'R1UT' .OR. ICASL7.EQ.'MWUF' .OR.   &
         ICASL7.EQ.'R2TS' .OR. ICASL7.EQ.'R2LT' .OR.   &
         ICASL7.EQ.'R2UT' .OR. ICASL7.EQ.'BRAT' .OR.   &
         ICASL7.EQ.'R3TS' .OR. ICASL7.EQ.'R3LT' .OR.   &
         ICASL7.EQ.'R3UT' .OR. ICASL7.EQ.'BPSE' .OR.   &
         ICASL7.EQ.'SOR3' .OR. ICASL7.EQ.'SOR4' .OR.   &
         ICASL7.EQ.'3DGR' .OR. ICASL7.EQ.'4DGR'.OR.   &
         ICASL7.EQ.'RAN3' .OR. ICASL7.EQ.'DPCL' .OR.   &
         ICASL7.EQ.'HCO2' .OR. ICASL7.EQ.'KCO2' .OR.   &
         ICASL7.EQ.'CBIN' .OR. ICASL7.EQ.'CBIR' .OR.   &
         ICASL7.EQ.'JOIN' .OR. ICASL7.EQ.'JSCT' .OR.   &
         ICASL7.EQ.'FNNE' .OR. ICASL7.EQ.'ANNE' .OR.   &
         ICASL7.EQ.'SPF1' .OR. ICASL7.EQ.'SPF2')THEN
        ICASEZ=3
        CALL DPMAT6(ICASL7,ICASEZ,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(ICASL7.EQ.'SPF2'.OR.ICASL7.EQ.'SOR4'.OR.   &
         ICASL7.EQ.'4DGR'.OR. ICASL7.EQ.'ANNE')THEN
        ICASEZ=4
        CALL DPMAT6(ICASL7,ICASEZ,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(ICASL7.EQ.'ANNE')THEN
        ICASEZ=5
        CALL DPMAT6(ICASL7,ICASEZ,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,491)NUMVAL
  491   FORMAT('AT THE END OF STEP 2--NUMVAL=',I8)
        CALL DPWRST('XXX','BUG ')
        DO 494 I=1,MAXCA2
        WRITE(ICOUT,492)ILEFT(I),ILEF2(I),NEWNAM(I),NUMNAM,   &
                        ILISL(I),NUMCOL,ICOLL(I),NIOLD
        CALL DPWRST('XXX','BUG ')
  492   FORMAT('ILEFT(I),ILEFT(I),NEWNAM(I),NUMNAM,ILISL(I),',   &
               'NUMCOL,ICOLL(I),NIOLD = ',A4,A4,2X,A4,2X,5I8)
  494   CONTINUE
      ENDIF
!
!     ****************************************************************
!     **  STEP 4--                                                   *
!     **  EXAMINE THE RIGHT-HAND SIDE--                              *
!     **  HAS EACH VARIABLE ON THE RIGHT                             *
!     **  ALREADY BEEN DEFINED?                                      *
!     **  NOTE THAT     ILISR(1), ILISR(2), ILISR(3), ILISR(4)       *
!     **  IS THE LINE IN THE TABLE                                   *
!     **  OF THE FIRST, SECOND, THIRD, FOURTH VARIABLE ON THE RIGHT, *
!     **  RESPECTIVELY.                                              *
!     **  NOTE THAT     ICOLR(1), ICOLR(2), ICOLR(3), ICOLR(4)       *
!     **  IS THE DATA COLUMN (1 TO 10+6)                             *
!     **  OF THE FIRST, SECOND, THIRD, FOURTH VARIABLE ON THE RIGHT, *
!     **  RESPECTIVELY.                                              *
!     ****************************************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ********************************************
!               **  STEP 4.1--                            **
!               **  DETERMINE THE NUMBER OF VARIABLES     **
!               **  ON THE RIGHT--1, 2, 3, OR 4           **
!               ********************************************
!
      ISTEPN='4.1'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMATSW='NO'
      NUMVAR=1
!
      IF(ICASL7.EQ.'Y1TS'.OR.ICASL7.EQ.'Y1TD'.OR.   &
         ICASL7.EQ.'Y2TS'.OR.ICASL7.EQ.'Y2TD'.OR.   &
         ICASL7.EQ.'X1TS'.OR.ICASL7.EQ.'X1TD'.OR.   &
         ICASL7.EQ.'X2TS'.OR.ICASL7.EQ.'X2TD')THEN
        NUMVAR=0
      ENDIF
      IF(ICASL7.EQ.'FOU1'.OR.ICASL7.EQ.'IFO1'.OR.   &
         ICASL7.EQ.'BINN'.OR.ICASL7.EQ.'BINR'.OR.   &
         ICASL7.EQ.'BINP'.OR.ICASL7.EQ.'BIRP'.OR.   &
         ICASL7.EQ.'ASHR'.OR.ICASL7.EQ.'ASHC'.OR.   &
         ICASL7.EQ.'FFT1'.OR.ICASL7.EQ.'IFF1'.OR.   &
         ICASL7.EQ.'COR1'.OR.ICASL7.EQ.'POSQ'.OR.   &
         ICASL7.EQ.'POSR'.OR.ICASL7.EQ.'VELE'.OR.   &
         ICASL7.EQ.'SECA'.OR.ICASL7.EQ.'SEEL'.OR.   &
         ICASL7.EQ.'IFRT'.OR.ICASL7.EQ.'COPV'.OR.   &
         ICASL7.EQ.'RANS'.OR.ICASL7.EQ.'RANP'.OR.   &
         ICASL7.EQ.'WMOM'.OR.ICASL7.EQ.'WMOM'.OR.   &
         ICASL7.EQ.'CBIN'.OR.ICASL7.EQ.'CBIR'.OR.   &
         ICASL7.EQ.'LPFI'.OR.ICASL7.EQ.'HPFI'.OR.   &
         ICASL7.EQ.'DIGI'.OR.ICASL7.EQ.'EQUF'.OR.   &
         ICASL7.EQ.'IQUF'.OR.ICASL7.EQ.'TIQF'.OR.   &
         ICASL7.EQ.'LONT'.OR.ICASL7.EQ.'WINS')THEN
        NUMVAR=1
      ELSEIF(ICASL7.EQ.'CONV'.OR.ICASL7.EQ.'DECO'.OR.   &
             ICASL7.EQ.'BOOT'.OR.ICASL7.EQ.'FREQ'.OR.   &
             ICASL7.EQ.'SUMD'.OR.ICASL7.EQ.'SUBS'.OR.   &
             ICASL7.EQ.'FOUT'.OR.ICASL7.EQ.'IFOU'.OR.   &
             ICASL7.EQ.'FFT' .OR.ICASL7.EQ.'CUMH'.OR.   &
             ICASL7.EQ.'HAZA'.OR.ICASL7.EQ.'FRAW'.OR.   &
             ICASL7.EQ.'EXPS'.OR.ICASL7.EQ.'IFFT'.OR.   &
             ICASL7.EQ.'COEX'.OR.ICASL7.EQ.'COSR'.OR.   &
             ICASL7.EQ.'CORO'.OR.ICASL7.EQ.'COCO'.OR.   &
             ICASL7.EQ.'POAD'.OR.ICASL7.EQ.'POSU'.OR.   &
             ICASL7.EQ.'POMU'.OR.ICASL7.EQ.'PODI'.OR.   &
             ICASL7.EQ.'POGC'.OR.ICASL7.EQ.'POLC'.OR.   &
             ICASL7.EQ.'POEV'.OR.ICASL7.EQ.'VEAD'.OR.   &
             ICASL7.EQ.'VESU'.OR.ICASL7.EQ.'VEDP'.OR.   &
             ICASL7.EQ.'VECP'.OR.ICASL7.EQ.'VEDI'.OR.   &
             ICASL7.EQ.'2DCH'.OR.ICASL7.EQ.'YTHL'.OR.   &
             ICASL7.EQ.'NEXS'.OR.ICASL7.EQ.'NEXP'.OR.   &
             ICASL7.EQ.'SOR2'.OR.ICASL7.EQ.'RAN2'.OR.   &
             ICASL7.EQ.'MWUF'.OR.ICASL7.EQ.'EXTP'.OR.   &
             ICASL7.EQ.'ENCB'.OR.ICASL7.EQ.'NNE1'.OR.   &
             ICASL7.EQ.'NNE2'.OR.ICASL7.EQ.'NNE3'.OR.   &
             ICASL7.EQ.'NNE4'.OR.ICASL7.EQ.'RAEQ'.OR.   &
             ICASL7.EQ.'GSQD'.OR.ICASL7.EQ.'GSQS'.OR.   &
             ICASL7.EQ.'GSQP'.OR.ICASL7.EQ.'GSQM'.OR.   &
             ICASL7.EQ.'GQMN'.OR.ICASL7.EQ.'GQMX'.OR.   &
             ICASL7.EQ.'GSQL'.OR.ICASL7.EQ.'GSQU'.OR.   &
             ICASL7.EQ.'UNST'.OR.ICASL7.EQ.'WSAT'.OR.   &
             ICASL7.EQ.'PSCO'.OR.ICASL7.EQ.'CSCO'.OR.   &
             ICASL7.EQ.'NKDM'.OR.ICASL7.EQ.'2DGR'.OR.   &
             ICASL7.EQ.'DREG'.OR.                       &
             ICASL7.EQ.'VEAN'.OR.ICASL7.EQ.'SEUN')THEN
        NUMVAR=2
      ELSEIF(ICASL7.EQ.'SEIN'.OR.ICASL7.EQ.'SECO'.OR.   &
             ICASL7.EQ.'SECP'.OR.ICASL7.EQ.'LOAN'.OR.   &
             ICASL7.EQ.'LOOR'.OR.ICASL7.EQ.'LONA'.OR.   &
             ICASL7.EQ.'LONO'.OR.ICASL7.EQ.'LOIM'.OR.   &
             ICASL7.EQ.'LOEQ'.OR.ICASL7.EQ.'LOXO'.OR.   &
             ICASL7.EQ.'FRAC'.OR.ICASL7.EQ.'GEMU'.OR.   &
             ICASL7.EQ.'JAIN'.OR.ICASL7.EQ.'CFRT'.OR.   &
             ICASL7.EQ.'HCON'.OR.ICASL7.EQ.'KCON'.OR.   &
             ICASL7.EQ.'LMOM'.OR.ICASL7.EQ.'PWMO'.OR.   &
             ICASL7.EQ.'BPWM'.OR.ICASL7.EQ.'SRTB'.OR.   &
             ICASL7.EQ.'GATH'.OR.ICASL7.EQ.'SCAT'.OR.   &
             ICASL7.EQ.'SHIF'.OR.ICASL7.EQ.'CSHI'.OR.   &
             ICASL7.EQ.'LARG'.OR.ICASL7.EQ.'SMAL'.OR.   &
             ICASL7.EQ.'VPER'.OR.ICASL7.EQ.'REMO'.OR.   &
             ICASL7.EQ.'KEEP'.OR.ICASL7.EQ.'OMIT'.OR.   &
             ICASL7.EQ.'TMIN'.OR.ICASL7.EQ.'TMAX'.OR.   &
             ICASL7.EQ.'EXPA'.OR.ICASL7.EQ.'JSCO'.OR.   &
             ICASL7.EQ.'PEAK'.OR.ICASL7.EQ.'PEAR'.OR.   &
             ICASL7.EQ.'DIPE'.OR.ICASL7.EQ.'MTC2'.OR.   &
             ICASL7.EQ.'TTT '.OR.ICASL7.EQ.'STTT'.OR.   &
             ICASL7.EQ.'COCD'.OR.ICASL7.EQ.'JITT')THEN
        NUMVAR=2
      ELSEIF(ICASL7.EQ.'INTR'.OR.ICASL7.EQ.'LINT'.OR.   &
             ICASL7.EQ.'HCO2'.OR.ICASL7.EQ.'KCO2'.OR.   &
             ICASL7.EQ.'COCP'.OR.ICASL7.EQ.'AGCO'.OR.   &
             ICASL7.EQ.'KNSE'.OR.ICASL7.EQ.'NEXC'.OR.   &
             ICASL7.EQ.'NEPA'.OR.ICASL7.EQ.'NEXE'.OR.   &
             ICASL7.EQ.'SPF2'.OR.ICASL7.EQ.'NEYT'.OR.   &
             ICASL7.EQ.'SOR3'.OR.ICASL7.EQ.'RAN3'.OR.   &
             ICASL7.EQ.'EBCL'.OR.ICASL7.EQ.'IZSC'.OR.   &
             ICASL7.EQ.'JOIN'.OR.ICASL7.EQ.'GRPS'.OR.   &
             ICASL7.EQ.'JSCT'.OR.ICASL7.EQ.'PA  '.OR.   &
             ICASL7.EQ.'GWSA'.OR.ICASL7.EQ.'3DGR'.OR.   &
             ICASL7.EQ.'HERI'.OR.ICASL7.EQ.'HERD'.OR.   &
             ICASL7.EQ.'INSE'.OR.   &
             ICASL7.EQ.'EBLL'.OR.ICASL7.EQ.'EBUL')THEN
        NUMVAR=3
      ELSEIF(ICASL7.EQ.'COAD'.OR.ICASL7.EQ.'COSU'.OR.   &
             ICASL7.EQ.'COMU'.OR.ICASL7.EQ.'CODI'.OR.   &
             ICASL7.EQ.'SOR4'.OR.ICASL7.EQ.'POPL'.OR.   &
             ICASL7.EQ.'EN  '.OR.ICASL7.EQ.'ZPRI'.OR.   &
             ICASL7.EQ.'EZPL'.OR.ICASL7.EQ.'EZMI'.OR.   &
             ICASL7.EQ.'IZET'.OR.ICASL7.EQ.'SRNP'.OR.   &
             ICASL7.EQ.'FNNE'.OR.ICASL7.EQ.'ANNE'.OR.   &
             ICASL7.EQ.'HERG'.OR.ICASL7.EQ.'4DGR'.OR.   &
             ICASL7.EQ.'EDGV'.OR.ICASL7.EQ.'SPF1')THEN
        NUMVAR=4
      ELSEIF(ICASL7.EQ.'2DIN'.OR.ICASL7.EQ.'BILI'.OR.   &
             ICASL7.EQ.'DPCL'.OR.ICASL7.EQ.'DPTS'.OR.   &
             ICASL7.EQ.'DPLT'.OR.ICASL7.EQ.'DPUT'.OR.   &
             ICASL7.EQ.'BRAT'.OR.ICASL7.EQ.'BPSE'.OR.   &
             ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
             ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BIVA')THEN
        NUMVAR=5
      ELSEIF(ICASL7.EQ.'BFPD'.OR.ICASL7.EQ.'BFCD'.OR.   &
             ICASL7.EQ.'BFPP'.OR.ICASL7.EQ.'PARL'.OR.   &
             ICASL7.EQ.'PERL')THEN
        NUMVAR=6
      ELSEIF(ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
             ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'TPOI')THEN
        NUMVAR=7
      ELSEIF(ICASL7.EQ.'EEPD'.OR.ICASL7.EQ.'EECD'.OR.   &
             ICASL7.EQ.'EEPP'.OR.ICASL7.EQ.'INTL')THEN
        NUMVAR=8
      ELSEIF(ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
             ICASL7.EQ.'R3UT')THEN
        NUMVAR=9
      ELSEIF(ICASL7.EQ.'SORC'.OR.ICASL7.EQ.'STAC'.OR.   &
             ICASL7.EQ.'RSTA'.OR.ICASL7.EQ.'MTCH'.OR.   &
             ICASL7.EQ.'STAN'.OR.ICASL7.EQ.'ZSCO'.OR.   &
             ICASL7.EQ.'USCO'.OR.ICASL7.EQ.'LSTA'.OR.   &
             ICASL7.EQ.'VSCO'.OR.ICASL7.EQ.'SSCO'.OR.   &
             ICASL7.EQ.'MSCO'.OR.ICASL7.EQ.'DSCO'.OR.   &
             ICASL7.EQ.'ASCO'.OR.   &
             ICASL7.EQ.'CUMI'.OR.ICASL7.EQ.'REPL'.OR.   &
             ICASL7.EQ.'LSST'.OR.ICASL7.EQ.'CRTA'.OR.   &
             ICASL7.EQ.'CTCU'.OR.   &
             ICASL7.EQ.'CDCT'.OR.ICASL7.EQ.'COMB'.OR.   &
             ICASL7.EQ.'MOVI'.OR.ICASL7.EQ.'CUMU'.OR.   &
             ICASL7.EQ.'WIND'.OR.   &
             ICASL7.EQ.'MNRK'.OR.ICASL7.EQ.'MDRK'.OR.   &
             ICASL7(1:2).EQ.'CT')THEN
!
        ISTRT=ILOCV
        ILAST=NUMARG
        DO 1051 I=ISTRT,NUMARG
          IHRIGH(I)=IHARG(I)
          IHRIG2(I)=IHARG2(I)
          IF(IHRIGH(I).EQ.'SUBS'.AND.IHRIG2(I).EQ.'ET  ')THEN
            ILAST=I-1
            GO TO 1054
          ELSEIF(IHRIGH(I).EQ.'EXCE'.AND.IHRIG2(I).EQ.'PT  ')THEN
            ILAST=I-1
            GO TO 1054
          ELSEIF(IHRIGH(I).EQ.'FOR '.AND.IHRIG2(I).EQ.'    ')THEN
            ILAST=I-1
            GO TO 1054
          ENDIF
 1051   CONTINUE
 1054   CONTINUE
        NUMVAR=ILAST-ISTRT+1
!
        IF(ICASL7.EQ.'MTCH' .OR. ICASL7.EQ.'REPL')THEN
          IF(NUMVAR.EQ.2)THEN
            ICASMT='INDE'
          ELSEIF(NUMVAR.EQ.3)THEN
            ICASMT='TRAN'
          ELSE
            IF(ICASL7.EQ.'MTCH')THEN
              WRITE(ICOUT,1061)
            ELSEIF(ICASL7.EQ.'REPL')THEN
              WRITE(ICOUT,1062)
            ENDIF
 1061       FORMAT('****** FOR THE MATCH COMMAND, THE NUMBER OF ',   &
                   'VARIABLES TO THE RIGHT')
 1062       FORMAT('****** FOR THE REPLACE COMMAND, THE NUMBER OF ',   &
                   'VARIABLES TO THE RIGHT')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1063)NUMVAR
 1063       FORMAT('       MUST BE 2 OR 3.  ',I8,' VARIABLES FOUND.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')THEN
        WRITE(ICOUT,1091)ICASL7,NUMVAR
 1091   FORMAT('ICASL7,NUMVAR = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************************
!               **  STEP 5.1--                       **
!               **  EXAMINE THE VARIABLES            **
!               **  ON THE RIGHT.                    **
!               ***************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFLAG1=0
      IF(ICASL7.EQ.'JAIN'.OR.ICASL7.EQ.'AGCO'.OR.   &
         ICASL7.EQ.'EBLL'.OR.ICASL7.EQ.'EBUL'.OR.   &
         ICASL7.EQ.'EBCL'.OR.   &
         ICASL7.EQ.'DPCL'.OR.ICASL7.EQ.'DPTS'.OR.   &
         ICASL7.EQ.'DPLT'.OR.ICASL7.EQ.'DPUT'.OR.   &
         ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
         ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'INTL'.OR.   &
         ICASL7.EQ.'PARL'.OR.ICASL7.EQ.'PERL'.OR.   &
         ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
         ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BRAT'.OR.   &
         ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
         ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
         ICASL7.EQ.'RANS'.OR.ICASL7.EQ.'RANP'.OR.   &
         ICASL7.EQ.'MWUF'.OR.ICASL7.EQ.'DIGI'.OR.   &
         ICASL7.EQ.'NEXS'.OR.ICASL7.EQ.'NEXP'.OR.   &
         ICASL7.EQ.'KNSE'.OR.ICASL7.EQ.'NEXC'.OR.   &
         ICASL7.EQ.'NEPA'.OR.ICASL7.EQ.'NEXE'.OR.   &
         ICASL7.EQ.'SRNP'.OR.   &
         ICASL7.EQ.'NEYT'.OR.ICASL7.EQ.'COMB'   &
         )THEN
         IFLAG1=1
      ENDIF
      ICASEZ=1
      IF(NUMVAR.GE.1)THEN
        CALL DPMAT7(ICASL7,ICASEZ,MAXCAS,ILOCR,   &
                    IHRIGH(1),IHRIG2(1),ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                    IFLAG1,ATEMP2,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IF(ICASL7.EQ.'NEXS' .OR. ICASL7.EQ.'NEXP'.OR.   &
         ICASL7.EQ.'NEPA' .OR. ICASL7.EQ.'NEXE')THEN
        IJUNK=INT(TEMPS(1)+0.01)
        IF(IJUNK.LE.0 .OR. IJUNK.NE.NLAST)THEN
          NUMVAR=1
        ENDIF
      ELSEIF(ICASL7.EQ.'KNSE' .OR. ICASL7.EQ.'NEXC')THEN
        IJUNK1=INT(TEMPS(1)+0.01)
      ELSEIF(ICASL7.EQ.'NEYT')THEN
        IJUNK1=INT(TEMPS(1)+0.01)
        IF(IJUNK1.NE.NLAST)THEN
          NUMVAR=2
        ENDIF
      ENDIF
!
      IF(NUMVAR.GE.2)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'LMOM' .OR. ICASL7.EQ.'PWMO' .OR.   &
           ICASL7.EQ.'BPWM' .OR. ICASL7.EQ.'JAIN' .OR.   &
           ICASL7.EQ.'EXPS' .OR. ICASL7.EQ.'MTCH' .OR.   &
           ICASL7.EQ.'MTC2' .OR.   &
           ICASL7.EQ.'EBLL' .OR. ICASL7.EQ.'EBUL' .OR.   &
           ICASL7.EQ.'EBCL' .OR. ICASL7.EQ.'INTL' .OR.   &
           ICASL7.EQ.'PARL' .OR. ICASL7.EQ.'PERL'.OR.   &
           ICASL7.EQ.'DPCL' .OR. ICASL7.EQ.'DPTS' .OR.   &
           ICASL7.EQ.'DPLT' .OR. ICASL7.EQ.'DPUT' .OR.   &
           ICASL7.EQ.'R1TS' .OR. ICASL7.EQ.'R1LT' .OR.   &
           ICASL7.EQ.'R1UT' .OR. ICASL7.EQ.'IZSC' .OR.   &
           ICASL7.EQ.'R2TS' .OR. ICASL7.EQ.'R2LT' .OR.   &
           ICASL7.EQ.'R2UT' .OR. ICASL7.EQ.'BRAT' .OR.   &
           ICASL7.EQ.'R3TS' .OR. ICASL7.EQ.'R3LT' .OR.   &
           ICASL7.EQ.'R3UT' .OR. ICASL7.EQ.'BPSE' .OR.   &
           ICASL7.EQ.'SHIF' .OR. ICASL7.EQ.'CSHI' .OR.   &
           ICASL7.EQ.'LARG' .OR. ICASL7.EQ.'SMAL' .OR.   &
           ICASL7.EQ.'VPER' .OR. ICASL7.EQ.'SRNP' .OR.   &
           ICASL7.EQ.'KNSE' .OR. ICASL7.EQ.'NEXC' .OR.   &
           ICASL7.EQ.'COMB' .OR. ICASL7.EQ.'MWUF' .OR.   &
           ICASL7.EQ.'IZSC' .OR. ICASL7.EQ.'ZPRI' .OR.   &
           ICASL7.EQ.'PA  ' .OR. ICASL7.EQ.'DIPE' .OR.   &
           ICASL7.EQ.'AGCO' .OR. ICASL7.EQ.'JITT')THEN
          IFLAG1=1
        ENDIF
        ICASEZ=2
        CALL DPMAT7(ICASL7,ICASEZ,MAXCAS,ILOCR,   &
                    IHRIGH(2),IHRIG2(2),ICOLR,ILISR,NIRIGH,   &
                    ITYPA,TEMPS,   &
                    IFLAG1,ATEMP2,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IF(ICASL7.EQ.'KNSE' .OR. ICASL7.EQ.'NEXC')THEN
        IJUNK2=INT(TEMPS(2)+0.01)
        IF((IJUNK1.LE.0 .OR. IJUNK1.NE.KLAST) .OR.   &
           (IJUNK2.LE.0 .OR. IJUNK2.NE.NLAST))THEN
          NUMVAR=2
        ENDIF
      ENDIF
!
      IF(NUMVAR.GE.3)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'EBLL' .OR. ICASL7.EQ.'EBUL' .OR.   &
           ICASL7.EQ.'EBCL' .OR. ICASL7.EQ.'SRNP' .OR.   &
           ICASL7.EQ.'DPCL' .OR. ICASL7.EQ.'DPTS' .OR.   &
           ICASL7.EQ.'DPLT' .OR. ICASL7.EQ.'DPUT' .OR.   &
           ICASL7.EQ.'R1TS' .OR. ICASL7.EQ.'R1LT' .OR.   &
           ICASL7.EQ.'R1UT' .OR. ICASL7.EQ.'INTL' .OR.   &
           ICASL7.EQ.'PARL' .OR. ICASL7.EQ.'PERL' .OR.   &
           ICASL7.EQ.'R2TS' .OR. ICASL7.EQ.'R2LT' .OR.   &
           ICASL7.EQ.'R2UT' .OR. ICASL7.EQ.'BRAT' .OR.   &
           ICASL7.EQ.'R3TS' .OR. ICASL7.EQ.'R3LT' .OR.   &
           ICASL7.EQ.'R3UT' .OR. ICASL7.EQ.'BPSE' .OR.   &
           ICASL7.EQ.'COMB' .OR. ICASL7.EQ.'EN  ' .OR.   &
           ICASL7.EQ.'IZSC' .OR. ICASL7.EQ.'ZPRI' .OR.   &
           ICASL7.EQ.'EZPL' .OR. ICASL7.EQ.'EZMI' .OR.   &
           ICASL7.EQ.'IZET' .OR. ICASL7.EQ.'TPOI' .OR.   &
           ICASL7.EQ.'PA  ' .OR. ICASL7.EQ.'GWSA' .OR.   &
           ICASL7.EQ.'HERG' .OR. ICASL7.EQ.'INSE' .OR.   &
           ICASL7.EQ.'AGCO' .OR. ICASL7.EQ.'SPF2')THEN
          IFLAG1=1
        ENDIF
        ICASEZ=3
        CALL DPMAT7(ICASL7,ICASEZ,MAXCAS,ILOCR,   &
                    IHRIGH(3),IHRIG2(3),ICOLR,ILISR,NIRIGH,   &
                    ITYPA,TEMPS,   &
                    IFLAG1,ATEMP2,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IF(NUMVAR.GE.4)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'DPCL'.OR.ICASL7.EQ.'DPTS'.OR.   &
           ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
           ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'INTL'.OR.   &
           ICASL7.EQ.'PARL'.OR.ICASL7.EQ.'PERL'.OR.   &
           ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
           ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
           ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
           ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BRAT'.OR.   &
           ICASL7.EQ.'COMB'.OR.ICASL7.EQ.'SRNP'.OR.   &
           ICASL7.EQ.'BFPD'.OR.ICASL7.EQ.'BFCD'.OR.   &
           ICASL7.EQ.'BFPP'.OR.ICASL7.EQ.'TPOI'.OR.   &
           ICASL7.EQ.'EEPD'.OR.ICASL7.EQ.'EECD'.OR.   &
           ICASL7.EQ.'EEPP'.OR.ICASL7.EQ.'EN  '.OR.   &
           ICASL7.EQ.'EZPL'.OR.ICASL7.EQ.'EZMI' .OR.   &
           ICASL7.EQ.'IZET'.OR.ICASL7.EQ.'ZPRI' .OR.   &
           ICASL7.EQ.'HERG'.OR.   &
           ICASL7.EQ.'DPLT'.OR.ICASL7.EQ.'DPUT')THEN
          IFLAG1=1
        ENDIF
        ICASEZ=4
        CALL DPMAT7(ICASL7,ICASEZ,MAXCAS,ILOCR,   &
                    IHRIGH(4),IHRIG2(4),ICOLR,ILISR,NIRIGH,   &
                    ITYPA,TEMPS,   &
                    IFLAG1,ATEMP2,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!  5 OR MORE VARIABLES.
!
      IF(NUMVAR.GE.5)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'DPCL'.OR.ICASL7.EQ.'DPTS'.OR.   &
           ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
           ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'INTL'.OR.   &
           ICASL7.EQ.'PARL'.OR.ICASL7.EQ.'PERL'.OR.   &
           ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
           ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
           ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
           ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BRAT'.OR.   &
           ICASL7.EQ.'COMB'.OR.   &
           ICASL7.EQ.'BFPD'.OR.ICASL7.EQ.'BFCD'.OR.   &
           ICASL7.EQ.'BFPP'.OR.   &
           ICASL7.EQ.'EEPD'.OR.ICASL7.EQ.'EECD'.OR.   &
           ICASL7.EQ.'EEPP'.OR.ICASL7.EQ.'TPOI'.OR.   &
           ICASL7.EQ.'DPLT'.OR.ICASL7.EQ.'DPUT')THEN
          IFLAG1=1
        ENDIF
        DO 1110 ICASEZ=5,NUMVAR
          CALL DPMAT7(ICASL7,ICASEZ,MAXCAS,ILOCR,   &
                      IHRIGH(ICASEZ),IHRIG2(ICASEZ),   &
                      ICOLR,ILISR,NIRIGH,   &
                      ITYPA,TEMPS,   &
                      IFLAG1,ATEMP2,ITEMP,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
!
!         LOCATION PARAMETER OPTIONAL FOR END EFFECTS WEIBULL,
!         SO CHECK TO SEE IF LAST PARAMETER GIVEN.
!
          IF(ICASL7.EQ.'EEPD'.OR.ICASL7.EQ.'EECD'.OR.   &
             ICASL7.EQ.'EEPP'.AND.ICASEZ.EQ.8)THEN
             IF(IERROR.EQ.'YES')THEN
               NUMVAR=7
               IERROR='NO'
             ENDIF
          ENDIF
 1110   CONTINUE
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!
!               ******************************************************
!               **  STEP 6.1--                                      **
!               **  FOR CERTAIN 2-VARIABLE AND 3-VARIABLE CASES,    **
!               **  CHECK THAT VARIABLES 1 AND 2 HAVE THE SAME      **
!               **  NUMBER OF ELEMENTS.                             **
!               **  THIS CHECK IS NOT DONE FOR CONVOLUTION,         **
!               **  DECONVOLUTION, FREQUENCY                        **
!               **  AND SUM (DISTINCT)                              **
!               ******************************************************
!
      ISTEPN='6.1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!  CASE 1: NO VARIABLES NEED TO BE SAME LENGTH
!
      IF(ICASL7.EQ.'CONV'.OR.ICASL7.EQ.'DECO'.OR.   &
         ICASL7.EQ.'FREQ'.OR.ICASL7.EQ.'SUMD'.OR.   &
         ICASL7.EQ.'SUBS'.OR.ICASL7.EQ.'POAD'.OR.   &
         ICASL7.EQ.'POSU'.OR.ICASL7.EQ.'POMU'.OR.   &
         ICASL7.EQ.'PODI'.OR.ICASL7.EQ.'POSQ'.OR.   &
         ICASL7.EQ.'POSR'.OR.ICASL7.EQ.'POGC'.OR.   &
         ICASL7.EQ.'POLC'.OR.ICASL7.EQ.'POEV'.OR.   &
         ICASL7.EQ.'SEUN'.OR.ICASL7.EQ.'SEIN'.OR.   &
         ICASL7.EQ.'SECO'.OR.ICASL7.EQ.'SECA'.OR.   &
         ICASL7.EQ.'SECP'.OR.ICASL7.EQ.'SEEL'.OR.   &
         ICASL7.EQ.'LONT'.OR.ICASL7.EQ.'VELE'.OR.   &
         ICASL7.EQ.'GEMU'.OR.ICASL7.EQ.'COCD'.OR.   &
         ICASL7.EQ.'KEEP'.OR.ICASL7.EQ.'OMIT'.OR.   &
         ICASL7.EQ.'COCP'.OR.ICASL7.EQ.'EXPS'.OR.   &
         ICASL7.EQ.'MTCH'.OR.ICASL7.EQ.'STAC'.OR.   &
         ICASL7.EQ.'MTC2'.OR.ICASL7.EQ.'STAC'.OR.   &
         ICASL7.EQ.'RSTA'.OR.ICASL7.EQ.'LMOM'.OR.   &
         ICASL7.EQ.'PWMO'.OR.ICASL7.EQ.'BPWM'.OR.   &
         ICASL7.EQ.'EBLL'.OR.ICASL7.EQ.'EBUL'.OR.   &
         ICASL7.EQ.'EBCL'.OR.ICASL7.EQ.'EXPA'.OR.   &
         ICASL7.EQ.'AGCO'.OR.ICASL7.EQ.'COMB'.OR.   &
         ICASL7.EQ.'DPCL'.OR.ICASL7.EQ.'DPTS'.OR.   &
         ICASL7.EQ.'DPLT'.OR.ICASL7.EQ.'DPUT'.OR.   &
         ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
         ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'INTL'.OR.   &
         ICASL7.EQ.'PARL'.OR.ICASL7.EQ.'PERL'.OR.   &
         ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
         ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
         ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
         ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BRAT'.OR.   &
         ICASL7.EQ.'NEXS'.OR.ICASL7.EQ.'NEXP'.OR.   &
         ICASL7.EQ.'KNSE'.OR.ICASL7.EQ.'NEXC'.OR.   &
         ICASL7.EQ.'GATH'.OR.ICASL7.EQ.'SCAT'.OR.   &
         ICASL7.EQ.'TMIN'.OR.ICASL7.EQ.'TMAX'.OR.   &
         ICASL7.EQ.'SHIF'.OR.ICASL7.EQ.'CSHI'.OR.   &
         ICASL7.EQ.'LARG'.OR.ICASL7.EQ.'SMAL'.OR.   &
         ICASL7.EQ.'VPER'.OR.ICASL7.EQ.'SRNP'.OR.   &
         ICASL7.EQ.'INSE'.OR.ICASL7.EQ.'PSCO'.OR.   &
         ICASL7.EQ.'REMO'.OR.                       &
         NUMVAR.LE.1)THEN
        GO TO 2190
!
!  CASE 1A: ALL VARIABLES NEED TO BE SAME LENGTH
!
      ELSEIF(ICASL7.EQ.'STAN' .OR. ICASL7.EQ.'ZSCO'.OR.   &
             ICASL7.EQ.'USCO' .OR. ICASL7.EQ.'LSTA'.OR.   &
             ICASL7.EQ.'VSCO' .OR. ICASL7.EQ.'SSCO'.OR.   &
             ICASL7.EQ.'MSCO' .OR. ICASL7.EQ.'DSCO'.OR.   &
             ICASL7.EQ.'ASCO' .OR.   &
             ICASL7.EQ.'LSST' .OR. ICASL7.EQ.'CRTA'.OR.   &
             ICASL7.EQ.'CTCU' .OR. ICASL7(1:2).EQ.'CT' .OR.   &
             ICASL7.EQ.'INTL' .OR. ICASL7.EQ.'SOR3' .OR.   &
             ICASL7.EQ.'SOR4' .OR. ICASL7.EQ.'RAN3' .OR.   &
             ICASL7.EQ.'WIND' .OR. ICASL7.EQ.'WSAT' .OR.   &
             ICASL7.EQ.'MNRK' .OR. ICASL7.EQ.'MDRK' .OR.   &
             ICASL7.EQ.'CSCO' .OR.   &
             ICASL7.EQ.'MOVI' .OR. ICASL7.EQ.'CUMU')THEN
        DO 2199 I=2,NUMVAR
          IF(NIRIGH(1).NE.NIRIGH(I))THEN
            IERROR='YES'
            WRITE(ICOUT,2191)
 2191       FORMAT('***** ERROR 2191 IN DPMATC--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2192)NUMVAR
 2192       FORMAT('      ALL ',I8,' VARIABLES SHOULD HAVE THE SAME ',   &
                   'NUMBER OF ELEMENTS.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2193)NIRIGH(1)
 2193       FORMAT('      VARIABLE ONE HAS ',I8,' OBSERVATIONS.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2194)I,NIRIGH(I)
 2194       FORMAT('      VARIABLE ',I2,' HAS ',I8,' OBSERVATIONS.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
 2199   CONTINUE
!
        IF(IERROR.EQ.'YES')THEN
          IF(IWIDTH.GE.1)THEN
             WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
             CALL DPWRST('XXX','BUG ')
           ENDIF
           GO TO 19000
        ENDIF
!
!  CASE 2: SAME LENGTH REQUIRED FOR VARIABLES 1 AND 2
!
      ELSEIF(ICASL7.EQ.'COEX'.OR.ICASL7.EQ.'COSR'.OR.   &
             ICASL7.EQ.'CORO'.OR.   &
             ICASL7.EQ.'COCO'.OR.ICASL7.EQ.'CFRT'.OR.   &
             ICASL7.EQ.'VEAD'.OR.ICASL7.EQ.'VESU'.OR.   &
             ICASL7.EQ.'VEDP'.OR.ICASL7.EQ.'VECP'.OR.   &
             ICASL7.EQ.'VEDI'.OR.ICASL7.EQ.'VEAN'.OR.   &
             ICASL7.EQ.'LOAN'.OR.ICASL7.EQ.'LOOR'.OR.   &
             ICASL7.EQ.'LONA'.OR.ICASL7.EQ.'LONO'.OR.   &
             ICASL7.EQ.'LOIM'.OR.ICASL7.EQ.'LOEQ'.OR.   &
             ICASL7.EQ.'LOXO'.OR.ICASL7.EQ.'HCON'.OR.   &
             ICASL7.EQ.'KCON'.OR.ICASL7.EQ.'SRTB'.OR.   &
             ICASL7.EQ.'2DCH'.OR.ICASL7.EQ.'EDGV'.OR.   &
             ICASL7.EQ.'SPF1'.OR.ICASL7.EQ.'SPF2'.OR.   &
             ICASL7.EQ.'YTHL'.OR.ICASL7.EQ.'EN  '.OR.   &
             ICASL7.EQ.'EZPL'.OR.ICASL7.EQ.'EZMI'.OR.   &
             ICASL7.EQ.'IZET'.OR.ICASL7.EQ.'JSCO'.OR.   &
             ICASL7.EQ.'SOR2'.OR.ICASL7.EQ.'RAN2'.OR.   &
             ICASL7.EQ.'TPOI'.OR.ICASL7.EQ.'EXTP'.OR.   &
             ICASL7.EQ.'PEAK'.OR.ICASL7.EQ.'PEAR'.OR.   &
             ICASL7.EQ.'ENCB'.OR.ICASL7.EQ.'RAEQ'.OR.   &
             ICASL7.EQ.'NNE1'.OR.ICASL7.EQ.'NNE2'.OR.   &
             ICASL7.EQ.'NNE3'.OR.ICASL7.EQ.'NNE4'.OR.   &
             ICASL7.EQ.'GSQD'.OR.ICASL7.EQ.'GSQS'.OR.   &
             ICASL7.EQ.'GSQP'.OR.ICASL7.EQ.'GSQM'.OR.   &
             ICASL7.EQ.'GQMN'.OR.ICASL7.EQ.'GQMX'.OR.   &
             ICASL7.EQ.'GSQL'.OR.ICASL7.EQ.'GSQU'.OR.   &
             (ICASL7.EQ.'ZSCO'.OR.ICASL7.EQ.'LSTA'.OR.   &
              ICASL7.EQ.'USCO'.OR.ICASL7.EQ.'LSST'.OR.   &
              ICASL7.EQ.'VSCO'.OR.ICASL7.EQ.'SSCO'.OR.   &
              ICASL7.EQ.'MSCO'.OR.ICASL7.EQ.'DSCO'.OR.   &
              ICASL7.EQ.'ASCO'.OR.   &
              ICASL7.EQ.'CRTA'.OR.ICASL7.EQ.'STAN'.OR.   &
              ICASL7.EQ.'CTCU'.OR.ICASL7.EQ.'WIND'.OR.   &
              ICASL7.EQ.'MOVI'.OR.ICASL7.EQ.'CUMU'.OR.   &
              ICASL7.EQ.'MNRK'.OR.ICASL7.EQ.'MDRK'.OR.   &
              ICASL7(1:2).EQ.'CT' .AND. NUMVAR.GE.2))THEN
        IF(NIRIGH(1).NE.NIRIGH(2))THEN
          WRITE(ICOUT,2111)
 2111     FORMAT('***** ERROR 2111 IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2112)
 2112     FORMAT('      VARIABLES ONE AND TWO MUST HAVE THE SAME')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2113)
 2113     FORMAT('      NUMBER OF OBSERVATIONS;  SUCH WAS NOT ',   &
                 'THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          DO 2114 J=1,2
            WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
 2115       FORMAT('           VARIABLE ',A4,A4,' HAS ',I8,   &
                   ' OBSERVATIONS;')
            CALL DPWRST('XXX','BUG ')
 2114     CONTINUE
          WRITE(ICOUT,2118)
 2118     FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
 2119       FORMAT('      ',100A1)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
!  CASE 3: SAME LENGTH REQUIRED FOR VARIABLES 1, 2, AND 3
!
      ELSEIF(ICASL7.EQ.'HCO2'.OR.ICASL7.EQ.'KCO2'.OR.   &
             ICASL7.EQ.'GWSA'.OR.   &
             ICASL7.EQ.'2DIN'.OR.ICASL7.EQ.'JOIN')THEN
        IF(NIRIGH(1).NE.NIRIGH(2) .OR. NIRIGH(1).NE.NIRIGH(3))THEN
          WRITE(ICOUT,2121)
 2121     FORMAT('***** ERROR 2121 IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2122)
 2122     FORMAT('      VARIABLES ONE , TWO, AND THREE MUST HAVE ',   &
                 'THE SAME')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2123)
 2123     FORMAT('      NUMBER OF OBSERVATIONS;  SUCH WAS NOT ',   &
                 'THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          DO 2124 J=1,3
            WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
            CALL DPWRST('XXX','BUG ')
 2124     CONTINUE
          WRITE(ICOUT,2118)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
!  CASE 4: SAME LENGTH REQUIRED FOR VARIABLES 1, 2, 3, AND 4
!
      ELSEIF(ICASL7.EQ.'COAD'.OR.ICASL7.EQ.'COSU'.OR.   &
             ICASL7.EQ.'COMU'.OR.ICASL7.EQ.'CODI')THEN
        IF(NIRIGH(1).NE.NIRIGH(2) .OR. NIRIGH(1).NE.NIRIGH(3) .OR.   &
           NIRIGH(1).NE.NIRIGH(4))THEN
          WRITE(ICOUT,2131)
 2131     FORMAT('***** ERROR 2131 IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2132)
 2132     FORMAT('      VARIABLES ONE , TWO, THREE, AND FOUR ',   &
                 'MUST HAVE THE SAME')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2133)
 2133     FORMAT('      NUMBER OF OBSERVATIONS;  SUCH WAS NOT ',   &
                 'THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          DO 2134 J=1,4
            WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
            CALL DPWRST('XXX','BUG ')
 2134     CONTINUE
          WRITE(ICOUT,2136)IHRIGH(1),IHRIG2(1),NIRIGH(1)
 2136     FORMAT('           VARIABLE ',A4,A4,' HAS ',I8,   &
                 ' OBSERVATIONS;')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2136)IHARG(ILOCV+1),IHARG2(ILOCV+1),NIRIGH(2)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2136)IHARG(ILOCV+2),IHARG2(ILOCV+2),NIRIGH(3)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2136)IHARG(ILOCV+3),IHARG2(ILOCV+3),NIRIGH(4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2118)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
!  CASE 5: SAME LENGTH REQUIRED FOR VARIABLES 1, 2, AND 3 AND
!          FOR VARIABLES 4 AND 5
!
      ELSEIF(ICASL7.EQ.'BILI'.OR.ICASL7.EQ.'BIVA')THEN
        IF(NIRIGH(1).EQ.NIRIGH(2).AND.NIRIGH(2).EQ.NIRIGH(3).AND.   &
           NIRIGH(4).EQ.NIRIGH(5))GO TO 2190
        WRITE(ICOUT,2141)
 2141   FORMAT('***** ERROR 2141 IN DPMATC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2142)
 2142   FORMAT('      FOR 2D INTERPOLATION, THE NUMBER OF ',   &
               'OBSERVATIONS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2143)
 2143   FORMAT('     IN THE FIRST THREE VARIABLES AND IN VARIABLES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2144)
 2144   FORMAT('      4 AND 5 MUST BE THE SAME; SUCH WAS NOT THE ',   &
               'CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        DO 2146 J=1,5
          WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
          CALL DPWRST('XXX','BUG ')
 2146   CONTINUE
        WRITE(ICOUT,2118)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 19000
!
!  CASE 6: VARIABLE 1 AND VARIABLE 3 MUST HAVE SAME LENGTH
!
      ELSEIF((ICASL7.EQ.'MTCH'.AND.ICASMT.EQ.'TRAN') .OR.   &
             (ICASL7.EQ.'REPL'.AND.ICASMT.EQ.'TRAN'))THEN
        IF(NIRIGH(1).NE.NIRIGH(3))THEN
          WRITE(ICOUT,2151)
 2151     FORMAT('***** ERROR 2151 IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2152)
 2152     FORMAT('      VARIABLES ONE AND THREE MUST HAVE THE SAME')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2153)
 2153     FORMAT('      NUMBER OF OBSERVATIONS;  SUCH WAS NOT ',   &
                 'THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2115)IHRIGH(1),IHRIG2(1),NIRIGH(1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2115)IHRIGH(3),IHRIG2(3),NIRIGH(3)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2158)
 2158     FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
!  CASE 7: SAME LENGTH REQUIRED FOR VARIABLES 1 AND 2 AND
!          FOR VARIABLES 3 AND 4
!
      ELSEIF(ICASL7.EQ.'EDGV' .OR. ICASL7.EQ.'SPF1' .OR.   &
             ICASL7.EQ.'FNNE' .OR. ICASL7.EQ.'ANNE' .OR.   &
             ICASL7.EQ.'POPL')THEN
        IF(NIRIGH(1).NE.NIRIGH(2))THEN
          WRITE(ICOUT,2161)
 2161     FORMAT('***** ERROR IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          IF(ICASL7.EQ.'EDGV')THEN
            WRITE(ICOUT,2162)
 2162       FORMAT('      FOR EDGE TO VERTICES, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ELSEIF(ICASL7.EQ.'SPF1')THEN
            WRITE(ICOUT,2168)
 2168       FORMAT('      FOR SPANNING FOREST, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ELSEIF(ICASL7.EQ.'POPL')THEN
            WRITE(ICOUT,2169)
 2169       FORMAT('      FOR POINTS IN POLYGON, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ELSEIF(ICASL7.EQ.'FNNE')THEN
            WRITE(ICOUT,22162)
22162       FORMAT('      FOR FIRST NEAREST NEIGHBOR, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ELSEIF(ICASL7.EQ.'ANNE')THEN
            WRITE(ICOUT,22163)
22163       FORMAT('      FOR ALL NEAREST NEIGHBORS, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ENDIF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2163)
 2163     FORMAT('     FOR VARIABLES ONE AND TWO MUST BE THE SAME.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2164)
 2164     FORMAT('      SUCH WAS NOT THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          DO 2166 J=1,2
            WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
            CALL DPWRST('XXX','BUG ')
 2166     CONTINUE
          WRITE(ICOUT,2118)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
        IF(NIRIGH(3).NE.NIRIGH(4))THEN
          WRITE(ICOUT,2171)
 2171     FORMAT('***** ERROR IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          IF(ICASL7.EQ.'EDGV')THEN
            WRITE(ICOUT,2172)
 2172       FORMAT('      FOR EDGE TO VERTICES, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ELSE
            WRITE(ICOUT,2178)
 2178       FORMAT('      FOR SPANNING FOREST, THE NUMBER OF ',   &
                   'OBSERVATIONS')
          ENDIF
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2173)
 2173     FORMAT('     FOR VARIABLES THREE AND FOUR MUST BE THE SAME.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2174)
 2174     FORMAT('      SUCH WAS NOT THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          DO 2176 J=3,4
            WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
            CALL DPWRST('XXX','BUG ')
 2176     CONTINUE
          WRITE(ICOUT,2118)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
!  CASE 8: SAME LENGTH REQUIRED FOR VARIABLES 2 AND 3
!
      ELSEIF(ICASL7.EQ.'NEPA' .OR.   &
             ICASL7.EQ.'BFPD'.OR.ICASL7.EQ.'BFCD'.OR.   &
             ICASL7.EQ.'BFPP'.OR.   &
             ICASL7.EQ.'EEPD'.OR.ICASL7.EQ.'EECD'.OR.   &
             ICASL7.EQ.'EEPP'.OR.   &
             (ICASL7.EQ.'NEYT' .AND. NUMVAR.EQ.3))THEN
        IF(NIRIGH(2).NE.NIRIGH(3))THEN
          WRITE(ICOUT,2181)
 2181     FORMAT('***** ERROR IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          IF(ICASL7.EQ.'NEPA')THEN
            WRITE(ICOUT,2182)
 2182       FORMAT('      FOR NEXT PARTITION, THE NUMBER OF ',   &
                   'OBSERVATIONS')
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICASL7.EQ.'NEYT')THEN
            WRITE(ICOUT,2183)
 2183       FORMAT('      FOR NEXT YOUNG TABLEAUX, THE NUMBER OF ',   &
                   'OBSERVATIONS')
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICASL7.EQ.'BFPD' .OR. ICASL7.EQ.'BFCD' .OR.   &
                 ICASL7.EQ.'BFPP')THEN
            WRITE(ICOUT,2184)
 2184       FORMAT('      FOR BRITTLE FIBER WEIBULL PDF/CDF/PPF, ',   &
                   'THE NUMBER OF OBSERVATIONS')
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICASL7.EQ.'EEPD' .OR. ICASL7.EQ.'EECD' .OR.   &
                 ICASL7.EQ.'EEPP')THEN
            WRITE(ICOUT,2185)
 2185       FORMAT('      FOR END EFFECTS WEIBULL PDF/CDF/PPF, ',   &
                   'THE NUMBER OF OBSERVATIONS')
            CALL DPWRST('XXX','BUG ')
          ENDIF
          WRITE(ICOUT,2186)
 2186     FORMAT('     FOR VARIABLES TWO AND THREE MUST BE THE SAME.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2187)
 2187     FORMAT('      SUCH WAS NOT THE CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          DO 2188 J=2,3
            WRITE(ICOUT,2115)IHRIGH(J),IHRIG2(J),NIRIGH(J)
            CALL DPWRST('XXX','BUG ')
 2188     CONTINUE
          WRITE(ICOUT,2119)
          CALL DPWRST('XXX','BUG ')
          IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2119)(IANS(I),I=1,MAX(100,IWIDTH))
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IERROR='YES'
          GO TO 19000
        ENDIF
!
      ENDIF
!
 2190 CONTINUE
!
!               *******************************
!               **  STEP 7--                 **
!               **  DETERMINE THE SUBCASE    **
!               **  AND BRANCH ACCORDINGLY.  **
!               *******************************
!
      ISTEPN='7'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,7003)NUMVAR,NUMARG
 7003   FORMAT('7008--NUMVAR,NUMARG = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 7005 I=1,NUMVAR
        WRITE(ICOUT,7008)I,ITYPA(I),ILOCR(I)
 7008   FORMAT('7008-I,ITYPA(I),ILOCR(I) = ',I4,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
 7005   CONTINUE
        WRITE(ICOUT,7006)IHARG(ILOCR(NUMVAR)),IHARG2(ILOCR(NUMVAR))
 7006   FORMAT('IHARG(ILOCR(NUMVAR)),IHARG2(ILOCR(NUMVAR)) = ',2A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7007)IHARG(ILOCR(NUMVAR)+1),   &
                         IHARG2(ILOCR(NUMVAR)+1)
 7007   FORMAT('IHARG(ILOCR(NUMVAR)+1),IHARG2(ILOCR(NUMVAR)+1) = ',   &
               2A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC FOR EXPONENTIAL SMOOTH, SECOND ARGUMENT OPTIONAL.
!
      IF(ICASL7.EQ.'EXPS')THEN
        IF(ILOCR(1).EQ.NUMARG)THEN
          TEMPS(2)=0.0
          NUMVAR=1
          GO TO 8000
        ELSEIF(IHARG(ILOCR(2)).EQ.'SUBS'.OR.   &
               IHARG(ILOCR(2)).EQ.'EXCE'.OR.   &
               IHARG(ILOCR(2)).EQ.'FOR ')THEN
          TEMPS(2)=0.0
          NUMVAR=1
          IF(IHARG(ILOCR(2)).EQ.'SUBS')GO TO 9000
          IF(IHARG(ILOCR(2)).EQ.'EXCE')GO TO 9000
          IF(IHARG(ILOCR(2)).EQ.'FOR ')GO TO 10000
        ENDIF
      ELSEIF(ICASL7.EQ.'SORC' .OR. ICASL7.EQ.'STAC'.OR.   &
             ICASL7.EQ.'RSTA' .OR. ICASL7.EQ.'COMB')THEN
        NUMVAR=1
        ISTRT=4
        IF(ICASL7.EQ.'STAC')ISTRT=5
        IF(ICASL7.EQ.'RSTA')ISTRT=7
        IF(NUMARG.LE.ISTRT)GO TO 8000
        DO 7051 I=ISTRT+1,NUMARG
          ILOCR7=I
          NUMVAR=NUMVAR+1
          IF(ILOCR7.GE.NUMARG)GO TO 8000
          IF(ILOCR7.LT.NUMARG.AND.IHARG(ILOCR7+1).EQ.'SUBS'.AND.   &
             IHARG2(ILOCR7+1).EQ.'ET  ')GO TO 9000
          IF(ILOCR7.LT.NUMARG.AND.IHARG(ILOCR7+1).EQ.'EXCE'.AND.   &
             IHARG2(ILOCR7+1).EQ.'PT  ')GO TO 9000
          IF(ILOCR7.LT.NUMARG.AND.IHARG(ILOCR7+1).EQ.'FOR '.AND.   &
             IHARG2(ILOCR7+1).EQ.'    ')GO TO 10000
 7051   CONTINUE
        GO TO 8000
      ENDIF
!
      IF(ILOCR(NUMVAR).EQ.NUMARG)GO TO 8000
      IF(NUMVAR.EQ.0)GO TO 11000
!
      IF(ILOCR(NUMVAR).LT.NUMARG)THEN
        IT1=ILOCR(NUMVAR+1)
        IF(IHARG(IT1).EQ.'SUBS'.AND.IHARG2(IT1).EQ.'ET  ')GO TO 9000
        IF(IHARG(IT1).EQ.'EXCE'.AND.IHARG2(IT1).EQ.'PT  ')GO TO 9000
        IF(IHARG(IT1).EQ.'FOR '.AND.IHARG2(IT1).EQ.'    ')GO TO 10000
      ENDIF
!
      WRITE(ICOUT,7081)
 7081 FORMAT('***** ERROR 7081 IN DPMATC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7082)
 7082 FORMAT('      ILLEGAL SYNTAX FOR LET COMMAND AT 7082--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7083)
 7083 FORMAT('      THE COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7084)(IANS(I),I=1,MAX(100,IWIDTH))
 7084 FORMAT(100A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7088)ILOCV,NUMARG,NUMVAR
 7088 FORMAT('ILOCV,NUMARG,NUMVAR = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 7089 I=1,NUMVAR
      WRITE(ICOUT,7086)I,ILOCR(I)
 7086 FORMAT('I,ILOCR(I) = ',I4,2X,I8)
      CALL DPWRST('XXX','BUG ')
 7089 CONTINUE
      IERROR='YES'
      GO TO 19000
!
!               ************************************************
!               **  STEP 8--                                  **
!               **  TREAT THE FULL VARIABLE CASE.             **
!               **  EXAMPLE--LET Y = SORT X                   **
!               **         --LET Y(I) = SORT X                **
!               **  THEN JUMP TO STEP NUMBER 10 BELOW         **
!               **  FOR THE LIST UPDATING AND                 **
!               **  FOR SOME INFORMATIVE PRINTING.            **
!               ************************************************
!
!
 8000 CONTINUE
      ISTEPN='8'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,8011)NUMVAR,NIRIGH(1)
 8011   FORMAT('NUMVAR,NIRIGH(1) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICASEQ='FULL'
      NIOLD=NIRIGH(1)
      IF(NUMVAR.GE.2)THEN
        DO 8020 I=2,NUMVAR
          IF(NIRIGH(I).GT.NIOLD)NIOLD=NIRIGH(I)
 8020   CONTINUE
      ENDIF
      NINEW=NIOLD
      NIFOR=NINEW
      DO 8100 I=1,NINEW
        ISUB(I)=1
 8100 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,8021)NINEW,NIRIGH(1)
 8021   FORMAT('NINEW,NIRIGH(1) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 11000
!
!               **************************************************
!               **  STEP 9--                                     *
!               **  TREAT THE PARTIAL VARIABLE SUBSET CASE.      *
!               **  EXAMPLE--LET Y = SORT X     SUBSET 2 3 5     *
!               **         --LET Y(I) = SORT X  SUBSET 2 3 5     *
!               **  JUMP TO STEP NUMBER 11 BELOW                 *
!               **  FOR THE ACTUAL MATHEMATICAL OPERATION,       *
!               **  FOR THE LIST UPDATING, AND                   *
!               **  FOR SOME INFORMATIVE PRINTING.               *
!               **************************************************
!
 9000 CONTINUE
      ISTEPN='9'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='SUBS'
      ILOCSV=ILOCR(NUMVAR)+2
      IHSET=IHARG(ILOCSV)
      IHSET2=IHARG2(ILOCSV)
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,9002)ILOCSV,IHSET,IHSET2
 9002   FORMAT('ILOCSV,IHSET,IHSET2 = ',I8,2X,A4,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHSET,IHSET2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
      IF(IERROR.EQ.'YES')GO TO 19000
      NIOLD=IN(ILOC)
      CALL DPSUBS(NIOLD,ILOCS,NSTEMP,IBUGQ,IERROR)
      NINEW=NIOLD
      NIFOR=NINEW
      GO TO 11000
!
!               **************************************************
!               **  STEP 10--                                    *
!               **  TREAT THE PARTIAL VARIABLE FOR CASE.         *
!               **  EXAMPLE--LET Y = SORT X     FOR I = 1 2 10   *
!               **         --LET Y(I) = SORT X  FOR I = 1 2 10   *
!               **  JUMP TO STEP NUMBER 11 BELOW                 *
!               **  FOR THE ACTUAL MATHEMATICAL OPERATION,       *
!               **  FOR THE LIST UPDATING, AND                   *
!               **  FOR SOME INFORMATIVE PRINTING.               *
!               **************************************************
!
10000 CONTINUE
      ISTEPN='10'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FOR'
      CALL DPFOR(NIOLD,NINEW,IROW1,IROWN,   &
      NLOCAL,ILOCS,NSTEMP,IBUGQ,IERROR)
      NIFOR=NINEW
      GO TO 11000
!
!               *******************************************
!               **  STEP 11--                            **
!               **  CARRY OUT THE                        **
!               **  MATHEMATICAL OPERATION.              **
!               *******************************************
!
11000 CONTINUE
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        DO 11109 I=1,NUMVAR
          WRITE(ICOUT,11101)I,ITYPA(I)
11101     FORMAT('11101--I,ITYPA(I) = ',I4,2X,A4)
          CALL DPWRST('XXX','BUG ')
11109   CONTINUE
      ENDIF
!
      NITEMX=NINEW
      NS1=0
      NS2=0
      NS3=0
      NS4=0
      NS5=0
      NS6=0
      NS7=0
      NS8=0
      NS9=0
!
!CCCC NOTE: FOR SCATTER, EXTRACT CURRENT VALUES OF VARIABLE
!CCCC       ON LEFT HAND SIDE IF VARIABLE ALREADY EXISTS:
!CCCC
      IF(ICASL7.EQ.'SCAT')THEN
        IF(NEWNAM(1).EQ.'NO')THEN
          NILEFT=IN(ILISL(1))
          NS99=0
          DO 11110 I=1,NILEFT
            IJ=MAXN*(ICOLL(1)-1)+I
            NS99=NS99+1
            IF(ICOLL(1).LE.MAXCOL)TEMP91(NS99)=V(IJ)
            IF(ICOLL(1).EQ.MAXCP1)TEMP91(NS99)=PRED(I)
            IF(ICOLL(1).EQ.MAXCP2)TEMP91(NS99)=RES(I)
            IF(ICOLL(1).EQ.MAXCP3)TEMP91(NS99)=YPLOT(I)
            IF(ICOLL(1).EQ.MAXCP4)TEMP91(NS99)=XPLOT(I)
            IF(ICOLL(1).EQ.MAXCP5)TEMP91(NS99)=X2PLOT(I)
            IF(ICOLL(1).EQ.MAXCP6)TEMP91(NS99)=TAGPLO(I)
11110     CONTINUE
        ELSE
          NS99=-1
        ENDIF
      ENDIF
!
      IF(NUMVAR.GE.1 .AND. ITYPA(1).EQ.'VARI')THEN
        DO 11111 I=1,NINEW
          IF(ISUB(I).EQ.0)GO TO 11111
          IF(I.GT.NIRIGH(1))GO TO 11119
          IJ=MAXN*(ICOLR(1)-1)+I
!
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')THEN
            WRITE(ICOUT,11112)I,NS1,NINEW,ISUB(I),IJ,V(IJ)
11112       FORMAT('I,NS1,NINEW,ISUB(I),IJ,V(IJ) = ',5I8,F12.5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          NS1=NS1+1
          IF(ICOLR(1).LE.MAXCOL)TEMP1(NS1)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)TEMP1(NS1)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)TEMP1(NS1)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)TEMP1(NS1)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)TEMP1(NS1)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)TEMP1(NS1)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)TEMP1(NS1)=TAGPLO(I)
11111   CONTINUE
11119   CONTINUE
      ENDIF
!
!     FOR BRITTLE FIBER WEIBULL AND END EFFECTS WEIBULL CASES, IGNORE
!     SUBSET CLAUSE, ALSO CAN BE DIFFERENT LENGTH THAN VARIABLE 1.
!
      IF(NUMVAR.GE.2 .AND. ITYPA(2).EQ.'VARI')THEN
        IFLAGN=0
        IF(ICASL7.EQ.'BFPD' .OR. ICASL7.EQ.'BFCD' .OR.   &
           ICASL7.EQ.'BFPP') THEN
           IFLAGN=1
        ELSEIF(ICASL7.EQ.'EEPD' .OR. ICASL7.EQ.'EECD' .OR.   &
           ICASL7.EQ.'EEPP') THEN
           IFLAGN=1
        ELSEIF(ICASL7.EQ.'TMIN' .OR. ICASL7.EQ.'TMAX')THEN
           IFLAGN=1
        ENDIF
        DO 11121 I=1,NIRIGH(2)
          IF(ISUB(I).EQ.0 .AND. IFLAGN.EQ.0)GO TO 11121
          IF(I.GT.NIRIGH(2))GO TO 11129
          NS2=NS2+1
          IJ=MAXN*(ICOLR(2)-1)+I
          IF(ICOLR(2).LE.MAXCOL)TEMP2(NS2)=V(IJ)
          IF(ICOLR(2).EQ.MAXCP1)TEMP2(NS2)=PRED(I)
          IF(ICOLR(2).EQ.MAXCP2)TEMP2(NS2)=RES(I)
          IF(ICOLR(2).EQ.MAXCP3)TEMP2(NS2)=YPLOT(I)
          IF(ICOLR(2).EQ.MAXCP4)TEMP2(NS2)=XPLOT(I)
          IF(ICOLR(2).EQ.MAXCP5)TEMP2(NS2)=X2PLOT(I)
          IF(ICOLR(2).EQ.MAXCP6)TEMP2(NS2)=TAGPLO(I)
11121   CONTINUE
11129   CONTINUE
      ENDIF
!
!     FOR BRITTLE FIBER WEIBULL AND END EFFECT WEIBULL CASES, IGNORE
!     SUBSET CLAUSE, ALSO CAN BE DIFFERENT LENGTH THAN VARIABLE 1.
!
      IF(NUMVAR.GE.3 .AND. ITYPA(3).EQ.'VARI')THEN
        IFLAGN=0
        IF(ICASL7.EQ.'BFPD' .OR. ICASL7.EQ.'BFCD' .OR.   &
           ICASL7.EQ.'BFPP') THEN
           IFLAGN=1
        ELSEIF(ICASL7.EQ.'EEPD' .OR. ICASL7.EQ.'EECD' .OR.   &
           ICASL7.EQ.'EEPP') THEN
           IFLAGN=1
        ENDIF
        DO 11131 I=1,NIRIGH(3)
          IF(ISUB(I).EQ.0 .AND. IFLAGN.EQ.0)GO TO 11131
          IF(I.GT.NIRIGH(3))GO TO 11139
          NS3=NS3+1
          IJ=MAXN*(ICOLR(3)-1)+I
          IF(ICOLR(3).LE.MAXCOL)TEMP3(NS3)=V(IJ)
          IF(ICOLR(3).EQ.MAXCP1)TEMP3(NS3)=PRED(I)
          IF(ICOLR(3).EQ.MAXCP2)TEMP3(NS3)=RES(I)
          IF(ICOLR(3).EQ.MAXCP3)TEMP3(NS3)=YPLOT(I)
          IF(ICOLR(3).EQ.MAXCP4)TEMP3(NS3)=XPLOT(I)
          IF(ICOLR(3).EQ.MAXCP5)TEMP3(NS3)=X2PLOT(I)
          IF(ICOLR(3).EQ.MAXCP6)TEMP3(NS3)=TAGPLO(I)
11131   CONTINUE
11139   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.4 .AND. ITYPA(4).EQ.'VARI')THEN
        DO 11141 I=1,NIRIGH(4)
          IF(ISUB(I).EQ.0)GO TO 11141
          IF(I.GT.NIRIGH(4))GO TO 11149
          NS4=NS4+1
          IJ=MAXN*(ICOLR(4)-1)+I
          IF(ICOLR(4).LE.MAXCOL)TEMP4(NS4)=V(IJ)
          IF(ICOLR(4).EQ.MAXCP1)TEMP4(NS4)=PRED(I)
          IF(ICOLR(4).EQ.MAXCP2)TEMP4(NS4)=RES(I)
          IF(ICOLR(4).EQ.MAXCP3)TEMP4(NS4)=YPLOT(I)
          IF(ICOLR(4).EQ.MAXCP4)TEMP4(NS4)=XPLOT(I)
          IF(ICOLR(4).EQ.MAXCP5)TEMP4(NS4)=X2PLOT(I)
          IF(ICOLR(4).EQ.MAXCP6)TEMP4(NS4)=TAGPLO(I)
11141   CONTINUE
11149   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.5 .AND. ITYPA(5).EQ.'VARI')THEN
        DO 11151 I=1,NIRIGH(5)
          IF(ISUB(I).EQ.0)GO TO 11151
          IF(I.GT.NIRIGH(5))GO TO 11159
          NS5=NS5+1
          IJ=MAXN*(ICOLR(5)-1)+I
          IF(ICOLR(5).LE.MAXCOL)TEMP5(NS5)=V(IJ)
          IF(ICOLR(5).EQ.MAXCP1)TEMP5(NS5)=PRED(I)
          IF(ICOLR(5).EQ.MAXCP2)TEMP5(NS5)=RES(I)
          IF(ICOLR(5).EQ.MAXCP3)TEMP5(NS5)=YPLOT(I)
          IF(ICOLR(5).EQ.MAXCP4)TEMP5(NS5)=XPLOT(I)
          IF(ICOLR(5).EQ.MAXCP5)TEMP5(NS5)=X2PLOT(I)
          IF(ICOLR(5).EQ.MAXCP6)TEMP5(NS5)=TAGPLO(I)
11151   CONTINUE
11159   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.6 .AND. ITYPA(6).EQ.'VARI')THEN
        DO 11161 I=1,NIRIGH(6)
          IF(ISUB(I).EQ.0)GO TO 11161
          IF(I.GT.NIRIGH(6))GO TO 11169
          NS6=NS6+1
          IJ=MAXN*(ICOLR(6)-1)+I
          IF(ICOLR(6).LE.MAXCOL)TEMP6(NS6)=V(IJ)
          IF(ICOLR(6).EQ.MAXCP1)TEMP6(NS6)=PRED(I)
          IF(ICOLR(6).EQ.MAXCP2)TEMP6(NS6)=RES(I)
          IF(ICOLR(6).EQ.MAXCP3)TEMP6(NS6)=YPLOT(I)
          IF(ICOLR(6).EQ.MAXCP4)TEMP6(NS6)=XPLOT(I)
          IF(ICOLR(6).EQ.MAXCP5)TEMP6(NS6)=X2PLOT(I)
          IF(ICOLR(6).EQ.MAXCP6)TEMP6(NS6)=TAGPLO(I)
11161   CONTINUE
11169   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.7 .AND. ITYPA(7).EQ.'VARI')THEN
        DO 11171 I=1,NIRIGH(7)
          IF(ISUB(I).EQ.0)GO TO 11171
          IF(I.GT.NIRIGH(6))GO TO 11179
          NS7=NS7+1
          IJ=MAXN*(ICOLR(7)-1)+I
          IF(ICOLR(7).LE.MAXCOL)TEMP7(NS7)=V(IJ)
          IF(ICOLR(7).EQ.MAXCP1)TEMP7(NS7)=PRED(I)
          IF(ICOLR(7).EQ.MAXCP2)TEMP7(NS7)=RES(I)
          IF(ICOLR(7).EQ.MAXCP3)TEMP7(NS7)=YPLOT(I)
          IF(ICOLR(7).EQ.MAXCP4)TEMP7(NS7)=XPLOT(I)
          IF(ICOLR(7).EQ.MAXCP5)TEMP7(NS7)=X2PLOT(I)
          IF(ICOLR(7).EQ.MAXCP6)TEMP7(NS7)=TAGPLO(I)
11171   CONTINUE
11179   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.8 .AND. ITYPA(8).EQ.'VARI')THEN
        DO 11181 I=1,NIRIGH(8)
          IF(ISUB(I).EQ.0)GO TO 11181
          IF(I.GT.NIRIGH(6))GO TO 11189
          NS8=NS8+1
          IJ=MAXN*(ICOLR(8)-1)+I
          IF(ICOLR(8).LE.MAXCOL)TEMP8(NS8)=V(IJ)
          IF(ICOLR(8).EQ.MAXCP1)TEMP8(NS8)=PRED(I)
          IF(ICOLR(8).EQ.MAXCP2)TEMP8(NS8)=RES(I)
          IF(ICOLR(8).EQ.MAXCP3)TEMP8(NS8)=YPLOT(I)
          IF(ICOLR(8).EQ.MAXCP4)TEMP8(NS8)=XPLOT(I)
          IF(ICOLR(8).EQ.MAXCP5)TEMP8(NS8)=X2PLOT(I)
          IF(ICOLR(8).EQ.MAXCP6)TEMP8(NS8)=TAGPLO(I)
11181   CONTINUE
11189   CONTINUE
      ENDIF
!
      IF(NUMVAR.GE.9 .AND. ITYPA(9).EQ.'VARI')THEN
        DO 11191 I=1,NIRIGH(9)
          IF(ISUB(I).EQ.0)GO TO 11191
          IF(I.GT.NIRIGH(6))GO TO 11199
          NS9=NS9+1
          IJ=MAXN*(ICOLR(9)-1)+I
          IF(ICOLR(9).LE.MAXCOL)TEMP9(NS9)=V(IJ)
          IF(ICOLR(9).EQ.MAXCP1)TEMP9(NS9)=PRED(I)
          IF(ICOLR(9).EQ.MAXCP2)TEMP9(NS9)=RES(I)
          IF(ICOLR(9).EQ.MAXCP3)TEMP9(NS9)=YPLOT(I)
          IF(ICOLR(9).EQ.MAXCP4)TEMP9(NS9)=XPLOT(I)
          IF(ICOLR(9).EQ.MAXCP5)TEMP9(NS9)=X2PLOT(I)
          IF(ICOLR(9).EQ.MAXCP6)TEMP9(NS9)=TAGPLO(I)
11191   CONTINUE
11199   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')THEN
        WRITE(ICOUT,11292)NINEW,ICASL7,ICASEQ
11292   FORMAT('11292--NINEW,ICASL7,ICASEQ = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11293)NS1,NS2,NS3,NS4,NS5,NS6,NS7
11293   FORMAT('NS1,NS2,NS3,NS4,NS5,NS6,NS7 = ',7I8)
        CALL DPWRST('XXX','BUG ')
        DO 11294 II=1,7
          WRITE(ICOUT,11291)II,ICOLR(II),ITYPA(II)
11291     FORMAT('II,ICOLR(II),ITYPA(II) = ',I8,2X,I8,2X,A4)
          CALL DPWRST('XXX','BUG ')
11294   CONTINUE
        WRITE(ICOUT,11296)IMATSW,ICASL7
11296   FORMAT('IMATSW,ICASL7 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     -----BRANCH TO THE PROPER CASE-----
!
      IWRITE='ON'
      IF(IPRINT.EQ.'OFF')IWRITE='OFF'
      IF(IFEEDB.EQ.'OFF')IWRITE='OFF'
!
      IF(ICASL7.EQ.'SORT')THEN
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')THEN
          DO 11310 I=1,NS1
            WRITE(ICOUT,11311)I,TEMP1(I)
11311       FORMAT('I,TEMP1(I) = ',I8,2X,F10.5)
            CALL DPWRST('XXX','BUG ')
11310     CONTINUE
        ENDIF
        CALL SORT(TEMP1,NS1,TEMP1)
!CCCC   CHECK DIRECTION.  JANUARY 2000.
        IF(ISORDI.EQ.'DESC')THEN
          DO 11315 I=1,NS1
            TEMP2(I)=TEMP1(I)
11315     CONTINUE
          DO 11317 I=1,NS1
            II=NS1-I+1
            TEMP1(I)=TEMP2(II)
11317     CONTINUE
        ENDIF
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')THEN
          DO 11312 I=1,NS1
            WRITE(ICOUT,11311)I,TEMP1(I)
            CALL DPWRST('XXX','BUG ')
11312     CONTINUE
        ENDIF
      ELSEIF(ICASL7.EQ.'SOR2')THEN
        CALL SORT2(TEMP1,TEMP2,N,IWRITE,TEMP91,TEMP92,   &
                   TEMP3,TEMP4,   &
                   ISORDI,ISUBRO,IBUGA3,IERROR)
        DO 11313 I=1,N
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
11313   CONTINUE
      ELSEIF(ICASL7.EQ.'SOR3')THEN
        CALL SORT3(TEMP1,TEMP2,TEMP3,N,IWRITE,TEMP91,TEMP92,TEMP4,   &
                   TEMP5,TEMP12(1),TEMP12(MAXOBV+1),TEMP6(1),   &
                   TEMP6(MAXOBV+1),TEMP6(2*MAXOBV+1),   &
                   TEMP6(3*MAXOBV+1),   &
                   ISORDI,ISUBRO,IBUGA3,IERROR)
        DO 11314 I=1,N
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
          TEMP91(I)=TEMP4(I)
11314   CONTINUE
      ELSEIF(ICASL7.EQ.'SOR4')THEN
        CALL SORT4(TEMP1,TEMP2,TEMP3,TEMP4,N,IWRITE,   &
                   TEMP91,TEMP92,TEMP5,TEMP6(1),   &
                   TEMP12(1),TEMP12(MAXOBV+1),   &
                   TEMP6(MAXOBV+1),TEMP6(2*MAXOBV+1),   &
                   TEMP6(3*MAXOBV+1),TEMP6(4*MAXOBV+1),   &
                   TEMP7,TEMP8,   &
                   TEMP21,TEMP22,TEMP23,   &
                   TEMP24,TEMP25,TEMP26,   &
                   ISORDI,ISUBRO,IBUGA3,IERROR)
        DO 11319 I=1,N
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
          TEMP91(I)=TEMP5(I)
          TEMP92(I)=TEMP6(I)
11319   CONTINUE
      ELSEIF(ICASL7.EQ.'2DGR')THEN
        CALL DP2DGR(TEMP1,NS1,TEMP2,NS2,IWRITE,   &
                    TEMP91,TEMP92,TEMP21,NITEMX,MAXOBV,   &
                    ISUBRO,IBUGA3,IERROR)
        DO 14323 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
14323   CONTINUE
        IUPFLG='FULL'
      ELSEIF(ICASL7.EQ.'3DGR')THEN
