            CALL CHECKN(IH1,IH2,IHWUSE,   &
                 IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                 ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
            IF(IERROR.EQ.'YES')GO TO 19000
            ICOLRI=IVALUE(ILOC)
            NITEMP=IN(ILOC)
!
            CALL DPSUBS(NITEMP,ILOCS,NSTEMP,IBUGQ,IERROR)
!
            NR=0
            DO 11413 I=1,NITEMP
              IF(ISUB(I).EQ.0)GO TO 11413
              NR=NR+1
              IJ=MAXN*(ICOLRI-1)+NR
              IF(ICOLRI.LE.MAXCOL)TEMP2(NR)=V(IJ)
              IF(ICOLRI.EQ.MAXCP1)TEMP2(NR)=PRED(I)
              IF(ICOLRI.EQ.MAXCP2)TEMP2(NR)=RES(I)
              IF(ICOLRI.EQ.MAXCP3)TEMP2(NR)=YPLOT(I)
              IF(ICOLRI.EQ.MAXCP4)TEMP2(NR)=XPLOT(I)
              IF(ICOLRI.EQ.MAXCP5)TEMP2(NR)=X2PLOT(I)
              IF(ICOLRI.EQ.MAXCP6)TEMP2(NR)=TAGPLO(I)
11413       CONTINUE
!
            DO 11414 I=1,NR
              J=INT(TEMP91(I)+0.5)
              TEMP3(I)=TEMP2(J)
11414       CONTINUE
            IF(ISORDI.EQ.'DESC')THEN
              DO 11416 I=1,NR
                TEMP4(I)=TEMP3(I)
11416         CONTINUE
              DO 11419 I=1,NR
                II=NR-I+1
                TEMP3(I)=TEMP4(II)
11419         CONTINUE
            ENDIF
!
            J=0
            DO 11415 I=1,NITEMP
              IF(ISUB(I).EQ.0)GO TO 11415
              J=J+1
              IJ=MAXN*(ICOLRI-1)+I
              IF(ICOLRI.LE.MAXCOL)V(IJ)=TEMP3(J)
              IF(ICOLRI.EQ.MAXCP1)PRED(I)=TEMP3(J)
              IF(ICOLRI.EQ.MAXCP2)RES(I)=TEMP3(J)
              IF(ICOLRI.EQ.MAXCP3)YPLOT(I)=TEMP3(J)
              IF(ICOLRI.EQ.MAXCP4)XPLOT(I)=TEMP3(J)
              IF(ICOLRI.EQ.MAXCP5)X2PLOT(I)=TEMP3(J)
              IF(ICOLRI.EQ.MAXCP6)TAGPLO(I)=TEMP3(J)
11415       CONTINUE
11412     CONTINUE
11418   CONTINUE
!
!CCCC THE FOLLOWING STACK SECTION ADDED MAY 2003
!CCCC FEBRUARY 2005: ADD SUPPORT FOR REPLICATED STACK.  IN THIS
!CCCC                CASE, LAST VARIABLE IS A REPLICATION NUMBER
!CCCC                THAT WILL BE DUPLICATED FOR EACH GROUP.
!
      ELSEIF(ICASL7.EQ.'STAC' .OR. ICASL7.EQ.'RSTA')THEN
        IF(NUMARG.LE.4)GO TO 91499
        IF(ICASL7.EQ.'RSTA' .AND. NUMARG.LE.6)GO TO 91499
!
        ICNT=0
        IVARCN=0
        NLAST=NUMARG
        NSTRT=5
        IF(ICASL7.EQ.'RSTA')NSTRT=7
        IF(ICASL7.EQ.'RSTA')THEN
          NLAST=NUMARG-1
          DO 91403 II=NSTRT,NUMARG
            IH1=IHARG(II)
            IH2=IHARG2(II)
            IF(IH1.EQ.'SUBS'.AND.IH2.EQ.'ET  ')THEN
              NLAST=II-1
              GO TO 91407
            ELSEIF(IH1.EQ.'EXCE'.AND.IH2.EQ.'PT  ')THEN
              NLAST=II-1
              GO TO 91407
            ELSEIF(IH1.EQ.'FOR '.AND.IH2.EQ.'    ')THEN
              NLAST=II-1
              GO TO 91407
            ENDIF
91403     CONTINUE
91407     CONTINUE
          NREPL=NLAST+1
        ENDIF
!
        DO 91412 ILOCRI=NSTRT,NLAST
!
          IF(ICASL7.EQ.'RSTA')THEN
            IHREPL=IHARG(NREPL)
            IHREP2=IHARG2(NREPL)
            IF(IHREPL.EQ.'SUBS'.AND.IHREP2.EQ.'ET  ')GO TO 91499
            IF(IHREPL.EQ.'EXCE'.AND.IHREP2.EQ.'PT  ')GO TO 91499
            IF(IHREPL.EQ.'FOR '.AND.IHREP2.EQ.'    ')GO TO 91499
            IHWUSE='V'
            MESSAG='YES'
            CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
            IF(IERROR.EQ.'YES')GO TO 19000
            ICOLRP=IVALUE(ILOC)
            NIREPL=IN(ILOC)
          ENDIF
!
          IHREPL=IHARG(ILOCRI)
          IHREP2=IHARG2(ILOCRI)
          IF(IHREPL.EQ.'SUBS'.AND.IHREP2.EQ.'ET  ')GO TO 91499
          IF(IHREPL.EQ.'EXCE'.AND.IHREP2.EQ.'PT  ')GO TO 91499
          IF(IHREPL.EQ.'FOR '.AND.IHREP2.EQ.'    ')GO TO 91499
          IHWUSE='V'
          MESSAG='YES'
          CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
               IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
               ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
          IF(IERROR.EQ.'YES')GO TO 19000
          ICOLRI=IVALUE(ILOC)
          NITEMP=IN(ILOC)
          IVARCN=IVARCN+1
!
          CALL DPSUBS(NITEMP,ILOCS,NSTEMP,IBUGQ,IERROR)
!
          NR=0
          DO 91413 I=1,NITEMP
            IF(ISUB(I).EQ.0)GO TO 91413
            NR=NR+1
            IJ=MAXN*(ICOLRI-1)+NR
            IF(ICOLRI.LE.MAXCOL)ATEMP=V(IJ)
            IF(ICOLRI.EQ.MAXCP1)ATEMP=PRED(I)
            IF(ICOLRI.EQ.MAXCP2)ATEMP=RES(I)
            IF(ICOLRI.EQ.MAXCP3)ATEMP=YPLOT(I)
            IF(ICOLRI.EQ.MAXCP4)ATEMP=XPLOT(I)
            IF(ICOLRI.EQ.MAXCP5)ATEMP=X2PLOT(I)
            IF(ICOLRI.EQ.MAXCP6)ATEMP=TAGPLO(I)
!
            IF(ICASL7.EQ.'RSTA')THEN
              IJ=MAXN*(ICOLRP-1)+NR
              IF(ICOLRP.LE.MAXCOL)ATEMP2=V(IJ)
              IF(ICOLRP.EQ.MAXCP1)ATEMP2=PRED(I)
              IF(ICOLRP.EQ.MAXCP2)ATEMP2=RES(I)
              IF(ICOLRP.EQ.MAXCP3)ATEMP2=YPLOT(I)
              IF(ICOLRP.EQ.MAXCP4)ATEMP2=XPLOT(I)
              IF(ICOLRP.EQ.MAXCP5)ATEMP2=X2PLOT(I)
              IF(ICOLRP.EQ.MAXCP6)ATEMP2=TAGPLO(I)
            ENDIF
!
            ICNT=ICNT+1
            IF(ICNT.GT.MAXOBV)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,91417)
91417         FORMAT('****** WARNING FROM STACK COMMAND--')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,91419)
91419         FORMAT('       MAXIMUM NUMBER OF ROWS, ',I8,   &
                     ' HAS BEEN EXCEEDED.')
              CALL DPWRST('XXX','BUG ')
              GO TO 91418
            ENDIF
!
            TEMP1(ICNT)=ATEMP
            TEMP2(ICNT)=REAL(IVARCN)
            TEMP91(ICNT)=ATEMP2
91413     CONTINUE
!
          J=0
          DO 91415 I=1,NITEMP
            IF(ISUB(I).EQ.0)GO TO 91415
            J=J+1
91415     CONTINUE
91412   CONTINUE
91418   CONTINUE
!
        NITEMX=ICNT
        IFOUND='YES'
        GO TO 11900
!
91499   CONTINUE
        IERROR='YES'
        GO TO 9000
!
!     FOR COMBINE COMMAND, ADD LIST OF VARIABLES/PARAMETERS TO
!     CREATE A SINGLE OUTPUT VECTOR.
!
      ELSEIF(ICASL7.EQ.'COMB')THEN
!
        ICNT=0
        IVARCN=0
        NLAST=NUMARG
        NSTRT=4
!
        DO 91712 ILOCRI=NSTRT,NLAST
!
          IHREPL=IHARG(ILOCRI)
          IHREP2=IHARG2(ILOCRI)
          ATEMPP=ARG(ILOCRI)
          IF(IHREPL.EQ.'SUBS'.AND.IHREP2.EQ.'ET  ')GO TO 91799
          IF(IHREPL.EQ.'EXCE'.AND.IHREP2.EQ.'PT  ')GO TO 91799
          IF(IHREPL.EQ.'FOR '.AND.IHREP2.EQ.'    ')GO TO 91799
!
!         CHECK FOR MATRIX OR STRING (THESE NOT CURRENTLY
!         SUPPORTED FOR COMBINE COMMAND)
!
          IHWUSE='M'
          MESSAG='NO'
          CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
               IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
               ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
          IF(IERROR.EQ.'NO')THEN
            WRITE(ICOUT,91731)
91731       FORMAT('****** ERROR FROM COMBINE COMMAND--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,91733)IHREPL,IHREP2
91733       FORMAT('       MATRICES ARE NOT ALLOWED.  ',A4,A4,   &
                   'IS A MATRIX.')
            CALL DPWRST('XXX','BUG ')
            IFOUND='YES'
            IERROR='YES'
            GO TO 8000
          ENDIF
!
          IHWUSE='F'
          MESSAG='NO'
          CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
               IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
               ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
          IF(IERROR.EQ.'NO')THEN
            WRITE(ICOUT,91731)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,91735)IHREPL,IHREP2
91735       FORMAT('       FUNCTIONS (STRINGS) ARE NOT ALLOWED.  ',   &
                   A4,A4,'IS A FUNCTION OR A STRING.')
            CALL DPWRST('XXX','BUG ')
            IFOUND='YES'
            IERROR='YES'
            GO TO 8000
          ENDIF
!
!         CHECK FOR PARAMETER
!
          IHWUSE='P'
          MESSAG='NO'
          CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
               IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
               ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
          IF(IERROR.EQ.'NO')THEN
            ICNT=ICNT+1
            IF(ICNT.GT.MAXOBV)GO TO 91716
            TEMP1(ICNT)=VALUE(ILOC)
            GO TO 91712
          ENDIF
!
!         CHECK FOR VARIABLE - IF NOT PARAMETER, VARIABLE, MATRIX,
!                              OR STRING/FUNCTION, ASSUME ARGUMENT
!                              IS A NUMERIC VALUE.
!
          IHWUSE='V'
          MESSAG='NO'
          CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
               IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
               ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
          IF(IERROR.EQ.'YES')THEN
            ICNT=ICNT+1
            IF(ICNT.GT.MAXOBV)GO TO 91716
            TEMP1(ICNT)=ATEMPP
            GO TO 91712
          ENDIF
!
          ICOLRI=IVALUE(ILOC)
          NITEMP=IN(ILOC)
!
          CALL DPSUBS(NITEMP,ILOCS,NSTEMP,IBUGQ,IERROR)
!
          NR=0
          DO 91713 I=1,NITEMP
            IF(ISUB(I).EQ.0)GO TO 91713
            NR=NR+1
            IJ=MAXN*(ICOLRI-1)+NR
            IF(ICOLRI.LE.MAXCOL)ATEMP=V(IJ)
            IF(ICOLRI.EQ.MAXCP1)ATEMP=PRED(I)
            IF(ICOLRI.EQ.MAXCP2)ATEMP=RES(I)
            IF(ICOLRI.EQ.MAXCP3)ATEMP=YPLOT(I)
            IF(ICOLRI.EQ.MAXCP4)ATEMP=XPLOT(I)
            IF(ICOLRI.EQ.MAXCP5)ATEMP=X2PLOT(I)
            IF(ICOLRI.EQ.MAXCP6)ATEMP=TAGPLO(I)
!
            ICNT=ICNT+1
            IF(ICNT.GT.MAXOBV)GO TO 91716
!
            TEMP1(ICNT)=ATEMP
91713     CONTINUE
!
91712   CONTINUE
!
        NITEMX=ICNT
        IFOUND='YES'
        IERROR='NO'
        GO TO 11900
!
91799   CONTINUE
        IERROR='YES'
        GO TO 9000
!
91716   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,91717)
91717   FORMAT('****** WARNING FROM COMBINE COMMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,91719)
91719   FORMAT('       MAXIMUM NUMBER OF ROWS, ',I8,   &
               ' HAS BEEN EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
        NITEMX=ICNT
        IFOUND='YES'
        GO TO 11900
!
      ELSEIF(ICASL7.EQ.'FREQ')THEN
        CALL FREQUE(TEMP1,NS1,TEMP2,NS2,NUMVAR,IWRITE,   &
                    TEMP91,NITEMX,IBUGA3,IERROR)
        DO 11425 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11425   CONTINUE
      ELSEIF(ICASL7.EQ.'JITT')THEN
        DELTA=TEMPS(2)
        CALL JITTER(TEMP1,NS1,DELTA,   &
                    TEMP91,NITEMX,ISEED,IBUGA3,IERROR)
        DO 11428 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11428   CONTINUE
      ELSEIF(ICASL7.EQ.'COPV')THEN
!
!       NOTE 7/16/2008:
!       FOR VARIABLE COPY, COPY OVER CONTENTS OF VARIABLE
!       ON RIGHT HAND SIDE.  THE SUBSET/EXCEPT/FOR WILL BE
!       HANDLED WHEN WE UPDATE THE LEFT HAND SIDE VARIABLE.
!       DO THIS SO THAT "ROW INDEX" MAINTAINED ON SUBSET
!       CLAUSES.
!
!       MARCH 2009: PUT IN A CHECK FOR AN EMPTY SUBSET.
!                   IN THIS CASE, WE WANT TO DO NOTHING.
!
        DO 11426 I=1,NINEW
          IJ=MAXN*(ICOLR(1)-1)+I
          IF(ICOLR(1).LE.MAXCOL)TEMP1(I)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)TEMP1(I)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)TEMP1(I)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)TEMP1(I)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)TEMP1(I)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)TEMP1(I)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)TEMP1(I)=TAGPLO(I)
11426   CONTINUE
        NITEMX=NINEW
        NSX=0
        DO 11427 I=1,NITEMX
          IF(ISUB(I).EQ.1)NSX=NSX+1
11427   CONTINUE
        IF(NSX.EQ.0)THEN
          IFOUND='YES'
          IERROR='NO'
          GO TO 19000
        END IF
      ELSEIF(ICASL7.EQ.'AGCO')THEN
!
!       AUGUST 2008: ALLOW P AND N TO BE EITHER VECTORS OR
!                    SCALARS.  NOTE THAT ALPHA WILL ALWAYS
!                    BE A SCALAR.
!
        ALPHAT=TEMPS(3)
!
        IF(ITYPA(1).EQ.'PARA' .AND. ITYPA(2).EQ.'PARA')THEN
          PTEMP=TEMPS(1)
          NTEMP=INT(TEMPS(2)+0.5)
          CALL DPAGCO(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                      ALOWLM,AUPPLM,IBUGA3,IERROR)
          SCAL91=ALOWLM
          ITYP91='SCAL'
          SCAL92=AUPPLM
          ITYP92='SCAL'
        ELSEIF(ITYPA(1).EQ.'VARI' .OR. ITYPA(2).EQ.'VARI')THEN
          DO 11431 I=1,NINEW
            IF(ITYPA(1).EQ.'VARI')THEN
              PTEMP=TEMP1(I)
            ELSE
              PTEMP=TEMPS(1)
            ENDIF
            IF(ITYPA(2).EQ.'VARI')THEN
              NTEMP=INT(TEMP2(I)+0.5)
            ELSE
              NTEMP=INT(TEMPS(2)+0.5)
            ENDIF
            CALL DPAGCO(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                        ALOWLM,AUPPLM,IBUGA3,IERROR)
            TEMP1(I)=ALOWLM
            TEMP2(I)=AUPPLM
11431     CONTINUE
          ITYP91='VARI'
          ITYP92='VARI'
        ENDIF
      ELSEIF(ICASL7.EQ.'EBLL')THEN
!
!       AUGUST 2008: ALLOW P AND N TO BE EITHER VECTORS OR
!                    SCALARS.  NOTE THAT ALPHA WILL ALWAYS
!                    BE A SCALAR.
!
        ALPHAT=TEMPS(3)
!
        IF(ITYPA(1).EQ.'PARA' .AND. ITYPA(2).EQ.'PARA')THEN
          PTEMP=TEMPS(1)
          NTEMP=INT(TEMPS(2)+0.5)
          CALL DPEBLL(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                      ALOWLM,'TWOS',IBUGA3,IERROR)
          SCAL91=ALOWLM
          ITYP91='SCAL'
        ELSEIF(ITYPA(1).EQ.'VARI' .OR. ITYPA(2).EQ.'VARI')THEN
          DO 11432 I=1,NINEW
            IF(ITYPA(1).EQ.'VARI')THEN
              PTEMP=TEMP1(I)
            ELSE
              PTEMP=TEMPS(1)
            ENDIF
            IF(ITYPA(2).EQ.'VARI')THEN
              NTEMP=INT(TEMP2(I)+0.5)
            ELSE
              NTEMP=INT(TEMPS(2)+0.5)
            ENDIF
            CALL DPEBLL(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                        ALOWLM,'TWOS',IBUGA3,IERROR)
            TEMP1(I)=ALOWLM
11432     CONTINUE
          ITYP91='VARI'
        ENDIF
      ELSEIF(ICASL7.EQ.'EBUL')THEN
!
!       AUGUST 2008: ALLOW P AND N TO BE EITHER VECTORS OR
!                    SCALARS.  NOTE THAT ALPHA WILL ALWAYS
!                    BE A SCALAR.
!
        ALPHAT=TEMPS(3)
!
        IF(ITYPA(1).EQ.'PARA' .AND. ITYPA(2).EQ.'PARA')THEN
          PTEMP=TEMPS(1)
          NTEMP=INT(TEMPS(2)+0.5)
          CALL DPEBUL(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                      AUPPLM,'TWOS',IBUGA3,IERROR)
          SCAL91=AUPPLM
          ITYP91='SCAL'
        ELSEIF(ITYPA(1).EQ.'VARI' .OR. ITYPA(2).EQ.'VARI')THEN
          DO 11433 I=1,NINEW
            IF(ITYPA(1).EQ.'VARI')THEN
              PTEMP=TEMP1(I)
            ELSE
              PTEMP=TEMPS(1)
            ENDIF
            IF(ITYPA(2).EQ.'VARI')THEN
              NTEMP=INT(TEMP2(I)+0.5)
            ELSE
              NTEMP=INT(TEMPS(2)+0.5)
            ENDIF
            CALL DPEBUL(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                        AUPPLM,'TWOS',IBUGA3,IERROR)
            TEMP1(I)=AUPPLM
11433     CONTINUE
          ITYP91='VARI'
        ENDIF
      ELSEIF(ICASL7.EQ.'EBCL')THEN
!
!       ALLOW P AND N TO BE EITHER VECTORS OR SCALARS.  NOTE THAT
!       ALPHA WILL ALWAYS BE A SCALAR.
!
        ALPHAT=TEMPS(3)
!
        IF(ITYPA(1).EQ.'PARA' .AND. ITYPA(2).EQ.'PARA')THEN
          PTEMP=TEMPS(1)
          NTEMP=INT(TEMPS(2)+0.5)
          CALL DPEBLL(PTEMP,NTEMP,P2,IWRITE,   &
                      ALOWLM,'TWOS',IBUGA3,IERROR)
          CALL DPEBUL(PTEMP,NTEMP,P2,IWRITE,   &
                      AUPPLM,'TWOS',IBUGA3,IERROR)
          SCAL91=ALOWLM
          ITYP91='SCAL'
          SCAL92=AUPPLM
          ITYP92='SCAL'
        ELSEIF(ITYPA(1).EQ.'VARI' .OR. ITYPA(2).EQ.'VARI')THEN
          DO 11443 I=1,NINEW
            IF(ITYPA(1).EQ.'VARI')THEN
              PTEMP=TEMP1(I)
            ELSE
              PTEMP=TEMPS(1)
            ENDIF
            IF(ITYPA(2).EQ.'VARI')THEN
              NTEMP=INT(TEMP2(I)+0.5)
            ELSE
              NTEMP=INT(TEMPS(2)+0.5)
            ENDIF
            CALL DPEBLL(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                        ALOWLM,'TWOS',IBUGA3,IERROR)
            TEMP1(I)=ALOWLM
            CALL DPEBUL(PTEMP,NTEMP,ALPHAT,IWRITE,   &
                        AUPPLM,'TWOS',IBUGA3,IERROR)
            TEMP2(I)=AUPPLM
11443     CONTINUE
          ITYP91='VARI'
          ITYP92='VARI'
        ENDIF
      ELSEIF(ICASL7.EQ.'DPCL')THEN
!
        ALPHAT=TEMPS(5)
!
        IF(ITYPA(1).EQ.'PARA' .AND. ITYPA(2).EQ.'PARA' .AND.   &
           ITYPA(3).EQ.'PARA' .AND. ITYPA(4).EQ.'PARA')THEN
          P1TEMP=TEMPS(1)
          N1TEMP=INT(TEMPS(2)+0.5)
          P2TEMP=TEMPS(3)
          N2TEMP=INT(TEMPS(4)+0.5)
          CALL DPDPCL(P1TEMP,N1TEMP,P2TEMP,N2TEMP,ALPHAT,IWRITE,   &
                      PDIFF,ALOWLM,AUPPLM,IBUGA3,IERROR)
          SCAL91=PDIFF
          ITYP91='SCAL'
          SCAL92=ALOWLM
          ITYP92='SCAL'
          SCAL93=AUPPLM
          ITYP93='SCAL'
        ELSEIF(ITYPA(1).EQ.'VARI' .OR. ITYPA(2).EQ.'VARI' .OR.   &
               ITYPA(3).EQ.'VARI' .OR. ITYPA(4).EQ.'VARI')THEN
          DO 11436 I=1,NINEW
            IF(ITYPA(1).EQ.'VARI')THEN
              P1TEMP=TEMP1(I)
            ELSE
              P1TEMP=TEMPS(1)
            ENDIF
            IF(ITYPA(2).EQ.'VARI')THEN
              N1TEMP=INT(TEMP2(I)+0.5)
            ELSE
              N1TEMP=INT(TEMPS(2)+0.5)
            ENDIF
            IF(ITYPA(3).EQ.'VARI')THEN
              P2TEMP=TEMP3(I)
            ELSE
              P2TEMP=TEMPS(3)
            ENDIF
            IF(ITYPA(4).EQ.'VARI')THEN
              N2TEMP=INT(TEMP4(I)+0.5)
            ELSE
              N2TEMP=INT(TEMPS(4)+0.5)
            ENDIF
            CALL DPDPCL(P1TEMP,N1TEMP,P2TEMP,N2TEMP,ALPHAT,IWRITE,   &
                        PDIFF,ALOWLM,AUPPLM,IBUGA3,IERROR)
            TEMP1(I)=PDIFF
            TEMP2(I)=ALOWLM
            TEMP91(I)=AUPPLM
11436     CONTINUE
          ITYP91='VARI'
          ITYP92='VARI'
          ITYP93='VARI'
        ENDIF
      ELSEIF(ICASL7.EQ.'DPTS' .OR. ICASL7.EQ.'DPLT' .OR.   &
             ICASL7.EQ.'DPUT')THEN
!
        IF(ICASL7.EQ.'DPTS')THEN
          ICASAN='BPTS'
        ELSEIF(ICASL7.EQ.'DPLT')THEN
          ICASAN='BPLT'
        ELSEIF(ICASL7.EQ.'DPUT')THEN
          ICASAN='BPUT'
        ENDIF
!
        ALPHAT=TEMPS(5)
!
        IF(ITYPA(1).EQ.'PARA' .AND. ITYPA(2).EQ.'PARA' .AND.   &
