        CALL SETARI(TEMP1,TEMP2,NS1,NS2,IACASE,IWRITE,   &
                    TEMP91,TEMP92,NITEMX,SCAL91,ITYP91,   &
                    TEMP21,TEMP22,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        IF(ITYP91.EQ.'SCAL')GO TO 11869
        DO 11865 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
11865   CONTINUE
11869   CONTINUE
      ELSEIF(ICASL7.EQ.'LOAN'.OR.ICASL7.EQ.'LOOR'.OR.   &
             ICASL7.EQ.'LONA'.OR.ICASL7.EQ.'LONO'.OR.   &
             ICASL7.EQ.'LOIM'.OR.ICASL7.EQ.'LOEQ'.OR.   &
             ICASL7.EQ.'LONT'.OR.ICASL7.EQ.'LOXO')THEN
        IACASE=ICASL7
        CALL LOGARI(TEMP1,TEMP2,NS1,IACASE,IWRITE,   &
                    TEMP91,NITEMX,SCAL91,ITYP91,IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        IF(ITYP91.EQ.'SCAL')GO TO 11879
        DO 11875 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11875   CONTINUE
11879   CONTINUE
      ELSEIF(ICASL7.EQ.'FRAC')THEN
        IPROD=4*NS1
        IF(IPROD.GT.MAXOBV)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11511)
11511     FORMAT('***** ERROR 11511 IN DPMATC--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11512)
11512     FORMAT('      THE NEW FRACTAL VARIABLES WOULD BE ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11513)
11513     FORMAT('      TOO LONG (THAT IS, WOULD EXCEED ',I8,')')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        CALL FRACTA(TEMP1,TEMP2,NS1,IWRITE,   &
                    TEMP91,TEMP92,NITEMX,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        DO 11519 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
11519   CONTINUE
      ELSEIF(ICASL7.EQ.'BOOT')THEN
        CALL BOOTSS(TEMP1,TEMP2,NS1,IWRITE,   &
                    TEMP91,NITEMX,   &
                    TEMP21,TEMP22,   &
                    IBUGA3,ISUBRO,IERROR)
        DO 11525 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11525   CONTINUE
      ELSEIF(ICASL7.EQ.'SUBS')THEN
        CALL SUBSAM(TEMP1,TEMP2,NS1,NS2,IWRITE,   &
                    TEMP91,NITEMX,IBUGA3,ISUBRO,IERROR)
        DO 11535 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11535   CONTINUE
      ELSEIF(ICASL7.EQ.'NNE1' .OR. ICASL7.EQ.'NNE2' .OR.   &
             ICASL7.EQ.'NNE3' .OR. ICASL7.EQ.'NNE4')THEN
        CALL NEARNE(TEMP1,TEMP2,NS1,TEMP91,TEMP92,   &
                    IBUGA3,ISUBRO,IERROR)
        NITEMX=NS1
        IF(ICASL7.EQ.'NNE1' .OR. ICASL7.EQ.'NNE4')THEN
          DO 11541 I=1,NITEMX
            TEMP1(I)=TEMP91(I)
11541     CONTINUE
        ELSEIF(ICASL7.EQ.'NNE2')THEN
          DO 11543 I=1,NITEMX
            TEMP1(I)=TEMP92(I)
11543     CONTINUE
        ELSEIF(ICASL7.EQ.'NNE3')THEN
          DO 11544 I=1,NITEMX
            TEMP1(I)=TEMP91(I)
            TEMP2(I)=TEMP92(I)
11544     CONTINUE
        ENDIF
      ELSEIF(ICASL7.EQ.'FNNE' .OR. ICASL7.EQ.'ANNE')THEN
        ICASET=1
        IF(ICASL7.EQ.'ANNE')ICASET=2
        CALL NEARN2(TEMP1,TEMP2,NS1,TEMP3,TEMP4,NS3,ICASET,MAXOBV,   &
                    TEMP24,TEMP5,TEMP7,TEMP8,TEMP25,   &
                    TEMP91,TEMP92,TEMP21,TEMP22,TEMP23,NITEMX,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IF(ICASL7.EQ.'FNNE')THEN
          DO 11644 I=1,NITEMX
            TEMP1(I)=TEMP91(I)
            TEMP2(I)=TEMP92(I)
            TEMP91(I)=TEMP21(I)
11644     CONTINUE
        ELSEIF(ICASL7.EQ.'ANNE')THEN
          DO 11646 I=1,NITEMX
            TEMP1(I)=TEMP91(I)
            TEMP2(I)=TEMP92(I)
            TEMP91(I)=TEMP21(I)
            TEMP92(I)=TEMP22(I)
            TEMP5(I)=TEMP23(I)
11646     CONTINUE
          NS4=NITEMX
          NS5=NITEMX
        ENDIF
      ELSEIF(ICASL7.EQ.'GEMU')THEN
        IACASE=ICASL7
!CCCC   CALL GENARI(TEMP1,TEMP2,TEMP3,TEMP4,NS1,NS3,ICASE,MAXOBV,
!CCCC1              TEMP91,TEMP92,NITEMX,NITE2X,SCAL91,ITYP91,
!CCCC1              IBUGA3,ISUBRO,IERROR)
        CALL GENARI(TEMP1,TEMP2,TEMP2,TEMP2,NS1,NS2,ICASE,IWRITE,   &
                    TEMP91,TEMP92,NITEMX,NITE2X,SCAL91,ITYP91,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        IF(ITYP91.EQ.'SCAL')GO TO 11899
        DO 11895 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11895   CONTINUE
11899   CONTINUE
      GO TO 11900
!
      ELSEIF(ICASL7.EQ.'JAIN')THEN
        CALL JACKIN(TEMPS(1),TEMPS(2),IWRITE,   &
                    TEMP91,NITEMX,IBUGA3,ISUBRO,IERROR)
        DO 11545 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11545   CONTINUE
      ELSEIF(ICASL7.EQ.'FRAW')THEN
        CALL DPRAW(TEMP1,TEMP2,NS1,IWRITE,MAXOBV,TEMP3,NITEMX,   &
                   IBUGA3,IERROR)
        IF(IERROR.EQ.'NO')THEN
          DO 11555 I=1,NITEMX
            TEMP1(I)=TEMP3(I)
11555     CONTINUE
        ENDIF
      ELSEIF(ICASL7.EQ.'CUSA' .OR. ICASL7.EQ.'CU1A')THEN
        ICASE='TWOS'
        IF(ICASL7.EQ.'CU1A')ICASE='ONES'
        CALL CUSARL(TEMP1,NS1,IWRITE,TEMP2,ICASE,IBUGA3,IERROR)
        DO 21019 I=1,NS1
          TEMP1(I)=TEMP2(I)
21019   CONTINUE
      ELSEIF(ICASL7.EQ.'SRTB')THEN
        CALL SRTMEA(TEMP1,TEMP2,NS1,ICASS7,ISTARA,   &
                    MAXOBV,   &
                    TEMP12,TEMP4,TEMP5,TEMP6,TEMP92,   &
                    TEMP27,TEMP28,   &
                    TEMP6(2*MAXOBV+1),TEMP6(3*MAXOBV+1),   &
                    TEMP91,TEMP3,NUMSE1,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISUBRO,IBUGA3,IERROR)
        DO 21031 I=1,NS1
          TEMP1(I)=TEMP91(I)
21031   CONTINUE
        DO 21033 I=1,NUMSE1
          TEMP2(I)=TEMP3(I)
21033   CONTINUE
      ELSEIF(ICASL7.EQ.'MNRK'.OR.ICASL7.EQ.'MDRK')THEN
        CALL GRPRNK(TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,TEMP8,   &
                    NS1,NUMVAR,MAXOBV,ICASE,   &
                    TEMP21,TEMP22,TEMP23,TEMP24,   &
                    TEMP25,TEMP26,TEMP12,TEMPC1,   &
                    ITEMP1,   &
                    TEMP92,TEMP9,TEMP6(MAXOBV+1),TEMP6(2*MAXOBV+1),   &
                    TEMP91,NITEMX,   &
                    ISUBRO,IBUGA3,IERROR)
        NS1=NITEMX
        DO 21034 II=1,NITEMX
          TEMP1(II)=TEMP91(II)
21034   CONTINUE
      ELSEIF(ICASL7.EQ.'STAN'.OR.ICASL7.EQ.'ZSCO'.OR.   &
             ICASL7.EQ.'USCO'.OR.ICASL7.EQ.'LSTA'.OR.   &
             ICASL7.EQ.'LSST'.OR.ICASL7.EQ.'CRTA'.OR.   &
             ICASL7.EQ.'CTCU'.OR.   &
             ICASL7(1:2).EQ.'CT')THEN
!
        IF(ICASL7.EQ.'CTCU')THEN
          ICASE='CTCU'
          ICASE2=ICASL7
        ELSE
          ICASE='STAN'
          ICASE2='    '
          IF(ICASL7.EQ.'LSTA')ICASE='LOCA'
          IF(ICASL7.EQ.'LSST')ICASE='SCAL'
          IF(ICASL7.EQ.'ZSCO')ICASE='ZSCO'
          IF(ICASL7.EQ.'USCO')ICASE='USCO'
          IF(ICASL7(1:2).EQ.'CT')THEN
            ICASE='CRTA'
            ICASE2=ICASL7
          ENDIF
        ENDIF
!
        IF(ISTANR.LE.0 .OR. ICASS7(1:3).EQ.'GRO' .OR.   &
           ICASS7.EQ.'NUMB')THEN
          IF(ICASS7(1:3).EQ.'GRO')ISTANR=0
          IF(ICASS7.EQ.'NUMB')ISTANR=0
          CALL GRPSTA(TEMP1,TEMP1,TEMP1,   &
                      TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,NS1,   &
                      ISTANR,NUMVAR,   &
                      ICASE,ICASE2,ICASS7,ISTARA,MAXOBV,   &
                      TEMP21,TEMP22,TEMP23,TEMP24,   &
                      TEMP6(MAXOBV+1),TEMP6(MAXOBV+2),   &
                      TEMP26,TEMP12,TEMP12(MAXOBV+1),   &
                      TEMPC1,TEMP25,TEMP8,TEMP27,TEMP28,   &
                      TEMP91,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      ISUBRO,IBUGA3,IERROR)
        ELSEIF(ISTANR.LE.1)THEN
          CALL GRPSTA(TEMP1,TEMP1,TEMP1,   &
                      TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,NS1,   &
                      ISTANR,NUMVAR,   &
                      ICASE,ICASE2,ICASS7,ISTARA,MAXOBV,   &
                      TEMP21,TEMP22,TEMP23,TEMP24,   &
                      TEMP6(MAXOBV+1),TEMP6(MAXOBV+2),   &
                      TEMP26,TEMP12,TEMP12(MAXOBV+1),   &
                      TEMPC1,TEMP25,TEMP8,TEMP27,TEMP28,   &
                      TEMP91,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      ISUBRO,IBUGA3,IERROR)
        ELSEIF(ISTANR.LE.2)THEN
          CALL GRPSTA(TEMP1,TEMP2,TEMP2,   &
                      TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,TEMP8,NS1,   &
                      ISTANR,NUMVAR,   &
                      ICASE,ICASE2,ICASS7,ISTARA,MAXOBV,   &
                      TEMP21,TEMP22,TEMP23,TEMP24,   &
                      TEMP6(MAXOBV+1),TEMP6(MAXOBV+2),   &
                      TEMP26,TEMP12,TEMP12(MAXOBV+1),   &
                      TEMPC1,TEMP25,TEMP6(MAXOBV+3),   &
                      TEMP27,TEMP28,   &
                      TEMP91,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      ISUBRO,IBUGA3,IERROR)
        ELSEIF(ISTANR.LE.3)THEN
          CALL GRPSTA(TEMP1,TEMP2,TEMP3,   &
                      TEMP4,TEMP5,TEMP6,TEMP7,TEMP8,TEMP9,NS1,   &
                      ISTANR,NUMVAR,   &
                      ICASE,ICASE2,ICASS7,ISTARA,MAXOBV,   &
                      TEMP21,TEMP22,TEMP23,TEMP24,   &
                      TEMP6(MAXOBV+1),TEMP6(MAXOBV+2),   &
                      TEMP26,TEMP12,TEMP12(MAXOBV+1),   &
                      TEMPC1,TEMP25,TEMP6(MAXOBV+3),   &
                      TEMP27,TEMP28,   &
                      TEMP91,   &
                      ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                      DTEMP1,DTEMP2,DTEMP3,   &
                      ISUBRO,IBUGA3,IERROR)
        ENDIF
        DO 21029 I=1,NS1
          TEMP1(I)=TEMP91(I)
21029   CONTINUE
!
!       2018/07: IF SUBSET CLAUSE WAS USED, WANT NITEMX TO BE SIZE OF
!                ORIGINAL VARIABLE.  BUT USE "SET LET CROSS TABULATE
!                <EXPAND/COLLAPSE>" CONTROL THIS.
!
        NITEMX=NS1
        IF(ICTALT.EQ.'EXPA')THEN
          NITEMX=NIRIGH(1)
        ELSEIF(ICASL7.EQ.'ZSCO' .OR. ICASL7.EQ.'USCO' .OR.   &
               ICASL7.EQ.'STAN' .OR. ICASL7.EQ.'LSTA' .OR.   &
               ICASL7.EQ.'LSST' .OR. ICASL7.EQ.'LOCA' .OR.   &
               ICASL7.EQ.'SCAL')THEN
          NITEMX=NIRIGH(1)
        ENDIF
!
      ELSEIF(ICASL7.EQ.'MOVI')THEN
        IF(FILWID.EQ.CPUMIN)IFILWI=3
        IF(FILWID.NE.CPUMIN)IFILWI=INT(FILWID+0.5)
!
        CALL MOVSTA(TEMP1,TEMP2,TEMP3,NS1,NUMVAR,ICASS7,ISTARA,MAXOBV,   &
                    ISEED,IQUAME,IQUASE,PSTAMV,   &
                    IMOVEP,IMOVDI,IFILWI,   &
                    TEMP21,TEMP22,TEMP23,TEMP27,TEMP28,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    TEMP91,NOUT,   &
                    ISUBRO,IBUGA3,IERROR)
        NS1=NOUT
        NITEMX=NOUT
        DO 21039 I=1,NS1
          TEMP1(I)=TEMP91(I)
21039   CONTINUE
      ELSEIF(ICASL7.EQ.'WIND')THEN
!
!       EXTRACT THE SIZE OF THE INTERVAL
!
        IHREPL='NSIZ'
        IHREP2='E   '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHREPL,IHREP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                    NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
        IF(IERROR.EQ.'YES')THEN
          IF(NS1.LE.1000)THEN
          ELSE
            NSIZE=NS1/100
          ENDIF
        ELSE
          NSIZE=INT(VALUE(ILOC)+0.5)
        ENDIF
!
        CALL WINSTA(TEMP1,TEMP2,TEMP3,NS1,NUMVAR,ICASS7,ISTARA,MAXOBV,   &
                    ISEED,NSIZE,   &
                    TEMP21,TEMP22,TEMP23,TEMP27,TEMP28,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    TEMP91,NOUT,   &
                    ISUBRO,IBUGA3,IERROR)
        NS1=NOUT
        NITEMX=NOUT
        DO 21037 I=1,NS1
          TEMP1(I)=TEMP91(I)
21037   CONTINUE
      ELSEIF(ICASL7.EQ.'CUMU')THEN
!
        CALL CUMSTA(TEMP1,TEMP2,TEMP3,NS1,NUMVAR,ICASS7,ISTARA,MAXOBV,   &
                    ISEED,ICSTSV,   &
                    TEMP21,TEMP22,TEMP23,TEMP27,TEMP28,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    TEMP91,NOUT,   &
                    ISUBRO,IBUGA3,IERROR)
        NS1=NOUT
        NITEMX=NOUT
        DO 21038 I=1,NS1
          TEMP1(I)=TEMP91(I)
21038   CONTINUE
      ELSEIF(ICASL7.EQ.'EN')THEN
        IWRITE='OFF'
        CALL EN(TEMP1,TEMP2,TEMPS(3),TEMPS(4),NS1,IWRITE,TEMP91,   &
                IBUGA3,ISUBRO,IERROR)
!
        DO 21041 I=1,NS1
          TEMP1(I)=TEMP91(I)
21041   CONTINUE
      ELSEIF(ICASL7.EQ.'PA')THEN
        IWRITE='OFF'
        CALL PA(TEMP1,NS1,TEMPS(2),TEMPS(3),IWRITE,TEMP91,   &
                IBUGA3,ISUBRO,IERROR)
!
        DO 21042 I=1,NS1
          TEMP1(I)=TEMP91(I)
21042   CONTINUE
      ELSEIF(ICASL7.EQ.'DIPE')THEN
        IWRITE='OFF'
        CALL DIPERC(TEMP1,NS1,TEMPS(2),IWRITE,TEMP91,   &
                    IBUGA3,ISUBRO,IERROR)
!
        DO 21044 I=1,NS1
          TEMP1(I)=TEMP91(I)
21044   CONTINUE
      ELSEIF(ICASL7.EQ.'IZSC' .OR. ICASL7.EQ.'ZPRI' .OR.   &
             ICASL7.EQ.'IZET' .OR. ICASL7.EQ.'EZPL' .OR.   &
             ICASL7.EQ.'EZMI')THEN
        XREF=CPUMIN
        UREF=CPUMIN
        SIGMA=CPUMIN
        IF(ICASL7.EQ.'IZSC')THEN
          ICASET=1
          XREF=TEMPS(2)
          SIGMA=TEMPS(3)
        ELSEIF(ICASL7.EQ.'ZPRI')THEN
          ICASET=2
          XREF=TEMPS(2)
          SIGMA=TEMPS(3)
          UREF=TEMPS(4)
        ELSEIF(ICASL7.EQ.'IZET')THEN
          ICASET=3
          XREF=TEMPS(3)
          UREF=TEMPS(4)
        ELSEIF(ICASL7.EQ.'EZMI')THEN
          ICASET=4
          XREF=TEMPS(3)
          UREF=TEMPS(4)
        ELSEIF(ICASL7.EQ.'EZPL')THEN
          ICASET=5
          XREF=TEMPS(3)
          UREF=TEMPS(4)
        ENDIF
        IWRITE='OFF'
        CALL ZSCORE(TEMP1,TEMP2,XREF,UREF,SIGMA,NS1,ICASET,IWRITE,   &
                    TEMP91,   &
                    IBUGA3,ISUBRO,IERROR)
!
        DO 21043 I=1,NS1
          TEMP1(I)=TEMP91(I)
21043   CONTINUE
      ELSEIF(ICASL7.EQ.'INSE')THEN
        AVAL=TEMPS(3)
        NLOC=INT(AVAL+0.1)
        CALL INSERT(TEMP1,NS1,TEMP2,NS2,NLOC,IWRITE,TEMP9,NOUT,MAXOBV,   &
                    IINSOW,IBUGA3,ISUBRO,IERROR)
        DO 21047 I=1,NOUT
          TEMP1(I)=TEMP9(I)
21047   CONTINUE
        NITEMX=NOUT
      ELSEIF(ICASL7.EQ.'WINS')THEN
!
!        2012/10: FOR WINSORIZING, CAN SPECIFY EITHER A SPECIFIC NUMBER
!                 TO WINSORIZE OR A PERCENTAGE TO WINSORIZE.  CHECK FOR
!                 SPECIFIC NUMBER FIRST AND IF NOT SPECIFIED, CHECK FOR A
!                 PERCENTAGE.
!
        NTRIM1=-1
        NTRIM2=-1
        P1=-99.0
        P2=-99.0
!
        IHP='NTRI'
        IHP2='M1  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'NO')THEN
          NTRIM1=INT(VALUE(ILOCP)+0.1)
          IF(NTRIM1.LT.0)NTRIM1=0
        ENDIF
!
        IHP='NTRI'
        IHP2='M2  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'NO')THEN
          NTRIM2=INT(VALUE(ILOCP)+0.1)
          IF(NTRIM2.LT.0)NTRIM2=0
        ENDIF
!
        IF(NTRIM1.LE.0)THEN
          IHP='P1  '
          IHP2='    '
          IHWUSE='P'
          MESSAG='YES'
          CALL CHECKN(IHP,IHP2,IHWUSE,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          IF(PROP1.LT.0.0 .OR. PROP1.GT.100.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21061)
21061       FORMAT('***** ERROR IN DPMATC--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21062)
21062       FORMAT('      THE PROPORTION FOR WINSORIZING BELOW MUST')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21063)
21063       FORMAT('      BE BETWEEN 0 AND 100, BUT WAS NOT.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21064)PROP1
21064       FORMAT('      PARAMETER P1 = LOWER PROPORTION = ',G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21065)
21065       FORMAT('      USE THE LET COMMAND TO PRE-DEFINE P1 AS IN')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21066)
21066       FORMAT('      LET P1 = 25')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSE
            PROP1=VALUE(ILOCP)
          ENDIF
        ENDIF
!
        IF(NTRIM2.LE.0)THEN
          IHP='P2  '
          IHP2='    '
          IHWUSE='P'
          MESSAG='YES'
          CALL CHECKN(IHP,IHP2,IHWUSE,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          IF(PROP2.LT.0.0 .OR. PROP2.GT.100.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21061)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21072)
21072       FORMAT('      THE PROPORTION FOR WINSORIZING ABOVE MUST')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21063)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21074)PROP2
21074       FORMAT('      PARAMETER P2 = LOWER PROPORTION = ',G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21075)
21075       FORMAT('      USE THE LET COMMAND TO PRE-DEFINE P2 AS IN')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,21076)
21076       FORMAT('      LET P2 = 25')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSE
            PROP2=VALUE(ILOCP)
          ENDIF
        ENDIF
!
        CALL WINSOR(TEMP1,NS1,PROP1,PROP2,NTRIM1,NTRIM2,IWRITE,   &
                    TEMP2,MAXOBV,TEMP3,   &
                    IBUGA3,ISUBRO,IERROR)
!
        DO 21059 I=1,NS1
          TEMP1(I)=TEMP3(I)
21059   CONTINUE
      ELSEIF(ICASL7.EQ.'CFRT')THEN
        IHP='MINS'
        IHP2='IZE '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          MINSIZ=5
        ELSE
          MINSIZ=INT(VALUE(ILOCP)+0.5)
          IF(MINSIZ.LE.0)MINSIZ=5
        ENDIF
!
        CALL DPCOMB(TEMP1,TEMP2,NS1,MINSIZ,   &
                    TEMP91,TEMP92,TEMP5,NITEMX,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        DO 22016 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
          TEMP91(I)=TEMP5(I)
22016   CONTINUE
      ELSEIF(ICASL7.EQ.'JOIN')THEN
        CALL JOIN(TEMP1,TEMP2,TEMP3,NS1,TEMP91,TEMP92,TEMP5,N3,MAXOBV,   &
                  IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        NITEMX=N3
        DO 22116 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
          TEMP91(I)=TEMP5(I)
22116   CONTINUE
      ELSEIF(ICASL7.EQ.'MWUF')THEN
        NS1=INT(TEMPS(1)+0.5)
        NS2=INT(TEMPS(2)+0.5)
        CALL UDIST(NS1,NS2,TEMP2,TEMP91,MAXOBV,TEMP5,MAXOBV,IFAULT)
        IF(IFAULT.GT.0)GO TO 19000
        NITEMX=NS1*NS2+1
        DO 22017 I=1,NITEMX
          TEMP1(I)=REAL(I-1)
22017   CONTINUE
      ELSEIF(ICASL7.EQ.'IFRT')THEN
        IHP='MINS'
        IHP2='IZE '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          MINSIZ=5
        ELSE
          MINSIZ=INT(VALUE(ILOCP)+0.5)
          IF(MINSIZ.LE.0)MINSIZ=5
        ENDIF
!
        CALL DPICOM(TEMP1,TEMP2,NS1,MINSIZ,   &
                    TEMP91,TEMP92,TEMP5,NITEMX,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        DO 22216 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP92(I)
          TEMP91(I)=TEMP5(I)
22216   CONTINUE
      ELSEIF(ICASL7.EQ.'HCON')THEN
        CALL HCONS(TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,NS1,IWRITE,   &
                   TEMP91,NITEMX,   &
                   TEMP6,TEMP7,TEMP8,TEMP21,ITEMP1,   &
                   ISUBRO,IBUGA3,IERROR)
        DO 22029 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
22029   CONTINUE
      ELSEIF(ICASL7.EQ.'KCON')THEN
        CALL KCONS(TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,ITEMP1,NS1,   &
                   IWRITE,TEMP91,NITEMX,IBAL,AKCV,   &
                   ISUBRO,IBUGA3,IERROR)
        DO 22039 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
22039   CONTINUE
      ELSEIF(ICASL7.EQ.'HCO2')THEN
        CALL HCONS2(TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP12,   &
                    NS1,IWRITE,   &
                    TEMP91,TEMP92,TEMP9,NITEMX,   &
                    TEMP7,TEMP8,TEMP21,TEMP22,TEMP23,TEMP24,TEMP25,   &
                    ITEMP1,   &
                    ISUBRO,IBUGA3,IERROR)
        DO 22049 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP9(I)
          TEMP91(I)=TEMP92(I)
22049   CONTINUE
      ELSEIF(ICASL7.EQ.'KCO2')THEN
        CALL KCONS2(TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                    TEMP6,TEMP7,TEMP8,TEMP21,TEMP22,ITEMP1,NS1,   &
                    IWRITE,TEMP91,TEMP92,TEMP9,TEMP23,NITEMX,IBAL,   &
                    ISUBRO,IBUGA3,IERROR)
        DO 22059 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
          TEMP2(I)=TEMP9(I)
          TEMP91(I)=TEMP92(I)
22059   CONTINUE
      ELSEIF(ICASL7.EQ.'LMOM')THEN
        NMOM=INT(TEMPS(2)+0.5)
        IF(NMOM.LE.0)NMOM=4
        IF(NMOM.GT.100)NMOM=100
        IF(NMOM.GE.NS1)NMOM=NS1
        DO 22061 I=1,NS1
          DTEMP1(I)=DBLE(TEMP1(I))
22061   CONTINUE
        CALL SAMLMU(DTEMP1,NS1,DTEMP2,NMOM)
        DO 22063 I=1,NMOM
          TEMP1(I)=REAL(DTEMP2(I))
22063   CONTINUE
        NITEMX=NMOM
      ELSEIF(ICASL7.EQ.'PWMO')THEN
        NMOM=INT(TEMPS(2)+0.5)
        IF(NMOM.LE.0)NMOM=4
        IF(NMOM.GT.20)NMOM=20
        IF(NMOM.GE.NS1)NMOM=NS1
        ATEMP=0.0D0
        BTEMP=0.0D0
        IKIND=1
        DO 22071 I=1,NS1
          DTEMP1(I)=DBLE(TEMP1(I))
22071   CONTINUE
        CALL SAMPWM(DTEMP1,NS1,DTEMP2,NMOM,ATEMP,BTEMP,IKIND)
        DO 22073 I=1,NMOM
          TEMP1(I)=REAL(DTEMP2(I))
22073   CONTINUE
        NITEMX=NMOM
      ELSEIF(ICASL7.EQ.'BPWM')THEN
        NMOM=INT(TEMPS(2)+0.5)
        IF(NMOM.LE.0)NMOM=4
        IF(NMOM.GT.20)NMOM=20
        IF(NMOM.GE.NS1)NMOM=NS1
        ATEMP=0.0D0
        BTEMP=0.0D0
        IKIND=2
        DO 22081 I=1,NS1
          DTEMP1(I)=DBLE(TEMP1(I))
22081   CONTINUE
        CALL SAMPWM(DTEMP1,NS1,DTEMP2,NMOM,ATEMP,BTEMP,IKIND)
        DO 22083 I=1,NMOM
          TEMP1(I)=REAL(DTEMP2(I))
22083   CONTINUE
        NITEMX=NMOM
      ELSEIF(ICASL7.EQ.'WMOM')THEN
        XMEAN=TEMP1(1)
        XSD=TEMP1(2)
        XSKEW=TEMP1(3)
        XMIN=TEMP1(4)
        NTEMP=INT(TEMP1(5)+0.1)
        CALL WEIMO1(XMEAN,XSD,XMIN,XSKEW,NTEMP,PSTAMV,   &
                    ALOCMO,SCALMO,SHAPMO,   &
                    ALOCMM,SCALMM,SHAPMM,   &
                    SCALM2,SHAPM2,   &
                    ISUBRO,IBUGA3,IERROR)
!
        TEMP1(1)=ALOCMO
        TEMP1(2)=SCALMO
        TEMP1(3)=SHAPMO
        TEMP1(4)=ALOCMM
        TEMP1(5)=SCALMM
        TEMP1(6)=SHAPMM
        TEMP1(7)=SCALM2
        TEMP1(8)=SHAPM2
        NS1=8
        NITEMX=NS1
      ELSEIF(ICASL7.EQ.'LNMO')THEN
        XMEAN=TEMP1(1)
        XSD=TEMP1(2)
        XSKEW=TEMP1(3)
        XMIN=TEMP1(4)
        NTEMP=INT(TEMP1(5)+0.1)
        CALL LGNMO1(XMEAN,XSD,XMIN,XSKEW,NTEMP,PSTAMV,   &
                    ALOCMO,SCALMO,SHAPMO,UHATMO,   &
                    ALOCMM,SCALMM,SHAPMM,UHATMM,   &
                    ISUBRO,IBUGA3,IERROR)
!
        TEMP1(1)=ALOCMO
        TEMP1(2)=SCALMO
        TEMP1(3)=SHAPMO
        TEMP1(4)=UHATMO
        TEMP1(5)=ALOCMM
        TEMP1(6)=SCALMM
        TEMP1(7)=SHAPMM
        TEMP1(8)=UHATMM
        NS1=8
        NITEMX=NS1
      ELSEIF(ICASL7.EQ.'GAMO')THEN
        XMEAN=TEMP1(1)
        XSD=TEMP1(2)
        XSKEW=TEMP1(3)
        XMIN=TEMP1(4)
        NTEMP=INT(TEMP1(5)+0.1)
        CALL GAMMO1(XMEAN,XSD,XMIN,XSKEW,NTEMP,PSTAMV,   &
                    ALOCMO,SCALMO,SHAPMO,   &
                    ALOCMM,SCALMM,SHAPMM,   &
                    ISUBRO,IBUGA3,IERROR)
!
        TEMP1(1)=ALOCMO
        TEMP1(2)=SCALMO
        TEMP1(3)=SHAPMO
        TEMP1(4)=ALOCMM
        TEMP1(5)=SCALMM
        TEMP1(6)=SHAPMM
        NS1=6
        NITEMX=NS1
      ELSEIF(ICASL7.EQ.'IGMO')THEN
        XMEAN=TEMP1(1)
        XSD=TEMP1(2)
        XSKEW=TEMP1(3)
        XMIN=TEMP1(4)
        NTEMP=INT(TEMP1(5)+0.1)
        CALL IGMO1(XMEAN,XSD,XMIN,XSKEW,NTEMP,PSTAMV,   &
                   ALOCMO,AMUMO,SIGMMO,GAMMMO,   &
                   ALOCMM,AMUMM,SIGMMM,GAMMMM,   &
                   ISUBRO,IBUGA3,IERROR)
!
        TEMP1(1)=ALOCMO
        TEMP1(2)=AMUMO
        TEMP1(3)=SIGMMO
        TEMP1(4)=GAMMMO
        TEMP1(5)=ALOCMM
        TEMP1(6)=AMUMM
        TEMP1(7)=SIGMMM
        TEMP1(8)=GAMMMM
        NS1=8
        NITEMX=NS1
      ELSEIF(ICASL7.EQ.'LPFI' .OR. ICASL7.EQ.'HPFI')THEN
!
        IHP='FC  '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          FC=0.05D0
        ELSE
          FC=DBLE(VALUE(ILOCP))
          IF(FC.LE.0.0D0 .OR. FC.GE.0.5D0)FC=0.05D0
        ENDIF
!
        IHP='KTER'
        IHP2='M   '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          KTERM=15
        ELSE
          KTERM=INT(VALUE(ILOCP)+0.5)
          IF(MOD(KTERM,2).EQ.0)KTERM=KTERM+1
          IF(KTERM.LT.3)KTERM=3
          IF(KTERM.GT.NS1)KTERM=NS1
        ENDIF
!
        DO 22091 I=1,NS1
          DTEMP1(I)=DBLE(TEMP1(I))
22091   CONTINUE
!
        IF(ICASL7.EQ.'LPFI')THEN
          CALL LOPASS(DTEMP1,NS1,FC,KTERM,DTEMP2,DTEMP3,NOUT,IERR2)
        ELSEIF(ICASL7.EQ.'LPFI')THEN
          CALL HIPASS(DTEMP1,NS1,FC,KTERM,DTEMP2,DTEMP3,NOUT,IERR2)
        ENDIF
!
        DO 22093 I=1,NOUT
          TEMP1(I)=REAL(DTEMP3(I))
22093   CONTINUE
        NS1=NOUT
        NITEMX=NS1
      ELSE
        WRITE(ICOUT,11301)
11301   FORMAT('***** INTERNAL ERROR 11301 IN DPMATC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11302)
11302   FORMAT('      NAME OF DESIRED DATA MANIPULATION OPERATION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11303)
11303   FORMAT('      WAS FOUND IN INTERNAL LIST IN CKMATH, BUT JUMP')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11305)
11305   FORMAT('      TO APPROPRIATE SUBROUTINE DID NOT TAKE PLACE ',   &
               'IN DPMATC.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11306)ICASL7
11306   FORMAT('ICASL7 = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
      ENDIF
      GO TO 11900
!
!     -----BEGINNING OF MATH CALCULATIONS-----
!
11900 CONTINUE
      IFOUND='YES'
      IF(IERROR.EQ.'YES')GO TO 19000
!
!
!               *****************************************************
!               **  STEP XX--                                      **
!               **  BRANCH TO THE PROPER CASE
!               **  DEPENDING ON THE TYPE OF OUTPUT--
!               **     1) SCALAR (= PARAMETER)
!               **     2) VECTOR (= VARIABLE) (THE USUAL)
!               **     3) MATRIX
!               **  UPDATE DATAPLOT'S INTERNAL WORKSPACE
!               **  AND HOUSEKEEPING TABLES
!               *****************************************************
!
!
!               *****************************************************
!               **  STEP 14--                                      **
!               **  TREAT THE PARAMETER (SCALAR) CASE.             **
!               **  EXAMPLE--LET D = DETERMINANT A                 **
!               **           WHERE A WAS PREVIOUSLY UNDEFINED      **
!               **           OR WHERE A WAS PREVIOUSLY A PARAMETER.**
!               **  CARRY OUT THE LIST UPDATING  AND               **
!               **  GENERATE THE INFORMATIVE PRINTING.             **
!               **  THEN EXIT.                                     **
!               *****************************************************
!
!     FEBRUARY 2007: AGRESTI-COULL LIMITS RETURNS TWO SCALAR
!                    VALUES.  CURRENTLY, LOGIC ONLY SUPPORTS
!                    ONE SCALAR OR TWO SCALAR OUTPUTS (I.E.,
!                    NO VECTOR-SCALAR).
      IF(ITYP91.EQ.'SCAL')THEN
        ISTEPN='14'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IHNAME(ILISL(1))=ILEFT(1)
        IHNAM2(ILISL(1))=ILEF2(1)
        IUSE(ILISL(1))='P'
        VALUE(ILISL(1))=SCAL91
!
!       2014/04: NEED TO ROUND DIFFERENTLY FOR NEGATIVE NUMBERS
!
        IF(VALUE(ILISL(1)).GE.0.0)THEN
          IVALUE(ILISL(1))=INT(VALUE(ILISL(1))+0.5)
        ELSE
          IVALUE(ILISL(1))=INT(VALUE(ILISL(1))-0.5)
        ENDIF
        IN(ILISL(1))=1
        IF(NEWNAM(1).EQ.'YES')NUMNAM=NUMNAM+1
!
        IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,14011)ILEFT(1),ILEF2(1),SCAL91
14011     FORMAT('THE COMPUTED VALUE OF THE CONSTANT ',   &
                 A4,A4,'      = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(ITYP92.EQ.'SCAL')THEN
          ISTEPN='14.B'
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IHNAME(ILISL(2))=ILEFT(2)
          IHNAM2(ILISL(2))=ILEF2(2)
          IUSE(ILISL(2))='P'
          VALUE(ILISL(2))=SCAL92
!CCCC     IVALUE(ILISL(2))=VALUE(ILISL(2))+0.5
!
!       2014/04: NEED TO ROUND DIFFERENTLY FOR NEGATIVE NUMBERS
!
          IF(VALUE(ILISL(2)).GE.0.0)THEN
            IVALUE(ILISL(2))=INT(VALUE(ILISL(2))+0.5)
          ELSE
            IVALUE(ILISL(2))=INT(VALUE(ILISL(2))-0.5)
          ENDIF
          IN(ILISL(2))=1
          IF(NEWNAM(2).EQ.'YES')NUMNAM=NUMNAM+1
!
          IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,14011)ILEFT(2),ILEF2(2),SCAL92
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
!
        IF(ITYP93.EQ.'SCAL')THEN
          ISTEPN='14.C'
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATC')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IHNAME(ILISL(3))=ILEFT(3)
          IHNAM2(ILISL(3))=ILEF2(3)
          IUSE(ILISL(3))='P'
          VALUE(ILISL(3))=SCAL93
!CCCC     IVALUE(ILISL(3))=VALUE(ILISL(3))+0.5
!
!       2014/04: NEED TO ROUND DIFFERENTLY FOR NEGATIVE NUMBERS
!
          IF(VALUE(ILISL(3)).GE.0.0)THEN
            IVALUE(ILISL(3))=INT(VALUE(ILISL(3))+0.5)
          ELSE
            IVALUE(ILISL(3))=INT(VALUE(ILISL(3))-0.5)
          ENDIF
          IN(ILISL(3))=1
          IF(NEWNAM(3).EQ.'YES')NUMNAM=NUMNAM+1
!
          IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,14011)ILEFT(3),ILEF2(3),SCAL93
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
!
        GO TO 19000
      ENDIF
!
!     -----TREAT THE VECTOR AND MATRIX CASE-----
!
      ISTEPN='11.1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     STORE FIRST VARIABLE ON THE LEFT
!
      NSX=0
      IF(NITEMX.LE.0)IROW1=0
      IF(NITEMX.LE.0)IROWN=0
      IF(NITEMX.LE.0)THEN
        IN(ILISL(1))=0
        GO TO 12119
      ENDIF
!
      IF(IUPFLG.EQ.'FULL' .OR. ICASEQ.EQ.'FULL')THEN
        DO 12105 I=1,NITEMX
          ISUB(I)=1
12105   CONTINUE
        NIFOR=NITEMX
      ENDIF
!
!CCCC 5/2010: BUG IN "COPY" CASE.  FOR SYNTAX
!CCCC             LET Y = X  SUBSET TAG = 1
!CCCC         WE WANT TO MAINTAIN ORIGINAL ROWS OF Y THAT
!CCCC         ARE NOT AFFECTED BY THE SUBSET.
!CCCC
      IF(ICASL7.EQ.'COPV')THEN
        DO 12115 I=1,NITEMX
!
          IF(I.GT.NIFOR)GO TO 12115
          IF(ISUB(I).EQ.0)GO TO 12115
          NSX=NSX+1
!
          IJ=MAXN*(ICOLL(1)-1)+I
          IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMP1(I)
          IF(ICOLL(1).EQ.MAXCP1)PRED(I)=TEMP1(I)
          IF(ICOLL(1).EQ.MAXCP2)RES(I)=TEMP1(I)
          IF(ICOLL(1).EQ.MAXCP3)YPLOT(I)=TEMP1(I)
          IF(ICOLL(1).EQ.MAXCP4)XPLOT(I)=TEMP1(I)
          IF(ICOLL(1).EQ.MAXCP5)X2PLOT(I)=TEMP1(I)
          IF(ICOLL(1).EQ.MAXCP6)TAGPLO(I)=TEMP1(I)
!
12115   CONTINUE
        IROW1=1
        IROWN=NITEMX
      ELSE
        DO 12110 I=1,NITEMX
!
!         FOR SOME COMMANDS, MAY NEED TO SKIP SUBSET
!
          IF(ICASL7.EQ.'DIGI')GO TO 12111
          IF(ICASL7.EQ.'DIST')GO TO 12111
          IF(ICASL7.EQ.'BLOC')GO TO 12111
          IF(ICASL7.EQ.'FLOC')GO TO 12111
          IF(ICASL7.EQ.'FLEN')GO TO 12111
          IF(ICASL7.EQ.'2DGR')GO TO 12111
          IF(ICASL7.EQ.'3DGR')GO TO 12111
          IF(ICASL7.EQ.'4DGR')GO TO 12111
          IF(ICASL7.EQ.'KCON')GO TO 12111
          IF(ICASL7.EQ.'KCO2')GO TO 12111
          IF(ICASL7.EQ.'HCON')GO TO 12111
          IF(ICASL7.EQ.'HCO2')GO TO 12111
          IF(ICASL7.EQ.'CRTA' .AND. ICTALT.EQ.'COLL')GO TO 12111
          IF(ICASL7.EQ.'CTAB' .AND. ICTALT.EQ.'COLL')GO TO 12111
          IF(ICASL7.EQ.'MNRK' .AND. ICTALT.EQ.'COLL')GO TO 12111
!
          IF(I.GT.NIFOR)GO TO 12110
          IF(ISUB(I).EQ.0)GO TO 12110
12111     CONTINUE
          NSX=NSX+1
!
          IJ=MAXN*(ICOLL(1)-1)+I
          IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMP1(NSX)
          IF(ICOLL(1).EQ.MAXCP1)PRED(I)=TEMP1(NSX)
          IF(ICOLL(1).EQ.MAXCP2)RES(I)=TEMP1(NSX)
          IF(ICOLL(1).EQ.MAXCP3)YPLOT(I)=TEMP1(NSX)
          IF(ICOLL(1).EQ.MAXCP4)XPLOT(I)=TEMP1(NSX)
          IF(ICOLL(1).EQ.MAXCP5)X2PLOT(I)=TEMP1(NSX)
          IF(ICOLL(1).EQ.MAXCP6)TAGPLO(I)=TEMP1(NSX)
!
          IF(NSX.EQ.1)IROW1=I
          IROWN=I
!
12110   CONTINUE
      ENDIF
!
      IN(ILISL(1))=NITEMX
!
12119 CONTINUE
!
!     STORE SECOND VARIABLE ON THE LEFT
!
      IF(ICASL7.EQ.'FOUT'.OR.ICASL7.EQ.'FOU1'.OR.   &
         ICASL7.EQ.'IFOU'.OR.ICASL7.EQ.'IFO1'.OR.   &
         ICASL7.EQ.'FFT' .OR.ICASL7.EQ.'FFT1'.OR.   &
         ICASL7.EQ.'IFFT'.OR.ICASL7.EQ.'IFF1'.OR.   &
         ICASL7.EQ.'COAD'.OR.ICASL7.EQ.'COSU'.OR.   &
         ICASL7.EQ.'COMU'.OR.ICASL7.EQ.'CODI'.OR.   &
         ICASL7.EQ.'COEX'.OR.ICASL7.EQ.'COSR'.OR.   &
         ICASL7.EQ.'CORO'.OR.ICASL7.EQ.'COR1'.OR.   &
         ICASL7.EQ.'COCO'.OR.ICASL7.EQ.'PODI'.OR.   &
         ICASL7.EQ.'SECP'.OR.ICASL7.EQ.'FRAC'.OR.   &
         ICASL7.EQ.'BINN'.OR.ICASL7.EQ.'BINR'.OR.   &
         ICASL7.EQ.'CBIN'.OR.ICASL7.EQ.'CBIR'.OR.   &
         ICASL7.EQ.'BINP'.OR.ICASL7.EQ.'BIRP'.OR.   &
         ICASL7.EQ.'ASHC'.OR.ICASL7.EQ.'ASHR'.OR.   &
         ICASL7.EQ.'STAC'.OR.ICASL7.EQ.'RSTA'.OR.   &
         ICASL7.EQ.'CFRT'.OR.ICASL7.EQ.'HCO2'.OR.   &
         ICASL7.EQ.'IFRT'.OR.ICASL7.EQ.'2DCH'.OR.   &
         ICASL7.EQ.'EDGV'.OR.ICASL7.EQ.'NEPA'.OR.   &
         ICASL7.EQ.'NEXE'.OR.ICASL7.EQ.'CYTB'.OR.   &
         ICASL7.EQ.'SPF1'.OR.ICASL7.EQ.'SPF2'.OR.   &
         ICASL7.EQ.'AGCO'.OR.ICASL7.EQ.'DPCL'.OR.   &
         ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
         ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'EBCL'.OR.   &
         ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
         ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BRAT'.OR.   &
         ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
         ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
         ICASL7.EQ.'SOR2'.OR.ICASL7.EQ.'SOR3'.OR.   &
         ICASL7.EQ.'SOR4'.OR.ICASL7.EQ.'MWUF'.OR.   &
         ICASL7.EQ.'TMIN'.OR.ICASL7.EQ.'TMAX'.OR.   &
         ICASL7.EQ.'TPOI'.OR.ICASL7.EQ.'EXTP'.OR.   &
         ICASL7.EQ.'ENCB'.OR.ICASL7.EQ.'INTL'.OR.   &
         ICASL7.EQ.'PARL'.OR.ICASL7.EQ.'PERL'.OR.   &
         ICASL7.EQ.'JOIN'.OR.ICASL7.EQ.'NNE3'.OR.   &
         ICASL7.EQ.'FNNE'.OR.ICASL7.EQ.'ANNE'.OR.   &
         ICASL7.EQ.'PEAK'.OR.ICASL7.EQ.'JSCT'.OR.   &
         ICASL7.EQ.'GSQD'.OR.ICASL7.EQ.'GSQS'.OR.   &
         ICASL7.EQ.'GSQP'.OR.ICASL7.EQ.'GSQM'.OR.   &
         ICASL7.EQ.'GQMN'.OR.ICASL7.EQ.'GQMX'.OR.   &
         ICASL7.EQ.'GSQL'.OR.ICASL7.EQ.'GSQU'.OR.   &
         ICASL7.EQ.'NKDM'.OR.ICASL7.EQ.'EQUF'.OR.   &
         ICASL7.EQ.'IQUF'.OR.ICASL7.EQ.'TIQF'.OR.   &
         ICASL7.EQ.'SRNP'.OR.ICASL7.EQ.'2DGR'.OR.   &
         ICASL7.EQ.'3DGR'.OR.ICASL7.EQ.'4DGR'.OR.   &
         ICASL7.EQ.'PSCO'.OR.ICASL7.EQ.'DREG'.OR.   &
         ICASL7.EQ.'KCO2'.OR.ICASL7.EQ.'SRTB')THEN
!
        NSX=0
        NITEM2=NITEMX
        IF(ICASL7.EQ.'SRTB')NITEM2=NUMSE1
        IF(ICASL7.EQ.'PODI')NITEM2=NITE2X
        IF(ICASL7.EQ.'NEXE')NITEM2=NC
        IF(NITEM2.LE.0)IROW12=0
        IF(NITEM2.LE.0)IROWN2=0
        IF(NITEM2.LE.0)THEN
          IN(ILISL(2))=0
          GO TO 12129
        ENDIF
!
        DO 12120 I=1,NITEM2
!
          IF(NITEM2.EQ.NITEMX)THEN
            IF(I.GT.NIFOR)GO TO 12120
            IF(ISUB(I).EQ.0)GO TO 12120
          ENDIF
          NSX=NSX+1
!
          IJ=MAXN*(ICOLL(2)-1)+I
          IF(ICOLL(2).LE.MAXCOL)V(IJ)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP1)PRED(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP2)RES(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP3)YPLOT(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP4)XPLOT(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP5)X2PLOT(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP6)TAGPLO(I)=TEMP2(NSX)
!
          IF(NSX.EQ.1)IROW12=I
          IROWN2=I
!
12120   CONTINUE
!
        IN(ILISL(2))=NITEM2
!
12129   CONTINUE
      ENDIF
!
      IF(ICASL7.EQ.'CFRT'.OR.ICASL7.EQ.'RSTA'.OR.   &
         ICASL7.EQ.'IFRT'.OR.ICASL7.EQ.'EDGV'.OR.   &
         ICASL7.EQ.'R1TS'.OR.ICASL7.EQ.'R1LT'.OR.   &
         ICASL7.EQ.'R1UT'.OR.ICASL7.EQ.'DPCL'.OR.   &
         ICASL7.EQ.'R2TS'.OR.ICASL7.EQ.'R2LT'.OR.   &
         ICASL7.EQ.'R2UT'.OR.ICASL7.EQ.'BRAT'.OR.   &
         ICASL7.EQ.'R3TS'.OR.ICASL7.EQ.'R3LT'.OR.   &
         ICASL7.EQ.'R3UT'.OR.ICASL7.EQ.'BPSE'.OR.   &
         ICASL7.EQ.'SOR3'.OR.ICASL7.EQ.'SOR4'.OR.   &
         ICASL7.EQ.'HCO2'.OR.ICASL7.EQ.'KCO2'.OR.   &
         ICASL7.EQ.'CBIN'.OR.ICASL7.EQ.'CBIR'.OR.   &
         ICASL7.EQ.'MWUF'.OR.ICASL7.EQ.'JOIN'.OR.   &
         ICASL7.EQ.'FNNE'.OR.ICASL7.EQ.'ANNE'.OR.   &
         ICASL7.EQ.'3DGR'.OR.ICASL7.EQ.'4DGR'.OR.   &
         ICASL7.EQ.'JSCT'.OR.   &
         ICASL7.EQ.'SPF1'.OR.ICASL7.EQ.'SPF2')THEN
!
        NSX=0
        NITEM3=NITEMX
        IF(ICASL7.EQ.'SPF2')NITEM3=NS3
        IF(ICASL7.EQ.'CBIN' .OR. ICASL7.EQ.'CBIR')NITEM3=NS1
        IF(NITEM3.LE.0)IROW13=0
        IF(NITEM3.LE.0)IROWN3=0
        IF(NITEM3.LE.0)THEN
          IN(ILISL(3))=0
          GO TO 12139
        ENDIF
!
        DO 12130 I=1,NITEM3
!
          IF(NITEM3.EQ.NITEMX)THEN
            IF(I.GT.NIFOR)GO TO 12130
            IF(ISUB(I).EQ.0)GO TO 12130
          ENDIF
          NSX=NSX+1
!
          IJ=MAXN*(ICOLL(3)-1)+I
          IF(ICOLL(3).LE.MAXCOL)V(IJ)=TEMP91(NSX)
          IF(ICOLL(3).EQ.MAXCP1)PRED(I)=TEMP91(NSX)
          IF(ICOLL(3).EQ.MAXCP2)RES(I)=TEMP91(NSX)
          IF(ICOLL(3).EQ.MAXCP3)YPLOT(I)=TEMP91(NSX)
          IF(ICOLL(3).EQ.MAXCP4)XPLOT(I)=TEMP91(NSX)
          IF(ICOLL(3).EQ.MAXCP5)X2PLOT(I)=TEMP91(NSX)
          IF(ICOLL(3).EQ.MAXCP6)TAGPLO(I)=TEMP91(NSX)
!
          IF(NSX.EQ.1)IROW13=I
          IROWN3=I
!
12130   CONTINUE
!
        IN(ILISL(3))=NITEM3
!
12139   CONTINUE
      ENDIF
!
      IF(ICASL7.EQ.'SPF2'.OR.ICASL7.EQ.'SOR4'.OR.   &
         ICASL7.EQ.'4DGR'.OR.ICASL7.EQ.'ANNE')THEN
!
        NSX=0
        NITEM4=NS4
        IF(ICASL7.EQ.'4DGR')NITEM4=NITEMX
        IF(NITEM4.LE.0)THEN
          IROW14=0
          IROWN4=0
          IN(ILISL(4))=0
          GO TO 12149
        ENDIF
!
        DO 12140 I=1,NITEM4
!
          IF(NITEM4.EQ.NITEMX)THEN
            IF(I.GT.NIFOR)GO TO 12140
            IF(ISUB(I).EQ.0)GO TO 12140
          ENDIF
          NSX=NSX+1
!
          IJ=MAXN*(ICOLL(4)-1)+I
          IF(ICOLL(4).LE.MAXCOL)V(IJ)=TEMP92(NSX)
          IF(ICOLL(4).EQ.MAXCP1)PRED(I)=TEMP92(NSX)
          IF(ICOLL(4).EQ.MAXCP2)RES(I)=TEMP92(NSX)
          IF(ICOLL(4).EQ.MAXCP3)YPLOT(I)=TEMP92(NSX)
          IF(ICOLL(4).EQ.MAXCP4)XPLOT(I)=TEMP92(NSX)
          IF(ICOLL(4).EQ.MAXCP5)X2PLOT(I)=TEMP92(NSX)
          IF(ICOLL(4).EQ.MAXCP6)TAGPLO(I)=TEMP92(NSX)
!
          IF(NSX.EQ.1)IROW14=I
          IROWN4=I
!
12140   CONTINUE
!
        IN(ILISL(4))=NITEM4
!
12149   CONTINUE
      ENDIF
!
      IF(ICASL7.EQ.'ANNE')THEN
!
        NSX=0
        NITEM5=NS5
        IF(NITEM5.LE.0)THEN
          IROW15=0
          IROWN5=0
          IN(ILISL(5))=0
          GO TO 12159
        ENDIF
!
        DO 12150 I=1,NITEM5
!
          IF(NITEM5.EQ.NITEMX)THEN
            IF(I.GT.NIFOR)GO TO 12150
            IF(ISUB(I).EQ.0)GO TO 12150
          ENDIF
          NSX=NSX+1
!
          IJ=MAXN*(ICOLL(5)-1)+I
          IF(ICOLL(5).LE.MAXCOL)V(IJ)=TEMP5(NSX)
          IF(ICOLL(5).EQ.MAXCP1)PRED(I)=TEMP5(NSX)
          IF(ICOLL(5).EQ.MAXCP2)RES(I)=TEMP5(NSX)
          IF(ICOLL(5).EQ.MAXCP3)YPLOT(I)=TEMP5(NSX)
          IF(ICOLL(5).EQ.MAXCP4)XPLOT(I)=TEMP5(NSX)
          IF(ICOLL(5).EQ.MAXCP5)X2PLOT(I)=TEMP5(NSX)
          IF(ICOLL(5).EQ.MAXCP6)TAGPLO(I)=TEMP5(NSX)
!
          IF(NSX.EQ.1)IROW15=I
          IROWN5=I
!
12150   CONTINUE
!
        IN(ILISL(5))=NITEM5
!
12159   CONTINUE
      ENDIF
!
      DO 12210 J4=1,NUMNAM
        IF((IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(1)).OR.   &
           (IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(1)))THEN
          IUSE(J4)='V'
          IVALUE(J4)=ICOLL(1)
          VALUE(J4)=ICOLL(1)
          IN(J4)=NITEMX
          IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')THEN
            IVALUE(J4)=ICOLL(1)
!CCCC       IVALU2(J4)=ICOLL(1)+NC91-1
            IVALU2(J4)=ICOLL(1)
          ENDIF
        ENDIF
12210 CONTINUE
!
      IF(NUMVAL.GE.2)THEN
        DO 12220 J4=1,NUMNAM
          IF((IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(2)).OR.   &
             (IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(2)))THEN
            IUSE(J4)='V'
            IVALUE(J4)=ICOLL(2)
            VALUE(J4)=INT(ICOLL(2))
            IN(J4)=NITEM2
          ENDIF
12220   CONTINUE
      ENDIF
!
      IF(NUMVAL.GE.3)THEN
        DO 12230 J4=1,NUMNAM
          IF((IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(3)).OR.   &
             (IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(3)))THEN
            IUSE(J4)='V'
            IVALUE(J4)=ICOLL(3)
            VALUE(J4)=ICOLL(3)
            IN(J4)=NITEM3
          ENDIF
12230   CONTINUE
      ENDIF
!
      IF(NUMVAL.GE.4)THEN
        DO 12240 J4=1,NUMNAM
          IF((IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(4)).OR.   &
             (IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(4)))THEN
            IUSE(J4)='V'
            IVALUE(J4)=ICOLL(4)
            VALUE(J4)=ICOLL(4)
            IN(J4)=NITEM4
          ENDIF
12240   CONTINUE
      ENDIF
!
      IF(NUMVAL.GE.5)THEN
        DO 12250 J5=1,NUMNAM
          IF((IUSE(J5).EQ.'V'.AND.IVALUE(J5).EQ.ICOLL(5)).OR.   &
             (IUSE(J5).EQ.'M'.AND.IVALUE(J5).EQ.ICOLL(5)))THEN
            IUSE(J5)='V'
            IVALUE(J5)=ICOLL(5)
            VALUE(J5)=ICOLL(5)
            IN(J5)=NITEM5
          ENDIF
12250   CONTINUE
      ENDIF
!
!               *******************************************
!               **  STEP 16--                            **
!               **  TREAT THE VARIABLE (VECTOR) CASE--   **
!               **  CARRY OUT THE LIST UPDATING AND      **
!               **  GENERATE THE INFORMATIVE PRINTING    **
!               **  FOR STEP NUMBERS 7, 8, AND 9 ABOVE.  **
!               *******************************************
!
      ISTEPN='16'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATC')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHNAME(ILISL(1))=ILEFT(1)
      IHNAM2(ILISL(1))=ILEF2(1)
      IUSE(ILISL(1))='V'
      IVALUE(ILISL(1))=ICOLL(1)
      VALUE(ILISL(1))=ICOLL(1)
      IF(NEWNAM(1).EQ.'YES')THEN
        NUMNAM=NUMNAM+1
        NUMCOL=NUMCOL+1
      ENDIF
!
      IF(NUMVAL.GE.2)THEN
        IHNAME(ILISL(2))=ILEFT(2)
        IHNAM2(ILISL(2))=ILEF2(2)
        IUSE(ILISL(2))='V'
        IVALUE(ILISL(2))=ICOLL(2)
        VALUE(ILISL(2))=ICOLL(2)
        IF(NEWNAM(2).EQ.'YES')THEN
          NUMNAM=NUMNAM+1
          NUMCOL=NUMCOL+1
        ENDIF
      ENDIF
!
      IF(NUMVAL.GE.3)THEN
        IHNAME(ILISL(3))=ILEFT(3)
        IHNAM2(ILISL(3))=ILEF2(3)
        IUSE(ILISL(3))='V'
        IVALUE(ILISL(3))=ICOLL(3)
        VALUE(ILISL(3))=ICOLL(3)
        IF(NEWNAM(3).EQ.'YES')THEN
          NUMNAM=NUMNAM+1
          NUMCOL=NUMCOL+1
        ENDIF
      ENDIF
!
      IF(NUMVAL.GE.4)THEN
        IHNAME(ILISL(4))=ILEFT(4)
        IHNAM2(ILISL(4))=ILEF2(4)
        IUSE(ILISL(4))='V'
        IVALUE(ILISL(4))=ICOLL(4)
        VALUE(ILISL(4))=ICOLL(4)
        IF(NEWNAM(4).EQ.'YES')THEN
          NUMNAM=NUMNAM+1
          NUMCOL=NUMCOL+1
        ENDIF
      ENDIF
!
      IF(NUMVAL.GE.5)THEN
        IHNAME(ILISL(5))=ILEFT(5)
        IHNAM2(ILISL(5))=ILEF2(5)
        IUSE(ILISL(5))='V'
        IVALUE(ILISL(5))=ICOLL(5)
        VALUE(ILISL(5))=ICOLL(5)
        IF(NEWNAM(5).EQ.'YES')THEN
          NUMNAM=NUMNAM+1
          NUMCOL=NUMCOL+1
        ENDIF
      ENDIF
!
      IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
!
        WRITE(ICOUT,16011)ILEFT(1),ILEF2(1),NSX
16011   FORMAT('THE NUMBER OF VALUES GENERATED FOR ',   &
               'THE VARIABLE ',A4,A4,' = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IJ=MAXN*(ICOLL(1)-1)+IROW1
        IF(ICOLL(1).LE.MAXCOL)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),V(IJ),IROW1
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP1)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),PRED(IROW1),IROW1
16021     FORMAT('THE FIRST           COMPUTED VALUE OF ',A4,A4,   &
                 ' = ',E16.7,'   (ROW ',I6,')')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP2)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),RES(IROW1),IROW1
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP3)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),YPLOT(IROW1),IROW1
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP4)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),XPLOT(IROW1),IROW1
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP5)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),X2PLOT(IROW1),IROW1
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP6)THEN
          WRITE(ICOUT,16021)ILEFT(1),ILEF2(1),TAGPLO(IROW1),IROW1
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IJ=MAXN*(ICOLL(1)-1)+IROWN
        IF(ICOLL(1).LE.MAXCOL.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),V(IJ),IROWN
16031     FORMAT('THE LAST (',I5,'-TH) COMPUTED VALUE OF ',A4,A4,   &
                 ' = ',E16.7,'   (ROW ',I6,')')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP1.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),PRED(IROWN),IROWN
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP2.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),RES(IROWN),IROWN
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP3.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),YPLOT(IROWN),IROWN
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP4.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),XPLOT(IROWN),IROWN
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP5.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),X2PLOT(IROWN),IROWN
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICOLL(1).EQ.MAXCP6.AND.NSX.NE.1)THEN
          WRITE(ICOUT,16031)NSX,ILEFT(1),ILEF2(1),TAGPLO(IROWN),IROWN
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IF(NSX.EQ.1)THEN
          WRITE(ICOUT,16032)
16032     FORMAT('SINCE THE GENERATED SAMPLE SIZE WAS ONLY 1,')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,16033)
16033     FORMAT('THE ABOVE VALUE WAS THE SOLE VALUE COMPUTED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(NUMVAL.GE.2)THEN
          WRITE(ICOUT,16011)ILEFT(2),ILEF2(2),NSX
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IJ=MAXN*(ICOLL(2)-1)+IROW1
          IF(ICOLL(2).LE.MAXCOL)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),V(IJ),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP1)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),PRED(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP2)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),RES(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP3)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),YPLOT(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP4)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),XPLOT(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP5)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),X2PLOT(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP6)THEN
            WRITE(ICOUT,16021)ILEFT(2),ILEF2(2),TAGPLO(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IJ=MAXN*(ICOLL(2)-1)+IROWN
          IF(ICOLL(2).LE.MAXCOL.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),V(IJ),IROWN
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP1.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),PRED(IROWN),IROWN
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP2.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),RES(IROWN),IROWN
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP3.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),YPLOT(IROWN),IROWN
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP4.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),XPLOT(IROWN),IROWN
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP5.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),X2PLOT(IROWN),IROWN
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(2).EQ.MAXCP6.AND.NSX.NE.1)THEN
            WRITE(ICOUT,16031)NSX,ILEFT(2),ILEF2(2),TAGPLO(IROWN),IROWN
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IF(NSX.EQ.1)THEN
            WRITE(ICOUT,16032)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,16033)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
        ENDIF
!
        IF(NUMVAL.GE.3)THEN
          WRITE(ICOUT,16011)ILEFT(3),ILEF2(3),NSX
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IJ=MAXN*(ICOLL(3)-1)+IROW1
          IF(ICOLL(3).LE.MAXCOL)THEN
            WRITE(ICOUT,16021)ILEFT(3),ILEF2(3),V(IJ),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(3).EQ.MAXCP1)THEN
            WRITE(ICOUT,16021)ILEFT(3),ILEF2(3),PRED(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(3).EQ.MAXCP2)THEN
            WRITE(ICOUT,16021)ILEFT(3),ILEF2(3),RES(IROW1),IROW1
            CALL DPWRST('XXX','BUG ')
