!     UPDATED         --AUGUST    2018. COSINE <COLUMN/ROW> SIMILARITY
!     UPDATED         --AUGUST    2018. ANGULAR COSINE <COLUMN/ROW> DISTANCE
!     UPDATED         --AUGUST    2018. ANGULAR COSINE <COLUMN/ROW> SIMILARITY
!     UPDATED         --AUGUST    2018. JACCARD <COLUMN/ROW> DISTANCE
!     UPDATED         --AUGUST    2018. JACCARD <COLUMN/ROW> SIMILARITY
!     UPDATED         --AUGUST    2018. PEARSON <COLUMN/ROW> DISTANCE
!     UPDATED         --AUGUST    2018. PEARSON <COLUMN/ROW> SIMILARITY
!     UPDATED         --AUGUST    2018. HAMMING <COLUMN/ROW> DISTANCE
!     UPDATED         --AUGUST    2018. CANBERRA <COLUMN/ROW> SIMILARITY
!     UPDATED         --SEPTEMBER 2018. DEX CHECK CENTER POINTS
!     UPDATED         --JULY      2019. TWEAK SCRATCH STORAGE
