!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASL7
      CHARACTER*4 ICASS7
      CHARACTER*4 IMSUBC
      CHARACTER*4 ISTARA
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!CCCC PARAMETER(MAXCAS=30)
!CCCC PARAMETER(MAXCAS=999)
      PARAMETER(MAXCAS=2000)
      PARAMETER(MAXCA2=4)
!
      CHARACTER*4 NEWNAM(MAXCA2)
      CHARACTER*4 ICASEQ
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IWRITE
      CHARACTER*4 ITCASE
      CHARACTER*4 IMCASE
!
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
