      INTEGER ICOLL(MAXCA2)
      INTEGER ILOCR(MAXCAS)
      INTEGER ILISR(MAXCAS)
      INTEGER ICOLR(MAXCAS)
      INTEGER NIRIGH(MAXCAS)
      INTEGER NS(MAXCAS)
