      DIMENSION TEMPV(20)
!
!     2021/01: UP FROM MAX OF 40 CHARACTERS TO MAX OF 80 CHARACTERS
!
      CHARACTER*80 STME(500)
      CHARACTER*80 STMEC(500)
      CHARACTER*80 ST2T(500)
      CHARACTER*80 ST2TC(500)
      CHARACTER*80 STC(500)
      CHARACTER*80 STT(500)
      INCLUDE 'DPCOZC.INC'
      EQUIVALENCE (CGARBG(1),STC(1))
      EQUIVALENCE (CGARBG(100001),STME(1))
      EQUIVALENCE (CGARBG(200001),STMEC(1))
      EQUIVALENCE (CGARBG(300001),ST2T(1))
      EQUIVALENCE (CGARBG(400001),ST2TC(1))
      EQUIVALENCE (CGARBG(500001),STT(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IUPFLG='SUBS'
      ISUBN1='DPMA'
      ISUBN2='T2  '
      IFOUND='NO'
      IERROR='NO'
      IMATSW='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      NUMVAR=0
      NJ=-99
      NIFOR=0
      ILOCR(1)=ILOCV
      DO 10 I=2,MAXCAS
        ILOCR(I)=ILOCR(I-1)+1
   10 CONTINUE
!
      DO 12 I=1,MAXCA2
        NEWNAM(I)='NO'
   12 CONTINUE
      NUMVAL=1
!
      ITYP91='VECT'
      SCAL91=(-999.0)
!
      DO 14 I=1,MAXCAS
        ITYPA(I)='VARI'
        TEMPS(I)=(-999.0)
        ILISR(I)=(-999)
   14 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IBUGQ,ISUBRO,IMSUBC,ICASL7,ILOCV
   52   FORMAT('IBUGA3,IBUGQ,ISUBRO,IMSUBC,ICASL7,ILOCV = ',5(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **********************************
!               **  STEP 1--                    **
!               **  INITIALIZE SOME VARIABLES.  **
!               **********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NEWNAM(1)='NO'
!
!     ***************************************************************
!     **  STEP 2A--                                                 *
!     **  EXAMINE THE LEFT-HAND SIDE--                              *
!     **  IS THE VARIABLE NAME TO LEFT OF = SIGN                    *
!     **  ALREADY IN THE NAME LIST?    AS A VARIABLE?               *
!     **  NOTE THAT     ILEFT(I)   IS THE NAME OF THE VARIABLE      *
!     **  ON THE LEFT.                                              *
!     **  NOTE THAT     ILISL(I)  IS THE LINE IN THE TABLE          *
!     **  OF THE NAME ON THE LEFT.                                  *
!     **  NOTE THAT     ICOLL(I)  IS THE DATA COLUMN (1 TO 12)      *
!     **  FOR THE NAME OF THE LEFT.                                 *
!     ***************************************************************
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASE=1
      CALL DPMAT6(ICASL7,ICASE,MAXCA2,   &
                  ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                  NUMVAL,NIOLD,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 19000
!
      IF(ICASL7.EQ.'MASD' .OR. ICASL7.EQ.'MASF' .OR.   &
         ICASL7.EQ.'MQRD' .OR. ICASL7.EQ.'MATB' .OR.   &
         ICASL7.EQ.'MARB' .OR. ICASL7.EQ.'MSPT' .OR.   &
         ICASL7.EQ.'BIPL' .OR. ICASL7.EQ.'CONF' .OR.   &
         ICASL7.EQ.'MFTR' .OR. ICASL7.EQ.'MFTC' .OR.   &
         ICASL7.EQ.'MSP2' .OR. ICASL7.EQ.'JOIN')THEN
        ICASE=2
        CALL DPMAT6(ICASL7,ICASE,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(ICASL7.EQ.'MASD' .OR. ICASL7.EQ.'MASF' .OR.   &
         ICASL7.EQ.'MFTR' .OR. ICASL7.EQ.'MFTC' .OR.   &
         ICASL7.EQ.'MSPT' .OR. ICASL7.EQ.'BIPL')THEN
        ICASE=3
        CALL DPMAT6(ICASL7,ICASE,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(ICASL7.EQ.'MFTR' .OR. ICASL7.EQ.'MFTC')THEN
        ICASE=4
        CALL DPMAT6(ICASL7,ICASE,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,491)
  491   FORMAT('AT THE END OF STEP 2--')
        CALL DPWRST('XXX','BUG ')
        DO 494 I=1,MAXCA2
        WRITE(ICOUT,492)ILEFT(I),ILEF2(I),NEWNAM(I),NUMNAM,   &
                        ILISL(I),NUMCOL,ICOLL(I),NIOLD
        CALL DPWRST('XXX','BUG ')
  492   FORMAT('ILEFT(I),ILEFT(I),NEWNAM(I),NUMNAM,ILISL(I),',   &
               'NUMCOL,ICOLL(I),NIOLD = ',A4,A4,2X,A4,2X,5I8)
  494   CONTINUE
      ENDIF
!
!     ****************************************************************
!     **  STEP 4--                                                   *
!     **  EXAMINE THE RIGHT-HAND SIDE--                              *
!     **  HAS EACH VARIABLE ON THE RIGHT ALREADY BEEN DEFINED?       *
!     **  NOTE THAT     ILISR(1), ILISR(2), ILISR(3), ILISR(4)       *
!     **  IS THE LINE IN THE TABLE OF THE FIRST, SECOND, THIRD,      *
!     **  FOURTH VARIABLE ON THE RIGHT, RESPECTIVELY.                *
!     **  NOTE THAT     ICOLR(1), ICOLR(2), ICOLR3, ICOLR4           *
!     **  IS THE DATA COLUMN (1 TO 10+6) OF THE FIRST SECOND,        *
!     **  THIRD, FOURTH VARIABLE ON THE RIGHT, RESPECTIVELY.         *
!     ****************************************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ********************************************
!               **  STEP 4.1--                            **
!               **  DETERMINE THE NUMBER OF VARIABLES     **
!               **  ON THE RIGHT--1, 2, 3, OR 4           **
!               ********************************************
!
      ISTEPN='4.1'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,1021)ICASL7,NUMARG
 1021   FORMAT('ICASL7,NUMARG = ',A4,2X,I2)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IMATSW='YES'
      NUMVAR=1
!
      IF(ICASL7.EQ.'MAIN'.OR.ICASL7.EQ.'MATR'.OR.ICASL7.EQ.'MAEN'.OR.   &
         ICASL7.EQ.'MAAJ'.OR.ICASL7.EQ.'MACE'.OR.ICASL7.EQ.'MAVC'.OR.   &
         ICASL7.EQ.'MAEA'.OR.ICASL7.EQ.'VINF'.OR.ICASL7.EQ.'MACO'.OR.   &
         ICASL7.EQ.'MACC'.OR.ICASL7.EQ.'VINF'.OR.ICASL7.EQ.'MACP'.OR.   &
         ICASL7.EQ.'MACM'.OR.ICASL7.EQ.'BIPL'.OR.ICASL7.EQ.'MPCO'.OR.   &
         ICASL7.EQ.'MPCC'.OR.ICASL7.EQ.'MPCP'.OR.   &
         ICASL7.EQ.'CIND'.OR.ICASL7.EQ.'MAEE'.OR.ICASL7.EQ.'MAPC'.OR.   &
         ICASL7.EQ.'MAP1'.OR.ICASL7.EQ.'MAP2'.OR.ICASL7.EQ.'MAP3'.OR.   &
         ICASL7.EQ.'MAP4'.OR.ICASL7.EQ.'MAP5'.OR.ICASL7.EQ.'MAP6'.OR.   &
         ICASL7.EQ.'MAP7'.OR.ICASL7.EQ.'MAP8'.OR.ICASL7.EQ.'MAP9'.OR.   &
         ICASL7.EQ.'MA10'.OR.(ICASL7.EQ.'MARA'.AND.NUMARG.EQ.5))THEN
        NUMVAR=1
      ELSEIF(   &
         ICASL7.EQ.'MADE'.OR.ICASL7.EQ.'MAPE'.OR.ICASL7.EQ.'MASV'.OR.   &
         ICASL7.EQ.'MASN'.OR.ICASL7.EQ.'MASR'.OR.ICASL7.EQ.'MASD'.OR.   &
         ICASL7.EQ.'MANR'.OR.ICASL7.EQ.'MANC'.OR.ICASL7.EQ.'MATC'.OR.   &
         ICASL7.EQ.'MASF'.OR.ICASL7.EQ.'MACH'.OR.ICASL7.EQ.'MADI'.OR.   &
         ICASL7.EQ.'MAMM'.OR.ICASL7.EQ.'MADM'.OR.ICASL7.EQ.'DIMA'.OR.   &
         ICASL7.EQ.'MAVT'.OR.ICASL7.EQ.'MATI'.OR.ICASL7.EQ.'MPIN'.OR.   &
         ICASL7.EQ.'MDER'.OR.ICASL7.EQ.'MDEC'.OR.ICASL7.EQ.'MDMR'.OR.   &
         ICASL7.EQ.'MDMC'.OR.ICASL7.EQ.'MDBR'.OR.ICASL7.EQ.'MDBC'.OR.   &
         ICASL7.EQ.'MDKR'.OR.ICASL7.EQ.'MDKC'.OR.ICASL7.EQ.'MDCR'.OR.   &
         ICASL7.EQ.'MDCC'.OR.ICASL7.EQ.'MRSC'.OR.ICASL7.EQ.'MCSC'.OR.   &
         ICASL7.EQ.'MCSR'.OR.ICASL7.EQ.'MCSC'.OR.   &
         ICASL7.EQ.'MCDR'.OR.ICASL7.EQ.'MCDC'.OR.   &
         ICASL7.EQ.'MJSR'.OR.ICASL7.EQ.'MJSC'.OR.   &
         ICASL7.EQ.'MJDR'.OR.ICASL7.EQ.'MJDC'.OR.   &
         ICASL7.EQ.'MPDR'.OR.ICASL7.EQ.'MPDC'.OR.   &
         ICASL7.EQ.'MPSR'.OR.ICASL7.EQ.'MPSC'.OR.   &
         ICASL7.EQ.'MHDR'.OR.ICASL7.EQ.'MHDC'.OR.   &
         ICASL7.EQ.'MXDR'.OR.ICASL7.EQ.'MXDC'.OR.   &
         ICASL7.EQ.'MZSR'.OR.ICASL7.EQ.'MASC'.OR.   &
         ICASL7.EQ.'MZDR'.OR.ICASL7.EQ.'MADC'.OR.   &
         ICASL7.EQ.'MROW'.OR.ICASL7.EQ.'MCOL'.OR.ICASL7.EQ.'MGRA'.OR.   &
         ICASL7.EQ.'MATB'.OR.ICASL7.EQ.'MARB'.OR.ICASL7.EQ.'MSP2'.OR.   &
         ICASL7.EQ.'MACN'.OR.ICASL7.EQ.'MARC'.OR.   &
         ICASL7.EQ.'MDIP'.OR.ICASL7.EQ.'MQRD'.OR.ICASL7.EQ.'MSUM')THEN
        NUMVAR=1
      ELSEIF(ICASL7.EQ.'MAAD'.OR.ICASL7.EQ.'MASU'.OR.   &
             ICASL7.EQ.'MAMU'.OR.ICASL7.EQ.'MASO'.OR.   &
             (ICASL7.EQ.'MARA'.AND.NUMARG.EQ.6).OR.   &
             ICASL7.EQ.'MASS'.OR.ICASL7.EQ.'MARW'.OR.   &
             ICASL7.EQ.'MAAU'.OR.ICASL7.EQ.'VMAT'.OR.   &
             ICASL7.EQ.'MATZ'.OR.ICASL7.EQ.'MAUZ'.OR.   &
             ICASL7.EQ.'MAAR'.OR.ICASL7.EQ.'MADR'.OR.   &
             ICASL7.EQ.'MATS'.OR.ICASL7.EQ.'MAIS'.OR.   &
             ICASL7.EQ.'MQFO'.OR.ICASL7.EQ.'MALC'.OR.   &
             ICASL7.EQ.'MAGM'.OR.ICASL7.EQ.'MAGS'.OR.   &
             ICASL7.EQ.'MHT1'.OR.ICASL7.EQ.'MHT2'.OR.   &
             ICASL7.EQ.'MPDF'.OR.ICASL7.EQ.'DPDF'.OR.   &
             ICASL7.EQ.'INRN'.OR.ICASL7.EQ.'DLPD'.OR.   &
             ICASL7.EQ.'MPVC'.OR.ICASL7.EQ.'DIRN'.OR.   &
             ICASL7.EQ.'MFTR'.OR.ICASL7.EQ.'MFTC'.OR.   &
             ICASL7.EQ.'MCRO'.OR.ICASL7.EQ.'MCCO'.OR.   &
             ICASL7.EQ.'MSPT')THEN
        NUMVAR=2
      ELSEIF(ICASL7.EQ.'MASM'.OR.ICASL7.EQ.'MAMI'.OR.   &
             ICASL7.EQ.'MACF'.OR.ICASL7.EQ.'MAEL'.OR.   &
             (ICASL7.EQ.'MADF'.AND.NUMARG.EQ.7).OR.   &
             ICASL7.EQ.'MARR'.OR.ICASL7.EQ.'MVRN'.OR.   &
             ICASL7.EQ.'MURN'.OR.   &
             ICASL7.EQ.'ADMA'.OR.ICASL7.EQ.'ADMD'.OR.   &
             ICASL7.EQ.'WIRN'.OR.ICASL7.EQ.'IURN'.OR.   &
             ICASL7.EQ.'MPAR'.OR.ICASL7.EQ.'MARN')THEN
        NUMVAR=3
      ELSEIF((ICASL7.EQ.'MADF'.AND.NUMARG.EQ.8).OR.   &
             ICASL7.EQ.'MARE'.OR.ICASL7.EQ.'MATD'.OR.   &
             ICASL7.EQ.'MTRN')THEN
        NUMVAR=4
!
!     2023/05: TREAT CREATE MATRIX SEPARATELY
!
      ELSEIF(ICASL7.EQ.'CRMA')THEN
        ISTRT=5
        ILAST=NUMARG
!
!       CHECK FOR LOCATION OF FIRST (IF ANY) SUBSET, EXCEPT OR
!       FOR CLAUSE
!
        DO 91051 I=ISTRT,NUMARG
          IHRIGH=IHARG(I)
          IHRIG2=IHARG2(I)
          IF(IHRIGH.EQ.'SUBS'.AND.IHRIG2.EQ.'ET  ')THEN
            ILAST=I-1
            GO TO 91052
          ELSEIF(IHRIGH.EQ.'EXCE'.AND.IHRIG2.EQ.'PT  ')THEN
            ILAST=I-1
            GO TO 91052
          ELSEIF(IHRIGH.EQ.'FOR '.AND.IHRIG2.EQ.'    ')THEN
            ILAST=I-1
            GO TO 91052
          ENDIF
91051   CONTINUE
91052   CONTINUE
!
!       CALL EXTVAR SO THAT " TO " SYNTAX CAN BE USED
!
!CCCC   NUMVAR=ILAST-ISTRT+1
        CALL EXTVAR(IHARG,IHARG2,NUMARG,ISTRT,ILAST,MAXCAS,   &
                    IHNAME,IHNAM2,IUSE,NUMNAM,   &
                    IVARN1,IVARN2,NUMVAR,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
!
        CALL DPMAT8(IVARN1,IVARN2,NUMVAR,   &
                    ICOLR,ILISR,NIRIGH,ITYPA,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
        GO TO 7000
!
      ELSEIF(ICASL7.EQ.'CORE' .OR. ICASL7.EQ.'CONF' .OR.   &
             ICASL7.EQ.'CKCL' .OR. ICASL7.EQ.'CKCP')THEN
        ISTRT=5
        IF(ICASL7.EQ.'CONF' .OR. ICASL7.EQ.'CKCL')ISTRT=6
        IF(ICASL7.EQ.'CKCP')ISTRT=7
        ILAST=NUMARG
        DO 1051 I=ISTRT,NUMARG
          IHRIGH=IHARG(I)
          IHRIG2=IHARG2(I)
          IF(IHRIGH.EQ.'SUBS'.AND.IHRIG2.EQ.'ET  ')THEN
            ILAST=I-1
            GO TO 1054
          ELSEIF(IHRIGH.EQ.'EXCE'.AND.IHRIG2.EQ.'PT  ')THEN
            ILAST=I-1
            GO TO 1054
          ELSEIF(IHRIGH.EQ.'FOR '.AND.IHRIG2.EQ.'    ')THEN
            ILAST=I-1
            GO TO 1054
          ENDIF
 1051   CONTINUE
 1054   CONTINUE
        NUMVAR=ILAST-ISTRT+1
      ELSEIF(ICASL7.EQ.'GMST')THEN
        ISTRT=ILOCV
        ILAST=NUMARG
        DO 1056 I=ISTRT,ILAST
          IHRIGH=IHARG(I)
          IHRIG2=IHARG2(I)
          IF(IHRIGH.EQ.'SUBS'.AND.IHRIG2.EQ.'ET  ')THEN
            ILAST=I-1
            GO TO 1059
          ELSEIF(IHRIGH.EQ.'EXCE'.AND.IHRIG2.EQ.'PT  ')THEN
            ILAST=I-1
            GO TO 1059
          ELSEIF(IHRIGH.EQ.'FOR '.AND.IHRIG2.EQ.'    ')THEN
            ILAST=I-1
            GO TO 1059
          ENDIF
 1056   CONTINUE
 1059   CONTINUE
        NUMVAR=ILAST-ISTRT+1
      ELSEIF(ICASL7.EQ.'NCDF'.OR.ICASL7.EQ.'TCDF')THEN
        ISTRT=6
        ILAST=NUMARG
        DO 1061 I=ISTRT,NUMARG
          IHRIGH=IHARG(I)
          IHRIG2=IHARG2(I)
          IF(IHRIGH.EQ.'SUBS'.AND.IHRIG2.EQ.'ET  ')THEN
            ILAST=I-1
            GO TO 1064
          ELSEIF(IHRIGH.EQ.'EXCE'.AND.IHRIG2.EQ.'PT  ')THEN
            ILAST=I-1
            GO TO 1064
          ELSEIF(IHRIGH.EQ.'FOR '.AND.IHRIG2.EQ.'    ')THEN
            ILAST=I-1
            GO TO 1064
          ENDIF
 1061   CONTINUE
 1064   CONTINUE
        NUMVAR=ILAST-ISTRT+1
        IF(ICASL7.EQ.'NCDF')THEN
          IF(NUMVAR.EQ.3)THEN
            IFLGLL='ON'
          ELSEIF(NUMVAR.EQ.2)THEN
            IFLGLL='OFF'
          ELSE
            WRITE(ICOUT,1066)
 1066       FORMAT('***** ERROR FOR MULTIVARIATE NORMAL CDF--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1068)NUMVAR
 1068       FORMAT('      EITHER 2 OR 3 ARGUMENTS EXPECTED, ',I8,   &
                   'FOUND.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(ICASL7.EQ.'TCDF')THEN
          IF(NUMVAR.EQ.4)THEN
            IFLGLL='ON'
          ELSEIF(NUMVAR.EQ.3)THEN
            IFLGLL='OFF'
          ELSE
            WRITE(ICOUT,1076)
 1076       FORMAT('***** ERROR FOR MULTIVARIATE T CDF--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1078)NUMVAR
 1078       FORMAT('      EITHER 3 OR 4 ARGUMENTS EXPECTED, ',I8,   &
                   'FOUND.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ENDIF
!
      IMATSW='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,1091)ICASL7,NUMVAR
 1091   FORMAT('ICASL7,NUMVAR = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************************
!               **  STEP 5.1--                       **
!               **  EXAMINE THE VARIABLES            **
!               **  ON THE RIGHT.                    **
!               ***************************************
!
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     2023/05:  FOR CASES THAT CAN HAVE 5 OR MORE VARIABLES,
!               TREAT SPECIAL.  SPECIFICALLY SUPPORT "TO" SYNTAX.
!               ALSO THESE CASES ONLY WANT VARIABLES.
!
!               5 VARIABLES OR MORE CURRENTLY ONLY RELEVANT FOR THE
!               "CREATE MATRIX", "DEX CORE", AND "DEX CONFOUND" COMMANDS.
!
      IF(NUMVAR.GE.5)THEN
        DO 1110 ICASE=5,NUMVAR
          IFLAG1=0
          CALL DPMAT7(ICASL7,ICASE,MAXCAS,ILOCR,   &
                      IHRIGH,IHRIG2,ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                      IFLAG1,ATEMP,ITEMP,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
 1110   CONTINUE
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IFLAG1=0
      IF(ICASL7.EQ.'MAAD'.OR.ICASL7.EQ.'MASU'.OR.ICASL7.EQ.'MAMU'.OR.   &
         ICASL7.EQ.'JAIN'.OR.ICASL7.EQ.'MATZ'.OR.ICASL7.EQ.'MAUZ')THEN
         IFLAG1=1
      ENDIF
      ICASE=1
      CALL DPMAT7(ICASL7,ICASE,MAXCAS,ILOCR,   &
      IHRIGH,IHRIG2,ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
      IFLAG1,ATEMP,ITEMP,   &
      IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(ITYPA(ICASE).EQ.'MATR')IMATSW='YES'
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NUMVAR.GE.2)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'MAAD'.OR.ICASL7.EQ.'MASU'.OR.ICASL7.EQ.'MAMU'.OR.   &
           ICASL7.EQ.'MASM'.OR.ICASL7.EQ.'MAMI'.OR.ICASL7.EQ.'MACF'.OR.   &
           ICASL7.EQ.'MADF'.OR.ICASL7.EQ.'MARA'.OR.ICASL7.EQ.'MARW'.OR.   &
           ICASL7.EQ.'MAEL'.OR.ICASL7.EQ.'MARE'.OR.ICASL7.EQ.'JAIN'.OR.   &
           ICASL7.EQ.'DIRN'.OR.ICASL7.EQ.'TCDF'.OR.ICASL7.EQ.'INRN'.OR.   &
           ICASL7.EQ.'MPAR'.OR.ICASL7.EQ.'MATZ'.OR.ICASL7.EQ.'MAUZ'.OR.   &
           ICASL7.EQ.'MFTR'.OR.ICASL7.EQ.'MFTC'.OR.ICASL7.EQ.'MAUZ'.OR.   &
           ICASL7.EQ.'MFTR'.OR.ICASL7.EQ.'MFTC'.OR.ICASL7.EQ.'MAUZ'.OR.   &
           ICASL7.EQ.'VMAT'.OR.   &
           ICASL7.EQ.'EXPS'.OR.ICASL7.EQ.'MADR'.OR.ICASL7.EQ.'MURN')   &
        THEN
          IFLAG1=1
        ENDIF
          ICASE=2
          CALL DPMAT7(ICASL7,ICASE,MAXCAS,ILOCR,   &
                      IHRIGH,IHRIG2,ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                      IFLAG1,ATEMP,ITEMP,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(ITYPA(ICASE).EQ.'MATR')IMATSW='YES'
          IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IF(NUMVAR.GE.3)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'MAAD'.OR.ICASL7.EQ.'MASU'.OR.ICASL7.EQ.'MAMU'.OR.   &
           ICASL7.EQ.'MASM'.OR.ICASL7.EQ.'MAMI'.OR.ICASL7.EQ.'MACF'.OR.   &
           ICASL7.EQ.'MADF'.OR.ICASL7.EQ.'MAEL'.OR.ICASL7.EQ.'MARE'.OR.   &
           ICASL7.EQ.'MARR'.OR.ICASL7.EQ.'MVRN'.OR.ICASL7.EQ.'MURN'.OR.   &
           ICASL7.EQ.'WIRN'.OR.ICASL7.EQ.'MADR'.OR.ICASL7.EQ.'MURN'.OR.   &
           ICASL7.EQ.'MPAR'.OR.ICASL7.EQ.'ADMA'.OR.ICASL7.EQ.'ADMD'.OR.   &
           ICASL7.EQ.'IURN'.OR.ICASL7.EQ.'MTRN')   &
        THEN
           IFLAG1=1
        ENDIF
        ICASE=3
        CALL DPMAT7(ICASL7,ICASE,MAXCAS,ILOCR,   &
                    IHRIGH,IHRIG2,ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                    IFLAG1,ATEMP,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(ITYPA(ICASE).EQ.'MATR')IMATSW='YES'
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IF(NUMVAR.GE.4)THEN
        IFLAG1=0
        IF(ICASL7.EQ.'MAAD'.OR.ICASL7.EQ.'MASU'.OR.ICASL7.EQ.'MARA'.OR.   &
           ICASL7.EQ.'MAMU'.OR.ICASL7.EQ.'MADF'.OR.ICASL7.EQ.'MARE'.OR.   &
           ICASL7.EQ.'MURN'.OR.ICASL7.EQ.'MTRN')THEN
           IFLAG1=1
        ENDIF
        ICASE=4
        CALL DPMAT7(ICASL7,ICASE,MAXCAS,ILOCR,   &
                    IHRIGH,IHRIG2,ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                    IFLAG1,ATEMP,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(ITYPA(ICASE).EQ.'MATR')IMATSW='YES'
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!     *******************************
!     **  STEP 7--                 **
!     **  DETERMINE THE SUBCASE    **
!     **  AND BRANCH ACCORDINGLY.  **
!     *******************************
!
 7000 CONTINUE
!
      ISTEPN='7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,7003)NUMVAR,NUMARG
 7003   FORMAT('7008--NUMVAR,NUMARG = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 7005 I=1,NUMVAR
          WRITE(ICOUT,7008)I,ITYPA(I),ILOCR(I)
 7008     FORMAT('7008-I,ITYPA(I),ILOCR(I) = ',I4,2X,A4,2X,I8)
          CALL DPWRST('XXX','BUG ')
 7005   CONTINUE
        WRITE(ICOUT,7006)IHARG(ILOCR(NUMVAR)),IHARG2(ILOCR(NUMVAR))
 7006   FORMAT('IHARG(ILOCR(NUMVAR)),IHARG2(ILOCR(NUMVAR)) = ',2A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7007)IHARG(ILOCR(NUMVAR)+1),   &
                         IHARG2(ILOCR(NUMVAR)+1)
 7007   FORMAT('IHARG(ILOCR(NUMVAR)+1),IHARG2(ILOCR(NUMVAR)+1) = ',   &
               2A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ICASL7.NE.'CRMA'.AND.ICASL7.NE.'GMST'.AND.ICASL7.NE.'CORE'.AND.   &
         ICASL7.NE.'CONF'.AND.ICASL7.NE.'CKCL'.AND.ICASL7.NE.'CKCP'.AND.   &
         NUMVAR.GE.5)THEN
        WRITE(ICOUT,7011)
 7011   FORMAT('***** ERROR IN DPMAT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7012)
 7012   FORMAT('      ILLEGAL SYNTAX FOR LET COMMAND AT 7000--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7013)
 7013   FORMAT('      THERE WERE 5 OR MORE VARIABLES ON THE RIGHT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7014)
 7014   FORMAT('      HAND SIDE OF THE EQUAL SIGN.  THERE ARE NO')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7015)
 7015   FORMAT('      MATRIX  LET  SYNTAXES (EXCEPT CREATE MATRIX)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7016)
 7016   FORMAT('      WITH THAT MANY VARIABLES ON THE RIGHT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7017)
 7017   FORMAT('      THE COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7019)(IANS(I),I=1,MAX(100,IWIDTH))
 7019   FORMAT(100A1)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 19000
      ENDIF
!
      IF(ILOCR(NUMVAR).EQ.NUMARG)GO TO 8000
!
!     2023/05: CREATE MATRIX NOW SUPPORT " TO " SYNATX, SO
!              HANDLE SEPARETLY FOR SUBSET/EXCEPT/FOR CLAUSES
!
      IF(ICASL7.EQ.'CRMA')THEN
        DO 77001 II=5,NUMARG
          IF(IHARG(II).EQ.'SUBS'.AND.IHARG2(II).EQ.'ET  ')THEN
            IT1=ILOCR(II)
            GO TO 9000
          ELSEIF(IHARG(II).EQ.'EXCE'.AND.IHARG2(II).EQ.'PT  ')THEN
            IT1=ILOCR(II)
            GO TO 9000
          ELSEIF(IHARG(II).EQ.'FOR '.AND.IHARG2(II).EQ.'    ')THEN
            IT1=ILOCR(II)
            GO TO 10000
           ENDIF
77001   CONTINUE
        GO TO 8000
      ENDIF
!
      IF(ILOCR(NUMVAR).LT.NUMARG)THEN
        IT1=ILOCR(NUMVAR+1)
        IF(IHARG(IT1).EQ.'SUBS'.AND.IHARG2(IT1).EQ.'ET  ')GO TO 9000
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
          WRITE(ICOUT,7009)
 7009     FORMAT('AFTER TEST FOR SUBSET')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7006)IHARG(ILOCR(NUMVAR)),   &
                           IHARG2(ILOCR(NUMVAR))
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,7007)IHARG(ILOCR(NUMVAR)+1),   &
                           IHARG2(ILOCR(NUMVAR)+1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IHARG(IT1).EQ.'EXCE'.AND.IHARG2(IT1).EQ.'PT  ')GO TO 9000
        IF(IHARG(IT1).EQ.'FOR '.AND.IHARG2(IT1).EQ.'    ')GO TO 10000
      ENDIF
!
      WRITE(ICOUT,7081)
 7081 FORMAT('***** ERROR 7081 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7082)
 7082 FORMAT('      ILLEGAL SYNTAX FOR LET COMMAND AT 7082--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7017)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7019)(IANS(I),I=1,MIN(100,IWIDTH))
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7088)ILOCV,NUMARG,NUMVAR
 7088 FORMAT('ILOCV,NUMARG,NUMVAR = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 7089 I=1,NUMVAR
        WRITE(ICOUT,7086)I,ILOCR(I)
 7086   FORMAT('I,ILOCR(I) = ',I4,2X,I8)
        CALL DPWRST('XXX','BUG ')
 7089 CONTINUE
      IERROR='YES'
      GO TO 19000
!
!     ************************************************
!     **  STEP 8--                                  **
!     **  TREAT THE FULL VARIABLE CASE.             **
!     **  EXAMPLE--LET Y = COVARIANCE MATRIX X      **
!     **  THEN JUMP TO STEP NUMBER 10 BELOW         **
!     **  FOR THE LIST UPDATING AND                 **
!     **  FOR SOME INFORMATIVE PRINTING.            **
!     ************************************************
!
!
 8000 CONTINUE
      ISTEPN='8'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,8011)NINEW,NIRIGH(1)
 8011   FORMAT('NINEW,NIRIGH(1) = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICASEQ='FULL'
      NIOLD=NIRIGH(1)
      IF(NUMVAR.GE.2)THEN
        DO 8020 I=2,NUMVAR
          IF(NIRIGH(I).GT.NIOLD)NIOLD=NIRIGH(I)
 8020   CONTINUE
      ENDIF
      NINEW=NIOLD
      DO 8100 I=1,NINEW
      ISUB(I)=1
 8100 CONTINUE
      GO TO 11000
!
!     ****************************************************************
!     **  STEP 9--                                                   *
!     **  TREAT THE PARTIAL VARIABLE SUBSET CASE.                    *
!     **  EXAMPLE--LET Y = SORT X     SUBSET 2 3 5                   *
!     **         --LET Y(I) = SORT X  SUBSET 2 3 5                   *
!     **  JUMP TO STEP NUMBER 11 BELOW                               *
!     **  FOR THE ACTUAL MATHEMATICAL OPERATION,                     *
!     **  FOR THE LIST UPDATING, AND                                 *
!     **  FOR SOME INFORMATIVE PRINTING.                             *
!     ****************************************************************
!
 9000 CONTINUE
      ISTEPN='9'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='SUBS'
      ILOCSV=ILOCR(NUMVAR)+2
      IHSET=IHARG(ILOCSV)
      IHSET2=IHARG2(ILOCSV)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,9002)ILOCSV,IHSET,IHSET2
 9002   FORMAT('ILOCSV,IHSET,IHSET2 = ',I8,2X,A4,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IHSET,IHSET2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
      IF(IERROR.EQ.'YES')GO TO 19000
      NIOLD=IN(ILOC)
      CALL DPSUBS(NIOLD,ILOCS,NSTEMP,IBUGQ,IERROR)
      NINEW=NIOLD
      GO TO 11000
!
!     ****************************************************************
!     **  STEP 10--                                                  *
!     **  TREAT THE PARTIAL VARIABLE FOR CASE.                       *
!     **  EXAMPLE--LET Y = SORT X     FOR I = 1 2 10                 *
!     **         --LET Y(I) = SORT X  FOR I = 1 2 10                 *
!     **  JUMP TO STEP NUMBER 11 BELOW                               *
!     **  FOR THE ACTUAL MATHEMATICAL OPERATION,                     *
!     **  FOR THE LIST UPDATING, AND                                 *
!     **  FOR SOME INFORMATIVE PRINTING.                             *
!     ****************************************************************
!
10000 CONTINUE
      ISTEPN='10'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FOR'
      CALL DPFOR(NIOLD,NINEW,IROW1,IROWN,   &
      NLOCAL,ILOCS,NSTEMP,IBUGQ,IERROR)
      NIFOR=NINEW
      GO TO 11000
!
!               *******************************************
!               **  STEP 11--                            **
!               **  CARRY OUT THE                        **
!               **  MATHEMATICAL OPERATION.              **
!               *******************************************
!
11000 CONTINUE
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        DO 11109 I=1,NUMVAR
        WRITE(ICOUT,11101)I,ITYPA(I)
11101   FORMAT('11101--I,ITYPA(I) = ',I4,2X,A4)
        CALL DPWRST('XXX','BUG ')
11109   CONTINUE
      ENDIF
!
      NITEMX=NINEW
      DO 11113 I=1,MAXCAS
        NS(I)=0
11113 CONTINUE
!
!CCCC CREATE MATRIX, DEX CORE, DEX CONFOUND, AND DEX CHECK CLASSIC
!CCCC HANDLED SEPARATELY, VARIABLES ARE COPIED INTO A MATRIX.
!
      IF(ICASL7.EQ.'CRMA' .OR. ICASL7.EQ.'CORE' .OR.   &
         ICASL7.EQ.'CONF' .OR. ICASL7.EQ.'CKCL' .OR.   &
         ICASL7.EQ.'CKCP')THEN
        IMCASE=ICASL7
        IMATSW='YES'
        DO 11010 K=1,NUMVAR
          IF(ITYPA(K).EQ.'VARI')THEN
            NJ=0
            DO 11011 I=1,NINEW
              IJ=MAXN*(ICOLR(K)-1)+I
              IF(ISUB(I).EQ.0)GO TO 11011
              IF(I.GT.NIRIGH(K))GO TO 11019
              NJ=NJ+1
              IF(NJ.GT.MAXROM)GO TO 11019
              IJ=MAXN*(ICOLR(K)-1)+I
              IJ2=(K-1)*MAXROM+NJ
!
              IF(IJ2.GT.MAXTOM)THEN
                WRITE(ICOUT,999)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,7011)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,62132)
62132           FORMAT('      IN CREATING A MATRIX, THE NUMBER OF ',   &
                       'VALUES')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,62133)
62133           FORMAT('      (NUMBER OF ROWS TIMES NUMBER OF COLUMNS)')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,62134)MAXTOMM
62134           FORMAT('      EXCEEDED THE CURRENT MAXIMUM (',I10,').')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,62135)
62135           FORMAT('      THE MATRIX WAS NOT CREATED.')
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 19000
              ENDIF
!
              IF(ICOLR(K).LE.MAXCOL)TEMPM1((K-1)*MAXROM+NJ)=V(IJ)
              IF(ICOLR(K).EQ.MAXCP1)TEMPM1((K-1)*MAXROM+NJ)=PRED(I)
              IF(ICOLR(K).EQ.MAXCP2)TEMPM1((K-1)*MAXROM+NJ)=RES(I)
              IF(ICOLR(K).EQ.MAXCP3)TEMPM1((K-1)*MAXROM+NJ)=YPLOT(I)
              IF(ICOLR(K).EQ.MAXCP4)TEMPM1((K-1)*MAXROM+NJ)=XPLOT(I)
              IF(ICOLR(K).EQ.MAXCP5)TEMPM1((K-1)*MAXROM+NJ)=X2PLOT(I)
              IF(ICOLR(K).EQ.MAXCP6)TEMPM1((K-1)*MAXROM+NJ)=TAGPLO(I)
11011       CONTINUE
11019       CONTINUE
          ENDIF
11010   CONTINUE
        NR1=NJ
        IF(NR1.GT.MAXROM)NR1=MAXROM
        NR2=0
        NR3=0
        NC1=NUMVAR
        NC2=0
        NC3=0
        GO TO 11189
!
!CCCC GENERATE MATRIX <STAT> HANDLED SEPARATELY.  COMPUTE STATISTIC
!CCCC FOR EACH PAIRWISE SET OF VARIABLES AND STORE THE RESULT IN A
!CCCC SQUARE MATRIX.  NOTE THAT NOT ALL STATISTICS ARE NECCESSARILY
!CCCC SYMMETRIC (E.G., SOME OF THE MATCHING STATISTICS), SO COMPUTE
!CCCC (I,J) AND (J,I) CASES SEPARATELY EVEN THOUGH THAT MAY BE
!CCCC REDUNDANT IN MOST CASES.
!
      ELSEIF(ICASL7.EQ.'GMST')THEN
        IMCASE=ICASL7
        IMATSW='YES'
!
        DO 21030 II=1,NUMVAR*NUMVAR
          TEMPM1(II)=CPUMIN
21030   CONTINUE
!
        DO 21010 KROW=1,NUMVAR
!
!         EXTRACT FIRST RESPONSE VARIABLE
!
          IF(ITYPA(KROW).EQ.'VARI')THEN
            NJ=0
            DO 21011 I=1,NINEW
              IJ=MAXN*(ICOLR(KROW)-1)+I
              IF(ISUB(I).EQ.0)GO TO 21011
              IF(I.GT.NIRIGH(KROW))GO TO 21019
              NJ=NJ+1
              IJ=MAXN*(ICOLR(KROW)-1)+I
              IF(ICOLR(KROW).LE.MAXCOL)TEMP1(NJ)=V(IJ)
              IF(ICOLR(KROW).EQ.MAXCP1)TEMP1(NJ)=PRED(I)
              IF(ICOLR(KROW).EQ.MAXCP2)TEMP1(NJ)=RES(I)
              IF(ICOLR(KROW).EQ.MAXCP3)TEMP1(NJ)=YPLOT(I)
              IF(ICOLR(KROW).EQ.MAXCP4)TEMP1(NJ)=XPLOT(I)
              IF(ICOLR(KROW).EQ.MAXCP5)TEMP1(NJ)=X2PLOT(I)
              IF(ICOLR(KROW).EQ.MAXCP6)TEMP1(NJ)=TAGPLO(I)
21011       CONTINUE
21019       CONTINUE
            NS1=NJ
          ENDIF
!
          DO 21020 KCOL=1,NUMVAR
!
!           EXTRACT SECOND RESPONSE VARIABLE
!
            IF(ITYPA(KCOL).EQ.'VARI')THEN
              NJ=0
              DO 21021 I=1,NINEW
                IJ=MAXN*(ICOLR(KCOL)-1)+I
                IF(ISUB(I).EQ.0)GO TO 21021
                IF(I.GT.NIRIGH(KCOL))GO TO 21029
                NJ=NJ+1
                IJ=MAXN*(ICOLR(KCOL)-1)+I
                IF(ICOLR(KCOL).LE.MAXCOL)TEMP2(NJ)=V(IJ)
                IF(ICOLR(KCOL).EQ.MAXCP1)TEMP2(NJ)=PRED(I)
                IF(ICOLR(KCOL).EQ.MAXCP2)TEMP2(NJ)=RES(I)
                IF(ICOLR(KCOL).EQ.MAXCP3)TEMP2(NJ)=YPLOT(I)
                IF(ICOLR(KCOL).EQ.MAXCP4)TEMP2(NJ)=XPLOT(I)
                IF(ICOLR(KCOL).EQ.MAXCP5)TEMP2(NJ)=X2PLOT(I)
                IF(ICOLR(KCOL).EQ.MAXCP6)TEMP2(NJ)=TAGPLO(I)
21021         CONTINUE
21029         CONTINUE
              NS2=NJ
            ENDIF
!
!           NOW COMPUTE THE STATISTIC
!
            NUMV2=2
            CALL CMPSTA(TEMP1,TEMP2,TEMP3,TEMP4,TEMP91,TEMP92,   &
                        TEMP12(1),TEMP12(MAXOBV+1),   &
                        MAXOBV,NS1,NS2,NS1,NUMV2,ICASS7,ISTARA,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        RIGHT,   &
                        ISUBRO,IBUGA3,IERROR)
             IF(IERROR.EQ.'YES')GO TO 9000
             INDX=(KCOL-1)*MAXROM + KROW
             TEMPM1(INDX)=RIGHT
!
21020     CONTINUE
!
21010   CONTINUE
        NR1=NUMVAR
        IF(NR1.GT.MAXROM)NR1=MAXROM
        NR2=0
        NR3=0
        NC1=NUMVAR
        NC2=0
        NC3=0
        GO TO 11189
      ENDIF
!
      DO 11110 K=1,MIN(NUMVAR,4)
        IF(ITYPA(K).EQ.'VARI')THEN
          DO 11111 I=1,NINEW
            IJ=MAXN*(ICOLR(K)-1)+I
!CCCC       IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
!CCCC         WRITE(ICOUT,11112)I,NS(K),NINEW,ISUB(I),IJ,V(IJ)
!11112        FORMAT('I,NS(K),NINEW,ISUB(I),IJ,V(IJ) = ',5I8,F12.5)
!CCCC         CALL DPWRST('XXX','BUG ')
!CCCC       ENDIF
            IF(ISUB(I).EQ.0)GO TO 11111
            IF(I.GT.NIRIGH(K))GO TO 11119
            NS(K)=NS(K)+1
            IJ=MAXN*(ICOLR(K)-1)+I
            IF(ICOLR(K).LE.MAXCOL)TEMP4(NS(K))=V(IJ)
            IF(ICOLR(K).EQ.MAXCP1)TEMP4(NS(K))=PRED(I)
            IF(ICOLR(K).EQ.MAXCP2)TEMP4(NS(K))=RES(I)
            IF(ICOLR(K).EQ.MAXCP3)TEMP4(NS(K))=YPLOT(I)
            IF(ICOLR(K).EQ.MAXCP4)TEMP4(NS(K))=XPLOT(I)
            IF(ICOLR(K).EQ.MAXCP5)TEMP4(NS(K))=X2PLOT(I)
            IF(ICOLR(K).EQ.MAXCP6)TEMP4(NS(K))=TAGPLO(I)
11111     CONTINUE
11119     CONTINUE
          IF(K.EQ.1)THEN
            DO 11126 J=1,NS(K)
              TEMP1(J)=TEMP4(J)
!CCCC         IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
!CCCC           WRITE(ICOUT,11137)K,J,TEMP1(J)
!11137           FORMAT('K,J,TEMP1(J) = ',2I8,E15.7)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC         ENDIF
11126       CONTINUE
          ELSEIF(K.EQ.2)THEN
            DO 11127 J=1,NS(K)
              TEMP2(J)=TEMP4(J)
!CCCC         IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
!CCCC           WRITE(ICOUT,11138)K,J,TEMP1(J)
!11138           FORMAT('K,J,TEMP1(J) = ',2I8,E15.7)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC         ENDIF
11127       CONTINUE
          ELSEIF(K.EQ.3)THEN
            DO 11128 J=1,NS(K)
              TEMP3(J)=TEMP4(J)
!CCCC         IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
!CCCC           WRITE(ICOUT,11139)K,J,TEMP1(J)
!11139           FORMAT('K,J,TEMP1(J) = ',2I8,E15.7)
!CCCC           CALL DPWRST('XXX','BUG ')
!CCCC         ENDIF
11128       CONTINUE
          ENDIF
        ENDIF
11110 CONTINUE
!
!     -----BEGIN MATRIX COPY-----
!
      IF(ICASL7.EQ.'MADF')IMATSW='YES'
      IF(ICASL7.EQ.'DIMA')IMATSW='YES'
      IF(ICASL7.EQ.'MAVT')IMATSW='YES'
      IF(IMATSW.EQ.'NO')GO TO 11290
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        IF(ITYPA(1).EQ.'MATR')THEN
          WRITE(ICOUT,11201)ILISR(1),ICOLR(1),IVALUE(ILISR(1)),   &
                            IVALU2(ILISR(1))
11201     FORMAT('11201--ILISR(1),ICOLR(1),IVALUE(ILISR(1)),',   &
                 'IVALU2(ILISR(1))=',14I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        DO 11208 I=1,MIN(4,NUMVAR)
          WRITE(ICOUT,11202)I,ITYPA(I)
11202     FORMAT('11202--I,ITYPA(I) = ',I4,2X,A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11204)I,ILISR(I),IVALU2(ILISR(I))
11204     FORMAT('11204--I,ILISR(I),IVALU2(I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
11208   CONTINUE
      ENDIF
!
      NC1=1
      NC2=1
      NC3=1
      IF(ITYPA(1).EQ.'MATR'.AND.NUMVAR.GE.1)   &
      NC1=IVALU2(ILISR(1))-IVALUE(ILISR(1))+1
      IF(ITYPA(2).EQ.'MATR'.AND.NUMVAR.GE.2)   &
      NC2=IVALU2(ILISR(2))-IVALUE(ILISR(2))+1
      IF(ITYPA(3).EQ.'MATR'.AND.NUMVAR.GE.3)   &
      NC3=IVALU2(ILISR(3))-IVALUE(ILISR(3))+1
      IF(ICASL7.EQ.'MADF')NC1=INT(TEMPS(3)+0.1)
!
      IF(NUMVAR.LE.0)GO TO 11219
      IF(ITYPA(1).EQ.'MATR'.OR.ICASL7.EQ.'MADF')THEN
        NLOOP=NC1
        IF(NLOOP.LT.1)NLOOP=1
        DO 11211 JLOOP=1,NLOOP
          NS(1)=0
          DO 11212 I=1,NINEW
          IJ=MAXN*(ICOLR(1)-1+JLOOP-1)+I
!
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
            WRITE(ICOUT,11213)I,JLOOP,NS(1),NINEW,ISUB(I),IJ,V(IJ)
11213       FORMAT('I,JLOOP,NS(1),NINEW,ISUB(I),IJ,V(IJ) = ',6I8,F12.5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(ISUB(I).EQ.0)GO TO 11212
          IF(I.GT.NIRIGH(1))GO TO 11214
          NS(1)=NS(1)+1
          IJ=MAXN*(ICOLR(1)-1+JLOOP-1)+I
          IF(ICOLR(1).LE.MAXCOL)TEMPM1((JLOOP-1)*MAXROM+NS(1))=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)TEMPM1((JLOOP-1)*MAXROM+NS(1))=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)TEMPM1((JLOOP-1)*MAXROM+NS(1))=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)TEMPM1((JLOOP-1)*MAXROM+NS(1))=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)TEMPM1((JLOOP-1)*MAXROM+NS(1))=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)TEMPM1((JLOOP-1)*MAXROM+NS(1))=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)TEMPM1((JLOOP-1)*MAXROM+NS(1))=TAGPLO(I)
11212     CONTINUE
11214     CONTINUE
11211   CONTINUE
      ENDIF
11219 CONTINUE
!
      IF(NUMVAR.LE.1)GO TO 11229
      IF(ITYPA(2).EQ.'MATR')THEN
        NLOOP=NC2
        IF(NLOOP.LT.1)NLOOP=1
        DO 11221 JLOOP=1,NLOOP
          NS(2)=0
          DO 11222 I=1,NINEW
          IJ=MAXN*(ICOLR(2)-1+JLOOP-1)+I
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
            WRITE(ICOUT,11223)I,JLOOP,NS(2),NINEW,ISUB(I),IJ,V(IJ)
11223       FORMAT('I,JLOOP,NS(2),NINEW,ISUB(I),IJ,V(IJ) = ',6I8,F12.5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IF(ISUB(I).EQ.0)GO TO 11222
          IF(I.GT.NIRIGH(2))GO TO 11224
          NS(2)=NS(2)+1
          IJ=MAXN*(ICOLR(2)-1+JLOOP-1)+I
          IF(ICOLR(2).LE.MAXCOL)TEMPM2((JLOOP-1)*MAXROM+NS(2))=V(IJ)
          IF(ICOLR(2).EQ.MAXCP1)TEMPM2((JLOOP-1)*MAXROM+NS(2))=PRED(I)
          IF(ICOLR(2).EQ.MAXCP2)TEMPM2((JLOOP-1)*MAXROM+NS(2))=RES(I)
          IF(ICOLR(2).EQ.MAXCP3)TEMPM2((JLOOP-1)*MAXROM+NS(2))=YPLOT(I)
          IF(ICOLR(2).EQ.MAXCP4)TEMPM2((JLOOP-1)*MAXROM+NS(2))=XPLOT(I)
          IF(ICOLR(2).EQ.MAXCP5)TEMPM2((JLOOP-1)*MAXROM+NS(2))=X2PLOT(I)
          IF(ICOLR(2).EQ.MAXCP6)TEMPM2((JLOOP-1)*MAXROM+NS(2))=TAGPLO(I)
11222     CONTINUE
11224     CONTINUE
11221   CONTINUE
      ENDIF
11229 CONTINUE
!
      IF(NUMVAR.LE.2)GO TO 11239
        IF(ITYPA(3).EQ.'MATR')THEN
        NLOOP=NC3
        IF(NLOOP.LT.1)NLOOP=1
        DO 11231 JLOOP=1,NLOOP
          NS(3)=0
          DO 11232 I=1,NINEW
          IJ=MAXN*(ICOLR(3)-1+JLOOP-1)+I
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
            WRITE(ICOUT,11233)I,JLOOP,NS(3),NINEW,ISUB(I),IJ,V(IJ)
11233       FORMAT('I,JLOOP,NS(3),NINEW,ISUB(I),IJ,V(IJ) = ',6I8,F12.5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IF(ISUB(I).EQ.0)GO TO 11232
          IF(I.GT.NIRIGH(3))GO TO 11234
          NS(3)=NS(3)+1
          IJ=MAXN*(ICOLR(3)-1+JLOOP-1)+I
          IF(ICOLR(3).LE.MAXCOL)TEMM91((JLOOP-1)*MAXROM+NS(3))=V(IJ)
          IF(ICOLR(2).EQ.MAXCP1)TEMM91((JLOOP-1)*MAXROM+NS(3))=PRED(I)
          IF(ICOLR(2).EQ.MAXCP2)TEMM91((JLOOP-1)*MAXROM+NS(3))=RES(I)
          IF(ICOLR(2).EQ.MAXCP3)TEMM91((JLOOP-1)*MAXROM+NS(3))=YPLOT(I)
          IF(ICOLR(2).EQ.MAXCP4)TEMM91((JLOOP-1)*MAXROM+NS(3))=XPLOT(I)
          IF(ICOLR(2).EQ.MAXCP5)TEMM91((JLOOP-1)*MAXROM+NS(3))=X2PLOT(I)
          IF(ICOLR(2).EQ.MAXCP6)TEMM91((JLOOP-1)*MAXROM+NS(3))=TAGPLO(I)
11232     CONTINUE
11234     CONTINUE
11231   CONTINUE
      ENDIF
11239 CONTINUE
!
11290 CONTINUE
!
!     -----END MATRIX COPY-----
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,11291)ICOLL(1),ICOLR(1),ICOLR(2),ICOLR(3),   &
                          NS(1),NS(2),NS(3)
11291   FORMAT('11291--ICOLL(1),ICOLR(1),ICOLR(2),ICOLR(3),',   &
               'NS(1),NS(2),NS(3) = ',7I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11292)NINEW,ICASL7,ICASEQ
11292   FORMAT('11292--NINEW,ICASL7,ICASEQ = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 11294 I=1,NUMVAR
        WRITE(ICOUT,11293)I,ITYPA(I)
11293   FORMAT('11293--I,ITYPA(I) =',I4,2X,A4)
        CALL DPWRST('XXX','BUG ')
11294   CONTINUE
        WRITE(ICOUT,11295)NS(1),NS(2),NS(3),NS(4)
11295   FORMAT('11295--NS(1),NS(2),NS(3),NS(4) = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11296)IMATSW,ICASL7
11296   FORMAT('11296--IMATSW,ICASL7 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IWRITE='ON'
      IF(IPRINT.EQ.'OFF')IWRITE='OFF'
      IF(IFEEDB.EQ.'OFF')IWRITE='OFF'
!
!     -----MATRIX SECTION-----
!
      IMCASE=ICASL7
      IUPFLG='FULL'
      NR1=1
      NR2=1
      NR3=1
      IF(ITYPA(1).EQ.'MATR'.AND.NUMVAR.GE.1)NR1=NS(1)
      IF(ITYPA(2).EQ.'MATR'.AND.NUMVAR.GE.2)NR2=NS(2)
      IF(ITYPA(3).EQ.'MATR'.AND.NUMVAR.GE.3)NR3=NS(3)
      IF(ICASL7.EQ.'MADF')NR1=INT(TEMPS(2)+0.1)
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
        WRITE(ICOUT,11881)NS(1),NS(2),NS(3),NR1,NC1,NR2,NC2,NR3,NC3
11881   FORMAT('NS(1),NS(2),NS(3),NR1,NC1,NR2,NC2,NR3,NC3 = ',9I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
11189 CONTINUE
      IF(ICASL7.EQ.'MASV'.OR.ICASL7.EQ.'MASD'.OR.ICASL7.EQ.'MASF'.OR.   &
         ICASL7.EQ.'MARW'.OR.ICASL7.EQ.'MAEL'.OR.ICASL7.EQ.'MACH'.OR.   &
         ICASL7.EQ.'MAAU'.OR.ICASL7.EQ.'MADI'.OR.ICASL7.EQ.'DIMA'.OR.   &
         ICASL7.EQ.'MARR'.OR.ICASL7.EQ.'MARE'.OR.ICASL7.EQ.'MATD'.OR.   &
         ICASL7.EQ.'BIPL'.OR.   &
         ICASL7.EQ.'MATS'.OR.ICASL7.EQ.'MATI'.OR.ICASL7.EQ.'MAIS')THEN
        CALL MATAR2(TEMPM1,NR1,NC1,TEMPM2,NR2,NC2,NR3,NC3,   &
        MAXROM,MAXCOM,   &
        TEMP1,NS(1),TEMP2,NS(2),TEMP3,NS(3),TEMP4,NS(4),   &
        ITEMP1,   &
        TEMPS(1),TEMPS(2),TEMPS(3),TEMPS(4),   &
        IMCASE,IUPFLG,IMSUBC,   &
        ITYPA(1),ITYPA(2),ITYPA(3),ITYPA(4),NUMVAR,IWRITE,   &
        IBPLSC,PBPLCO,   &
        TEMM91,NR91,NC91,TEMP91,NVECT9,SCAL91,ITYP91,   &
        IBUGA3,ISUBRO,IERROR)
      ELSEIF(ICASL7.EQ.'MPIN'.OR.ICASL7.EQ.'MQFO'.OR.   &
         ICASL7.EQ.'MALC'.OR.ICASL7.EQ.'MAVT'.OR.ICASL7.EQ.'MAGM'.OR.   &
         ICASL7.EQ.'MAGS'.OR.ICASL7.EQ.'MHT1'.OR.ICASL7.EQ.'MHT2'.OR.   &
         ICASL7.EQ.'MPVC'.OR.ICASL7.EQ.'MAMM'.OR.ICASL7.EQ.'MAAR'.OR.   &
         ICASL7.EQ.'MADR'.OR.ICASL7.EQ.'MDER'.OR.ICASL7.EQ.'MDEC'.OR.   &
         ICASL7.EQ.'MDMR'.OR.ICASL7.EQ.'MDMC'.OR.ICASL7.EQ.'MDBR'.OR.   &
         ICASL7.EQ.'MDBC'.OR.ICASL7.EQ.'MDKR'.OR.ICASL7.EQ.'MDKC'.OR.   &
         ICASL7.EQ.'MDCR'.OR.ICASL7.EQ.'MDCC'.OR.ICASL7.EQ.'MRSC'.OR.   &
         ICASL7.EQ.'MCSC'.OR.ICASL7.EQ.'MDIP'.OR.ICASL7.EQ.'MADM'.OR.   &
         ICASL7.EQ.'MVRN'.OR.ICASL7.EQ.'MACA'.OR.ICASL7.EQ.'XTXI'.OR.   &
         ICASL7.EQ.'VINF'.OR.ICASL7.EQ.'CIND'.OR.ICASL7.EQ.'MARN'.OR.   &
         ICASL7.EQ.'MURN'.OR.ICASL7.EQ.'WIRN'.OR.ICASL7.EQ.'MPDF'.OR.   &
         ICASL7.EQ.'MROW'.OR.ICASL7.EQ.'MCOL'.OR.ICASL7.EQ.'DPDF'.OR.   &
         ICASL7.EQ.'NCDF'.OR.ICASL7.EQ.'TCDF'.OR.ICASL7.EQ.'DLPD'.OR.   &
         ICASL7.EQ.'MTRN'.OR.ICASL7.EQ.'DIRN'.OR.ICASL7.EQ.'INRN'.OR.   &
         ICASL7.EQ.'MPAR'.OR.ICASL7.EQ.'MGRA'.OR.ICASL7.EQ.'MSP2'.OR.   &
         ICASL7.EQ.'MATB'.OR.ICASL7.EQ.'MARB'.OR.ICASL7.EQ.'MSPT'.OR.   &
         ICASL7.EQ.'ADMA'.OR.ICASL7.EQ.'ADMD'.OR.ICASL7.EQ.'CONF'.OR.   &
         ICASL7.EQ.'MFTR'.OR.ICASL7.EQ.'MFTC'.OR.ICASL7.EQ.'CKCL'.OR.   &
         ICASL7.EQ.'CKCP'.OR.   &
         ICASL7.EQ.'VMAT'.OR.ICASL7.EQ.'MVAR'.OR.ICASL7.EQ.'CORE'.OR.   &
         ICASL7.EQ.'MCRO'.OR.ICASL7.EQ.'MCCO'.OR.ICASL7.EQ.'GMST'.OR.   &
         ICASL7.EQ.'MCSR'.OR.ICASL7.EQ.'MCSC'.OR.   &
         ICASL7.EQ.'MCDR'.OR.ICASL7.EQ.'MCDC'.OR.   &
         ICASL7.EQ.'MZSR'.OR.ICASL7.EQ.'MASC'.OR.   &
         ICASL7.EQ.'MZDR'.OR.ICASL7.EQ.'MADC'.OR.   &
         ICASL7.EQ.'MJSR'.OR.ICASL7.EQ.'MJSC'.OR.   &
         ICASL7.EQ.'MJDR'.OR.ICASL7.EQ.'MJDC'.OR.   &
         ICASL7.EQ.'MPDR'.OR.ICASL7.EQ.'MPDC'.OR.   &
         ICASL7.EQ.'MPSR'.OR.ICASL7.EQ.'MPSC'.OR.   &
         ICASL7.EQ.'MHDR'.OR.ICASL7.EQ.'MHDC'.OR.   &
         ICASL7.EQ.'MXDR'.OR.ICASL7.EQ.'MXDC'.OR.   &
         ICASL7.EQ.'CRMA'.OR.ICASL7.EQ.'IURN'.OR.ICASL7.EQ.'MSUM')THEN
!
        IHP='P   '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          P=2.0
        ELSE
          P=VALUE(ILOCP)
        ENDIF
!
        IHP='ABSE'
        IHP2='PS  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ABSEPS=0.00005
          IF(ICASL7.EQ.'TCDF')ABSEPS=0.0
        ELSE
          ABSEPS=VALUE(ILOCP)
        ENDIF
!
        IHP='RELE'
        IHP2='PS  '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          RELEPS=0.0
          IF(ICASL7.EQ.'TCDF')RELEPS=0.005
        ELSE
          RELEPS=VALUE(ILOCP)
        ENDIF
!
        IRELAT='OFF'
        IF(ICASL7.EQ.'MARB')IRELAT='ON'
        CLWID=CLWIDT(1)
        XSTART=CLLIMI(1)
        XSTOP=CLLIMI(2)
!
        CALL MATAR3(TEMPM1,NR1,NC1,TEMPM2,NR2,NC2,NR3,NC3,   &
                    MAXROM,MAXCOM,MAXOBV,   &
                    TEMP1,NS(1),TEMP2,NS(2),TEMP3,NS(3),   &
                    TEMP4,NS(4),TEMP12,TEMP92,   &
                    INDEX,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    P,ABSEPS,RELEPS,ERRS,   &
                    TEMPS(1),TEMPS(2),TEMPS(3),TEMPS(4),   &
                    ASIG90,ASIG95,ASIG99,ASG995,   &
                    IMCASE,IUPFLG,IMSUBC,   &
                    ITYPA(1),ITYPA(2),ITYPA(3),ITYPA(4),NUMVAR,IWRITE,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,   &
                    ITEMP5,ITEMP6,ITEMP7,   &
                    TEMM91,NR91,NC91,TEMP91,NVECT9,SCAL91,ITYP91,   &
                    ICASS7,ISTARA,   &
                    IRELAT,CLWID,XSTART,XSTOP,   &
                    STME,STMEC,ST2T,ST2TC,STC,STT,   &
                    IBUGA3,ISUBRO,IERROR)
!
        IF(ICASL7.EQ.'CONF')THEN
          IHP='FLAG'
          IHP2='DCON'
          VALUE0=1.0
          IF(IERROR.EQ.'YES')THEN
            VALUE0=0.0
            CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
            IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
            IANS,IWIDTH,IBUGA3,IERROR)
            GO TO 19000
          ENDIF
          CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
          IANS,IWIDTH,IBUGA3,IERROR)
        ELSEIF(ICASL7.EQ.'MHT1'.OR.ICASL7.EQ.'MHT2')THEN
          IHP='B90 '
          IHP2='    '
          VALUE0=ASIG90
          CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
          IANS,IWIDTH,IBUGA3,IERROR)
!
          IHP='B95 '
          IHP2='    '
          VALUE0=ASIG95
          CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
          IANS,IWIDTH,IBUGA3,IERROR)
!
          IHP='B99 '
          IHP2='    '
          VALUE0=ASIG99
          CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
          IANS,IWIDTH,IBUGA3,IERROR)
!
          IHP='B995'
          IHP2='    '
          VALUE0=ASG995
          CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
          IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
          IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
      ELSE
        IHP='P1  '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          P1=10.0
        ELSE
          P1=VALUE(ILOCP)
          IF(P1.LT.0.0)P1=10.0
          IF(P1.GT.50.0)P1=50.0
        ENDIF
!
        IHP='P2  '
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          P2=10.0
        ELSE
          P2=VALUE(ILOCP)
          IF(P2.LT.0.0)P2=10.0
          IF(P2.GT.50.0)P2=50.0
        ENDIF
!
        IHP='BETA'
        IHP2='    '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          BETA=0.1
        ELSE
          BETA=VALUE(ILOCP)
          IF(BETA.LE.0.0)BETA=0.01
          IF(P2.GT.0.5)BETA=0.5
        ENDIF
!
        CALL MATARI(TEMPM1,NR1,NC1,TEMPM2,NR2,NC2,NR3,NC3,   &
        MAXROM,MAXCOM,   &
        TEMP1,NS(1),TEMP2,NS(2),TEMP3,NS(3),TEMP4,NS(4),   &
        ITEMP1,ITEMP2,ITEMP3,   &
        DTEMP1,DTEMP2,P1,P2,BETA,   &
        TEMPS(1),TEMPS(2),TEMPS(3),TEMPS(4),   &
        IMCASE,IUPFLG,IMSUBC,   &
        ITYPA(1),ITYPA(2),ITYPA(3),ITYPA(4),NUMVAR,IWRITE,   &
        TEMM91,NR91,NC91,TEMP91,NVECT9,SCAL91,ITYP91,   &
        IBUGA3,ISUBRO,IERROR)
!
      ENDIF
!
      NITEMX=NVECT9
      IF(IERROR.EQ.'YES')GO TO 19000
      IF(ITYP91.EQ.'VECT')THEN
        DO 11887 I=1,NITEMX
          TEMP1(I)=TEMP91(I)
11887   CONTINUE
      ELSEIF(ITYP91.EQ.'MATR')THEN
        NITEMX=NR91
        DO 11882 J=1,NC91
        DO 11883 I=1,NITEMX
          TEMPM1((J-1)*MAXROM+I)=TEMM91((J-1)*MAXROM+I)
!
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')THEN
            WRITE(ICOUT,11885)I,J,TEMM91((J-1)*MAXROM+I)
11885       FORMAT('I,J,TEMPM1((J-1)*MAXROM+I) = ',2I8,E15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
11883   CONTINUE
11882   CONTINUE
        IF(ICASL7.EQ.'MASD' .OR. ICASL7.EQ.'MASF')THEN
          DO 11886 I=1,NVECT9
            TEMP1(I)=TEMP91(I)
11886     CONTINUE
        ENDIF
      ENDIF
      IFOUND='YES'
      IF(IERROR.EQ.'YES')GO TO 19000
!
!
!               ************************************************
!               **  STEP XX--                                 **
!               **  BRANCH TO THE PROPER CASE                 **
!               **  DEPENDING ON THE TYPE OF OUTPUT--         **
!               **     1) SCALAR (= PARAMETER)                **
!               **     2) VECTOR (= VARIABLE) (THE USUAL)     **
!               **     3) MATRIX                              **
!               **  UPDATE DATAPLOT'S INTERNAL WORKSPACE      **
!               **  AND HOUSEKEEPING TABLES                   **
!               ************************************************
!
      IF(ITYP91.EQ.'SCAL')GO TO 14000
!
!     -----TREAT THE VECTOR AND MATRIX CASE-----
!
!CCCC NOTE: FOR "MATRIX COLUMN <STAT>"
!CCCC CASE, TREAT AS FULL EVEN IF A SUBSET CLAUSE WAS ENTERED
!CCCC (NUMBER OF ROWS IN THE RETURNED VECTOR IS KEYED TO THE
!CCCC COLUMNS IN THE MATRIX, NOT THE ROWS IN THE MATRIX).
!CCCC NOTE: FURTHER CONSIDERATION SHOWED THAT WHETHER UPDATING
!CCCC SHOULD BE DONE AS "FULL" OR AS SUBSET CASE DEPENDDS ON THE
!CCCC SPECIFIC MATRIX COMMAND (E.G., MATRIX ADDITION SHOULD MAINTAIN
!CCCC THE SUBSET WHEN SAVING THE RESULT, WHILE A CORRELATION
!CCCC MATRIX SHOULD ALWAYS BE UPDATED AS A FULL MATRIX).
!
      IF(IUPFLG.EQ.'FULL' .OR. ICASEQ.EQ.'FULL')GO TO 12100
      IF(ICASEQ.EQ.'SUBS')GO TO 12300
      IF(ICASEQ.EQ.'FOR')GO TO 12500
!
!               *******************************************
!               **  STEP 11.1--                          **
!               **  TREAT THE FULL CASE.                 **
!               *******************************************
!
12100 CONTINUE
      ISTEPN='11.1'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      NSX=0
      IF(NITEMX.LE.0)THEN
        IROW1=0
        IROWN=0
        GO TO 12190
      ENDIF
!
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')GO TO 12130
      IF(ICASL7.EQ.'IURN'.AND.ITYP91.EQ.'MATR')GO TO 12130
      IF(ICASL7.EQ.'DIRN'.AND.ITYP91.EQ.'MATR')GO TO 12130
      IF(ICASL7.EQ.'MURN'.AND.ITYP91.EQ.'MATR')GO TO 12130
      IF(ICASL7.EQ.'WIRN'.AND.ITYP91.EQ.'MATR')GO TO 12130
      IF(ICASL7.EQ.'ADMA'.AND.ITYP91.EQ.'MATR')GO TO 12130
      IF(ICASL7.EQ.'VMAT'.AND.ITYP91.EQ.'MATR')GO TO 12130
!
      DO 12110 I=1,NITEMX
        NSX=I
!
        IJ=MAXN*(ICOLL(1)-1)+I
        IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP1)PRED(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP2)RES(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP3)YPLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP4)XPLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP5)X2PLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP6)TAGPLO(I)=TEMP1(NSX)
12110 CONTINUE
!
      IF(ICASL7.EQ.'MATB' .OR. ICASL7.EQ.'MARB' .OR.   &
         ICASL7.EQ.'MSPT' .OR. ICASL7.EQ.'MSP2' .OR.   &
         ICASL7.EQ.'MFTR' .OR. ICASL7.EQ.'MFTC' .OR.   &
         ICASL7.EQ.'BIPL' .OR. ICASL7.EQ.'CONF')THEN
        DO 12120 I=1,NITEMX
          NSX=I
          IJ=MAXN*(ICOLL(2)-1)+I
          IF(ICOLL(2).LE.MAXCOL)V(IJ)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP1)PRED(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP2)RES(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP3)YPLOT(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP4)XPLOT(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP5)X2PLOT(I)=TEMP2(NSX)
          IF(ICOLL(2).EQ.MAXCP6)TAGPLO(I)=TEMP2(NSX)
12120   CONTINUE
      ENDIF
!
      IF(ICASL7.EQ.'MSPT' .OR. ICASL7.EQ.'BIPL' .OR.   &
         ICASL7.EQ.'MFTR' .OR. ICASL7.EQ.'MFTC')THEN
        DO 12122 I=1,NITEMX
          NSX=I
          IJ=MAXN*(ICOLL(3)-1)+I
          IF(ICOLL(3).LE.MAXCOL)V(IJ)=TEMP3(NSX)
          IF(ICOLL(3).EQ.MAXCP1)PRED(I)=TEMP3(NSX)
          IF(ICOLL(3).EQ.MAXCP2)RES(I)=TEMP3(NSX)
          IF(ICOLL(3).EQ.MAXCP3)YPLOT(I)=TEMP3(NSX)
          IF(ICOLL(3).EQ.MAXCP4)XPLOT(I)=TEMP3(NSX)
          IF(ICOLL(3).EQ.MAXCP5)X2PLOT(I)=TEMP3(NSX)
          IF(ICOLL(3).EQ.MAXCP6)TAGPLO(I)=TEMP3(NSX)
12122   CONTINUE
      ENDIF
!
      IF(ICASL7.EQ.'MFTR' .OR. ICASL7.EQ.'MFTC')THEN
        DO 12123 I=1,NITEMX
          NSX=I
          IJ=MAXN*(ICOLL(4)-1)+I
          IF(ICOLL(4).LE.MAXCOL)V(IJ)=TEMP4(NSX)
          IF(ICOLL(4).EQ.MAXCP1)PRED(I)=TEMP4(NSX)
          IF(ICOLL(4).EQ.MAXCP2)RES(I)=TEMP4(NSX)
          IF(ICOLL(4).EQ.MAXCP3)YPLOT(I)=TEMP4(NSX)
          IF(ICOLL(4).EQ.MAXCP4)XPLOT(I)=TEMP4(NSX)
          IF(ICOLL(4).EQ.MAXCP5)X2PLOT(I)=TEMP4(NSX)
          IF(ICOLL(4).EQ.MAXCP6)TAGPLO(I)=TEMP4(NSX)
12123   CONTINUE
      ENDIF
!
      GO TO 12190
!
!     -----BEGIN MATRIX COPY FOR FULL CASE-----
!
12130 CONTINUE
      ISTEPN='FULL'
      ISTEPN='11.3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      NLOOP=NC91
!
      ICOL=ICOLL(1)-1+NLOOP
      IF(ICOL.LE.MAXCOL)GO TO 12139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12131)
12131 FORMAT('***** ERROR 12131 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12132)
12132 FORMAT('      AN ATTEMPT WAS MADE TO CREATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12133)
12133 FORMAT('      A MATRIX WHOSE COLUMNS EXTEND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12134)MAXCOL
12134 FORMAT('      BEYOND THE ALLOWABLE ',I8,' COLUMNS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12135)
12135 FORMAT('      OF THE INTERNAL INTERNAL WORKSHEET.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
12139 CONTINUE
!
!CCCC OCTOBER 1993.  FOR MATRIX AUGMENT, NEED TO ADD NC2 BLANK
!CCCC COLUMNS IF LEFT HAND MATRIX IS OLD.
      IF(NEWNAM(1).NE.'YES'.AND.ICASL7.EQ.'MAAU')THEN
        NFIRST=IVALU2(ILISL(1))+1
        NUMADD=NC2
        IERROR='NO'
        CALL DPUPD2(NUMADD,NFIRST,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 19000
      ENDIF
!
      ISTEPN='11.4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      DO 12140 JLOOP=1,NLOOP
      NSX=0
      DO 12150 I=1,NITEMX
      NSX=I
      IJ=MAXN*(ICOLL(1)-1+JLOOP-1)+I
      IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMPM1((JLOOP-1)*MAXROM+NSX)
12150 CONTINUE
12140 CONTINUE
!
!CCCC JULY 1993.  IF FIRST MATRIX IS NEW, NEED TO ADJUST COLUMN
!CCCC             NUMBERS FOR SECOND (AND POSSIBLY THIRD) NEW VARIABLES
!CCCC             OR MATRICES ON LEFT.
      IF(NEWNAM(1).EQ.'YES')THEN
        IF(NEWNAM(2).EQ.'YES')THEN
          NADD=NLOOP-1
          ICOLL(2)=ICOLL(2)+NADD
          ILISL(2)=ILISL(2)+NADD+1
        ENDIF
        IF(NEWNAM(3).EQ.'YES')THEN
          NADD=NLOOP-1
          ICOLL(3)=ICOLL(3)+NADD
          ILISL(3)=ILISL(3)+NADD+1
        ENDIF
      ENDIF
      IF(ICASL7.EQ.'MASD')GO TO 22130
      IF(ICASL7.EQ.'MASF')GO TO 22130
      GO TO 12190
!
!CCCC NOTE: FOR SVD, SVF, HAVE LET U S V = MATRIX SING VALUE FACT M
!CCCC       I.E., THE SECOND MATRIX IS IN THE THIRD ARGUMENT.
22130 CONTINUE
      NLOOP=NC2
!
      ICOL=ICOLL(3)-1+NLOOP
      IF(ICOL.LE.MAXCOL)GO TO 22139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22131)
22131 FORMAT('***** ERROR 22131 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22132)
22132 FORMAT('      AN ATTEMPT WAS MADE TO CREATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22133)
22133 FORMAT('      A MATRIX WHOSE COLUMNS EXTEND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22134)MAXCOL
22134 FORMAT('      BEYOND THE ALLOWABLE ',I8,' COLUMNS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22135)
22135 FORMAT('      OF THE INTERNAL INTERNAL WORKSHEET.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
22139 CONTINUE
!
      DO 22140 JLOOP=1,NLOOP
      NSX=0
      DO 22150 I=1,NR2
      NSX=I
      IJ=MAXN*(ICOLL(3)-1+JLOOP-1)+I
      IF(ICOLL(3).LE.MAXCOL)V(IJ)=TEMPM2((JLOOP-1)*MAXROM+NSX)
22150 CONTINUE
22140 CONTINUE
      GO TO 12190
!
!     -----END MATRIX COPY FOR FULL CASE-----
!
12190 CONTINUE
!
      IF(ICASL7.NE.'MASD'.AND.ICASL7.NE.'MASF')THEN
        IF(NITEMX.GE.1)IROW1=1
        IF(NITEMX.GE.1)IROWN=NITEMX
        IN(ILISL(1))=NITEMX
        IF(NUMVAL.GE.2)IN(ILISL(2))=NITEMX
        IF(NUMVAL.GE.3)IN(ILISL(3))=NITEMX
        IF(NUMVAL.GE.4)IN(ILISL(4))=NITEMX
      ELSE
        IF(NITEMX.GE.1)IROW1=1
        IF(NITEMX.GE.1)IROWN=NITEMX
        IN(ILISL(1))=NITEMX
        IF(NUMVAL.EQ.2)IN(ILISL(2))=NVECT9
        IF(NUMVAL.EQ.3)IN(ILISL(3))=NR2
      ENDIF
!
      DO 12210 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(1))GO TO 12215
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(1))GO TO 12215
      GO TO 12210
12215 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(1)
      VALUE(J4)=ICOLL(1)
      IN(J4)=NITEMX
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')THEN
        IVALUE(J4)=ICOLL(1)
        IVALU2(J4)=ICOLL(1)+NC91-1
      ENDIF
12210 CONTINUE
!
      IF(NUMVAL.LE.1)GO TO 12229
      DO 12220 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(2))GO TO 12225
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(2))GO TO 12225
      GO TO 12220
12225 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(2)
      VALUE(J4)=ICOLL(2)
      IF(ICASL7.NE.'MASD'.AND.ICASL7.NE.'MASF')THEN
        IN(J4)=NITEMX
      ELSE
        IN(J4)=NVECT9
      ENDIF
12220 CONTINUE
12229 CONTINUE
!
      IF(NUMVAL.LE.2)GO TO 12239
      DO 12230 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(3))GO TO 12235
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(3))GO TO 12235
      GO TO 12230
12235 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(3)
      VALUE(J4)=ICOLL(3)
      IF(ICASL7.NE.'MASD'.AND.ICASL7.NE.'MASF')THEN
        IN(J4)=NITEMX
      ELSE
        IN(J4)=NR2
        IVALUE(J4)=ICOLL(3)
        IVALU2(J4)=ICOLL(3)+NC2-1
      ENDIF
12230 CONTINUE
12239 CONTINUE
!
      IF(NUMVAL.LE.3)GO TO 12249
      DO 12240 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(4))GO TO 12245
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(4))GO TO 12245
      GO TO 12240
12245 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(4)
      VALUE(J4)=ICOLL(4)
      IN(J4)=NITEMX
12240 CONTINUE
12249 CONTINUE
!
      GO TO 13000
!
!               *******************************************
!               **  STEP 11.2--                          **
!               **  TREAT THE SUBSET CASE.               **
!               *******************************************
!
12300 CONTINUE
      ISTEPN='11.2'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      NSX=0
      IF(NITEMX.LE.0)IROW1=0
      IF(NITEMX.LE.0)IROWN=0
      IF(NITEMX.LE.0)GO TO 12390
!
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')GO TO 12330
!
      DO 12310 I=1,NITEMX
        IF(ISUB(I).EQ.0)GO TO 12310
        NSX=NSX+1
!
        IJ=MAXN*(ICOLL(1)-1)+I
        IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP1)PRED(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP2)RES(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP3)YPLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP4)XPLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP5)X2PLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP6)TAGPLO(I)=TEMP1(NSX)
        IF(NSX.EQ.1)IROW1=I
        IROWN=I
!
12310 CONTINUE
      GO TO 12390
!
!     -----BEGIN MATRIX COPY FOR SUBSET CASE-----
!
12330 CONTINUE
      NLOOP=NC91
!
      ICOL=ICOLL(1)-1+NLOOP
      IF(ICOL.LE.MAXCOL)GO TO 12339
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12331)
12331 FORMAT('***** ERROR 12331 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12332)
12332 FORMAT('      AN ATTEMPT WAS MADE TO CREATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12333)
12333 FORMAT('      A MATRIX WHOSE COLUMNS EXTEND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12334)MAXCOL
12334 FORMAT('      BEYOND THE ALLOWABLE ',I8,' COLUMNS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12335)
12335 FORMAT('      OF THE INTERNAL INTERNAL WORKSHEET.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
12339 CONTINUE
!
      DO 12340 JLOOP=1,NLOOP
      NSX=0
      DO 12350 I=1,NITEMX
      IF(ISUB(I).EQ.0)GO TO 12350
      NSX=NSX+1
      IJ=MAXN*(ICOLL(1)-1+JLOOP-1)+I
      IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMPM1((JLOOP-1)*MAXROM+NSX)
      IF(NSX.EQ.1)IROW1=I
      IROWN=I
12350 CONTINUE
12340 CONTINUE
      GO TO 12390
!
!     -----END MATRIX COPY FOR SUBSET CASE-----
!
12390 CONTINUE
!
      IN(ILISL(1))=NITEMX
      IF(NUMVAL.EQ.2)IN(ILISL(2))=NITEMX
!
      DO 12410 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(1))GO TO 12415
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(1))GO TO 12415
      GO TO 12410
12415 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(1)
      VALUE(J4)=ICOLL(1)
      IN(J4)=NITEMX
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')IVALUE(J4)=ICOLL(1)
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')IVALU2(J4)=ICOLL(1)+NC91-1
12410 CONTINUE
!
      IF(NUMVAL.LE.1)GO TO 12429
      DO 12420 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(2))GO TO 12425
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(2))GO TO 12425
      GO TO 12420
12425 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(2)
      VALUE(J4)=ICOLL(2)
      IN(J4)=NITEMX
12420 CONTINUE
12429 CONTINUE
!
      GO TO 13000
!
!               *******************************************
!               **  STEP 11.3--                          **
!               **  TREAT THE FOR CASE.                  **
!               *******************************************
!
12500 CONTINUE
      ISTEPN='11.3'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
      NSX=0
      IF(NITEMX.LE.0)IROW1=0
      IF(NITEMX.LE.0)IROWN=0
      IF(NITEMX.LE.0)GO TO 12590
!
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')GO TO 12530
!
      DO 12510 I=1,NITEMX
        IF(I.GT.NIFOR)GO TO 12590
        IF(ISUB(I).EQ.0)GO TO 12510
        NSX=NSX+1
        IJ=MAXN*(ICOLL(1)-1)+I
        IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP1)PRED(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP2)RES(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP3)YPLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP4)XPLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP5)X2PLOT(I)=TEMP1(NSX)
        IF(ICOLL(1).EQ.MAXCP6)TAGPLO(I)=TEMP1(NSX)
        IF(NSX.EQ.1)IROW1=I
        IROWN=I
!
12510 CONTINUE
      GO TO 12590
!
!     -----BEGIN MATRIX COPY FOR   FOR    CASE-----
!
12530 CONTINUE
      NLOOP=NC91
!
      ICOL=ICOLL(1)-1+NLOOP
      IF(ICOL.LE.MAXCOL)GO TO 12539
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12531)
12531 FORMAT('***** ERROR 12531 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12532)
12532 FORMAT('      AN ATTEMPT WAS MADE TO CREATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12533)
12533 FORMAT('      A MATRIX WHOSE COLUMNS EXTEND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12534)MAXCOL
12534 FORMAT('      BEYOND THE ALLOWABLE ',I8,' COLUMNS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,12535)
12535 FORMAT('      OF THE INTERNAL INTERNAL WORKSHEET.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
12539 CONTINUE
!
      DO 12540 JLOOP=1,NLOOP
      NSX=0
      DO 12550 I=1,NITEMX
      IF(I.GT.NIFOR)GO TO 12550
      IF(ISUB(I).EQ.0)GO TO 12550
      NSX=NSX+1
      IJ=MAXN*(ICOLL(1)-1+JLOOP-1)+I
      IF(ICOLL(1).LE.MAXCOL)V(IJ)=TEMPM1((JLOOP-1)*MAXROM+NSX)
      IF(NSX.EQ.1)IROW1=I
      IROWN=I
12550 CONTINUE
12540 CONTINUE
      GO TO 12590
!
!     -----END MATRIX COPY FOR   FOR    CASE-----
!
12590 CONTINUE
!
      IN(ILISL(1))=NITEMX
      IF(NUMVAL.EQ.2)IN(ILISL(2))=NITEMX
!
      DO 12610 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(1))GO TO 12615
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(1))GO TO 12615
      GO TO 12610
12615 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(1)
      VALUE(J4)=ICOLL(1)
      IN(J4)=NITEMX
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')IVALUE(J4)=ICOLL(1)
      IF(IMATSW.EQ.'YES'.AND.ITYP91.EQ.'MATR')IVALU2(J4)=ICOLL(1)+NC91-1
12610 CONTINUE
!
      IF(NUMVAL.LE.1)GO TO 12629
      DO 12620 J4=1,NUMNAM
      IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL(2))GO TO 12625
      IF(IUSE(J4).EQ.'M'.AND.IVALUE(J4).EQ.ICOLL(2))GO TO 12625
      GO TO 12620
12625 CONTINUE
      IUSE(J4)='V'
      IVALUE(J4)=ICOLL(2)
      VALUE(J4)=ICOLL(2)
      IN(J4)=NITEMX
12620 CONTINUE
12629 CONTINUE
!
      GO TO 13000
!
!               *****************************************************
!               **  STEP 13--                                      **
!               **  BRANCH TO THE PROPER CASE
!               **  DEPENDING ON THE TYPE OF OUTPUT--
!               **     1) SCALAR (= PARAMETER)
!               **     2) VECTOR (= VARIABLE) (THE USUAL)
!               **     3) MATRIX
!               **  UPDATE DATAPLOT'S INTERNAL WORKSPACE
!               **  AND HOUSEKEEPING TABLES
!               *****************************************************
!
13000 CONTINUE
      IF(ITYP91.EQ.'SCAL')GO TO 14000
      IF(ITYP91.EQ.'MATR')GO TO 15000
      GO TO 16000
!
!               *****************************************************
!               **  STEP 14--                                      **
!               **  TREAT THE PARAMETER (SCALAR) CASE.             **
!               **  EXAMPLE--LET D = DETERMINANT A                 **
!               **           WHERE A WAS PREVIOUSLY UNDEFINED      **
!               **           OR WHERE A WAS PREVIOUSLY A PARAMETER.**
!               **  CARRY OUT THE LIST UPDATING  AND               **
!               **  GENERATE THE INFORMATIVE PRINTING.             **
!               **  THEN EXIT.                                     **
!               *****************************************************
!
14000 CONTINUE
      ISTEPN='14'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHNAME(ILISL(1))=ILEFT(1)
      IHNAM2(ILISL(1))=ILEF2(1)
      IUSE(ILISL(1))='P'
      VALUE(ILISL(1))=SCAL91
      IVALUE(ILISL(1))=INT(VALUE(ILISL(1))+0.5)
      IN(ILISL(1))=1
      IF(NEWNAM(1).EQ.'YES')NUMNAM=NUMNAM+1
!
      IF(IPRINT.EQ.'OFF')GO TO 14019
      IF(IFEEDB.EQ.'OFF')GO TO 14019
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,14011)ILEFT(1),ILEF2(1),SCAL91
14011 FORMAT('THE COMPUTED VALUE OF THE CONSTANT ',   &
      A4,A4,'      = ',E15.8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
14019 CONTINUE
!
!  FOR MULTIVARIATE NORMAL CDF OR MULTIVARIATE T CDF, UPDATE
!  AN ADDITIONAL PARAMETER.  SET IT AFTER OTHER SCALAR UPDATE
!  TO AVOID OVERWRITE.
!
      IF(ICASL7.EQ.'NCDF'.OR.ICASL7.EQ.'TCDF')THEN
        IHP='NCDF'
        IHP2='ERRS'
        VALUE0=ERRS
        CALL DPADDP(IHP,IHP2,VALUE0,IHOST1,ISUBN0,   &
        IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
        IANS,IWIDTH,IBUGA3,IERROR)
      ENDIF
      GO TO 19000
!
!               *******************************************
!               **  STEP 15--                            **
!               **  TREAT THE MATRIX CASE--              **
!               **  CARRY OUT THE LIST UPDATING AND      **
!               **  GENERATE THE INFORMATIVE PRINTING    **
!               **  FOR STEP NUMBERS 7, 8, AND 9 ABOVE.  **
!               *******************************************
!
15000 CONTINUE
      ISTEPN='15'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHMAT1=ILEFT(1)
      IHMAT2=ILEF2(1)
      IMATNR=NR91
      IMATNC=NC91
      IMATCO=ICOLL(1)
!
      IHNAME(ILISL(1))=IHMAT1
      IHNAM2(ILISL(1))=IHMAT2
      IUSE(ILISL(1))='M'
      IVALUE(ILISL(1))=IMATCO
      IN(ILISL(1))=IMATNR
      IVALU2(ILISL(1))=IMATCO+IMATNC-1
      IF(NEWNAM(1).EQ.'YES')NUMNAM=NUMNAM+1
!CCCC AUGUST 1993.  NUMBER OF COLUMNS UPDATED IN SUBSEQUENT LOOP
!CCCC IF(NEWNAM(1).EQ.'YES')NUMCOL=NUMCOL+1
!
      IF(IMATNC.LE.0)GO TO 15039
      INAM=NUMNAM
      DO 15010 J=1,IMATNC
!
      INAM=INAM+1
      IF(INAM.LE.MAXNAM)GO TO 15019
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15011)
15011 FORMAT('***** ERROR 15011 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15012)
15012 FORMAT('      THE NUMBER OF VARIABLE AND/OR PARAMETER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15013)MAXNAM
15013 FORMAT('      NAMES HAS JUST EXCEEDED THE MAX ALLOWABLE ',   &
      I8,'  .')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
15019 CONTINUE
!
      ICOL=IMATCO+J-1
      IF(ICOL.LE.MAXCOL)GO TO 15029
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15021)
15021 FORMAT('***** ERROR 15021 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15022)
15022 FORMAT('      THE NUMBER OF WORKSHEET VARIABLES (COLUMNS)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15023)MAXCOL
15023 FORMAT('      HAS JUST EXCEEDED THE MAX ALLOWABLE ',   &
      I8,'  .')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
15029 CONTINUE
!
      CALL DPAPN2(IHMAT1,IHMAT2,J,MAXCAS,   &
                  IH1,IH2,IBUGA3,ISUBRO,IERROR)
      IHNAME(INAM)=IH1
      IHNAM2(INAM)=IH2
      IUSE(INAM)='V'
      IVALUE(INAM)=ICOL
      IN(INAM)=IMATNR
      IF(NEWNAM(1).EQ.'YES')NUMNAM=NUMNAM+1
      IF(NEWNAM(1).EQ.'YES')NUMCOL=NUMCOL+1
!
15010 CONTINUE
15039 CONTINUE
!
      IF(IPRINT.EQ.'OFF')GO TO 15090
      IF(IFEEDB.EQ.'OFF')GO TO 15090
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,15041)IHMAT1,IHMAT2,IMATNR
15041 FORMAT('THE NUMBER OF ROWS    GENERATED FOR ',   &
      'THE MATRIX   ',A4,A4,' = ',I8)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,15042)IHMAT1,IHMAT2,IMATNC
15042 FORMAT('THE NUMBER OF COLUMNS GENERATED FOR ',   &
      'THE MATRIX   ',A4,A4,' = ',I8)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,15051)IHMAT1,IHMAT2
15051 FORMAT('THE FIRST           COMPUTED ROW   OF ',A4,A4,' =')
      CALL DPWRST('XXX','BUG ')
      JMAX=IMATNC
      IF(JMAX.GT.10)JMAX=10
      DO 15055 J=1,JMAX
      IJ=MAXN*(IMATCO-1+J-1)+1
      TEMPV(J)=V(IJ)
15055 CONTINUE
      IF(JMAX.LE.10)WRITE(ICOUT,15056)(TEMPV(J),J=1,JMAX)
15056 FORMAT(10E10.3)
      IF(JMAX.LE.10)CALL DPWRST('XXX','BUG ')
      IF(JMAX.GT.10)WRITE(ICOUT,15057)(TEMPV(J),J=1,JMAX)
15057 FORMAT(10E10.3,' ...')
      IF(JMAX.GT.10)CALL DPWRST('XXX','BUG ')
!
      WRITE(ICOUT,15061)IMATNR,IHMAT1,IHMAT2
15061 FORMAT('THE LAST (',I5,'-TH) COMPUTED ROW   OF ',A4,A4,' =')
      CALL DPWRST('XXX','BUG ')
      JMAX=IMATNC
      IF(JMAX.GT.10)JMAX=10
      DO 15065 J=1,JMAX
      IJ=MAXN*(IMATCO-1+J-1)+IMATNR
      TEMPV(J)=V(IJ)
15065 CONTINUE
      IF(JMAX.LE.10)WRITE(ICOUT,15066)(TEMPV(J),J=1,JMAX)
15066 FORMAT(10E10.3)
      IF(JMAX.LE.10)CALL DPWRST('XXX','BUG ')
      IF(JMAX.GT.10)WRITE(ICOUT,15067)(TEMPV(J),J=1,JMAX)
15067 FORMAT(10E10.3,' ...')
      IF(JMAX.GT.10)CALL DPWRST('XXX','BUG ')
!
      IF(IMATNR.NE.1.AND.IMATNC.NE.1)GO TO 15079
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,15072)
15072 FORMAT('CAUTION--THIS MATRIX HAS ONLY 1 ROW AND 1 COLUMN')
      CALL DPWRST('XXX','BUG ')
15079 CONTINUE
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
!
      IHCV11='    '
      IHCV12='    '
      IHCV21='    '
      IHCV22='    '
      IHCV31='    '
      IHCV32='    '
      IF(IMATNC.GE.1)THEN
        J=1
        CALL DPAPN2(IHMAT1,IHMAT2,J,MAXCAS,   &
                    IHCV11,IHCV12,IBUGA3,ISUBRO,IERROR)
      ENDIF
      IF(IMATNC.GE.2)THEN
        J=2
        CALL DPAPN2(IHMAT1,IHMAT2,J,MAXCAS,   &
                    IHCV21,IHCV22,IBUGA3,ISUBRO,IERROR)
      ENDIF
      IF(IMATNC.GE.3)THEN
        J=3
        CALL DPAPN2(IHMAT1,IHMAT2,J,MAXCAS,   &
                    IHCV31,IHCV32,IBUGA3,ISUBRO,IERROR)
      ENDIF
      IF(IMATNC.LE.3)THEN
        WRITE(ICOUT,15081)IHMAT1,IHMAT2,IHCV11,IHCV12,IHCV21,IHCV22,   &
                          IHCV31,IHCV32
15081   FORMAT('THE COLUMN VECTOR NAMES ASSIGNED TO MATRIX ',2A4,   &
               'ARE ',2(2A4,2X),2A4)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IMATNC.GT.3)THEN
         WRITE(ICOUT,15082)IHMAT1,IHMAT2,IHCV11,IHCV12,IHCV21,IHCV22,   &
                           IHCV31,IHCV32
15082   FORMAT('THE COLUMN VECTOR NAMES ASSIGNED TO MATRIX ',2A4,   &
               'ARE ',3(2A4,2X),'...')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICV1=IMATCO
      ICV2=IMATCO+IMATNC-1
      WRITE(ICOUT,15083)IHMAT1,IHMAT2,ICV1,ICV2
15083 FORMAT('THE WORKSHEET COLUMNS   ASSIGNED TO MATRIX ',2A4,   &
             'ARE ',I8,' TO',I8)
      CALL DPWRST('XXX','BUG ')
!
15090 CONTINUE
      IF(ICASL7.EQ.'MASD' .OR. ICASL7.EQ.'MASF')GO TO 25000
!
      GO TO 19000
!
!               *******************************************
!               **  STEP 25--                            **
!               **  TREAT THE MATRIX CASE--              **
!               **  UPDATE MATRIX 2                      **
!               **  CARRY OUT THE LIST UPDATING AND      **
!               **  GENERATE THE INFORMATIVE PRINTING    **
!               **  FOR STEP NUMBERS 7, 8, AND 9 ABOVE.  **
!               *******************************************
!
25000 CONTINUE
      ISTEPN='25'
!CCCC JULY 1993.  SINGULAR VALUE DECOMPOSTION USES VECTOR AS SECOND
!CCCC ARGUMENT ON LEFT.
      IHNAME(ILISL(2))=ILEFT(2)
      IHNAM2(ILISL(2))=ILEF2(2)
      IUSE(ILISL(2))='V'
      IVALUE(ILISL(2))=ICOLL(2)
      VALUE(ILISL(2))=ICOLL(2)
      IN(ILISL(2))=NVECT9
      IF(NEWNAM(2).EQ.'YES')NUMNAM=NUMNAM+1
!CCCC AUGUST 1993.  NUMBER OF COLUMNS UPDATED IN SUBSEQUENT LOOP
!CCCC IF(NEWNAM(2).EQ.'YES')NUMCOL=NUMCOL+1
      IF(NEWNAM(2).EQ.'YES')NUMCOL=NUMCOL+1
!
      DO 25002 I=1,NVECT9
      IJ=MAXN*(ICOLL(2)-1)+I
      IF(ICOLL(2).LE.MAXCOL)V(IJ)=TEMP1(I)
      IF(ICOLL(2).EQ.MAXCP1)PRED(I)=TEMP1(I)
      IF(ICOLL(2).EQ.MAXCP2)RES(I)=TEMP1(I)
      IF(ICOLL(2).EQ.MAXCP3)YPLOT(I)=TEMP1(I)
      IF(ICOLL(2).EQ.MAXCP4)XPLOT(I)=TEMP1(I)
      IF(ICOLL(2).EQ.MAXCP5)X2PLOT(I)=TEMP1(I)
      IF(ICOLL(2).EQ.MAXCP6)TAGPLO(I)=TEMP1(I)
25002 CONTINUE
!
      ISTEPN='25A'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHMAT1=ILEFT(3)
      IHMAT2=ILEF2(3)
      IMATNR=NR2
      IMATNC=NC2
      IMATCO=ICOLL(3)
!
      IHNAME(ILISL(3))=IHMAT1
      IHNAM2(ILISL(3))=IHMAT2
      IUSE(ILISL(3))='M'
      IVALUE(ILISL(3))=IMATCO
      IN(ILISL(3))=IMATNR
      IVALU2(ILISL(3))=IMATCO+IMATNC-1
      IF(NEWNAM(3).EQ.'YES')NUMNAM=NUMNAM+1
      IF(NEWNAM(3).EQ.'YES')NUMCOL=NUMCOL+1
!
      IF(IMATNC.LE.0)GO TO 25039
      INAM=NUMNAM
      DO 25010 J=1,IMATNC
!
      INAM=INAM+1
      IF(INAM.LE.MAXNAM)GO TO 25019
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,25011)
25011 FORMAT('***** ERROR 15011 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,25012)
25012 FORMAT('      THE NUMBER OF VARIABLE AND/OR PARAMETER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,25013)MAXNAM
25013 FORMAT('      NAMES HAS JUST EXCEEDED THE MAX ALLOWABLE ',   &
      I8,'  .')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
25019 CONTINUE
!
      ICOL=IMATCO+J-1
      IF(INAM.LE.MAXNAM)GO TO 25029
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,25021)
25021 FORMAT('***** ERROR 25021 IN DPMAT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,25022)
25022 FORMAT('      THE NUMBER OF WORKSHEET VARIABLES (COLUMNS)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,25023)MAXCOL
25023 FORMAT('      HAS JUST EXCEEDED THE MAX ALLOWABLE ',   &
      I8,'  .')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
25029 CONTINUE
!
      CALL DPAPN2(IHMAT1,IHMAT2,J,MAXCAS,   &
                  IH1,IH2,IBUGA3,ISUBRO,IERROR)
      IHNAME(INAM)=IH1
      IHNAM2(INAM)=IH2
      IUSE(INAM)='V'
      IVALUE(INAM)=ICOL
      IN(INAM)=IMATNR
