19014   FORMAT('ILOCV,ICASL7,ITCASE,IWRITE = ',I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19016)NSX,NITEMX,NS(1),NS(2)
19016   FORMAT('NSX,NITEMX,NS(1),NS(2) = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19021)ILEFT(1),ILEF2(1),ILISL(1),ICOLL(1)
19021   FORMAT('ILEFT(1),ILEF2(1),ILISL(1),ICOLL(1) = ',A4,2X,A4,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19022)ILEFT(2),ILEF2(2),ILISL(2),ICOLL(2)
19022   FORMAT('ILEFT(2),ILEF2(2),ILISL(2),ICOLL(2) = ',A4,2X,A4,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19023)NUMVAL,NEWNAM(1),NEWNAM(2),NUMVAR
19023   FORMAT('NUMVAL,NEWNAM(1),NEWNAM(2),NUMVAR = ',I8,2X,A4,2X,A4,I8)
        CALL DPWRST('XXX','BUG ')
        DO 19025 I=1,4
          WRITE(ICOUT,19024)I,ILISR(I),ICOLR(I),ITYPA(I)
19024     FORMAT('I,ILISR(I),ICOLR(I),ITYPA(I) = ',I2,I8,I8,1X,A4)
          CALL DPWRST('XXX','BUG ')
19025   CONTINUE
        WRITE(ICOUT,19026)TEMPS(1),TEMPS(2),TEMPS(3),TEMPS(4)
19026   FORMAT('TEMPS(1),TEMPS(2),TEMPS(3),TEMPS(4) = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        IF(IMATSW.EQ.'NO')THEN
          WRITE(ICOUT,19032)NR1,NC1,NR2,NC2,NR91,NC91
19032     FORMAT('NR1,NC1,NR2,NC2,NR91,NC91 = ',6I8)
          CALL DPWRST('XXX','BUG ')
          IF(ITYPA(1).EQ.'MATR'.OR.ITYPA(1).EQ.'VARI')THEN
            WRITE(ICOUT,19033)ILISR(1),IN(ILISR(1)),IVALUE(ILISR(1)),   &
                              IVALU2(ILISR(1))
19033       FORMAT('ILISR(1),IN(ILISR(1)),IVALUE(ILISR(1)),',   &
                   'IVALU2(ILISR(1)) = ',4I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          WRITE(ICOUT,19034)(ILOCR(J),J=3,7)
19034     FORMAT('ILOCR(3),...,ILOCR(7) = ',5I8)
          CALL DPWRST('XXX','BUG ')
!
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(NR1.GT.0 .AND. NC1.GT.0)THEN
            JMAX=NC1
            IF(JMAX.GT.10)JMAX=10
            DO 19045 I=1,NR1
              WRITE(ICOUT,19046)I,(TEMPM1((J-1)*MAXROM+I),J=1,JMAX)
19046         FORMAT('I,TEMPM1(I,.) = ',I8,10E10.3)
              CALL DPWRST('XXX','BUG ')
19045       CONTINUE
          ENDIF
!
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(NR2.GT.0 .AND. NC2.GT.0)THEN
            JMAX=NC2
            IF(JMAX.GT.10)JMAX=10
            DO 19055 I=1,NR2
              WRITE(ICOUT,19056)I,(TEMPM2((J-1)*MAXROM+I),J=1,JMAX)
19056         FORMAT('I,TEMPM2(I,.) = ',I8,10E10.3)
              CALL DPWRST('XXX','BUG ')
19055       CONTINUE
          ENDIF
!
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IF(NR91.GT.0 .AND. NC91.GT.0)THEN
            JMAX=NC91
            IF(JMAX.GT.10)JMAX=10
            DO 19065 I=1,NR91
              WRITE(ICOUT,19066)I,(TEMM91((J-1)*MAXROM+I),J=1,JMAX)
19066         FORMAT('I,TEMM91(I,.) = ',I8,10E10.3)
              CALL DPWRST('XXX','BUG ')
19065       CONTINUE
          ENDIF
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAT2
      SUBROUTINE DPMAT6(ICASL7,ICASE,MAXCAS,   &
                        ILEFT,ILEFT2,NEWNAM,ILISL,ICOLL,   &
                        NUMVAL,NIOLD,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
!
!     NOTE--THIS SUBROUTINE IS A UTILITY ROUTINE FOR DPMATC AND
!           DPMAT2.  IT CHECKS A VARIABLE ON THE LEFT HAND SIDE
!           OF THE EQUAL SIGN.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/6
!     ORIGINAL VERSION--JUNE      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASL7
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 NEWNAM(MAXCAS)
      CHARACTER*4 ILEFT(MAXCAS)
      CHARACTER*4 ILEFT2(MAXCAS)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER ILISL(MAXCAS)
      INTEGER ICOLL(MAXCAS)
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='T6  '
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT6')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAT6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASL7,IBUGA3,ISUBRO
   52   FORMAT('ICASL7,IBUGA3,ISUBRO = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **********************************
!               **  STEP 1--                    **
!               **  INITIALIZE SOME VARIABLES.  **
!               **********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT6')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NEWNAM(ICASE)='NO'
!
!               ******************************************************
!               **  STEP 2A--                                        *
!               **  EXAMINE THE LEFT-HAND SIDE--                     *
!               **  IS THE VARIABLE NAME TO LEFT OF = SIGN           *
!               **  ALREADY IN THE NAME LIST?    AS A VARIABLE?      *
!               **  NOTE THAT  ILEFT   IS THE NAME OF THE VARIABLE   *
!               **  ON THE LEFT.                                     *
!               **  NOTE THAT     ILISL     IS THE LINE IN THE TABLE *
!               **  OF THE NAME ON THE LEFT.                         *
!               **  NOTE THAT  ICOLL(ICASE)  IS THE DATA COLUMN      *
!               **  (1 TO 12)                                        *
!               **  FOR THE NAME OF THE LEFT.                        *
!               ******************************************************
!
      ISTEPN='2A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT6')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILEFT(ICASE)=IHARG(ICASE)
      ILEFT2(ICASE)=IHARG2(ICASE)
      DO 210 I=1,NUMNAM
        I2=I
        IF(ILEFT(ICASE).EQ.IHNAME(I).AND.ILEFT2(ICASE).EQ.IHNAM2(I))THEN
          IF(IUSE(I).EQ.'P')THEN
            GO TO 230
          ELSEIF(IUSE(I).EQ.'V' .OR. IUSE(I).EQ.'M')THEN
            GO TO 280
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,221)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,110)ILEFT(ICASE),ILEFT2(ICASE)
  110       FORMAT('      AN ATTEMPT WAS MADE TO USE ',2A4,' AS A ',   &
                   'VARIABLE')
            CALL DPWRST('XXX','BUG ')
            IF(IUSE(I).EQ.'F')THEN
              WRITE(ICOUT,111)
  111         FORMAT('      EVEN THOUGH IT ALREADY EXISTS AS A STRING.')
              CALL DPWRST('XXX','BUG ')
            ELSE
              WRITE(ICOUT,113)IUSE(I)
  113         FORMAT('      EVEN THOUGH IT ALREADY EXISTS AS A ',A4,'.')
              CALL DPWRST('XXX','BUG ')
            ENDIF
            IERROR='YES'
            GO TO 19000
          ENDIF
        ENDIF
  210 CONTINUE
!
!  CASE WHERE NAME NOT FOUND IN CURRENT NAME LIST
!
      NEWNAM(ICASE)='YES'
      IF(ICASE.GT.1)NUMVAL=ICASE
!
      IJUNK=0
      DO 211 I=1,ICASE
        IF(NEWNAM(I).EQ.'YES')IJUNK=IJUNK+1
  211 CONTINUE
      ILISL(ICASE)=NUMNAM+IJUNK
!
      IF(ILISL(ICASE).GT.MAXNAM)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,221)
  221   FORMAT('***** ERROR 221 IN DPMAT6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,222)
  222   FORMAT('      THE NUMBER OF VARIABLE AND/OR PARAMETER')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,223)MAXNAM
  223   FORMAT('      NAMES HAS JUST EXCEEDED THE MAX ALLOWABLE ',   &
               I8,'  .')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,224)
  224   FORMAT('      SUGGESTED ACTION--ENTER    STATUS VARIABLES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,226)
  226   FORMAT('      TO FIND OUT THE FULL LIST OF USED NAMES,')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,227)
  227   FORMAT('      AND THEN REDEFINE (REUSE) SOME OF THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,228)
  228   FORMAT('      ALREADY-USED NAMES.  ALTERNATIVELY, USE THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,229)
  229   FORMAT('      DELETE COMMAND TO FREE NO LONGER NEED NAMES.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 19000
      ELSE
        GO TO 235
      ENDIF
!
!  CASE WHERE NAME FOUND AS A PARAMETER
!
  230 CONTINUE
      IF(ICASE.GT.1)NUMVAL=ICASE
      ILISL(ICASE)=I2
      GO TO 235
!
  235 CONTINUE
      NIOLD=0
      IF(ICASE.GT.1)NUMVAL=ICASE
      IF(ICASE.EQ.1)THEN
        ICOLL(ICASE)=NUMCOL+1
      ELSEIF(ICASE.GT.1)THEN
        ICOLL(ICASE)=NUMCOL
        DO 237 I=1,ICASE
          IF(NEWNAM(I).EQ.'YES')ICOLL(ICASE)=ICOLL(ICASE)+1
  237   CONTINUE
      ENDIF
      IF(ICOLL(ICASE).LE.MAXCOL)GO TO 290
!
      WRITE(ICOUT,241)
  241 FORMAT('***** ERROR 241 IN DPMAT6--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,242)
  242 FORMAT('      THE NUMBER OF DATA COLUMNS HAS JUST EXCEEDED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,243)MAXCOL
  243 FORMAT('      THE MAX ALLOWABLE ',I8,'  .  SUGGESTED ACTION--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,245)
  245 FORMAT('      ENTER      STATUS VARIABLES')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,246)
  246 FORMAT('      TO FIND OUT THE FULL LIST OF USED COLUMNS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,247)
  247 FORMAT('      AND THEN OVERWRITE SOME COLUMNS.   EXAMPLE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,248)
  248 FORMAT('      IF       LET X(I) = 3.14         FAILED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,249)
  249 FORMAT('      THEN ONE MIGHT ENTER     LET X = COLUMN 7')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,250)
  250 FORMAT('      (THEREBY EQUATING THE NAME X WITH COLUMN 7')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,251)
  251 FORMAT('      FOLLOWED BY              LET X(I) = 3.14')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,252)
  252 FORMAT('      (WHICH WILL ACTUALLY OVERWRITE COLUMN 7')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,253)
  253 FORMAT('      WITH THE NUMERIC CONSTANTS 3.14).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,255)
  255 FORMAT('      ALTERNATIVELY, USE THE DIMENSION COMMAND TO ',   &
             'CREATE MORE COLUMNS.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
!
!  CASE WHERE NAME FOUND AS A VARIABLE
!
  280 CONTINUE
      IF(ICASE.GT.1)NUMVAL=ICASE
      ILISL(ICASE)=I2
      ICOLL(ICASE)=IVALUE(ILISL(ICASE))
      NIOLD=IN(ILISL(ICASE))
!
  290 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT6')THEN
        WRITE(ICOUT,291)
  291   FORMAT('AT THE END OF STEP 2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,292)ILEFT(ICASE),ILEFT2(ICASE),NEWNAM(ICASE),   &
                        NUMNAM,ILISL(ICASE),   &
                        ICOLL(ICASE),NIOLD
        CALL DPWRST('XXX','BUG ')
  292   FORMAT('ILEFT,ILEFT2,NEWNAM,NUMNAM,ILISL(ICASE),',   &
               'ICOLL(ICASE),NIOLD = ',A4,A4,2X,A4,2X,4I8)
      ENDIF
                                                                                                                                  
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
19000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT6')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19011)
19011   FORMAT('***** AT THE END       OF DPMAT6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19012)IFOUND,IERROR
19012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19021)ILEFT(ICASE),ILEFT2(ICASE),ILISL(ICASE),   &
                          ICOLL(ICASE)
19021   FORMAT('ILEFT,ILEFT2,ILISL(ICASE),ICOLL(ICASE) = ',   &
               A4,2X,A4,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19023)NEWNAM(ICASE)
19023   FORMAT('NEWNAM = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAT6
      SUBROUTINE DPMAT7(ICASL7,ICASE,MAXCAS,ILOCR,   &
                        IHRIGH,IHRIG2,ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                        IFLAG1,ATEMP,ITEMP,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
!
!     NOTE--THIS SUBROUTINE IS A UTILITY ROUTINE FOR DPMATC AND
!           DPMAT2.  IT CHECKS A VARIABLE ON THE RIGHT HAND SIDE
!           OF THE EQUAL SIGN.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/6
!     ORIGINAL VERSION--JUNE      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASL7
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 ITYPA(MAXCAS)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      REAL TEMPS(MAXCAS)
!
      INTEGER ICOLR(MAXCAS)
      INTEGER ILISR(MAXCAS)
      INTEGER NIRIGH(MAXCAS)
      INTEGER ILOCR(MAXCAS)
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='T7  '
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT7')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAT7--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASL7,IBUGA3,ISUBRO
   52   FORMAT('ICASL7,IBUGA3,ISUBRO = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASE
   53   FORMAT('ICASE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)ILOCR(ICASE)
   54   FORMAT('ILOCR(ICASE) = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ICOLR(ICASE)
   55   FORMAT('ICOLR(ICASE) = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)ILISR(ICASE)
   56   FORMAT('ILISR(ICASE) = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************************
!               **  STEP 1--                         **
!               **  EXAMINE THE VARIABLE             **
!               **  ON THE RIGHT.                    **
!               ***************************************
!
      ISTEPN='1.0'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT7')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHRIGH=IHARG(ILOCR(ICASE))
      IHRIG2=IHARG2(ILOCR(ICASE))
      ATEMP=ARG(ILOCR(ICASE))
      ITEMP=IARG(ILOCR(ICASE))
      DO 1220 I=1,NUMNAM
        I2=I
        IF(IHRIGH.EQ.IHNAME(I).AND.   &
           IHRIG2.EQ.IHNAM2(I).AND.   &
           IUSE(I).EQ.'V')GO TO 1270
        IF(IHRIGH.EQ.IHNAME(I).AND.   &
           IHRIG2.EQ.IHNAM2(I).AND.   &
           IUSE(I).EQ.'M')GO TO 1280
        IF(IHRIGH.EQ.IHNAME(I).AND.   &
           IHRIG2.EQ.IHNAM2(I).AND.   &
           IUSE(I).EQ.'P')GO TO 1240
 1220 CONTINUE
!
      IF(IFLAG1.EQ.1)GO TO 1250
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1221)
 1221 FORMAT('***** ERROR 1221 IN DPMAT7--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1222)ICASE
 1222 FORMAT('      THE SPECIFIED ARGUMENT ',I3)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1223)
 1223 FORMAT('      (VARIABLE NAME OR COLUMN NUMBER)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1224)
 1224 FORMAT('      ON THE RIGHT OF THE = SIGN')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1225)
 1225 FORMAT('      WAS NOT FOUND IN THE INTERNAL NAME LIST')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1226)
 1226 FORMAT('      OF AVAILABLE VARIABLE NAMES.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1227)IHRIGH,IHRIG2
 1227 FORMAT('      THE VARIABLE IN QUESTION WAS ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1228)
 1228 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,1229)(IANS(I),I=1,MIN(100,IWIDTH))
 1229   FORMAT(100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 19000
!
 1240 CONTINUE
      IF(IFLAG1.EQ.1)GO TO 1260
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1241)
 1241 FORMAT('***** ERROR 1241 IN DPMAT7--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1242)ICASE
 1242 FORMAT('      THE SPECIFIED ARGUMENT ',I4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1243)
 1243 FORMAT('      (VARIABLE NAME OR COLUMN NUMBER)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1244)
 1244 FORMAT('      ON THE RIGHT OF THE = SIGN')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1245)
 1245 FORMAT('      WAS FOUND IN THE INTERNAL NAME LIST,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1246)
 1246 FORMAT('      BUT AS A PARAMETER,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1247)
 1247 FORMAT('      AND NOT AS A VARIABLE AS IT SHOULD BE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1248)
 1248 FORMAT('      THE COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1249)(IANS(I),I=1,MIN(100,IWIDTH))
 1249 FORMAT(100A1)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 19000
!
 1250 CONTINUE
      ITYPA(ICASE)='PARA'
      TEMPS(ICASE)=ARG(ILOCR(ICASE))
      NIRIGH(ICASE)=1
      GO TO 1290
!
 1260 CONTINUE
      ITYPA(ICASE)='PARA'
      ILISR(ICASE)=I2
      TEMPS(ICASE)=VALUE(ILISR(ICASE))
      NIRIGH(ICASE)=1
      GO TO 1290
!
 1270 CONTINUE
      ITYPA(ICASE)='VARI'
      ILISR(ICASE)=I2
      ICOLR(ICASE)=IVALUE(ILISR(ICASE))
      NIRIGH(ICASE)=IN(ILISR(ICASE))
      GO TO 1290
!
 1280 CONTINUE
      ITYPA(ICASE)='MATR'
      ILISR(ICASE)=I2
      ICOLR(ICASE)=IVALUE(ILISR(ICASE))
      NIRIGH(ICASE)=IN(ILISR(ICASE))
      GO TO 1290
!
 1290 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
19000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT7')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19011)
19011   FORMAT('***** AT THE END       OF DPMAT7--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19012)IFOUND,IERROR
19012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19013)IBUGA3,ISUBRO
19013   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19021)IHRIGH,IHRIG2,   &
                          ILISR(ICASE),NIRIGH(ICASE)
19021   FORMAT('IHRIGH,IHRIG2,ILISR(ICASE),',   &
               'NIRIGH(ICASE) = ',A4,2X,A4,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19023)ITYPA(ICASE),ICOLR(ICASE)
19023   FORMAT('ITYPA(ICASE),ICOLR(ICASE) = ',A4,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19025)TEMPS(ICASE),NIRIGH(ICASE)
19025   FORMAT('TEMPS(ICASE),NIRIGH(ICASE) = ',E15.7,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAT7
      SUBROUTINE DPMAT8(IVARN1,IVARN2,NUMVAR,   &
                        ICOLR,ILISR,NIRIGH,ITYPA,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     NOTE--EXTRACT INFO FROM LIST OF VARIABLES
!     NOTE--THIS SUBROUTINE IS A UTILITY ROUTINE FOR DPMAT2 AND
!           SPECIFICALLY FOR THE CREATE MATRIX COMMAND.  THIS COMMAND
!           CAN HANDLE A POTENTIALLY LARGE NUMBER OF VARIABLES.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/05
!     ORIGINAL VERSION--MAY       2023
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IVARN1(*)
      CHARACTER*4 IVARN2(*)
      CHARACTER*4 ITYPA(*)
!
      INTEGER ICOLR(*)
      INTEGER ILISR(*)
      INTEGER NIRIGH(*)
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMA'
      ISUBN2='T8  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT8')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMAT8--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NUMVAR
   52   FORMAT('IBUGA3,ISUBRO,NUMVAR = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,NUMVAR
          WRITE(ICOUT,62)I,IVARN1(I),IVARN2(I)
   62     FORMAT('I,IVARN1(I),IVARN2(I) = ',I8,2(2X,A4))
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!               ***************************************
!               **  STEP 1--                         **
!               **  EXTRACT INFO FOR THE VARIABLES   **
!               **  IN THE LIST.                     **
!               ***************************************
!
      ISTEPN='1.0'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1053 JJ=1,NUMVAR
        write(18,*)'jj,ivarn1(jj),ivarn2(jj) = ',   &
                    jj,ivarn1(jj),ivarn2(jj)
        DO 1054 KK=1,NUMNAM
          IF(IVARN1(JJ).EQ.IHNAME(KK) .AND.   &
             IVARN2(JJ).EQ.IHNAM2(KK))THEN
             ILISR(JJ)=KK
             ICOLR(JJ)=IVALUE(ILISR(JJ))
             NIRIGH(JJ)=IN(ILISR(JJ))
             ITYPA(JJ)='VARI'
             write(18,*)'ilisr(jj),icolr(jj),nirigh(jj),itypa(jj)=',   &
                         ilisr(jj),icolr(jj),nirigh(jj),itypa(jj)
             GO TO 1053
          ENDIF
 1054   CONTINUE
!
        WRITE(ICOUT,1070)
 1070   FORMAT('****** ERROR IN CREATE MATRIX (DPMAT8)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1071)IVARN1(JJ),IVARN2(JJ)
 1071   FORMAT('      VARIABLE ',2A4,' NOT FOUND IN INTERNAL ',  &
               'NAME TABLE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
!
 1053 CONTINUE
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MAT8')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,19011)
19011   FORMAT('***** AT THE END       OF DPMAT8--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NUMVAR
          WRITE(ICOUT,9021)I,ILISR(I),ICOLR(I),NIRIGH(I),ITYPA(I)
 9021     FORMAT('I,ILISR(I),ICOLR(I),NIRIGH(I),ITYPA(I) = ',   &
                 4I8,2X,A4)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPMAT8
      SUBROUTINE DPMATH(ICHARC,IOP,X,Y,NUMCO,IXMINS,IXMAXS,IXDELS,   &
                        IBUGD2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE AND SET THE HERSHEY CHARACTER SET COORDINATES
!              FOR MATH SYMBOLS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/4
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MARCH     1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1987.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICHARC
      CHARACTER*4 IOP
      CHARACTER*4 IBUGD2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IOP(*)
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      NUMCO=1
      ISTART=1
      ISTOP=1
      NC=1
!
!               ******************************************
!               **  TREAT THE ROMAN SIMPLEX UPPER CASE  **
!               **  HERSHEY CHARACTER SET CASE          **
!               ******************************************
!
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'MATH')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMATH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ICHARC
   52 FORMAT('ICHARC = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,59)IBUGG4,ISUBG4,IFOUND,IERROR
   59 FORMAT('IBUGG4,ISUBG4,IFOUND,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************************************
!               **  STEP 1--                                    **
!               **  SEARCH FOR THE INPUT CHARACTER(S).          **
!               **  MAP THE CHARACTER(S) INTO A NUMERIC VALUE.  **
!               **************************************************
!
      CALL DPCHMA(ICHARC,ICHARN,IBUGD2,IFOUND)
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      IF(ICHARN.LE.32)GO TO 1010
      GO TO 1019
 1010 CONTINUE
      CALL DMATH1(ICHARN,IOP,X,Y,NUMCO,IXMINS,IXMAXS,IXDELS,   &
      IBUGD2,IFOUND,IERROR)
      GO TO 9000
 1019 CONTINUE
!
      IF(33.LE.ICHARN.AND.ICHARN.LE.51)GO TO 1020
      GO TO 1029
 1020 CONTINUE
      CALL DMATH2(ICHARN,IOP,X,Y,NUMCO,IXMINS,IXMAXS,IXDELS,   &
      IBUGD2,IFOUND,IERROR)
      GO TO 9000
 1029 CONTINUE
!
      IF(52.LE.ICHARN.AND.ICHARN.LE.60)GO TO 1030
      GO TO 1039
 1030 CONTINUE
      CALL DMATH3(ICHARN,IOP,X,Y,NUMCO,IXMINS,IXMAXS,IXDELS,   &
      IBUGD2,IFOUND,IERROR)
      GO TO 9000
 1039 CONTINUE
!
      IF(ICHARN.GE.61)GO TO 1040
      GO TO 1049
 1040 CONTINUE
      CALL DMATH4(ICHARN,IOP,X,Y,NUMCO,IXMINS,IXMAXS,IXDELS,   &
      IBUGD2,IFOUND,IERROR)
      GO TO 9000
 1049 CONTINUE
!
      IFOUND='NO'
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'MATH')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMATH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IFOUND,IERROR
 9012 FORMAT('IBUGG4,ISUBG4,IFOUND,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)ICHARC,ICHARN
 9013 FORMAT('ICHARC,ICHARN = ',A4,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)ISTART,ISTOP,NC,NUMCO
 9014 FORMAT('ISTART,ISTOP,NC,NUMCO = ',4I8)
      CALL DPWRST('XXX','BUG ')
      IF(NUMCO.GE.1.AND.NUMCO.LE.1000)GO TO 9019
      DO 9015 I=1,NUMCO
      WRITE(ICOUT,9016)I,IOP(I),X(I),Y(I)
 9016 FORMAT('I,IOP(I),X(I),Y(I) = ',I8,2X,A4,2F10.2)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9019 CONTINUE
      WRITE(ICOUT,9021)IXMINS,IXMAXS,IXDELS
 9021 FORMAT('IXMINS,IXMAXS,IXDELS = ',3I8)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMATH
      SUBROUTINE DPMATN(ICOM,IHARG,IARGT,IARG,NUMARG,   &
                        IX1JSW,IX2JSW,IY1JSW,IY2JSW,   &
                        NMJX1T,NMJX2T,NMJY1T,NMJY2T,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE NUMBER OF MAJOR TIC MARKS
!              FOR HORIZONTAL FRAME LINES OR VERTICAL FRAME LINES OR BOTH.
!     INPUT  ARGUMENTS--ICOM  (A  CHARACTER VECTOR)
!                     --IHARG  (A  CHARACTER VECTOR)
!                     --IARG   (AN INTEGER VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--
!                     --IX1JSW (A CHARACTER VARIABLE)
!                     --IX2JSW (A CHARACTER VARIABLE)
!                     --IY1JSW (A CHARACTER VARIABLE)
!                     --IY2JSW (A CHARACTER VARIABLE)
!                     --NMJX1T (AN INTEGER VARIABLE)
!                     --NMJX2T (AN INTEGER VARIABLE)
!                     --NMJY1T (AN INTEGER VARIABLE)
!                     --NMJY2T (AN INTEGER VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1982.
!     UPDATED--JANUARY  1988. (OPTIONAL OMISSION OF THE WORD   MAJOR)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IX1JSW
      CHARACTER*4 IX2JSW
      CHARACTER*4 IY1JSW
      CHARACTER*4 IY2JSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(ICOM.NE.'MAJO')GO TO 1010
      GO TO 1019
 1010 CONTINUE
      IF(ICOM.EQ.'XTIC')GO TO 1100
      IF(ICOM.EQ.'X1TI')GO TO 1200
      IF(ICOM.EQ.'X2TI')GO TO 1300
      IF(ICOM.EQ.'YTIC')GO TO 1400
      IF(ICOM.EQ.'Y1TI')GO TO 1500
      IF(ICOM.EQ.'Y2TI')GO TO 1600
      IF(ICOM.EQ.'TIC')GO TO 1700
      IF(ICOM.EQ.'TICS')GO TO 1700
      GO TO 9000
 1019 CONTINUE
!
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.1)GO TO 1020
      GO TO 1029
 1020 CONTINUE
      IF(IHARG(1).EQ.'XTIC')GO TO 1100
      IF(IHARG(1).EQ.'X1TI')GO TO 1200
      IF(IHARG(1).EQ.'X2TI')GO TO 1300
      IF(IHARG(1).EQ.'YTIC')GO TO 1400
      IF(IHARG(1).EQ.'Y1TI')GO TO 1500
      IF(IHARG(1).EQ.'Y2TI')GO TO 1600
      IF(IHARG(1).EQ.'TIC')GO TO 1700
      IF(IHARG(1).EQ.'TICS')GO TO 1700
      GO TO 9000
 1029 CONTINUE
      GO TO 9000
!
!               ********************************************************
!               **  STEP 1--
!               **  TREAT THE CASE WHEN
!               **  ONLY THE HORIZONTAL MAJOR TICS ARE TO BE CHANGED
!               ********************************************************
!
 1100 CONTINUE
      IF(ICOM.NE.'MAJO'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'NUMB')GO TO 1110
      IF(ICOM.NE.'MAJO'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1110
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1110
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.3.AND.IHARG(3).EQ.'NUMB')GO TO 1110
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1101)
 1101 FORMAT('***** ERROR IN DPMATN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1102)
 1102 FORMAT('      IMPROPER FORM FOR SPECIFYING THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1103)
 1103 FORMAT('      NUMBER OF MAJOR (HORIZONTAL) TIC MARKS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1104)
 1104 FORMAT('      EXAMPLE TO SPECIFY 3 MAJOR TIC MARKS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1105)
 1105 FORMAT('      (ON THE HORIZONTAL FRAME LINES)--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1106)
 1106 FORMAT('      MAJOR XTIC MARK NUMBER 3')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1107)
 1107 FORMAT('      MAJOR XTICS NUMBER 3')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1110 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'NUMB')GO TO 1150
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1160
      IERROR='YES'
      GO TO 9000
!
 1150 CONTINUE
      IHHOLD='FLOA'
      IHOLD=(-1)
      GO TO 1180
!
 1160 CONTINUE
      IHHOLD='FIXE'
      IHOLD=IARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      IX1JSW=IHHOLD
      IX2JSW=IHHOLD
      NMJX1T=IHOLD
      NMJX2T=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE NUMBER OF MAJOR TIC MARKS ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)
 1182 FORMAT('(FOR BOTH HORIZONTAL FRAME LINES')
      CALL DPWRST('XXX','BUG ')
      IF(IHHOLD.EQ.'FIXE')WRITE(ICOUT,1183)IHOLD
 1183 FORMAT('HAS JUST BEEN SET TO ',I8)
      IF(IHHOLD.EQ.'FIXE')CALL DPWRST('XXX','BUG ')
      IF(IHHOLD.EQ.'FLOA')WRITE(ICOUT,1184)
 1184 FORMAT('HAS JUST BEEN SET TO AUTOMATIC.')
      IF(IHHOLD.EQ.'FLOA')CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
!               ********************************************************
!               **  STEP 2--
!               **  TREAT THE CASE WHEN
!               **  ONLY THE BOTTOM HORIZONTAL MAJOR TICS ARE TO BE CHANGED
!               ********************************************************
!
 1200 CONTINUE
      IF(ICOM.NE.'MAJO'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'NUMB')GO TO 1210
      IF(ICOM.NE.'MAJO'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1210
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1210
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.3.AND.IHARG(3).EQ.'NUMB')GO TO 1210
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1201)
 1201 FORMAT('***** ERROR IN DPMATN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1202)
 1202 FORMAT('      IMPROPER FORM FOR SPECIFYING THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1203)
 1203 FORMAT('      NUMBER OF MAJOR (HORIZONTAL) TIC MARKS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1204)
 1204 FORMAT('      EXAMPLE TO SPECIFY 3 MAJOR TIC MARKS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1205)
 1205 FORMAT('      (ON THE BOTTOM HORIZONTAL FRAME LINES)--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1206)
 1206 FORMAT('      MAJOR X1TIC MARK NUMBER 3')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1207)
 1207 FORMAT('      MAJOR X1TICS NUMBER 3')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1210 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1250
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1250
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1250
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1250
      IF(IHARG(NUMARG).EQ.'NUMB')GO TO 1250
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1260
      IERROR='YES'
      GO TO 9000
!
 1250 CONTINUE
      IHHOLD='FLOA'
      IHOLD=(-1)
      GO TO 1280
!
 1260 CONTINUE
      IHHOLD='FIXE'
      IHOLD=IARG(NUMARG)
      GO TO 1280
!
 1280 CONTINUE
      IFOUND='YES'
      IX1JSW=IHHOLD
      NMJX1T=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1281)
 1281 FORMAT('THE NUMBER OF MAJOR TIC MARKS ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1282)
 1282 FORMAT('(FOR THE BOTTOM HORIZONTAL FRAME LINE')
      CALL DPWRST('XXX','BUG ')
      IF(IHHOLD.EQ.'FIXE')WRITE(ICOUT,1283)IHOLD
 1283 FORMAT('HAS JUST BEEN SET TO ',I8)
      IF(IHHOLD.EQ.'FIXE')CALL DPWRST('XXX','BUG ')
      IF(IHHOLD.EQ.'FLOA')WRITE(ICOUT,1284)
 1284 FORMAT('HAS JUST BEEN SET TO AUTOMATIC.')
      IF(IHHOLD.EQ.'FLOA')CALL DPWRST('XXX','BUG ')
 1289 CONTINUE
      GO TO 9000
!
!               ********************************************************
!               **  STEP 3--
!               **  TREAT THE CASE WHEN
!               **  ONLY THE TOP    HORIZONTAL MAJOR TICS ARE TO BE CHANGED
!               ********************************************************
!
 1300 CONTINUE
      IF(ICOM.NE.'MAJO'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'NUMB')GO TO 1310
      IF(ICOM.NE.'MAJO'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1310
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1310
      IF(ICOM.EQ.'MAJO'.AND.NUMARG.GE.3.AND.IHARG(3).EQ.'NUMB')GO TO 1310
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1301)
 1301 FORMAT('***** ERROR IN DPMATN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1302)
 1302 FORMAT('      IMPROPER FORM FOR SPECIFYING THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1303)
 1303 FORMAT('      NUMBER OF MAJOR (HORIZONTAL) TIC MARKS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1304)
 1304 FORMAT('      EXAMPLE TO SPECIFY 3 MAJOR TIC MARKS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1305)
 1305 FORMAT('      (ON THE TOP HORIZONTAL FRAME LINES)--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1306)
 1306 FORMAT('      MAJOR X2TIC MARK NUMBER 3')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1307)
 1307 FORMAT('      MAJOR X2TICS NUMBER 3')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1310 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1350
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1350
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1350
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1350
      IF(IHARG(NUMARG).EQ.'NUMB')GO TO 1350
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1360
      IERROR='YES'
      GO TO 9000
!
 1350 CONTINUE
      IHHOLD='FLOA'
      IHOLD=(-1)
      GO TO 1380
