      SUBROUTINE DPMAX(ICOM,IHARG,IARGT,ARG,NUMARG,   &
                       GX1MAX,GY1MAX,GX2MAX,GY2MAX,   &
                       IX1MAX,IY1MAX,IX2MAX,IY2MAX,   &
                       IFOUND,IERROR)
!
!     PURPOSE--DEFINE AXIS MAXIMA
!              (HORIZONTAL AXIS OR VERTICAL AXIS OR BOTH)
!              WHICH IN TURN WILL DEFINE THE UPPER EXTREME
!              WHICH WILL APPEAR ON THE PLOT.
!              THE MAXIMA WILL BE PLACED IN THE 4 VARIABLES
!              GX1MAX,GY1MAX,
!              GX2MAX,GY2MAX,
!              THE STATUS (FIXED OR FLOAT) WILL BE PLACED
!              IN THE 4 VARIABLES
!              IX1MAX,IY1MAX,
!              IX2MAX,IY2MAX,
!     INPUT  ARGUMENTS--ICOM  (A  HOLLERITH VARIABLE)
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--
!                     --GX1MAX = MAXIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --GY1MAX = MAXIMUM FOR LEFT   VERTICAL   AXIS
!                     --GX2MAX = MAXIMUM FOR TOP    HORIZONTAL AXIS
!                     --GX2MAX = MAXIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IX1MAX = STATUS FOR MAXIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --IY1MAX = STATUS FOR MAXIMUM FOR LEFT   VERTICAL   AXIS
!                     --IX2MAX = STATUS FOR MAXIMUM FOR TOP    HORIZONTAL AXIS
!                     --IX2MAX = STATUS FOR MAXIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
