 1417 FORMAT('SO THAT IT WILL FLOAT WITH THE PLOTTED DATA')
      CALL DPWRST('XXX','BUG ')
 1419 CONTINUE
      GO TO 9000
!
 1420 CONTINUE
      IFOUND='YES'
      A1=ARG(1)
      GY1MAX=A1
      GY2MAX=A1
      IY1MAX='FIXE'
      IY2MAX='FIXE'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1429
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1425)
 1425 FORMAT('THE Y AXIS MAXIMUM (FOR BOTH VERTICAL')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1426)GY1MAX
 1426 FORMAT('FRAME LINES) HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1429 CONTINUE
      GO TO 9000
!
 1499 CONTINUE
!
!               *****************************************************
!               **  TREAT THE CASE WHEN THE                        **
!               **  LEFT   VERTICAL   AXIS MAXIMUM ARE TO BE FIXED  **
!               *****************************************************
!
      IF(ICOM.EQ.'Y1MA')GO TO 1500
      GO TO 1599
!
 1500 CONTINUE
      IF(NUMARG.LE.0)GO TO 1510
      IF(IARGT(1).EQ.'NUMB')GO TO 1520
      GO TO 1510
!
 1510 CONTINUE
      IFOUND='YES'
      GY1MAX=CPUMAX
      IY1MAX='FLOA'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1519
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1515)
 1515 FORMAT('THE Y AXIS MAXIMUM (FOR THE LEFT   VERTICAL  ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1516)
 1516 FORMAT('FRAME LINE) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1517)
 1517 FORMAT('SO THAT IT WILL FLOAT WITH THE PLOTTED DATA')
      CALL DPWRST('XXX','BUG ')
 1519 CONTINUE
      GO TO 9000
!
 1520 CONTINUE
      IFOUND='YES'
      A1=ARG(1)
      GY1MAX=A1
      IY1MAX='FIXE'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1529
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1525)
 1525 FORMAT('THE Y AXIS MAXIMUM (FOR THE LEFT   VERTICAL  ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1526)GY1MAX
 1526 FORMAT('FRAME LINE) HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1529 CONTINUE
      GO TO 9000
!
 1599 CONTINUE
!
!               *****************************************************
!               **  TREAT THE CASE WHEN THE                        **
!               **  RIGHT  VERTICAL   AXIS MAXIMUM ARE TO BE FIXED  **
!               *****************************************************
!
      IF(ICOM.EQ.'Y2MA')GO TO 1600
      GO TO 1699
!
 1600 CONTINUE
      IF(NUMARG.LE.0)GO TO 1610
      IF(IARGT(1).EQ.'NUMB')GO TO 1620
      GO TO 1610
!
 1610 CONTINUE
      IFOUND='YES'
      GY2MAX=CPUMAX
      IY2MAX='FLOA'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1619
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1615)
 1615 FORMAT('THE Y AXIS MAXIMUM (FOR THE RIGHT  VERTICAL  ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1616)
 1616 FORMAT('FRAME LINE) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1617)
 1617 FORMAT('SO THAT IT WILL FLOAT WITH THE PLOTTED DATA')
      CALL DPWRST('XXX','BUG ')
 1619 CONTINUE
      GO TO 9000
!
 1620 CONTINUE
      IFOUND='YES'
      A1=ARG(1)
      GY2MAX=A1
      IY2MAX='FIXE'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1629
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1625)
 1625 FORMAT('THE Y AXIS MAXIMUM (FOR THE RIGHT  VERTICAL  ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1626)GY2MAX
 1626 FORMAT('FRAME LINE) HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1629 CONTINUE
      GO TO 9000
!
 1699 CONTINUE
!
!               ******************************************
!               **  TREAT THE CASE WHEN                 **
!               **  BOTH AXIS MAXIMUM ARE TO BE FIXED    **
!               ******************************************
!
!
      IF(ICOM.EQ.'XYMA')GO TO 1700
      IF(ICOM.EQ.'YXMA')GO TO 1700
      IF(ICOM.EQ.'MAXI')GO TO 1700
      IF(ICOM.EQ.'MAX ')GO TO 1700
      GO TO 1799
!
 1700 CONTINUE
      IF(NUMARG.LE.0)GO TO 1710
      IF(IARGT(1).EQ.'NUMB')GO TO 1720
      GO TO 1710
!
 1710 CONTINUE
      IFOUND='YES'
      GX1MAX=CPUMAX
      GY1MAX=CPUMAX
      GX2MAX=CPUMAX
      GY2MAX=CPUMAX
      IX1MAX='FLOA'
      IY1MAX='FLOA'
      IX2MAX='FLOA'
      IY2MAX='FLOA'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1719
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1715)
 1715 FORMAT('THE X AXIS MAXIMUM (FOR ALL 4')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1716)
 1716 FORMAT('FRAME LINES) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1717)
 1717 FORMAT('SO THAT IT WILL FLOAT WITH THE PLOTTED DATA')
      CALL DPWRST('XXX','BUG ')
 1719 CONTINUE
      GO TO 9000
!
 1720 CONTINUE
      IFOUND='YES'
      A1=ARG(1)
      GX1MAX=A1
      GY1MAX=A1
      GX2MAX=A1
      GY2MAX=A1
      IX1MAX='FIXE'
      IY1MAX='FIXE'
      IX2MAX='FIXE'
      IY2MAX='FIXE'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1729
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1725)
 1725 FORMAT('THE AXIS MAXIMUM (FOR ALL 4')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1726)GX1MAX
 1726 FORMAT('FRAME LINES) HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1729 CONTINUE
      GO TO 9000
!
 1799 CONTINUE
      GO TO 9000
!
!               ********************************************
!               **  STEP 81--                             **
!               **  TREAT THE    ?    CASE--              **
!               **  DUMP OUT CURRENT AND DEFAULT VALUES.  **
!               ********************************************
!
 8100 CONTINUE
      IFOUND='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8111)
 8111 FORMAT('THE CURRENT AXIS MAXIMA ARE ')
      CALL DPWRST('XXX','BUG ')
      IF(IX1MAX.NE.'FLOA')WRITE(ICOUT,8112)GX1MAX
 8112 FORMAT('            --X1 (BOTTOM HORIZONTAL) = ',E15.7)
      IF(IX1MAX.NE.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IX1MAX.EQ.'FLOA')WRITE(ICOUT,8113)
 8113 FORMAT('            --X1 (BOTTOM HORIZONTAL) = FLOAT & NEAT')
      IF(IX1MAX.EQ.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IX2MAX.NE.'FLOA')WRITE(ICOUT,8114)GX2MAX
 8114 FORMAT('            --X2 (TOP    HORIZONTAL) = ',E15.7)
      IF(IX2MAX.NE.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IX2MAX.EQ.'FLOA')WRITE(ICOUT,8115)
 8115 FORMAT('            --X2 (TOP    HORIZONTAL) = FLOAT & NEAT')
      IF(IX2MAX.EQ.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IY1MAX.NE.'FLOA')WRITE(ICOUT,8116)GY1MAX
 8116 FORMAT('            --Y1 (LEFT   VERTICAL  ) = ',E15.7)
      IF(IY1MAX.NE.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IY1MAX.EQ.'FLOA')WRITE(ICOUT,8117)
 8117 FORMAT('            --Y1 (LEFT   VERTICAL  ) = FLOAT & NEAT')
      IF(IY1MAX.EQ.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IY2MAX.NE.'FLOA')WRITE(ICOUT,8118)GY2MAX
 8118 FORMAT('            --Y2 (RIGHT  VERTICAL  ) = ',E15.7)
      IF(IY2MAX.NE.'FLOA')CALL DPWRST('XXX','BUG ')
      IF(IY2MAX.EQ.'FLOA')WRITE(ICOUT,8119)
 8119 FORMAT('            --Y2 (RIGHT  VERTICAL  ) = FLOAT & NEAT')
      IF(IY2MAX.EQ.'FLOA')CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8121)
 8121 FORMAT('THE DEFAULT AXIS MAXIMA ARE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8122)
 8122 FORMAT('            --X1 (BOTTOM HORIZONTAL) = FLOAT & NEAT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8123)
 8123 FORMAT('            --X2 (TOP    HORIZONTAL) = FLOAT & NEAT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8124)
 8124 FORMAT('            --Y1 (LEFT   VERTICAL  ) = FLOAT & NEAT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8125)
 8125 FORMAT('            --Y2 (BOTTOM VERTICAL  ) = FLOAT & NEAT')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPMAX
      SUBROUTINE DPMB10(Y,N,   &
                        XTEMP,XTEMP2,XTEMP3,DTEMP1,MAXNXT,   &
                        SHAPSV,SCALSV,   &
                        SHAPML,SCALML,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE BURR TYPE 10 DISTRIBUTION.
!              THE MAXIMUM LIKELIHOOD ESTIMATES ARE THE SOLUTION TO
!              THE FOLLOWING SIMULTANEOUS NONLINEAR EQUATIONS:
!              EQUATIONS.
!
!              (N/R) + SUM[i=1 to N][LN(1 - EXP(-(S*X(i))**2) = 0
!
!              C(2*N/S) - 2*S*SUM[i=1 to n][X(i)**2 +
!              2*S*(R-1)*SUM[i=1 tp n][X(i)^2*EXP(-(S*X(i))**2)/
!              1 - EXP(-(S*X(i))**2)) = 0
!
!              WITH R AND S DENOTING THE SHAPE PARAMETER R AND
!              SCALE PARAMETER S RESPECTIVELY.
!
!     EXAMPLE--BURR TYPE 10 MAXIMUM LIKELIHOOD Y
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PP. 53-54.
!               --LUC DEVROYE, "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", 1986, SPRINGER-VERLANG, PP. 476-477.
!                 (NOTE: THERE IS A TYPO IN THE DEVROYE CDF EQUATION,
!                 CORRECT FORM TAKEN FROM JOHNSON AND KOTZ).
!               --KUNDU AND RAQAB, "GENERALIZED RAYLEIGH DISTRIBUTION:
!                 METHODS OF ESTIMATION", COMPUTATIONAL STATISTICS
!                 AND DATA ANALYSIS, 49, PP. 187-200.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/10
!     ORIGINAL VERSION--OCTOBER   2007.
!     UPDATED         --FEBRUARY  2010. EXTRACT POINT ESTIMATES TO
!                                       B10ML1 TO MAKE IT CALLABLE
!                                       FROM MULTIPLE ROUTINES
!     UPDATED         --FEBRUARY  2010. PRINT TABLES WITH DPDTA1
!     UPDATED         --APRIL     2011. ADD STANDARD ERRORS,
!                                       CONFIDENCE LIMITS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ILIKFL
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XTEMP(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION QP(1)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION DALPH
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DI11
      DOUBLE PRECISION DI12
      DOUBLE PRECISION DI22
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DALPSE
      DOUBLE PRECISION DLAMSE
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION DPSIAL
      DOUBLE PRECISION DPSIA2
      DOUBLE PRECISION DPSI1
      DOUBLE PRECISION DPSI2
      DOUBLE PRECISION DTRIAL
      DOUBLE PRECISION DTRI2
      DOUBLE PRECISION DANS(10)
!
      EXTERNAL DPSI
      EXTERNAL TRIGAM
!
      PARAMETER (NUMALP=6)
      DIMENSION ALPHA(NUMALP)
      DIMENSION ALOWSC(NUMALP)
      DIMENSION AUPPSC(NUMALP)
      DIMENSION ALOWGA(NUMALP)
      DIMENSION AUPPGA(NUMALP)
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=30)
      PARAMETER(NUMCLI=3)
      PARAMETER(MAXLIN=2)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*40 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ALPHA /0.50, 0.25, 0.10, 0.05, 0.01, 0.001/
!
      ISUBN1='DPMB'
      ISUBN2='10  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MB10')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMB10--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR BURR TYPE 10 MLE ESTIMATION       **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MB10')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NMIN=3
      NPERC=0
      CALL CKDIST(Y,N,NMIN,QP,NPERC,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CALL B10ML1(Y,N,MAXNXT,   &
                  XTEMP,XTEMP2,XTEMP3,DTEMP1,   &
                  XMEAN,XSD,XVAR,XMIN,XMAX,   &
                  SCALSV,SHAPSV,SCALML,SHAPML,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ICASPL='BU10'
      ALOC=0.0
      CALL B10LI1(Y,N,ICASPL,ALOC,SCALML,SHAPML,   &
                  ALIK,AIC,AICC,BIC,   &
                  ISUBRO,IBUGA3,IERROR)
!
!     APRIL 2011: COMPUTE STANDARD ERRORS BASED ON FORMULAS IN
!                 KUNDU AND RAQAB ARTICLE.
!
!                 IN SOME CASES, I AM GETTING NEGATIVE VALUES FOR
!                 THE STANDARD ERRORS.  SO ONLY PRINT STANDARD
!                 ERRORS AND CONFIDENCE INTERVALS IF OBTAIN
!                 POSITIVE VALUES FOR BOTH.  EVEN WHEN BOTH
!                 ARE POSITIVE, THE STANDARD ERRORS DO NOT SEEM
!                 CREDIBLE.  SO FOR NOW, BYPASS THIS CODE.  LEAVE
!                 IN SO WE CAN RE-ACTIVATE IF WE FIND A CORRECTION
!                 FOR THE FORMULAS.
!
      IFLGSE=0
      GO TO 199
!
      DALPH=DBLE(SHAPML)
      DLAMB=DBLE(1.0/SCALML)
      DPSIAL=DPSI(DALPH)
      DPSIA2=DPSI(DALPH+1.0D0)
      DPSI1=DPSI(1.0D0)
      DPSI2=DPSI(2.0D0)
!
      KODE=1
      NTEMP=1
      M=1
      NZ=0
      CALL DPSIFN(DALPH,NTEMP,KODE,M,DANS,NZ,IERR)
      DTRIAL=DANS(1)
      DTERM1=2.0D0
      CALL DPSIFN(DTERM1,NTEMP,KODE,M,DANS,NZ,IERR)
      DTRI2=DANS(1)
!
      DI11=-1.0D0/DALPH**2
!
      DTERM1=2.0D0/((DALPH-1.0D0)*DLAMB**2)
      DI12=DTERM1*(DPSIAL - DPSI1 - (DALPH-1.0D0)/DALPH)
!
      DTERM1=-2.0D0/DLAMB**2
      DTERM2=DTERM1*(DPSIA2 - DPSI1)
      DTERM3=(-2.0D0*DALPH/DLAMB**3)*(DPSI1 - DPSIAL)
      DTERM4=-2.0D0*(DALPH-1.0D0)/DLAMB**3
      DTERM5=(-4.0D0*DALPH/(DLAMB**3*(DALPH-2.0D0)))*   &
             ((DPSI2 - DPSIAL)**2 + DTRI2 - DTRIAL)
      DI22=DTERM1 + DTERM2 + DTERM3 + DTERM4 + DTERM5
!
      IFLGSE=1
      DALPSE=DBLE(CPUMIN)
      DLAMSE=DBLE(CPUMIN)
      DTERM1=DI22/(D11*DI22 - DI12**2)
      IF(DTERM1.GE.0.0D0)THEN
        DALPSE=DSQRT(DTERM1)
      ELSE
        IFLGSE=0
      ENDIF
      DTERM1=DI11/(DI11*DI22 - DI12**2)
      IF(DTERM1.GE.0.0D0)THEN
        DLAMSE=DSQRT(DTERM1)
      ELSE
        IFLGSE=0
      ENDIF
!
!     CONFIDENCE INTERVALS FOR PARAMETERS BASED ON NORMAL APPROXIMATION
!
  199 CONTINUE
!
      IF(IFLGSE.EQ.1)THEN
        DO 110 I=1,NUMALP
          ALP=ALPHA(I)
          P=1.0-(ALP/2.0)
          CALL NORPPF(P,PPF)
          ALOWSC(I)=SCALML - PPF*REAL(DLAMSE)
          AUPPSC(I)=SCALML + PPF*REAL(DLAMSE)
          ALOWGA(I)=SHAPML - PPF*REAL(DALPSE)
          AUPPGA(I)=SHAPML + PPF*REAL(DALPSE)
  110   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MB10')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)DALPH,DLAMB,DPSIAL,DPSIA2
  101   FORMAT('DALPH,DLAMB,DPSIAL,DPSIA2 =',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)DPSI1,DPSI2,DTRIAL,DTRI2
  102   FORMAT('DPSI1,DPSI2,DTRIAL,DTRI2 =',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)DI11,DI12,DI22,DALPSE,DLAMSE
  103   FORMAT('DI11,DI12,DI22,DALPSE,DLAMSE = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ***********************************************
!               **   STEP 42--                               **
!               **   WRITE OUT EVERYTHING                    **
!               **   FOR BURR TYPE 10 MLE                    **
!               **   ESTIMATION                              **
!               ***********************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MB10')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT SUMMARY STATISTICS TABLE
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Two-Parameter Burr Type 10 Parameter Estimation:'
      NCTITL=48
      ITITLZ='Full Sample Case'
      NCTITZ=16
      ITEXT(1)='Summary Statistics:'
      NCTEXT(1)=19
      AVALUE(1)=0.0
      IDIGIT(1)=0
      ITEXT(2)='Number of Observations:'
      NCTEXT(2)=23
      AVALUE(2)=REAL(N)
      IDIGIT(2)=0
      ITEXT(3)='Sample Mean:'
      NCTEXT(3)=12
      AVALUE(3)=XMEAN
      IDIGIT(3)=NUMDIG
      ITEXT(4)='Sample Standard Deviation:'
      NCTEXT(4)=26
      AVALUE(4)=XSD
      IDIGIT(4)=NUMDIG
      ITEXT(5)='Sample Minimum:'
      NCTEXT(5)=15
      AVALUE(5)=XMIN
      IDIGIT(5)=NUMDIG
      ITEXT(6)='Sample Maximum:'
      NCTEXT(6)=15
      AVALUE(6)=XMAX
      IDIGIT(6)=NUMDIG
      NUMROW=6
      NTOT(1:NUMROW)=15
      NTOT(2)=8
!
      IFRST=.TRUE.
      ILAST=.FALSE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                  NCTEXT,AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      IFRST=.FALSE.
      ITITLE=' '
      NCTITL=0
!
      ITEXT(1)='Maximum Likelihood:'
      NCTEXT(1)=19
      AVALUE(1)=0.0
      IDIGIT(1)=-1
      ITEXT(2)='Estimate of Shape (R):'
      NCTEXT(2)=22
      AVALUE(2)=SHAPML
      IDIGIT(2)=NUMDIG
      ITEXT(3)='Estimate of Scale:'
      NCTEXT(3)=18
      AVALUE(3)=SCALML
      IDIGIT(3)=NUMDIG
      ICNT=3
!
      IF(IFLGSE.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Standard Error of Shape (R):'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=REAL(DALPSE)
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Standard Error of Scale:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=REAL(DLAMSE)
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Log-likelihood:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=ALIK
      IDIGIT(ICNT)=-7
      ICNT=ICNT+1
      ITEXT(ICNT)='AIC:'
      NCTEXT(ICNT)=4
      AVALUE(ICNT)=AIC
      IDIGIT(ICNT)=-7
      ICNT=ICNT+1
      ITEXT(ICNT)='AICc:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=AICC
      IDIGIT(ICNT)=-7
      ICNT=ICNT+1
      ITEXT(ICNT)='BIC:'
      NCTEXT(ICNT)=4
      AVALUE(ICNT)=BIC
      IDIGIT(ICNT)=-7
!
      NUMROW=ICNT
      NTOT(1:NUMROW)=15
!CCCC DO2320I=1,NUMROW
!CCCC   NTOT(I)=15
!2320 CONTINUE
!
      IFRST=.FALSE.
      ILAST=.FALSE.
      ITITLZ=' '
      NCTITZ=0
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IFLGSE.EQ.1)THEN
        ILIKFL='OFF'
        CALL DPDTA8(ALOWSC,AUPPSC,ALOWSC,AUPPSC,   &
                    ALOWGA,AUPPGA,ALOWGA,AUPPGA,ALPHA,NUMALP,   &
                    ICAPSW,ICAPTY,NUMDIG,ILIKFL,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MB10')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMB10--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)N
 9015   FORMAT('N = ',I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMB10
      SUBROUTINE DPMBCO(IHARG,NUMARG,IDEMBC,MAXMAR,IMABCO,   &
                        IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MARKER BORDER COLORS = THE COLORS
!              OF THE BORDER LINE AROUND THE MARKERS.
!              THESE ARE LOCATED IN THE VECTOR IMABCO(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEMBC
!                     --MAXMAR
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--IMABCO (A CHARACTER VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEMBC
      CHARACTER*4 IMABCO
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
      CHARACTER*4 IHOLD2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
      DIMENSION IMABCO(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPMB'
      ISUBN2='CO  '
!
      NUMMAR=0
      IHOLD1='-999'
      IHOLD2='-999'
!
      IF(IBUGP2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMBCO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR
   52 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXMAR,NUMMAR
   53 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IHOLD1,IHOLD2
   54 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)IDEMBC
   55 FORMAT('IDEMBC = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,60)NUMARG
   60 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,NUMARG
      WRITE(ICOUT,66)IHARG(I)
   66 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,70)IMABCO(1)
   70 FORMAT('IMABCO(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 75 I=1,10
      WRITE(ICOUT,76)I,IMABCO(I)
   76 FORMAT('I,IMABCO(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   75 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.1)GO TO 9000
      IF(NUMARG.EQ.2)GO TO 1120
      IF(NUMARG.EQ.3)GO TO 1130
      IF(NUMARG.EQ.4)GO TO 1140
      GO TO 1150
!
 1120 CONTINUE
      GO TO 1200
!
 1130 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1='    '
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1140 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1=IHARG(4)
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      IF(IHARG(4).EQ.'ALL')IHOLD1=IHARG(3)
      IF(IHARG(4).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1150 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE      SPECIFICATION  CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.2)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMMAR=1
      IMABCO(1)=IDEMBC
      GO TO 1270
!
 1220 CONTINUE
      NUMMAR=NUMARG-2
      IF(NUMMAR.GT.MAXMAR)NUMMAR=MAXMAR
      DO 1225 I=1,NUMMAR
      J=I+2
      IHOLD1=IHARG(J)
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2=IDEMBC
      IF(IHOLD1.EQ.'OFF')IHOLD2=IDEMBC
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMBC
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMBC
      IMABCO(I)=IHOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMMAR
      WRITE(ICOUT,1276)I,IMABCO(I)
 1276 FORMAT('THE COLOR OF MARKER BORDER ',I6,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMMAR=MAXMAR
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2=IDEMBC
      IF(IHOLD1.EQ.'OFF')IHOLD2=IDEMBC
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMBC
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMBC
      DO 1315 I=1,NUMMAR
      IMABCO(I)=IHOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)IMABCO(I)
 1316 FORMAT('THE COLOR OF ALL MARKER BORDERS',   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMBCO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGP2,IFOUND,IERROR
 9012 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)MAXMAR,NUMMAR
 9013 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IHOLD1,IHOLD2
 9014 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IDEMBC
 9015 FORMAT('IDEMBC = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9020)NUMARG
 9020 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9025 I=1,NUMARG
      WRITE(ICOUT,9026)IHARG(I)
 9026 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
      WRITE(ICOUT,9030)IMABCO(1)
 9030 FORMAT('IMABCO(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 9035 I=1,10
      WRITE(ICOUT,9036)I,IMABCO(I)
 9036 FORMAT('I,IMABCO(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9035 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMBCO
      SUBROUTINE DPMBFW(Y,AL,N,   &
                        TEMP1,TEMP2,DTEMP1,MAXNXT,   &
                        SCALSV,SHAPSV,SCALML,SHAPML,   &
                        AIC,AICC,BIC,ALIKE,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER BRITTLE FIBER WEIBULL DISTRIBUTION
!              FOR THE FULL SAMPLE CASE.
!
!              NOTE THAT THIS INITIAL IMPLEMENTATION ONLY GENERATES
!              POINT ESTIMATES, NOT INTERVAL ESTIMATES.
!     EXAMPLE--BRITTLE FIBER WEIBULL MAXIMUM LIKELIHOOD Y
!     REFERENCES--STONER, EDIE, AND DURHAM (1994), "AN END-EFFECT MODEL
!                 FOR THE SINGLE-FILAMENT TENSILE TEST", JOURNAL OF
!                 OF MATERIALS SCIENCE, 29, PP. 6561-6574.
!               --NEWELL AND SAGENDORF (1999), "EXPERIMENTAL VERIFICATION
!                 OF THE END-EFFECT WEIBULL MODEL AS A PREDICTOR OF THE
!                 TENSILE STRENGTH OF KEVLAR-29 (POLY
!                 p-PHENYLENETEREPHTHALAMIDE) FIBRES AT DIFFERENCE GAUGE
!                 LENGTHS", HIGH PERFORMANCE POLYMERS, 11, PP. 297-305.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/11
!     ORIGINAL VERSION--NOVEMBER  2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASPL
      CHARACTER*40 IDIST
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION AL(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DIMENSION QP(1)
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*40 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMB'
      ISUBN2='FW  '
      IERROR='NO'
!
      IDIST='2-PARAMETER BRITTLE FIBER WEIBULL'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MBFW')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMBFW--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,NUMV
   52   FORMAT('IBUGA3,ISUBRO,N,NUMV = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),AL(I)
   57     FORMAT('I,Y(I),AL(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MBFW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NMIN=3
      NPERC=0
      CALL CKDIST(Y,N,NMIN,QP,NPERC,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     STEP 1: OBTAIN POINT ESTIMATES AND STANDARD ERRORS
!
      ISTEPN='12'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MBFW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL BFWML1(Y,AL,N,MAXNXT,   &
                  TEMP1,TEMP2,DTEMP1,   &
                  XMEAN,XSD,XVAR,XMIN,XMAX,   &
                  SCALSV,SHAPSV,SCALML,SHAPML,   &
                  ISUBRO,IBUGA3,IERROR)
       IF(IERROR.EQ.'YES')GO TO 9000
!
      ISTEPN='13'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MBFW')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
       ALIKE=CPUMIN
       AIC=CPUMIN
       AICC=CPUMIN
       BIC=CPUMIN
       MINMAX=1
       ALOC=0.0
       ICASPL='WEIB'
       CALL BFWLI1(Y,AL,N,ICASPL,MINMAX,ALOC,SCALML,SHAPML,   &
                   ALIKE,AIC,AICC,BIC,   &
                   ISUBRO,IBUGA3,IERROR)
!
!               ***********************************************
!               **   STEP 42--                              **
!               **   WRITE OUT EVERYTHING                   **
!               **   FOR 2-PARAMETER BRITTLE FIBER WEIBULL  **
!               **   MLE ESTIMATE                           **
!               **********************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MBFW')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT SUMMARY STATISTICS TABLE
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Two-Parameter Brittle Fiber Weibull Parameter Estimation:'
      NCTITL=57
      ITITLZ='Full Sample Case'
      NCTITZ=16
!
      ICNT=1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Maximum Likelihood:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Scale:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=SCALML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Shape (Gamma):'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=SHAPML
      IDIGIT(ICNT)=NUMDIG
!
      IF(ALIKE.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Log-likelihood:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=ALIKE
        IDIGIT(ICNT)=-7
        ICNT=ICNT+1
        ITEXT(ICNT)='AIC:'
        NCTEXT(ICNT)=4
        AVALUE(ICNT)=AIC
        IDIGIT(ICNT)=-7
        ICNT=ICNT+1
        ITEXT(ICNT)='AICc:'
        NCTEXT(ICNT)=5
        AVALUE(ICNT)=AICC
        IDIGIT(ICNT)=-7
        ICNT=ICNT+1
        ITEXT(ICNT)='BIC:'
        NCTEXT(ICNT)=4
        AVALUE(ICNT)=BIC
        IDIGIT(ICNT)=-7
      ENDIF
!
      NUMROW=ICNT
      DO 2320 I=1,NUMROW
        NTOT(I)=15
 2320 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MBFW')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMBFW--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)SCALML,SHAPML
 9014   FORMAT('SCALML,SHAPML = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMBFW
      SUBROUTINE DPMBLI(IHARG,IHARG2,NUMARG,IDEMBL,MAXMAR,IMABLI,   &
                        IBUGP2,IFOUND,IERROR)
!CCCC AUGUST 1995.  ADD IHARG2 FOR DASH2, ETC
!CCCC SUBROUTINE DPMBLI(IHARG,NUMARG,IDEMBL,MAXMAR,IMABLI,
!
!     PURPOSE--DEFINE THE BORDER LINES = THE LINES TYPES
!              OF THE BORDER AROUND THE MARKERS.
!              THESE ARE LOCATED IN THE VECTOR IMABLI(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEMBL
!                     --MAXMAR
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--IMABLI (A CHARACTER VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!     UPDATED         --AUGUST    1995.  DASH2 BUG
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
!CCCC AUGUST 1995.  ADD FOLLOWING LINE
      CHARACTER*4 IHARG2
      CHARACTER*4 IDEMBL
      CHARACTER*4 IMABLI
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
      CHARACTER*4 IHOLD2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
!CCCC AUGUST 1995.  ADD FOLLOWING LINE
      DIMENSION IHARG2(*)
      DIMENSION IMABLI(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPMB'
      ISUBN2='LI  '
!
      NUMMAR=0
      IHOLD1='-999'
      IHOLD2='-999'
!
      IF(IBUGP2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMBLI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR
   52 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXMAR,NUMMAR
   53 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IHOLD1,IHOLD2
   54 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)IDEMBL
   55 FORMAT('IDEMBL = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,60)NUMARG
   60 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,NUMARG
      WRITE(ICOUT,66)IHARG(I)
   66 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,70)IMABLI(1)
   70 FORMAT('IMABLI(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 75 I=1,10
      WRITE(ICOUT,76)I,IMABLI(I)
   76 FORMAT('I,IMABLI(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   75 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.2)GO TO 9000
      IF(NUMARG.EQ.3)GO TO 1130
      IF(NUMARG.EQ.4)GO TO 1140
      IF(NUMARG.EQ.5)GO TO 1150
      GO TO 1160
!
 1130 CONTINUE
      GO TO 1200
!
 1140 CONTINUE
      IF(IHARG(5).EQ.'ALL')IHOLD1='    '
      IF(IHARG(5).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1150 CONTINUE
      IF(IHARG(5).EQ.'ALL')THEN
        IHOLD1=IHARG(6)
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(6).EQ.'2')IHOLD1='DA2'
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(6).EQ.'3')IHOLD1='DA3'
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(6).EQ.'4')IHOLD1='DA4'
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(6).EQ.'5')IHOLD1='DA5'
        GO TO 1300
      ENDIF
      IF(IHARG(6).EQ.'ALL')THEN
        IHOLD1=IHARG(5)
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(5).EQ.'2')IHOLD1='DA2'
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(5).EQ.'3')IHOLD1='DA3'
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(5).EQ.'4')IHOLD1='DA4'
        IF(IHOLD1.EQ.'DASH'.AND.IHARG2(5).EQ.'5')IHOLD1='DA5'
        GO TO 1300
      ENDIF
      GO TO 1200
!
 1160 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE     SPECIFICATION  CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.3)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMMAR=1
      IMABLI(1)='    '
      GO TO 1270
!
 1220 CONTINUE
      NUMMAR=NUMARG-3
      IF(NUMMAR.GT.MAXMAR)NUMMAR=MAXMAR
      DO 1225 I=1,NUMMAR
      J=I+3
      IHOLD1=IHARG(J)
      IF(IHOLD1.EQ.'DASH'.AND.IHARG2(J).EQ.'2')IHOLD1='DA2'
      IF(IHOLD1.EQ.'DASH'.AND.IHARG2(J).EQ.'3')IHOLD1='DA3'
      IF(IHOLD1.EQ.'DASH'.AND.IHARG2(J).EQ.'4')IHOLD1='DA4'
      IF(IHOLD1.EQ.'DASH'.AND.IHARG2(J).EQ.'5')IHOLD1='DA5'
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2='SOLI'
      IF(IHOLD1.EQ.'OFF')IHOLD2='    '
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMBL
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMBL
      IMABLI(I)=IHOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMMAR
      WRITE(ICOUT,1276)I,IMABLI(I)
 1276 FORMAT('THE LINE TYPE FOR MARKER BORDER ',I6,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMMAR=MAXMAR
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2='SOLI'
      IF(IHOLD1.EQ.'OFF')IHOLD2='    '
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMBL
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMBL
      DO 1315 I=1,NUMMAR
      IMABLI(I)=IHOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)IMABLI(I)
 1316 FORMAT('THE LINE TYPE FOR ALL MARKER BORDERS',   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMBLI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGP2,IFOUND,IERROR
 9012 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)MAXMAR,NUMMAR
 9013 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IHOLD1,IHOLD2
 9014 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IDEMBL
 9015 FORMAT('IDEMBL = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9020)NUMARG
 9020 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9025 I=1,NUMARG
      WRITE(ICOUT,9026)IHARG(I)
 9026 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
      WRITE(ICOUT,9030)IMABLI(1)
 9030 FORMAT('IMABLI(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 9035 I=1,10
      WRITE(ICOUT,9036)I,IMABLI(I)
 9036 FORMAT('I,IMABLI(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9035 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMBLI
      SUBROUTINE DPMBTH(IHARG,IARGT,ARG,NUMARG,PDEMBT,MAXMAR,PMABTH,   &
                        IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MARKER (BORDER) LINE THICKNESSES = THE THICKNESSES
!              OF THE BORDER LINE AROUND THE MARKERS.
!              THESE ARE LOCATED IN THE VECTOR PMABTH(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --IARGT  (A  CHARACTER VECTOR)
!                     --ARG
!                     --NUMARG
!                     --PDEMBT
!                     --MAXMAR
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--PMABTH (A FLOATING POINT VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
      DIMENSION PMABTH(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPMB'
      ISUBN2='TH  '
!
      NUMMAR=0
      IHOLD1='-999'
      HOLD1=-999.0
      HOLD2=-999.0
!
      IF(IBUGP2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMBTH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR
   52 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXMAR,NUMMAR
   53 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IHOLD1,HOLD1,HOLD2
   54 FORMAT('IHOLD1,HOLD1,HOLD2 = ',A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)PDEMBT
   55 FORMAT('PDEMBT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,60)NUMARG
   60 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,NUMARG
      WRITE(ICOUT,66)IHARG(I),IARGT(I),ARG(I)
   66 FORMAT('IHARG(I),IARGT(I),ARG(I) = ',A4,2X,A4,I8)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,70)PMABTH(1)
   70 FORMAT('PMABTH(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 75 I=1,10
      WRITE(ICOUT,76)I,PMABTH(I)
   76 FORMAT('I,PMABTH(I) = ',I8,2X,E15.7)
      CALL DPWRST('XXX','BUG ')
   75 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.1)GO TO 9000
      IF(NUMARG.EQ.2)GO TO 1120
      IF(NUMARG.EQ.3)GO TO 1130
      IF(NUMARG.EQ.4)GO TO 1140
      GO TO 1150
!
 1120 CONTINUE
      GO TO 1200
!
 1130 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1='    '
      IF(IHARG(3).EQ.'ALL')HOLD1=PDEMBT
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1140 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1=IHARG(4)
      IF(IHARG(3).EQ.'ALL')HOLD1=ARG(4)
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      IF(IHARG(4).EQ.'ALL')IHOLD1=IHARG(3)
      IF(IHARG(4).EQ.'ALL')HOLD1=ARG(3)
      IF(IHARG(4).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1150 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE     SPECIFICATION  CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.2)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMMAR=1
      PMABTH(1)=PDEMBT
      GO TO 1270
!
 1220 CONTINUE
      NUMMAR=NUMARG-2
      IF(NUMMAR.GT.MAXMAR)NUMMAR=MAXMAR
      DO 1225 I=1,NUMMAR
      J=I+2
      IHOLD1=IHARG(J)
      HOLD1=ARG(J)
      HOLD2=HOLD1
      IF(IHOLD1.EQ.'ON')HOLD2=PDEMBT
      IF(IHOLD1.EQ.'OFF')HOLD2=PDEMBT
      IF(IHOLD1.EQ.'AUTO')HOLD2=PDEMBT
      IF(IHOLD1.EQ.'DEFA')HOLD2=PDEMBT
      PMABTH(I)=HOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMMAR
      WRITE(ICOUT,1276)I,PMABTH(I)
 1276 FORMAT('THE THICKNESS OF MARKER BORDER ',I6,   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMMAR=MAXMAR
      HOLD2=HOLD1
      IF(IHOLD1.EQ.'ON')HOLD2=PDEMBT
      IF(IHOLD1.EQ.'OFF')HOLD2=PDEMBT
      IF(IHOLD1.EQ.'AUTO')HOLD2=PDEMBT
      IF(IHOLD1.EQ.'DEFA')HOLD2=PDEMBT
      DO 1315 I=1,NUMMAR
      PMABTH(I)=HOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)PMABTH(I)
 1316 FORMAT('THE THICKNESS OF ALL MARKER BORDERS',   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMBTH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGP2,IFOUND,IERROR
 9012 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)MAXMAR,NUMMAR
 9013 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IHOLD1,HOLD1,HOLD2
 9014 FORMAT('IHOLD1,HOLD1,HOLD2 = ',A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PDEMBT
 9015 FORMAT('PDEMBT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9030)PMABTH(1)
 9030 FORMAT('PMABTH(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 9035 I=1,10
      WRITE(ICOUT,9036)I,PMABTH(I)
 9036 FORMAT('I,PMABTH(I) = ',I8,2X,E15.7)
      CALL DPWRST('XXX','BUG ')
 9035 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMBTH
      SUBROUTINE DPMCNE(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--COMPUTE MCNEMAR TEST.
!     EXAMPLE--MCNEMAR TEST Y1 Y2
!            --MCNEMAR TEST N11 N21 N12 N22
!     REFERENCE--CONOVER (1999), "PRACTICAL NONPARAMETRIC
!                STATISTICS", THIRD EDITION, WILEY, PP. 166-169.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --JANUARY   2011. USE DPPARS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASEQ
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN0
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
!
      PARAMETER (MAXSPN=20)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      PARAMETER(MAXLEV=1000)
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      REAL TEMP1(MAXOBV)
      REAL TEMP2(MAXOBV)
      REAL TEMP3(MAXOBV)
      REAL XIDTEM(MAXOBV)
      REAL XIDTE2(MAXOBV)
      REAL XMAT(MAXLEV,MAXLEV)
!
      EQUIVALENCE (GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB2),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB3),TEMP3(1))
      EQUIVALENCE (GARBAG(IGARB4),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB6),XMAT(1,1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMC'
      ISUBN2='NE  '
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      N11=(-999)
      N21=(-999)
      N12=(-999)
      N22=(-999)
!
      NS1=(-999)
      NS2=(-999)
      NS3=(-999)
      NS4=(-999)
!
      ICASE='PARA'
      MINN2=2
!
      IFOUND='YES'
      ICASEQ='UNKN'
!
!               ***************************************************
!               **  TREAT THE MCNEMAR TEST CASE                  **
!               ***************************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMCNE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ICASAN
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ICASAN = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,NUMARG
   55   FORMAT('MAXNXT,NUMARG = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 59 I=1,NUMARG
          WRITE(ICOUT,57)I,IHARG(I),IHARG2(I),ARG(I)
   57     FORMAT('I,IHARG(I),IHARG2(I),ARG(I) = ',I5,A4,A4,G15.7)
   59   CONTINUE
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='MCNEMAR TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=9
      IFLAGP=9
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=4
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),PVAR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),PVAR(I) = ',I8,2X,A4,A4,2X,3I8,G15.7)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************
!               **  STEP 22--                    **
!               **  CHECK FOR PROPER VALUES FOR  **
!               **  INPUT PARAMETERS             **
!               ***********************************
!
      IF(IVARTY(1).EQ.'PARA' .OR. IVARTY(1).EQ.'NUMB')THEN
        N11=INT(PVAR(1)+0.5)
        N21=INT(PVAR(2)+0.5)
        N12=INT(PVAR(3)+0.5)
        N22=INT(PVAR(4)+0.5)
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        ICASE='PARA'
!
        ISTEPN='22'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
 2201     FORMAT('***** ERROR FROM MCNEMAR TEST--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2203)
 2203     FORMAT('      THE VALUE OF THE FIRST PARAMETER (N11 = THE ',   &
                 'NUMBER OF SUCCESSES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2204)
 2204     FORMAT('      FOR THE FIRST VARIABLE MUST BE NON-NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2205)N11
 2205     FORMAT('      N11 = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2303)
 2303     FORMAT('      THE VALUE OF THE SECOND PARAMETER (N21 = THE ',   &
                 'NUMBER OF FAILURES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2304)
 2304     FORMAT('      FOR THE FIRST VARIABLE MUST BE NON-NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2305)N21
 2305     FORMAT('      N21 = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2403)
 2403     FORMAT('      THE VALUE OF THE THIRD PARAMETER (N12 = THE ',   &
                 'NUMBER OF SUCCESSES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2404)
 2404     FORMAT('      FOR THE SECOND VARIABLE MUST BE NON-NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2405)N12
 2405     FORMAT('      N12 = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2503)
 2503     FORMAT('      THE VALUE OF THE FOURTH PARAMETER (N22 = THE ',   &
                 'NUMBER OF FAILURES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2504)
 2504     FORMAT('      FOR THE SECOND VARIABLE MUST BE NON-NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2505)N22
 2505     FORMAT('      N22 = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
      ELSEIF(IVARTY(1).EQ.'VARI')THEN
!
        ICASE='VARI'
        ICOL=1
        IF(NUMVAR.GT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2603)
 2603     FORMAT('      MORE THAN TWO VARIABLES GIVEN.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2605)NUMVAR
 2605     FORMAT('      THE NUMBER OF VARIABLES GIVEN  = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,X,X,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NS1=NLOCAL
        NS2=NLOCA2
!
      ELSEIF(IVARTY(1).EQ.'MATR')THEN
        ICASE='MATR'
        ICOL=1
        NUMVAR=1
        CALL DPPAR6(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    XMAT,MAXLEV,NROW,NCOL,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        ICASE='TABL'
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ***********************************
!               **  STEP 61--                    **
!               **  COMPUTE THE MCNEMAR    TEST  **
!               ***********************************
!
      ISTEPN='61'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MCNE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6111)
 6111   FORMAT('***** FROM DPMCNE--READY TO COMPUTE TEST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6112)AN11,AN21,AN12,AN22
 6112   FORMAT('AN11,AN21,AN12,AN22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL DPMCN2(Y,NS1,X,NS2,   &
                  AN11,AN21,AN12,AN22,   &
                  XMAT,MAXLEV,NROW,NCOL,   &
                  XIDTEM,   &
                  ICASE,ICAPSW,ICAPTY,IFORSW,   &
                  STATVA,CDF,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 62--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='62'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN0='MCNE'
!
      IH='STAT'
      IH2='VAL '
      VALUE0=STATVA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='CDF '
      VALUE0=CDF
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCNE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMCNE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA2,IBUGA3
 9012   FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IERROR
 9016   FORMAT('IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMCNE
      SUBROUTINE DPMCN2(Y1,N1,Y2,N2,   &
                        AN11,AN21,AN12,AN22,   &
                        XMAT,MAXLEV,NROW,NCOL,   &
                        XIDTEM,   &
                        ICASE,ICAPSW,ICAPTY,IFORSW,   &
                        STATVA,CDF,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A MCNEMAR TEST FOR INDEPENDENCE.
!              THE INPUT CAN EITHER BE ENTERED AS TWO VARIABLES
!              CONTAINING 1's (FOR SUCCESS) AND 0's (FOR FAILURES)
!              OR AS FOUR PARAMETERS:
!                 N11 = NUMBER OF SUCCESSES FOR VARIABLE 1 = A
!                 N21 = NUMBER OF FAILURES  FOR VARIABLE 1 = C
!                 N12 = NUMBER OF SUCCESSES FOR VARIABLE 2 = B
!                 N22 = NUMBER OF SUCCESSES FOR VARIABLE 2 = D
!
!              WE THEN USE THE TEST STATISTIC:
!
!                 T = (B-C)**2/(B+C)    B+C >= 20
!
!                 T = B                 B+C < 20
!
!              A CONTINUITY CORRECTION CAN BE APPLIED:
!
!                 T = {|B-C| - 1}**2/(B+C)    B+C >= 20
!
!     EXAMPLE--MCNEMAR TEST Y1 Y2
!              SAMPLE 1 IS IN INPUT VECTOR Y1 (WITH N1 OBSERVATIONS).
!              SAMPLE 2 IS IN INPUT VECTOR Y2 (WITH N2 OBSERVATIONS).
!            --MCNEMAR TEST N11 N21 N12 N22
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGYU LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/3
!     ORIGINAL VERSION--MARCH     2007.
!     UPDATED         --JANUARY   2011. USE DPAUFI TO OPEN/CLOSE
!                                       AUXILLARY FILES
!     UPDATED         --JANUARY   2011. USE DPDTA1, DPDT5B TO PRINT
!                                       TABLES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 ICASE
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IWRITE
!
      CHARACTER*6 ICONC1
      CHARACTER*6 ICONC2
      CHARACTER*6 ICONC3
      CHARACTER*6 ICONC4
      CHARACTER*6 ICONC5
      CHARACTER*6 ICONC6
!
      CHARACTER*6 KCONC1
      CHARACTER*6 KCONC2
      CHARACTER*6 KCONC3
      CHARACTER*6 KCONC4
      CHARACTER*6 KCONC5
      CHARACTER*6 KCONC6
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XMAT(MAXLEV,MAXLEV)
!
!
      PARAMETER (NUMALP=5)
!CCCC DIMENSION SIGVAL(NUMALP)
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPPF
!
      PARAMETER(NUMCLI=6)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      IDIGI2(MAXROW,NUMCLI)
      INTEGER      NTOT(MAXRO2)
      INTEGER      ROWSEP(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      NCOLSP(MAXLIN,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA SIGVAL /0.50, 0.80, 0.90, 0.95, 0.99, 0.999/
!CCCC DATA SIGVAL /0.50, 0.80, 0.90, 0.95, 0.99/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMC'
      ISUBN2='N2  '
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MCN2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMCN2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,IBINCC
   52   FORMAT('IBUGA3,ISUBRO,ICASE,IBINCC = ',4(A4,2X))
        CALL DPWRST('XXX','WRIT')
        IF(ICASE.EQ.'VARI')THEN
          WRITE(ICOUT,55)N1
   55     FORMAT('N1 = ',I8)
          CALL DPWRST('XXX','WRIT')
          DO 56 I=1,N1
            WRITE(ICOUT,57)I,Y1(I)
   57       FORMAT('I,Y1(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
          WRITE(ICOUT,65)N2
   65     FORMAT('N2 = ',I8)
          CALL DPWRST('XXX','WRIT')
          DO 66 I=1,N2
            WRITE(ICOUT,67)I,Y2(I)
   67       FORMAT('I,Y2(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
   66     CONTINUE
        ELSE
          WRITE(ICOUT,75)AN11,AN21,AN12,AN22
   75     FORMAT('AN11,AN21,AN12,AN22 = ',4G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 0--                              **
!               **  BRANCH TO APPROPRIATE CASE (PARAMETER **
!               **  OR VARIABLE)                          **
!               ********************************************
!
      ISTEPN='00'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASE.EQ.'PARA')GO TO 1000
      IF(ICASE.EQ.'VARI')GO TO 2000
      IF(ICASE.EQ.'TABL')GO TO 3000
!
!               ********************************************
!               **  STEP 11--                             **
!               **  PARAMETER CASE                        **
!               ********************************************
!
 1000 CONTINUE
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ********************************************
!               **  STEP 12--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      N11=INT(AN11+0.5)
      N21=INT(AN21+0.5)
      N12=INT(AN12+0.5)
      N22=INT(AN22+0.5)
!
      ISTEPN='12'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N11.LT.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR FROM THE MCNEMAR TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE VALUE OF THE FIRST PARAMETER (N11 = THE ',   &
               'NUMBER OF SUCCESSES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1204)
 1204   FORMAT('      FOR THE FIRST VARIABLE MUST BE NON-NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1205)N11
 1205   FORMAT('      N11 = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N21.LT.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1303)
 1303   FORMAT('      THE VALUE OF THE SECOND PARAMETER (N21 = THE ',   &
               'NUMBER OF FAILURES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1304)
 1304   FORMAT('      FOR THE FIRST VARIABLE MUST BE NON-NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1305)N21
 1305   FORMAT('      N21 = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N12.LT.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1403)
 1403   FORMAT('      THE VALUE OF THE THIRD PARAMETER (N12 = THE ',   &
               'NUMBER OF SUCCESSES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1404)
 1404   FORMAT('      FOR THE SECOND VARIABLE MUST BE NON-NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1405)N12
 1405   FORMAT('      N12 = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N22.LT.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1503)
 1503   FORMAT('      THE VALUE OF THE FOURTH PARAMETER (N22 = THE ',   &
               'NUMBER OF FAILURES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1504)
 1504   FORMAT('      FOR THE SECOND VARIABLE MUST BE NON-NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1505)N22
 1505   FORMAT('      N22 = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 12--                             **
!               **  COMPUTE THE LOG ODDS RATIO TEST       **
!               ********************************************
!
!
      GO TO 4000
!
!               ********************************************
!               **  STEP 20--                             **
!               **  VARIABLE  CASE                        **
!               ********************************************
!
 2000 CONTINUE
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2101)
 2101   FORMAT('      THE NUMBER OF OBSERVATIONS FOR VARIABLE 1 ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2103)N1
 2103   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2106)
 2106   FORMAT('      THE NUMBER OF OBSERVATIONS FOR VARIABLE 2 ',   &
               'IS NON-POSITIVE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2103)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(Y1,N1,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2202 I=1,N1
          Y1(I)=1.0
 2202   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2203 I=1,N1
            IF(Y1(I).NE.1.0)Y1(I)=0.0
 2203     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2208 I=1,N1
            IF(Y1(I).EQ.ATEMP1)Y1(I)=0.0
            IF(Y1(I).EQ.ATEMP2)Y1(I)=1.0
 2208     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2211)
 2211   FORMAT('      RESPONSE VARIABLE ONE SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2213)
 2213   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2215)NDIST
 2215   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL SUMDP(Y1,N1,IWRITE,XSUM,IBUGA3,IERROR)
      AN11=XSUM
      N11=INT(AN11+0.5)
      N21=N1-N11
      AN21=REAL(N21)
!
      CALL DISTIN(Y2,N2,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        AVAL=XIDTEM(1)
        IF(ABS(AVAL).LE.0.5)THEN
          AVAL=0.0
        ELSE
          AVAL=1.0
        ENDIF
        DO 2302 I=1,N2
          Y2(I)=1.0
 2302   CONTINUE
      ELSEIF(NDIST.EQ.2)THEN
        IF(XIDTEM(1).EQ.1.0 .OR. XIDTEM(2).EQ.1.0)THEN
          DO 2303 I=1,N2
            IF(Y2(I).NE.1.0)Y2(I)=0.0
 2303     CONTINUE
        ELSE
          ATEMP1=MIN(XIDTEM(1),XIDTEM(2))
          ATEMP2=MAX(XIDTEM(1),XIDTEM(2))
          DO 2308 I=1,N2
            IF(Y2(I).EQ.ATEMP1)Y2(I)=0.0
            IF(Y2(I).EQ.ATEMP2)Y2(I)=1.0
 2308     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2311)
 2311   FORMAT('      RESPONSE VARIABLE TWO SHOULD CONTAIN AT MOST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2313)
 2313   FORMAT('      TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2315)NDIST
 2315   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL SUMDP(Y2,N2,IWRITE,XSUM,IBUGA3,IERROR)
      AN12=XSUM
      N12=INT(AN12+0.5)
      N22=N2-N12
      AN22=REAL(N22)
!
      GO TO 4000
!
 3000 CONTINUE
!
!               ********************************************
!               **  STEP 31--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               **  ALL TABLE ENTRIES SHOULD BE           **
!               **  NON-NEGATIVE INTEGERS.  NEGATIVE      **
!               **  VALUES WILL BE FLAGGED AS ERRORS      **
!               **  WHILE NON-INTEGER VALUES WILL BE      **
!               **  ROUNDED TO NEAREST INTEGER.           **
!               **  SINCE WE ARE SCANNING TABLE, COMPUTE  **
!               **  ROW AND COLUMN TOTALS.                **
!               **  NOTE THAT FOR THIS COMMAND IS         **
!               **  COMPUTED ON A 2X2 CONTINGENCY TABLE.  **
!               **  THEREFORE:                            **
!               **  1) IF NUMBER OF COLUMNS NOT EQUAL     **
!               **     TWO, FLAG AN ERROR.                **
!               **  2) IF NUMBER OF ROWS EQUAL TWO, THEN  **
!               **     EXTRACT THE RELEVANT 4 VALUES AND  **
!               **     GO TO THE PARAMETER CASE.          **
!               **  3) IF NUMBER OF ROWS GREATER THAN     **
!               **     TWO, THEN NEED TO CROSS-TABULATE   **
!               **     (I.E., HAVE THE VARIABLE CASE).    **
!               ********************************************
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ODR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
!
      IF(NCOL.NE.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3101)
 3101   FORMAT('      THE NUMBER OF COLUMNS IN THE INPUT MATRIX')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3103)
 3103   FORMAT('      MUST BE EXACTLY TWO; SUCH WAS NOT THE CASE ',   &
               'HERE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3105)NCOL
 3105   FORMAT('      THE NUMBER OF COLUMNS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NROW.EQ.2)THEN
        AN11=XMAT(1,1)
        AN21=XMAT(2,1)
        AN12=XMAT(1,2)
        AN22=XMAT(2,2)
        GO TO 1000
      ELSE
        DO 3120 I=1,NROW
          Y1(NROW)=XMAT(I,1)
          Y2(NROW)=XMAT(I,2)
 3120   CONTINUE
        N1=NROW
        N2=NROW
        GO TO 2000
      ENDIF
!
 4000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     COMPUTE THE MCNEMAR TEST.
!
      NR1=N11+N12
      NR2=N21+N22
      NC1=N11+N21
      NC2=N12+N22
      NTOTZZ=NR1+NR2
      ANR1=REAL(NR1)
      ANR2=REAL(NR2)
      ANC1=REAL(NC1)
      ANC2=REAL(NC2)
      AN=REAL(NTOTZZ)
!
      A=REAL(N11)
      B=REAL(N12)
      C=REAL(N21)
      D=REAL(N22)
!
      P11=A/ANC1
      P21=C/ANC1
      P12=B/ANC2
      P22=D/ANC2
!
      ICONC1='REJECT'
      ICONC2='REJECT'
      ICONC3='REJECT'
      ICONC4='REJECT'
      ICONC5='REJECT'
      ICONC6='REJECT'
      KCONC1='REJECT'
      KCONC2='REJECT'
      KCONC3='REJECT'
      KCONC4='REJECT'
      KCONC5='REJECT'
      KCONC6='REJECT'
!
      IF(B+C.LE.20.0)THEN
        STATVA=B
        STATV2=B
        P=0.5
        NTEMP=INT(B+C+0.5)
        CALL BINCDF(DBLE(STATVA),DBLE(P),NTEMP,DCDF)
        CDF2=REAL(DCDF)
!
        ALPHA=0.50
        ALPHAL=(1.0 - ALPHA)/2.0
        ALPHAU=1.0 - ALPHAL
        CALL BINPPF(DBLE(ALPHAL),DBLE(P),NTEMP,DPPF)
        CV1L=REAL(DPPF)
        CALL BINPPF(DBLE(ALPHAU),DBLE(P),NTEMP,DPPF)
        CV1U=REAL(DPPF)
        IF(CDF.GE.ALPHAL.AND.CDF.LE.ALPHAU)ICONC1='ACCEPT'
!
        ALPHA=0.80
        ALPHAL=(1.0 - ALPHA)/2.0
        ALPHAU=1.0 - ALPHAL
        CALL BINPPF(DBLE(ALPHAL),DBLE(P),NTEMP,DPPF)
        CV2L=REAL(DPPF)
        CALL BINPPF(DBLE(ALPHAU),DBLE(P),NTEMP,DPPF)
        CV2U=REAL(DPPF)
        IF(CDF.GE.ALPHAL.AND.CDF.LE.ALPHAU)ICONC2='ACCEPT'
!
        ALPHA=0.90
        ALPHAL=(1.0 - ALPHA)/2.0
        ALPHAU=1.0 - ALPHAL
        CALL BINPPF(DBLE(ALPHAL),DBLE(P),NTEMP,DPPF)
        CV3L=REAL(DPPF)
        CALL BINPPF(DBLE(ALPHAU),DBLE(P),NTEMP,DPPF)
        CV3U=REAL(DPPF)
        IF(CDF.GE.ALPHAL.AND.CDF.LE.ALPHAU)ICONC3='ACCEPT'
!
        ALPHA=0.95
        ALPHAL=(1.0 - ALPHA)/2.0
        ALPHAU=1.0 - ALPHAL
        CALL BINPPF(DBLE(ALPHAL),DBLE(P),NTEMP,DPPF)
        CV4L=REAL(DPPF)
        CALL BINPPF(DBLE(ALPHAU),DBLE(P),NTEMP,DPPF)
        CV4U=REAL(DPPF)
        IF(CDF.GE.ALPHAL.AND.CDF.LE.ALPHAU)ICONC4='ACCEPT'
!
        ALPHA=0.98
        ALPHAL=(1.0 - ALPHA)/2.0
        ALPHAU=1.0 - ALPHAL
        CALL BINPPF(DBLE(ALPHAL),DBLE(P),NTEMP,DPPF)
        CV5L=REAL(DPPF)
        CALL BINPPF(DBLE(ALPHAU),DBLE(P),NTEMP,DPPF)
        CV5U=REAL(DPPF)
        IF(CDF.GE.ALPHAL.AND.CDF.LE.ALPHAU)ICONC5='ACCEPT'
!
        ALPHA=0.99
        ALPHAL=(1.0 - ALPHA)/2.0
        ALPHAU=1.0 - ALPHAL
        CALL BINPPF(DBLE(ALPHAL),DBLE(P),NTEMP,DPPF)
        CV6L=REAL(DPPF)
        CALL BINPPF(DBLE(ALPHAU),DBLE(P),NTEMP,DPPF)
        CV6U=REAL(DPPF)
        IF(CDF.GE.ALPHAL.AND.CDF.LE.ALPHAU)ICONC6='ACCEPT'
!
      ELSE
        STATVA=(B-C)**2/(B+C)
        STATV2=(ABS(B-C) - 1.0)**2/(B+C)
        NU=1
        CALL CHSCDF(STATVA,NU,CDF)
        CALL CHSCDF(STATV2,NU,CDF2)
        ALPHA=0.50
        CALL CHSPPF(ALPHA,NU,CV1)
        ALPHA=0.80
        CALL CHSPPF(ALPHA,NU,CV2)
        ALPHA=0.90
        CALL CHSPPF(ALPHA,NU,CV3)
        ALPHA=0.95
        CALL CHSPPF(ALPHA,NU,CV4)
        ALPHA=0.99
        CALL CHSPPF(ALPHA,NU,CV5)
!
        IF(0.0.LE.CDF.AND.CDF.LE.0.500)ICONC1='ACCEPT'
        IF(0.0.LE.CDF.AND.CDF.LE.0.800)ICONC2='ACCEPT'
        IF(0.0.LE.CDF.AND.CDF.LE.0.900)ICONC3='ACCEPT'
        IF(0.0.LE.CDF.AND.CDF.LE.0.950)ICONC4='ACCEPT'
        IF(0.0.LE.CDF.AND.CDF.LE.0.990)ICONC5='ACCEPT'
!
        IF(0.0.LE.CDF2.AND.CDF2.LE.0.500)KCONC1='ACCEPT'
        IF(0.0.LE.CDF2.AND.CDF2.LE.0.800)KCONC2='ACCEPT'
        IF(0.0.LE.CDF2.AND.CDF2.LE.0.900)KCONC3='ACCEPT'
        IF(0.0.LE.CDF2.AND.CDF2.LE.0.950)KCONC4='ACCEPT'
        IF(0.0.LE.CDF2.AND.CDF2.LE.0.990)KCONC5='ACCEPT'
!
      ENDIF
!
      IWRITE='OFF'
!
!               ******************************
!               **   STEP 42--              **
!               **   WRITE OUT EVERYTHING   **
!               **   FOR ODDS RATIO   TEST  **
!               ******************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCN2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT SUMMARY STATISTICS TABLE
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='McNemar Test for New Better Than Old'
      NCTITL=36
      ITITLZ='(2x2 Table)'
      NCTITZ=11
!
      ICNT=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: New and Old are Equal'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: New and Old are Not Equal'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 2310 I=1,NUMROW
        NTOT(I)=15
 2310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                  NCTEXT,AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE(1:13)='Summary Table'
      NCTITL=13
      ITITL9=' '
      NCTIT9=0
!
      NUMCOL=6
      NUMLIN=2
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      NCOLSP(1,1)=1
      ITITL2(2,1)='Variable One'
      NCTIT2(2,1)=12
      NCOLSP(2,1)=1
      ITITL2(1,2)=' | '
      NCTIT2(1,2)=3
      NCOLSP(1,2)=1
      ITITL2(2,2)=' | '
      NCTIT2(2,2)=3
      NCOLSP(2,2)=1
!
      ITITL2(1,3)='Variable Two'
      NCTIT2(1,3)=12
      NCOLSP(1,3)=2
      ITITL2(2,3)='Successes'
      NCTIT2(2,3)=9
      NCOLSP(2,3)=1
      ITITL2(1,4)=' '
      NCTIT2(1,4)=0
      NCOLSP(1,4)=0
      ITITL2(2,4)='Failures'
      NCTIT2(2,4)=8
      NCOLSP(2,4)=1
!
      ITITL2(1,5)=' | '
      NCTIT2(1,5)=3
      NCOLSP(1,5)=1
      ITITL2(2,5)=' | '
      NCTIT2(2,5)=3
      NCOLSP(2,5)=1
!
      ITITL2(1,6)='Row'
      NCTIT2(1,6)=3
      NCOLSP(1,6)=1
      ITITL2(2,6)='Total'
      NCTIT2(2,6)=5
      NCOLSP(2,6)=1
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2 .OR. I.EQ.5)NTOT(I)=3
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IF(I.EQ.1 .OR. I.EQ.2 .OR. I.EQ.5)ITYPCO(I)='ALPH'
        DO 4213 J=1,MAXROW
          IDIGI2(J,I)=0
          IF(I.EQ.3 .OR. I.EQ.4)THEN
            IF(J.EQ.2 .OR. J.EQ.4)THEN
              IDIGI2(J,I)=NUMDIG
            ENDIF
          ENDIF
          IF(I.EQ.6)THEN
            IF(J.EQ.2 .OR. J.EQ.4)THEN
              IDIGI2(J,I)=-1
            ELSE
              IDIGI2(J,I)=0
            ENDIF
          ENDIF
 4213   CONTINUE
!
 4210 CONTINUE
!
      DO 4289 J=1,MAXROW
        IVALUE(J,1)=' '
        IVALUE(J,2)=' '
        IVALUE(J,3)=' '
        IVALUE(J,4)=' '
        IVALUE(J,5)=' '
        IVALUE(J,6)=' '
        NCVALU(J,1)=0
        NCVALU(J,2)=0
        NCVALU(J,3)=0
        NCVALU(J,4)=0
        NCVALU(J,5)=0
        NCVALU(J,6)=0
        AMAT(J,1)=0.0
        AMAT(J,2)=0.0
        AMAT(J,3)=0.0
        AMAT(J,4)=0.0
        AMAT(J,5)=0.0
        AMAT(J,6)=0.0
        ROWSEP(J)=0
 4289 CONTINUE
      AMAT(1,3)=REAL(N11)
      AMAT(1,4)=REAL(N12)
      AMAT(1,6)=REAL(NR1)
      AMAT(2,3)=P11
      AMAT(2,4)=P12
      AMAT(2,6)=CPUMIN
      AMAT(3,3)=REAL(N21)
      AMAT(3,4)=REAL(N22)
      AMAT(3,6)=REAL(NR2)
      AMAT(4,3)=P21
      AMAT(4,4)=P22
      AMAT(4,6)=CPUMIN
      AMAT(5,3)=REAL(NC1)
      AMAT(5,4)=REAL(NC2)
      AMAT(5,6)=REAL(NTOTZZ)
      IVALUE(1,1)='Successes'
      NCVALU(1,1)=9
      IVALUE(1,2)=' | '
      NCVALU(1,2)=3
      IVALUE(1,5)=' | '
      NCVALU(1,5)=3
      IVALUE(2,2)=' | '
      NCVALU(2,2)=3
      IVALUE(2,5)=' | '
      NCVALU(2,5)=3
      IVALUE(3,1)='Failures'
      NCVALU(3,1)=8
      IVALUE(3,2)=' | '
      NCVALU(3,2)=3
      IVALUE(3,5)=' | '
      NCVALU(3,5)=3
      IVALUE(4,2)=' | '
      NCVALU(4,2)=3
      IVALUE(4,5)=' | '
      NCVALU(4,5)=3
      IVALUE(5,1)='Column Total'
      NCVALU(5,1)=12
      IVALUE(5,2)=' | '
      NCVALU(5,2)=3
      IVALUE(5,5)=' | '
      NCVALU(5,5)=3
      ROWSEP(4)=1
!
      IWHTML(1)=150
      IWHTML(2)=25
      IWHTML(3)=150
      IWHTML(4)=150
      IWHTML(5)=25
      IWHTML(6)=150
      IINC=1800
      IINC2=200
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC2
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC2
      IWRTF(6)=IWRTF(5)+IINC
!
      ICNT=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDT5B(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGI2,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  NCOLSP,ROWSEP,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=0
      IF(NTOTZZ.LT.20)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Small Sample Case (N < 20)'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Critical Values Based on Binomial with'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='P = 0.5 and N = '
        WRITE(ITEXT(ICNT)(17:18),'(I2)')N12+N21
        NCTEXT(ICNT)=18
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Value of Test Statistic:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=STATVA
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='CDF of Test Statistic:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=CDF
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Large Sample Case (N >= 20)'
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Critical Values Based on Chi-Square with'
        NCTEXT(ICNT)=40
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='One Degree of Freedom'
        NCTEXT(ICNT)=21
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Without Continuity Correction'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Value of Test Statistic:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=STATVA
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='CDF of Test Statistic:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=CDF
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='With Continuity Correction'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Value of Test Statistic:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=STATV2
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='CDF of Test Statistic:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=CDF2
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      NUMROW=ICNT
      DO 4310 I=1,NUMROW
        NTOT(I)=15
 4310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,   &
                  NCTEXT,AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(NTOTZZ.LT.20)THEN
      ELSE
        ITITLE(1:30)='Without Continuity Correction:'
        NCTITL=30
        ITITL9=' '
        NCTIT9=0
!
        ITITL2(1,1)=' '
        NCTIT2(1,1)=0
        ITITL2(2,1)='Null'
        NCTIT2(2,1)=4
        ITITL2(3,1)='Hypothesis'
        NCTIT2(3,1)=10
        ITITL2(1,2)=' '
        NCTIT2(1,2)=0
        ITITL2(2,2)='Confidence'
        NCTIT2(2,2)=10
        ITITL2(3,2)='Level'
        NCTIT2(3,2)=5
        ITITL2(1,3)=' '
        NCTIT2(1,3)=0
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value'
        NCTIT2(3,3)=5
        ITITL2(1,4)='Null Hypothesis'
        NCTIT2(1,4)=15
        ITITL2(2,4)='Acceptance'
        NCTIT2(2,4)=10
        ITITL2(3,4)='Interval'
        NCTIT2(3,4)=8
        ITITL2(1,5)='Null'
        NCTIT2(1,5)=4
        ITITL2(2,5)='Hypothesis'
        NCTIT2(2,5)=10
        ITITL2(3,5)='Conclusion'
        NCTIT2(3,5)=10
!
        NMAX=0
        NUMCOL=5
        DO 5210 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT(I)=15
          NMAX=NMAX+NTOT(I)
          IF(I.EQ.3)THEN
            ITYPCO(I)='NUME'
          ELSE
            ITYPCO(I)='ALPH'
          ENDIF
          IF(I.EQ.2)THEN
            IDIGIT(I)=1
          ELSEIF(I.EQ.3)THEN
            IDIGIT(I)=2
          ELSE
            IDIGIT(I)=NUMDIG
          ENDIF
          IWHTML(1)=150
          IWHTML(2)=125
          IWHTML(3)=125
          IWHTML(4)=150
          IWHTML(5)=150
          IINC=1600
          IINC2=1400
          IINC3=2200
          IWRTF(1)=1800
          IWRTF(2)=IWRTF(1)+IINC
          IWRTF(3)=IWRTF(2)+IINC2
          IWRTF(4)=IWRTF(3)+IINC3
          IWRTF(5)=IWRTF(4)+IINC2
!
          DO 5289 J=1,NUMALP
            IF(J.EQ.1)THEN
              IVALUE(J,2)='50.0%'
              NCVALU(J,2)=5
              AMAT(J,3)=CV1
              IVALUE(J,5)(1:6)=ICONC1(1:6)
              NCVALU(J,5)=6
              IVALUE(J,4)='(0,0.500)'
              NCVALU(J,4)=9
            ELSEIF(J.EQ.2)THEN
              IVALUE(J,2)='80.0%'
              NCVALU(J,2)=5
              AMAT(J,3)=CV2
              IVALUE(J,5)(1:6)=ICONC2(1:6)
              NCVALU(J,5)=6
              IVALUE(J,4)='(0,0.800)'
              NCVALU(J,4)=9
            ELSEIF(J.EQ.3)THEN
              IVALUE(J,2)='90.0%'
              NCVALU(J,2)=5
              AMAT(J,3)=CV3
              IVALUE(J,5)(1:6)=ICONC3(1:6)
              NCVALU(J,5)=6
              IVALUE(J,4)='(0,0.900)'
              NCVALU(J,4)=9
            ELSEIF(J.EQ.4)THEN
              IVALUE(J,2)='95.0%'
              NCVALU(J,2)=5
              AMAT(J,3)=CV4
              IVALUE(J,5)(1:6)=ICONC4(1:6)
              NCVALU(J,5)=6
              IVALUE(J,4)='(0,0.950)'
              NCVALU(J,4)=9
            ELSEIF(J.EQ.5)THEN
              IVALUE(J,2)='99.0%'
              NCVALU(J,2)=5
              AMAT(J,3)=CV5
              IVALUE(J,5)(1:6)=ICONC6(1:6)
              NCVALU(J,5)=6
              IVALUE(J,4)='(0,0.990)'
              NCVALU(J,4)=9
            ENDIF
            AMAT(J,1)=0.0
            AMAT(J,2)=0.0
            AMAT(J,4)=0.0
            AMAT(J,5)=0.0
            IVALUE(J,1)='New/Old Equal'
            NCVALU(J,1)=13
 5289     CONTINUE
!
 5210   CONTINUE
!
        ICNT=NUMALP
        NUMLIN=3
        NUMCOL=5
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
        ITITLE(1:30)='With Continuity Correction:'
        NCTITL=27
!
        NUMCOL=5
        DO 5310 I=1,NUMCOL
!
          DO 5389 J=1,NUMALP
            IF(J.EQ.1)THEN
              IVALUE(J,5)(1:6)=KCONC1(1:6)
              NCVALU(J,5)=6
            ELSEIF(J.EQ.2)THEN
              IVALUE(J,5)(1:6)=KCONC2(1:6)
              NCVALU(J,5)=6
            ELSEIF(J.EQ.3)THEN
              IVALUE(J,5)(1:6)=KCONC3(1:6)
              NCVALU(J,5)=6
            ELSEIF(J.EQ.4)THEN
              IVALUE(J,5)(1:6)=KCONC4(1:6)
              NCVALU(J,5)=6
            ELSEIF(J.EQ.5)THEN
              IVALUE(J,5)(1:6)=KCONC5(1:6)
              NCVALU(J,5)=6
            ELSEIF(J.EQ.6)THEN
              IVALUE(J,5)(1:6)=KCONC6(1:6)
              NCVALU(J,5)=6
            ENDIF
 5389     CONTINUE
!
 5310   CONTINUE
!
        ICNT=NUMALP
        NUMLIN=3
        NUMCOL=5
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MCN2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMCN2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)AN11,AN21,AN12,AN22
 9013   FORMAT('AN11,AN21,AN12,AN22=',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)AN1,AN2
 9015   FORMAT('AN1,AN2=',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)N11,N21,N12,N22
 9017   FORMAT('N11,N21,N12,N22=',4I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMCN2
      SUBROUTINE DPMCWE(MAXNXT,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT MCCOOL WEIBULL LOCATION TEST
!              (TESTS FOR 2-PARAMETER WEIBULL VERSUS 3-PARAMETER WEIBULL,
!              I.E,, IS LOCATION PARAMETER > 0)
!     EXAMPLE--MCCOOL WEIBULL LOCATION TEST Y X
!     REFERENCE --JOHN MCCOOL (1998), "INFERENCE ON THE WEIBULL LOCATION
!                 PARAMETER, JOURNAL OF QUALITY TECHNOLOGY, VOL. 30,
!                 NO. 2, PP. 119-126.
!               --JOHN MCCOOL (2012), "USING THE WEIBULL DISTRIBUTION:
!                 RELIABILITY, MODELING, AND INFERENCE", WILEY,
!                 PP. 301-307.
!               --HORST RINNE (2009), "THE WEIBULL DISTRIBUTION: A
!                 HANDBOOK", CRC PRESS, PP. 640-642.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/8
!     ORIGINAL VERSION--AUGUST    2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 IHOST1
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION        TEMP1(MAXOBV)
      DIMENSION        TEMP2(MAXOBV)
      DIMENSION        TEMP3(MAXOBV)
      DIMENSION        TEMP4(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      INTEGER          ITEMP1(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
      INCLUDE 'DPCOZI.INC'
!
      EQUIVALENCE(GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE(GARBAG(IGARB2),TEMP2(1))
      EQUIVALENCE(GARBAG(IGARB3),TEMP3(1))
      EQUIVALENCE(GARBAG(IGARB4),TEMP4(1))
      EQUIVALENCE(DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE(IGARBG(IIGAR1),ITEMP1(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMC'
      ISUBN2='WE  '
      IFOUND='YES'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               *****************************************************
!               **  TREAT THE MCCOOL WEIBULL LOCATION TEST   CASE  **
!               *****************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MCWE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMCWE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT
   55   FORMAT('MAXNXT = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCWE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='MCCOOL WEIBULL LOCATION TEST'
      MINNA=1
      MAXNA=100
      MINN2=10
      IFLAGE=1
      IFLAGM=0
      MINNVA=2
      MAXNVA=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCWE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
!     CURRENTLY, DO NOT SUPPORT EITHER "MULTIPLE" OPTION OR
!     "REPLICATION" OPTION.
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCWE')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      NUMVA2=2
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y,X,TEMP1,NS1,NLOCA2,NLOCA3,ICASE,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 52--                          **
!               **  DO MCCOOL WEIBULL LOCATION TEST    **
!               *****************************************
!
      ISTEPN='52'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MCWE')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5211)
 5211   FORMAT('***** FROM DPMCWE, AS WE ARE ABOUT TO CALL DPMCW2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5212)NS1,MAXN
 5212   FORMAT('NS1,MAXN = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 5215 I=1,NS1
          WRITE(ICOUT,5216)I,Y(I),X(I)
 5216     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 5215   CONTINUE
      ENDIF
!
      CALL DPMCW2(Y,X,NS1,   &
                  TEMP1,TEMP2,TEMP3,TEMP4,DTEMP1,ITEMP1,MAXOBV,   &
                  ICAPSW,ICAPTY,IFORSW,IVARN1,IVARN2,   &
                  STATVA,STATCD,PVALUE,   &
                  CUT50,CUT75,CUT90,CUT95,CUT975,CUT99,CUT999,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               ***************************************
!               **  STEP 61--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='61'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MCWE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN0='MCWE'
!
      IH='STAT'
      IH2='VAL '
      VALUE0=STATVA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='CDF '
      VALUE0=STATCD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PVAL'
      IH2='UE  '
      VALUE0=PVALUE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF50'
      VALUE0=CUT50
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF75'
      VALUE0=CUT75
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF90'
      VALUE0=CUT90
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF95'
      VALUE0=CUT95
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF99'
      VALUE0=CUT99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F999'
      VALUE0=CUT999
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MCWE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMCWE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)STATVA,STATCD,PVALUE,NS1,IERROR
 9014   FORMAT('STATVA,STATCD,PVALUE,NS1,IERROR = ',3G15.7,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMCWE
      SUBROUTINE DPMCW2(Y,TAG,N,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,DTEMP1,ITEMP1,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,IVARID,IVARI2,   &
                        STATVA,STATCD,PVAL,   &
                        CUT50,CUT75,CUT90,CUT95,CUT975,CUT99,CUT999,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT MCCOOL WEIBULL LOCATION TEST
!              (TESTS FOR 2-PARAMETER WEIBULL VERSUS 3-PARAMETER WEIBULL,
!              I.E,, IS LOCATION PARAMETER > 0)
!     EXAMPLE--MCCOOL WEIBULL LOCATION TEST Y TAG
!     REFERENCE --JOHN MCCOOL (1998), "INFERENCE ON THE WEIBULL LOCATION
!                 PARAMETER, JOURNAL OF QUALITY TECHNOLOGY, VOL. 30,
!                 NO. 2, PP. 119-126.
!               --JOHN MCCOOL (2012), "USING THE WEIBULL DISTRIBUTION:
!                 RELIABILITY, MODELING, AND INFERENCE", WILEY,
!                 PP. 301-307.
!               --HORST RINNE (2009), "THE WEIBULL DISTRIBUTION: A
!                 HANDBOOK", CRC PRESS, PP. 640-642.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATIION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/8
!     ORIGINAL VERSION--AUGUST    2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
!
      DOUBLE PRECISION DTEMP1(*)
      INTEGER          ITEMP1(*)
!
      PARAMETER (NUMALP=7)
      REAL ALPHA(NUMALP)
      REAL CVAL(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       50.0, 75.0, 90.0, 95.0, 97.5, 99.0, 99.9/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMC'
      ISUBN2='W2  '
      IERROR='NO'
!
      STATVA=CPUMIN
      STATCD=CPUMIN
      PVAL=CPUMIN
      CUT50=CPUMIN
      CUT75=CPUMIN
      CUT90=CPUMIN
      CUT95=CPUMIN
      CUT975=CPUMIN
      CUT99=CPUMIN
      CUT999=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MCW2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMCW2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IFORSW,N
   52   FORMAT('IBUGA3,ISUBRO,IFORSW,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)IVARID(1),IVARI2(1),IVARID(2),IVARI2(2)
   53   FORMAT('IVARID(1),IVARI2(1),IVARID(2),IVARI2(2) = ',   &
               A4,A4,2X,A4,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
      ICASE='CV'
      CALL DPMCW3(Y,TAG,N,TEMP4,TEMP1,TEMP2,TEMP3,DTEMP1,ITEMP1,   &
                  ICASE,ISEED,MAXNXT,   &
                  STATVA,STATCD,PVAL,CV50,CV90,CV95,   &
                  CA,CL,IR,IR1,IMCCR1,IRANAL,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CUT50=CV50
      CUT75=TEMP3(7500)
      CUT90=CV90
      CUT95=CV95
      CUT975=TEMP3(9750)
      CUT99=TEMP3(9900)
      CUT999=TEMP3(9990)
      CVAL(1)=CUT50
      CVAL(2)=CUT75
      CVAL(3)=CUT90
      CVAL(4)=CUT95
      CVAL(5)=CUT975
      CVAL(6)=CUT99
      CVAL(7)=CUT999
!
!               ******************************************
!               **   STEP 43--                          **
!               **   WRITE OUT EVERYTHING               **
!               ******************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCW2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='McCool Weibull Location Test'
      NCTITL=28
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Censoring Variable: '
      WRITE(ITEXT(ICNT)(21:24),'(A4)')IVARID(2)(1:4)
      WRITE(ITEXT(ICNT)(25:28),'(A4)')IVARI2(2)(1:4)
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: mu = 0'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: mu > 0'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Uncensored Observations:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=REAL(IR)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Value of R1:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=REAL(IR1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Value of Shape Parameter for All Data:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=CA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Value of Shape Parameter for R1 Data:'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=CL
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF of Test Statistic:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value for Test Statistic:'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=PVAL
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 5010 I=1,NUMROW
        NTOT(I)=15
 5010 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCW2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MCW2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Upper 1-Tailed Test)'
      NCTITL=33
!
      DO 5030 J=1,5
        DO 5040 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 5040   CONTINUE
 5030 CONTINUE
!
      ITITL2(2,1)='Null'
      NCTIT2(2,1)=4
      ITITL2(3,1)='Hypothesis'
      NCTIT2(3,1)=10
!
      ITITL2(2,2)='Significance'
      NCTIT2(2,2)=12
      ITITL2(3,2)='Level'
      NCTIT2(3,2)=5
!
      ITITL2(2,3)='Test '
      NCTIT2(2,3)=4
      ITITL2(3,3)='Statistic'
      NCTIT2(3,3)=9
!
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Region (>=)'
      NCTIT2(3,4)=11
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 5050 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=12
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.2 .OR. I.EQ.5)THEN
          ITYPCO(I)='ALPH'
        ENDIF
        IWHTML(1)=150
        IWHTML(2)=125
        IWHTML(3)=150
        IWHTML(4)=150
        IWHTML(5)=150
        IINC=1600
        IINC2=1400
        IINC3=2200
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC2
        IWRTF(4)=IWRTF(3)+IINC
        IWRTF(5)=IWRTF(4)+IINC
!
        DO 5060 J=1,NUMALP
!
          IVALUE(J,1)='mu = 0'
          NCVALU(J,1)=6
          AMAT(J,3)=STATVA
          AMAT(J,4)=CVAL(J)
          IVALUE(J,5)(1:6)='REJECT'
          IF(STATVA.LT.CVAL(J))THEN
            IVALUE(J,5)(1:6)='ACCEPT'
          ENDIF
          NCVALU(J,5)=6
!
          ALPHAT=ALPHA(J)
          ALPHAT=ALPHAT
          WRITE(IVALUE(J,2)(1:4),'(F4.1)')ALPHAT
          IVALUE(J,2)(5:5)='%'
          NCVALU(J,2)=5
 5060   CONTINUE
!
 5050 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MCW2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMCW2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2(2X,A4))
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATCD,PVAL
 9013   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMCW2
      SUBROUTINE DPMCW3(Y,TAG,N,TAG2,TEMP1,TEMP2,TEMP3,DTEMP1,ITEMP1,   &
                        ICASE,ISEED,MAXNXT,   &
                        STATVA,STATCD,PVAL,CV50,CV90,CV95,   &
                        CA,CL,IR,IR1,IMCCR1,IRANAL,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE PERFORMS MCCOOL'S TEST FOR DISTINGUISHING
!              BETWEEN A 2-PARAMETER WEIBULL VERSUS A 3-PARAMETER
!              WEIBULL.  THIS TEST IS CURRENTLY SUPPORTED FOR SAMPLE
!              SIZES BETWEEN 10 AND 100.
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION RESPONSE VARIABLE.
!                       X      = A TAG VARIABLE WHERE "1" INDICATES AN
!                                UNCENSORED OBSERVATION AND "0" INDICATES
!                                A CENSORED OBSERVATION.
!                     --N      = AN INTEGER PARAMETER THAT SPECIFIES THE
!                                NUMBER OF VALUES IN THE RESPONSE
!                                VARIABLE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE DOUBLE WEIBULL DISTRIBUTION
!             WITH TAIL LENGHT PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE --JOHN MCCOOL (1998), "INFERENCE ON THE WEIBULL LOCATION
!                 PARAMETER, JOURNAL OF QUALITY TECHNOLOGY, VOL. 30,
!                 NO. 2, PP. 119-126.
!               --JOHN MCCOOL (2012), "USING THE WEIBULL DISTRIBUTION:
!                 RELIABILITY, MODELING, AND INFERENCE", WILEY,
!                 PP. 301-307.
!               --HORST RINNE (2009), "THE WEIBULL DISTRIBUTION: A
!                 HANDBOOK", CRC PRESS, PP. 640-642.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/8
!     ORIGINAL VERSION--AUGUST    2013.
!
!---------------------------------------------------------------------
!
      REAL Y(*)
      REAL TAG(*)
      REAL TAG2(*)
      REAL TEMP1(*)
      REAL TEMP2(*)
      REAL TEMP3(*)
      DOUBLE PRECISION DTEMP1(*)
      INTEGER ITEMP1(*)
!
      CHARACTER*4 ICASE
      CHARACTER*4 IRANAL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IDIR
      CHARACTER*4 IRANSV
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBRO.EQ.'MCW3' .OR. IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPMCW3')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,MAXNXT,N
   52   FORMAT('IBUGA3,ISUBRO,ICASE,MAXNXT,N = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      STATVA=CPUMIN
      STATCD=CPUMIN
      PVAL=CPUMIN
      IMCCR1=0
!
      IRANSV=IRANAL
      IRANAL='FINC'
      ISEESV=ISEED
      IF(ISEED.EQ.305)THEN
        ISEED=23709
      ENDIF
!
!     ESTIMATE THE SHAPE PARAMETER BASED ON ALL OF THE DATA
!
      IR=0
      DO 100 I=1,N
        AVAL=TAG(I)
        IF(ABS(AVAL).LE.0.5)THEN
          TAG(I)=0.0
        ELSE
          TAG(I)=1.0
          IR=IR+1
        ENDIF
  100 CONTINUE
!
      IERR=0
      IF(IMCCR1.GT.0 .AND. IMCCR1.LT.IR)THEN
        IR1=IMCCR1
        NMAX=N
      ELSE
        NMAX=100
        IF(N.LE.30)THEN
          IR1=5
          IF(IR.LT.6)THEN
            IERR=1
          ENDIF
        ELSEIF(N.GT.30 .AND. N.LT.40)THEN
          IR1=6
          IF(IR.LT.7)THEN
            IERR=1
          ENDIF
        ELSEIF(N.GE.40 .AND. N.LE.60)THEN
          IR1=7
          IF(IR.LT.8)THEN
            IERR=1
          ENDIF
        ELSEIF(N.GT.60 .AND. N.LT.80)THEN
          IR1=8
          IF(IR.LT.9)THEN
            IERR=1
          ENDIF
        ELSEIF(N.GE.80 .AND. N.LE.100)THEN
          IR1=9
          IF(IR.LT.10)THEN
            IERR=1
          ENDIF
        ENDIF
      ENDIF
!
      IF(IERR.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,91)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,191)
  191   FORMAT('      THERE ARE AN INSUFFICIENT NUMBER OF UNCENSORED ',   &
               'OBSERVATIONS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,193)IR
  193   FORMAT('      NUMBER OF UNCENSORED OBSERVATIONS IS         ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,195)IR1
  195   FORMAT('      MINIMUM NUMBER OF UNCENSORED OBSERVATIONS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.LT.10 .OR. N.GT.NMAX)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,91)
   91   FORMAT('***** ERROR IN MCCOOL WEIBULL TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,93)NMAX
   93   FORMAT('      THIS TEST IS CURRENTLY ONLY SUPPORTED FOR ',   &
               'SAMPLE SIZES BETWEEN 10 AND ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,95)N
   95   FORMAT('      THE NUMBER OF RESPONSE VALUES IS   ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     ESTIMATE BASED ON ALL DATA
!
      CALL WEIM2B(Y,TAG,N,MAXNXT,   &
                  TEMP1,DTEMP1,ITEMP1,   &
                  CA,   &
                  ISUBRO,IBUGA3,IERROR)
!
!     NOW ESTIMATE BASED ON THE FIRST "R1"
!
      DO 110 I=1,N
        TAG2(I)=TAG(I)
  110 CONTINUE
!
      ICNT=0
      DO 200 I=1,N
        IF(TAG2(I).GE.0.5)THEN
          ICNT=ICNT+1
          IF(ICNT.GT.IR1)THEN
            TAG2(I)=0.0
            TEMP3(I)=Y(IR1)
          ELSE
            TEMP3(I)=Y(I)
          ENDIF
        ENDIF
  200 CONTINUE
      CALL WEIM2B(TEMP3,TAG2,N,MAXNXT,   &
                  TEMP1,DTEMP1,ITEMP1,   &
                  CL,   &
                  ISUBRO,IBUGA3,IERROR)
!
      STATVA=CL/CA
!
!     NOW PERFORM SIMULATIONS TO OBTAIN CRITICAL VALUES.  GENERATE
!     10,000 SAMPLES FROM A 2-PARAMETER WEIBULL.  BASED ON MCCOOL'S
!     PAPER, USE A SHAPE PARAMETER OF 1 AND A TENTH PERCENTILE OF 1.0.
!     USE THE FOLLOWING FORMULA (BASED ON MENON'S ESTIMATES FOR THE
!     2-PARAMETER WEIBULL) FROM PP. 132-134 OF MCCOOL'S BOOK:
!
!            Xhat(p) = (k(p))**(1/BETAHAT)*SCALE
!
!     WHERE
!
!            Xhat(p)   = THE ESTIMATE OF THE p-TH PERCENTILE
!            k(p)      = THE DESIRED PERCENTILE (0.10 IN THIS CASE)
!            BETAHAT   = THE ESTIMATED SHAPE PARAMETER (WE ARE USING
!                        A VALUE OF 1 FOR THE PURPOSES OF THE MONTE
!                        CARLO SIMULATION)
!
!     THIS MEANS THAT TO OBTAIN A TENTH PERCENTILE OF 1, WE USE
!
!           SCALE = 1/0.10**(1/BETA)
!                 = 10 FOR BETA = 1
!
      IF(ICASE.EQ.'STAT')GO TO 9000
      NMCSAM=10000
      SCALE=10.0
      GAMMA=1.0
!CCCC GAMMA=CA
!CCCC SCALE=1.0/0.10**(1.0/GAMMA)
      MINMAX=1
!
      ICNT=0
      DO 300 I=1,NMCSAM
        CALL WEIRAN(N,GAMMA,MINMAX,ISEED,TEMP2)
        CALL SORT(TEMP2,N,TEMP2)
        DO 310 J=1,N
          TEMP2(J)=SCALE*TEMP2(J)
  310   CONTINUE
!
        DO 320 J=1,IR
          TAG2(J)=1.0
  320   CONTINUE
        IF(IR.LT.N)THEN
          DO 330 J=IR+1,N
             TAG2(J)=0.0
  330     CONTINUE
        ENDIF
        CALL WEIM2B(TEMP2,TAG2,N,MAXNXT,   &
                    TEMP1,DTEMP1,ITEMP1,   &
                    CAT,   &
                    ISUBRO,IBUGA3,IERROR)
!
        DO 340 J=1,IR1
          TAG2(J)=1.0
  340   CONTINUE
        DO 350 J=IR1+1,N
           TAG2(J)=0.0
           TEMP2(J)=TEMP2(IR1)
  350   CONTINUE
        CALL WEIM2B(TEMP2,TAG2,N,MAXNXT,   &
                    TEMP1,DTEMP1,ITEMP1,   &
                    CLT,   &
                    ISUBRO,IBUGA3,IERROR)
!
        TEMP3(I)=CLT/CAT
!
  300 CONTINUE
!
!     NOW DETERMINE REFERENCE VALUES AND P-VALUE
!
      IDIR='UPPE'
      CALL DPGOF8(TEMP3,NMCSAM,STATVA,PVAL,IDIR,   &
                  IBUGA3,ISUBRO,IERROR)
      STATCD=1.0 - PVAL
      CV50=TEMP3(5000)
      CV90=TEMP3(9000)
      CV95=TEMP3(9500)
!
 9000 CONTINUE
      IRANAL=IRANSV
      ISEED=ISEESV
!
      IF(ISUBRO.EQ.'MCW3' .OR. IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9001)
 9001   FORMAT('AT THE BEGINNING OF DPMCW3')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9002)IERROR,STATVA,STATCD,PVAL
 9002   FORMAT('IERROR,STATVA,STATCD,PVAL = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)IR,IR1,CL,CA
 9003   FORMAT('IR,IR1,CL,CA = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMCW3
      SUBROUTINE DPMDCL(XMED,QUASE,N,ALPHA,IWRITE,ALOWLM,AUPPLM,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--FOR A GIVEN MEAN, SD, N, AND ALPHA, COMPUTE THE
!              LOWER AND UPPER CONFIDENCE LIMITS FOR THE MEDIAN.
!              THIS IS PRIMARILY USED BY THE CROSS TABULATE COMMAND.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/5
!     ORIGINAL VERSION--MAY       2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      REAL XMEAN
      REAL QUASE
      REAL ALPHA
      REAL ALOWLM
      REAL AUPPLM
      INTEGER N
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMD'
      ISUBN2='CL  '
      ALOWLM=CPUMIN
      AUPPLM=CPUMIN
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMDCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE
   52   FORMAT('IBUGA3,IWRITE = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)XMEAN,N,ALPHA
   53   FORMAT('XMEAN,N,ALPHA = ',G15.7,I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************
!               **  STEP 1--                  **
!               **  CHECK FOR INPUT ERRORS    **
!               ********************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR IN DPMDCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,152)
  152   FORMAT('      THE INPUT SAMPLE SIZE FOR THE MEDIAN CONFIDENCE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,154)
  154   FORMAT('      LIMITS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,157)N
  157   FORMAT('      THE INPUT SAMPLE SIZE            = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(N.LT.3)THEN
        ALOWLM=XMED
        AUPPLM=XMED
        GO TO 9000
      ENDIF
!
      ALPHSV=ALPHA
      IF(ALPHA.GT.1.0 .AND. ALPHA.LE.100.0)ALPHA=ALPHA/100.0
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,171)
  171   FORMAT('***** ERROR IN DPMDCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)
  172   FORMAT('      THE VALUE OF ALPHA IS OUTSIDE THE (0,1) ',   &
               'INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,177)ALPHA
  177   FORMAT('      THE VALUE OF ALPHA = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  COMPUTE THE MEAN CONFIDENCE INTERVALS **
!               ********************************************
!
      ALP=ALPHA
      IF(ALP.LT.0.5)THEN
        ALP=1.0-ALP
      ENDIF
!
      ALP=1.0 - ALP
      P1=ALP/2.0
      P2=1.0-(ALP/2.0)
      AN=REAL(N)
!
      AN=REAL(N)
      CALL NORPPF(P2,ZALPHA)
      ALOWLM=XMED - ZALPHA*QUASE
      AUPPLM=XMED + ZALPHA*QUASE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMDCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IERROR,ALOWLM,AUPPLM
 9014   FORMAT('IERROR,ALOWLM,AUPPLM = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMDCL
      SUBROUTINE DPMECL(XMEAN,XSD,N,ALPHA,IWRITE,ALOWLM,AUPPLM,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--FOR A GIVEN MEAN, SD, N, AND ALPHA, COMPUTE THE
!              LOWER AND UPPER CONFIDENCE LIMITS FOR THE MEAN.
!              THIS IS PRIMARILY USED BY THE CROSS TABULATE COMMAND.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/5
!     ORIGINAL VERSION--MAY       2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      REAL XMEAN
      REAL ALPHA
      REAL ALOWLM
      REAL AUPPLM
      INTEGER N
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPME'
      ISUBN2='CL  '
      IERROR='NO'
      AN=REAL(N)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMECL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,IWRITE
   52   FORMAT('IBUGA3,IWRITE = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)XMEAN,N,ALPHA
   53   FORMAT('XMEAN,N,ALPHA = ',G15.7,I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************
!               **  STEP 1--                  **
!               **  CHECK FOR INPUT ERRORS    **
!               ********************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR IN DPMECL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,152)
  152   FORMAT('      THE INPUT SAMPLE SIZE FOR THE MEAN CONFIDENCE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,154)
  154   FORMAT('      LIMITS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,157)N
  157   FORMAT('      THE INPUT SAMPLE SIZE            = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      ALPHSV=ALPHA
      IF(ALPHA.GT.1.0 .AND. ALPHA.LE.100.0)ALPHA=ALPHA/100.0
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,171)
  171   FORMAT('***** ERROR IN DPMECL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)
  172   FORMAT('      THE VALUE OF ALPHA IS OUTSIDE THE (0,1) ',   &
               'INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,177)ALPHA
  177   FORMAT('      THE VALUE OF ALPHA = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  COMPUTE THE MEAN CONFIDENCE INTERVALS **
!               ********************************************
!
      ALP=ALPHA
      IF(ALP.LT.0.5)THEN
        ALP=1.0-ALP
      ENDIF
!
      ALP=1.0 - ALP
      P1=ALP/2.0
      P2=1.0-(ALP/2.0)
      AN=REAL(N)
!
      IF(N.LE.1)THEN
        ALOWLM=XMEAN
        AUPPLM=XMEAN
      ELSE
        IDF=N-1
        CALL TPPF(P2,REAL(IDF),ZALPHA)
        ALOWLM=XMEAN - ZALPHA*XSD/SQRT(AN)
        AUPPLM=XMEAN + ZALPHA*XSD/SQRT(AN)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMECL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ZALPHA,XSD,SQRT(AN)
 9013   FORMAT('ZALPHA,XSD,SQRT(AN) = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ALOWLM,AUPPLM
 9014   FORMAT('ALOWLM,AUPPLM = ',G15.7,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)ALPHA,ALP,P1,P2
 9015   FORMAT('ALPHA,ALP,P1,P2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMECL
      SUBROUTINE DPMED3(X1,X2,X3,XMED3,IBUGG3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE MEDIAN
!              OF THE 3 NUMBERS X1, X2, AND X3.
!     OUTPUT ARGUMENTS--XMED3  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MEDIAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MEDIAN.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MCNEIL, INTERACTIVE DATA ANALYSIS
!                 1977, PAGE 145
!                 (= SOURCE OF ALGORITHM).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION--JULY      1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGG3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMED3--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG3
   52 FORMAT('IBUGG3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)X1,X2,X3
   53 FORMAT('X1,X2,X3 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **********************
!               **  COMPUTE MEDIAN  **
!               **********************
!
      XMED3=X2
      IF(X1.LE.X2.AND.X2.LE.X3)GO TO 9000
      IF(X3.LE.X2.AND.X2.LE.X1)GO TO 9000
!
      XMED3=X1
      IF(X2.LE.X1.AND.X1.LE.X3)GO TO 9000
      IF(X3.LE.X1.AND.X1.LE.X2)GO TO 9000
!
      XMED3=X3
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMED3--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG3,IERROR
 9012 FORMAT('IBUGG3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)X1,X2,X3
 9013 FORMAT('X1,X2,X3 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)XMED3
 9014 FORMAT('XMED3 = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMED3
      SUBROUTINE DPMEDM(NLAB,AMEAN,ASD,TEMP1,TEMP2,   &
                        IWRITE,ICAPSW,ICAPTY,NUMDIG,MAXNXT,   &
                        XMEDME,SEMEK1,SEMEK2,ALOWCL,AUPPCL,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE A CONSENSUS VALUE BASED ON THE MEDIAN OF THE
!              MEANS.  THIS IS A MORE ROBUST VERSION OF THE MEAN OF
!              MEANS METHOD (I.E., PROTECTS AGAINST OUTLIER LABS).
!              THE ASSOCIATED UNCERTAINTY IS:
!
!                u(med(x)) = SQRT(PI/(2*NLAB))*MADe
!
!              WHERE MADe = 1.483*MAD WITH MAD DENOTING THE MEDIAN
!              ABSOLUTE DEVIATION.
!
!              THE ADVANTAGE OF THIS METHOD IS THAT IT PROTECTS AGAINST
!              OUTLYING LAB MEANS.  AS WITH MEAN OF MEANS METHOD, THE
!              DISADVANTAGE OF THIS METHOD IS THAT IT DOES NOT TAKE
!              WITHIN-LAB VARIANCE INTO ACCOUNT.
!
!     REFERENCE--CCQM GUIDANCE note: Estimation of a consensus KCRV and
!                associated Degrees of Equivalence", Version: 10,
!                2013-04-12, pp. 25-26.
!     PRINTING--YES
!     SUBROUTINES NEEDED--MEDIAN, MAD
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/03
!     ORIGINAL VERSION--MARCH     2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      DIMENSION AMEAN(*)
      DIMENSION ASD(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI /3.14159265/
!
!-----START POINT------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEDM')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMEDM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NLAB
   52   FORMAT('NLAB = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,NLAB
          WRITE(ICOUT,62)I,AMEAN(I),ASD(I)
   62     FORMAT('I,AMEAN(I),ASD(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
      IERROR='NO'
      ISUBN1='DPME'
      ISUBN2='DM  '
!
!     STEP 1: COMPUTE THE MEDIAN OF THE MEANS
!
      CALL MEDIAN(AMEAN,NLAB,IWRITE,TEMP1,MAXNXT,XMEDME,IBUGA3,IERROR)
!
!     STEP 2: COMPUTE THE MADe
!
      CALL MAD(AMEAN,NLAB,IWRITE,TEMP1,TEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
      XMADE=XMAD/0.67449
      SEMEK1=SQRT(PI/(2.0*REAL(NLAB)))*XMADE
      SEMEK2=2.0*SEMEK1
!
!     STEP 3: COMPUTE 95% CONFIDENCE INTERVAL
!
      ALPHA=0.975
      CALL NORPPF(ALPHA,TVAL)
      ALOWCL=XMEDME - TVAL*SEMEK1
      AUPPCL=XMEDME + TVAL*SEMEK1
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)='14. Method: Median of Means'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Median of Lab Means:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=XMEDME
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Scaled Median Absolute Deviation of Lab Means:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=XMADE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMEK1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SEMEK2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Lower 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=ALOWCL
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Upper 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=AUPPCL
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Note: Median of Means Best Usage:'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='          Number of Labs >= 5:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 310 I=1,NUMROW
        NTOT(I)=15
  310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEDM')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMEDM--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XMEDME,SEMEK1,SEMEK2,ALOWCL,AUPPCL
 9015   FORMAT('XMEDME,SEMEK1,SEMEK2,ALOWCL,AUPPCL = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMEDM
      SUBROUTINE DPMEPO(ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT A MEDIAN POLISH.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--FEBRUARY  1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988. ADD LOFCDF
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!                                       MOVE DIMENSIONING OF Y2 AND Z
!     UPDATED         --MAY       2011. USE DPPARS
!     UPDATED         --MAY       2011. SUPPORT FOR HTML, LATEX, RTF OUTPUT
!     UPDATED         --JULY      2019. TWEAK SCRATCH STORAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IREPU
      CHARACTER*4 IRESU
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      PARAMETER (MAXLEV=500)
      PARAMETER (MAXFAC=5)
!
      DIMENSION PRED2(MAXOBV)
      DIMENSION RES2(MAXOBV)
      DIMENSION W(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Z(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
!
      DIMENSION F1(MAXOBV,MAXFAC)
      DIMENSION F1ID(MAXLEV,MAXFAC)
      DIMENSION F1N(MAXLEV,MAXFAC)
      DIMENSION F1TYP(MAXLEV,MAXFAC)
      DIMENSION F1MEAN(MAXLEV,MAXFAC)
      DIMENSION F1EFFE(MAXLEV,MAXFAC)
      DIMENSION F1EFSD(MAXLEV,MAXFAC)
!
      DIMENSION B(MAXLEV)
      DIMENSION SDB(MAXLEV)
      DIMENSION FCUM(MAXLEV)
      DIMENSION Y2MED(MAXLEV)
      DIMENSION N1(MAXFAC)
      DIMENSION ISET(MAXFAC)
      DIMENSION AN1(MAXFAC)
      DIMENSION E1(MAXFAC)
      DIMENSION SS1(MAXFAC)
      DIMENSION RESMS1(MAXFAC)
      DIMENSION FVAL(MAXFAC)
      DIMENSION F1CDF2(MAXFAC)
      DIMENSION RSD(MAXFAC)
!
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),F1(1,1))
      EQUIVALENCE (GARBAG(IGAR10),PRED2(1))
      EQUIVALENCE (GARBAG(JGAR11),RES2(1))
      EQUIVALENCE (GARBAG(JGAR12),W(1))
      EQUIVALENCE (GARBAG(JGAR13),Y2(1))
      EQUIVALENCE (GARBAG(JGAR14),B(1))
      EQUIVALENCE (GARBAG(JGAR15),SDB(1))
      EQUIVALENCE (GARBAG(JGAR16),FCUM(1))
      EQUIVALENCE (GARBAG(JGAR17),Y2MED(1))
      EQUIVALENCE (GARBAG(JGAR18),F1ID(1,1))
      EQUIVALENCE (GARBAG(JGAR19),F1N(1,1))
      EQUIVALENCE (GARBAG(IGAR11),F1TYP(1,1))
      EQUIVALENCE (GARBAG(IGAR12),F1MEAN(1,1))
      EQUIVALENCE (GARBAG(IGAR13),F1EFFE(1,1))
      EQUIVALENCE (GARBAG(IGAR14),F1EFSD(1,1))
      EQUIVALENCE (GARBAG(IGAR15),AN1(1))
      EQUIVALENCE (GARBAG(IGAR15+100),E1(1))
      EQUIVALENCE (GARBAG(IGAR15+200),SS1(1))
      EQUIVALENCE (GARBAG(IGAR15+300),RESMS1(1))
      EQUIVALENCE (GARBAG(IGAR15+400),FVAL(1))
      EQUIVALENCE (GARBAG(IGAR15+500),F1CDF2(1))
      EQUIVALENCE (GARBAG(IGAR15+600),RSD(1))
      EQUIVALENCE (GARBAG(IGAR16),TEMP1(1))
      EQUIVALENCE (GARBAG(IGAR17),Z(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPME'
      ISUBN2='PO  '
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               *******************************************
!               **  TREAT THE MEDIAN POLISH        CASE  **
!               *******************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MEPO')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMEPO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'MEDI'.AND.IHARG(1).EQ.'POLI')THEN
        ILASTC=1
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='MEIDAN POLISH'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=2
      MAXNVA=MAXFAC+1
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      NUMFAC=NUMVAR-1
      J=0
      IMAX=NRIGHT(1)
      IF(NQ.LT.NRIGHT(1))IMAX=NQ
      DO 660 I=1,IMAX
        IF(ISUB(I).EQ.0)GO TO 660
        J=J+1
!
        IJ=MAXN*(ICOLR(1)-1)+I
        IF(ICOLR(1).LE.MAXCOL)Y(J)=V(IJ)
        IF(ICOLR(1).EQ.MAXCP1)Y(J)=PRED(I)
        IF(ICOLR(1).EQ.MAXCP2)Y(J)=RES(I)
        IF(ICOLR(1).EQ.MAXCP3)Y(J)=YPLOT(I)
        IF(ICOLR(1).EQ.MAXCP4)Y(J)=XPLOT(I)
        IF(ICOLR(1).EQ.MAXCP5)Y(J)=X2PLOT(I)
        IF(ICOLR(1).EQ.MAXCP6)Y(J)=TAGPLO(I)
!
        DO 659 LL=1,NUMFAC
          ICOLT=ICOLR(LL+1)
          IJ=MAXN*(ICOLT-1)+I
          IF(ICOLT.LE.MAXCOL)F1(J,LL)=V(IJ)
          IF(ICOLT.EQ.MAXCP1)F1(J,LL)=PRED(I)
          IF(ICOLT.EQ.MAXCP2)F1(J,LL)=RES(I)
          IF(ICOLT.EQ.MAXCP3)F1(J,LL)=YPLOT(I)
          IF(ICOLT.EQ.MAXCP4)F1(J,LL)=XPLOT(I)
          IF(ICOLT.EQ.MAXCP5)F1(J,LL)=X2PLOT(I)
          IF(ICOLT.EQ.MAXCP6)F1(J,LL)=TAGPLO(I)
 659    CONTINUE
!
  660 CONTINUE
      NS=J
!
!               **************************************************
!               **  STEP 8--                                    **
!               **  PREPARE FOR ENTRANCE INTO DPMED2--          **
!               **  SET THE WEIGHT VECTOR TO UNITY THROUGHOUT.  **
!               **************************************************
!
      ISTEPN='8'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 680 I=1,NS
        W(I)=1.0
  680 CONTINUE
!
!               ***********************************
!               **  STEP 9--                     **
!               **  CARRY OUT THE MEDIAN POLISH  **
!               ***********************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MEPO')THEN
        ISTEPN='9'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,711)
  711   FORMAT('***** FROM DPMEPO, AS WE ARE ABOUT TO CALL DPMEP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,712)ICOLR(1),MAXN,NS,NUMFAC
  712   FORMAT('ICOLR(1),MAXN,NS,NUMFAC = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 715 I=1,NS
          WRITE(ICOUT,716)I,Y(I),(F1(I,LL),LL=1,MAXFAC),W(I)
  716     FORMAT('I,Y(I),F1(I),F2(I),F3(I),F4(I),F5(I),W(I) = ',   &
                 I6,2X,7F10.5)
          CALL DPWRST('XXX','BUG ')
  715   CONTINUE
      ENDIF
!
      CALL DPMEP2(Y,F1,W,NS,NUMFAC,   &
                  MAXOBV,MAXLEV,MAXFAC,   &
                  B,SDB,FCUM,   &
                  REPSD,REPDF,RESSD,RESDF,PRED2,RES2,ALFCDF,   &
                  Y2,Z,TEMP1,   &
                  F1ID,F1N,F1TYP,F1MEAN,F1EFFE,F1EFSD,Y2MED,   &
                  N1,ISET,AN1,E1,SS1,RESMS1,FVAL,F1CDF2,RSD,   &
                  ICAPSW,ICAPTY,IFORSW,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               ***************************************
!               **  STEP 10--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='10'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOLPR=MAXCP1
      ICOLRE=MAXCP2
      IREPU='ON'
      IRESU='ON'
      CALL UPDAPR(ICOLPR,ICOLRE,PRED2,RES2,PRED,RES,ISUB,NLEFT,   &
      IREPU,REPSD,REPDF,IRESU,RESSD,RESDF,ALFCDF,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,ILOCN,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MEPO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMEPO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NS,NUMFAC
 9014   FORMAT('NS,NUMFAC = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMEPO
      SUBROUTINE DPMEP2(Y,F1,W,N,NUMFAC,   &
                        MAXOBV,MAXLEV,MAXFAC,   &
                        B,SDB,FCUM,   &
                        REPSD,REPDF,RESSD,RESDF,PRED2,RES2,ALFCDF,   &
                        Y2,Z,TEMP1,   &
                        F1ID,F1N,F1TYP,F1MEAN,F1EFFE,F1EFSD,Y2MED,   &
                        N1,ISET,AN1,E1,SS1,RESMS1,FVAL,F1CDF2,RSD,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IBUGA3,ISUBRO,IERROR)
!
!CCCC JUNE, 1990.  MOVE DIMENSIONING OF Y2 AND Z TO DPMEPO.
!
!     PURPOSE--PERFORM A MULTI-WAY MEDIAN POLISH
!              FOR 1, 2, 3, 4, OR 5 FACTORS.
!              THE ASSUMED MODEL IS RESPONSE = CONSTANT + FACTOR-1 EFFECT + ...
!                                              FACTOR-NUMFAC EFFECT + ERROR
!     NOTE-- LINES NEAR 390 NEED TO BE GENERALIZED FOR
!            UNEQUAL NUMBER OF OBS PER CELL.
!     PRINTING--YES
!     SUBROUTINES NEEDED--FCDF
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1978.
!     UPDATED         --NOVEMBER  1978.
!     UPDATED         --JULY      1979.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1988. ADD LOFCDF
!     UPDATED         --JUNE      1990. MOVE DIMENSIONING OF Y2 AND Z
!     UPDATED         --JANUARY   1996. MAKE MAXIMUM NUMBER OF LEVELS
!                                       SETTABLE VIA PARAMETER
!                                       STATEMENT (AND PUT IN CHECKS
!                                       FOR EXCEEDING THIS MAXIMUM)
!     UPDATED         --MAY       2011. USE DPDTA1 AND DPDT5B TO PRINT
!                                       TABLES (ADDS SUPPORT FOR HTML,
!                                       LATEX, RTF OUTPUT)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IREP
      CHARACTER*4 ICASBL
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
!CCCC JUNE, 1990.  MOVE DIMENSIONING OF Y2 AND Z TO DPMEPO
!CCCC       INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y2(*)
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION TEMP1(*)
      DIMENSION W(*)
      DIMENSION B(*)
      DIMENSION SDB(*)
      DIMENSION FCUM(*)
      DIMENSION PRED2(*)
      DIMENSION RES2(*)
      DIMENSION Y2MED(*)
      DIMENSION FVAL(*)
      DIMENSION RSD(*)
      DIMENSION AN1(*)
      DIMENSION E1(*)
      DIMENSION SS1(*)
      DIMENSION RESMS1(*)
      DIMENSION F1CDF2(*)
      DIMENSION N1(*)
      DIMENSION ISET(*)
!
      DIMENSION F1(MAXOBV,MAXLEV)
      DIMENSION F1ID(MAXLEV,MAXFAC)
      DIMENSION F1N(MAXLEV,MAXFAC)
      DIMENSION F1TYP(MAXLEV,MAXFAC)
      DIMENSION F1MEAN(MAXLEV,MAXFAC)
      DIMENSION F1EFFE(MAXLEV,MAXFAC)
      DIMENSION F1EFSD(MAXLEV,MAXFAC)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*30 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      IWRITE='OFF'
      ISUBN1='DPAN'
      ISUBN2='O2  '
!
      AN=N
      J1=0
      NIOLD=0
      MAXPAS=25
      CUTOFF=0.99
      GTYP=0.0
      FITCD2=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEP2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMEP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,NUMFAC,MAXLEV,MAXFAC
   52   FORMAT('N,NUMFAC,MAXLEV,MAXFAC = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),(F1(I,J),J=1,5),W(I)
   56     FORMAT('I,Y(I),F1(I),F2(I),F3(I),F4(I),F5(I),W(I) = ',   &
                 I8,7E11.3)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N
          WRITE(ICOUT,66)I,(F1MEAN(I,J),J=1,5)
   66     FORMAT('I,(F1MEAN(I,J),J=1,5) = ',I8,5G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN MEIDAN POLISH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE MEDIAN POLISH')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      WAS LESS THAN TWO.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)N
  104   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMFAC.LT.1.OR.NUMFAC.GT.MAXFAC)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,132)
  132   FORMAT('      THE NUMBER OF FACTORS FOR THE MEDIAN POLISH MUST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)MAXFAC
  133   FORMAT('      BE AT LEAST 1 AND AT MOST ',I6,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,134)NUMFAC
  134   FORMAT('      THE ENTERED NUMBER OF FACTORS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 140 I=1,N
        IF(Y(I).NE.HOLD)GO TO 149
  140 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,142)
  142 FORMAT('      ALL RESPONSE VARIABLE ELEMENTS FOR THE MEDIAN ',   &
             'POLISH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,143)HOLD
  143 FORMAT('      ARE IDENTICALLY EQUAL TO ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  149 CONTINUE
!
      DO 150 J=1,NUMFAC
        HOLD=F1(1,J)
        DO 155 I=1,N
          HOLD2=F1(I,J)
          IF(HOLD2.NE.HOLD)GO TO 150
  155   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** DIAGNOSTIC NOTE FROM MEDIAN POLISH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,152)J
  152   FORMAT('      ALL ELEMENTS OF FACTOR ',I5,' IN THE ',   &
               'MEDIAN POLISH')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)HOLD
  153   FORMAT('      ARE IDENTICALLY EQUAL TO ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
  150 CONTINUE
!
!               ***********************************************
!               **  STEP 1.1--                               **
!               **  DETERMINE THE NUMBER OF DISTINCT VALUES  **
!               **  FOR FACTOR 1                             **
!               ***********************************************
!
!CCCC JANUARY 1996.  CHECK FOR EXCEEDING MAXIMUM NUMBER OF LEVELS
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1159 I=1,MAXFAC
        N1(I)=0
 1159 CONTINUE
!
      DO 1160 K=1,NUMFAC
        N1(K)=0
        DO 160 I=1,N
          IF(N1(K).LE.0)GO TO 180
          DO 170 J=1,N1(K)
            IF(F1(I,K).EQ.F1ID(J,K))GO TO 160
  170     CONTINUE
  180     CONTINUE
          N1(K)=N1(K)+1
          IF(N1(K).GT.MAXLEV)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,190)MAXLEV,K
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
  190     FORMAT('      THE MAXIMUM NUMBER OF LEVELS, ',I10,   &
                 ' EXCEEDED FOR FACTOR ',I5)
          F1ID(N1(K),K)=F1(I,K)
  160   CONTINUE
        IF(N1(K).LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,165)K
  165     FORMAT('      N = 0 FOR FACTOR ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        AN1(K)=REAL(N1(K))
 1160 CONTINUE
!
!               **************************************
!               **  STEP 2--                        **
!               **  SORT THE LEVELS OF EACH FACTOR  **
!               **  SO AS TO PUT THEM IN ORDER FOR  **
!               **  PRESENTATION PURPOSES.          **
!               **************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEP2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1900 K=1,NUMFAC
        CALL SORT(F1ID(1,K),N1(K),F1ID(1,K))
 1900 CONTINUE
!
!               ********************************************
!               **  STEP 3--                              **
!               **  DETERMINE IF HAVE                     **
!               **  REPLICATION WITHIN CELLS.             **
!               **  IF SO, COMPUTE (FOR EACH CELL)--      **
!               **         1) NUMBER OF OBSERVATIONS;     **
!               **         2) MEAN;                       **
!               **         3) SUM OF SQUARED DEVIATIONS.  **
!               ********************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IREP='NO'
      IREPDF=0
      REPDF=0.0
      REPSS=0.0
      REPSD=0.0
!
      K=0
      ICASBL='YES'
      DO 3510 ISET1=1,N1(1)
        ISET(1)=ISET1
        DO 3520 ISET2=1,MAX(1,N1(2))
        ISET(2)=ISET2
        DO 3530 ISET3=1,MAX(1,N1(3))
        ISET(3)=ISET3
        DO 3540 ISET4=1,MAX(1,N1(4))
        ISET(4)=ISET4
        DO 3550 ISET5=1,MAX(1,N1(5))
        ISET(5)=ISET5
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEP2')THEN
            ISTEPN='3.5B'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,3511)ISET1,ISET2,ISET3,ISET4,ISET5
 3511       FORMAT('ISET1,ISET2,ISET3,ISET4,ISET5=',5I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          K=K+1
          CELLN=0.0
          CELLME=0.0
!
          NI=0
          DO 3560 I=1,N
            DO 3565 L=1,NUMFAC
              IF(F1(I,L).NE.F1ID(ISET(L),L))GO TO 3560
 3565       CONTINUE
            NI=NI+1
            Z(NI)=Y(I)
 3560     CONTINUE
!
          CELLN=REAL(NI)
          IF(NI.LE.0)GO TO 3590
          IF(NI.EQ.1)THEN
            CELLME=Z(NI)
            GO TO 3590
          ENDIF
          IREP='YES'
          SUM=0.0
          DO 3570 I=1,NI
            SUM=SUM+Z(I)
 3570     CONTINUE
          CELLME=SUM/CELLN
!
          IF(K.EQ.1)NIOLD=NI
          IF(NI.NE.NIOLD.AND.ICASBL.EQ.'YES')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
!CCCC       WRITE(ICOUT,3571)
!CCCC       CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            ICASBL='NO'
          ENDIF
          NIOLD=NI
          SUM=0.0
          DO 3580 I=1,NI
            SUM=SUM+(Z(I)-CELLME)**2
 3580     CONTINUE
          CELLV=SUM/(CELLN-1.0)
!
          REPSS=REPSS+SUM
          IREPDF=IREPDF+NI-1
 3590     CONTINUE
!3571     FORMAT('WARNING: UNBALANCED CASE DETECTED.  SOME ',
!CCCC1       'COMPUTATIONS MAY NOT BE ACCURATE.')
 3550   CONTINUE
 3540   CONTINUE
 3530   CONTINUE
 3520   CONTINUE
 3510 CONTINUE
!
      NUMCEL=K
      IF(IREP.EQ.'YES')THEN
        REPDF=IREPDF
        REPMS=REPSS/REPDF
        IF(REPMS.LE.0.0)REPSD=0.0
        IF(REPMS.GT.0.0)REPSD=SQRT(REPMS)
      ENDIF
!
!               ******************************
!               **  STEP 4--                **
!               **  COMPUTE THE GRAND MEAN  **
!               ******************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y,N,IWRITE,GMEAN,IBUGA3,IERROR)
      CALL SD(Y,N,IWRITE,GSD,IBUGA3,IERROR)
      GVAR=GSD**2
      CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXOBV,GMED,IBUGA3,IERROR)
      YMIN=Y(1)
      YMAX=Y(1)
      DO 4300 I=1,N
        IF(Y(I).LT.YMIN)YMIN=Y(I)
        IF(Y(I).GT.YMAX)YMAX=Y(I)
 4300 CONTINUE
      GRANGE=YMAX-YMIN
!
!               **********************************************
!               **  STEP 5.01--                             **
!               **  INITIALIZE ROW AND COLUMN MEDIANS TO 0  **
!               **********************************************
!
      ISTEPN='5.01'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 4500 I=1,N
        RES2(I)=Y(I)
 4500 CONTINUE
!
      DO 4510 L=1,NUMFAC
        DO 4520 J=1,N1(L)
          F1EFFE(J,L)=0.0
 4520   CONTINUE
 4510 CONTINUE
!
!               ******************************************
!               **  STEP 5.02--                         **
!               **  COMPUTE THE NUMBER OF OBSERVATIONS  **
!               **  IN EACH LEVEL OF EACH VARIABLE      **
!               ******************************************
!
      ISTEPN='5.02'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 4690 K=1,NUMFAC
        DO 4600 J=1,N1(K)
          SUM1=0.0
          DO 4620 I=1,N
            IF(F1(I,K).EQ.F1ID(J,K))THEN
              SUM1=SUM1+1.0
            ENDIF
 4620     CONTINUE
          F1N(J,K)=SUM1
 4600   CONTINUE
 4690 CONTINUE
!
!               *******************************************************
!               **  STEP 5.03--                                      **
!               **  DEFINE THE ITERATION LOOP FOR THE MEDIAN POLISH  **
!               *******************************************************
!
      ISTEPN='5.03'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 5000 IPASS=1,MAXPAS
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEP2')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5011)
 5011     FORMAT('******************************')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5012)IPASS
 5012     FORMAT('AT BEGINNING OF PASS ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5011)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               ***********************************************
!               **  STEP 5.1--                               **
!               **  FOR THIS PASS--                          **
!               **  DETERMINE (FOR EACH LEVEL OF FACTOR 1)   **
!               **      1) UPDATED MEDIAN;                   **
!               **      2) UPDATED RESIDUALS                 **
!               ***********************************************
!
        ISTEPN='5.1'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        DO 5100 L=1,NUMFAC
          DO 5110 J=1,N1(L)
!
            K=0
            DO 5120 I=1,N
              IF(F1(I,L).EQ.F1ID(J,L))THEN
                K=K+1
                Y2(K)=RES2(I)
              ENDIF
 5120       CONTINUE
            CALL MEDIAN(Y2,K,IWRITE,TEMP1,MAXOBV,Y2MED(J),IBUGA3,IERROR)
            F1EFFE(J,L)=F1EFFE(J,L)+Y2MED(J)
!
            DO 5140 I=1,N
              IF(F1(I,L).EQ.F1ID(J,L))THEN
                RES2(I)=RES2(I)-Y2MED(J)
              ENDIF
 5140       CONTINUE
!
 5110     CONTINUE
!
          IF(L.EQ.1)THEN
            Y3MED=0.0
            IF(NUMFAC.GE.2.AND.IPASS.GE.2)   &
            CALL MEDIAN(F1EFFE(1,2),N1(2),IWRITE,TEMP1,MAXOBV,Y3MED,   &
                        IBUGA3,IERROR)
            GTYP=GTYP+Y3MED
!
            DO 5160 J=1,N1(2)
              F1EFFE(J,2)=F1EFFE(J,2)-Y3MED
 5160       CONTINUE
          ELSE
            CALL MEDIAN(F1EFFE(1,1),N1(1),IWRITE,TEMP1,MAXOBV,Y3MED,   &
                        IBUGA3,IERROR)
            GTYP=GTYP+Y3MED
!
            DO 5165 J=1,N1(1)
              F1EFFE(J,1)=F1EFFE(J,1)-Y3MED
 5165       CONTINUE
          ENDIF
!
          DO 5170 J=1,N1(L)
            F1TYP(J,L)=GTYP+F1EFFE(J,L)
 5170     CONTINUE
!
          IF(IBUGA3.EQ.'ON'.OR. ISUBRO.EQ.'MEP2')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5181)L
 5181       FORMAT('***** AFTER THE SWEEP FOR FACTOR ',I1,'--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            DO 5182 I=1,N
              WRITE(ICOUT,5183)I,RES2(I)
 5183         FORMAT('I,RES2(I)  = ',I8,G15.7)
              CALL DPWRST('XXX','BUG ')
 5182       CONTINUE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            DO 5184 J=1,N1(L)
              WRITE(ICOUT,5185)J,F1EFFE(J,L)
 5185         FORMAT('J,F1EFFE(J,L) = ',I8,G15.7)
              CALL DPWRST('XXX','BUG ')
 5184       CONTINUE
            NFACT=L
            IF(L.EQ.1)NFACT=2
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            DO 5196 J=1,N1(NFACT)
              WRITE(ICOUT,5197)J,NFACT,F1EFFE(J,NFACT)
 5197         FORMAT('J,FACTOR,F1EFFE(J,NFACT) = ',2I8,G15.7)
              CALL DPWRST('XXX','BUG ')
 5196       CONTINUE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5188)GTYP
 5188       FORMAT('GTYP       = ',8X,G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 5100   CONTINUE
!
!               *************************************************************
!               **  STEP 5.6--                                             **
!               **  DETERMINE IF THE CHANGE IN THE  RESIDUALS              **
!               **  (FROM THIS PASS AS COMPARED TO THE PREVIOUS PASS)      **
!               **  IS SO SMALL THAT THE ITERATIONS SHOULD BE TERMINATED.  **
!               *************************************************************
!
        ISTEPN='5.6'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        SUM=0.0
        DO 5810 I=1,N
          SUM=SUM+ABS(RES2(I))
 5810   CONTINUE
        AARES=SUM/AN
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEP2')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5811)IPASS
 5811     FORMAT('***** AT THE CLOSE OF PASS ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5812)IPASS,AN,SUM,AARES,AARESO
 5812     FORMAT('IPASS,AN,SUM,AARES,AARESO = ',I8,4E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(AARES.LE.0.0)GO TO 5900
!
        IF(IPASS.EQ.1)THEN
          AARESO=AARES
          GO TO 5000
        ENDIF
!
        RATIO=AARES/AARESO
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEP2')THEN
          WRITE(ICOUT,5816)IPASS,AARES,AARESO,RATIO,CUTOFF
 5816     FORMAT('IPASS,AARES,AARESO,RATIO,CUTOFF = ',I8,4E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(RATIO.GE.CUTOFF)GO TO 5900
        AARESO=AARES
!
 5000 CONTINUE
!
 5900 CONTINUE
!
!               ******************************************
!               **  STEP 6--                            **
!               **  COMPUTE THE FOLLOWING--             **
!               **     1) PREDICTED VALUES;             **
!               **     2) RESIDUALS;                    **
!               **     3) RESIDUAL STANDARD DEVIATION;  **
!               **     4) RESIDUAL DEGREES OF FREEDOM;  **
!               **  IF HAVE REPLICATION,                **
!               **  THEN ALSO CARRY OUT                 **
!               **  THE LACK OF FIT F TEST.             **
!               ******************************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      RESSS=0.0
      IRESDF=0
      RESDF=0.0
      RESMS=0.0
      RESSD=0.0
      ALFCDF=(-999.99)
!
      DO 6000 I=1,N
        DO 6200 K=1,NUMFAC
          DO 6100 ISET1=1,N1(K)
            J1=ISET1
            IF(F1(I,K).EQ.F1ID(ISET1,K))GO TO 6115
 6100     CONTINUE
 6115     CONTINUE
          E1(K)=F1EFFE(J1,K)
 6200   CONTINUE
!
        PRED2(I)=GTYP
        DO 6310 K=1,NUMFAC
         PRED2(I)=PRED2(I)+E1(K)
 6310   CONTINUE
!
 6000 CONTINUE
!
      IRESDF=N-1
      DO 6910 K=1,NUMFAC
        IRESDF=IRESDF-(N1(K)-1)
 6910 CONTINUE
      RESDF=IRESDF
!
      SUM=0.0
      DO 6920 I=1,N
        SUM=SUM+RES2(I)*RES2(I)
 6920 CONTINUE
      RESSS=SUM
      RESMS=RESSS/RESDF
      IF(RESMS.LE.0.0)RESSD=0.0
      IF(RESMS.GT.0.0)RESSD=SQRT(RESMS)
!
      IF(IREP.EQ.'YES')THEN
        IFITDF=IRESDF-IREPDF
        FITDF=IFITDF
        IF(IFITDF.LE.0)GO TO 6990
        FITSS=RESSS-REPSS
        FITMS=FITSS/FITDF
        FITFVA=FITMS/REPMS
        CALL FCDF(FITFVA,IFITDF,IREPDF,FITCDF)
        FITCD2=100.0*FITCDF
        ALFCDF=FITCDF
      ENDIF
!
 6990 CONTINUE
!
!               ************************************************
!               **  STEP 7--                                  **
!               **  COMPUTE THE ESTIMATED STANDARD DEVIATION  **
!               **  OF THE GRAND MEAN                         **
!               **  AND THE ESTIMATED STANDARD DEVIATION      **
!               **  OF THE ESTIMATED EFFECTS.                 **
!               ************************************************
!
      ISTEPN='7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      GMEASD=0.0
      IF(N.GT.0)GMEASD=RESSD/SQRT(AN)
!
      DO 7190 K=1,NUMFAC
        DO 7100 ISET1=1,N1(K)
          ANI=F1N(ISET1,K)
          CONST=((1.0/ANI)-(1.0/AN))
          F1EFSD(ISET1,K)=0.0
          IF(CONST.GT.0.0)F1EFSD(ISET1,K)=RESSD*SQRT(CONST)
 7100   CONTINUE
 7190 CONTINUE
!
!               ********************************
!               **  STEP 8--                  **
!               **  PERFORM THE F TEST        **
!               **  TO TEST THE SIGNIFICANCE  **
!               **  OF EACH FACTOR            **
!               ********************************
!
      ISTEPN='8'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IRESDF.LE.0.OR.RESMS.LE.0.0)GO TO 8900
!
      DO 8190 K=1,NUMFAC
!
        SUM=0.0
        DO 8100 J=1,N1(K)
          SUM=SUM+F1N(J,K)*F1EFFE(J,K)*F1EFFE(J,K)
 8100   CONTINUE
        SS1(K)=SUM
        IDF1=N1(K)-1
        DF1=IDF1
        RESMS1(K)=SS1(K)/DF1
        IF(RESMS1(K).LE.0.0)RSD(K)=0.0
        IF(RESMS1(K).GT.0.0)RSD(K)=SQRT(RESMS1(K))
        FVAL(K)=RESMS1(K)/RESMS
        CALL FCDF(FVAL(K),IDF1,IRESDF,FCUM(K))
        F1CDF2(K)=100.0*FCUM(K)
 8190 CONTINUE
!
 8900 CONTINUE
!
!               *************************************************
!               **  STEP 9.1--                                 **
!               **  DETERMINE THE RESIDUAL STANDARD DEVIATION  **
!               **  FOR FACTOR K ONLY MODEL.                   **
!               *************************************************
!
      ISTEPN='9.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 9190 K=1,NUMFAC
        SUM=0.0
        DO 9100 I=1,N
        DO 9110 J=1,N1(K)
          J1=J
          IF(F1(I,K).EQ.F1ID(J,K))GO TO 9120
 9110   CONTINUE
 9120   CONTINUE
        WMEAN=F1TYP(J1,K)
        SUM=SUM+(Y(I)-WMEAN)**2
 9100   CONTINUE
        WSS1=SUM
        WDF1=AN-AN1(K)
        WVAR1=WSS1/WDF1
        WSD1=0.0
        IF(WVAR1.LE.0.0)WSD1=0.0
        IF(WVAR1.GT.0.0)WSD1=SQRT(WVAR1)
        RSD(K)=WSD1
 9190 CONTINUE
!
!               ********************************************************
!               **  STEP 10--                                         **
!               **  COPY OVER INTO THE OUTPUT VECTORS B(.) AND SDB(.)--*
!               **       1) THE GRAND MEAN;                           **
!               **       2) THE ESTIMATED EFFECTS;                    **
!               **       3) THE STANDARD DEVIATIONS OF GRAND MEAN AND **
!               **          EFFECTS.                                  **
!               ********************************************************
!
      ISTEPN='10'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      K=1
      B(K)=GTYP
      SDB(K)=GMEASD
!
      DO 10190 L=1,NUMFAC
!
        DO 10100 ISET1=1,N1(L)
          K=K+1
          B(K)=F1EFFE(ISET1,L)
          SDB(K)=F1EFSD(ISET1,L)
10100   CONTINUE
10190 CONTINUE
!
!               ****************************
!               **  STEP 11--             **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MEPO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT TABLES
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE(1:20)='  -Way Median Polish'
      WRITE(ITITLE(1:2),'(I2)')NUMFAC
      NCTITL=20
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Factors:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=REAL(NUMFAC)
      IDIGIT(ICNT)=0
      DO 11102 L=1,NUMFAC
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Levels for Factor   :'
        WRITE(ITEXT(ICNT)(29:30),'(I2)')L
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=REAL(N1(L))
        IDIGIT(ICNT)=0
11102 CONTINUE
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Distinct Cells:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=REAL(NUMCEL)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Grand Mean:'
      NCTEXT(ICNT)=11
      AVALUE(ICNT)=GMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Grand Median:'
      NCTEXT(ICNT)=13
      AVALUE(ICNT)=GMED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Median Polish Typical Value:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=GTYP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Grand Range:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=GRANGE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Grand Standard Deviation:'
      NCTEXT(ICNT)=25
      AVALUE(ICNT)=GSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Residual Standard Deviation:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=RESSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Residual Degrees of Freedom:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=REAL(IRESDF)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(IREP.EQ.'NO')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='No Replication Case:'
        NCTEXT(ICNT)=20
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Replication Case:'
        NCTEXT(ICNT)=17
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Replication Standard Deviation:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=REPSD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Replication Degrees of Freedom:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=REAL(IREPDF)
        IDIGIT(ICNT)=0
        IF(IFITDF.LT.1)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Lack of Fit F Test cannot be done'
          NCTEXT(ICNT)=33
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
          ICNT=ICNT+1
          ITEXT(ICNT)='because there are 0 degrees of freedom'
          NCTEXT(ICNT)=38
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
          ICNT=ICNT+1
          ITEXT(ICNT)='in the numerator of the F ratio.  This'
          NCTEXT(ICNT)=38
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
          ICNT=ICNT+1
          ITEXT(ICNT)='happens when the number of parameters'
          NCTEXT(ICNT)=37
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
          ICNT=ICNT+1
          ITEXT(ICNT)='fitted is identical to the number of'
          NCTEXT(ICNT)=36
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
          ICNT=ICNT+1
          ITEXT(ICNT)='distinct subsets.'
          NCTEXT(ICNT)=17
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
        ELSE
          ICNT=ICNT+1
          ITEXT(ICNT)='Lack of Fit F Ratio:'
          NCTEXT(ICNT)=20
          AVALUE(ICNT)=FITFVA
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Lack of Fit F Ratio CDF (%):'
          NCTEXT(ICNT)=28
          AVALUE(ICNT)=FITCD2
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Lack of Fit Degrees of Freedom 1:'
          NCTEXT(ICNT)=33
          AVALUE(ICNT)=REAL(IFITDF)
          IDIGIT(ICNT)=0
          ICNT=ICNT+1
          ITEXT(ICNT)='Lack of Fit Degrees of Freedom 2:'
          NCTEXT(ICNT)=33
          AVALUE(ICNT)=REAL(IREPDF)
          IDIGIT(ICNT)=0
        ENDIF
      ENDIF
!
      NUMROW=ICNT
      DO 1105 I=1,NUMROW
        NTOT(I)=15
 1105 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE='Estimation'
      NCTITL=10
      ITITL9=' '
      NCTIT9=0
!
      NUMCOL=5
      NUMLIN=1
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      ITITL2(1,2)='Level-ID'
      NCTIT2(1,2)=8
      ITITL2(1,3)='NI'
      NCTIT2(1,3)=2
      ITITL2(1,4)='Typical Value'
      NCTIT2(1,4)=13
      ITITL2(1,5)='Effect'
      NCTIT2(1,5)=6
!
      NMAX=0
      DO 23010 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=11
        IF(I.EQ.1)NTOT(I)=10
        IF(I.EQ.2)NTOT(I)=9
        IF(I.EQ.3)NTOT(I)=8
        IF(I.EQ.4)NTOT(I)=17
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IF(I.EQ.1)ITYPCO(I)='ALPH'
        IDIGIT(I)=5
        IF(I.LE.3)IDIGIT(I)=0
23010 CONTINUE
!
      ICNT=0
      DO 11590 L=1,NUMFAC
        DO 11595 I=1,N1(L)
          ICNT=ICNT+1
          IF(I.EQ.1)THEN
            IVALUE(ICNT,1)='Factor   '
            WRITE(IVALUE(ICNT,1)(8:9),'(I2)')L
          ELSE
            IVALUE(ICNT,1)='         '
          ENDIF
          NCVALU(ICNT,1)=9
          AMAT(ICNT,2)=F1ID(I,L)
          AMAT(ICNT,3)=F1N(I,L)
          AMAT(ICNT,4)=F1TYP(I,L)
          AMAT(ICNT,5)=F1EFFE(I,L)
11595 CONTINUE
11590 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=125
      IWHTML(3)=125
      IWHTML(4)=125
      IWHTML(5)=125
      IINC=1800
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE='Models'
      NCTITL=6
      ITITL9=' '
      NCTIT9=0
!
      NUMCOL=2
      NUMLIN=1
!
      ITITL2(1,1)='Model'
      NCTIT2(1,1)=5
      ITITL2(1,2)='Residual Standard Deviation'
      NCTIT2(1,2)=27
!
      NMAX=0
      DO 24010 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='l'
        NTOT(I)=30
        IF(I.EQ.2)NTOT(I)=27
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IF(I.EQ.1)ITYPCO(I)='ALPH'
        IDIGIT(I)=NUMDIG
24010 CONTINUE
!
      ICNT=0
      ICNT=ICNT+1
      IVALUE(ICNT,1)='Constant               Only--'
      NCVALU(ICNT,1)=30
      AMAT(ICNT,2)=GSD
      DO 12827 L=1,NUMFAC
        ICNT=ICNT+1
        IVALUE(ICNT,1)='Constant and Factor    Only--'
        WRITE(IVALUE(ICNT,1)(21:22),'(I2)')L
        NCVALU(ICNT,1)=30
        AMAT(ICNT,2)=RSD(L)
12827 CONTINUE
      ICNT=ICNT+1
      IVALUE(ICNT,1)='Constant and All    Factors--'
      WRITE(IVALUE(ICNT,1)(18:19),'(I2)')NUMFAC
      NCVALU(ICNT,1)=30
      AMAT(ICNT,2)=RESSD
!
      IWHTML(1)=300
      IWHTML(2)=200
      IINC3=3000
      IWRTF(1)=IINC3
      IWRTF(2)=IWRTF(1)+IINC
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE='Testing'
      NCTITL=7
      ITITL9=' '
      NCTIT9=0
!
      NUMCOL=4
      NUMLIN=1
!
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      ITITL2(1,2)='Number of Levels'
      NCTIT2(1,2)=16
      ITITL2(1,3)='F Statistic'
      NCTIT2(1,3)=11
      ITITL2(1,4)='F CDF'
      NCTIT2(1,4)=5
!
      NMAX=0
      DO 11610 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=10
        IF(I.EQ.2)NTOT(I)=18
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IF(I.EQ.1)ITYPCO(I)='ALPH'
        IF(I.EQ.4)ITYPCO(I)='ALPH'
        IDIGIT(I)=NUMDIG
        IF(I.LE.2)IDIGIT(I)=0
11610 CONTINUE
!
      ICNT=0
      DO 11690 L=1,NUMFAC
        ICNT=ICNT+1
        IVALUE(ICNT,1)='Factor   '
        WRITE(IVALUE(ICNT,1)(8:9),'(I2)')L
        NCVALU(ICNT,1)=9
        AMAT(ICNT,2)=N1(L)
        AMAT(ICNT,3)=FVAL(L)
        WRITE(IVALUE(ICNT,4)(1:8),'(F8.3)')F1CDF2(L)
        IVALUE(ICNT,4)(9:9)='%'
        NCVALU(ICNT,4)=9
11690 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=125
      IWHTML(3)=125
      IWHTML(4)=125
      IINC=1800
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MEP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMEP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IBUGA3,IREP,N,NUMFAC
 9012   FORMAT('IERROR,IBUGA3,IREP,N,NUMFAC = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9023)REPSS,REPMS,REPSD,REPDF
 9023   FORMAT('REPSS,REPMS,REPSD,REPDF = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9025 I=1,N
          WRITE(ICOUT,9026)I,Y(I),F1(I,1),F1(I,2),W(I),PRED2(I),RES2(I)
 9026     FORMAT('I,Y(I),F1(I,1),F1(I,2),W(I),PRED2(I),RES2(I) = ',   &
                 I8,6E11.4)
          CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPMEP2
      SUBROUTINE DPMERG(IBUGA2,IBUGA3,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--MERGE TWO SETS OF DATA.  FOR EXAMPLE,
!
!              LET SRCN CONTN INST1N XMEAN1 XMEAN2 INST2N =
!                  SRC1 CONT1 INST1 XMEAN1 SRC2 CONT2 INST2 XMEAN2
!
!              WHERE INST1 SRC1 CONT1 XMEAN1 CONSTITUTE THE FIRST
!              DATA SET AND INST2 SRC2 CONT2 CONSTITUTE THE SECOND
!              DATA SET.  NOTE THAT THE FOLLOWING MERGE IS DONE:
!
!                   LOOP THROUGHT DATA SET 1.  FOR THE VALUES OF
!                   SRC1 AND CONT1, LOOP THROUGH DATA SET 2 AND
!                   FIND ALL ROWS THE VALUES OF SRC2 AND CONT2
!                   MATCH THE VALUES OF SRC1 AND CONT1.  THESE
!                   DEFINE A "MERGED" ROW.  THE VALUES OF
!                   INST1, XMEAN1, INST2, AND XMEAN2 ARE "CARRIED"
!                   ON THE MERGED ROW.
!
!              SO NOTE THAT WE DEFINE TWO TYPES OF VARIABLES:
!
!                   1) MATCH VARIABLES
!                   2) CARRY VARIABLES
!
!              WE ASSUME THAT BOTH SETS OF DATA HAVE THE SAME
!              "MATCH" AND "CARRY" VARIABLES.  THE NUMBER OF
!              MATCH AND CARRY VARIABLES ARE SPECIFIED BY THE
!              VARIABLES IMERMA AND IMERCA (THESE ARE DEFINED
!              BY THE "SET MERGE MATCH VARIABLES <VALUE>" AND
!              "SET MERGE CARRY VARIABLES <VALUE>".
!
!              THE NUMBER OF VARIABLES TO THE LEFT OF THE "="
!              SHOULD BE "NMATCH + 2*NCARRY" AND THE NUMBER
!              OF VARIABLES TO THE RIGHT OF THE "=" SHOULD BE
!              "2*(NMATCH + NCARRY)".
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/8
!     ORIGINAL VERSION--AUGUST   2008.
!     UPDATED         --JUNE     2009. ALLOW THE 2 SETS OF DATA ON
!                                      THE RHS TO HAVE A DIFFERENT
!                                      NUMBER OF CARRY VARIABLES
!     UPDATED         --JUNE     2009. ALLOW CASE WHERE THERE ARE
!                                      NO MATCH VARIABLES (I.E.,
!                                      EACH ROW OF SET 1 IS MERGED
!                                      WITH EACH ROW OF SET 2)
!     UPDATED         --OCTOBER  2009. ALLOW MAXIMUM OF 4 MATCH
!                                      VARIABLES
!     UPDATED         --MARCH    2010. SPECIAL CASE WHERE NUMBER OF MATCH
!                                      AND NUMBER OF CARRY VARIABLES ARE
!                                      BOTH SET TO 0.  FOR THIS CASE,
!                                      GENERATE ALL PERMUTATIONS.
!     UPDATED         --JULY     2019. MODIFY USE OF SCRATCH STORAGE
!     UPDATED         --JANUARY  2024. MODIFY USE OF EQUIVALENCE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC PARAMETER (MAXMAT=3)
      PARAMETER (MAXMAT=4)
      PARAMETER (MAXCAR=8)
      PARAMETER (MAXLEF=MAXMAT + 2*MAXCAR)
      PARAMETER (MAXRIG=2*MAXMAT + 2*MAXCAR)
      PARAMETER (MAXRI2=MAXMAT + MAXCAR)
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASLE
      CHARACTER*4 ICASL7
      CHARACTER*4 IBUGQ
      CHARACTER*4 ICASEQ
!
      CHARACTER*4 NEWNAM(MAXLEF)
      CHARACTER*4 ILEFT(MAXLEF)
      CHARACTER*4 ILEF2(MAXLEF)
!
      CHARACTER*4 ITYPA(MAXRIG)
      CHARACTER*4 IHRIGH(MAXRIG)
      CHARACTER*4 IHRIG2(MAXRIG)
!
      INTEGER ILISL(MAXLEF)
      INTEGER ICOLL(MAXLEF)
      INTEGER ILOCR(MAXRIG)
      INTEGER ILISR(MAXRIG)
      INTEGER ICOLR(MAXRIG)
      INTEGER NIRIGH(MAXRIG)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
      INCLUDE 'DPCOHO.INC'
!
      PARAMETER (MAXOB2=MAXOBV/2)
      REAL TEMPS(MAXRIG)
      REAL YLEFT(MAXOB2,MAXLEF)
      REAL YRIGH1(MAXOB2,MAXRI2)
      REAL YRIGH2(MAXOB2,MAXRI2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
!CCCC EQUIVALENCE (YRIGH1(1,1),Y(1))
!CCCC EQUIVALENCE (YRIGH2(1,1),GARBAG(IGAR11))
!CCCC EQUIVALENCE (YLEFT(1,1),GARBAG(IGARB1))
      EQUIVALENCE (YRIGH1(1,1),GARBAG(IGARB1))
      EQUIVALENCE (YRIGH2(1,1),GARBAG(IGAR11))
      EQUIVALENCE (YLEFT(1,1),DGARBG(IDGAR1))
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPME'
      ISUBN2='RG  '
      IBUGQ=IBUGA3
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MINV2=2
      MINN2=2
      NQ=1
      ICNT=0
      HOLD=0.0
!
!               ******************************
!               **  TREAT THE MERGE CASE    **
!               ******************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMERG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,IBUGA3
   53   FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)NUMNAM,IMERMA,IMERCA,IMERC2
   56   FORMAT('NUMNAM,IMERMA,IMERCA,IMERC2 = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 57 I=1,NUMNAM
          WRITE(ICOUT,58)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),   &
                         IVALUE(I),VALUE(I)
   58     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
                 'VALUE(I) = ',I8,2X,2A4,2X,A4,2I8,F15.7)
          CALL DPWRST('XXX','BUG ')
   57   CONTINUE
      ENDIF
!
!     ***************************************
!     **  STEP 1A-                         **
!     **  FIND THE LOCATION OF "= MERGE"   **
!     ***************************************
!
      ISTEPN='1A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MINNA=MINV2
      MAXNA=100
      CALL CHECKA(NUMARG,MINNA,MAXNA,IANS,IWIDTH,ISUBN1,ISUBN2,   &
      IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DO 100 I=1,NUMARG-1
        IF(IHARG(I).EQ.'=' .AND. IHARG(I+1).EQ.'MERG')THEN
          NLEFT=I-1
          ILOCV=I+2
          GO TO 109
        ENDIF
  100 CONTINUE
!
      IFOUND='NO'
      GO TO 9000
!
  109 CONTINUE
      IFOUND='YES'
!
!     ************************************************
!     **  STEP 1B-                                  **
!     **  FIND THE LOCATION OF THE LAST ARGUMENT OR **
!     **  THE SUBSET/EXPCEPT/FOR CLASUE             **
!     ************************************************
!
      ISTEPN='1B'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
      IF(ILOCV.LE.NUMARG)THEN
        DO 110 J=ILOCV,NUMARG
          J1=J
          IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')GO TO 111
          IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')GO TO 111
          IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 111
  110   CONTINUE
        ILOCQ=NUMARG+1
        GO TO 112
  111   CONTINUE
        ILOCQ=J1
        GO TO 112
  112   CONTINUE
        NQ=ILOCQ-1
!
        NRIGHT=NQ-ILOCV+1
!
      ENDIF
!
!     **********************************************************
!     **  STEP 1B-                                            **
!     **  CHECK FOR AN APPROPRIATE NUMBER OF VARIABLES ON THE **
!     **  LEFT OF THE "=" AND TO THE RIGHT OF THE "=".        **
!     **********************************************************
!
      ISTEPN='1B'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NMATCH=IMERMA
      NCARR1=IMERCA
      NCARR2=IMERC2
      IF(NMATCH.EQ.0 .AND. NCARR1.EQ.0) THEN
        NEXPLE=NLEFT
        NEXPRI=NLEFT
        IFLAGP=1
      ELSE
        NEXPLE=NMATCH + NCARR1 + NCARR2
        NEXPRI=2*NMATCH+NCARR1+NCARR2
        IFLAGP=0
      ENDIF
!
      IF(NLEFT.NE.NEXPLE)THEN
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR IN MERGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,132)
  132   FORMAT('      THE EXPECTED NUMBER OF VARIABLES TO THE LEFT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      OF THE "=" DOES NOT EQUAL THE ACTUAL NUMBER OF')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,134)
  134   FORMAT('      VARIABLES TO THE LEFT OF THE "=".')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,135)NLEFT
  135   FORMAT('      THE NUMBER OF VARIABLES TO THE LEFT OF THE "=" ',   &
               'IS            ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,136)NMATCH
  136   FORMAT('      THE NUMBER OF MATCH VARIABLES IS               ',   &
               '              ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,137)NCARR1
  137   FORMAT('      THE NUMBER OF CARRY VARIABLES FOR SET 1 IS     ',   &
               '              ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,138)NCARR2
  138   FORMAT('      THE NUMBER OF CARRY VARIABLES FOR SET 2 IS     ',   &
               '              ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,139)NEXPLE
  139   FORMAT('      THE EXPECTED NUMBER OF VARIABLES TO THE LEFT OF',   &
               ' THE "=" IS   ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,140)(IANS(J),J=1,MIN(100,IWIDTH))
  140     FORMAT('      COMMAND LINE--',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NRIGHT.NE.NEXPRI)THEN
        WRITE(ICOUT,131)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,142)
  142   FORMAT('      THE EXPECTED NUMBER OF VARIABLES TO THE RIGHT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      OF THE "=" DOES NOT EQUAL THE ACTUAL NUMBER OF')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,144)
  144   FORMAT('      VARIABLES TO THE RIGHT OF THE "=".')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,145)NLEFT
  145   FORMAT('      THE NUMBER OF VARIABLES TO THE RIGHT OF ',   &
               'THE "=" IS            ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)NMATCH
  146   FORMAT('      THE NUMBER OF MATCH VARIABLES IS               ',   &
               '              ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)NCARR1
  147   FORMAT('      THE NUMBER OF CARRY VARIABLES FOR SET 1 IS     ',   &
               '              ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,148)NCARR2
  148   FORMAT('      THE NUMBER OF CARRY VARIABLES FOR SET 2 IS     ',   &
               '              ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,149)NEXPRI
  149   FORMAT('      THE EXPECTED NUMBER OF VARIABLES TO THE RIGHT',   &
               ' OF THE "=" IS   ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,139)(IANS(J),J=1,MIN(100,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IFOUND='YES'
      ICASLE='MERG'
!
!     *******************************************************
!     **  STEP 2--                                         **
!     **  CHECK THE VARIABLE NAMES ON THE LEFT HAND SIDE.  **
!     *******************************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MAXCA2=20
      DO 200 I=1,NLEFT
!
        ICASEZ=I
        CALL DPMAT6(ICASL7,ICASEZ,MAXCA2,   &
                    ILEFT,ILEF2,NEWNAM,ILISL,ICOLL,   &
                    NUMVAL,NIOLD,   &
                    IBUGA2,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'MERG')THEN
          WRITE(ICOUT,211)
  211     FORMAT('AFTER CALL TO DPMAT6--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,212)ILEFT(I),ILEF2(I),NEWNAM(I),NUMNAM,   &
                        ILISL(I),NUMCOL,ICOLL(I),NIOLD
          CALL DPWRST('XXX','BUG ')
  212     FORMAT('ILEFT(I),ILEFT(I),NEWNAM(I),NUMNAM,ILISL(I),',   &
                 'NUMCOL,ICOLL(I),NIOLD = ',A4,A4,2X,A4,2X,5I8)
        ENDIF
!
  200 CONTINUE
!
!     *******************************************************
!     **  STEP 3--                                         **
!     **  CHECK THE VARIABLE NAMES ON THE RIGHT HAND SIDE. **
!     *******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MAXCAS=2*NMATCH+NCARR1 + NCARR2
      IF(IFLAGP.EQ.1)MAXCAS=NRIGHT
      ILOCR(1)=ILOCV
      DO 300 I=2,MAXCAS
        ILOCR(I)=ILOCR(I-1)+1
        ITYPA(I)='VARI'
        TEMPS(I)=-999.0
        ILISR(I)=-999
        ICOLR(I)=-999
        NIRIGH(I)=-999
  300 CONTINUE
!
      IFLAG1=0
      IPART2=NMATCH+NCARR1+1
      IF(IFLAGP.EQ.1)IPART2=0
      DO 310 I=1,NRIGHT
        ICASEZ=I
        CALL DPMAT7(ICASL7,ICASEZ,MAXCAS,ILOCR,   &
                    IHRIGH(ICASEZ),IHRIG2(ICASEZ),   &
                    ICOLR,ILISR,NIRIGH,ITYPA,TEMPS,   &
                    IFLAG1,ATEMP2,ITEMP,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
!
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,301)
  301     FORMAT('AFTER DPMAT7:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,302)ICASEZ,ICOLR(ICASEZ),ILISR(ICASEZ),   &
                          NIRIGH(ICASEZ)
  302     FORMAT('ICASEZ,ICOLR(ICASEZ),ILISR(ICASEZ),NIRIGH(ICASEZ)=',   &
                 4I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IF(ICASEZ.GT.1 .AND. ICASEZ.LE.NMATCH+NCARR1 .AND.   &
           IFLAGP.EQ.0)THEN
          IF(NIRIGH(ICASEZ).NE.NIRIGH(1))THEN
            IINDX=ILOCV+I-1
            WRITE(ICOUT,131)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,312)IHARG(IINDX),IHARG2(IINDX)
  312       FORMAT('      THE NUMBER OF OBSERVATIONS FOR VARIABLE ',   &
                   A4,A4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,313)IHARG(ILOCV),IHARG2(ILOCV)
  313       FORMAT('      DOES NOT EQUAL THE NUMBER OF OBSERVATIONS ',   &
                   'FOR VARIABLE ',A4,A4,'.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,314)IHARG(IINDX),IHARG2(IINDX),NIRIGH(ICASEZ)
  314       FORMAT('      VARIABLE ',A4,A4,' HAS ',I8,   &
                   ' OBSERVATIONS.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,314)IHARG(ILOCV),IHARG2(ILOCV),NIRIGH(1)
            CALL DPWRST('XXX','BUG ')
            IF(IWIDTH.GE.1)THEN
              WRITE(ICOUT,139)(IANS(J),J=1,MIN(100,IWIDTH))
              CALL DPWRST('XXX','BUG ')
            ENDIF
            IERROR='YES'
            GO TO 9000
          ENDIF
        ELSEIF(ICASEZ.GT.IPART2 .AND. IFLAGP.EQ.0)THEN
          IF(NIRIGH(ICASEZ).NE.NIRIGH(IPART2))THEN
            IINDX=ILOCV+I-1
            IINDX2=IPART2+ILOCV
            WRITE(ICOUT,131)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,312)IHARG(IINDX),IHARG2(IINDX)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,313)IHARG(IINDX2),IHARG2(IINDX2)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,314)IHARG(IINDX),IHARG2(IINDX),NIRIGH(ICASEZ)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,314)IHARG(IINDX2),IHARG2(IINDX2),NIRIGH(IPART2)
            CALL DPWRST('XXX','BUG ')
            IF(IWIDTH.GE.1)THEN
              WRITE(ICOUT,139)(IANS(J),J=1,MIN(100,IWIDTH))
              CALL DPWRST('XXX','BUG ')
            ENDIF
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
  310 CONTINUE
!
!     **********************************************
!     **  STEP 4--                                **
!     **  CHECK TO SEE THE TYPE CASE--            **
!     **    1) UNQUALIFIED (THAT IS, FULL);       **
!     **    2) SUBSET/EXCEPT; OR                  **
!     **    3) FOR.                               **
!     **********************************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 490
      DO 400 J=1,NUMARG
      J1=J
      IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')GO TO 410
      IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')GO TO 410
      IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')GO TO 420
  400 CONTINUE
      GO TO 490
  410 CONTINUE
      ICASEQ='SUBS'
      ILOCQ=J1
      GO TO 490
  420 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 490
  490 CONTINUE
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')THEN
        WRITE(ICOUT,491)NUMARG,ILOCQ,IPART2
  491   FORMAT('NUMARG,ILOCQ,IPART2 = ',3I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     *****************************************************
!     **  STEP 5--                                       **
!     **  BRANCH TO THE APPROPRIATE SUBCASE; THEN        **
!     **  CREATE THE MATRICES FOR TWO SETS OF DATA.      **
!     *****************************************************
!
      ISTEPN='5'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,501)N,ILOCQ-1
  501   FORMAT('N,ILOCQ-1 = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGP.EQ.1)THEN
        NTEMP=NIRIGH(1)
        DO 506 I=1,NRIGHT
          NTEMP=MAX(NTEMP,NIRIGH(I))
  506   CONTINUE
        NTEMP1=NTEMP
        NTEMP2=0
        NTEMP9=NRIGHT
      ELSE
        NTEMP1=NIRIGH(1)
        NTEMP2=NIRIGH(IPART2)
        NTEMP=MAX(NTEMP1,NTEMP2)
        NTEMP9=NMATCH+NCARR1
      ENDIF
!
      IF(ICASEQ.EQ.'FULL' .OR. IFLAGP.EQ.1)GO TO 510
      IF(ICASEQ.EQ.'SUBS')GO TO 520
      IF(ICASEQ.EQ.'FOR')GO TO 530
!
  510 CONTINUE
      DO 515 I=1,NTEMP
      ISUB(I)=1
  515 CONTINUE
      NQZ=NTEMP
      GO TO 550
!
  520 CONTINUE
      NIOLD=NTEMP
!CCCC CALL DPSUB2(NIOLD,ILOCS,NSTEMP,IBUGQ,IERROR)
      CALL DPSUBS(NIOLD,ILOCS,NSTEMP,IBUGQ,IERROR)
      NQZ=NIOLD
      GO TO 550
!
  530 CONTINUE
      NIOLD=NTEMP
      CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
      NLOCAL,ILOCS,NSTEMP,IBUGQ,IERROR)
      NQZ=NFOR
      GO TO 550
!
  550 CONTINUE
      J=0
      DO 560 I=1,NTEMP1
        IF(ISUB(I).EQ.0)GO TO 560
        J=J+1
!
!       2024/01: CHECK THAT J <= MAXOB2
!
        IF(J.GT.MAXOB2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,562)MAXOB2
  562     FORMAT('      MAXIMUM NUMBER OF OUTPUT ROWS (',I10,   &
                 ') EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        DO 570 JJ=1,NTEMP9
          K=ICOLR(JJ)
          IJ=MAXN*(K-1)+I
          IF(K.LE.MAXCOL)YRIGH1(J,JJ)=V(IJ)
          IF(K.EQ.MAXCP1)YRIGH1(J,JJ)=PRED(I)
          IF(K.EQ.MAXCP2)YRIGH1(J,JJ)=RES(I)
          IF(K.EQ.MAXCP3)YRIGH1(J,JJ)=YPLOT(I)
          IF(K.EQ.MAXCP4)YRIGH1(J,JJ)=XPLOT(I)
          IF(K.EQ.MAXCP5)YRIGH1(J,JJ)=X2PLOT(I)
          IF(K.EQ.MAXCP6)YRIGH1(J,JJ)=TAGPLO(I)
  570   CONTINUE
  560 CONTINUE
      NS1=J
!
      IF(IFLAGP.EQ.1)GO TO 669
      J=0
      DO 660 I=1,NTEMP2
        IF(ISUB(I).EQ.0)GO TO 660
        J=J+1
!
!       2024/01: CHECK THAT J <= MAXOB2
!
        IF(J.GT.MAXOB2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,562)MAXOB2
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        DO 670 JJ=1,NMATCH+NCARR2
          JJTEMP=NMATCH+NCARR1+JJ
          K=ICOLR(JJTEMP)
          IJ=MAXN*(K-1)+I
          IF(K.LE.MAXCOL)YRIGH2(J,JJ)=V(IJ)
          IF(K.EQ.MAXCP1)YRIGH2(J,JJ)=PRED(I)
          IF(K.EQ.MAXCP2)YRIGH2(J,JJ)=RES(I)
          IF(K.EQ.MAXCP3)YRIGH2(J,JJ)=YPLOT(I)
          IF(K.EQ.MAXCP4)YRIGH2(J,JJ)=XPLOT(I)
          IF(K.EQ.MAXCP5)YRIGH2(J,JJ)=X2PLOT(I)
          IF(K.EQ.MAXCP6)YRIGH2(J,JJ)=TAGPLO(I)
  670   CONTINUE
  660 CONTINUE
      NS2=J
  669 CONTINUE
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,691)
  691   FORMAT('***** FROM DPMERG, AFTER FORMING RHS MATRICES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,692)NTEMP1,NTEMP2,NTEMP,NS1,NS2
  692   FORMAT('NTEMP1,NTEMP2,NTEMP,NS1,NS2 = ',5(I8,2X))
        CALL DPWRST('XXX','BUG ')
        NTEMP8=NMATCH+NCARR1+NCARR2
        IF(IFLAGP.EQ.1)NTEMP8=NRIGHT
        DO 693 I=1,NTEMP8
          WRITE(ICOUT,694)I,ICOLR(I),ILOCR(I)
  694     FORMAT('I,ICOLR(I),ILOCR(I) = ',3(I8,2X))
          CALL DPWRST('XXX','BUG ')
  693   CONTINUE
        DO 695 I=1,NS1
          WRITE(ICOUT,696)I,(YRIGH1(I,JJ),JJ=1,NTEMP9)
  696     FORMAT(I8,20(G15.7))
          CALL DPWRST('XXX','BUG ')
  695   CONTINUE
        IF(IFLAGP.EQ.0)THEN
          DO 697 I=1,NS2
            WRITE(ICOUT,696)I,(YRIGH2(I,JJ),JJ=1,NMATCH+NCARR2)
            CALL DPWRST('XXX','BUG ')
  697     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 6--                                        **
!               **  CARRY OUT THE MERGE                             **
!               ******************************************************
!
      ISTEPN='6'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IFLAGP.EQ.1)THEN
!
        ISTEPN='6A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(NRIGHT.EQ.1)THEN
          DO 6010 I=1,NIRIGH(1)
            YLEFT(I,1)=YRIGH1(I,1)
 6010     CONTINUE
          NINEW=NIRIGH(1)
        ELSEIF(NRIGHT.EQ.2)THEN
          ICNT=0
          DO 6110 ISET1=1,NIRIGH(1)
            AHOLD1=YRIGH1(ISET1,1)
            DO 6120 ISET2=1,NIRIGH(2)
              AHOLD2=YRIGH1(ISET2,2)
              ICNT=ICNT+1
!
              IF(ICNT.GT.MAXN .OR. ICNT.GT.MAXOB2)THEN
                WRITE(ICOUT,131)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6121)
 6121           FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                       'RIGHT HAND SIDE')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6123)MAXN
 6123           FORMAT('      HAS JUST EXCEEDED THE MAXIMUM ',   &
                       'ALLOWABLE (',I8,')')
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 9000
              ENDIF
!
              YLEFT(ICNT,1)=AHOLD1
              YLEFT(ICNT,2)=AHOLD2
 6120       CONTINUE
 6110     CONTINUE
          NINEW=ICNT
        ELSEIF(NRIGHT.EQ.3)THEN
          ICNT=0
          DO 6210 ISET1=1,NIRIGH(1)
            AHOLD1=YRIGH1(ISET1,1)
            DO 6220 ISET2=1,NIRIGH(2)
              AHOLD2=YRIGH1(ISET2,2)
              DO 6230 ISET3=1,NIRIGH(3)
              AHOLD3=YRIGH1(ISET3,3)
              ICNT=ICNT+1
!
              IF(ICNT.GT.MAXN .OR. ICNT.GT.MAXOB2)THEN
                WRITE(ICOUT,131)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6231)
 6231           FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                       'RIGHT HAND SIDE')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6233)MAXN
 6233           FORMAT('      HAS JUST EXCEEDED THE MAXIMUM ',   &
                       'ALLOWABLE (',I8,')')
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 9000
              ENDIF
!
              YLEFT(ICNT,1)=AHOLD1
              YLEFT(ICNT,2)=AHOLD2
              YLEFT(ICNT,3)=AHOLD3
 6230       CONTINUE
 6220       CONTINUE
 6210     CONTINUE
          NINEW=ICNT
        ELSEIF(NRIGHT.EQ.4)THEN
          ICNT=0
          DO 6310 ISET1=1,NIRIGH(1)
            AHOLD1=YRIGH1(ISET1,1)
            DO 6320 ISET2=1,NIRIGH(2)
              AHOLD2=YRIGH1(ISET2,2)
              DO 6330 ISET3=1,NIRIGH(3)
              AHOLD3=YRIGH1(ISET3,3)
              DO 6340 ISET4=1,NIRIGH(4)
              AHOLD4=YRIGH1(ISET4,4)
              ICNT=ICNT+1
!
              IF(ICNT.GT.MAXN .OR. ICNT.GT.MAXOB2)THEN
                WRITE(ICOUT,131)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6341)
 6341           FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                       'RIGHT HAND SIDE')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6343)MAXN
 6343           FORMAT('      HAS JUST EXCEEDED THE MAXIMUM ',   &
                       'ALLOWABLE (',I8,')')
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 9000
              ENDIF
!
              YLEFT(ICNT,1)=AHOLD1
              YLEFT(ICNT,2)=AHOLD2
              YLEFT(ICNT,3)=AHOLD3
              YLEFT(ICNT,4)=AHOLD4
 6340       CONTINUE
 6330       CONTINUE
 6320       CONTINUE
 6310     CONTINUE
          NINEW=ICNT
        ELSEIF(NRIGHT.EQ.5)THEN
          ICNT=0
          DO 6410 ISET1=1,NIRIGH(1)
            AHOLD1=YRIGH1(ISET1,1)
            DO 6420 ISET2=1,NIRIGH(2)
              AHOLD2=YRIGH1(ISET2,2)
              DO 6430 ISET3=1,NIRIGH(3)
              AHOLD3=YRIGH1(ISET3,3)
              DO 6440 ISET4=1,NIRIGH(4)
              AHOLD4=YRIGH1(ISET3,4)
              DO 6450 ISET5=1,NIRIGH(5)
              AHOLD5=YRIGH1(ISET5,5)
              ICNT=ICNT+1
!
              IF(ICNT.GT.MAXN .OR. ICNT.GT.MAXOB2)THEN
                WRITE(ICOUT,131)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6451)
 6451           FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                       'RIGHT HAND SIDE')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6453)MAXN
 6453           FORMAT('      HAS JUST EXCEEDED THE MAXIMUM ',   &
                       'ALLOWABLE (',I8,')')
                CALL DPWRST('XXX','BUG ')
                IERROR='YES'
                GO TO 9000
              ENDIF
!
              YLEFT(ICNT,1)=AHOLD1
              YLEFT(ICNT,2)=AHOLD2
              YLEFT(ICNT,3)=AHOLD3
              YLEFT(ICNT,4)=AHOLD4
              YLEFT(ICNT,5)=AHOLD5
 6450       CONTINUE
 6440       CONTINUE
 6430       CONTINUE
 6420       CONTINUE
 6410     CONTINUE
          NINEW=ICNT
        ELSEIF(NRIGHT.EQ.6)THEN
          ICNT=0
          DO 6510 ISET1=1,NIRIGH(1)
            AHOLD1=YRIGH1(ISET1,1)
            DO 6520 ISET2=1,NIRIGH(2)
              AHOLD2=YRIGH1(ISET2,2)
              DO 6530 ISET3=1,NIRIGH(3)
              AHOLD3=YRIGH1(ISET3,3)
              DO 6540 ISET4=1,NIRIGH(4)
              AHOLD4=YRIGH1(ISET3,4)
              DO 6550 ISET5=1,NIRIGH(5)
              AHOLD5=YRIGH1(ISET5,5)
              DO 6560 ISET6=1,NIRIGH(6)
              AHOLD6=YRIGH1(ISET6,6)
              ICNT=ICNT+1
!
              IF(ICNT.GT.MAXN .OR. ICNT.GT.MAXOB2)THEN
                WRITE(ICOUT,131)
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6561)
 6561           FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                       'RIGHT HAND SIDE')
                CALL DPWRST('XXX','BUG ')
                WRITE(ICOUT,6563)MAXN
 6563           FORMAT('      HAS JUST EXCEEDED THE MAXIMUM ',   &
                       'ALLOWABLE (',I8,')')
                CALL DPWRST('XXX','BUG ')
