        IHNAME(ILISL(I))=ILEFT(I)
        IHNAM2(ILISL(I))=ILEF2(I)
        IUSE(ILISL(I))='V'
        IVALUE(ILISL(I))=ICOLL(I)
        VALUE(ILISL(I))=ICOLL(I)
        IF(NEWNAM(I).EQ.'YES')THEN
          NUMNAM=NUMNAM+1
          NUMCOL=NUMCOL+1
        ENDIF
!
        IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
