                   ' = ',G16.7,'   (ROW ',I6,')')
            CALL DPWRST('XXX','BUG ')
          ELSEIF(ICOLL(I).EQ.MAXCP2)THEN
            WRITE(ICOUT,8121)ILEFT(I),ILEF2(I),RES(IROW1),IROW1
