!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'MERG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMERG--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMERG
      SUBROUTINE DPMESS(IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE DATAPLOT MESSAGES
!              FOR THE ANALYST'S PERUSAL UPON
!              SIGNING ON TO DATAPLOT.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/1
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --JANUARY   1979.
!     UPDATED         --NOVEMBER  1980.
!     UPDATED         --JUNE      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --DECEMBER  1985.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=MAXFNC) :: IFILE
      CHARACTER*12 ISTAT
      CHARACTER*12 IFORM
      CHARACTER*12 IACCES
      CHARACTER*12 IPROT
      CHARACTER*12 ICURST
      CHARACTER*4 IENDFI
      CHARACTER*4 IREWIN
      CHARACTER*4 ISUBN0
      CHARACTER*4 IERRFI
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*80 ISTRIN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPME'
      ISUBN2='SS  '
      IFOUND='YES'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMESS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGS2,ISUBRO,IERROR,IMESNU
   53   FORMAT('IBUGS2,ISUBRO,IERROR,IMESNU = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)IMESNA
   62   FORMAT('IMESNA = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IMESST,IMESFO,IMESAC,IMESFO,IMESCS
   63   FORMAT('IMESST,IMESFO,IMESAC,IMESFO,IMESCS = ',4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************
!               **  STEP 11--           **
!               **  COPY OVER VARIABLES **
!               **************************
!
      ISTEPN='11'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOUNIT=IMESNU
      IFILE=IMESNA
      ISTAT=IMESST
      IFORM=IMESFO
      IACCES=IMESAC
      IPROT=IMESPR
      ICURST=IMESCS
!
      ISUBN0='MESS'
      IERRFI='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')THEN
        WRITE(ICOUT,1193)ISUBN0,IERRFI,IOUNIT
 1193   FORMAT('ISUBN0,IERRFI,IOUNIT = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1194)IFILE(1:80)
 1194   FORMAT('IFILE = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1195)ISTAT,IFORM,IACCES,IPROT,ICURST
 1195   FORMAT('ISTAT,IFORM,IACCES,IPROT,ICURST = ',4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************
!               **  STEP 12--                            **
!               **  CHECK TO SEE IF MESSAGE FILE EXISTS  **
!               *******************************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISTAT.EQ.'NONE')GO TO 9000
!
!               *********************
!               **  STEP 31--      **
!               **  OPEN THE FILE  **
!               *********************
!
      ISTEPN='31'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IREWIN='ON'
      CALL DPOPFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      IF(IERRFI.EQ.'YES')GO TO 9000
!
!               ******************************
!               **  STEP 41--               **
!               **  READ THE FILE.          **
!               **  WRITE OUT THE MESSAGES. **
!               ******************************
!
      ISTEPN='41'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ANUMLI=0.0
      READ(IOUNIT,4111,END=4190)ANUMLI
 4111 FORMAT(F10.0)
      NUMLIN=INT(ANUMLI+0.5)
!
      IF(NUMLIN.GE.1)THEN
        NMAX=80
        DO 4120 I=1,NUMLIN
          READ(IOUNIT,4121,END=4190)(ISTRIN(J:J),J=1,80)
 4121     FORMAT(80A1)
          CALL DPDB80(ISTRIN,JMAX,NMAX,IBUGS2,ISUBRO,IERROR)
          IF(JMAX.GE.1)THEN
            WRITE(ICOUT,4122)(ISTRIN(J:J),J=1,JMAX)
 4122       FORMAT(5X,80A1)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
 4120   CONTINUE
      ENDIF
!
 4190 CONTINUE
!
!               ***********************
!               **  STEP 51--        **
!               **  CLOSE THE FILE.  **
!               ***********************
!
      ISTEPN='51'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IENDFI='OFF'
      IREWIN='ON'
      CALL DPCLFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MESS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMESS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9028)IENDFI,IREWIN,IERRFI,JMAX
 9028   FORMAT('IENDFI,IREWIN,IERRFI,JMAX = ',2(A4,2X),A12,2X,I8)
        CALL DPWRST('XXX','BUG ')
        IF(JMAX.GE.1)THEN
          WRITE(ICOUT,9042)(ISTRIN(J:J),J=1,JMAX)
 9042     FORMAT('ISTRIN--',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPMESS
      SUBROUTINE DPMETE(MAXNXT,ICAPSW,IFORSW,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT NONPARAMETRIC MEDIAN TEST TO TEST FOR
!              EQUAL MEDIANS AMONG K GROUPS.
!     EXAMPLE--MEDIAN TEST Y X
!              MEDIAN TEST Y1 Y2 Y3
!              MEDIAN TEST Y1 TO YK
!     REFERENCE--CONOVER (1999), "PRACTICAL NONPARAMETRIC STATISTICS",
!                THIRD EDITION, WILEY, PP. 218-224.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/6
!     ORIGINAL VERSION--JUNE      2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IMULT
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
!
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
!
      EQUIVALENCE(GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE(GARBAG(IGARB2),TEMP2(1))
      EQUIVALENCE(GARBAG(IGARB3),TEMP3(1))
      EQUIVALENCE(GARBAG(IGARB4),TEMP4(1))
      EQUIVALENCE(DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE(DGARBG(IDGAR2),DTEMP2(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPME'
      ISUBN2='TE  '
      IFOUND='YES'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ******************************************
!               **  TREAT THE SQUARED RANKS TEST CASE  **
!               ******************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'METE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPMETE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)IMULT,IKRUGS,MAXNXT
   55   FORMAT('IMULT,IKRUGS,MAXNXT = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  EXTRACT THE COMMAND                                **
!               *********************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTZ=9999
      ICASAN='METE'
      IMULT='OFF'
!
!     LOOK FOR:
!
!          MEDIAN TEST
!          MULTIPLE
!
      DO 100 I=0,NUMARG-1
!
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
        ELSE
          ICTMP1=IHARG(I)
        ENDIF
        ICTMP2=IHARG(I+1)
        ICTMP3=IHARG(I+2)
!
        IF(ICTMP1.EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(ICTMP1.EQ.'MEDI' .AND. ICTMP2.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='METE'
          ILASTZ=I+1
        ELSEIF(ICTMP1.EQ.'MULT')THEN
          IMULT='ON'
          ILASTZ=MAX(ILASTZ,I+1)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')THEN
        WRITE(ICOUT,91)ICASAN,ICASA2,IMULT,ISHIFT
   91   FORMAT('DPMETE: ICASAN,ICASA2,IMULT,ISHIFT = ',   &
               3(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='MEDIAN TEST'
      MAXNA=100
      MINNVA=2
      MAXNVA=MAXSPN
      MINNA=1
      IFLAGE=1
      IFLAGM=0
      IF(IMULT.EQ.'ON')THEN
        IFLAGE=0
        IFLAGM=1
        MAXNVA=MAXSPN
      ENDIF
      MINN2=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT
  182   FORMAT('NQ,NUMVAR,IMULT = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               *******************************************************
!               **  STEP 3--                                         **
!               **  GENERATE THE MEDIAN         TEST FOR THE VARIOUS **
!               **  CASES                                            **
!               *******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
      IF(IMULT.EQ.'OFF')THEN
        ISTEPN='3A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=2
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,X,X,NLOCAL,NLOCA2,NLOCA2,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!
!               ******************************************************
!               **  STEP 3B--
!               **  PREPARE FOR ENTRANCE INTO DPMET2--
!               ******************************************************
!
        ISTEPN='3B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,331)
  331     FORMAT('***** FROM DPMETE, AS WE ARE ABOUT TO CALL DPMET2--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,332)NLOCAL
  332     FORMAT('NLOCAL = ',I8)
          CALL DPWRST('XXX','BUG ')
          DO 335 I=1,NLOCAL
            WRITE(ICOUT,336)I,Y(I),X(I)
  336       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
  335     CONTINUE
        ENDIF
!
        CALL DPMET2(Y,X,NLOCAL,IVARN1,IVARN2,ICASA2,   &
                    PMTEQU,IQUAME,MAXNXT,   &
                    TEMP1,TEMP2,TEMP3,   &
                    STATVA,STATCD,PVAL,IDF,NDIST,   &
                    CUT0,CUT50,CUT75,CUT90,CUT95,CUT975,   &
                    CUT99,CUT999,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,   &
                    ISUBRO,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IFLAGU='ON'
          IFRST=.TRUE.
          ILAST=.TRUE.
          CALL DPFRT5(STATVA,STATCD,PVAL,   &
                      CUT0,CUT50,CUT75,CUT90,CUT95,   &
                      CUT975,CUT99,CUT999,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!               *******************************************************
!               **  STEP 4A--                                        **
!               **  CASE 2: MULTIPLE RESPONSE VARIABLES.  NOTE THAT  **
!               **          FOR MEDIAN TEST, THE MULTIPLE LABS ARE   **
!               **          CONVERTED INTO A "Y X" STACKED PAIR      **
!               **          WHERE "X" IS THE LAB-ID VARIABLE.        **
!               *******************************************************
!
      ELSEIF(IMULT.EQ.'ON')THEN
        ISTEPN='4A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=NUMVAR
        CALL DPPAR8(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    TEMP1,Y,X,NLOCAL,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        NUMVAR=2
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'METE')THEN
          ISTEPN='4B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,442)
  442     FORMAT('***** FROM THE MIDDLE  OF DPMETE--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,443)ICASAN,NUMVAR,NLOCAL
  443     FORMAT('ICASAN,NUMVAR,NLOCAL = ',A4,2I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 445 I=1,NLOCAL
              WRITE(ICOUT,446)I,Y(I),X(I)
  446         FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
  445       CONTINUE
          ENDIF
        ENDIF
!
        CALL DPMET2(Y,X,NLOCAL,IVARN1,IVARN2,ICASA2,   &
                    PMTEQU,IQUAME,MAXNXT,   &
                    TEMP1,TEMP2,TEMP3,   &
                    STATVA,STATCD,PVAL,IDF,NDIST,   &
                    CUT0,CUT50,CUT75,CUT90,CUT95,CUT975,   &
                    CUT99,CUT999,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,   &
                    ISUBRO,IBUGA3,IERROR)
!
!         ***************************************
!         **  STEP 8C--                        **
!         **  UPDATE INTERNAL DATAPLOT TABLES  **
!         ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'METE')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IFLAGU='ON'
          IFRST=.TRUE.
          ILAST=.TRUE.
          CALL DPFRT5(STATVA,STATCD,PVAL,   &
                      CUT0,CUT50,CUT75,CUT90,CUT95,   &
                      CUT975,CUT99,CUT999,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'METE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMETE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NLOCAL,STATVA,STATCD,PVAL
 9014   FORMAT('NLOCAL,STATVA,STATCD,PVAL = ',I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMETE
      SUBROUTINE DPMET2(Y,TAG,N,IVARID,IVARI2,ICASAN,   &
                        PMTEQU,IQUAME,MAXNXT,   &
                        TEMP1,TEMP2,XIDTEM,   &
                        STATVA,STATCD,PVAL,IDF,NDIST,   &
                        CUT0,CUT50,CUT75,CUT90,CUT95,CUT975,   &
                        CUT99,CUT999,   &
                        ICAPSW,ICAPTY,IFORSW,IMULT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT A NONPARAMETRIC MEDIAN
!              TEST FOR EQUAL MEDIANS
!     EXAMPLE--MEDIAN TEST Y TAG
!     REFERENCE--W. J. CONOVER, "PRACTICAL NONPARAMETRIC
!                STATISTICS", THIRD EDITION, 1999, WILEY,
!                PP. 218-224.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/6
!     ORIGINAL VERSION--JUNE      2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IQUAME
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION XIDTEM(*)
!
!---------------------------------------------------------------------
!
      PARAMETER (NUMALP=8)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=4)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ALPHA/   &
       0.0, 50.0, 75.0, 90.0, 95.0, 97.5, 99.0, 99.9/
!
      ISUBN1='DPME'
      ISUBN2='T2  '
      ISUBN0='    '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MET2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMET2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,N
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ****************************************************
!               **  STEP 1--                                      **
!               **  CARRY OUT CALCULATIONS FOR MEDIAN       TEST  **
!               **  (COMPUTATIONS PERFORMED IN DPMET3)            **
!               ****************************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NSAVE=N
      CALL DPMET3(Y,TAG,N,   &
                  TEMP1,TEMP2,XIDTEM,PMTEQU,IQUAME,MAXNXT,   &
                  XMED,XA,XB,IDF,NDIST,   &
                  STATVA,STATCD,PVAL,   &
                  IBUGA3,ISUBRO,IERROR)
!
      CUT0=0.0
      CALL CHSPPF(.50,IDF,CUT50)
      CALL CHSPPF(.75,IDF,CUT75)
      CALL CHSPPF(.90,IDF,CUT90)
      CALL CHSPPF(.95,IDF,CUT95)
      CALL CHSPPF(.975,IDF,CUT975)
      CALL CHSPPF(.99,IDF,CUT99)
      CALL CHSPPF(.999,IDF,CUT999)
!
      IOP='OPEN'
      IFLG1=1
      IFLG2=0
      IFLG3=0
      IFLG4=0
      IFLG5=0
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2301)
 2301 FORMAT('   GROUP    OBS. ABOVE     OBS. TOTAL')
      DO 2310 I=1,NDIST
        WRITE(IOUNI1,2305)I,TEMP1(I),TEMP2(I)
 2305   FORMAT(I8,2E15.7)
 2310 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ********************************
!               **   STEP 42--                **
!               **   WRITE OUT EVERYTHING     **
!               **   FOR MEDIAN        TEST   **
!               ********************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Median Test'
      NCTITL=11
      ITITLZ=' '
      NCTITZ=0
      IF(PMTEQU.NE.0.5)THEN
        ITITLE='Median Test for User Specified Quantile'
         NCTITL=39
        ITITLZ=' '
        NCTITZ=0
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(IMULT.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Group-ID Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      IF(PMTEQU.NE.0.5)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='H0: Samples Have Equal Quantile'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Ha: At Least Two Samples Have Different Quantile'
        NCTEXT(ICNT)=48
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='H0: Samples Have Equal Medians'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Ha: At Least Two Samples Have Different Medians'
        NCTEXT(ICNT)=47
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(PMTEQU.NE.0.5)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='User Specified Quantile to Test:'
        NCTEXT(ICNT)=32
        AVALUE(ICNT)=PMTEQU
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)='Original Number of Observations:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=REAL(NSAVE)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations After Omitting'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Groups With Less Than Two Observations:'
      NCTEXT(ICNT)=39
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=REAL(NDIST)
      IDIGIT(ICNT)=0
      IF(PMTEQU.NE.0.5)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Grand Quantile:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=XMED
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Points > the Grand Quantile:'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=XA
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Points <= the Grand Quantile:'
        NCTEXT(ICNT)=39
        AVALUE(ICNT)=REAL(N) - XA
        IDIGIT(ICNT)=0
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Grand Median:'
        NCTEXT(ICNT)=13
        AVALUE(ICNT)=XMED
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Points > the Grand Median:'
        NCTEXT(ICNT)=36
        AVALUE(ICNT)=XA
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Points <= the Grand Median:'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=REAL(N) - XA
        IDIGIT(ICNT)=0
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Median Test Statistic Value:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF of Test Statistic:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value:'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=PVAL
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE=' '
      NCTITL=0
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:55)=   &
      'Percent Points of the Chi-Square Reference Distribution'
      NCTITL=55
      NUMLIN=1
      NUMROW=NUMALP
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 4221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=1
      IDIGIT(3)=3
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            AMAT(I,J)=ALPHA(I)
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            IF(I.EQ.1)THEN
              AMAT(I,J)=RND(CUT0,IDIGIT(J))
            ELSEIF(I.EQ.2)THEN
              AMAT(I,J)=RND(CUT50,IDIGIT(J))
            ELSEIF(I.EQ.3)THEN
              AMAT(I,J)=RND(CUT75,IDIGIT(J))
            ELSEIF(I.EQ.4)THEN
              AMAT(I,J)=RND(CUT90,IDIGIT(J))
            ELSEIF(I.EQ.5)THEN
              AMAT(I,J)=RND(CUT95,IDIGIT(J))
            ELSEIF(I.EQ.6)THEN
              AMAT(I,J)=RND(CUT975,IDIGIT(J))
            ELSEIF(I.EQ.7)THEN
              AMAT(I,J)=RND(CUT99,IDIGIT(J))
            ELSEIF(I.EQ.8)THEN
              AMAT(I,J)=RND(CUT999,IDIGIT(J))
            ENDIF
          ENDIF
 4225   CONTINUE
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.FALSE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE='Upper-Tailed Test: Chi-Square Approximation'
      NCTITL=43
      IF(PMTEQU.NE.0.5)THEN
        ITITL9='H0: Quantiles Are Equal; Ha: Quantiles Are Not Equal'
        NCTIT9=52
      ELSE
        ITITL9='H0: Medians Are Equal; Ha: Medians Are Not Equal'
        NCTIT9=48
      ENDIF
!
      DO 2130 J=1,NUMCLI
        DO 2140 I=1,MAXLIN
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 2140   CONTINUE
 2130 CONTINUE
!
      NUMCOL=4
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (>)'
      NCTIT2(3,3)=9
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      DO 2150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.4)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 2150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(3)=175
      IWHTML(4)=175
      IINC=1800
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
!
      ICNT=0
      DO 2160 J=4,NUMALP
!
        ICNT=ICNT+1
        AMAT(ICNT,2)=STATVA
        ALPHAT=ALPHA(J)
        ATEMP=ALPHAT/100.0
        CALL CHSPPF(ATEMP,IDF,CUTTMP)
        AMAT(ICNT,3)=CUTTMP
        IVALUE(ICNT,4)(1:6)='ACCEPT'
        IF(STATVA.GT.AMAT(ICNT,3))THEN
          IVALUE(ICNT,4)(1:6)='REJECT'
        ENDIF
        NCVALU(ICNT,4)=6
!
        WRITE(IVALUE(ICNT,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(ICNT,1)(5:5)='%'
        NCVALU(ICNT,1)=5
 2160 CONTINUE
!
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
!
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MET2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMET2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9025)STATVA,STATCD,PVAL
 9025   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMET2
      SUBROUTINE DPMET3(Y,X,N,   &
                        TEMP1,TEMP2,XIDTEM,PMTEQU,IQUAME,MAXNXT,   &
                        XMED,XA,XB,IDF,NDIST,   &
                        STATVA,STATCD,PVALUE,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MEDIAN K-SAMPLE TEST
!              STATISTIC FOR EQUAL MEDIANS AND ASSOCIATED CDF AND
!              P-VALUES.
!
!              THIS PART IS EXTRACTED FROM DPMET2 IN ORDER TO
!              ALLOW IT TO BE COMPUTED FROM THE "STATISTICS" ROUTINES
!              (E.G., STATISTIC PLOT, BOOTSTRAP).
!
!              THE TEST STATISTIC IS:
!
!                 T = (N**2/a*b)*SUM[i=1 to k][(O(1i) - n(i)*a/N)**2/n(i)]
!
!              WHERE
!
!                 N      = TOTAL SAMPLE SIZE
!                 O(1i)  = NUMBER OF OBSERVAIONS IN GROUP i > GRAND MEDIAN
!                 n(i)   = SAMPLE SIZE OF GROUP i
!                 a      = TOTAL NUMBER OF OBSERVATIONS GREATER THAN THE
!                          GRAND MEDIAN
!                 b      = TOTAL NUMBER OF OBSERVATIONS LESS THAN OR EQUAL
!                          TO THE GRAND MEDIAN
!
!              AT THE RECOMMENDATION OF CONOVER, ANY GROUPS WITH LESS THAN
!              TWO OBSERVATIONS ARE OMITTED FROM THE ANALYSIS AS THESE CAN
!              MAKE THE CHI-SQUARE APPROXIMATION INACCURATE.
!
!     EXAMPLE--MEDIAN TEST Y X
!     REFERENCE--CONOVER (1999), "PRACTICAL NONPARAMETRIC STATISTICS",
!                THIRD EDITION, WILEY, PP. 218 - 224.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/6
!     ORIGINAL VERSION--JUNE      2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IQUAME
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DFACT
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION XIDTEM(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPME'
      ISUBN2='T3  '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=CPUMIN
      STATCD=CPUMIN
      PVALUE=CPUMIN
      IDF=-99
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMET3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IQUAME,N,PMTEQU
   52   FORMAT('IBUGA3,ISUBRO,IQUAME,N,PMTEQU = ',3(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 01--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='01'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN MEDIAN TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES MUST BE 2 OR LARGER.  SUCH WAS NOT ',   &
               'THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS   = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,131)HOLD
  131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
      HOLD=X(1)
      DO 145 I=2,N
        IF(X(I).NE.HOLD)GO TO 149
  145 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,141)HOLD
  141 FORMAT('      THE GROUP-ID VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
  149 CONTINUE
!
!               *************************************
!               **   STEP 11--                     **
!               **   COMPUTE MEDIAN   TEST         **
!               *************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     DETERMINE DISTINCT VALUES OF GROUP-ID VARIABLE.  OMIT
!     ANY GROUPS WITH FEWER THAN TWO OBSERVATIONS.
!
      DO 1003 I=1,N
        TEMP1(I)=1.0
 1003 CONTINUE
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      DO 1010 K=1,NDIST
        HOLD=XIDTEM(K)
        NTEMP=0
        DO 1020 I=1,N
          IF(X(I).EQ.HOLD)THEN
            NTEMP=NTEMP+1
          ENDIF
 1020   CONTINUE
        IF(NTEMP.LE.1)THEN
          DO 1030 I=1,N
            IF(X(I).EQ.HOLD)TEMP1(I)=0.0
 1030     CONTINUE
        ENDIF
 1010 CONTINUE
!
      ICNT=0
      DO 1040 I=1,N
        IF(TEMP1(I).EQ.1.0)THEN
          ICNT=ICNT+1
          Y(ICNT)=Y(I)
          X(ICNT)=X(I)
        ENDIF
 1040 CONTINUE
      N=ICNT
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1041)
 1041   FORMAT('      AFTER OMITTING GROUPS WITH SAMPLE SIZE = 1')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1043)
 1043   FORMAT('      THE NUMBER OF RESPONSE VALUES IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     COMPUTE GRAND MEDIAN AND DETERMINE COUNTS ABOVE GRAND
!     MEDIAN FOR EACH GROUP
!
      IF(PMTEQU.NE.0.5)THEN
        CALL QUANT(PMTEQU,Y,N,IWRITE,TEMP1,MAXNXT,   &
                   IQUAME,   &
                   XMED,IBUGA3,IERROR)
      ELSE
        CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXNXT,XMED,IBUGA3,IERROR)
      ENDIF
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
!
      IF(NDIST.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1046)
 1046   FORMAT('      AFTER OMITTING GROUPS WITH SAMPLE SIZE = 1')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1048)
 1048   FORMAT('      THE NUMBER OF GROUPS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 1050 K=1,NDIST
        HOLD=XIDTEM(K)
        NTEMP=0
        IABOVE=0
        DO 1060 I=1,N
          IF(X(I).EQ.HOLD)THEN
            NTEMP=NTEMP+1
            IF(Y(I).GT.XMED)IABOVE=IABOVE+1
          ENDIF
 1060   CONTINUE
        TEMP1(K)=REAL(IABOVE)
        TEMP2(K)=REAL(NTEMP)
 1050 CONTINUE
!
      CALL SUMDP(TEMP1,NDIST,IWRITE,XA,IBUGA3,IERROR)
      AN=REAL(N)
      XB=AN - XA
      DFACT=DBLE(AN)**2/DBLE(XA*XB)
!
      DSUM1=0.0D0
      DO 1070 I=1,NDIST
        DSUM1=DSUM1 + (TEMP1(I) - TEMP2(I)*XA/AN)**2/TEMP2(I)
 1070 CONTINUE
      STATVA=REAL(DFACT*DSUM1)
!
!     CDF AND P-VALUES COMPUTED FROM CHI-SQUARE APPROXIMATION
!
      IDF=NDIST-1
      CALL CHSCDF(STATVA,IDF,STATCD)
      PVALUE=1.0 - STATCD
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MET3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMET3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATCD,PVALUE,IDF
 9013   FORMAT('STATVA,STATCD,PVALUE,IDF = ',3G15.7,I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)SBAR,D2,DSUM1,DSUM2,DSUM3
 9014   FORMAT('SBAR,D2,DSUM1,DSUM2,DSUM3 = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMET3
      SUBROUTINE DPMFCO(IHARG,NUMARG,IDEMFC,MAXMAR,IMAFCO,   &
                        IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MARKER FILL COLORS = THE COLORS
!              OF THE (BACKGROUND) FILL WITHIN THE MARKERS.
!              THESE ARE LOCATED IN THE VECTOR IMAFCO(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEMFC
!                     --MAXMAR
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--IMAFCO (A CHARACTER VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEMFC
      CHARACTER*4 IMAFCO
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
      CHARACTER*4 IHOLD2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
      DIMENSION IMAFCO(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPMF'
      ISUBN2='CO  '
!
      NUMMAR=0
      IHOLD1='-999'
      IHOLD2='-999'
!
      IF(IBUGP2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMFCO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR
   52 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXMAR,NUMMAR
   53 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IHOLD1,IHOLD2
   54 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)IDEMFC
   55 FORMAT('IDEMFC = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,60)NUMARG
   60 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,NUMARG
      WRITE(ICOUT,66)IHARG(I)
   66 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,70)IMAFCO(1)
   70 FORMAT('IMAFCO(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 75 I=1,10
      WRITE(ICOUT,76)I,IMAFCO(I)
   76 FORMAT('I,IMAFCO(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   75 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.1)GO TO 9000
      IF(NUMARG.EQ.2)GO TO 1120
      IF(NUMARG.EQ.3)GO TO 1130
      IF(NUMARG.EQ.4)GO TO 1140
      GO TO 1150
!
 1120 CONTINUE
      GO TO 1200
!
 1130 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1='    '
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1140 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1=IHARG(4)
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      IF(IHARG(4).EQ.'ALL')IHOLD1=IHARG(3)
      IF(IHARG(4).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1150 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE      SPECIFICATION  CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.2)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMMAR=1
      IMAFCO(1)=IDEMFC
      GO TO 1270
!
 1220 CONTINUE
      NUMMAR=NUMARG-2
      IF(NUMMAR.GT.MAXMAR)NUMMAR=MAXMAR
      DO 1225 I=1,NUMMAR
      J=I+2
      IHOLD1=IHARG(J)
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2=IDEMFC
      IF(IHOLD1.EQ.'OFF')IHOLD2=IDEMFC
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMFC
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMFC
      IMAFCO(I)=IHOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMMAR
      WRITE(ICOUT,1276)I,IMAFCO(I)
 1276 FORMAT('THE FILL COLOR OF MARKER ',I6,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMMAR=MAXMAR
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2=IDEMFC
      IF(IHOLD1.EQ.'OFF')IHOLD2=IDEMFC
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMFC
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMFC
      DO 1315 I=1,NUMMAR
      IMAFCO(I)=IHOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)IMAFCO(I)
 1316 FORMAT('THE FILL COLOR OF ALL MARKERS',   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMFCO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGP2,IFOUND,IERROR
 9012 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)MAXMAR,NUMMAR
 9013 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IHOLD1,IHOLD2
 9014 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IDEMFC
 9015 FORMAT('IDEMFC = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9020)NUMARG
 9020 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9025 I=1,NUMARG
      WRITE(ICOUT,9026)IHARG(I)
 9026 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
      WRITE(ICOUT,9030)IMAFCO(1)
 9030 FORMAT('IMAFCO(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 9035 I=1,10
      WRITE(ICOUT,9036)I,IMAFCO(I)
 9036 FORMAT('I,IMAFCO(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9035 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMFCO
      SUBROUTINE DPMFSW(IHARG,NUMARG,IDEMFS,MAXMAR,IMAFSW,   &
                        IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MARKER FILL SWITCHES = THE ON/OFF SWITCHES
!              OF THE (BACKGROUND) FILL WITHIN THE MARKERS.
!              THESE ARE LOCATED IN THE VECTOR IMAFSW(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEMFS
!                     --MAXMAR
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--IMAFSW (A CHARACTER VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEMFS
      CHARACTER*4 IMAFSW
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
      CHARACTER*4 IHOLD2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
      DIMENSION IMAFSW(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPMF'
      ISUBN2='SW  '
!
      NUMMAR=0
      IHOLD1='-999'
      IHOLD2='-999'
!
      IF(IBUGP2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPMFSW--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR
   52 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXMAR,NUMMAR
   53 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IHOLD1,IHOLD2
   54 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)IDEMFS
   55 FORMAT('IDEMFS = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,60)NUMARG
   60 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,NUMARG
      WRITE(ICOUT,66)IHARG(I)
   66 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,70)IMAFSW(1)
   70 FORMAT('IMAFSW(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 75 I=1,10
      WRITE(ICOUT,76)I,IMAFSW(I)
   76 FORMAT('I,IMAFSW(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   75 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.1)GO TO 9000
      IF(NUMARG.EQ.2)GO TO 1120
      IF(NUMARG.EQ.3)GO TO 1130
      IF(NUMARG.EQ.4)GO TO 1140
      GO TO 1150
!
 1120 CONTINUE
      GO TO 1200
!
 1130 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1='ON'
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1140 CONTINUE
      IF(IHARG(3).EQ.'ALL')IHOLD1=IHARG(4)
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      IF(IHARG(4).EQ.'ALL')IHOLD1=IHARG(3)
      IF(IHARG(4).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1150 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE      SPECIFICATION  CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.2)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMMAR=1
      IMAFSW(1)='ON'
      GO TO 1270
!
 1220 CONTINUE
      NUMMAR=NUMARG-2
      IF(NUMMAR.GT.MAXMAR)NUMMAR=MAXMAR
      DO 1225 I=1,NUMMAR
      J=I+2
      IHOLD1=IHARG(J)
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2='ON'
      IF(IHOLD1.EQ.'OFF')IHOLD2='OFF'
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMFS
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMFS
      IMAFSW(I)=IHOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMMAR
      WRITE(ICOUT,1276)I,IMAFSW(I)
 1276 FORMAT('THE FILL SWITCH FOR MARKER ',I6,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMMAR=MAXMAR
      IHOLD2=IHOLD1
      IF(IHOLD1.EQ.'ON')IHOLD2='ON'
      IF(IHOLD1.EQ.'OFF')IHOLD2='OFF'
      IF(IHOLD1.EQ.'AUTO')IHOLD2=IDEMFS
      IF(IHOLD1.EQ.'DEFA')IHOLD2=IDEMFS
      DO 1315 I=1,NUMMAR
      IMAFSW(I)=IHOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)IMAFSW(I)
 1316 FORMAT('THE FILL SWITCH FOR ALL MARKERS',   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPMFSW--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGP2,IFOUND,IERROR
 9012 FORMAT('IBUGP2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)MAXMAR,NUMMAR
 9013 FORMAT('MAXMAR,NUMMAR = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IHOLD1,IHOLD2
 9014 FORMAT('IHOLD1,IHOLD2 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IDEMFS
 9015 FORMAT('IDEMFS = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9020)NUMARG
 9020 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9025 I=1,NUMARG
      WRITE(ICOUT,9026)IHARG(I)
 9026 FORMAT('IHARG(I) = ',A4)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
      WRITE(ICOUT,9030)IMAFSW(1)
 9030 FORMAT('IMAFSW(1) = ',A4)
      CALL DPWRST('XXX','BUG ')
      DO 9035 I=1,10
      WRITE(ICOUT,9036)I,IMAFSW(I)
 9036 FORMAT('I,IMAFSW(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9035 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPMFSW
      SUBROUTINE DPMGET(Y,X,N,NVAR,   &
                        TEMP1,TEMP2,TEMP3,DTEMP1,   &
                        AMUMOM,BETAMO,AMUFR,BETAFR,AMUML,BETAML,   &
                        ICAPSW,ICAPTY,IFORSW,MAXNXT,   &
                        IGETDF,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE GEETA DISTRIBUTION.  ESTIMATES
!              ARE GENERATED IN TERMS OF THE MU/BETA
!              PARAMETERIZATION.
!
!              THE MOMENT ESTIMATES OF MU AND BETA ARE:
!
!                 MUHAT = XBAR
!                 BETAHAT = (S**2 - XBAR*(XBAR-1))/
!                           (S**2 - XBAR**2*(XBAR-1))
!
!              THE MEAN AND ONES FREQUENCY ESTIMATE OF MU IS:
!
!                  MUHAT = XBAR
!
!              THE ESTIMATE OF BETA IS THEN THE SOLUTION OF THE
!              EQUATION
!
!                 ((BETA-1)*XBAR/(BETA*XBAR-1))**(BETA-1) - (N1/N) = 0
!
!              THE MAXIMUM LIKELIHOOD FREQUENCY ESTIMATE OF MU IS:
!
!                  MUHAT = XBAR
!
!              THE ESTIMATE OF BETA IS THEN THE SOLUTION OF THE
!              EQUATION
!
!                 ((BETA-1)*XBAR/(BETA*XBAR-1))**(BETA-1) -
!                 (1/(N*XBAR))*
!                 SUM[X=2 to k][SUM[i=2 to k][X*N(x)/(BETA*X-1)]] = 0
!
!              THERE ARE TWO CASES:
!
!              1) ONE VARIABLE CASE: Y IS RAW DATA
!              2) TWO VARIABLE CASE: Y IS FREQUENCY, X IS CLASS
!                 MID-POINT.
!
!     EXAMPLE--GEETA MAXIMUM LIKELIHOOD Y
!            --GEETA MAXIMUM LIKELIHOOD Y X
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!     UPDATED         --APRIL     2011. USE DPDTA1 TO PRINT OUTPUT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IGETDF
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
!
!-------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(1)
      DOUBLE PRECISION FVEC(1)
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XMID
!
      DOUBLE PRECISION GETFUN
      DOUBLE PRECISION GETFU2
      EXTERNAL GETFUN
      EXTERNAL GETFU2
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION F1FREQ
      COMMON/GETCOM/XBAR,S2,F1FREQ,MAXRO2,NTOT2
!
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*1  ITITLZ
      CHARACTER*40 IDIST
      CHARACTER*40 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL      IFRST
      LOGICAL      ILAST
!
!-------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
      ISUBN1='DPMG'
      ISUBN2='ET  '
      IERROR='NO'
      IWRITE='OFF'
!
      AMUMOM=CPUMIN
      BETAMO=CPUMIN
      AMUFR=CPUMIN
      BETAFR=CPUMIN
      AMUML=CPUMIN
      BETAML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGET')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMGET--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IGETDF,N,NVAR
   52   FORMAT('IBUGA3,ISUBRO,IGETDF,N,NVAR = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        IF(NVAR.EQ.1)THEN
          DO 56 I=1,MIN(N,100)
            WRITE(ICOUT,57)I,Y(I)
   57       FORMAT('I,Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ELSE
          DO 61 I=1,N
            WRITE(ICOUT,62)I,X(I),Y(I)
   62       FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   61     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  1) ROUND DATA TO INTEGER VALUES       **
!               **  2) COMPUTE SUMMARY STATISTICS         **
!               **  3) CHECK INPUT FOR NEGATIVE VALUES,   **
!               **     INSUFFICIENT SAMPLE SIZE           **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GEETA'
!
      NPERC=0
      MAXGRP=MAXNXT/2
      NMIN=2
      IF(NVAR.EQ.1)THEN
        DO 1105 I=1,N
          ITEMP=INT(Y(I)+0.5)
          Y(I)=REAL(ITEMP)
 1105   CONTINUE
        CALL CKDIST(Y,N,NMIN,TEMP1,NPERC,ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IFLAG=1
        CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NTOTZZ=N
!
!       NOW BIN THE DATA FOR USE BY THE ESTIMATION METHOD BELOW
!
        IRELAT='OFF'
        IRHSTG='OFF'
        XSTART=XMIN-0.5
        XSTOP=XMAX+0.5
        CLWID=1.0
        CALL DPBINI(Y,N,IRELAT,CLWID,XSTART,XSTOP,IRHSTG,   &
                    TEMP1,X,N2,IBUGA3,IERROR)
        ICNT=0
        DO 1121 I=1,N2
          Y(I)=TEMP1(I)
          IF(Y(I).GT.0.0)THEN
            ICNT=ICNT+1
            Y(ICNT)=Y(I)
            X(ICNT)=X(I)
          ENDIF
1121    CONTINUE
        N2=ICNT
      ELSE
        CALL CKDIS2(Y,X,TEMP1,N,MAXGRP,NMIN,TEMP2,NPERC,NTOTZZ,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IFLAG1=1
        IFLAG2=1
        CALL SUMGRP(Y,X,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOTZZ,   &
                    ISUBRO,IBUGA3,IERROR)
        ICNT=0
        NTOTZZ=0
        DO 1211 I=1,N
          IF(Y(I).GT.0.0)THEN
            ICNT=ICNT+1
            Y(ICNT)=Y(I)
            X(ICNT)=X(I)
            NTOTZZ=NTOTZZ + INT(Y(I)+0.01)
          ENDIF
1211    CONTINUE
        N2=ICNT
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGET')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1311)
 1311   FORMAT('AFTER COMPUTE SUMMARY STATISTICS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1312)XMEAN,XVAR,XSD,XMIN,XMAX,NTOTZZ
 1312   FORMAT('XMEAN,XVAR,XSD,XMIN,XMAX,NTOTZZ = ',5G15.7,I10)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               *********************************************
!               **  STEP 21--                              **
!               **  CARRY OUT CALCULATIONS                 **
!               **  FOR GEETA MLE                          **
!               **  ESTIMATION                             **
!               *********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      F1=Y(1)/REAL(NTOTZZ)
      IINDX=MAXNXT/2
      IF(N2.LE.IINDX)THEN
        IML=0
        DO 2210 I=1,N2
          TEMP3(I)=Y(I)
          TEMP3(IINDX+I)=X(I)
 2210   CONTINUE
        IK=N2
      ELSE
        IML=1
      ENDIF
!
      ACUT=XMEAN**2*(XMEAN-1.0)
      IF(XVAR.LE.ACUT)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1131)
 1131   FORMAT('***** ERROR IN GEETA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2223)
 2223   FORMAT('      IN ORDER FOR THE GEETA DISTRIBUTION TO BE ',   &
               'APPLICABLE,')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2225)
 2225   FORMAT('         S**2 > XBAR**2*(XBAR - 1)')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2227)
 2227   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2228)XMEAN
 2228   FORMAT('      SAMPLE MEAN     = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2229)XVAR
 2229   FORMAT('      SAMPLE VARIANCE = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
!
      AMUMOM=XMEAN
      BETAMO=(XVAR - XMEAN*(XMEAN-1.0))/(XVAR - XMEAN**2*(XMEAN-1.0))
      AMUFR=XMEAN
      BETAFR=0.0
      AMUML=XMEAN
      BETAML=0.0
!
      AE=1.D-7
      RE=1.D-7
      XBAR=DBLE(XMEAN)
      S2=DBLE(XSD)**2
      F1FREQ=DBLE(F1)
      XMID=DBLE(BETAMO)
      XLOW=1.000001D0
      XUP=XMID + 10.0D0
      CALL DFZERO(GETFUN,XLOW,XUP,XMID,RE,AE,IFLAG)
      BETAFR=REAL(XLOW)
!
      IOPT=2
      TOL=1.0D-3
      NPAR=1
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      MAXRO2=MAXNXT
      NTOT2=NTOTZZ
!
      XPAR(1)=DBLE(BETAFR)
      XPAR(1)=1.5D0
      CALL DNSQE(GETFU2,JAC,IOPT,NPAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                   DTEMP1,LWA,TEMP3,IK)
!
      BETAML=REAL(XPAR(1))
!
!               ***********************************************
!               **   STEP 42--                               **
!               **   WRITE OUT EVERYTHING                    **
!               **   FOR GEETA MLE                           **
!               **   ESTIMATION                              **
!               ***********************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT SUMMARY STATISTICS TABLE
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Geeta Parameter Estimation'
      NCTITL=42
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(NTOTZZ)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample First Frequency:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=F1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Moments:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      IF(IGETDF.EQ.'THET')THEN
        ITEXT(ICNT)='Estimate of Theta:'
        NCTEXT(ICNT)=18
      ELSE
        ITEXT(ICNT)='Estimate of Mu:'
        NCTEXT(ICNT)=15
      ENDIF
      AVALUE(ICNT)=AMUMOM
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAMO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of First Frequency and Mean:'
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      IF(IGETDF.EQ.'THET')THEN
        ITEXT(ICNT)='Estimate of Theta:'
        NCTEXT(ICNT)=18
      ELSE
        ITEXT(ICNT)='Estimate of Mu:'
        NCTEXT(ICNT)=15
      ENDIF
      AVALUE(ICNT)=AMUFR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAFR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Maximum Likelihood:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      IF(IGETDF.EQ.'THET')THEN
        ITEXT(ICNT)='Estimate of Theta:'
        NCTEXT(ICNT)=18
      ELSE
        ITEXT(ICNT)='Estimate of Mu:'
        NCTEXT(ICNT)=15
      ENDIF
      AVALUE(ICNT)=AMUML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 2310 I=1,NUMROW
        NTOT(I)=15
 2310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGET')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMGET--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)AMUMOM,BETAMO,AMUFR,BETAFR,AMUML,BETAML
 9013   FORMAT('AMUMOM,BETAMO,AMUFR,BETAFR,AMUML,BETAML = ',6G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMGET
      SUBROUTINE DPMGNB(Y,X,N,NVAR,   &
                        TEMP1,TEMP2,TEMP3,DTEMP1,   &
                        THETMO,BETAMO,AMMOM,   &
                        THETFR,BETAFR,AMFR,   &
                        THETF2,BETAF2,AMF2,   &
                        THETML,BETAML,AMML,   &
                        ICAPSW,ICAPTY,IFORSW,MAXNXT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE GENERALIZED NEGATIVE BINOMIAL
!              DISTRIBUTION.
!
!              THE MOMENT ESTIMATE OF THETA IS THE SOLUTION
!              OF THE EQUATION:
!
!                 THETAHAT = 1 - 0.5*A + (A**2/4 - 1)**(0.5)
!                 A = -2 + (XBAR*S3 - 3*S2**2)**2/(XBAR*S2**3)
!
!                 BETAHAT = {1 - SQRT(XBAR*(1-THETAHAT)/S2)}/THETAHAT
!                 MHAT = XBAR*(1-THETAHAT*BETAHAT)/THETAHAT
!
!                 S2 = SAMPLE VARIANCE
!                 S3 = SAMPLE THIRD SAMPLE MOMENT
!                      (SUM[i=0 to k][N(i)*(i-XBAR)**3/(N-1) =
!                       SUM[j=1 to n][(X(j) - XBAR)**2]
!
!              THE MOMENTS AND ZERO FREQUENCY ESTIMATE OF THETA
!              IS THE SOLUTION OF THE EQUATION
!
!                 S2*(LOG(F0)**2/XBAR**3 -
!                 (1-THETA)*(LOG(1-THETA))**2/THETA**2 = 0
!
!                 MHAT = SQRT{(1-THETAHAT)*XBAR**3/S2}/THETAHAT
!                 BETAHAT = (1/THETAHAT) - MHAT/XBAR
!
!
!              THE MOMENTS AND RATIO OF FREQUENCIES ESTIMATE OF
!              THETA IS THE SOLUTION OF THE EQUATION
!
!                 {(2/THETA) - (2/THETA)*SQRT(XBAR*(1-THETA)/S2)-1}*
!                 LOG(1-THETA) - LOG(S2*F10**2/XBAR**3) = 0
!
!                 F10 = F1/F0
!
!                 MHAT = SQRT{(1-THETAHAT)*XBAR**3/S2}/THETA
!                 BETAHAT = (1/THETAHAT) - MHAT/XBAR
!
!              THE MAXIMUM LIKELIHOOD ESTIMATES ARE THE SOLUTIONS
!              TO THE EQUATIONS:
!
!                 (N-N0)*XBAR/M - SUM[X=2 to k][SUM[i=1 to x-1]
!                 [(X-XBAR)*N(x)/(M+BETA*X-i]] = 0
!
!                 N*XBAR*LOG(1-XBAR/(M+BETA*XBAR)) +
!                 SUM[X=2 to k][SUM[i=1 to x-1]
!                 [X*N(x)/(M+BETA*X-i]] = 0
!
!                 THETAHAT = XBAR/(MHAT+BETA*XBAR)
!
!              THERE ARE TWO CASES:
!
!              1) ONE VARIABLE CASE: Y IS RAW DATA
!              2) TWO VARIABLE CASE: Y IS FREQUENCY, X IS CLASS
!                 MID-POINT.
!
!     EXAMPLE--GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y
!            --GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y X
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!     UPDATED         --APRIL     2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
!
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*1  ITITLZ
      CHARACTER*40 IDIST
      CHARACTER*40 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL      IFRST
      LOGICAL      ILAST
!
!-------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(3)
      DOUBLE PRECISION FVEC(3)
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XMID
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DA
!
      DOUBLE PRECISION GNBFUN
      DOUBLE PRECISION GNBFU3
      DOUBLE PRECISION GNBFU4
      DOUBLE PRECISION GNBFU5
      EXTERNAL GNBFUN
      EXTERNAL GNBFU2
      EXTERNAL GNBFU3
      EXTERNAL GNBFU4
      EXTERNAL GNBFU5
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
      DOUBLE PRECISION F0FREQ
      DOUBLE PRECISION F1FREQ
      DOUBLE PRECISION F10FRE
      DOUBLE PRECISION DC1
      COMMON/GNBCOM/XBAR,S2,S3,F0FREQ,F1FREQ,F10FRE,DC1,   &
                    MAXRO2,NTOT2
!
!-------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
      ISUBN1='DPMG'
      ISUBN2='NB  '
      IERROR='NO'
      IWRITE='OFF'
!
      THETMO=CPUMIN
      BETAMO=CPUMIN
      AMMOM=CPUMIN
      THETFR=CPUMIN
      BETAFR=CPUMIN
      AMFR=CPUMIN
      THETF2=CPUMIN
      BETAF2=CPUMIN
      AMF2=CPUMIN
      THETML=CPUMIN
      BETAML=CPUMIN
      AMML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGNB')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPMGNB--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,NVAR
   52   FORMAT('IBUGA3,ISUBRO,N,NVAR = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        IF(NVAR.EQ.1)THEN
          DO 56 I=1,MIN(N,100)
            WRITE(ICOUT,57)I,Y(I)
   57       FORMAT('I,Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ELSE
          DO 61 I=1,N
            WRITE(ICOUT,62)I,X(I),Y(I)
   62       FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   61     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  1) ROUND DATA TO INTEGER VALUES       **
!               **  2) COMPUTE SUMMARY STATISTICS         **
!               **  3) CHECK INPUT FOR NEGATIVE VALUES,   **
!               **     INSUFFICIENT SAMPLE SIZE           **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MLAE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GENERALIZED NEGATIVE BINOMIAL'
!
      NPERC=0
      MAXGRP=MAXNXT/2
      NMIN=2
      IF(NVAR.EQ.1)THEN
        DO 1105 I=1,N
          ITEMP=INT(Y(I)+0.5)
          Y(I)=REAL(ITEMP)
 1105   CONTINUE
        CALL CKDIST(Y,N,NMIN,TEMP1,NPERC,ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IFLAG=1
        CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NTOTZZ=N
!
!       NOW BIN THE DATA FOR USE BY THE ESTIMATION METHOD BELOW
!
        IRELAT='OFF'
        IRHSTG='OFF'
        XSTART=XMIN-0.5
        XSTOP=XMAX+0.5
        CLWID=1.0
        CALL DPBINI(Y,N,IRELAT,CLWID,XSTART,XSTOP,IRHSTG,   &
                    TEMP1,X,N2,IBUGA3,IERROR)
        ICNT=0
        DO 1121 I=1,N2
          IF(TEMP1(I).GT.0.0)THEN
            ICNT=ICNT+1
            Y(ICNT)=TEMP1(I)
            X(ICNT)=X(I)
          ENDIF
1121    CONTINUE
        N2=ICNT
      ELSE
        CALL CKDIS2(Y,X,TEMP1,N,MAXGRP,NMIN,TEMP2,NPERC,NTOTZZ,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IFLAG1=1
        IFLAG2=1
        CALL SUMGRP(Y,X,N,IDIST,IFLAG1,IFLAG2,   &
                    TEMP1,TEMP2,TEMP3,MAXNXT,   &
                    XMEAN,XVAR,XSD,XMIN,XMAX,NTOTZZ,   &
                    ISUBRO,IBUGA3,IERROR)
        ICNT=0
        DO 1221 I=1,N
          IF(Y(I).GT.0.0)THEN
            ICNT=ICNT+1
            Y(ICNT)=Y(I)
            X(ICNT)=X(I)
          ENDIF
1221    CONTINUE
        N2=ICNT
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGNB')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1311)
 1311   FORMAT('AFTER COMPUTE SUMMARY STATISTICS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1312)XMEAN,XVAR,XSD,XMIN,XMAX,NTOTZZ
 1312   FORMAT('XMEAN,XVAR,XSD,XMIN,XMAX,NTOTZZ = ',5G15.7,I10)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               *********************************************
!               **  STEP 21--                              **
!               **  CARRY OUT CALCULATIONS                 **
!               **  FOR GENERALIZED NEGATIVE BINOMIAL MLE  **
!               **  ESTIMATION                             **
!               *********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGNB')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IML=0
      IINDX=MAXNXT/2
      IF(N2.LE.IINDX)THEN
        IWD=0
        DO 2290 I=1,N2
          TEMP3(I)=Y(I)
          TEMP3(IINDX+I)=X(I)
 2290   CONTINUE
        IK=N2
      ELSE
        IML=1
      ENDIF
!
      F0=Y(1)
      F1=Y(2)
      F10=F0/F1
!
      DSUM=0.0D0
      DO 2208 I=1,N2
        DSUM=DSUM +  DBLE(Y(I))*(DBLE(I) - DBLE(XMEAN))**3
 2208 CONTINUE
      S3=REAL(DSUM/DBLE(NTOTZZ-1))
!
      XBAR=DBLE(XMEAN)
      S2=DBLE(XSD)**2
      DA=-2.0D0 + (XBAR*S3 - 3.0D0*S2**2)**2/(XBAR*S2**3)
      THETMO=REAL(1.0D0 - 0.5D0*DA + DSQRT(DA**2/4.0D0 - 1.0D0))
      BETAMO=(1.0 - SQRT(XBAR*(1.0-THETMO)/S2))/THETMO
      IF(BETAMO.LE.1.0)BETAMO=1.0
      AMMOM=XBAR*(1.0-THETMO*BETAMO)/THETMO
!
      AE=1.D-7
      RE=1.D-7
      XLOW=0.000001D0
      XUP=0.999999D0
      XMID=0.5D0
      F0FREQ=DBLE(F0)
      F1FREQ=DBLE(F1)
      F10FRE=DBLE(F10)
      NTOT2=NTOTZZ
!
      IFR=0
      IF(F0.GT.0.0)THEN
        C1=S2*LOG(F0)**2/(XBAR**3)
        IF(C1.GE.1.0 .OR. C1.LE.0.0)IFR=1
      ELSE
        IFR=1
      ENDIF
      IF(IFR.EQ.0)THEN
        DC1=DBLE(C1)
        XLOW=0.000001D0
        XUP=0.999999D0
        XMID=DBLE(THETMO)
        CALL DFZERO(GNBFU3,XLOW,XUP,XMID,RE,AE,IFLAG)
        THETFR=REAL(XLOW)
        AMFR=SQRT((1.0-THETFR)*XMEAN**3/XVAR)/THETFR
        BETAFR=(1.0/THETFR) - (AMFR/XMEAN)
        IF(BETAFR.LE.1.0)BETAFR=1.0
      ENDIF
!
      IFR2=0
      XLOW=0.000001D0
      XUP=0.999999D0
      DTERM1=GNBFU4(XLOW)
      DTERM2=GNBFU4(XUP)
      IF(DTERM1*DTERM2.GT.0.0D0)THEN
        IFR2=1
      ENDIF
      IF(IFR2.EQ.0)THEN
        XMID=DBLE(THETMO)
        CALL DFZERO(GNBFU4,XLOW,XUP,XMID,RE,AE,IFLAG)
        THETF2=REAL(XLOW)
        AMF2=SQRT((1.0-THETF2)*XMEAN**3/XVAR)/THETF2
        BETAF2=(1.0/THETF2) - (AMF2/XMEAN)
        IF(BETAF2.LE.1.0)BETAF2=1.0
      ENDIF
!
      IF(IML.EQ.0)THEN
        IOPT=2
        TOL=1.0D-5
        NPAR=3
        NPRINT=-1
        INFO=0
        LWA=MAXNXT
        MAXRO2=MAXNXT
!
        IF(IFR2.EQ.0)THEN
          XPAR(1)=DBLE(BETAF2)
          XPAR(2)=DBLE(AMF2)
          XPAR(3)=DBLE(THETF2)
        ELSEIF(IFR.EQ.0)THEN
          XPAR(1)=DBLE(BETAFR)
          XPAR(2)=DBLE(AMFR)
          XPAR(3)=DBLE(THETFR)
        ELSE
          XPAR(1)=DBLE(BETAMO)
          XPAR(2)=DBLE(BETAMO)
          XPAR(3)=DBLE(THETMO)
        ENDIF
        CALL DNSQE(GNBFU2,JAC,IOPT,NPAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                   DTEMP1,LWA,TEMP3,IK)
!
        BETAML=REAL(XPAR(1))
        AMML=REAL(XPAR(2))
        THETML=REAL(XPAR(3))
      ENDIF
!
!     1/2007: NOW DO THE TRUNCATED CASE.
!
!     METHOD 1: MEAN AND RATIO OF FREQUENCIES (RATIO METHOD)
!
      AE=1.D-7
      RE=1.D-7
      XLOW=0.005D0
      XMID=DBLE(AMMOM)
      XUP=5.0D0*XMID
      F0FREQ=DBLE(F0)
      F1FREQ=DBLE(F1)
      F10FRE=DBLE(F10)
      NTOT2=NTOTZZ
!
!CCCC CALL DFZERO(GNBFU3,XLOW,XUP,XMID,RE,AE,IFLAG)
!CCCC AMRA=REAL(XLOW)
!CCCC BETARA=AMRA*F0FREQ*F2FREQ/(F1FREQ**2) - (AMRA-1.0)/2.0
!CCCC print *,'amra,betara=',amra,betara
!CCCC THETRA=
!
!
!               ***********************************************
!               **   STEP 42--                               **
!               **   WRITE OUT EVERYTHING                    **
!               **   FOR GENERALIZED NEGATIVE BINOMIAL MLE   **
!               **   ESTIMATION                              **
!               ***********************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MGNB')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT SUMMARY STATISTICS TABLE
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Generalized Negative Binomial Parameter Estimation'
      NCTITL=50
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(NTOTZZ)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Centralized Third Moment:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=REAL(S3)
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Zero-Class Frequency:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=F0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Ones-Class Frequency:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=F1
      IDIGIT(ICNT)=NUMDIG
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Ratio of Ones- and Zero-Frequencies:'
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=F10
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Moments:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Theta:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=THETMO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAMO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of M:'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=AMMOM
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Zero-Class Frequency/Moments:'
      NCTEXT(ICNT)=39
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Theta:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=THETFR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAFR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of M:'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=AMFR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Ratio of Frequencies/Moments:'
      NCTEXT(ICNT)=39
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Theta:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=THETF2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAF2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of M:'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=AMF2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Maximum Likelihood:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Theta:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=THETML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Beta:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=BETAML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of M:'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=AMML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 2310 I=1,NUMROW
        NTOT(I)=15
 2310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGNB')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPMGNB--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPMGNB
      SUBROUTINE DPMGU1(Y,N,   &
                        XTEMP,DTEMP,MAXNXT,   &
                        SCALML,SCALSE,SCALMO,SCMOSE,   &
                        ALOCML,ALMLSE,ALOCMO,ALMOSE,COVSE,   &
                        NUMV,   &
                        ICAPSW,ICAPTY,IFORSW,MINMAX,   &
                        QP,XQPHAT,XQPSE,XQPLCL,XQPUCL,NPERC,   &
                        XQPHTZ,XQPLCZ,XQPUCZ,   &
                        IOUNI1,IOUNI2,ALPHAP,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD
!              ESTIMATES FOR GUMBEL (EXTREME VALUE TYPE 1) DISTRIBUTION
!              FOR THE FULL SAMPLE CASE.
!     EXAMPLE--GUMBEL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 15.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/12
!     ORIGINAL VERSION--DECEMBER  2004.
!     UPDATED         --OCTOBER   2009. DEFAULT MINMAX CASE =
!                                       MAXIMUM (TO BE CONSISTENT
!                                       WITH EV1CDF, EV1PDF, EV1PPF)
!     UPDATED         --OCTOBER   2009. EXTRACT SOME CODE TO EV1ML1
!                                       (TO MAKE IT EASIER FOR OTHER
!                                       ROUTINES TO OBTAIN ML
!                                       ESTIMATES)
!     UPDATED         --JUNE      2010. USE DPDTA1 AND DPDTA7 TO
!                                       PRINT OUTPUT, ADD AIC AND
!                                       RELATED STATISTICS TO OUTPUT
!     UPDATED         --MARCH     2014. SUPPORT FOR ONE-SIDED PERCENTILES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ILIKFL
      CHARACTER*4 INORM
      CHARACTER*7 ICASE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      PARAMETER (NUMALP=6)
      DIMENSION ALPHA(NUMALP)
      DIMENSION ALOWLO(NUMALP)
      DIMENSION AUPPLO(NUMALP)
      DIMENSION ALOWL2(NUMALP)
      DIMENSION AUPPL2(NUMALP)
      DIMENSION ALOWSC(NUMALP)
      DIMENSION AUPPSC(NUMALP)
      DIMENSION ALOWS2(NUMALP)
      DIMENSION AUPPS2(NUMALP)
!
      DIMENSION Y(*)
      DIMENSION XTEMP(*)
      DIMENSION XQPHTZ(*)
      DIMENSION XQPLCZ(*)
      DIMENSION XQPUCZ(*)
      DIMENSION QP(*)
      DIMENSION XQPHAT(*)
      DIMENSION XQPSE(*)
      DIMENSION XQPLCL(*)
      DIMENSION XQPUCL(*)
!
      DOUBLE PRECISION DTEMP(*)
!
      DOUBLE PRECISION EV1FU6
      EXTERNAL EV1FU6
!
      DOUBLE PRECISION DQ
      DOUBLE PRECISION SHATML
      COMMON/EV1CO6/DQ,SHATML
!
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA /0.50, 0.25, 0.10, 0.05, 0.01, 0.001/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPMG'
      ISUBN2='U1  '
      IERROR='NO'
!
      ICASE='Minimum'
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)ICASE='Maximum'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGU1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPPGU1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,NUMV,IOUNI1,MAXNXT
   55   FORMAT('N,NUMV,IOUNI1,MAXNXT = ',4I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGU1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NMIN=3
      CALL CKDIST(Y,N,NMIN,QP,NPERC,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               **********************************
!               **  STEP 41--                   **
!               **  CARRY OUT CALCULATIONS      **
!               **  FOR GUMBEL MLE              **
!               **  ESTIMATE (FULL SAMPLE CASE) **
!               **********************************
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGU1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      AN=REAL(N)
      ICAS2=1
      CALL EV1ML1(Y,N,MINMAX,IGUMBC,ICAS2,   &
                  DTEMP,   &
                  ALOWLO,AUPPLO,ALOWSC,AUPPSC,   &
                  ALOWL2,AUPPL2,ALOWS2,AUPPS2,   &
                  ALPHA,NUMALP,NUMOUT,   &
                  XMEAN,XSD,XMIN,XMAX,   &
                  ALOCMO,SCALMO,ALMOSE,SCMOSE,   &
                  ALOCML,SCALML,SCA2ML,ALMLSE,SCALSE,COVSE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IGUMBC.EQ.'ON')THEN
        SCALML=SCA2ML
      ENDIF
!
      CALL EV1LI1(Y,N,MINMAX,ALOCML,SCALML,   &
                  ALIK,AIC,AICC,BIC,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               **********************************************
!               **  STEP 41B--                              **
!               **  ESTIMATE CONFIDENCE LIMITS FOR SELECTED **
!               **  PERCENTILES.  THE CONFIDENCE LIMITS ON  **
!               **  SIGMA ARE (SL,SU) ARE:                  **
!               **  (2*N*SIGMAHAT/CHSPPF(2N,1-ALPHA/2),     **
!               **   2*N*SIGMAHAT/CHSPPF(2N,1-ALPHA/2))     **
!               **  THEN (XpLCL,XpUCL) IS:                  **
!               **  ((-LN(1 - Xp))*SL,(-LN(1 - Xp))*SU)     **
!               **********************************************
!
      ISTEPN='41B'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MLNO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!  NOTE: FOR 2-PARAMETER MODEL, USE APPROXIMATION
!        FOR LOWER LIMIT GIVEN ON PP. 190-191 OF BURY.
!
      IF(NPERC.GE.1)THEN
!
        NUTEMP=1
        IF(IDTYPR.EQ.'LOWE')THEN
          ALP=ALPHAP
          P=1.0-ALP
        ELSEIF(IDTYPR.EQ.'UPPE')THEN
          ALP=ALPHAP
          P=1.0-ALP
        ELSE
          ALP=ALPHAP
          P=1.0-(ALP/2.0)
        ENDIF
!
        CALL NORPPF(P,ANOR)
        DK=DBLE(APPF)
        SHATML=DBLE(SCALML)
        CALL CHSPPF(1.0-ALP,NUTEMP,APPF)
!
        DAE=1.D-7
        DRE=1.D-7
!
        WRITE(IOUNI2,3131)
 3131   FORMAT(15X,'       POINT     ','   STANDARD    ',   &
               '     LOWER     ','     UPPER')
        WRITE(IOUNI2,3132)
 3132   FORMAT('    PERCENTILE ','     ESTIMATE   ','     ERROR     ',   &
               'CONFIDENCE LIMIT ','CONFIDENCE LIMIT')
        DO 3130 I=1,NPERC
!
          QPTEMP=QP(I)/100.0
          CALL EV1PPF(QPTEMP,MINMAX,APPF)
!
          XQPHAT(I)=ALOCML + SCALML*APPF
          SEXQP=ALMLSE**2 + (APPF*SCALSE)**2 + 2.0*APPF*COVSE**2
          XQPSE(I)=SQRT(SEXQP)
          IF(IDTYPR.EQ.'LOWE')THEN
            XQPLCL(I)=XQPHAT(I) - ANOR*XQPSE(I)
            XQPUCL(I)=CPUMIN
          ELSEIF(IDTYPR.EQ.'UPPE')THEN
            XQPLCL(I)=CPUMIN
            XQPUCL(I)=XQPHAT(I) + ANOR*XQPSE(I)
          ELSE
            XQPLCL(I)=XQPHAT(I) - ANOR*XQPSE(I)
            XQPUCL(I)=XQPHAT(I) + ANOR*XQPSE(I)
          ENDIF
          WRITE(IOUNI2,'(6E15.7)')   &
               QP(I),XQPHAT(I),SEXQP,XQPLCL(I),XQPUCL(I)
!
          DQ=DBLE(QPTEMP)
          DPPF=DBLE(XQPHAT(I))
          DXSTRT=DBLE(XQPLCL(I))
          DXLOW=DPPF/2.0D0
          DXUP=DBLE(XQPHAT(I))
          CALL DFZER2(EV1FU6,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
          XQPLCZ(I)=REAL(DXLOW)
!
          DXSTRT=DBLE(XQPUCL(I))
          DXUP=DPPF*2.0D0
          DXLOW=DBLE(XQPHAT(I))
          CALL DFZER2(EV1FU6,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
          XQPUCZ(I)=REAL(DXLOW)
!
          IF(IDTYPR.EQ.'LOWE')XQPUCL(I)=CPUMIN
          IF(IDTYPR.EQ.'UPPE')XQPLCL(I)=CPUMIN
!
 3130   CONTINUE
!
      ENDIF
!
!               *************************************
!               **   STEP 42--                     **
!               **   WRITE OUT EVERYTHING          **
!               **   FOR GUMBEL MLE ESTIMATE       **
!               *************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGU1')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(MINMAX.EQ.1)THEN
        ITITLE='Gumbel (Minimum) Parameter Estimation'
        NCTITL=37
        ITITLZ='f(x) = (1/s)*EXP((x-u)/s)*EXP(-EXP((x-u)/x))'
        NCTITZ=44
      ELSE
        ITITLE='Gumbel (Maximum) Parameter Estimation'
        NCTITL=37
        ITITLZ='f(x) = (1/s)*EXP(-(x-u)/s)*EXP(-EXP(-(x-u)/s))'
        NCTITZ=46
      ENDIF
      ICNT=1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Method of Moments:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Location:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=ALOCMO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Error of Location:'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=ALMOSE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Scale:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=SCALMO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Error of Scale:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=SCMOSE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      IF(IGUMBC.EQ.'ON')THEN
        ITEXT(ICNT)='Maximum Likelihood (with Bias Correction):'
        NCTEXT(ICNT)=42
      ELSE
        ITEXT(ICNT)='Maximum Likelihood (without Bias Correction):'
        NCTEXT(ICNT)=45
      ENDIF
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Location:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=ALOCML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Error of Location:'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=ALMLSE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Scale:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=SCALML
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Error of Scale:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=SCALSE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Covariance:'
      NCTEXT(ICNT)=11
      AVALUE(ICNT)=COVSE
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Log-likelihood:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=ALIK
      IDIGIT(ICNT)=-7
      ICNT=ICNT+1
      ITEXT(ICNT)='AIC:'
      NCTEXT(ICNT)=4
      AVALUE(ICNT)=AIC
      IDIGIT(ICNT)=-7
      ICNT=ICNT+1
      ITEXT(ICNT)='AICc:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=AICC
      IDIGIT(ICNT)=-7
      ICNT=ICNT+1
      ITEXT(ICNT)='BIC:'
      NCTEXT(ICNT)=4
      AVALUE(ICNT)=BIC
      IDIGIT(ICNT)=-7
!
      NUMROW=ICNT
      DO 2320 I=1,NUMROW
        NTOT(I)=15
 2320 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      NCTITZ=0
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!     NOTE: LIKELIHOOD RATIO METHOD CURRENTLY NOT WORKING FOR
!           MINIMUM CASE.
!
      IF(NUMOUT.GT.1)THEN
        INORM='YES'
        IF(MINMAX.EQ.1)THEN
          CALL DPDTA7(ALOWLO,AUPPLO,ALOWSC,AUPPSC,ALPHA,NUMALP,   &
                      ICAPSW,ICAPTY,NUMDIG,INORM,   &
                      ISUBRO,IBUGA3,IERROR)
        ELSE
          CALL DPDT77(ALOWLO,AUPPLO,ALOWSC,AUPPSC,   &
                      ALOWL2,AUPPL2,ALOWS2,AUPPS2,   &
                      ALPHA,NUMALP,   &
                      ICAPSW,ICAPTY,NUMDIG,   &
                      ISUBRO,IBUGA3,IERROR)
        ENDIF
      ENDIF
!
      IF(NPERC.GE.1)THEN
        ILIKFL='OFF'
        CALL DPDTA9(QP,XQPHAT,XQPLCL,XQPUCL,XQPSE,NPERC,   &
                    ICAPSW,ICAPTY,ILIKFL,NUMDIG,ALPHAP,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(MINMAX.EQ.2)THEN
          ILIKFL='ON'
          CALL DPDTA9(QP,XQPHAT,XQPLCZ,XQPUCZ,XQPSE,NPERC,   &
                      ICAPSW,ICAPTY,ILIKFL,NUMDIG,ALPHAP,   &
                      ISUBRO,IBUGA3,IERROR)
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MGU1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPPGU1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 9014 I=1,N
          WRITE(ICOUT,9015)I,XQPHTZ(I),XTEMP(I)
 9015     FORMAT('I,XQPHTZ(I),XTEMP(I) = ',I8,2X,2G15.7)
          CALL DPWRST('XXX','WRIT')
 9014   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPMGU1
      SUBROUTINE DPMIN(ICOM,IHARG,IARGT,ARG,NUMARG,   &
                       GX1MIN,GY1MIN,GX2MIN,GY2MIN,   &
                       IX1MIN,IY1MIN,IX2MIN,IY2MIN,   &
                       IFOUND,IERROR)
!
!     PURPOSE--DEFINE AXIS MINIMA
!              (HORIZONTAL AXIS OR VERTICAL AXIS OR BOTH)
!              WHICH IN TURN WILL DEFINE THE LOWER EXTREME
!              WHICH WILL APPEAR ON THE PLOT.
!              THE MINIMA WILL BE PLACED IN THE 4 VARIABLES
!              GX1MIN,GY1MIN,
!              GX2MIN,GY2MIN,
!              THE STATUS (FIXED OR FLOAT) WILL BE PLACED
!              IN THE 4 VARIABLES
!              IX1MIN,IY1MIN,
!              IX2MIN,IY2MIN,
!     INPUT  ARGUMENTS--ICOM  (A  HOLLERITH VARIABLE)
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--
!                     --GX1MIN = MINIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --GY1MIN = MINIMUM FOR LEFT   VERTICAL   AXIS
!                     --GX2MIN = MINIMUM FOR TOP    HORIZONTAL AXIS
!                     --GX2MIN = MINIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IX1MIN = STATUS FOR MINIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --IY1MIN = STATUS FOR MINIMUM FOR LEFT   VERTICAL   AXIS
!                     --IX2MIN = STATUS FOR MINIMUM FOR TOP    HORIZONTAL AXIS
!                     --IX2MIN = STATUS FOR MINIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY 1992.  FIX YMIN WITH NO ARG BOMB
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IX1MIN
      CHARACTER*4 IY1MIN
      CHARACTER*4 IX2MIN
      CHARACTER*4 IY2MIN
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
!CCCC THE FOLLOWING LINE WAS FIXED FEBRUARY 1992
!CCCC IF(IHARG(NUMARG).EQ.'?')GO TO 8100
      IF(NUMARG.LE.0)GO TO 1090
      IF(IHARG(NUMARG).EQ.'?')GO TO 8100
 1090 CONTINUE
!
!               *****************************************************
!               **  TREAT THE CASE WHEN                           **
!               **  BOTH HORIZONTAL AXIS MINIMA ARE TO BE FIXED    **
!               *****************************************************
!
      IF(ICOM.EQ.'XMIN')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(NUMARG.LE.0)GO TO 1110
      IF(IARGT(1).EQ.'NUMB')GO TO 1120
      GO TO 1110
!
 1110 CONTINUE
      IFOUND='YES'
      GX1MIN=CPUMIN
      GX2MIN=CPUMIN
      IX1MIN='FLOA'
      IX2MIN='FLOA'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1119
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1115)
 1115 FORMAT('THE X AXIS MINIMUM (FOR BOTH HORIZONTAL')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('FRAME LINES) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1117)
 1117 FORMAT('SO THAT IT WILL FLOAT WITH THE PLOTTED DATA')
      CALL DPWRST('XXX','BUG ')
 1119 CONTINUE
      GO TO 9000
!
 1120 CONTINUE
      IFOUND='YES'
      A1=ARG(1)
      GX1MIN=A1
      GX2MIN=A1
      IX1MIN='FIXE'
      IX2MIN='FIXE'
!
