      SUBROUTINE DPMITN(IHARG,IARGT,IARG,NUMARG,   &
                        IX1NSW,IX2NSW,IY1NSW,IY2NSW,   &
                        NMNX1T,NMNX2T,NMNY1T,NMNY2T,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE NUMBER OF MINOR TIC MARKS
!              FOR HORIZONTAL FRAME LINES OR VERTICAL FRAME LINES OR BOTH.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --IARG   (AN INTEGER VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--
!                     --IX1NSW (A CHARACTER VARIABLE)
!                     --IX2NSW (A CHARACTER VARIABLE)
!                     --IY1NSW (A CHARACTER VARIABLE)
!                     --IY2NSW (A CHARACTER VARIABLE)
!                     --NMNX1T (AN INTEGER VARIABLE)
!                     --NMNX2T (AN INTEGER VARIABLE)
!                     --NMNY1T (AN INTEGER VARIABLE)
!                     --NMNY2T (AN INTEGER VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
