!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IX1NSW
      CHARACTER*4 IX2NSW
      CHARACTER*4 IY1NSW
      CHARACTER*4 IY2NSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XTIC')GO TO 1100
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'X1TI')GO TO 1200
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'X2TI')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YTIC')GO TO 1400
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'Y1TI')GO TO 1500
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'Y2TI')GO TO 1600
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'TIC')GO TO 1700
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'TICS')GO TO 1700
      GO TO 9000
!
!               ********************************************************
!               **  STEP 1--
!               **  TREAT THE CASE WHEN
!               **  ONLY THE HORIZONTAL MINOR TICS ARE TO BE CHANGED
!               ********************************************************
!
 1100 CONTINUE
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1110
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'NUMB')GO TO 1110
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1101)
 1101 FORMAT('***** ERROR IN DPMITN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1102)
 1102 FORMAT('      IMPROPER FORM FOR SPECIFYING THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1103)
 1103 FORMAT('      NUMBER OF MINOR (HORIZONTAL) TIC MARKS.')
