      GO TO 9000
!
 1150 CONTINUE
      IHHOLD='FLOA'
      IHOLD=(-1)
      GO TO 1180
!
 1160 CONTINUE
      IHHOLD='FIXE'
      IHOLD=IARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
