!
 1300 CONTINUE
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'NUMB')GO TO 1310
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'NUMB')GO TO 1310
!
      WRITE(ICOUT,999)
