      SUBROUTINE DPMJTC(ICOM,IHARG,IARGT,ARG,NUMARG,   &
                        IX1TSW,IX2TSW,IY1TSW,IY2TSW,   &
                        X1COOR,X2COOR,Y1COOR,Y2COOR,   &
                        NX1COO,NX2COO,NY1COO,NY2COO,   &
                        MAXTIC,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE MAJOR TIC MARK COORDINATES
!              FOR ANY OF THE 4 FRAME LINES.
!              THE MAJOR TIC MARK COORDINATES ARE GIVEN IN UNITS
!              OF THE PLOTTED DATA.
!     ALSO, A SECONDARY PURPOSE IS TO ADJUST ACCORDINGLY
!              THE TIC MARK SWITCHES
!              FOR ANY OF THE 4 FRAME LINES.
!              SUCH TIC MARK SWITCHES TURN ON OR OFF
!              THE TIC MARKS ON THE 4 FRAME LINES OF A PLOT.
!              THE CONTENTS OF A TIC MARK SWITCH ARE
!              ON   OR    OFF
!              THE TIC MARK SWITCHES DEFINE WHETHER
!              THE TIC MARKS FOR A GIVEN FRAME SHOULD
!              BE ON (THAT IS, APPEAR), OR BE OFF (THAT IS,
!              BE SUPPRESSED.
!              THE TIC MARK SWITCHES FOR THE 4 FRAME LINES
!              ARE CONTAINED IN THE 4 VARIABLES
!              IX1TSW,IX2TSW,IY1TSW,IY2TSW,
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!                     --MAXTIC
!     OUTPUT ARGUMENTS--
!                     --IX1TSW,IX2TSW,IY1TSW,IY2TSW,
!                     --X1COOR,X2COOR,Y1COOR,Y2COOR,
!                     --NX1COO,NX2COO,NY1COO,NY2COO,
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IX1TSW
      CHARACTER*4 IX2TSW
      CHARACTER*4 IY1TSW
      CHARACTER*4 IY2TSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION X1COOR(*)
      DIMENSION X2COOR(*)
      DIMENSION Y1COOR(*)
      DIMENSION Y2COOR(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      ILOCC=0
      IF(NUMARG.LE.0)GO TO 1900
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'COOR')ILOCC=1
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'COOR')ILOCC=2
      IF(NUMARG.GE.3.AND.IHARG(2).EQ.'COOR')ILOCC=3
      ILOCCP=ILOCC+1
      IF(ILOCC.EQ.0)GO TO 1900
!
!               *****************************************************
!               **  TREAT THE CASE WHEN MAJOR TIC MARK COORDINATES ON    **
!               **  BOTH HORIZONTAL FRAME LINES ARE TO BE DEFINED  **
!               *****************************************************
!
      IF(ICOM.EQ.'XTIC')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(ILOCC.EQ.NUMARG)GO TO 1110
      IF(IHARG(ILOCCP).EQ.'ON')GO TO 1110
      IF(IHARG(ILOCCP).EQ.'OFF')GO TO 1120
      IF(IHARG(ILOCCP).EQ.'AUTO')GO TO 1110
      IF(IHARG(ILOCCP).EQ.'DEFA')GO TO 1110
      GO TO 1130
!
 1110 CONTINUE
      IFOUND='YES'
      IX1TSW='ON'
      IX2TSW='ON'
      NX1COO=-1
      NX2COO=-1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1119
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1115)
 1115 FORMAT('THE MAJOR TIC MARK COORDINATES (FOR BOTH HORIZONTAL ',   &
      'FRAME LINES)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('HAVE JUST BEEN SET TO AUTOMATIC')
      CALL DPWRST('XXX','BUG ')
 1119 CONTINUE
      GO TO 1900
!
 1120 CONTINUE
      IFOUND='YES'
      IX1TSW='OFF'
      IX2TSW='OFF'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('THE MAJOR TIC MARK COORDINATES (FOR BOTH HORIZONTAL ',   &
      'FRAME LINES)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('HAVE JUST BEEN TURNED OFF ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)
 1127 FORMAT('(THUS NO MAJOR TIC MARKS WILL APPEAR ON THEM')
      CALL DPWRST('XXX','BUG ')
 1129 CONTINUE
      GO TO 1900
!
 1130 CONTINUE
      IX1TSW='ON'
      IX2TSW='ON'
!
      J=0
      DO 1131 I=ILOCCP,NUMARG
      J=J+1
      IF(J.GT.MAXTIC)GO TO 1800
      IF(IARGT(I).NE.'NUMB')GO TO 1850
      X1COOR(J)=ARG(I)
      X2COOR(J)=ARG(I)
 1131 CONTINUE
      IFOUND='YES'
      NX1COO=J
      NX2COO=J
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('THE MAJOR TIC MARK COORDINATES (FOR BOTH HORIZONTAL ',   &
      'FRAME LINES)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('HAVE JUST BEEN MANUALLY SPECIFIED')
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN MAJOR TIC MARK COORDINATES ON
!               **  ONLY THE BOTTOM HORIZONTAL FRAME LINE ARE TO BE DEFINED **
!               **************************************************************
!
      IF(ICOM.EQ.'X1TI')GO TO 1200
      GO TO 1299
!
!
 1200 CONTINUE
      IF(ILOCC.EQ.NUMARG)GO TO 1210
      IF(IHARG(ILOCCP).EQ.'ON')GO TO 1210
      IF(IHARG(ILOCCP).EQ.'OFF')GO TO 1220
      IF(IHARG(ILOCCP).EQ.'AUTO')GO TO 1210
      IF(IHARG(ILOCCP).EQ.'DEFA')GO TO 1210
      GO TO 1230
!
 1210 CONTINUE
      IFOUND='YES'
      IX1TSW='ON'
      NX1COO=-1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1219
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('THE TIC COORDINATES (FOR THE BOTTOM HORIZONTAL ',   &
      'FRAME LINE)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)
 1216 FORMAT('HAVE JUST BEEN SET TO AUTOMATIC')
      CALL DPWRST('XXX','BUG ')
 1219 CONTINUE
      GO TO 1900
!
 1220 CONTINUE
      IFOUND='YES'
      IX1TSW='OFF'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1229
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1225)
 1225 FORMAT('THE TIC COORDINATES (FOR THE BOTTOM HORIZONTAL ',   &
      'FRAME LINE)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1226)
 1226 FORMAT('HAVE JUST BEEN TURNED OFF ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1227)
 1227 FORMAT('(THUS NO MAJOR TIC MARKS WILL APPEAR ON IT)')
      CALL DPWRST('XXX','BUG ')
 1229 CONTINUE
      GO TO 1900
!
 1230 CONTINUE
      IX1TSW='ON'
!
      J=0
      DO 1231 I=ILOCCP,NUMARG
      J=J+1
      IF(J.GT.MAXTIC)GO TO 1800
      IF(IARGT(I).NE.'NUMB')GO TO 1850
      X1COOR(J)=ARG(I)
 1231 CONTINUE
      IFOUND='YES'
      NX1COO=J
!
      IF(IFEEDB.EQ.'OFF')GO TO 1239
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1235)
 1235 FORMAT('THE TIC COORDINATES (FOR THE BOTTOM HORIZONTAL ',   &
      'FRAME LINE)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1236)
 1236 FORMAT('HAVE JUST BEEN MANUALLY SPECIFIED')
      CALL DPWRST('XXX','BUG ')
 1239 CONTINUE
      GO TO 1900
!
 1299 CONTINUE
!
